// HELPERS GLOBALES PARA DESCARGA EXCEL (reutilizables en cualquier pestaña)
// ═══════════════════════════════════════════════════════════════════════════

// Genera un archivo Excel con múltiples hojas
// hojas = [{ nombre: "Resumen", datos: [["col1","col2"], ["a","b"]] }, ...]
async function descargarExcelMultihoja(hojas, nombreArchivo) {
  if (!window.XLSX) {
    // Cargar la librería si no existe
    await new Promise((resolve, reject) => {
      const s = document.createElement("script");
      s.src = "https://cdn.sheetjs.com/xlsx-0.20.0/package/dist/xlsx.full.min.js";
      s.onload = resolve;
      s.onerror = reject;
      document.head.appendChild(s);
    });
  }
  const XLSX = window.XLSX;
  if (!XLSX) {
    alert("No se pudo cargar la librería de Excel. Revisá tu conexión a internet.");
    return;
  }
  const wb = XLSX.utils.book_new();
  for (const h of hojas) {
    const ws = XLSX.utils.aoa_to_sheet(h.datos);
    // Anchos de columna automáticos basados en el contenido
    if (h.datos.length > 0) {
      const colWidths = h.datos[0].map((_, colIdx) => {
        let max = 8;
        for (const row of h.datos) {
          const v = row[colIdx];
          if (v != null) max = Math.max(max, String(v).length);
        }
        return { wch: Math.min(max + 2, 60) };
      });
      ws["!cols"] = colWidths;
    }
    XLSX.utils.book_append_sheet(wb, ws, (h.nombre || "Hoja").slice(0, 31));
  }
  const fechaStr = new Date().toLocaleDateString("es-CL").replace(/\//g, "-");
  XLSX.writeFile(wb, `${nombreArchivo}_${fechaStr}.xlsx`);
}

// Convierte array de objetos a array 2D para Excel (con headers)
function objetosATabla(objetos, columnas) {
  // columnas: [{ key: "campo", label: "Etiqueta" }] o solo array de strings
  if (!columnas) {
    if (objetos.length === 0) return [[]];
    columnas = Object.keys(objetos[0]).map(k => ({ key: k, label: k }));
  }
  if (typeof columnas[0] === "string") {
    columnas = columnas.map(k => ({ key: k, label: k }));
  }
  const headers = columnas.map(c => c.label);
  const rows = objetos.map(obj => columnas.map(c => {
    let v = obj[c.key];
    if (v == null) return "";
    if (typeof v === "boolean") return v ? "Sí" : "No";
    if (typeof v === "object") return JSON.stringify(v);
    return v;
  }));
  return [headers, ...rows];
}

// Botón de descarga estandarizado
function BotonDescargarExcel({ onClick, disabled, label = "Descargar Excel" }) {
  return (
    <button onClick={onClick} disabled={disabled} className="btn-blue"
      style={{
        padding: "7px 14px", fontSize: 11, fontWeight: 600,
        background: "#1a3a6b", color: "#fff", border: "none",
        borderRadius: 6, cursor: disabled ? "not-allowed" : "pointer",
        opacity: disabled ? 0.5 : 1, fontFamily: "Geist, sans-serif",
        whiteSpace: "nowrap",
      }}>
      📥 {label}
    </button>
  );
}

