// SheetJS lazy-load para descarga Excel
const cargarSheetJS = () => new Promise((resolve, reject) => {
  if (window.XLSX) return resolve(window.XLSX);
  const s = document.createElement('script');
  s.src = 'https://cdn.sheetjs.com/xlsx-0.20.1/package/dist/xlsx.full.min.js';
  s.onload = () => resolve(window.XLSX);
  s.onerror = reject;
  document.head.appendChild(s);
});

async function descargarExcelMeli(filas, nombreArchivo, nombreHoja = "Datos") {
  if (!filas || filas.length === 0) {
    alert("No hay datos para descargar");
    return;
  }
  try {
    const XLSX = await cargarSheetJS();
    const wb = XLSX.utils.book_new();
    const ws = XLSX.utils.json_to_sheet(filas);
    XLSX.utils.book_append_sheet(wb, ws, nombreHoja.slice(0, 31));
    XLSX.writeFile(wb, `${nombreArchivo}.xlsx`);
  } catch (e) {
    console.error("Error descargando Excel:", e);
    alert("No se pudo descargar el Excel: " + (e.message || e));
  }
}

// Helper para nombres de meses en español
const NOMBRES_MES = ["Enero", "Febrero", "Marzo", "Abril", "Mayo", "Junio", 
                     "Julio", "Agosto", "Septiembre", "Octubre", "Noviembre", "Diciembre"];

function diasDelMes(anio, mes) {
  return new Date(anio, mes, 0).getDate();
}

// Calcula el rango {desde, hasta} de un mes seleccionado.
// Regla: si el mes ya terminó → mes completo. Si es el actual → hasta ayer (CURRENT_DATE - 1).
function rangoMesGlobal(mesGlobal) {
  const yyyy = mesGlobal.anio;
  const mm = String(mesGlobal.mes).padStart(2, '0');
  const desde = `${yyyy}-${mm}-01`;
  
  const hoy = new Date();
  const esMesActual = mesGlobal.anio === hoy.getFullYear() && mesGlobal.mes === (hoy.getMonth() + 1);
  
  let hasta;
  if (esMesActual) {
    // Mes en curso: hasta ayer
    const ayer = new Date(hoy);
    ayer.setDate(ayer.getDate() - 1);
    hasta = ayer.toISOString().slice(0, 10);
  } else {
    // Mes pasado: mes completo
    const ultDia = diasDelMes(mesGlobal.anio, mesGlobal.mes);
    hasta = `${yyyy}-${mm}-${String(ultDia).padStart(2, '0')}`;
  }
  return { desde, hasta };
}

function IndicadoresOperacionalesMX({ usuario }) {
  const [vista, setVista] = useState("compromiso");
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [resumen, setResumen] = useState(null);
  const [drivers, setDrivers] = useState([]);
  const [vehiculos, setVehiculos] = useState([]);
  const [scs, setSCs] = useState([]);
  const [scores, setScores] = useState([]);
  const [modal, setModal] = useState(null);
  
  // ─── SELECTOR GLOBAL DE MES ─────────────────────────────────────────────
  const [mesesDisponibles, setMesesDisponibles] = useState([]);
  const [mesGlobal, setMesGlobal] = useState(() => {
    const hoy = new Date();
    return { anio: hoy.getFullYear(), mes: hoy.getMonth() + 1 };
  });

  // Estado para vista detalle in-place (driver o vehículo)
  const [detalle, setDetalle] = useState(null); // { tipo: 'driver'|'vehiculo', registro: {...} }

  // Cargar meses disponibles UNA sola vez al montar
  useEffect(() => {
    (async () => {
      try {
        const { data, error } = await sb.rpc("get_meses_con_datos_meli");
        if (error) throw error;
        setMesesDisponibles(data || []);
        // Si no hay datos del mes actual, ir al mes más reciente
        const hoy = new Date();
        const anioActual = hoy.getFullYear(), mesActual = hoy.getMonth() + 1;
        const tieneActual = (data || []).some(m => m.anio === anioActual && m.mes === mesActual);
        if (!tieneActual && data && data.length > 0) {
          setMesGlobal({ anio: data[0].anio, mes: data[0].mes });
        }
      } catch (e) {
        console.error("Error cargando meses:", e);
      }
    })();
  }, []);

  // Recargar TODOS los datos cuando cambia el mes
  useEffect(() => {
    let alive = true;
    (async () => {
      setLoading(true);
      setError(null);
      try {
        const { desde, hasta } = rangoMesGlobal(mesGlobal);
        
        const [r1, r2, r3, r4, r5] = await Promise.all([
          sb.from("vw_meli_dashboard_resumen").select("*").maybeSingle(),
          sb.rpc("get_inventario_drivers_mes", { fecha_desde: desde, fecha_hasta: hasta }),
          sb.rpc("get_inventario_vehiculos_mes", { fecha_desde: desde, fecha_hasta: hasta }),
          sb.rpc("get_ciclo_aceptacion_sc", { fecha_desde: desde, fecha_hasta: hasta }),
          sb.rpc("get_score_compromiso", { fecha_desde: desde, fecha_hasta: hasta }),
        ]);
        if (!alive) return;
        if (r1.error || r2.error || r3.error || r4.error || r5.error) {
          throw new Error(r1.error?.message || r2.error?.message || r3.error?.message || r4.error?.message || r5.error?.message);
        }
        setResumen(r1.data);
        setDrivers((r2.data || []).sort((a, b) => (b.viajes_total || 0) - (a.viajes_total || 0)));
        setVehiculos((r3.data || []).sort((a, b) => (b.viajes_total || 0) - (a.viajes_total || 0)));
        setSCs((r4.data || []).sort((a, b) => (b.ofrecidas || 0) - (a.ofrecidas || 0)));
        setScores((r5.data || []).sort((a, b) => (b.score_total || 0) - (a.score_total || 0)));
      } catch (e) {
        if (alive) setError(e.message || "Error cargando datos");
      } finally {
        if (alive) setLoading(false);
      }
    })();
    return () => { alive = false; };
  }, [mesGlobal.anio, mesGlobal.mes]);

  // Tabs: Compromiso MELI, KPI de Operación, Diferencias Maestros, Inventario, Control Helper
  // Nota: pestaña "validacion_bt" oculta del menú (render condicional abajo queda intacto).
  // El Padrón MELI (altas/bajas/cambios) se movió a Administración → "Padrón MELI".
  const tabs = [
    { id: "compromiso", label: "Compromiso MELI", desc: "Operativa de mañana · SDD vs SPOT" },
    { id: "kpi_operacion", label: "KPI de Operación", desc: "NS Informe MELI vs Snapshots" },
    { id: "inventario", label: "Inventario", desc: "Drivers, vehículos, fantasmas" },
    { id: "control_helper", label: "Control Helper", desc: "Helpers no autorizados / certificados / fantasmas" },
    { id: "torre_rostering_hoy", label: "Torre Rostering HOY", desc: "Operativo en vivo · cronómetros + alertas SDD" },
  ];

  if (loading) {
    return (
      <div className="pg">
        <div className="sec-title">Indicadores Operacionales MX</div>
        <div className="sec-sub">Pool Mercado Libre · Bigticket México</div>
        <div className="form-card" style={{ textAlign: "center", padding: 40, color: "#666" }}>
          Cargando indicadores…
        </div>
      </div>
    );
  }

  // Tabs que NO dependen del loader pesado del wrapper
  const tabsIndependientes = ["torre_rostering_hoy", "compromiso", "control_helper"];
  if (error && !tabsIndependientes.includes(vista)) {
    return (
      <div className="pg">
        <div className="sec-title">Indicadores Operacionales MX</div>
        <div className="sec-sub">Pool Mercado Libre · Bigticket México</div>
        <div className="form-card" style={{ background: "#fef2f2", border: "1px solid #fecaca", marginBottom: 12 }}>
          <div style={{ fontSize: 13, fontWeight: 600, color: "#991b1b", marginBottom: 6 }}>
            No se pudo cargar la información del módulo
          </div>
          <div style={{ fontSize: 12, color: "#7f1d1d", lineHeight: 1.6 }}>
            {error}
            <br /><br />
            <strong>Causa probable:</strong> timeout en alguna RPC pesada. Probá las tabs:
            {" "}<button onClick={() => setVista("torre_rostering_hoy")}
                 style={{background:"none",border:"none",color:"#1a3a6b",fontWeight:600,cursor:"pointer",padding:0,textDecoration:"underline"}}>Torre Rostering HOY</button>,
            {" "}<button onClick={() => setVista("compromiso")}
                 style={{background:"none",border:"none",color:"#1a3a6b",fontWeight:600,cursor:"pointer",padding:0,textDecoration:"underline"}}>Compromiso MELI</button> o
            {" "}<button onClick={() => setVista("control_helper")}
                 style={{background:"none",border:"none",color:"#1a3a6b",fontWeight:600,cursor:"pointer",padding:0,textDecoration:"underline"}}>Control Helper</button>
            {" "}que no requieren los datos pesados.
          </div>
        </div>
      </div>
    );
  }

  // Vista detalle ocupa toda la pantalla del módulo
  if (detalle) {
    return (
      <PoolMeliDetalleRegistro 
        tipo={detalle.tipo} 
        registro={detalle.registro} 
        onVolver={() => setDetalle(null)} 
      />
    );
  }

  return (
    <div style={{ padding: 0 }}>
      <div style={{ background: "#fff", borderBottom: "1px solid #e4e7ec", padding: "12px 24px" }}>
        <div style={{ fontSize: 18, fontWeight: 700, color: "#1a3a6b", marginBottom: 4 }}>
          Indicadores Operacionales MX
        </div>
        <div style={{ fontSize: 12, color: "#64748b", marginBottom: 10 }}>
          Pool Mercado Libre · cruce de 6 fuentes operativas
        </div>
        <div style={{ display: "flex", gap: 0, borderBottom: "2px solid #e4e7ec", marginLeft: -8, flexWrap: "wrap", alignItems: "flex-end", justifyContent: "space-between" }}>
          <div style={{ display: "flex", gap: 0, flexWrap: "wrap" }}>
            {tabs.map(t => (
              <button key={t.id} onClick={() => setVista(t.id)}
                style={{
                  background: "transparent", border: "none", padding: "10px 16px",
                  fontSize: 13, fontWeight: 600, cursor: "pointer", color: vista === t.id ? "#1a3a6b" : "#64748b",
                  borderBottom: vista === t.id ? "2px solid #1a3a6b" : "2px solid transparent",
                  marginBottom: -2,
                }}>
                <div>{t.label}</div>
                <div style={{ fontSize: 10, color: "#94a3b8", fontWeight: 400, marginTop: 2 }}>{t.desc}</div>
              </button>
            ))}
          </div>
          {/* Dropdown global de mes (solo aplica en Inventario) */}
          {vista === "inventario" && (
          <div style={{ display: "flex", alignItems: "center", gap: 8, paddingBottom: 8 }}>
            <span style={{ fontSize: 11, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5 }}>
              Período:
            </span>
            <select 
              value={`${mesGlobal.anio}-${mesGlobal.mes}`}
              onChange={(e) => {
                const [a, m] = e.target.value.split('-').map(Number);
                setMesGlobal({ anio: a, mes: m });
              }}
              style={{
                padding: "6px 12px", fontSize: 13, fontWeight: 600, borderRadius: 6,
                border: "1px solid #cbd5e1", background: "#fff", color: "#1a3a6b",
                cursor: "pointer", fontFamily: "'Geist', sans-serif", outline: "none",
              }}>
              {mesesDisponibles.map(m => (
                <option key={`${m.anio}-${m.mes}`} value={`${m.anio}-${m.mes}`}>
                  {NOMBRES_MES[m.mes - 1]} {m.anio} ({m.dias_con_datos} días)
                </option>
              ))}
            </select>
          </div>
          )}
        </div>
      </div>

      {vista === "compromiso" && <PoolMeliCompromiso />}
      {vista === "kpi_operacion" && <PoolMeliKPIOperacion />}
      {vista === "diferencias" && <PoolMeliDiferenciasMaestros />}
      {vista === "inventario" && <PoolMeliInventario drivers={drivers} vehiculos={vehiculos} resumen={resumen} setModal={setModal} setDetalle={setDetalle} mesGlobal={mesGlobal} />}
      {vista === "control_helper" && <PoolMeliControlHelper />}
      {vista === "torre_rostering_hoy" && <TorreRosteringHoy />}
      {vista === "validacion_bt" && <PoolMeliValidacionBT usuario={usuario} />}

      {modal && <MeliModal modal={modal} onClose={() => setModal(null)} />}
    </div>
  );
}
// ════════════════════════════════════════════════════════════════════════════
// TORRE CONTROL ROSTERING HOY · Pool MELI MX
// Sub-tab dentro de IndicadoresOperacionalesMX
//
// Lee de:
//  - get_torre_rostering_hoy_resumen() · RPC con totales + por_sc + duplicados
//  - vw_torre_rostering_hoy · listado detallado por travel
//  - vw_torre_rostering_duplicados · drivers/placas repetidos
//
// Lógica visual:
//  - Sección crítica SDD al inicio (siempre visible si hay SDD)
//  - KPIs en franja
//  - Lista de SCs ordenadas por urgencia (vencido + en riesgo)
//  - Cada SC: alertas de duplicados arriba + tabla de rutas
//  - Cronómetro en vivo hacia lockDate (se actualiza cada minuto)
//  - Botón refrescar manual + auto-refresh cada 5 min
// ════════════════════════════════════════════════════════════════════════════

function TorreRosteringHoy() {
  const [resumen, setResumen] = useState(null);
  const [filas, setFilas] = useState([]);
  const [duplicados, setDuplicados] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [tick, setTick] = useState(0); // para refrescar cronómetros
  const [scExpandido, setScExpandido] = useState(new Set()); // SCs colapsadas/expandidas
  const [ultimaActualizacion, setUltimaActualizacion] = useState(null); // último fetch exitoso
  const [toastVisible, setToastVisible] = useState(false); // toast ✅ al refrescar

  // Cargar todos los datos
  const cargar = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const [resResumen, resFilas, resDups] = await Promise.all([
        sb.rpc("get_torre_rostering_hoy_resumen"),
        sb.from("vw_torre_rostering_hoy").select("*").order("sc").order("travel_id"),
        sb.from("vw_torre_rostering_duplicados").select("*"),
      ]);
      if (resResumen.error) throw resResumen.error;
      if (resFilas.error) throw resFilas.error;
      if (resDups.error) throw resDups.error;
      setResumen(resResumen.data || null);
      setFilas(resFilas.data || []);
      setDuplicados(resDups.data || []);
      const scsConDatos = new Set((resFilas.data || []).map(f => f.sc).filter(Boolean));
      setScExpandido(scsConDatos);
      // ✅ Feedback visual de refresco exitoso
      setUltimaActualizacion(new Date());
      setToastVisible(true);
      setTimeout(() => setToastVisible(false), 2500);
    } catch (e) {
      setError(e.message || String(e));
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { cargar(); }, [cargar]);

  // Tick cada 60s para actualizar cronómetros y refrescar datos cada 5 min
  useEffect(() => {
    const timerTick = setInterval(() => setTick(t => t + 1), 60_000);
    const timerRefresh = setInterval(() => cargar(), 5 * 60_000);
    return () => { clearInterval(timerTick); clearInterval(timerRefresh); };
  }, [cargar]);

  // Helper: minutos restantes hasta lockDate (recalcula en cada tick)
  const minutosHasta = (lockdateStr) => {
    if (!lockdateStr) return null;
    const target = new Date(lockdateStr).getTime();
    const ahora = Date.now();
    return Math.round((target - ahora) / 60000);
  };

  // Helper: formatear cronómetro
  const formatCrono = (min) => {
    if (min === null || min === undefined) return "—";
    const abs = Math.abs(min);
    const h = Math.floor(abs / 60);
    const m = abs % 60;
    const sign = min < 0 ? "-" : "";
    if (h === 0) return `${sign}${m}m`;
    return `${sign}${h}h ${m}m`;
  };

  // Helper: color del cronómetro
  const colorCrono = (min) => {
    if (min === null || min === undefined) return "#94a3b8";
    if (min < 0) return "#b91c1c";       // rojo vencido
    if (min < 60) return "#dc2626";       // rojo intenso (< 1h)
    if (min < 240) return "#d97706";      // naranja (1-4h)
    return "#047857";                     // verde (> 4h)
  };

  const toggleSc = (sc) => {
    setScExpandido(prev => {
      const next = new Set(prev);
      if (next.has(sc)) next.delete(sc); else next.add(sc);
      return next;
    });
  };

  if (loading && !resumen) {
    return (
      <div style={{ padding: 40, textAlign: "center", color: "#64748b" }}>
        Cargando Torre Control Rostering…
      </div>
    );
  }

  if (error) {
    return (
      <div style={{ padding: 20 }}>
        <div style={{ background: "#fef2f2", border: "1px solid #fecaca", padding: 16, borderRadius: 8 }}>
          <div style={{ fontWeight: 600, color: "#991b1b", marginBottom: 6 }}>Error cargando Torre</div>
          <div style={{ fontSize: 12, color: "#7f1d1d" }}>{error}</div>
          <div style={{ fontSize: 11, color: "#7f1d1d", marginTop: 8 }}>
            Verificá que las vistas <code>vw_torre_rostering_hoy</code> y <code>vw_torre_rostering_duplicados</code> existan en Supabase.
          </div>
        </div>
      </div>
    );
  }

  const totales = resumen?.totales || {};
  const meta = resumen?.meta || {};
  const porSc = resumen?.por_sc || [];

  // SDD en alerta principal · hard (vencidas) + incompletas (rescatables)
  const sddAlertas = filas.filter(f =>
    f.estado === "A_NO_SHOW_HARD_SDD" || f.estado === "C_INCOMPLETO_SDD"
  );
  // NO_SHOW HARD totales (SDD + Variable) · alerta separada
  const noShowHardAlertas = filas.filter(f =>
    f.estado === "A_NO_SHOW_HARD_SDD" || f.estado === "B_NO_SHOW_HARD_VARIABLE"
  );

  // Filas por SC (excluyendo cancel/otro)
  const filasOperativas = filas.filter(f =>
    f.estado && !["Z_CANCEL_MELI", "Z_OTRO"].includes(f.estado)
  );
  const scsConDatos = [...new Set(filasOperativas.map(f => f.sc).filter(Boolean))];

  // Ordenar SCs por urgencia: NO_SHOW_HARD_SDD > NO_SHOW_HARD_VAR > INCOMPLETO_SDD > INCOMPLETO_VAR
  const urgenciaSc = (sc) => {
    const s = porSc.find(x => x.sc === sc) || {};
    return (s.no_show_hard_sdd || 0) * 100000
         + (s.no_show_hard_variable || 0) * 10000
         + (s.incompleto_sdd || 0) * 1000
         + (s.incompleto_variable || 0) * 100
         + (s.rostereado_sin_p3 || 0);
  };
  const scsOrdenadas = scsConDatos.sort((a, b) => urgenciaSc(b) - urgenciaSc(a));

  return (
    <div style={{ padding: 20, fontFamily: "'Geist', sans-serif" }}>
      {/* Header */}
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-end", marginBottom: 16 }}>
        <div>
          <div style={{ fontSize: 18, fontWeight: 700, color: "#1a3a6b" }}>Torre Control Rostering HOY</div>
          <div style={{ fontSize: 12, color: "#64748b" }}>
            Fecha operativa: <strong>{meta.fecha || "—"}</strong>
            {" · "}Última captura: <strong>{meta.captura_hora || "—"}</strong>
            {" · "}Total travels: <strong>{totales.total_travels || 0}</strong>
          </div>
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          {ultimaActualizacion && (
            <div style={{ fontSize: 11, color: "#64748b" }}>
              Datos al{" "}
              <strong>
                {ultimaActualizacion.toLocaleTimeString("es-MX", { hour: "2-digit", minute: "2-digit", second: "2-digit" })}
              </strong>
            </div>
          )}
          <button onClick={cargar} disabled={loading}
            style={{
              padding: "6px 14px", borderRadius: 6,
              border: loading ? "1px solid #cbd5e1" : "1px solid #1a3a6b",
              background: loading ? "#f1f5f9" : (toastVisible ? "#d1fae5" : "#fff"),
              color: loading ? "#94a3b8" : (toastVisible ? "#047857" : "#1a3a6b"),
              fontWeight: 600, fontSize: 12,
              cursor: loading ? "wait" : "pointer",
              transition: "all 0.3s ease",
              display: "flex", alignItems: "center", gap: 6
            }}>
            {loading ? (
              <>
                <span style={{ display: "inline-block", animation: "spin 1s linear infinite" }}>⠹</span>
                Cargando…
              </>
            ) : toastVisible ? (
              <>✅ Actualizado</>
            ) : (
              <>🔄 Refrescar</>
            )}
          </button>
          <style>{`@keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }`}</style>
        </div>
      </div>

      {/* KPIs en franja · v3 · 6 boxes operativos */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(6, 1fr)", gap: 10, marginBottom: 16 }}>
        <KpiBox label="🆘 NO SHOW HARD SDD"
                value={totales.no_show_hard_sdd || 0}
                color="#7f1d1d" bg="#fecaca"
                detalle="multa SDD segura" />
        <KpiBox label="🚨 NO SHOW HARD"
                value={totales.no_show_hard_variable || 0}
                color="#b91c1c" bg="#fee2e2"
                detalle="multa variable" />
        <KpiBox label="🆘 Incompleto SDD"
                value={totales.incompleto_sdd || 0}
                color="#dc2626" bg="#fee2e2"
                detalle="rescatable" />
        <KpiBox label="🟠 Incompleto"
                value={totales.incompleto_variable || 0}
                color="#c2410c" bg="#ffedd5"
                detalle="rescatable" />
        <KpiBox label="🟢 Operando"
                value={totales.operando || 0}
                color="#047857" bg="#d1fae5"
                detalle={`SDD: ${totales.sdd_operando || 0}`} />
        <KpiBox label="⚠️ Duplicados"
                value={resumen?.duplicados?.total_duplicados || 0}
                color="#0891b2" bg="#cffafe"
                detalle={`con SDD: ${resumen?.duplicados?.dup_con_sdd || 0}`} />
      </div>

      {/* Sección crítica SDD */}
      {sddAlertas.length > 0 && (
        <div style={{
          background: "#fef2f2", border: "2px solid #b91c1c", borderRadius: 8,
          padding: 14, marginBottom: 16
        }}>
          <div style={{ fontSize: 14, fontWeight: 700, color: "#7f1d1d", marginBottom: 10 }}>
            🆘 ALERTA CRÍTICA · {sddAlertas.length} ruta{sddAlertas.length !== 1 ? "s" : ""} SDD sin rostering
          </div>
          <table style={{ width: "100%", fontSize: 12, borderCollapse: "collapse" }}>
            <thead>
              <tr style={{ borderBottom: "1px solid #fecaca", color: "#991b1b" }}>
                <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 600 }}>SC</th>
                <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 600 }}>Vehículo</th>
                <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 600 }}>Travel ID</th>
                <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 600 }}>Estado Pilar 1</th>
                <th style={{ textAlign: "right", padding: "4px 8px", fontWeight: 600 }}>Hora carga</th>
                <th style={{ textAlign: "right", padding: "4px 8px", fontWeight: 600 }}>⏰ Hasta lockDate</th>
              </tr>
            </thead>
            <tbody>
              {sddAlertas.map(f => {
                const min = minutosHasta(f.lockdate_str);
                return (
                  <tr key={f.travel_id} style={{ borderBottom: "1px solid #fee2e2" }}>
                    <td style={{ padding: "5px 8px", fontWeight: 700, color: "#7f1d1d" }}>{f.sc}</td>
                    <td style={{ padding: "5px 8px", color: "#7f1d1d" }}>{f.vehiculo}</td>
                    <td style={{ padding: "5px 8px", fontFamily: "monospace", color: "#7f1d1d" }}>{f.travel_id}</td>
                    <td style={{ padding: "5px 8px", color: "#7f1d1d" }}>
                      {f.travel_status === "pending" ? "🚨 PENDING (responder)" : "ACEPTADO sin rostear"}
                    </td>
                    <td style={{ padding: "5px 8px", textAlign: "right", color: "#7f1d1d" }}>{f.eta_visible || "—"}</td>
                    <td style={{ padding: "5px 8px", textAlign: "right", fontWeight: 700, color: colorCrono(min) }}>
                      {formatCrono(min)}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}

      {/* Sección por SC */}
      {scsOrdenadas.map(sc => {
        const filasSc = filasOperativas.filter(f => f.sc === sc);
        const dupsSc = duplicados.filter(d => d.sc === sc);
        const expandido = scExpandido.has(sc);
        const statsSc = porSc.find(x => x.sc === sc) || {};

        return (
          <div key={sc} style={{
            background: "#fff", border: "1px solid #e4e7ec", borderRadius: 8,
            marginBottom: 12, overflow: "hidden"
          }}>
            {/* Header SC */}
            <div onClick={() => toggleSc(sc)}
              style={{
                padding: "10px 14px", background: "#f8fafc", cursor: "pointer",
                display: "flex", justifyContent: "space-between", alignItems: "center",
                borderBottom: expandido ? "1px solid #e4e7ec" : "none"
              }}>
              <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                <span style={{ fontSize: 14, fontWeight: 700, color: "#1a3a6b" }}>{sc}</span>
                <span style={{ fontSize: 11, color: "#64748b" }}>{filasSc.length} rutas</span>
              </div>
              <div style={{ display: "flex", gap: 6, alignItems: "center", fontSize: 11, flexWrap: "wrap", justifyContent: "flex-end" }}>
                {statsSc.no_show_hard_sdd > 0 && (
                  <Badge color="#7f1d1d" bg="#fecaca" label={`HardSDD ${statsSc.no_show_hard_sdd}`} />
                )}
                {statsSc.no_show_hard_variable > 0 && (
                  <Badge color="#b91c1c" bg="#fee2e2" label={`Hard ${statsSc.no_show_hard_variable}`} />
                )}
                {statsSc.incompleto_sdd > 0 && (
                  <Badge color="#dc2626" bg="#fee2e2" label={`IncSDD ${statsSc.incompleto_sdd}`} />
                )}
                {statsSc.incompleto_variable > 0 && (
                  <Badge color="#c2410c" bg="#ffedd5" label={`Inc ${statsSc.incompleto_variable}`} />
                )}
                {statsSc.rostereado_sin_p3 > 0 && (
                  <Badge color="#ca8a04" bg="#fef9c3" label={`Rost ${statsSc.rostereado_sin_p3}`} />
                )}
                <Badge color="#047857" bg="#d1fae5" label={`Op ${statsSc.operando || 0}`} />
                <span style={{ color: "#64748b", fontSize: 14, marginLeft: 4 }}>
                  {expandido ? "▼" : "▶"}
                </span>
              </div>
            </div>

            {/* Alertas de duplicados */}
            {expandido && dupsSc.length > 0 && (
              <div style={{ padding: "10px 14px", background: "#fffbeb", borderBottom: "1px solid #fef3c7" }}>
                <div style={{ fontSize: 12, fontWeight: 600, color: "#92400e", marginBottom: 6 }}>
                  ⚠️ {dupsSc.length} duplicado{dupsSc.length !== 1 ? "s" : ""} detectado{dupsSc.length !== 1 ? "s" : ""}
                </div>
                {dupsSc.map((d, i) => (
                  <div key={i} style={{ fontSize: 11, color: "#7c2d12", marginBottom: 3 }}>
                    {d.incluye_sdd && <span style={{ color: "#b91c1c", fontWeight: 700 }}>[SDD] </span>}
                    <strong>{d.tipo === "driver_duplicado" ? "Driver" : "Placa"}</strong>
                    {" "}<code style={{ background: "#fef3c7", padding: "1px 6px", borderRadius: 3 }}>{d.valor}</code>
                    {" "}en <strong>{d.rutas}</strong> rutas: {(d.travel_ids || []).join(", ")}
                  </div>
                ))}
              </div>
            )}

            {/* Tabla de rutas */}
            {expandido && (
              <table style={{ width: "100%", fontSize: 11, borderCollapse: "collapse" }}>
                <thead>
                  <tr style={{ background: "#fafbfc", borderBottom: "1px solid #e4e7ec" }}>
                    <th style={{ textAlign: "left", padding: "6px 10px", fontWeight: 600, color: "#475569" }}>Estado</th>
                    <th style={{ textAlign: "left", padding: "6px 10px", fontWeight: 600, color: "#475569" }}>Travel</th>
                    <th style={{ textAlign: "left", padding: "6px 10px", fontWeight: 600, color: "#475569" }}>Vehículo</th>
                    <th style={{ textAlign: "left", padding: "6px 10px", fontWeight: 600, color: "#475569" }}>Flota</th>
                    <th style={{ textAlign: "left", padding: "6px 10px", fontWeight: 600, color: "#475569" }}>Driver</th>
                    <th style={{ textAlign: "left", padding: "6px 10px", fontWeight: 600, color: "#475569" }}>Placa</th>
                    <th style={{ textAlign: "center", padding: "6px 10px", fontWeight: 600, color: "#475569" }}>ETA</th>
                    <th style={{ textAlign: "right", padding: "6px 10px", fontWeight: 600, color: "#475569" }}>⏰ lockDate</th>
                  </tr>
                </thead>
                <tbody>
                  {filasSc.map(f => {
                    const min = minutosHasta(f.lockdate_str);
                    const estadoInfo = ESTADOS_INFO[f.estado] || { emoji: "❓", color: "#94a3b8" };
                    return (
                      <tr key={f.travel_id} style={{ borderBottom: "0.5px solid #f1f5f9" }}>
                        <td style={{ padding: "5px 10px" }}>
                          <span style={{ fontSize: 13 }}>{estadoInfo.emoji}</span>
                        </td>
                        <td style={{ padding: "5px 10px", fontFamily: "monospace", fontSize: 10, color: "#64748b" }}>
                          {f.travel_id}
                        </td>
                        <td style={{ padding: "5px 10px", color: "#475569" }}>{f.vehiculo || "—"}</td>
                        <td style={{ padding: "5px 10px" }}>
                          <span style={{
                            fontSize: 10, fontWeight: 600,
                            color: f.flota === "SDD" ? "#1e40af" : "#475569"
                          }}>
                            {f.flota || "—"}
                          </span>
                        </td>
                        <td style={{ padding: "5px 10px", color: f.driver_name ? "#1a3a6b" : "#b91c1c", fontWeight: f.driver_name ? 500 : 700 }}>
                          {f.driver_name || "🔴 SIN ASIGNAR"}
                        </td>
                        <td style={{ padding: "5px 10px", fontFamily: "monospace", color: f.vehicle_plate ? "#1a3a6b" : "#b91c1c", fontWeight: f.vehicle_plate ? 500 : 700 }}>
                          {f.vehicle_plate || "🔴 SIN PLACA"}
                        </td>
                        <td style={{ padding: "5px 10px", textAlign: "center", color: "#64748b" }}>
                          {f.eta_visible || "—"}
                        </td>
                        <td style={{ padding: "5px 10px", textAlign: "right", fontWeight: 600, color: colorCrono(min) }}>
                          {formatCrono(min)}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            )}
          </div>
        );
      })}

      {/* Tick invisible para forzar recálculo de cronómetros */}
      <div style={{ display: "none" }}>{tick}</div>
    </div>
  );
}

// ─── Componentes auxiliares ─────────────────────────────────────────────────

function KpiBox({ label, value, color, bg, detalle }) {
  return (
    <div style={{ background: bg, padding: "10px 12px", borderRadius: 6, border: `1px solid ${color}22` }}>
      <div style={{ fontSize: 10, fontWeight: 600, color, marginBottom: 4 }}>{label}</div>
      <div style={{ fontSize: 22, fontWeight: 800, color }}>{value}</div>
      {detalle && <div style={{ fontSize: 9, color, opacity: 0.7, marginTop: 2 }}>{detalle}</div>}
    </div>
  );
}

function Badge({ color, bg, label }) {
  return (
    <span style={{
      background: bg, color, padding: "2px 8px", borderRadius: 10,
      fontSize: 10, fontWeight: 700, whiteSpace: "nowrap"
    }}>{label}</span>
  );
}

const ESTADOS_INFO = {
  "A_NO_SHOW_HARD_SDD":      { emoji: "🆘", color: "#7f1d1d", label: "NO SHOW HARD SDD" },
  "B_NO_SHOW_HARD_VARIABLE": { emoji: "🚨", color: "#b91c1c", label: "NO SHOW HARD" },
  "C_INCOMPLETO_SDD":        { emoji: "🆘", color: "#dc2626", label: "Incompleto SDD" },
  "D_INCOMPLETO_VARIABLE":   { emoji: "🟠", color: "#c2410c", label: "Incompleto" },
  "E_OPERANDO":              { emoji: "🟢", color: "#047857", label: "Operando" },
  "F_ROSTEREADO_SIN_P3":     { emoji: "🟡", color: "#ca8a04", label: "Rostereado (sin P3)" },
  "Z_CANCEL_MELI":           { emoji: "⚪", color: "#94a3b8", label: "Cancel MELI" },
  "Z_OTRO":                  { emoji: "❓", color: "#94a3b8", label: "Otro" },
};

// ════════════════════════════════════════════════════════════════════════════
// CONTROL HELPER · Subpestaña dentro de IndicadoresOperacionalesMX
// Estructura visual: HTML Control_Helpers_Mexico_8.html
// Colores + fuente: Brain (Geist · #1a3a6b · #F47B20 · #f0f2f5)
// Datos: vw_control_helper_diario (Supabase)
// ════════════════════════════════════════════════════════════════════════════

// Paleta Brain
const CH_NAVY = "#1a3a6b";
const CH_ORANGE = "#F47B20";
const CH_BG = "#f0f2f5";
const CH_CARD = "#fff";
const CH_BORDER = "#e4e7ec";
const CH_TEXT = "#1a1a1a";
const CH_MUTED = "#64748b";
const CH_LIGHT = "#94a3b8";

// Tonos de gravedad (manteniendo lógica HTML pero con colores más coherentes Brain)
const CH_RED = "#dc2626";
const CH_RED_SOFT = "#fca5a5";
const CH_YELLOW = "#fef3c7";
const CH_YELLOW_TEXT = "#92400e";
const CH_GREEN = "#15803d";
const CH_GRAY = "#9ca3af";

function PoolMeliControlHelper() {
  const [fecha, setFecha] = useState(() => {
    // Default: ayer (D-1) · los datos se completan al final de la jornada operativa
    // con los snapshots y paquetes entregados
    const now = new Date();
    const mx = new Date(now.getTime() - 6 * 60 * 60 * 1000);
    mx.setDate(mx.getDate() - 1);
    return mx.toISOString().split('T')[0];
  });
  const [universo, setUniverso] = useState(0);
  const [periodo, setPeriodo] = useState(7);
  const [datos, setDatos] = useState([]);
  const [serie, setSerie] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [drillDown, setDrillDown] = useState(null);
  const [ddOpen, setDdOpen] = useState(false);

  useEffect(() => {
    let alive = true;
    (async () => {
      setLoading(true); setError(null);
      try {
        // Día consultado
        const { data: r1, error: e1 } = await sb
          .from('vw_control_helper_diario').select('*').eq('fecha', fecha).order('sc');
        if (e1) throw e1;
        // Día anterior (para calcular delta vs ayer)
        const dAyer = new Date(fecha);
        dAyer.setDate(dAyer.getDate() - 1);
        const fechaAyer = dAyer.toISOString().split('T')[0];
        const { data: r2, error: e2 } = await sb
          .from('vw_control_helper_diario').select('fecha,universo,id_ruta,es_chofer')
          .eq('fecha', fechaAyer);
        if (e2) throw e2;
        if (alive) {
          setDatos(r1 || []);
          // Conteos día anterior · solo helpers (es_chofer=false) y rutas únicas para total
          const ayer = { U1: 0, U2: 0, U3: 0, OK: 0, total: 0 };
          const rutasAyer = new Set();
          (r2 || []).forEach(r => {
            rutasAyer.add(r.id_ruta);
            if (r.es_chofer) return; // choferes no entran en universo
            if (r.universo) ayer[r.universo] = (ayer[r.universo] || 0) + 1;
          });
          ayer.total = rutasAyer.size;
          setSerie([{ fecha: fechaAyer, ...ayer }]);
        }
      } catch (e) {
        if (alive) setError(e.message || 'Error');
      } finally {
        if (alive) setLoading(false);
      }
    })();
    return () => { alive = false; };
  }, [fecha]);

  const conteos = useMemo(() => {
    const c = {
      total: 0,                          // ⭐ rutas únicas
      personasTotal: datos.length,       // todas las filas (chofer + helpers)
      choferesEscaneando: 0,             // filas con es_chofer = true
      helpersOperando: 0,                // filas con es_chofer = false
      rutasMulti: 0,
      U1: 0, U2: 0, U3: 0, OK: 0,
      // Match score (solo helpers)
      scoreExcelente: 0,
      scoreBueno: 0,
      scoreMedio: 0,
      sinPadron: 0,
      // BT (solo helpers)
      btAprobado: 0,
      btRechazado: 0,
      btPendiente: 0,
      noEnBt: 0,
      sinCurpParaBt: 0,
    };
    const rutasSet = new Set();
    const rutasCount = {};
    const rutasU1Set = new Set(); // ⭐ v9: U1 cuenta rutas únicas (incluye al chofer)
    datos.forEach(r => {
      rutasSet.add(r.id_ruta);
      rutasCount[r.id_ruta] = (rutasCount[r.id_ruta] || 0) + 1;
      // ⭐ v9: U1 se cuenta a nivel ruta — el chofer también pertenece a U1
      if (r.universo === 'U1') rutasU1Set.add(r.id_ruta);
      if (r.es_chofer) {
        c.choferesEscaneando++;
        return; // chofer no se evalúa en U2/U3/OK ni en cobertura padrón/BT
      }
      // Solo helpers reales (es_chofer = false)
      c.helpersOperando++;
      if (r.universo === 'U2') c.U2++;
      else if (r.universo === 'U3') c.U3++;
      else if (r.universo === 'OK') c.OK++;
      // U1 NO se cuenta acá: ya se contó arriba a nivel ruta
      const s = r.helper_match_score_padron;
      if (s == null) c.sinPadron++;
      else if (s >= 0.9) c.scoreExcelente++;
      else if (s >= 0.7) c.scoreBueno++;
      else c.scoreMedio++;
      const eb = r.helper_estado_bt;
      if (eb === 'BT_APROBADO') c.btAprobado++;
      else if (eb === 'BT_RECHAZADO') c.btRechazado++;
      else if (eb === 'BT_PENDIENTE') c.btPendiente++;
      else if (eb === 'NO_EN_BT') c.noEnBt++;
      else if (eb === 'SIN_CURP_PARA_BUSCAR') c.sinCurpParaBt++;
    });
    c.total = rutasSet.size;
    c.U1 = rutasU1Set.size; // ⭐ v9: rutas únicas no autorizadas
    c.rutasMulti = Object.values(rutasCount).filter(n => n > 2).length;  // 2+ helpers reales
    return c;
  }, [datos]);

  // Conteo del día anterior para mostrar deltas
  const ayerCount = useMemo(() => {
    const ayer = serie[0] || { U1: 0, U2: 0, U3: 0, OK: 0, total: 0 };
    return ayer;
  }, [serie]);
  const getAyer = (uni) => ayerCount[uni] || 0;
  // Backward compat para PanelU1 si todavía usa sparkline
  const getSerieVals = (uni) => [ayerCount[uni] || 0, conteos[uni] || 0];

  const matrizU1 = useMemo(() => {
    // ⭐ v9: U1 ahora incluye filas de chofer Y helpers (toda ruta no autorizada)
    // Las filas del drilldown muestran a todos los que entregaron en la ruta U1
    const vehiculos = ['Small Van MLP', 'Small Van MLP SDD', 'Large Van MLP', 'Large Van MLP SDD'];
    const u1 = datos.filter(r => r.universo === 'U1');
    const scs = [...new Set(u1.map(r => r.sc))].sort();
    const mat = {};
    scs.forEach(sc => { mat[sc] = {}; vehiculos.forEach(v => mat[sc][v] = []); });
    u1.forEach(r => { if (mat[r.sc] && mat[r.sc][r.vehiculo]) mat[r.sc][r.vehiculo].push(r); });
    return { scs, vehiculos, mat };
  }, [datos]);

  const matrizU2 = useMemo(() => {
    // U2 ahora incluye NO_CERTIFICADO (fantasma) Y BT_RECHAZADO (crítico operando)
    const u2 = datos.filter(r => r.universo === 'U2');
    const scs = [...new Set(u2.map(r => r.sc))].sort();
    const mat = {};
    scs.forEach(sc => mat[sc] = { noCert: [], btRech: [], total: 0 });
    u2.forEach(r => {
      if (!mat[r.sc]) return;
      if (r.helper_cert_estado === 'NO_CERTIFICADO') mat[r.sc].noCert.push(r);
      else if (r.helper_cert_estado === 'BT_RECHAZADO') mat[r.sc].btRech.push(r);
      mat[r.sc].total++;
    });
    const totals = {
      noCert: datos.filter(r => r.helper_cert_estado === 'NO_CERTIFICADO').length,
      btRech: datos.filter(r => r.helper_cert_estado === 'BT_RECHAZADO').length,
      sinBt: datos.filter(r => r.helper_cert_estado === 'SIN_BT').length,
      certOk: datos.filter(r => r.helper_cert_estado === 'OK').length,
    };
    return { scs, mat, totals };
  }, [datos]);

  const matrizU3 = useMemo(() => {
    // U3 ahora tiene 4 sub-categorías reales según helper_cert_estado y match_score
    const u3 = datos.filter(r => r.universo === 'U3');
    const scs = [...new Set(u3.map(r => r.sc))].sort();
    const mat = {};
    scs.forEach(sc => mat[sc] = { sinBt: [], btPend: [], meliInact: [], matchDudoso: [], total: 0 });
    u3.forEach(r => {
      if (!mat[r.sc]) return;
      if (r.helper_cert_estado === 'SIN_BT') mat[r.sc].sinBt.push(r);
      else if (r.helper_cert_estado === 'BT_PENDIENTE') mat[r.sc].btPend.push(r);
      else if (r.helper_cert_estado === 'MELI_INACTIVE') mat[r.sc].meliInact.push(r);
      else if (r.helper_estado_padron === 'MATCH_DUDOSO') mat[r.sc].matchDudoso.push(r);
      mat[r.sc].total++;
    });
    const totals = {
      sinBt: u3.filter(r => r.helper_cert_estado === 'SIN_BT').length,
      btPend: u3.filter(r => r.helper_cert_estado === 'BT_PENDIENTE').length,
      meliInact: u3.filter(r => r.helper_cert_estado === 'MELI_INACTIVE').length,
      matchDudoso: u3.filter(r =>
        r.helper_estado_padron === 'MATCH_DUDOSO'
        && r.helper_cert_estado !== 'SIN_BT'
        && r.helper_cert_estado !== 'BT_PENDIENTE'
        && r.helper_cert_estado !== 'MELI_INACTIVE'
      ).length,
    };
    return { scs, mat, totals };
  }, [datos]);

  const UCFG = [
    { badge: "U0", name: "Resumen ejecutivo", kv: conteos.total, ks: "rutas", icon: "ti-layout-dashboard" },
    { badge: "U1", name: "No autorizadas", kv: conteos.U1, ks: "rutas", icon: "ti-ban" },
    { badge: "U2", name: "Certificación", kv: conteos.U2, ks: "helpers", icon: "ti-id-badge" },
    { badge: "U3", name: "Proceso", kv: conteos.U3, ks: "rutas", icon: "ti-route" },
  ];

  if (loading) {
    return <div style={{ padding: 40, textAlign: 'center', color: CH_MUTED, fontSize: 13, fontFamily: "'Geist', sans-serif" }}>Cargando datos del {fecha}…</div>;
  }
  if (error) {
    return (
      <div style={{ padding: 24, fontFamily: "'Geist', sans-serif" }}>
        <div style={{ background: '#fef2f2', border: '1px solid #fecaca', borderRadius: 12, padding: 16 }}>
          <div style={{ fontSize: 13, fontWeight: 600, color: '#991b1b', marginBottom: 6 }}>No se pudo cargar Control Helper</div>
          <div style={{ fontSize: 12, color: '#7f1d1d', lineHeight: 1.6 }}>
            {error}<br /><br />
            <strong>Causa probable:</strong> la vista <code>vw_control_helper_diario</code> aún no existe.
          </div>
        </div>
      </div>
    );
  }

  const u = UCFG[universo];
  const curSerieKey = universo === 0 ? 'total' : ['U1', 'U2', 'U3'][universo - 1];

  return (
    <div style={{ fontFamily: "'Geist', sans-serif", background: CH_BG, color: CH_TEXT }}>

      {/* TAB-BAR (U0/U1/U2/U3) */}
      <div style={{ background: CH_CARD, borderBottom: `1px solid ${CH_BORDER}`, padding: '0 24px', display: 'flex', gap: 2 }}>
        {UCFG.map((cfg, idx) => (
          <div key={idx} onClick={() => setUniverso(idx)} style={{
            padding: '10px 16px', fontSize: 12, fontWeight: 600,
            color: universo === idx ? CH_NAVY : CH_MUTED,
            borderBottom: universo === idx ? `2px solid ${CH_ORANGE}` : '2px solid transparent',
            cursor: 'pointer', display: 'flex', alignItems: 'center', gap: 6,
            whiteSpace: 'nowrap', transition: 'all .12s',
          }}>
            <i className={`ti ${cfg.icon}`} style={{ fontSize: 13 }} />
            {cfg.badge} · {cfg.name}
          </div>
        ))}
      </div>

      {/* SBAR · dinámico según universo */}
      <div style={{ background: CH_CARD, borderBottom: `1px solid ${CH_BORDER}`, padding: '0 24px', display: 'flex', alignItems: 'center', gap: 10, height: 48 }}>
        <span style={{ fontSize: 10, fontWeight: 700, padding: '3px 9px', borderRadius: 5, color: '#fff', background: universo === 0 ? CH_MUTED : CH_NAVY, flexShrink: 0, letterSpacing: 0.3 }}>
          {u.badge}
        </span>
        <span style={{ fontSize: 13, fontWeight: 600, color: CH_TEXT, flexShrink: 0 }}>{u.name}</span>
        <div style={{ width: 1, height: 18, background: CH_BORDER, flexShrink: 0 }} />
        <span style={{ fontSize: 16, fontWeight: 800, color: CH_TEXT, flexShrink: 0, letterSpacing: -0.3 }}>{u.kv}</span>
        <span style={{ fontSize: 11, color: CH_LIGHT, flexShrink: 0 }}>{u.ks} · {fecha}</span>
        <div style={{ width: 1, height: 18, background: CH_BORDER, flexShrink: 0 }} />
        <div style={{ flex: 1, minWidth: 80, maxWidth: 140 }}><Spark vals={getSerieVals(curSerieKey)} height={28} /></div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginLeft: 'auto' }}>
          <button onClick={() => {
            const d = new Date(); d.setDate(d.getDate() - 1);
            setFecha(d.toISOString().split('T')[0]);
          }} style={{
            fontSize: 11, fontWeight: 600, padding: '6px 12px', borderRadius: 6,
            border: `1px solid ${CH_BORDER}`, background: '#f8fafc', color: CH_MUTED,
            cursor: 'pointer', fontFamily: "'Geist', sans-serif",
            whiteSpace: 'nowrap', lineHeight: 1, height: 28,
            display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
          }}>D-1</button>
          <button onClick={() => {
            const now = new Date();
            const mx = new Date(now.getTime() - 6 * 60 * 60 * 1000);
            setFecha(mx.toISOString().split('T')[0]);
          }} style={{
            fontSize: 11, fontWeight: 600, padding: '6px 12px', borderRadius: 6,
            border: `1px solid ${CH_BORDER}`, background: '#f8fafc', color: CH_MUTED,
            cursor: 'pointer', fontFamily: "'Geist', sans-serif",
            whiteSpace: 'nowrap', lineHeight: 1, height: 28,
            display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
          }}>Hoy</button>
          <input type="date" value={fecha} onChange={e => setFecha(e.target.value)} style={{
            fontSize: 12, fontWeight: 600, padding: '5px 10px', borderRadius: 6,
            border: `1px solid ${CH_BORDER}`, background: CH_CARD, color: CH_NAVY,
            fontFamily: "'Geist', sans-serif", cursor: 'pointer', outline: 'none',
            colorScheme: 'light',
          }} />
        </div>
      </div>

      {/* PANELS */}
      <div style={{ padding: '16px 24px' }}>
        {universo === 0 && <PanelU0 conteos={conteos} setUniverso={setUniverso} getAyer={getAyer} ayerCount={ayerCount} />}
        {universo === 1 && <PanelU1 matriz={matrizU1} conteos={conteos} datos={datos} drillDown={drillDown} setDrillDown={setDrillDown} fecha={fecha} getSerieVals={getSerieVals} />}
        {universo === 2 && <PanelU2 matriz={matrizU2} conteos={conteos} datos={datos} drillDown={drillDown} setDrillDown={setDrillDown} fecha={fecha} getAyer={getAyer} />}
        {universo === 3 && <PanelU3 matriz={matrizU3} conteos={conteos} datos={datos} drillDown={drillDown} setDrillDown={setDrillDown} fecha={fecha} getAyer={getAyer} />}
      </div>
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════════════
// PANEL U0 · RESUMEN EJECUTIVO
// ════════════════════════════════════════════════════════════════════════════
function PanelU0({ conteos, setUniverso, getAyer, ayerCount }) {
  // Sólo rutas con helper declarado (filtro fundamental de la vista)
  const cobPad = conteos.total - conteos.sinPadron;     // identificados en padrón
  const cobBt = conteos.btAprobado + conteos.btRechazado + conteos.btPendiente; // con respuesta BT
  return (
    <div>
      {/* Banner aclaratorio · desglose rutas vs personas */}
      <div style={{
        background: '#eff6ff', border: '1px solid #bfdbfe', borderRadius: 12,
        padding: '10px 14px', marginBottom: 14, fontSize: 11, color: '#1e40af',
        display: 'flex', alignItems: 'center', gap: 8,
      }}>
        <i className="ti ti-info-circle" style={{ fontSize: 14 }} />
        <span>
          <strong>{conteos.total} rutas</strong> con helper declarado por MELI ·{' '}
          <strong>{conteos.personasTotal} personas</strong> entregaron paquetes ·{' '}
          <strong>{conteos.helpersOperando} helpers</strong> reales ·{' '}
          <strong>{conteos.choferesEscaneando} choferes</strong> también escanearon
          {conteos.rutasMulti > 0 && <> · {conteos.rutasMulti} ruta{conteos.rutasMulti > 1 ? 's' : ''} con 2+ helpers</>}
        </span>
      </div>

      {/* Flowbar segmentado · solo categorías (el total ya está en el banner azul) */}
      <div style={{ height: 36, display: 'flex', borderRadius: 10, overflow: 'hidden', marginBottom: 16, fontSize: 11, fontWeight: 700, color: '#fff', border: `0.5px solid ${CH_BORDER}` }}>
        {conteos.U1 > 0 && <div style={{ flex: Math.max(conteos.U1, conteos.total * 0.08), background: CH_RED, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>U1 · {conteos.U1}</div>}
        {conteos.U2 > 0 && <div style={{ flex: Math.max(conteos.U2, conteos.total * 0.08), background: CH_ORANGE, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>U2 · {conteos.U2}</div>}
        {conteos.U3 > 0 && <div style={{ flex: Math.max(conteos.U3, conteos.total * 0.08), background: '#eab308', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>U3 · {conteos.U3}</div>}
        {conteos.OK > 0 && <div style={{ flex: Math.max(conteos.OK, conteos.total * 0.08), background: CH_GREEN, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>OK · {conteos.OK}</div>}
      </div>

      {/* Cobertura de cruces */}
      {/* Leyenda de gravedad */}
      <div style={{ display: 'flex', gap: 18, marginBottom: 16, flexWrap: 'wrap', fontSize: 11 }}>
        <LegItem color={CH_RED} label="Gravedad crítica" desc="— impacto financiero directo · acción inmediata" />
        <LegItem color={CH_ORANGE} label="Gravedad media" desc="— riesgo operativo · gestionar esta semana" />
        <LegItem color="#eab308" label="Gravedad baja" desc="— proceso corregible · seguimiento conductor" labelColor="#b45309" />
      </div>

      {/* 4 cards U0 */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 12, marginBottom: 14 }}>
        <U0Card label="U1 · No autorizadas" val={conteos.U1} sub={`${pct(conteos.U1, conteos.total)}% del total`} action="ver universo 1" onClick={() => setUniverso(1)} delta={conteos.U1 - getAyer('U1')} accent={CH_RED} />
        <U0Card label="U2 · Certificación" val={conteos.U2} sub={`${pct(conteos.U2, conteos.total)}% del total`} action="ver universo 2" onClick={() => setUniverso(2)} delta={conteos.U2 - getAyer('U2')} accent={CH_ORANGE} />
        <U0Card label="U3 · Proceso" val={conteos.U3} sub={`${pct(conteos.U3, conteos.total)}% del total`} action="ver universo 3" onClick={() => setUniverso(3)} delta={conteos.U3 - getAyer('U3')} accent="#eab308" />
        <U0Card label="OK · Válidas" val={conteos.OK} sub={`${pct(conteos.OK, conteos.total)}% del total`} action="—" delta={conteos.OK - getAyer('OK')} accent={CH_GREEN} />
      </div>

      {/* Math note */}
      <div style={{ background: CH_CARD, borderRadius: 12, padding: '12px 16px', fontSize: 12, color: CH_MUTED, border: `0.5px solid ${CH_BORDER}` }}>
        <strong style={{ color: CH_NAVY }}>
          {conteos.U1} + {conteos.U2} + {conteos.U3} + {conteos.OK} = {conteos.U1 + conteos.U2 + conteos.U3 + conteos.OK}
        </strong>{' '}
        helpers clasificados {conteos.U1 + conteos.U2 + conteos.U3 + conteos.OK === conteos.helpersOperando ? '✓' : `de ${conteos.helpersOperando} helpers`} ·  Haz clic en cualquier card para ver el drill-down
      </div>
    </div>
  );
}

function U0Card({ label, val, sub, action, onClick, delta, accent }) {
  // Color del delta según si subió/bajó (depende del contexto)
  // Para U1/U2/U3 (rechazos): subir es malo (rojo), bajar es bueno (verde)
  // Para OK: subir es bueno (verde), bajar es malo (rojo)
  const isOK = label.includes('OK');
  const subio = delta > 0;
  const bajo = delta < 0;
  const deltaColor = delta === 0 ? '#9ca3af'
    : (isOK ? (subio ? '#10b981' : '#ef4444') : (subio ? '#ef4444' : '#10b981'));
  const deltaIcon = delta === 0 ? '—' : (subio ? '▲' : '▼');
  const deltaText = delta === 0 ? 'igual ayer' : `${Math.abs(delta)} vs ayer`;

  return (
    <div onClick={onClick} style={{
      background: CH_CARD, border: `0.5px solid ${CH_BORDER}`, borderRadius: 12, padding: 14,
      cursor: onClick ? 'pointer' : 'default', display: 'flex', flexDirection: 'column',
      transition: 'all .12s', minHeight: 130,
    }}
      onMouseEnter={e => onClick && (e.currentTarget.style.borderColor = CH_NAVY)}
      onMouseLeave={e => onClick && (e.currentTarget.style.borderColor = CH_BORDER)}>
      <div style={{ fontSize: 11, fontWeight: 700, textTransform: 'uppercase', letterSpacing: 0.4, color: CH_MUTED, marginBottom: 8 }}>{label}</div>
      <div style={{ fontSize: 24, fontWeight: 800, letterSpacing: -0.5, color: CH_TEXT, lineHeight: 1 }}>{val}</div>
      <div style={{ fontSize: 11, color: CH_LIGHT, marginTop: 5, marginBottom: 10 }}>{sub}</div>
      <div style={{ height: 1, background: CH_BORDER, marginBottom: 10 }} />
      {/* Delta vs ayer */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 6, padding: '4px 0' }}>
        <span style={{ fontSize: 13, fontWeight: 700, color: deltaColor }}>{deltaIcon}</span>
        <span style={{ fontSize: 12, fontWeight: 600, color: deltaColor }}>{deltaText}</span>
      </div>
      <div style={{ height: 1, background: CH_BORDER, margin: '10px 0' }} />
      <div style={{ fontSize: 11, fontWeight: 500, color: CH_MUTED, marginTop: 'auto', display: 'flex', alignItems: 'center', gap: 4 }}>
        <i className="ti ti-arrow-right" style={{ fontSize: 12 }} />{action}
      </div>
    </div>
  );
}

function LegItem({ color, label, desc, labelColor }) {
  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: 6, color: CH_MUTED }}>
      <div style={{ width: 11, height: 11, borderRadius: 3, background: color, flexShrink: 0 }} />
      <span><strong style={{ color: labelColor || color }}>{label}</strong> {desc}</span>
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════════════
// PANEL U1 · NO AUTORIZADAS (mapa SC × vehículo)
// ════════════════════════════════════════════════════════════════════════════
function PanelU1({ matriz, conteos, datos, drillDown, setDrillDown, fecha, getSerieVals }) {
  const scsFor = ['SCQ1', 'SCY1', 'SQR1', 'STL1', 'SHP1', 'STX1', 'SVH1'];
  const scsForOperando = [...new Set(datos.filter(r => scsFor.includes(r.sc)).map(r => r.sc))];
  // ⭐ v9: contar RUTAS únicas — datos tiene 1 fila por persona
  const totalForaneo = new Set(
    datos.filter(r => scsFor.includes(r.sc) && r.helper_flag).map(r => r.id_ruta)
  ).size;
  const scsSinRutaLimpia = matriz.scs.filter(sc => {
    const rutasTodas = new Set(datos.filter(r => r.sc === sc && r.helper_flag).map(r => r.id_ruta));
    const rutasU1 = new Set(datos.filter(r => r.sc === sc && r.universo === 'U1').map(r => r.id_ruta));
    return rutasTodas.size > 0 && rutasTodas.size === rutasU1.size;
  });

  return (
    <div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 12, marginBottom: 14 }}>
        <KCard l="SVC fuera de tarifa" v={matriz.scs.length} s={`de ${scsForOperando.length || 7} SVC foráneos`} a="universo" sk={getSerieVals('U1')} accent={CH_RED} />
        <KCard l="Rutas no autorizadas" v={conteos.U1} s={`de ${totalForaneo || conteos.total} rutas`} a="volumen" sk={getSerieVals('U1')} accent={CH_RED} />
        <KCard l="% universo expuesto" v={`${pct(conteos.U1, totalForaneo)}%`} s="del total foráneo" a="magnitud" sk={getSerieVals('U1')} accent={CH_RED} />
        <KCard l="SVC sin ruta limpia" v={scsSinRutaLimpia.length} s={scsSinRutaLimpia.slice(0, 4).join('·') || '—'} a="alerta" sk={getSerieVals('U1')} accent={CH_RED} />
      </div>

      <SLabel text="Mapa de calor SVC × Vehículo" badge="Datos reales" badgeColor="blue" fecha={fecha} />
      <div style={{ background: CH_CARD, borderRadius: 12, border: `0.5px solid ${CH_BORDER}`, overflow: 'hidden' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr>
              <ThHm align="left">SVC</ThHm>
              {matriz.vehiculos.map(v => <ThHm key={v}>{v.replace('Van MLP SDD', 'Van SDD')}</ThHm>)}
              <ThHm>Total</ThHm>
            </tr>
          </thead>
          <tbody>
            {matriz.scs.length === 0 ? (
              <tr><td colSpan={6} style={{ padding: 24, textAlign: 'center', color: CH_LIGHT, fontSize: 12 }}>Sin rutas U1 para esta fecha</td></tr>
            ) : <>
              {matriz.scs.map(sc => {
                // ⭐ v9: contar RUTAS únicas (no filas, que incluyen driver+helpers)
                const total = matriz.vehiculos.reduce(
                  (s, v) => s + new Set(matriz.mat[sc][v].map(r => r.id_ruta)).size, 0
                );
                return (
                  <tr key={sc}>
                    <TdSn>{sc}</TdSn>
                    {matriz.vehiculos.map(v => {
                      const rutas = matriz.mat[sc][v];
                      const n = new Set(rutas.map(r => r.id_ruta)).size; // ⭐ v9: rutas únicas
                      const sel = drillDown && drillDown.uid === 1 && drillDown.svc === sc && drillDown.vehiculo === v;
                      return <TdHeat key={v} n={n} selected={sel}
                        onClick={() => n > 0 && setDrillDown({ uid: 1, svc: sc, vehiculo: v, n, rutas })} />;
                    })}
                    <TdTc>{total}</TdTc>
                  </tr>
                );
              })}
              <tr style={{ background: '#f8fafc', borderTop: `1px solid ${CH_BORDER}` }}>
                <TdSn total>Total</TdSn>
                {matriz.vehiculos.map(v => {
                  const t = matriz.scs.reduce(
                    (s, sc) => s + new Set(matriz.mat[sc][v].map(r => r.id_ruta)).size, 0
                  );
                  return <TdTotal key={v}>{t}</TdTotal>;
                })}
                <TdTotal strong>{conteos.U1}</TdTotal>
              </tr>
            </>}
          </tbody>
        </table>
        <HmLegend hint="Clic en celda → ver rutas" />
      </div>

      {drillDown && drillDown.uid === 1 && <DrillDown1 dd={drillDown} datos={datos} fecha={fecha} onClose={() => setDrillDown(null)} />}
      {!drillDown && matriz.scs.length > 0 && <Hint text="Haz clic en cualquier celda coloreada para ver las rutas" />}
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════════════
// PANEL U2 · CERTIFICACIÓN
// ════════════════════════════════════════════════════════════════════════════
function PanelU2({ matriz, conteos, datos, drillDown, setDrillDown, fecha, getAyer }) {
  const t = matriz.totals;

  return (
    <div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 12, marginBottom: 14 }}>
        <KCard l="🚨 BT Rechazados" v={t.btRech} s="MELI activo + BT rechazó" a="alerta crítica" delta={conteos.U2 - getAyer('U2')} deltaIsBad={true} />
        <KCard l="🚨 No certificados" v={t.noCert} s="helpers fantasma" a="investigar" delta={null} />
        <KCard l="🟡 Sin validar BT" v={t.sinBt} s="MELI activo · falta BT" a="informativo" delta={null} />
        <KCard l="✅ Certificados OK" v={t.certOk} s="MELI activo + BT aprobado" a="normal" delta={conteos.OK - getAyer('OK')} deltaIsBad={false} />
      </div>

      {/* BANNER WARNING para NO_CERTIFICADO */}
      {t.noCert > 0 && (
        <div style={{
          background: '#fef2f2', border: '1px solid #fecaca', borderRadius: 12,
          padding: '12px 16px', marginBottom: 14, fontSize: 12, color: '#7f1d1d',
        }}>
          <div style={{ fontWeight: 700, marginBottom: 4, fontSize: 13 }}>
            ⚠️ {t.noCert} helper{t.noCert > 1 ? 's' : ''} no identificado{t.noCert > 1 ? 's' : ''} · investigar manualmente
          </div>
          <div style={{ lineHeight: 1.5, color: '#991b1b' }}>
            MELI capturó nombres que no coinciden con el padrón ni con BBDD BT.
            Revisa el nombre raw en la tabla y verifica si es alias, error de escaneo, o helper fantasma real.
          </div>
        </div>
      )}

      <SLabel text="Helpers críticos por SC · MELI + BT" badge="cruce padrón MELI + BBDD BT" badgeColor="orange" fecha={fecha} />
      <div style={{ background: CH_CARD, borderRadius: 12, border: `0.5px solid ${CH_BORDER}`, overflow: 'hidden' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr>
              <ThHm align="left">SVC</ThHm>
              <ThHm>🚨 BT Rechazado</ThHm>
              <ThHm>🚨 No certificado</ThHm>
              <ThHm>Total críticos</ThHm>
            </tr>
          </thead>
          <tbody>
            {matriz.scs.length === 0 ? (
              <tr><td colSpan={4} style={{ padding: 24, textAlign: 'center', color: CH_LIGHT, fontSize: 12 }}>Sin helpers críticos para esta fecha</td></tr>
            ) : <>
              {matriz.scs.map(sc => {
                const cell = matriz.mat[sc];
                const selRech = drillDown && drillDown.uid === 2 && drillDown.svc === sc && drillDown.col === 'btRech';
                const selNoCert = drillDown && drillDown.uid === 2 && drillDown.svc === sc && drillDown.col === 'noCert';
                return (
                  <tr key={sc}>
                    <TdSn>{sc}</TdSn>
                    <TdHeat n={cell.btRech.length} selected={selRech} onClick={() => cell.btRech.length > 0 && setDrillDown({ uid: 2, svc: sc, col: 'btRech', n: cell.btRech.length, rutas: cell.btRech, label: 'BT Rechazado' })} />
                    <TdHeat n={cell.noCert.length} selected={selNoCert} onClick={() => cell.noCert.length > 0 && setDrillDown({ uid: 2, svc: sc, col: 'noCert', n: cell.noCert.length, rutas: cell.noCert, label: 'No certificado' })} />
                    <TdTc>{cell.total}</TdTc>
                  </tr>
                );
              })}
              <tr style={{ background: '#f8fafc', borderTop: `1px solid ${CH_BORDER}` }}>
                <TdSn total>Total</TdSn>
                <TdTotal>{t.btRech}</TdTotal>
                <TdTotal>{t.noCert}</TdTotal>
                <TdTotal strong>{conteos.U2}</TdTotal>
              </tr>
            </>}
          </tbody>
        </table>
        <HmLegend note="Clic en celda para ver detalle del helper" hint="Score < 0.7 → match dudoso · revisar nombre raw" />
      </div>

      {drillDown && drillDown.uid === 2 && <DrillDown2 dd={drillDown} datos={datos} fecha={fecha} onClose={() => setDrillDown(null)} />}
      {!drillDown && matriz.scs.length > 0 && <Hint text="Haz clic en cualquier celda coloreada para ver los helpers" />}
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════════════
// PANEL U3 · PROCESO
// ════════════════════════════════════════════════════════════════════════════
function PanelU3({ matriz, conteos, datos, drillDown, setDrillDown, fecha, getAyer }) {
  const t = matriz.totals;
  const scPrincipal = matriz.scs.length > 0
    ? [...matriz.scs].sort((a, b) => matriz.mat[b].total - matriz.mat[a].total)[0]
    : '—';

  return (
    <div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 12, marginBottom: 14 }}>
        <KCard l="🟡 Sin validar BT" v={t.sinBt} s="MELI activo · falta cargar BT" a="acción RH" delta={null} />
        <KCard l="🟠 BT pendiente" v={t.btPend} s="MELI activo · BT en revisión" a="esperar BT" delta={null} />
        <KCard l="⚪ MELI inactivo" v={t.meliInact} s="no activo en padrón" a="verificar" delta={null} />
        <KCard l="🔍 Match dudoso" v={t.matchDudoso} s="score < 0.7" a="revisar nombre" delta={null} />
      </div>

      <div style={{
        background: '#fffbeb', border: '1px solid #fde68a', borderRadius: 12,
        padding: '12px 16px', marginBottom: 14, fontSize: 12, color: '#78350f',
      }}>
        <div style={{ fontWeight: 700, marginBottom: 4, fontSize: 13 }}>
          🟡 {conteos.U3} warning{conteos.U3 !== 1 ? 's' : ''} · revisar pendientes operativos
        </div>
        <div style={{ lineHeight: 1.5 }}>
          Estos helpers están operando pero no cumplen los 3 requisitos para "OK" (MELI activo + BT aprobado + score ≥ 0.7).
          {scPrincipal !== '—' && ` SC con más casos: ${scPrincipal}.`}
        </div>
      </div>

      <SLabel text="Warnings por SC · estado de cada helper" badge="acción operativa" badgeColor="yellow" fecha={fecha} />
      <div style={{ background: CH_CARD, borderRadius: 12, border: `0.5px solid ${CH_BORDER}`, overflow: 'hidden' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr>
              <ThHm align="left">SVC</ThHm>
              <ThHm>🟡 Sin BT</ThHm>
              <ThHm>🟠 BT pend.</ThHm>
              <ThHm>⚪ MELI inact.</ThHm>
              <ThHm>🔍 Match dudoso</ThHm>
              <ThHm>Total</ThHm>
            </tr>
          </thead>
          <tbody>
            {matriz.scs.length === 0 ? (
              <tr><td colSpan={6} style={{ padding: 24, textAlign: 'center', color: CH_LIGHT, fontSize: 12 }}>Sin warnings para esta fecha</td></tr>
            ) : <>
              {matriz.scs.map(sc => {
                const m = matriz.mat[sc];
                const selSinBt = drillDown?.uid === 3 && drillDown?.svc === sc && drillDown?.col === 'sinBt';
                const selBtPend = drillDown?.uid === 3 && drillDown?.svc === sc && drillDown?.col === 'btPend';
                const selMeliInact = drillDown?.uid === 3 && drillDown?.svc === sc && drillDown?.col === 'meliInact';
                const selMatch = drillDown?.uid === 3 && drillDown?.svc === sc && drillDown?.col === 'matchDudoso';
                return (
                  <tr key={sc}>
                    <TdSn>{sc}</TdSn>
                    <TdHeat n={m.sinBt.length} selected={selSinBt} onClick={() => m.sinBt.length > 0 && setDrillDown({ uid: 3, svc: sc, col: 'sinBt', label: 'Sin BT', n: m.sinBt.length, rutas: m.sinBt })} />
                    <TdHeat n={m.btPend.length} selected={selBtPend} onClick={() => m.btPend.length > 0 && setDrillDown({ uid: 3, svc: sc, col: 'btPend', label: 'BT pendiente', n: m.btPend.length, rutas: m.btPend })} />
                    <TdHeat n={m.meliInact.length} selected={selMeliInact} onClick={() => m.meliInact.length > 0 && setDrillDown({ uid: 3, svc: sc, col: 'meliInact', label: 'MELI inactivo', n: m.meliInact.length, rutas: m.meliInact })} />
                    <TdHeat n={m.matchDudoso.length} selected={selMatch} onClick={() => m.matchDudoso.length > 0 && setDrillDown({ uid: 3, svc: sc, col: 'matchDudoso', label: 'Match dudoso', n: m.matchDudoso.length, rutas: m.matchDudoso })} />
                    <TdTc>{m.total}</TdTc>
                  </tr>
                );
              })}
              <tr style={{ background: '#f8fafc', borderTop: `1px solid ${CH_BORDER}` }}>
                <TdSn total>Total</TdSn>
                <TdTotal>{t.sinBt}</TdTotal>
                <TdTotal>{t.btPend}</TdTotal>
                <TdTotal>{t.meliInact}</TdTotal>
                <TdTotal>{t.matchDudoso}</TdTotal>
                <TdTotal strong>{conteos.U3}</TdTotal>
              </tr>
            </>}
          </tbody>
        </table>
        <HmLegend note="Sin BT y BT pendiente requieren acción de RH · MELI inactivo verificar con coordinador" hint="Clic en celda → ver helpers" />
      </div>

      {drillDown && drillDown.uid === 3 && <DrillDown3 dd={drillDown} datos={datos} fecha={fecha} onClose={() => setDrillDown(null)} />}
      {!drillDown && matriz.scs.length > 0 && <Hint text="Haz clic en cualquier celda coloreada para ver los helpers" />}
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════════════
// DRILL-DOWNS
// ════════════════════════════════════════════════════════════════════════════
function DrillDown1({ dd, datos, fecha, onClose }) {
  // ⭐ v9: expandir a tripulación completa de las rutas afectadas
  const filas = expandirTripulacion(dd.rutas, datos);
  // ⭐ v9.2: pre-calcular cuántas filas tiene cada ruta para usar rowSpan
  const rutaCount = {};
  filas.forEach(r => { rutaCount[r.id_ruta] = (rutaCount[r.id_ruta] || 0) + 1; });

  const exportar = () => exportCH(
    ["Disparador", "Driver (chofer)", "Driver ID", "Ruta", "SC", "Vehículo",
     "Es chofer", "Persona", "Persona Raw", "Persona ID",
     "Match Padrón MELI", "Nombre padrón", "CURP padrón", "Score padrón",
     "Match BT", "Nombre BT", "Respuesta BT", "Empresa BT",
     "Universo persona", "Cert estado",
     "% Persona", "% Participación helper ruta", "Alertas Maestro",
     "Razón", "Acción"],
    filas.map(r => [
      r._esDisparador ? '⭐ SÍ' : '',
      r.chofer_nombre || '—',
      r.chofer_user_id || '—',
      r.id_ruta,
      r.sc,
      r.vehiculo || '—',
      r.es_chofer ? 'SÍ (driver)' : 'NO (helper)',
      r.helper_nombre_limpio || '—',
      r.helpers_nombres || '—',
      r.helper_ids_personas || '—',
      r.helper_estado_padron || '—',
      r.helper_name_padron || '—',
      r.helper_curp_padron || '—',
      r.helper_match_score_padron != null ? r.helper_match_score_padron : '—',
      r.helper_estado_bt || '—',
      r.helper_nombre_bt || '—',
      r.helper_respuesta_bt || '—',
      r.helper_empresa_bt || '—',
      r.universo || '—',
      r.helper_cert_estado || '—',
      r.helper_pct || '—',
      r.pct_participacion_helper != null ? r.pct_participacion_helper : '—',
      (r.helper_alertas || []).join(' · '),
      `Tarifa helper NO autorizada — ${r.sc} · ${r.vehiculo || ''}`,
      'Bloquear · gestionar con MELI',
    ]),
    `BT_U1_${dd.svc}_${(dd.vehiculo || '').replace(/[^a-zA-Z0-9]/g, '_')}.csv`
  );
  return (
    <DrillWrap dd={dd} fecha={fecha} onClose={onClose} icon="ti-map-pin" onExport={exportar}>
      <table style={{ width: '100%', borderCollapse: 'collapse' }}>
        <thead><tr>
          <ThDt>Driver</ThDt>
          <ThDt>Ruta</ThDt>
          <ThDt>SC</ThDt>
          <ThDt>Persona que entregó</ThDt>
          <ThDt>Match Padrón MELI</ThDt>
          <ThDt>Match BT</ThDt>
          <ThDt>% Persona</ThDt>
          <ThDt>Alertas Maestro</ThDt>
          <ThDt>Acción</ThDt>
        </tr></thead>
        <tbody>{filas.map((r, i) => {
          const esPrimeraDeRuta = i === 0 || filas[i - 1].id_ruta !== r.id_ruta;
          const span = rutaCount[r.id_ruta];
          return (
            <DrillRow key={`${r.id_ruta}-${r.helper_idx}-${i}`} r={r} esPrimeraDeRuta={esPrimeraDeRuta && i > 0}>
              {esPrimeraDeRuta && <TdDt rowSpan={span}><DriverCell r={r} /></TdDt>}
              {esPrimeraDeRuta && <TdDt mono rowSpan={span}>{r.id_ruta}</TdDt>}
              {esPrimeraDeRuta && <TdDt mono rowSpan={span}>{r.sc}</TdDt>}
              <TdDt>
                <NombreHelper limpio={r.helper_nombre_limpio} raw={r.helpers_nombres} idx={r.helper_idx} count={r.helper_count} esChofer={r.es_chofer} esDisparador={r._esDisparador} />
                {r.helper_ids_personas && (
                  <div style={{ fontFamily: 'monospace', fontSize: 9, color: CH_LIGHT, marginTop: 2 }}>
                    id: {r.helper_ids_personas}
                  </div>
                )}
              </TdDt>
              <TdDt><PadronCell r={r} /></TdDt>
              <TdDt><BtCell r={r} /></TdDt>
              <TdDt center><PctHelperCell pct={r.helper_pct} /></TdDt>
              <TdDt>
                <AlertasInline alertas={r.helper_alertas} />
              </TdDt>
              <TdDt action>🚫 No autorizada · gestionar con MELI</TdDt>
            </DrillRow>
          );
        })}</tbody>
      </table>
    </DrillWrap>
  );
}

function DrillDown2({ dd, datos, fecha, onClose }) {
  const isBtRech = dd.col === 'btRech';
  const icon = isBtRech ? 'ti-shield-x' : 'ti-id-badge';
  const accionTxt = isBtRech
    ? '🔴 BT lo rechazó · NO debería operar · contactar SC inmediato'
    : '🔴 No identificado · investigar si es helper fantasma o alias';

  // ⭐ v9: expandir a tripulación completa de las rutas afectadas
  const filas = expandirTripulacion(dd.rutas, datos);
  // ⭐ v9.2: pre-calcular cuántas filas tiene cada ruta para usar rowSpan
  const rutaCount = {};
  filas.forEach(r => { rutaCount[r.id_ruta] = (rutaCount[r.id_ruta] || 0) + 1; });

  const exportar = () => exportCH(
    ["Disparador", "Driver (chofer)", "Driver ID", "Ruta", "SC",
     "Es chofer", "Helper", "Helper Raw", "Helper ID",
     "Match Padrón MELI", "Nombre padrón", "CURP padrón", "Score padrón",
     "Match BT", "Nombre BT", "Respuesta BT", "Empresa BT",
     "Universo persona", "Cert estado",
     "% Helper", "Alertas Maestro", "Acción"],
    filas.map(r => [
      r._esDisparador ? '⭐ SÍ' : '',
      r.chofer_nombre || '—',
      r.chofer_user_id || '—',
      r.id_ruta,
      r.sc,
      r.es_chofer ? 'SÍ (driver)' : 'NO (helper)',
      r.helper_nombre_limpio || '—',
      r.helpers_nombres || '—',
      r.helper_ids_personas || '—',
      r.helper_estado_padron || '—',
      r.helper_name_padron || '—',
      r.helper_curp_padron || '—',
      r.helper_match_score_padron != null ? r.helper_match_score_padron : '—',
      r.helper_estado_bt || '—',
      r.helper_nombre_bt || '—',
      r.helper_respuesta_bt || '—',
      r.helper_empresa_bt || '—',
      r.universo || '—',
      r.helper_cert_estado || '—',
      r.helper_pct || '—',
      (r.helper_alertas || []).join(' · '),
      r._esDisparador ? (isBtRech ? 'Contactar SC inmediato' : 'Verificar identidad') : 'Contexto · misma ruta',
    ]),
    `BT_U2_${dd.col}_${dd.svc}.csv`
  );

  return (
    <DrillWrap dd={dd} fecha={fecha} onClose={onClose} icon={icon} onExport={exportar}>
      <table style={{ width: '100%', borderCollapse: 'collapse' }}>
        <thead><tr>
          <ThDt>Driver</ThDt>
          <ThDt>Ruta</ThDt>
          <ThDt>SC</ThDt>
          <ThDt>Persona que entregó</ThDt>
          <ThDt>Match Padrón MELI</ThDt>
          <ThDt>Match BT</ThDt>
          <ThDt>% Persona</ThDt>
        </tr></thead>
        <tbody>{filas.map((r, i) => {
          const esPrimeraDeRuta = i === 0 || filas[i - 1].id_ruta !== r.id_ruta;
          const span = rutaCount[r.id_ruta];
          return (
            <DrillRow key={`${r.id_ruta}-${r.helper_idx}-${i}`} r={r} esPrimeraDeRuta={esPrimeraDeRuta && i > 0}>
              {esPrimeraDeRuta && <TdDt rowSpan={span}><DriverCell r={r} /></TdDt>}
              {esPrimeraDeRuta && <TdDt mono rowSpan={span}>{r.id_ruta}</TdDt>}
              {esPrimeraDeRuta && <TdDt mono rowSpan={span}>{r.sc}</TdDt>}
              <TdDt>
                <NombreHelper limpio={r.helper_nombre_limpio} raw={r.helpers_nombres} idx={r.helper_idx} count={r.helper_count} esChofer={r.es_chofer} esDisparador={r._esDisparador} />
                {r.helper_ids_personas && (
                  <div style={{ fontFamily: 'monospace', fontSize: 9, color: CH_LIGHT, marginTop: 2 }}>
                    id: {r.helper_ids_personas}
                  </div>
                )}
              </TdDt>
              <TdDt><PadronCell r={r} /></TdDt>
              <TdDt><BtCell r={r} /></TdDt>
              <TdDt center><PctHelperCell pct={r.helper_pct} /></TdDt>
            </DrillRow>
          );
        })}</tbody>
      </table>
    </DrillWrap>
  );
}

function DrillDown3({ dd, datos, fecha, onClose }) {
  const config = {
    sinBt: { pill: 'yellow', pillTxt: 'SIN BT', accion: 'RH cargar en BBDD BT', icon: 'ti-file-x' },
    btPend: { pill: 'orange', pillTxt: 'BT PENDIENTE', accion: 'Esperar respuesta de BT', icon: 'ti-clock' },
    meliInact: { pill: 'gray', pillTxt: 'MELI INACTIVE', accion: 'Verificar status con coordinador', icon: 'ti-user-off' },
    matchDudoso: { pill: 'yellow', pillTxt: 'SCORE BAJO', accion: 'Verificar identidad · revisar nombre raw', icon: 'ti-search' },
  };
  const cfg = config[dd.col] || config.sinBt;

  // ⭐ v9: expandir a tripulación completa de las rutas afectadas
  const filas = expandirTripulacion(dd.rutas, datos);
  // ⭐ v9.2: pre-calcular cuántas filas tiene cada ruta para usar rowSpan
  const rutaCount = {};
  filas.forEach(r => { rutaCount[r.id_ruta] = (rutaCount[r.id_ruta] || 0) + 1; });

  const exportar = () => exportCH(
    ["Disparador", "Driver (chofer)", "Driver ID", "Ruta", "SC",
     "Es chofer", "Helper", "Helper Raw", "Helper ID",
     "Match Padrón MELI", "Nombre padrón", "CURP padrón", "Score padrón",
     "Match BT", "Nombre BT", "Respuesta BT", "Empresa BT",
     "Universo persona", "Cert estado",
     "% Helper", "Alertas Maestro", "Acción"],
    filas.map(r => [
      r._esDisparador ? '⭐ SÍ' : '',
      r.chofer_nombre || '—',
      r.chofer_user_id || '—',
      r.id_ruta,
      r.sc,
      r.es_chofer ? 'SÍ (driver)' : 'NO (helper)',
      r.helper_nombre_limpio || '—',
      r.helpers_nombres || '—',
      r.helper_ids_personas || '—',
      r.helper_estado_padron || '—',
      r.helper_name_padron || '—',
      r.helper_curp_padron || '—',
      r.helper_match_score_padron != null ? r.helper_match_score_padron : '—',
      r.helper_estado_bt || '—',
      r.helper_nombre_bt || '—',
      r.helper_respuesta_bt || '—',
      r.helper_empresa_bt || '—',
      r.universo || '—',
      r.helper_cert_estado || '—',
      r.helper_pct || '—',
      (r.helper_alertas || []).join(' · '),
      r._esDisparador ? cfg.accion : 'Contexto · misma ruta',
    ]),
    `BT_U3_${dd.col}_${dd.svc}.csv`
  );

  return (
    <DrillWrap dd={dd} fecha={fecha} onClose={onClose} icon={cfg.icon} onExport={exportar}>
      <table style={{ width: '100%', borderCollapse: 'collapse' }}>
        <thead><tr>
          <ThDt>Driver</ThDt>
          <ThDt>Ruta</ThDt>
          <ThDt>SC</ThDt>
          <ThDt>Persona que entregó</ThDt>
          <ThDt>Match Padrón MELI</ThDt>
          <ThDt>Match BT</ThDt>
          <ThDt>% Persona</ThDt>
        </tr></thead>
        <tbody>{filas.map((r, i) => {
          const esPrimeraDeRuta = i === 0 || filas[i - 1].id_ruta !== r.id_ruta;
          const span = rutaCount[r.id_ruta];
          return (
            <DrillRow key={`${r.id_ruta}-${r.helper_idx}-${i}`} r={r} esPrimeraDeRuta={esPrimeraDeRuta && i > 0}>
              {esPrimeraDeRuta && <TdDt rowSpan={span}><DriverCell r={r} /></TdDt>}
              {esPrimeraDeRuta && <TdDt mono rowSpan={span}>{r.id_ruta}</TdDt>}
              {esPrimeraDeRuta && <TdDt mono rowSpan={span}>{r.sc}</TdDt>}
              <TdDt>
                <NombreHelper limpio={r.helper_nombre_limpio} raw={r.helpers_nombres} idx={r.helper_idx} count={r.helper_count} esChofer={r.es_chofer} esDisparador={r._esDisparador} />
                {r.helper_ids_personas && (
                  <div style={{ fontFamily: 'monospace', fontSize: 9, color: CH_LIGHT, marginTop: 2 }}>
                    id: {r.helper_ids_personas}
                  </div>
                )}
              </TdDt>
              <TdDt><PadronCell r={r} /></TdDt>
              <TdDt><BtCell r={r} /></TdDt>
              <TdDt center><PctHelperCell pct={r.helper_pct} /></TdDt>
            </DrillRow>
          );
        })}</tbody>
      </table>
    </DrillWrap>
  );
}

function DrillWrap({ dd, fecha, onClose, icon, onExport, children }) {
  return (
    <div style={{ marginTop: 14 }}>
      <div style={{
        display: 'flex', alignItems: 'center', gap: 8, padding: '10px 14px', background: '#f8fafc',
        borderRadius: 12, marginBottom: 10, fontSize: 12, border: `0.5px solid ${CH_BORDER}`,
      }}>
        <i className={`ti ${icon}`} style={{ fontSize: 16, color: CH_NAVY }} />
        <span style={{ fontWeight: 700, color: CH_NAVY, fontSize: 13 }}>{dd.svc}</span>
        {(dd.vehiculo || dd.label) && (
          <>
            <i className="ti ti-chevron-right" style={{ fontSize: 12, color: CH_LIGHT }} />
            <span style={{ color: CH_MUTED }}>{dd.vehiculo || dd.label}</span>
          </>
        )}
        {/* Mini-leyenda del resaltado · ⭐ v9.2 */}
        <span style={{
          marginLeft: 12, display: 'inline-flex', alignItems: 'center', gap: 5,
          fontSize: 10, color: CH_MUTED,
        }}>
          <span style={{
            background: '#fed7aa', color: '#9a3412',
            fontSize: 9, fontWeight: 700, padding: '1px 5px', borderRadius: 4,
            whiteSpace: 'nowrap',
          }}>⭐ CASO</span>
          <span style={{ color: CH_LIGHT }}>= persona que cumple el filtro · resto = tripulación de la misma ruta</span>
        </span>
        <span style={{
          background: '#fee2e2', color: '#991b1b', padding: '3px 9px', borderRadius: 5,
          fontSize: 10, fontWeight: 700, marginLeft: 'auto', letterSpacing: 0.3, textTransform: 'uppercase',
        }}>{dd.n} casos</span>
        <button onClick={onClose} style={{
          background: 'transparent', border: 'none', cursor: 'pointer', fontSize: 16, color: CH_MUTED, padding: '0 4px',
        }}>✕</button>
      </div>
      <div style={{ background: CH_CARD, borderRadius: 12, border: `0.5px solid ${CH_BORDER}`, overflow: 'hidden' }}>
        {children}
        <div style={{
          display: 'flex', alignItems: 'center', justifyContent: 'space-between',
          padding: '10px 14px', borderTop: `1px solid ${CH_BORDER}`, background: '#f8fafc',
        }}>
          <span style={{ fontSize: 10, color: CH_LIGHT, fontStyle: 'italic' }}>
            {dd.n} casos · {dd.svc} · {dd.vehiculo || dd.label || ''} · {fecha}
          </span>
          <button onClick={onExport} style={{
            display: 'flex', alignItems: 'center', gap: 6, fontSize: 11, fontWeight: 600,
            fontFamily: "'Geist', sans-serif", color: '#fff', border: 'none',
            borderRadius: 6, padding: '7px 14px', cursor: 'pointer', background: CH_NAVY,
          }}>
            <i className="ti ti-download" style={{ fontSize: 14 }} />Exportar CSV
          </button>
        </div>
      </div>
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════════════
// AUXILIARES
// ════════════════════════════════════════════════════════════════════════════
function KCard({ l, v, s, a, sk, accent, delta, deltaIsBad }) {
  // Si recibe delta numérico, mostrar comparación con ayer
  // deltaIsBad: si true, subir es malo (rojo) · si false, subir es bueno (verde)
  const showDelta = delta !== undefined && delta !== null;
  let deltaColor = '#9ca3af', deltaIcon = '—', deltaText = 'igual ayer';
  if (showDelta) {
    const subio = delta > 0;
    const bajo = delta < 0;
    if (subio) {
      deltaColor = deltaIsBad ? '#ef4444' : '#10b981';
      deltaIcon = '▲';
      deltaText = `${delta} vs ayer`;
    } else if (bajo) {
      deltaColor = deltaIsBad ? '#10b981' : '#ef4444';
      deltaIcon = '▼';
      deltaText = `${Math.abs(delta)} vs ayer`;
    }
  }
  return (
    <div style={{ background: CH_CARD, borderRadius: 12, border: `0.5px solid ${CH_BORDER}`, padding: '14px 14px 12px', display: 'flex', flexDirection: 'column', minHeight: 130 }}>
      <div style={{ fontSize: 11, fontWeight: 700, color: CH_MUTED, textTransform: 'uppercase', letterSpacing: 0.4, marginBottom: 8 }}>{l}</div>
      <div style={{ fontSize: 22, fontWeight: 800, color: CH_TEXT, letterSpacing: -0.5, lineHeight: 1 }}>{v}</div>
      <div style={{ fontSize: 11, color: CH_LIGHT, marginTop: 5 }}>{s}</div>
      <div style={{ height: 1, background: CH_BORDER, margin: '10px 0' }} />
      {showDelta ? (
        <div style={{ display: 'flex', alignItems: 'center', gap: 6, padding: '4px 0' }}>
          <span style={{ fontSize: 13, fontWeight: 700, color: deltaColor }}>{deltaIcon}</span>
          <span style={{ fontSize: 12, fontWeight: 600, color: deltaColor }}>{deltaText}</span>
        </div>
      ) : (
        <Spark vals={sk} height={28} color={accent} />
      )}
      <div style={{ height: 1, background: CH_BORDER, margin: '10px 0' }} />
      <div style={{ fontSize: 11, fontWeight: 500, color: CH_MUTED, marginTop: 'auto', display: 'flex', alignItems: 'center', gap: 4 }}>
        <i className="ti ti-arrow-right" style={{ fontSize: 12 }} />{a}
      </div>
    </div>
  );
}

function Spark({ vals, height = 28, color }) {
  if (!vals || vals.length < 2) return <svg width="100%" height={height} />;
  const smooth = vals.map((x, i, a) => { const p = a[i - 1] ?? x, n = a[i + 1] ?? x; return (p + x + x + n) / 4; });
  const w = 100, h = height, pad = 2;
  const mn = Math.min(...smooth) - 0.5, mx = Math.max(...smooth) + 0.5;
  const px = i => pad + (i / (smooth.length - 1)) * (w - pad * 2);
  const py = v => h - pad - (v - mn) / (mx - mn || 1) * (h - pad * 2);
  let d = `M${px(0).toFixed(1)},${py(smooth[0]).toFixed(1)}`;
  for (let i = 0; i < smooth.length - 1; i++) {
    const x1 = px(i), y1 = py(smooth[i]), x2 = px(i + 1), y2 = py(smooth[i + 1]), cx = (x1 + x2) / 2;
    d += ` C${cx.toFixed(1)},${y1.toFixed(1)} ${cx.toFixed(1)},${y2.toFixed(1)} ${x2.toFixed(1)},${y2.toFixed(1)}`;
  }
  const lx = px(smooth.length - 1).toFixed(1), ly = py(smooth[smooth.length - 1]).toFixed(1);
  const area = `${d} L${lx},${h} L${px(0).toFixed(1)},${h} Z`;
  const stroke = color || CH_LIGHT;
  return (
    <svg width="100%" height={height} viewBox={`0 0 100 ${height}`} preserveAspectRatio="none">
      <path d={area} fill={stroke} fillOpacity=".12" />
      <path d={d} fill="none" stroke={stroke} strokeWidth="1.2" strokeLinejoin="round" strokeLinecap="round" />
      <circle cx={lx} cy={ly} r="2" fill={stroke} />
    </svg>
  );
}

function SLabel({ text, badge, badgeColor, fecha }) {
  const colors = badgeColor === 'yellow'
    ? { bg: CH_YELLOW, color: CH_YELLOW_TEXT, border: '#fde68a' }
    : { bg: '#dbeafe', color: '#1e40af', border: '#bfdbfe' };
  return (
    <div style={{ fontSize: 10.5, fontWeight: 700, color: CH_MUTED, textTransform: 'uppercase', letterSpacing: 0.5, marginBottom: 8, display: 'flex', alignItems: 'center', gap: 8 }}>
      {text}
      <span style={{
        background: colors.bg, color: colors.color, border: `1px solid ${colors.border}`,
        fontSize: 9, fontWeight: 700, padding: '2px 8px', borderRadius: 5,
        marginLeft: 'auto', display: 'flex', alignItems: 'center', gap: 4, textTransform: 'none',
        letterSpacing: 0.2,
      }}>
        <i className="ti ti-database" style={{ fontSize: 10 }} />{badge} · {fecha}
      </span>
    </div>
  );
}

function Hint({ text }) {
  return (
    <div style={{
      textAlign: 'center', padding: 24, color: CH_LIGHT, fontSize: 12,
      border: `1px dashed ${CH_BORDER}`, borderRadius: 12, marginTop: 12, background: '#fafafa',
    }}>
      <i className="ti ti-hand-click" style={{ fontSize: 24, display: 'block', marginBottom: 6, color: '#d1d5db' }} />
      {text}
    </div>
  );
}

function HmLegend({ note, hint }) {
  return (
    <div style={{ display: 'flex', gap: 14, padding: '10px 14px 12px', flexWrap: 'wrap', alignItems: 'center' }}>
      <div style={{ display: 'flex', alignItems: 'center', gap: 5, fontSize: 10, color: CH_MUTED }}>
        <div style={{ width: 12, height: 12, borderRadius: 3, background: CH_RED }} />Crítico (6+)
      </div>
      <div style={{ display: 'flex', alignItems: 'center', gap: 5, fontSize: 10, color: CH_MUTED }}>
        <div style={{ width: 12, height: 12, borderRadius: 3, background: CH_RED_SOFT }} />Medio (3–5)
      </div>
      <div style={{ display: 'flex', alignItems: 'center', gap: 5, fontSize: 10, color: CH_MUTED }}>
        <div style={{ width: 12, height: 12, borderRadius: 3, background: CH_YELLOW, border: '1px solid #fde68a' }} />Bajo (1–2)
      </div>
      {note && <span style={{ fontSize: 10, color: CH_LIGHT, fontStyle: 'italic' }}>{note}</span>}
      {hint && <span style={{ marginLeft: 'auto', fontSize: 10, color: CH_LIGHT }}>{hint}</span>}
    </div>
  );
}

// Cells
function ThHm({ children, align }) {
  return <th style={{
    padding: '8px 10px', fontSize: 9, fontWeight: 700, textTransform: 'uppercase', letterSpacing: 0.5,
    color: CH_MUTED, textAlign: align || 'center', borderBottom: `1px solid ${CH_BORDER}`,
    background: '#f8fafc', whiteSpace: 'nowrap',
  }}>{children}</th>;
}

function TdSn({ children, total }) {
  return <td style={{
    padding: '9px 12px', border: `0.5px solid ${CH_BORDER}`, textAlign: 'left',
    fontWeight: 700, color: CH_NAVY, background: '#f8fafc',
    fontSize: total ? 12 : 11.5, borderTop: total ? `1px solid ${CH_BORDER}` : undefined,
  }}>{children}</td>;
}

function TdHeat({ n, selected, onClick }) {
  const cls = n === 0 ? { background: '#f8fafc', color: '#d1d5db' }
    : n >= 6 ? { background: CH_RED, color: '#fff', fontWeight: 700 }
    : n >= 3 ? { background: CH_RED_SOFT, color: '#7f1d1d', fontWeight: 700 }
    : { background: CH_YELLOW, color: CH_YELLOW_TEXT, fontWeight: 600 };
  return (
    <td onClick={onClick} style={{
      padding: '9px 10px', border: `0.5px solid ${CH_BORDER}`, textAlign: 'center',
      fontSize: 12.5, cursor: n > 0 ? 'pointer' : 'default',
      outline: selected ? `2.5px solid ${CH_ORANGE}` : undefined,
      outlineOffset: selected ? -2 : undefined, position: 'relative',
      ...cls,
    }}>{n === 0 ? '0' : n}</td>
  );
}

function TdNa({ children }) {
  return <td style={{ padding: '9px 10px', border: `0.5px solid ${CH_BORDER}`, textAlign: 'center', background: '#f8fafc', color: '#d1d5db', fontSize: 11 }}>{children}</td>;
}

function TdTc({ children }) {
  return <td style={{ padding: '9px 10px', border: `0.5px solid ${CH_BORDER}`, textAlign: 'center', background: '#f8fafc', fontWeight: 700, color: CH_TEXT, fontSize: 12 }}>{children}</td>;
}

function TdTotal({ children, strong }) {
  return <td style={{ padding: '9px 10px', textAlign: 'center', background: '#f8fafc', fontWeight: 700, color: strong ? CH_NAVY : CH_TEXT, fontSize: 12 }}>{children}</td>;
}

function ThDt({ children }) {
  return <th style={{
    padding: '9px 12px', fontSize: 9.5, fontWeight: 700, textTransform: 'uppercase', letterSpacing: 0.5,
    color: CH_MUTED, textAlign: 'left', borderBottom: `1px solid ${CH_BORDER}`, background: '#f8fafc',
  }}>{children}</th>;
}

function TdDt({ children, mono, bold, muted, center, action, rowSpan }) {
  return <td rowSpan={rowSpan} style={{
    padding: '9px 12px', borderBottom: '0.5px solid #f4f5f7', fontSize: 12,
    fontFamily: mono ? 'monospace' : "'Geist', sans-serif",
    color: action ? CH_NAVY : muted ? CH_MUTED : CH_TEXT,
    fontWeight: bold || action ? 600 : 'normal',
    textAlign: center ? 'center' : 'left',
    verticalAlign: rowSpan ? 'top' : 'baseline',
  }}>{children}</td>;
}

function Pill({ children, type }) {
  const palette = {
    red:    { background: '#fee2e2', color: '#991b1b' },
    orange: { background: '#fed7aa', color: '#9a3412' },
    yellow: { background: '#fef3c7', color: '#92400e' },
    rose:   { background: '#fce7f3', color: '#9f1239' },
    gray:   { background: '#f3f4f6', color: '#374151' },
    green:  { background: '#d1fae5', color: '#065f46' },
  };
  const styles = palette[type] || palette.yellow;
  return <span style={{ ...styles, fontSize: 9.5, fontWeight: 700, padding: '3px 8px', borderRadius: 5, textTransform: 'uppercase', letterSpacing: 0.3 }}>{children}</span>;
}

// ── Helper: expandir filas disparadoras a tripulación completa de las rutas ──
// ⭐ v9: cuando hacés click en una celda del heatmap, querés ver no solo a las
// personas que cumplen el filtro, sino a TODA la tripulación de esas rutas
// (driver + helpers), marcando cuáles fueron las disparadoras.
function expandirTripulacion(filasDisparadoras, datos) {
  if (!filasDisparadoras || filasDisparadoras.length === 0) return [];
  // Identificar disparadoras por (id_ruta + helper_idx) que es la clave única de cada fila
  const disparadorKey = new Set(
    filasDisparadoras.map(r => `${r.id_ruta}::${r.helper_idx ?? ''}`)
  );
  const rutaIds = new Set(filasDisparadoras.map(r => r.id_ruta));
  // Tomar TODAS las filas de las rutas afectadas
  const todasFilas = datos.filter(r => rutaIds.has(r.id_ruta));
  // Marcar disparadoras + ordenar por ruta, driver primero, luego helpers por idx
  const conFlag = todasFilas.map(r => ({
    ...r,
    _esDisparador: disparadorKey.has(`${r.id_ruta}::${r.helper_idx ?? ''}`),
  }));
  conFlag.sort((a, b) => {
    if (a.id_ruta !== b.id_ruta) return Number(a.id_ruta) - Number(b.id_ruta);
    if (a.es_chofer !== b.es_chofer) return a.es_chofer ? -1 : 1;
    return (a.helper_idx || 0) - (b.helper_idx || 0);
  });
  return conFlag;
}

// ── Componente: fila de drilldown con resaltado de disparadora ──
// ⭐ v9.2: con rowSpan en Driver/Ruta/SC, el border-left no se ve bien.
// El resaltado se hace con fondo + indicador ⭐ en la celda Persona (ver NombreHelper)
function DrillRow({ r, esPrimeraDeRuta, children }) {
  const esDisp = r._esDisparador;
  return (
    <tr style={{
      borderBottom: `0.5px solid #f4f5f7`,
      borderTop: esPrimeraDeRuta ? `2px solid ${CH_BORDER}` : undefined,
      background: esDisp ? '#fffaf2' : 'transparent',
      verticalAlign: 'top',
    }}>
      {children}
    </tr>
  );
}

// ── Componente: celda Driver (chofer) con nombre + user_id ──
function DriverCell({ r }) {
  if (!r.chofer_nombre) return <span style={{ color: CH_LIGHT }}>—</span>;
  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 1 }}>
      <span style={{ fontWeight: 600, fontSize: 11 }}>{r.chofer_nombre}</span>
      {r.chofer_user_id && (
        <span style={{ fontSize: 9, color: CH_LIGHT, fontFamily: 'monospace' }}>
          id: {r.chofer_user_id}
        </span>
      )}
    </div>
  );
}

// ── Componente: nombre limpio del Maestro + raw debajo si difiere ──
function NombreHelper({ limpio, raw, idx, count, esChofer, esDisparador }) {
  if (!limpio && !raw) return <span style={{ color: CH_LIGHT }}>—</span>;
  const showMulti = count > 1;
  // Pill rol DRIVER/HELPER
  const rolPill = esChofer === true ? (
    <span style={{
      background: '#d1fae5', color: '#065f46',
      fontSize: 9, fontWeight: 700, padding: '1px 5px', borderRadius: 4,
      whiteSpace: 'nowrap', marginRight: 4,
    }}>🚛 DRIVER</span>
  ) : esChofer === false ? (
    <span style={{
      background: '#dbeafe', color: '#1e40af',
      fontSize: 9, fontWeight: 700, padding: '1px 5px', borderRadius: 4,
      whiteSpace: 'nowrap', marginRight: 4,
    }}>👤 HELPER</span>
  ) : null;
  // ⭐ v9.2: pill de disparadora (la persona que cumple el filtro del drilldown)
  const dispPill = esDisparador ? (
    <span style={{
      background: '#fed7aa', color: '#9a3412',
      fontSize: 9, fontWeight: 700, padding: '1px 5px', borderRadius: 4,
      whiteSpace: 'nowrap', marginRight: 4,
    }}>⭐ CASO</span>
  ) : null;
  const multiPill = showMulti && (
    <span style={{
      background: '#ede9fe', color: '#5b21b6',
      fontSize: 9, fontWeight: 700, padding: '1px 5px', borderRadius: 4,
      whiteSpace: 'nowrap', marginLeft: 4,
    }}>{idx} de {count}</span>
  );
  const nombreMostrado = limpio || raw;
  // ⭐ v9.3: el raw del Maestro es a nivel ruta (mezcla todas las personas)
  // y solo confunde — se oculta siempre. Si hace falta investigar, está en el CSV exportado.
  return (
    <div style={{ display: 'flex', alignItems: 'center', flexWrap: 'wrap', gap: 2 }}>
      {dispPill}
      {rolPill}
      <span style={{ fontWeight: 600, fontSize: 11 }}>{nombreMostrado}</span>
      {multiPill}
    </div>
  );
}

// ── Componente: pills inline con alertas del Maestro Supervisores ──
function AlertasInline({ alertas }) {
  if (!alertas || alertas.length === 0) return <span style={{ color: CH_LIGHT }}>—</span>;
  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
      {alertas.map((a, idx) => {
        const isRojo = a.includes('Helper >90') || a.includes('Multi-ID');
        const isNaranja = a.includes('Investigar') || a.includes('3+ personas');
        const isGris = a.includes('invisible');
        return (
          <span key={idx} style={{
            background: isRojo ? '#fee2e2' : isNaranja ? '#fef3c7' : isGris ? '#f1f5f9' : '#e0e7ff',
            color: isRojo ? '#dc2626' : isNaranja ? '#b45309' : isGris ? '#475569' : '#4338ca',
            padding: '1px 6px', borderRadius: 4, fontSize: 9, fontWeight: 600, whiteSpace: 'nowrap',
          }}>{a}</span>
        );
      })}
    </div>
  );
}

// ── Componente: celda Match Padrón MELI (independiente) ──
function PadronCell({ r }) {
  const e = r.helper_estado_padron;
  const score = r.helper_match_score_padron;
  if (e === 'NO_EN_PADRON') {
    return (
      <div style={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
        <Pill type="rose">❌ NO EN PADRÓN</Pill>
        <span style={{ fontSize: 9, color: CH_LIGHT, fontStyle: 'italic' }}>fantasma · investigar</span>
      </div>
    );
  }
  const scoreColor = score >= 0.9 ? '#065f46' : score >= 0.7 ? '#15803d' : '#9a3412';
  const pillType =
    e === 'EN_PADRON_ACTIVO' ? 'green' :
    e === 'EN_PADRON_INACTIVO' ? 'gray' :
    e === 'MATCH_DUDOSO' ? 'orange' : 'yellow';
  const pillLabel =
    e === 'EN_PADRON_ACTIVO' ? '✅ ACTIVO' :
    e === 'EN_PADRON_INACTIVO' ? '⚪ INACTIVO' :
    e === 'MATCH_DUDOSO' ? '🔍 DUDOSO' : e;
  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
      <Pill type={pillType}>{pillLabel}</Pill>
      {r.helper_name_padron && (
        <span style={{ fontSize: 10, color: CH_MUTED }}>{r.helper_name_padron}</span>
      )}
      {score != null && (
        <span style={{ fontSize: 9, fontFamily: 'monospace', color: scoreColor, fontWeight: 600 }}>
          score: {Number(score).toFixed(3)}
        </span>
      )}
      {r.helper_curp_padron && (
        <span style={{ fontSize: 9, fontFamily: 'monospace', color: CH_LIGHT }}>
          {r.helper_curp_padron}
        </span>
      )}
    </div>
  );
}

// ── Componente: celda Match BBDD BT (independiente) ──
function BtCell({ r }) {
  const e = r.helper_estado_bt;
  if (e === 'SIN_CURP_PARA_BUSCAR') {
    return (
      <div style={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
        <Pill type="gray">⚪ SIN CURP</Pill>
        <span style={{ fontSize: 9, color: CH_LIGHT, fontStyle: 'italic' }}>no encontrado en padrón</span>
      </div>
    );
  }
  if (e === 'NO_EN_BT') {
    return (
      <div style={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
        <Pill type="yellow">🟡 NO EN BT</Pill>
        <span style={{ fontSize: 9, color: CH_LIGHT, fontStyle: 'italic' }}>cargar en BBDD BT</span>
      </div>
    );
  }
  const pillType =
    e === 'BT_APROBADO' ? 'green' :
    e === 'BT_RECHAZADO' ? 'red' :
    e === 'BT_PENDIENTE' ? 'orange' : 'gray';
  const pillLabel =
    e === 'BT_APROBADO' ? '✅ APROBADO' :
    e === 'BT_RECHAZADO' ? '🔴 RECHAZADO' :
    e === 'BT_PENDIENTE' ? '🟠 PENDIENTE' : e;
  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
      <Pill type={pillType}>{pillLabel}</Pill>
      {r.helper_nombre_bt && (
        <span style={{ fontSize: 10, color: CH_MUTED }}>{r.helper_nombre_bt}</span>
      )}
      {r.helper_empresa_bt && (
        <span style={{ fontSize: 9, color: CH_LIGHT, fontStyle: 'italic' }}>{r.helper_empresa_bt}</span>
      )}
    </div>
  );
}

// ── Componente: celda % Helper con color según severidad ──
function PctHelperCell({ pct }) {
  if (pct == null) return <span style={{ color: CH_LIGHT }}>—</span>;
  const high = pct > 90;
  return (
    <span style={{
      fontFamily: 'monospace', fontSize: 11, fontWeight: 700,
      color: high ? '#dc2626' : '#1a1a1a',
    }}>{pct}%</span>
  );
}

function exportCH(headers, rows, filename) {
  if (!rows || rows.length === 0) return;
  const csv = [
    headers.join(','),
    ...rows.map(r => r.map(v => `"${String(v).replace(/"/g, '""')}"`).join(','))
  ].join('\n');
  const blob = new Blob(['\uFEFF' + csv], { type: 'text/csv;charset=utf-8;' });
  const a = document.createElement('a');
  a.href = URL.createObjectURL(blob);
  a.download = filename;
  a.click();
}

// ════════════════════════════════════════════════════════════════════════════
// VALIDACIÓN BT · Subpestaña dentro de IndicadoresOperacionalesMX
// ════════════════════════════════════════════════════════════════════════════

const VBT_NAVY = "#1a3a6b";
const VBT_ORANGE = "#F47B20";
const VBT_BG = "#f0f2f5";
const VBT_CARD = "#fff";
const VBT_BORDER = "#e4e7ec";
const VBT_TEXT = "#1a1a1a";
const VBT_MUTED = "#64748b";
const VBT_LIGHT = "#94a3b8";
const VBT_RED = "#dc2626";
const VBT_YELLOW = "#fef3c7";
const VBT_GREEN = "#15803d";

function PoolMeliValidacionBT({ usuario }) {
  const [tab, setTab] = useState(0);
  const [bt, setBt] = useState([]);
  const [operando, setOperando] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [filtroGrav, setFiltroGrav] = useState('TODOS');
  const [filtroSvc, setFiltroSvc] = useState('TODOS');
  const [busqueda, setBusqueda] = useState('');
  const [showUpload, setShowUpload] = useState(false);
  const [historialCurp, setHistorialCurp] = useState(null);
  const [multiDriver, setMultiDriver] = useState([]);
  const [multiDriverSinBt, setMultiDriverSinBt] = useState([]);
  const [showMultiDriverModal, setShowMultiDriverModal] = useState(false);
  const esAdmin = usuario?.rol === 'superadmin';

  const cargar = async () => {
    setLoading(true); setError(null);
    try {
      const [r1q, r2q, r3q, r4q] = await Promise.all([
        sb.from('vw_bt_vs_padron').select('*').order('gravedad'),
        sb.from('vw_bt_rechazados_operando').select('*').order('rutas', { ascending: false }),
        sb.from('vw_bt_multi_driver_id').select('*'),
        sb.from('vw_meli_multi_driver_sin_bt').select('*'),
      ]);
      if (r1q.error) throw r1q.error;
      if (r2q.error) throw r2q.error;
      // Las 2 vistas multi-ID son opcionales · si fallan (no existen) seguimos sin ellas
      setBt(r1q.data || []);
      setOperando(r2q.data || []);
      setMultiDriver(r3q.error ? [] : (r3q.data || []));
      setMultiDriverSinBt(r4q.error ? [] : (r4q.data || []));
    } catch (e) { setError(e.message || 'Error'); } finally { setLoading(false); }
  };

  useEffect(() => { cargar(); }, []);

  const kpis = useMemo(() => {
    const hoy = new Date(Date.now() - 6*60*60*1000).toISOString().split('T')[0];
    // Dedup por CURP para obtener PERSONAS únicas (la vista trae filas duplicadas
    // cuando una persona tiene multi-driver_id en el padrón)
    const personasMap = new Map();
    for (const row of bt) {
      if (!row.curp) continue;
      if (!personasMap.has(row.curp)) personasMap.set(row.curp, row);
    }
    const personas = Array.from(personasMap.values());
    return {
      total_bt: personas.length,
      criticos: personas.filter(b => b.gravedad === 'CRITICO').length,
      altos: personas.filter(b => b.gravedad === 'ALTO').length,
      medios: personas.filter(b => b.gravedad === 'MEDIO').length,
      en_padron: personas.filter(b => b.driver_id_padron).length,
      no_padron: personas.filter(b => !b.driver_id_padron).length,
      multi_driver: multiDriver.length,
      multi_driver_critico: multiDriver.filter(m => m.es_critico).length,
      multi_driver_sin_bt: multiDriverSinBt.length,
      operando_personas: new Set(operando.map(o => o.curp)).size,
      operando_rutas: operando.reduce((s, o) => s + (o.rutas || 0), 0),
      operando_hoy: new Set(operando.filter(o => o.hasta === hoy).map(o => o.curp)).size,
    };
  }, [bt, operando, multiDriver, multiDriverSinBt]);

  const btFiltrado = useMemo(() => {
    let f = bt;
    if (filtroGrav !== 'TODOS') f = f.filter(b => b.gravedad === filtroGrav);
    if (filtroSvc !== 'TODOS') f = f.filter(b => b.svc === filtroSvc);
    if (busqueda) {
      const q = busqueda.toLowerCase();
      f = f.filter(b => (b.nombre_bt || '').toLowerCase().includes(q) || (b.curp || '').toLowerCase().includes(q));
    }
    return f;
  }, [bt, filtroGrav, filtroSvc, busqueda]);

  const svcs = useMemo(() => [...new Set(bt.map(b => b.svc).filter(Boolean))].sort(), [bt]);

  if (loading) return <div style={{ padding: 40, textAlign: 'center', color: VBT_MUTED, fontSize: 13, fontFamily: "'Geist', sans-serif" }}>Cargando datos BT…</div>;
  if (error) return (
    <div style={{ padding: 24, fontFamily: "'Geist', sans-serif" }}>
      <div style={{ background: '#fef2f2', border: '1px solid #fecaca', borderRadius: 12, padding: 16 }}>
        <div style={{ fontSize: 13, fontWeight: 600, color: '#991b1b', marginBottom: 6 }}>No se pudo cargar Validación BT</div>
        <div style={{ fontSize: 12, color: '#7f1d1d', lineHeight: 1.6 }}>
          {error}<br/><br/>
          <strong>Causa probable:</strong> falta correr <code>SQL_01_validacion_bt_setup.sql</code> y <code>SQL_02_validacion_bt_carga_inicial.sql</code>
        </div>
      </div>
    </div>
  );

  return (
    <div style={{ fontFamily: "'Geist', sans-serif", background: VBT_BG, color: VBT_TEXT }}>
      <div style={{ background: VBT_CARD, borderBottom: `1px solid ${VBT_BORDER}`, padding: '0 24px', display: 'flex', gap: 2 }}>
        {['Resumen', 'Operando (rechazados/pendientes)', 'Listado completo'].map((label, i) => (
          <div key={i} onClick={() => setTab(i)} style={{
            padding: '10px 16px', fontSize: 12, fontWeight: 600,
            color: tab === i ? VBT_NAVY : VBT_MUTED,
            borderBottom: tab === i ? `2px solid ${VBT_ORANGE}` : '2px solid transparent',
            cursor: 'pointer', display: 'flex', alignItems: 'center', gap: 6, whiteSpace: 'nowrap',
          }}>{label}</div>
        ))}
        <div style={{ marginLeft: 'auto', display: 'flex', alignItems: 'center', gap: 8, paddingRight: 4 }}>
          {esAdmin && (
            <button onClick={() => setShowUpload(true)} style={{
              fontSize: 11, fontWeight: 600, padding: '6px 12px', borderRadius: 6,
              border: `1px solid ${VBT_NAVY}`, background: VBT_NAVY, color: '#fff',
              cursor: 'pointer', fontFamily: "'Geist', sans-serif", whiteSpace: 'nowrap',
              display: 'inline-flex', alignItems: 'center', gap: 5, height: 28, lineHeight: 1,
            }}>
              <i className="ti ti-upload" style={{ fontSize: 13 }} />
              Subir Excel BT
            </button>
          )}
        </div>
      </div>

      <div style={{ padding: '16px 24px' }}>
        {tab === 0 && <ResumenBT kpis={kpis} bt={bt} operando={operando} onOpenMultiDriver={() => setShowMultiDriverModal(true)} />}
        {tab === 1 && <OperandoBT operando={operando} onSelectCurp={setHistorialCurp} />}
        {tab === 2 && <ListadoBT bt={btFiltrado} svcs={svcs}
          filtroGrav={filtroGrav} setFiltroGrav={setFiltroGrav}
          filtroSvc={filtroSvc} setFiltroSvc={setFiltroSvc}
          busqueda={busqueda} setBusqueda={setBusqueda}
          totalSinFiltro={bt.length} onSelectCurp={setHistorialCurp} />}
      </div>

      {showUpload && <UploadExcelBT onClose={() => { setShowUpload(false); cargar(); }} />}
      {historialCurp && <HistorialPersonaModal curp={historialCurp} onClose={() => setHistorialCurp(null)} />}
      {showMultiDriverModal && <MultiDriverIdModal data={multiDriver} sinBt={multiDriverSinBt} onClose={() => setShowMultiDriverModal(false)} onSelectCurp={(c) => { setShowMultiDriverModal(false); setHistorialCurp(c); }} />}
    </div>
  );
}

function ResumenBT({ kpis, bt, operando, onOpenMultiDriver }) {
  const porEmpresa = {};
  operando.forEach(o => {
    if (!porEmpresa[o.empresa]) porEmpresa[o.empresa] = { personas: new Set(), rutas: 0 };
    porEmpresa[o.empresa].personas.add(o.curp);
    porEmpresa[o.empresa].rutas += o.rutas || 0;
  });
  const empresasArr = Object.entries(porEmpresa)
    .map(([e, v]) => ({ empresa: e, personas: v.personas.size, rutas: v.rutas }))
    .sort((a, b) => b.rutas - a.rutas).slice(0, 8);
  const porSvc = {};
  operando.forEach(o => {
    if (!porSvc[o.svc]) porSvc[o.svc] = { personas: new Set(), rutas: 0 };
    porSvc[o.svc].personas.add(o.curp);
    porSvc[o.svc].rutas += o.rutas || 0;
  });
  const svcArr = Object.entries(porSvc).map(([s, v]) => ({ svc: s, personas: v.personas.size, rutas: v.rutas })).sort((a, b) => b.rutas - a.rutas);

  // Subtítulo dinámico del tile Multi-ID
  const multiSub = kpis.multi_driver === 0
    ? 'Sin casos detectados'
    : kpis.multi_driver_critico > 0
      ? `Múltiples driver_id · ${kpis.multi_driver_critico} crítico${kpis.multi_driver_critico === 1 ? '' : 's'}`
      : 'Múltiples driver_id · sin alertas';

  return (
    <div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(5, 1fr)', gap: 12, marginBottom: 14 }}>
        <VBT_KPI
          l="Total BT"
          v={kpis.total_bt}
          s={`${kpis.en_padron} en padrón · ${kpis.no_padron} no en MELI`}
          accent={VBT_NAVY}
          info="Total de personas únicas cargadas en el Excel BT (CURPs distintos). Es el universo de tripulantes que BT validó alguna vez. El subtítulo indica cuántos matchean con el padrón MELI actual y cuántos no aparecen en MELI."
        />
        <VBT_KPI
          l="🔴 Críticos"
          v={kpis.criticos}
          s="Rechazado por MELI"
          accent={VBT_RED}
          info="Personas que el Excel BT marca como RECHAZADO en la columna 'Respuesta MELI'. No deberían estar operando. Si están operando, aparecen en la pestaña 'Operando (rechazados/pendientes)'."
        />
        <VBT_KPI
          l="🟠 Pendientes"
          v={kpis.altos}
          s="Pendiente en MELI"
          accent={VBT_ORANGE}
          info="Personas que el Excel BT marca como PENDIENTE en la columna 'Respuesta MELI'. Falta resolución de MELI antes de que puedan operar normalmente."
        />
        <VBT_KPI
          l="🟡 Alerta BT"
          v={kpis.medios}
          s="Validación BT marcada"
          accent="#eab308"
          info="Personas marcadas como RECHAZADO o PENDIENTE en la columna interna 'Validación BT' del Excel. Es una segunda capa de control que BT lleva aparte del estado de MELI."
        />
        <VBT_KPI
          l="🟣 Multi-ID"
          v={kpis.multi_driver}
          s={multiSub}
          accent="#6366f1"
          info={`Personas con más de un driver_id activo simultáneamente en el padrón MELI (misma CURP, distintos IDs). Puede indicar duplicación administrativa o cambio de carrier. ${kpis.multi_driver_sin_bt > 0 ? `Además hay ${kpis.multi_driver_sin_bt} personas con multi-driver_id en MELI que no están cargadas en BT. ` : ''}Click en la tarjeta para ver el listado completo.`}
          onClick={kpis.multi_driver > 0 ? onOpenMultiDriver : undefined}
        />
      </div>

      {kpis.operando_personas > 0 && (
        <div style={{ background: '#fef2f2', border: '1px solid #fecaca', borderRadius: 12, padding: 16, marginBottom: 14 }}>
          <div style={{ fontSize: 13, fontWeight: 700, color: '#991b1b', marginBottom: 4, display: 'flex', alignItems: 'center', gap: 6 }}>
            <i className="ti ti-alert-triangle" style={{ fontSize: 16 }} />
            Universo crítico · Acción inmediata
          </div>
          <div style={{ fontSize: 12, color: '#7f1d1d', lineHeight: 1.5 }}>
            <strong>{kpis.operando_personas} personas</strong> con flags activos en BT operando últimos 30 días · <strong>{kpis.operando_rutas} rutas</strong> · <strong>{kpis.operando_hoy} operando HOY</strong>
          </div>
        </div>
      )}

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 }}>
        <div style={{ background: VBT_CARD, borderRadius: 12, border: `0.5px solid ${VBT_BORDER}`, overflow: 'hidden' }}>
          <div style={{ padding: '10px 14px', borderBottom: `1px solid ${VBT_BORDER}`, background: '#f8fafc' }}>
            <div style={{ fontSize: 11, fontWeight: 700, color: VBT_MUTED, textTransform: 'uppercase', letterSpacing: 0.5 }}>Por empresa · TOP 8 (con alerta operando)</div>
          </div>
          <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 12 }}>
            <thead><tr><VBT_ThS>Empresa</VBT_ThS><VBT_ThS>Personas</VBT_ThS><VBT_ThS>Rutas</VBT_ThS></tr></thead>
            <tbody>
              {empresasArr.length === 0 ? <tr><td colSpan={3} style={{ padding: 20, textAlign: 'center', color: VBT_LIGHT, fontSize: 11 }}>Sin datos</td></tr> :
                empresasArr.map((e, i) => (
                  <tr key={i} style={{ borderBottom: '0.5px solid #f4f5f7' }}>
                    <VBT_TdS bold>{e.empresa || '—'}</VBT_TdS>
                    <VBT_TdS center>{e.personas}</VBT_TdS>
                    <VBT_TdS center strong>{e.rutas}</VBT_TdS>
                  </tr>
                ))}
            </tbody>
          </table>
        </div>
        <div style={{ background: VBT_CARD, borderRadius: 12, border: `0.5px solid ${VBT_BORDER}`, overflow: 'hidden' }}>
          <div style={{ padding: '10px 14px', borderBottom: `1px solid ${VBT_BORDER}`, background: '#f8fafc' }}>
            <div style={{ fontSize: 11, fontWeight: 700, color: VBT_MUTED, textTransform: 'uppercase', letterSpacing: 0.5 }}>Por SVC</div>
          </div>
          <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 12 }}>
            <thead><tr><VBT_ThS>SVC</VBT_ThS><VBT_ThS>Personas</VBT_ThS><VBT_ThS>Rutas</VBT_ThS></tr></thead>
            <tbody>
              {svcArr.length === 0 ? <tr><td colSpan={3} style={{ padding: 20, textAlign: 'center', color: VBT_LIGHT, fontSize: 11 }}>Sin datos</td></tr> :
                svcArr.map((s, i) => (
                  <tr key={i} style={{ borderBottom: '0.5px solid #f4f5f7' }}>
                    <VBT_TdS bold>{s.svc || '—'}</VBT_TdS>
                    <VBT_TdS center>{s.personas}</VBT_TdS>
                    <VBT_TdS center strong>{s.rutas}</VBT_TdS>
                  </tr>
                ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

function OperandoBT({ operando, onSelectCurp }) {
  const exportar = () => {
    const headers = ['Gravedad','CURP','Nombre','SC','Cargo','Empresa','Respuesta MELI','Validación BT','Rol','Rutas','Desde','Hasta'];
    const rows = operando.map(o => [o.gravedad,o.curp,o.nombre_bt,o.svc,o.cargo,o.empresa,o.respuesta_meli,o.validacion_bt,o.rol,o.rutas,o.desde,o.hasta]);
    const csv = [headers.join(','), ...rows.map(r => r.map(v => `"${String(v||'').replace(/"/g,'""')}"`).join(','))].join('\n');
    const blob = new Blob(['\uFEFF' + csv], { type: 'text/csv;charset=utf-8;' });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob); a.download = `BT_rechazados_operando_${new Date().toISOString().split('T')[0]}.csv`; a.click();
  };

  if (operando.length === 0) return (
    <div style={{ padding: 40, textAlign: 'center', color: VBT_LIGHT, fontSize: 13, background: VBT_CARD, borderRadius: 12, border: `1px dashed ${VBT_BORDER}` }}>
      <i className="ti ti-circle-check" style={{ fontSize: 32, color: VBT_GREEN, display: 'block', marginBottom: 8 }} />
      Sin personas rechazadas/pendientes operando en los últimos 30 días
    </div>
  );

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 10 }}>
        <div style={{ fontSize: 12, color: VBT_MUTED }}>
          <strong>{new Set(operando.map(o=>o.curp)).size} personas</strong> con alerta operando · <strong>{operando.length} casos</strong> (rol chofer + helper)
        </div>
        <button onClick={exportar} style={{
          fontSize: 11, fontWeight: 600, padding: '6px 12px', borderRadius: 6,
          border: 'none', background: VBT_NAVY, color: '#fff', cursor: 'pointer',
          fontFamily: "'Geist', sans-serif",
          display: 'inline-flex', alignItems: 'center', gap: 5,
        }}>
          <i className="ti ti-download" style={{ fontSize: 13 }} />Exportar CSV
        </button>
      </div>
      <div style={{ background: VBT_CARD, borderRadius: 12, border: `0.5px solid ${VBT_BORDER}`, overflow: 'hidden' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 12 }}>
          <thead>
            <tr>
              <VBT_ThS>Gravedad</VBT_ThS><VBT_ThS>Nombre</VBT_ThS><VBT_ThS>SC</VBT_ThS><VBT_ThS>Cargo</VBT_ThS>
              <VBT_ThS>Respuesta MELI</VBT_ThS><VBT_ThS>Empresa</VBT_ThS><VBT_ThS>Rol</VBT_ThS><VBT_ThS>Rutas</VBT_ThS><VBT_ThS>Hasta</VBT_ThS>
            </tr>
          </thead>
          <tbody>
            {operando.map((o, i) => {
              const bg = o.gravedad === 'CRITICO' ? '#fef2f2' : o.gravedad === 'ALTO' ? '#fffbeb' : '#eff6ff';
              return (
                <tr key={i} onClick={() => onSelectCurp && onSelectCurp(o.curp)}
                    style={{ borderBottom: '0.5px solid #f4f5f7', background: bg, cursor: 'pointer' }}
                    title="Click para ver historial completo">
                  <VBT_TdS><VBT_Pill type={o.gravedad === 'CRITICO' ? 'red' : o.gravedad === 'ALTO' ? 'yellow' : 'blue'}>{o.gravedad}</VBT_Pill></VBT_TdS>
                  <VBT_TdS bold>{o.nombre_bt}</VBT_TdS>
                  <VBT_TdS mono>{o.svc}</VBT_TdS>
                  <VBT_TdS>{o.cargo}</VBT_TdS>
                  <VBT_TdS><VBT_Pill type={o.respuesta_meli === 'RECHAZADO' ? 'red' : 'yellow'}>{o.respuesta_meli}</VBT_Pill></VBT_TdS>
                  <VBT_TdS muted>{o.empresa}</VBT_TdS>
                  <VBT_TdS>{o.rol}</VBT_TdS>
                  <VBT_TdS center strong>{o.rutas}</VBT_TdS>
                  <VBT_TdS mono>{o.hasta}</VBT_TdS>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}

function ListadoBT({ bt, svcs, filtroGrav, setFiltroGrav, filtroSvc, setFiltroSvc, busqueda, setBusqueda, totalSinFiltro, onSelectCurp }) {
  const exportar = () => {
    const headers = ['CURP','Nombre','SC','Cargo','Empresa','Respuesta MELI','Validación BT','En padrón','Status padrón','Estado cruce','Gravedad'];
    const rows = bt.map(b => [b.curp,b.nombre_bt,b.svc,b.cargo,b.empresa,b.respuesta_meli,b.validacion_bt,b.driver_id_padron?'SÍ':'NO',b.status_padron||'',b.estado_cruce,b.gravedad]);
    const csv = [headers.join(','), ...rows.map(r => r.map(v => `"${String(v||'').replace(/"/g,'""')}"`).join(','))].join('\n');
    const blob = new Blob(['\uFEFF' + csv], { type: 'text/csv;charset=utf-8;' });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob); a.download = `BT_listado_${new Date().toISOString().split('T')[0]}.csv`; a.click();
  };

  return (
    <div>
      <div style={{ display: 'flex', gap: 8, alignItems: 'center', marginBottom: 12, flexWrap: 'wrap' }}>
        <input value={busqueda} onChange={e => setBusqueda(e.target.value)} placeholder="Buscar por nombre o CURP..."
          style={{ fontSize: 12, padding: '6px 10px', borderRadius: 6, border: `1px solid ${VBT_BORDER}`, width: 220, fontFamily: "'Geist', sans-serif", outline: 'none' }} />
        <select value={filtroGrav} onChange={e => setFiltroGrav(e.target.value)}
          style={{ fontSize: 12, padding: '6px 10px', borderRadius: 6, border: `1px solid ${VBT_BORDER}`, fontFamily: "'Geist', sans-serif", outline: 'none', cursor: 'pointer' }}>
          <option value="TODOS">Todas las gravedades</option>
          <option value="CRITICO">🔴 Crítico</option>
          <option value="ALTO">🟠 Alto</option>
          <option value="MEDIO">🟡 Medio</option>
          <option value="OK">🟢 OK</option>
        </select>
        <select value={filtroSvc} onChange={e => setFiltroSvc(e.target.value)}
          style={{ fontSize: 12, padding: '6px 10px', borderRadius: 6, border: `1px solid ${VBT_BORDER}`, fontFamily: "'Geist', sans-serif", outline: 'none', cursor: 'pointer' }}>
          <option value="TODOS">Todos los SC</option>
          {svcs.map(s => <option key={s} value={s}>{s}</option>)}
        </select>
        <span style={{ fontSize: 11, color: VBT_MUTED, marginLeft: 4 }}>{bt.length} / {totalSinFiltro} registros</span>
        <button onClick={exportar} style={{
          marginLeft: 'auto', fontSize: 11, fontWeight: 600, padding: '6px 12px', borderRadius: 6,
          border: 'none', background: VBT_NAVY, color: '#fff', cursor: 'pointer',
          fontFamily: "'Geist', sans-serif", display: 'inline-flex', alignItems: 'center', gap: 5,
        }}>
          <i className="ti ti-download" style={{ fontSize: 13 }} />Exportar CSV
        </button>
      </div>

      <div style={{ background: VBT_CARD, borderRadius: 12, border: `0.5px solid ${VBT_BORDER}`, overflow: 'hidden', maxHeight: '60vh', overflowY: 'auto' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 12 }}>
          <thead style={{ position: 'sticky', top: 0, zIndex: 1 }}>
            <tr>
              <VBT_ThS>Grav.</VBT_ThS><VBT_ThS>CURP</VBT_ThS><VBT_ThS>Nombre</VBT_ThS><VBT_ThS>SC</VBT_ThS><VBT_ThS>Cargo</VBT_ThS>
              <VBT_ThS>Empresa</VBT_ThS><VBT_ThS>Respuesta MELI</VBT_ThS><VBT_ThS>Padrón</VBT_ThS><VBT_ThS>Status</VBT_ThS><VBT_ThS>Hist.</VBT_ThS>
            </tr>
          </thead>
          <tbody>
            {bt.map((b, i) => (
              <tr key={i} onClick={() => onSelectCurp && onSelectCurp(b.curp)}
                  style={{ borderBottom: '0.5px solid #f4f5f7', cursor: 'pointer' }}
                  title="Click para ver historial completo">
                <VBT_TdS><VBT_Pill type={b.gravedad === 'CRITICO' ? 'red' : b.gravedad === 'ALTO' ? 'yellow' : b.gravedad === 'MEDIO' ? 'blue' : 'gray'}>{b.gravedad}</VBT_Pill></VBT_TdS>
                <VBT_TdS mono small>{b.curp}</VBT_TdS>
                <VBT_TdS bold>{b.nombre_bt}</VBT_TdS>
                <VBT_TdS mono>{b.svc}</VBT_TdS>
                <VBT_TdS>{b.cargo}</VBT_TdS>
                <VBT_TdS muted small>{b.empresa}</VBT_TdS>
                <VBT_TdS>{b.respuesta_meli || '—'}</VBT_TdS>
                <VBT_TdS center>{b.driver_id_padron ? '✅' : '🚨'}</VBT_TdS>
                <VBT_TdS mono small>{b.status_padron || '—'}</VBT_TdS>
                <VBT_TdS center>
                  {b.apariciones_historial > 1 ? (
                    <span style={{ background: '#fef3c7', color: '#92400e', fontSize: 10, fontWeight: 700, padding: '2px 6px', borderRadius: 4 }}>{b.apariciones_historial}×</span>
                  ) : <span style={{ color: VBT_LIGHT, fontSize: 10 }}>1</span>}
                </VBT_TdS>
              </tr>
            ))}
            {bt.length === 0 && (<tr><td colSpan={10} style={{ padding: 24, textAlign: 'center', color: VBT_LIGHT, fontSize: 12 }}>Sin resultados con esos filtros</td></tr>)}
          </tbody>
        </table>
      </div>
    </div>
  );
}

function HistorialPersonaModal({ curp, onClose }) {
  const [historial, setHistorial] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    let alive = true;
    (async () => {
      setLoading(true);
      try {
        const { data, error } = await sb.from('vw_bt_historial_por_persona').select('*').eq('curp', curp).order('pos_temporal', { ascending: true });
        if (error) throw error;
        if (alive) setHistorial(data || []);
      } catch (e) { if (alive) setError(e.message || 'Error'); } finally { if (alive) setLoading(false); }
    })();
    return () => { alive = false; };
  }, [curp]);

  const persona = historial[0] || {};
  const empresasUnicas = [...new Set(historial.map(h => h.empresa).filter(Boolean))];
  const cargosUnicos = [...new Set(historial.map(h => h.cargo).filter(Boolean))];

  return (
    <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', zIndex: 1000, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 20 }} onClick={onClose}>
      <div onClick={e => e.stopPropagation()} style={{ background: '#fff', borderRadius: 14, padding: 24, minWidth: 720, maxWidth: '90vw', maxHeight: '90vh', overflowY: 'auto', fontFamily: "'Geist', sans-serif" }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 14 }}>
          <div>
            <div style={{ fontSize: 16, fontWeight: 700, color: VBT_NAVY, marginBottom: 4 }}>{persona.nombre || 'Historial de la persona'}</div>
            <div style={{ fontSize: 11, fontFamily: 'monospace', color: VBT_MUTED }}>CURP: {curp}</div>
          </div>
          <button onClick={onClose} style={{ background: 'transparent', border: 'none', cursor: 'pointer', fontSize: 18, color: VBT_MUTED }}>✕</button>
        </div>

        {loading && <div style={{ padding: 40, textAlign: 'center', color: VBT_MUTED, fontSize: 13 }}>Cargando historial…</div>}
        {error && <div style={{ padding: 20, background: '#fef2f2', borderRadius: 8, fontSize: 12, color: '#991b1b' }}>{error}</div>}

        {!loading && !error && (
          <>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 10, marginBottom: 14 }}>
              <div style={{ background: '#f8fafc', borderRadius: 8, padding: 10, border: `0.5px solid ${VBT_BORDER}` }}>
                <div style={{ fontSize: 9, fontWeight: 700, color: VBT_MUTED, textTransform: 'uppercase', letterSpacing: 0.4 }}>Apariciones</div>
                <div style={{ fontSize: 22, fontWeight: 800, color: VBT_NAVY, marginTop: 4 }}>{historial.length}</div>
              </div>
              <div style={{ background: '#f8fafc', borderRadius: 8, padding: 10, border: `0.5px solid ${VBT_BORDER}` }}>
                <div style={{ fontSize: 9, fontWeight: 700, color: VBT_MUTED, textTransform: 'uppercase', letterSpacing: 0.4 }}>Empresas</div>
                <div style={{ fontSize: 22, fontWeight: 800, color: VBT_NAVY, marginTop: 4 }}>{empresasUnicas.length}</div>
              </div>
              <div style={{ background: '#f8fafc', borderRadius: 8, padding: 10, border: `0.5px solid ${VBT_BORDER}` }}>
                <div style={{ fontSize: 9, fontWeight: 700, color: VBT_MUTED, textTransform: 'uppercase', letterSpacing: 0.4 }}>Cargos</div>
                <div style={{ fontSize: 12, fontWeight: 700, color: VBT_TEXT, marginTop: 4 }}>{cargosUnicos.join(' / ') || '—'}</div>
              </div>
              <div style={{ background: '#f8fafc', borderRadius: 8, padding: 10, border: `0.5px solid ${VBT_BORDER}` }}>
                <div style={{ fontSize: 9, fontWeight: 700, color: VBT_MUTED, textTransform: 'uppercase', letterSpacing: 0.4 }}>SC actual</div>
                <div style={{ fontSize: 13, fontWeight: 700, color: VBT_NAVY, fontFamily: 'monospace', marginTop: 4 }}>{persona.svc || '—'}</div>
              </div>
            </div>

            {empresasUnicas.length > 0 && (
              <div style={{ marginBottom: 14 }}>
                <div style={{ fontSize: 10, fontWeight: 700, color: VBT_MUTED, textTransform: 'uppercase', letterSpacing: 0.5, marginBottom: 6 }}>Empresas por las que pasó</div>
                <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap' }}>
                  {empresasUnicas.map((e, i) => (
                    <span key={i} style={{ background: i === 0 ? VBT_NAVY : '#f1f5f9', color: i === 0 ? '#fff' : VBT_TEXT, fontSize: 11, fontWeight: 600, padding: '4px 10px', borderRadius: 6 }}>
                      {i === 0 && '★ '}{e}
                    </span>
                  ))}
                </div>
                <div style={{ fontSize: 10, color: VBT_LIGHT, marginTop: 4 }}>★ = empresa actual</div>
              </div>
            )}

            <div style={{ fontSize: 10, fontWeight: 700, color: VBT_MUTED, textTransform: 'uppercase', letterSpacing: 0.5, marginBottom: 6 }}>Historial completo · {historial.length} apariciones (más reciente arriba)</div>
            <div style={{ background: VBT_CARD, borderRadius: 10, border: `0.5px solid ${VBT_BORDER}`, overflow: 'hidden' }}>
              <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 11 }}>
                <thead>
                  <tr>
                    <VBT_ThS>#</VBT_ThS><VBT_ThS>Cargo</VBT_ThS><VBT_ThS>Empresa</VBT_ThS><VBT_ThS>SC</VBT_ThS>
                    <VBT_ThS>Respuesta MELI</VBT_ThS><VBT_ThS>H. Respuesta</VBT_ThS><VBT_ThS>F. Llegada</VBT_ThS><VBT_ThS>Validación BT</VBT_ThS>
                  </tr>
                </thead>
                <tbody>
                  {historial.map((h, i) => (
                    <tr key={i} style={{ borderBottom: '0.5px solid #f4f5f7', background: h.es_actual ? '#eff6ff' : '#fff' }}>
                      <VBT_TdS center bold>{h.es_actual ? '★' : h.pos_temporal}</VBT_TdS>
                      <VBT_TdS>{h.cargo || '—'}</VBT_TdS>
                      <VBT_TdS bold={h.es_actual}>{h.empresa || '—'}</VBT_TdS>
                      <VBT_TdS mono>{h.svc || '—'}</VBT_TdS>
                      <VBT_TdS>
                        <VBT_Pill type={h.respuesta_meli === 'RECHAZADO' ? 'red' : h.respuesta_meli === 'PENDIENTE' ? 'yellow' : h.respuesta_meli === 'APROBADO' ? 'green' : 'gray'}>
                          {h.respuesta_meli || '—'}
                        </VBT_Pill>
                      </VBT_TdS>
                      <VBT_TdS mono small>{h.h_respuesta_meli ? new Date(h.h_respuesta_meli).toLocaleString('es-MX', { dateStyle: 'short', timeStyle: 'short' }) : '—'}</VBT_TdS>
                      <VBT_TdS mono small>{h.f_llegada ? new Date(h.f_llegada).toLocaleString('es-MX', { dateStyle: 'short', timeStyle: 'short' }) : '—'}</VBT_TdS>
                      <VBT_TdS>
                        {h.validacion_bt ? <VBT_Pill type={h.validacion_bt === 'RECHAZADO' ? 'red' : 'yellow'}>{h.validacion_bt}</VBT_Pill> : <span style={{ color: VBT_LIGHT }}>—</span>}
                      </VBT_TdS>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            <div style={{ marginTop: 12, fontSize: 10, color: VBT_LIGHT, fontStyle: 'italic' }}>★ = fila actual (la más reciente por H. Respuesta MELI)</div>
          </>
        )}
      </div>
    </div>
  );
}

function UploadExcelBT({ onClose }) {
  const [status, setStatus] = useState('idle');
  const [msg, setMsg] = useState('');
  const [count, setCount] = useState({ total: 0, ok: 0 });
  const [errores, setErrores] = useState([]);

  const handleFile = async (file) => {
    setStatus('parsing'); setMsg(`Leyendo ${file.name}...`); setErrores([]);
    try {
      if (!window.XLSX) {
        await new Promise((resolve, reject) => {
          const s = document.createElement("script");
          s.src = "https://cdn.sheetjs.com/xlsx-0.20.0/package/dist/xlsx.full.min.js";
          s.onload = resolve; s.onerror = reject; document.head.appendChild(s);
        });
      }
      const XLSX = window.XLSX;
      if (!XLSX) { setStatus('error'); setMsg('No se pudo cargar SheetJS.'); return; }

      const data = await file.arrayBuffer();
      const wb = XLSX.read(data, { type: 'array', cellDates: true });
      let sheetName = wb.SheetNames.includes('DATOS') ? 'DATOS' : wb.SheetNames[0];
      const rows = XLSX.utils.sheet_to_json(wb.Sheets[sheetName], { raw: false, defval: null });
      if (rows.length === 0) { setStatus('error'); setMsg('El archivo no tiene filas'); return; }

      setStatus('uploading'); setMsg(`Procesando ${rows.length} filas...`); setCount({ total: rows.length, ok: 0 });

      const cleanSvc = (v) => v ? String(v).replace(/^ML_MX_/, '').trim() : null;
      const toDate = (v) => {
        if (!v) return null;
        if (v instanceof Date) {
          if (isNaN(v.getTime())) return null;
          const y = v.getFullYear(); if (y < 2020 || y > 2100) return null;
          return v.toISOString();
        }
        const s = String(v).trim();
        if (/\d{5,}/.test(s)) return null;
        const d = new Date(s); if (isNaN(d.getTime())) return null;
        const y = d.getFullYear(); if (y < 2020 || y > 2100) return null;
        return d.toISOString();
      };

      const allRows = rows.filter(r => r.CURP && String(r.CURP).trim()).map(r => ({
        curp: String(r.CURP).trim().toUpperCase(),
        nombre: r.Nombres || r.nombres || r.nombre || '',
        cargo: r.CARGO || null, empresa: r.EMPRESA || null, svc: cleanSvc(r.SVC),
        f_llegada: toDate(r['F. LLEGADA']), enviado_meli: toDate(r['ENVIADO MELI']),
        respuesta_meli: r['RESPUESTA MELI'] || null, h_respuesta_meli: toDate(r['H. RESPUESTA MELI']),
        validacion_bt: r['VALIDACION BIGTICKET'] || null, aviso_transporte: toDate(r['AVISO A TRANSPORTE']),
        rfc: r.RFC || null, lc: r['L.C'] || null, ine: r.INE || null,
        email: r.Email || null, telefono: r['Teléfono'] || r['Telefono'] || null, idv: r.IDV || null,
        raw_json: r,
      }));

      const sortKey = (x) => {
        const t1 = x.h_respuesta_meli ? new Date(x.h_respuesta_meli).getTime() : 0;
        const t2 = x.f_llegada ? new Date(x.f_llegada).getTime() : 0;
        return t1 || t2 || 0;
      };
      const ordenadas = [...allRows].sort((a, b) => sortKey(b) - sortKey(a));
      const seenCurp = new Set();
      const rowsPrincipal = [];
      for (const r of ordenadas) {
        if (!seenCurp.has(r.curp)) { seenCurp.add(r.curp); rowsPrincipal.push(r); }
      }

      setMsg(`Subiendo ${rowsPrincipal.length} CURPs únicos a tabla principal...`);
      const batchSize = 50;
      let ok = 0; const errs = [];
      for (let i = 0; i < rowsPrincipal.length; i += batchSize) {
        const batch = rowsPrincipal.slice(i, i + batchSize);
        const { error } = await sb.from('bt_tripulaciones').upsert(batch, { onConflict: 'curp' });
        if (error) errs.push(`Principal batch ${i}: ${error.message}`); else ok += batch.length;
        setCount({ total: rowsPrincipal.length, ok });
        setMsg(`Tabla principal: ${ok}/${rowsPrincipal.length}...`);
      }

      setMsg(`Subiendo ${allRows.length} filas al historial...`);
      const batchId = new Date().toISOString().replace(/[^0-9]/g, '').slice(0, 14);
      let okHist = 0;
      for (let i = 0; i < allRows.length; i += batchSize) {
        const batch = allRows.slice(i, i + batchSize).map(r => ({ ...r, upload_batch_id: batchId }));
        const { error } = await sb.from('bt_tripulaciones_historial').upsert(batch, { onConflict: 'curp,empresa,respuesta_meli,h_respuesta_meli', ignoreDuplicates: true });
        if (error) errs.push(`Historial batch ${i}: ${error.message}`); else okHist += batch.length;
        setMsg(`Historial: ${okHist}/${allRows.length}...`);
      }

      setCount({ total: rowsPrincipal.length, ok });
      setErrores(errs);
      setStatus(errs.length > 0 ? 'error' : 'done');
      setMsg(errs.length > 0
        ? `Cargado con errores: principal ${ok}/${rowsPrincipal.length} · historial ${okHist}/${allRows.length}`
        : `✅ ${ok} CURPs únicos cargados · ${okHist} filas en historial`);
    } catch (e) { setStatus('error'); setMsg('Error: ' + (e.message || e)); }
  };

  return (
    <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', zIndex: 1000, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 20 }} onClick={status === 'idle' || status === 'done' || status === 'error' ? onClose : undefined}>
      <div onClick={e => e.stopPropagation()} style={{ background: '#fff', borderRadius: 14, padding: 24, minWidth: 500, maxWidth: 600, fontFamily: "'Geist', sans-serif" }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
          <div style={{ fontSize: 16, fontWeight: 700, color: VBT_NAVY }}>Subir BBDD BT</div>
          <button onClick={onClose} style={{ background: 'transparent', border: 'none', cursor: 'pointer', fontSize: 18, color: VBT_MUTED }}>✕</button>
        </div>

        {status === 'idle' && (<>
          <div style={{ fontSize: 12, color: VBT_MUTED, marginBottom: 14, lineHeight: 1.6 }}>
            Arrastrá o seleccioná el archivo <strong>VALIDACION_TRIPULACIONES_MELI_MX.xlsx</strong>.<br/>
            Hace UPSERT por CURP y guarda todo el historial.
          </div>
          <label style={{ display: 'block', padding: 30, border: `2px dashed ${VBT_BORDER}`, borderRadius: 12, textAlign: 'center', cursor: 'pointer', background: '#f8fafc' }}>
            <i className="ti ti-cloud-upload" style={{ fontSize: 32, color: VBT_NAVY, display: 'block', marginBottom: 8 }} />
            <div style={{ fontSize: 13, fontWeight: 600, color: VBT_NAVY }}>Click para seleccionar archivo</div>
            <div style={{ fontSize: 11, color: VBT_MUTED, marginTop: 4 }}>.xlsx</div>
            <input type="file" accept=".xlsx,.xls" style={{ display: 'none' }} onChange={e => e.target.files[0] && handleFile(e.target.files[0])} />
          </label>
        </>)}

        {(status === 'parsing' || status === 'uploading') && (
          <div style={{ padding: 20, textAlign: 'center' }}>
            <i className="ti ti-loader-2" style={{ fontSize: 32, color: VBT_NAVY, display: 'inline-block' }} />
            <div style={{ fontSize: 13, color: VBT_TEXT, marginTop: 12 }}>{msg}</div>
            {count.total > 0 && (
              <div style={{ marginTop: 10, height: 8, background: VBT_BORDER, borderRadius: 4, overflow: 'hidden' }}>
                <div style={{ width: `${100*count.ok/count.total}%`, height: '100%', background: VBT_NAVY, transition: 'width .3s' }} />
              </div>
            )}
          </div>
        )}

        {status === 'done' && (
          <div style={{ padding: 20, textAlign: 'center' }}>
            <i className="ti ti-circle-check" style={{ fontSize: 40, color: VBT_GREEN }} />
            <div style={{ fontSize: 14, fontWeight: 600, color: VBT_TEXT, marginTop: 8 }}>{msg}</div>
            <button onClick={onClose} style={{ marginTop: 14, fontSize: 12, fontWeight: 600, padding: '8px 18px', borderRadius: 6, border: 'none', background: VBT_NAVY, color: '#fff', cursor: 'pointer', fontFamily: "'Geist', sans-serif" }}>Cerrar y refrescar</button>
          </div>
        )}

        {status === 'error' && (
          <div style={{ padding: 20 }}>
            <div style={{ background: '#fef2f2', border: '1px solid #fecaca', borderRadius: 8, padding: 12, marginBottom: 12 }}>
              <div style={{ fontSize: 13, fontWeight: 600, color: '#991b1b' }}>{msg}</div>
              {errores.length > 0 && (<div style={{ fontSize: 11, color: '#7f1d1d', marginTop: 6, maxHeight: 100, overflowY: 'auto' }}>{errores.map((e, i) => <div key={i}>{e}</div>)}</div>)}
            </div>
            <button onClick={() => { setStatus('idle'); setMsg(''); setErrores([]); }} style={{ fontSize: 12, fontWeight: 600, padding: '8px 18px', borderRadius: 6, border: `1px solid ${VBT_BORDER}`, background: VBT_CARD, color: VBT_TEXT, cursor: 'pointer', fontFamily: "'Geist', sans-serif" }}>Reintentar</button>
          </div>
        )}
      </div>
    </div>
  );
}

function VBT_KPI({ l, v, s, accent, info, onClick }) {
  const [hovered, setHovered] = useState(false);
  const [tooltipOpen, setTooltipOpen] = useState(false);
  const clickable = typeof onClick === 'function';
  return (
    <div
      onClick={clickable ? onClick : undefined}
      onMouseEnter={() => clickable && setHovered(true)}
      onMouseLeave={() => clickable && setHovered(false)}
      style={{
        background: VBT_CARD,
        borderRadius: 12,
        border: clickable && hovered ? `1px solid ${accent || VBT_NAVY}` : `0.5px solid ${VBT_BORDER}`,
        padding: 14,
        cursor: clickable ? 'pointer' : 'default',
        position: 'relative',
        transition: 'all 120ms ease',
        boxShadow: clickable && hovered ? `0 2px 8px ${accent ? accent + '22' : 'rgba(0,0,0,0.05)'}` : 'none',
        transform: clickable && hovered ? 'translateY(-1px)' : 'translateY(0)',
      }}
    >
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 8 }}>
        <div style={{ fontSize: 11, fontWeight: 700, color: VBT_MUTED, textTransform: 'uppercase', letterSpacing: 0.4 }}>{l}</div>
        {info && (
          <div
            onMouseEnter={(e) => { e.stopPropagation(); setTooltipOpen(true); }}
            onMouseLeave={(e) => { e.stopPropagation(); setTooltipOpen(false); }}
            onClick={(e) => e.stopPropagation()}
            style={{ position: 'relative', display: 'inline-flex', alignItems: 'center', justifyContent: 'center', width: 16, height: 16, borderRadius: '50%', border: `1px solid ${VBT_BORDER}`, color: VBT_MUTED, fontSize: 10, fontWeight: 700, cursor: 'help', fontFamily: 'serif', fontStyle: 'italic', lineHeight: 1, background: '#f8fafc' }}
          >
            i
            {tooltipOpen && (
              <div style={{ position: 'absolute', top: 'calc(100% + 8px)', right: -4, width: 260, background: '#1a1a1a', color: '#fff', fontSize: 11, lineHeight: 1.5, padding: '10px 12px', borderRadius: 8, boxShadow: '0 8px 24px rgba(0,0,0,0.25)', zIndex: 50, fontWeight: 400, fontFamily: "'Geist', sans-serif", textTransform: 'none', letterSpacing: 0, fontStyle: 'normal' }}>
                <div style={{ position: 'absolute', top: -4, right: 8, width: 8, height: 8, background: '#1a1a1a', transform: 'rotate(45deg)' }} />
                {info}
              </div>
            )}
          </div>
        )}
      </div>
      <div style={{ fontSize: 26, fontWeight: 800, color: accent || VBT_TEXT, letterSpacing: -0.5, lineHeight: 1 }}>{v}</div>
      <div style={{ fontSize: 11, color: VBT_LIGHT, marginTop: 6 }}>{s}</div>
      {clickable && (
        <div style={{ position: 'absolute', bottom: 8, right: 10, fontSize: 9, fontWeight: 600, color: accent || VBT_MUTED, textTransform: 'uppercase', letterSpacing: 0.5, opacity: hovered ? 1 : 0.45, transition: 'opacity 120ms' }}>
          Ver detalle →
        </div>
      )}
    </div>
  );
}

function VBT_ThS({ children }) {
  return <th style={{ padding: '8px 10px', fontSize: 9, fontWeight: 700, textTransform: 'uppercase', letterSpacing: 0.5, color: VBT_MUTED, textAlign: 'left', borderBottom: `1px solid ${VBT_BORDER}`, background: '#f8fafc', whiteSpace: 'nowrap' }}>{children}</th>;
}

function VBT_TdS({ children, bold, muted, mono, center, strong, small }) {
  return <td style={{ padding: '8px 10px', fontSize: small ? 11 : 12, fontFamily: mono ? 'monospace' : "'Geist', sans-serif", color: muted ? VBT_MUTED : strong ? VBT_NAVY : VBT_TEXT, fontWeight: bold || strong ? 600 : 'normal', textAlign: center ? 'center' : 'left' }}>{children}</td>;
}

function VBT_Pill({ children, type }) {
  const c = type === 'red' ? { bg: '#fee2e2', col: '#991b1b' }
    : type === 'yellow' ? { bg: '#fef3c7', col: '#92400e' }
    : type === 'blue' ? { bg: '#dbeafe', col: '#1e40af' }
    : type === 'green' ? { bg: '#d1fae5', col: '#065f46' }
    : { bg: '#f1f5f9', col: '#475569' };
  return <span style={{ background: c.bg, color: c.col, fontSize: 9.5, fontWeight: 700, padding: '3px 8px', borderRadius: 5, textTransform: 'uppercase', letterSpacing: 0.3, whiteSpace: 'nowrap' }}>{children}</span>;
}

// Modal Multi-Driver_ID: muestra personas BT con más de un driver_id activo en MELI.
// Incluye sección secundaria con personas multi-ID que NO están en BT (huérfanos).
function MultiDriverIdModal({ data, sinBt, onClose, onSelectCurp }) {
  const [showSinBt, setShowSinBt] = useState(false);
  const totalCriticos = (data || []).filter(d => d.es_critico).length;

  const exportarCSV = () => {
    const headers = ['CURP','Nombre BT','Empresa BT','SVC','Cargo','Respuesta MELI','Validación BT','# IDs','driver_ids','Nombres MELI','Carriers'];
    const rows = (data || []).map(d => [
      d.curp, d.nombre_bt, d.empresa_bt, d.svc, d.cargo,
      d.respuesta_meli, d.validacion_bt, d.cantidad_driver_ids,
      d.driver_ids, d.nombres_meli, d.carriers
    ]);
    const csv = [headers, ...rows].map(r => r.map(c => `"${(c ?? '').toString().replace(/"/g, '""')}"`).join(',')).join('\n');
    const blob = new Blob(['\uFEFF' + csv], { type: 'text/csv;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url; a.download = `multi_driver_id_bt_${new Date().toISOString().split('T')[0]}.csv`; a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div onClick={onClose} style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', zIndex: 9999, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 20, fontFamily: "'Geist', sans-serif" }}>
      <div onClick={e => e.stopPropagation()} style={{ background: '#fff', borderRadius: 12, width: '100%', maxWidth: 1100, maxHeight: '90vh', display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        {/* Header */}
        <div style={{ padding: '16px 20px', borderBottom: `1px solid ${VBT_BORDER}`, display: 'flex', alignItems: 'center', justifyContent: 'space-between', background: 'linear-gradient(135deg, #f8f7ff 0%, #fff 100%)' }}>
          <div>
            <div style={{ fontSize: 16, fontWeight: 700, color: VBT_NAVY, marginBottom: 4, display: 'flex', alignItems: 'center', gap: 8 }}>
              <span style={{ width: 10, height: 10, borderRadius: '50%', background: '#6366f1', display: 'inline-block' }} />
              Personas con múltiples driver_id en MELI
            </div>
            <div style={{ fontSize: 11.5, color: VBT_MUTED }}>
              {(data || []).length} {((data || []).length === 1) ? 'persona' : 'personas'} en BT con 2+ driver_id activos en el padrón
              {totalCriticos > 0 && <span style={{ color: '#991b1b', fontWeight: 600 }}> · {totalCriticos} con alerta BT</span>}
            </div>
          </div>
          <div style={{ display: 'flex', gap: 8 }}>
            {(data || []).length > 0 && (
              <button onClick={exportarCSV} style={{ fontSize: 11, fontWeight: 600, padding: '6px 12px', borderRadius: 6, border: `1px solid ${VBT_BORDER}`, background: '#fff', color: VBT_NAVY, cursor: 'pointer', fontFamily: "'Geist', sans-serif", display: 'inline-flex', alignItems: 'center', gap: 5 }}>
                <i className="ti ti-download" style={{ fontSize: 13 }} />
                Exportar CSV
              </button>
            )}
            <button onClick={onClose} style={{ background: 'transparent', border: 'none', cursor: 'pointer', fontSize: 20, color: VBT_MUTED, padding: 0, width: 32, height: 32, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>✕</button>
          </div>
        </div>

        {/* Cuerpo */}
        <div style={{ overflowY: 'auto', flex: 1, padding: 20 }}>
          {/* Tabla principal */}
          {(!data || data.length === 0) ? (
            <div style={{ padding: 40, textAlign: 'center', color: VBT_LIGHT, fontSize: 13 }}>
              No hay personas BT con múltiples driver_id en este momento.
            </div>
          ) : (
            <div style={{ border: `0.5px solid ${VBT_BORDER}`, borderRadius: 10, overflow: 'hidden' }}>
              <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 12 }}>
                <thead>
                  <tr>
                    <VBT_ThS>Estado</VBT_ThS>
                    <VBT_ThS>Nombre BT</VBT_ThS>
                    <VBT_ThS>CURP</VBT_ThS>
                    <VBT_ThS>Empresa BT</VBT_ThS>
                    <VBT_ThS>SVC</VBT_ThS>
                    <VBT_ThS>Respuesta MELI</VBT_ThS>
                    <VBT_ThS># IDs</VBT_ThS>
                    <VBT_ThS>driver_ids</VBT_ThS>
                    <VBT_ThS>Carriers</VBT_ThS>
                  </tr>
                </thead>
                <tbody>
                  {data.map((d, i) => (
                    <tr key={d.curp || i}
                      onClick={() => onSelectCurp && onSelectCurp(d.curp)}
                      style={{
                        borderBottom: '0.5px solid #f4f5f7',
                        background: d.es_critico ? '#fef2f2' : 'transparent',
                        cursor: onSelectCurp ? 'pointer' : 'default'
                      }}
                      onMouseEnter={(e) => { if (onSelectCurp) e.currentTarget.style.background = d.es_critico ? '#fee2e2' : '#f8fafc'; }}
                      onMouseLeave={(e) => { if (onSelectCurp) e.currentTarget.style.background = d.es_critico ? '#fef2f2' : 'transparent'; }}
                    >
                      <VBT_TdS>
                        {d.es_critico ? (
                          <VBT_Pill type="red">{d.respuesta_meli || 'CRÍTICO'}</VBT_Pill>
                        ) : (
                          <VBT_Pill type="gray">OK</VBT_Pill>
                        )}
                      </VBT_TdS>
                      <VBT_TdS bold>{d.nombre_bt || '—'}</VBT_TdS>
                      <VBT_TdS mono small>{d.curp}</VBT_TdS>
                      <VBT_TdS muted small>{d.empresa_bt || '—'}</VBT_TdS>
                      <VBT_TdS mono>{d.svc || '—'}</VBT_TdS>
                      <VBT_TdS>
                        {d.respuesta_meli === 'RECHAZADO' ? <VBT_Pill type="red">RECHAZADO</VBT_Pill>
                          : d.respuesta_meli === 'PENDIENTE' ? <VBT_Pill type="yellow">PENDIENTE</VBT_Pill>
                          : d.respuesta_meli === 'APROBADO' ? <VBT_Pill type="green">APROBADO</VBT_Pill>
                          : (d.respuesta_meli || '—')}
                      </VBT_TdS>
                      <VBT_TdS center strong>
                        <span style={{ background: '#eef2ff', color: '#4338ca', padding: '2px 8px', borderRadius: 10, fontSize: 11, fontWeight: 700 }}>
                          {d.cantidad_driver_ids}
                        </span>
                      </VBT_TdS>
                      <VBT_TdS mono small>{d.driver_ids}</VBT_TdS>
                      <VBT_TdS mono small muted>{d.carriers}</VBT_TdS>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}

          {/* Tip */}
          {data && data.length > 0 && onSelectCurp && (
            <div style={{ marginTop: 10, fontSize: 11, color: VBT_LIGHT, fontStyle: 'italic' }}>
              Click en una fila para ver el historial completo de la persona.
            </div>
          )}

          {/* Sección secundaria: multi-ID sin BT */}
          {sinBt && sinBt.length > 0 && (
            <div style={{ marginTop: 20, padding: 14, background: '#fffbeb', border: '1px solid #fde68a', borderRadius: 10 }}>
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', cursor: 'pointer' }} onClick={() => setShowSinBt(!showSinBt)}>
                <div>
                  <div style={{ fontSize: 12.5, fontWeight: 700, color: '#92400e', marginBottom: 2, display: 'flex', alignItems: 'center', gap: 6 }}>
                    <i className="ti ti-alert-circle" style={{ fontSize: 14 }} />
                    Además, {sinBt.length} {sinBt.length === 1 ? 'persona' : 'personas'} con multi-driver_id en MELI no están cargadas en BT
                  </div>
                  <div style={{ fontSize: 11, color: '#92400e', opacity: 0.85 }}>
                    Estos casos no fueron validados por BT pero existen como múltiples perfiles en el padrón MELI. Revisar con la carrier correspondiente.
                  </div>
                </div>
                <i className={`ti ti-chevron-${showSinBt ? 'up' : 'down'}`} style={{ fontSize: 16, color: '#92400e' }} />
              </div>
              {showSinBt && (
                <div style={{ marginTop: 12, background: '#fff', border: `0.5px solid ${VBT_BORDER}`, borderRadius: 8, overflow: 'hidden' }}>
                  <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 11.5 }}>
                    <thead>
                      <tr>
                        <VBT_ThS>CURP</VBT_ThS>
                        <VBT_ThS>Nombres MELI</VBT_ThS>
                        <VBT_ThS># IDs</VBT_ThS>
                        <VBT_ThS>driver_ids</VBT_ThS>
                        <VBT_ThS>Carriers</VBT_ThS>
                      </tr>
                    </thead>
                    <tbody>
                      {sinBt.map((p, i) => (
                        <tr key={p.curp || i} style={{ borderBottom: '0.5px solid #f4f5f7' }}>
                          <VBT_TdS mono small>{p.curp}</VBT_TdS>
                          <VBT_TdS bold small>{p.nombres_meli}</VBT_TdS>
                          <VBT_TdS center strong>
                            <span style={{ background: '#fef3c7', color: '#92400e', padding: '2px 8px', borderRadius: 10, fontSize: 11, fontWeight: 700 }}>
                              {p.cantidad_driver_ids}
                            </span>
                          </VBT_TdS>
                          <VBT_TdS mono small>{p.driver_ids}</VBT_TdS>
                          <VBT_TdS mono small muted>{p.carriers}</VBT_TdS>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════════════
// AUDITORÍA PADRÓN MELI · Subpestaña dentro de IndicadoresOperacionalesMX
// ════════════════════════════════════════════════════════════════════════════

// ════════════════════════════════════════════════════════════════════════════
// AUDITORÍA PADRÓN MELI · v2 · lee de meli_drivers_master
// El padrón se actualiza solo · cron diario 08:00 MX (14:00 UTC)
// ════════════════════════════════════════════════════════════════════════════

// ════════════════════════════════════════════════════════════════════════════
// PADRÓN MELI · Administración
// Conductores y vehículos · data completa, altas/bajas diarias, placas SDD
// repetidas y cambios por día. Fuente: meli_drivers_master / meli_vehicles_master
// (snapshot diario 08:00 MX · 14:00 UTC). Diffs vía RPC get_*_padron_diff.
// ════════════════════════════════════════════════════════════════════════════
const PADRON_CFG = {
  drivers: {
    tabla: "meli_drivers_master",
    rpcDiff: "get_drivers_padron_diff",
    llave: "driver_id",
    label: "conductores",
    icono: "ti-user",
    selectData: "driver_id,nombre,first_name,last_name,document_type,document_value,status,disabled,is_only_helper,carrier_id,email,phone,fecha_snapshot,created_at",
    cols: ["driver_id", "nombre", "document_value", "status", "disabled", "is_only_helper", "carrier_id", "email", "phone", "first_name", "last_name", "created_at"],
    diffCols: [
      { k: "driver_id", l: "Driver ID", mono: true },
      { k: "nombre", l: "Nombre", bold: true },
      { k: "document_value", l: "CURP", mono: true, small: true },
      { k: "status", l: "Status", badge: true },
      { k: "carrier_id", l: "Carrier", mono: true, small: true },
      { k: "detalle", l: "Detalle", muted: true },
    ],
    cambioTipos: ["cambio_status", "cambio_disabled", "cambio_carrier"],
    tieneRepetidas: false,
  },
  vehiculos: {
    tabla: "meli_vehicles_master",
    rpcDiff: "get_vehiculos_padron_diff",
    llave: "vehicle_id",
    label: "vehículos",
    icono: "ti-truck",
    selectData: "vehicle_id,placa,tipo_nombre,tipo_id,capacidad,es_sdd,is_traction,status,carrier_id,amount_plate,fecha_snapshot,created_at",
    cols: ["vehicle_id", "placa", "tipo_nombre", "capacidad", "es_sdd", "is_traction", "status", "carrier_id", "amount_plate", "created_at"],
    diffCols: [
      { k: "vehicle_id", l: "Vehicle ID", mono: true },
      { k: "placa", l: "Placa", bold: true, mono: true },
      { k: "tipo_nombre", l: "Tipo", small: true },
      { k: "capacidad", l: "Cap.", mono: true, small: true },
      { k: "status", l: "Status", badge: true },
      { k: "detalle", l: "Detalle", muted: true },
    ],
    cambioTipos: ["cambio_tipo", "cambio_status"],
    tieneRepetidas: true,
  },
};

// CSV genérico
function padronCsv(headers, rows, filename) {
  const csv = [headers.join(",")].concat(
    rows.map(r => r.map(v => `"${String(v == null ? "" : v).replace(/"/g, '""')}"`).join(","))
  ).join("\n");
  const blob = new Blob(["\uFEFF" + csv], { type: "text/csv;charset=utf-8;" });
  const a = document.createElement("a");
  a.href = URL.createObjectURL(blob);
  a.download = `${filename}_${new Date().toISOString().split("T")[0]}.csv`;
  a.click();
}

function padronFmt(v) {
  if (v === null || v === undefined || v === "") return "—";
  if (typeof v === "boolean") return v ? "Sí" : "No";
  return String(v);
}

// ── Helper de etiqueta de infracción para el padrón de conductores ──────────
// Rol del conductor (desde is_only_helper del detalle MELI)
function padronRolMeta(isOnlyHelper) {
  if (isOnlyHelper === true)  return { label: "Helper", color: "#F47B20", bg: "#fff3e6" };
  if (isOnlyHelper === false) return { label: "Driver", color: "#1a3a6b", bg: "#e8edf5" };
  return { label: "Sin dato", color: "#94a3b8", bg: "#f1f5f9" };
}
function PadronRolBadge({ value }) {
  const m = padronRolMeta(value);
  return <span style={{ background: m.bg, color: m.color, fontSize: 10, fontWeight: 700, padding: "2px 8px", borderRadius: 4 }}>{m.label}</span>;
}

function padronInfraccionLabel(key) {
  if (!key) return "Infracción";
  const map = {
    driver_advertencia: "Advertencia",
    driver_suspension: "Suspensión",
    driver_bloqueo: "Bloqueo",
  };
  return map[key] || String(key).replace(/^driver_/, "").replace(/_/g, " ");
}

// ── DATA COMPLETA · Conductores (cruza master del día con meli_drivers_detalle)
function PadronDriversData({ fecha }) {
  const [masterRows, setMasterRows] = useState([]);
  const [detalleMap, setDetalleMap] = useState(new Map());
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [busqueda, setBusqueda] = useState("");
  const [soloInfractores, setSoloInfractores] = useState(false);
  const [expandidos, setExpandidos] = useState(new Set());

  const PNAVY = "#1a3a6b", PMUTED = "#64748b", PLIGHT = "#94a3b8", PBORDER = "#e4e7ec";

  useEffect(() => {
    if (!fecha) return;
    let alive = true;
    (async () => {
      setLoading(true); setError(null); setExpandidos(new Set());
      try {
        // Snapshot del día (universo operativo) + detalle enriquecido (1 fila por driver)
        const [mRes, dRes] = await Promise.all([
          sb.from("meli_drivers_master")
            .select("driver_id,nombre,first_name,last_name,document_value,status")
            .eq("fecha_snapshot", fecha).limit(5000),
          sb.from("meli_drivers_detalle")
            .select("driver_id,first_name,last_name,document_value,email,phone,creation_date,status,tiene_infraccion,infraction_status,esta_bloqueado,blocking_reason,is_only_helper")
            .limit(5000),
        ]);
        if (mRes.error) throw mRes.error;
        if (dRes.error) throw dRes.error;
        const map = new Map((dRes.data || []).map(d => [Number(d.driver_id), d]));
        if (alive) { setMasterRows(mRes.data || []); setDetalleMap(map); }
      } catch (e) { if (alive) setError(e.message || "Error"); }
      finally { if (alive) setLoading(false); }
    })();
    return () => { alive = false; };
  }, [fecha]);

  // Merge master + detalle por driver_id
  const rows = useMemo(() => {
    return masterRows.map(m => {
      const d = detalleMap.get(Number(m.driver_id)) || null;
      const nombre = (d && (d.first_name || d.last_name))
        ? `${d.first_name || ""} ${d.last_name || ""}`.trim()
        : (m.first_name || m.last_name) ? `${m.first_name || ""} ${m.last_name || ""}`.trim()
        : (m.nombre || "—");
      return {
        driver_id: m.driver_id,
        nombre_completo: nombre || "—",
        curp: m.document_value || (d && d.document_value) || "—",
        creation_date: d ? d.creation_date : null,
        email: d ? d.email : null,
        phone: d ? d.phone : null,
        status: m.status || (d && d.status) || "—",
        is_only_helper: d ? d.is_only_helper : null,
        tiene_infraccion: !!(d && d.tiene_infraccion),
        infraction_status: d ? d.infraction_status : null,
        esta_bloqueado: !!(d && d.esta_bloqueado),
        blocking_reason: d ? d.blocking_reason : null,
        enriquecido: !!d,
      };
    });
  }, [masterRows, detalleMap]);

  const kpis = useMemo(() => ({
    total: rows.length,
    infractores: rows.filter(r => r.tiene_infraccion).length,
    conEmail: rows.filter(r => r.email).length,
    conTel: rows.filter(r => r.phone).length,
  }), [rows]);

  const filtradas = useMemo(() => {
    let res = rows;
    if (soloInfractores) res = res.filter(r => r.tiene_infraccion);
    const q = busqueda.toLowerCase().trim();
    if (q) {
      res = res.filter(r =>
        [r.driver_id, r.nombre_completo, r.curp, r.email, r.phone]
          .some(v => String(v ?? "").toLowerCase().includes(q))
      );
    }
    return res;
  }, [rows, busqueda, soloInfractores]);

  const toggleExpand = (id) => {
    setExpandidos(prev => {
      const n = new Set(prev);
      n.has(id) ? n.delete(id) : n.add(id);
      return n;
    });
  };

  const exportar = () => {
    const headers = ["ID conductor", "Nombre completo", "CURP", "Fecha de creación (MX)", "Correo", "Teléfono", "Estado", "Infracción"];
    const filas = filtradas.map(r => {
      const inf = r.tiene_infraccion && r.infraction_status
        ? `${padronInfraccionLabel(r.infraction_status.key)} ${r.infraction_status.date || ""}`.trim()
        : "";
      return [r.driver_id, r.nombre_completo, r.curp, fmtFechaHoraMX(r.creation_date), r.email || "", r.phone || "", r.status, inf];
    });
    padronCsv(headers, filas, "padron_conductores");
  };

  if (loading) return <div style={{ padding: 40, textAlign: "center", color: PMUTED, fontSize: 13 }}>Cargando conductores…</div>;
  if (error) return <div style={{ background: "#fef2f2", border: "1px solid #fecaca", borderRadius: 10, padding: 14, fontSize: 12, color: "#991b1b" }}>{error}</div>;

  const COLS = 9;

  return (
    <div>
      {/* KPIs */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 10, marginBottom: 12 }}>
        <PKpi l="Total conductores" v={kpis.total} s={`snapshot ${fecha || "—"}`} accent={PNAVY} />
        <PKpi l="⚠️ Con infracción" v={kpis.infractores} s="advertencias / sanciones" accent="#d97706" />
        <PKpi l="Con correo" v={kpis.conEmail} s={`${kpis.total ? Math.round(100 * kpis.conEmail / kpis.total) : 0}% del padrón`} accent="#10b981" />
        <PKpi l="Con teléfono" v={kpis.conTel} s={`${kpis.total ? Math.round(100 * kpis.conTel / kpis.total) : 0}% del padrón`} accent="#10b981" />
      </div>

      {/* Toolbar */}
      <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 10, flexWrap: "wrap" }}>
        <input value={busqueda} onChange={e => setBusqueda(e.target.value)} placeholder={`Buscar por nombre, CURP, correo, teléfono o ID…`}
          style={{ flex: 1, minWidth: 240, maxWidth: 400, padding: "7px 10px", border: `1px solid #d0d5dd`, borderRadius: 6, fontSize: 12, fontFamily: "'Geist', sans-serif" }} />
        <button onClick={() => setSoloInfractores(v => !v)} style={{
          fontSize: 12, fontWeight: 700, padding: "7px 12px", borderRadius: 8, cursor: "pointer",
          border: soloInfractores ? "none" : `1px solid ${PBORDER}`,
          background: soloInfractores ? "#d97706" : "#fff",
          color: soloInfractores ? "#fff" : PMUTED,
          fontFamily: "'Geist', sans-serif", display: "inline-flex", alignItems: "center", gap: 6,
        }}>
          <i className="ti ti-alert-triangle" style={{ fontSize: 14 }} />
          {soloInfractores ? `Mostrando infractores (${kpis.infractores})` : "Solo infractores"}
        </button>
        <span style={{ fontSize: 12, color: PMUTED }}>{filtradas.length} de {rows.length}</span>
        <button onClick={exportar} style={{ marginLeft: "auto", fontSize: 11, fontWeight: 600, padding: "6px 11px", borderRadius: 6, border: "none", background: PNAVY, color: "#fff", cursor: "pointer", fontFamily: "'Geist', sans-serif", display: "inline-flex", alignItems: "center", gap: 5 }}>
          <i className="ti ti-download" style={{ fontSize: 12 }} />Exportar CSV
        </button>
      </div>

      {/* Tabla */}
      <div style={{ background: "#fff", borderRadius: 12, border: `0.5px solid ${PBORDER}`, overflow: "hidden" }}>
        <div style={{ maxHeight: "60vh", overflow: "auto" }}>
          <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
            <thead style={{ position: "sticky", top: 0, zIndex: 1, background: "#f8fafc" }}>
              <tr>
                <ApTh>ID conductor</ApTh>
                <ApTh>Nombre completo</ApTh>
                <ApTh>CURP</ApTh>
                <ApTh>Fecha de creación (MX)</ApTh>
                <ApTh>Correo</ApTh>
                <ApTh>Teléfono</ApTh>
                <ApTh>Estado</ApTh>
                <ApTh>Rol</ApTh>
                <ApTh>Infracción</ApTh>
              </tr>
            </thead>
            <tbody>
              {filtradas.length === 0 && (
                <tr><td colSpan={COLS} style={{ padding: 30, textAlign: "center", color: PLIGHT }}>Sin resultados</td></tr>
              )}
              {filtradas.map((r, i) => {
                const abierto = expandidos.has(r.driver_id);
                const inf = r.infraction_status || {};
                return (
                  <Fragment key={r.driver_id ?? i}>
                    <tr
                      onClick={() => r.tiene_infraccion && toggleExpand(r.driver_id)}
                      style={{ borderBottom: abierto ? "none" : "0.5px solid #f4f5f7", cursor: r.tiene_infraccion ? "pointer" : "default", background: abierto ? "#fffbeb" : "transparent" }}>
                      <ApTd mono>{r.driver_id}</ApTd>
                      <ApTd bold>{r.nombre_completo}</ApTd>
                      <ApTd mono small>{r.curp}</ApTd>
                      <ApTd small>{fmtFechaHoraMX(r.creation_date)}</ApTd>
                      <ApTd small>{r.email || <span style={{ color: PLIGHT }}>—</span>}</ApTd>
                      <ApTd mono small>{r.phone || <span style={{ color: PLIGHT }}>—</span>}</ApTd>
                      <ApTd>
                        <span style={{ background: r.status === "active" ? "#d1fae5" : "#fef3c7", color: r.status === "active" ? "#065f46" : "#92400e", fontSize: 10, fontWeight: 700, padding: "2px 7px", borderRadius: 4 }}>{r.status}</span>
                      </ApTd>
                      <ApTd><PadronRolBadge value={r.is_only_helper} /></ApTd>
                      <ApTd>
                        {r.tiene_infraccion ? (
                          <span style={{ display: "inline-flex", alignItems: "center", gap: 5, background: "#fef3c7", color: "#92400e", fontSize: 10, fontWeight: 700, padding: "2px 8px", borderRadius: 4 }}>
                            <i className="ti ti-alert-triangle" style={{ fontSize: 12 }} />
                            {padronInfraccionLabel(inf.key)}
                            <i className={`ti ${abierto ? "ti-chevron-up" : "ti-chevron-down"}`} style={{ fontSize: 12 }} />
                          </span>
                        ) : (
                          <span style={{ color: PLIGHT }}>—</span>
                        )}
                      </ApTd>
                    </tr>
                    {abierto && r.tiene_infraccion && (
                      <tr style={{ borderBottom: "0.5px solid #f4f5f7", background: "#fffbeb" }}>
                        <td colSpan={COLS} style={{ padding: "10px 16px 14px 16px" }}>
                          <div style={{ display: "flex", flexWrap: "wrap", gap: 24, fontSize: 12, color: "#1a1a1a" }}>
                            <div><span style={{ color: PMUTED, fontWeight: 700, fontSize: 10, textTransform: "uppercase", letterSpacing: 0.4, display: "block", marginBottom: 2 }}>Tipo</span>{padronInfraccionLabel(inf.key)}</div>
                            <div><span style={{ color: PMUTED, fontWeight: 700, fontSize: 10, textTransform: "uppercase", letterSpacing: 0.4, display: "block", marginBottom: 2 }}>Fecha infracción</span>{inf.date || "—"}</div>
                            <div><span style={{ color: PMUTED, fontWeight: 700, fontSize: 10, textTransform: "uppercase", letterSpacing: 0.4, display: "block", marginBottom: 2 }}>Clasificación</span>{inf.sentenceType || "—"}</div>
                            <div><span style={{ color: PMUTED, fontWeight: 700, fontSize: 10, textTransform: "uppercase", letterSpacing: 0.4, display: "block", marginBottom: 2 }}>Clave MELI</span><code style={{ fontSize: 11 }}>{inf.key || "—"}</code></div>
                            {r.esta_bloqueado && (
                              <div><span style={{ color: "#991b1b", fontWeight: 700, fontSize: 10, textTransform: "uppercase", letterSpacing: 0.4, display: "block", marginBottom: 2 }}>🔒 Bloqueado</span>{JSON.stringify(r.blocking_reason)}</div>
                            )}
                          </div>
                        </td>
                      </tr>
                    )}
                  </Fragment>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
      <div style={{ marginTop: 10, fontSize: 11, color: PLIGHT, fontStyle: "italic" }}>
        ℹ️ Contacto, fecha de creación e infracciones provienen del detalle de MELI (tabla de enriquecimiento). Conductores sin estos datos aún no fueron enriquecidos o MELI no los expone. Clic en una fila con <strong style={{ color: "#92400e" }}>infracción</strong> para ver el detalle.
      </div>
    </div>
  );
}

// ── SUB-MUNDO CURSOS · lee vw_cursos_actividad ──────────────────────────────
function PadronCursos() {
  const [rows, setRows] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [busqueda, setBusqueda] = useState("");
  const [soloOperan, setSoloOperan] = useState(false);
  const PNAVY = "#1a3a6b", PMUTED = "#64748b", PLIGHT = "#94a3b8", PBORDER = "#e4e7ec";

  useEffect(() => {
    let alive = true;
    (async () => {
      setLoading(true); setError(null);
      try {
        const { data, error } = await sb.from("vw_cursos_actividad").select("*").limit(5000);
        if (error) throw error;
        if (alive) setRows(data || []);
      } catch (e) { if (alive) setError(e.message || "Error"); }
      finally { if (alive) setLoading(false); }
    })();
    return () => { alive = false; };
  }, []);

  const kpis = useMemo(() => ({
    total: rows.length,
    operan: rows.filter(r => r.opera_hoy).length,
    sin_op: rows.filter(r => !r.opera_hoy).length,
  }), [rows]);

  const filtradas = useMemo(() => {
    let res = rows;
    if (soloOperan) res = res.filter(r => r.opera_hoy);
    const q = busqueda.toLowerCase().trim();
    if (q) res = res.filter(r =>
      [r.driver_id, r.nombre, r.email, r.telefono, r.curp].some(v => String(v ?? "").toLowerCase().includes(q)));
    return res;
  }, [rows, busqueda, soloOperan]);

  const exportar = () => {
    const headers = ["ID conductor", "Nombre", "Curso", "Estado", "Correo", "Teléfono", "CURP", "Opera hoy"];
    const filas = filtradas.map(r => [r.driver_id, r.nombre, r.course_name, r.status,
      r.email || "", r.telefono || "", r.curp || "", r.opera_hoy ? "Sí" : "No"]);
    padronCsv(headers, filas, "cursos_pendientes");
  };

  if (loading) return <div style={{ padding: 40, textAlign: "center", color: PMUTED, fontSize: 13 }}>Cargando cursos…</div>;
  if (error) return <div style={{ background: "#fef2f2", border: "1px solid #fecaca", borderRadius: 10, padding: 14, fontSize: 12, color: "#991b1b" }}>{error}</div>;

  return (
    <div style={{ padding: 20 }}>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 10, marginBottom: 12 }}>
        <PKpi l="Cursos pendientes" v={kpis.total} s='"Cómo hacer entregas con la app"' accent={PNAVY} />
        <PKpi l="Operan hoy" v={kpis.operan} s="en el padrón operativo · accionables" accent="#d97706" />
        <PKpi l="No operan hoy" v={kpis.sin_op} s="pendientes fuera de operación" accent={PLIGHT} />
      </div>

      <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 10, flexWrap: "wrap" }}>
        <input value={busqueda} onChange={e => setBusqueda(e.target.value)} placeholder="Buscar por nombre, ID, correo, teléfono…"
          style={{ flex: 1, minWidth: 240, maxWidth: 400, padding: "7px 10px", border: "1px solid #d0d5dd", borderRadius: 6, fontSize: 12, fontFamily: "'Geist', sans-serif" }} />
        <button onClick={() => setSoloOperan(v => !v)} style={{
          fontSize: 12, fontWeight: 700, padding: "7px 12px", borderRadius: 8, cursor: "pointer",
          border: soloOperan ? "none" : `1px solid ${PBORDER}`,
          background: soloOperan ? "#d97706" : "#fff", color: soloOperan ? "#fff" : PMUTED,
          fontFamily: "'Geist', sans-serif",
        }}>{soloOperan ? `Mostrando operativos (${kpis.operan})` : "Solo los que operan hoy"}</button>
        <span style={{ fontSize: 12, color: PMUTED }}>{filtradas.length} de {rows.length}</span>
        <button onClick={exportar} style={{ marginLeft: "auto", fontSize: 11, fontWeight: 600, padding: "6px 11px", borderRadius: 6, border: "none", background: PNAVY, color: "#fff", cursor: "pointer", fontFamily: "'Geist', sans-serif", display: "inline-flex", alignItems: "center", gap: 5 }}>
          <i className="ti ti-download" style={{ fontSize: 12 }} />Exportar CSV
        </button>
      </div>

      <div style={{ background: "#fff", borderRadius: 12, border: `0.5px solid ${PBORDER}`, overflow: "hidden" }}>
        <div style={{ maxHeight: "60vh", overflow: "auto" }}>
          <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
            <thead style={{ position: "sticky", top: 0, zIndex: 1, background: "#f8fafc" }}>
              <tr>
                <ApTh>ID conductor</ApTh><ApTh>Nombre</ApTh><ApTh>Curso</ApTh>
                <ApTh>Estado</ApTh><ApTh>Rol</ApTh><ApTh>Correo</ApTh><ApTh>Teléfono</ApTh><ApTh>Opera hoy</ApTh>
              </tr>
            </thead>
            <tbody>
              {filtradas.length === 0 && (
                <tr><td colSpan={8} style={{ padding: 30, textAlign: "center", color: PLIGHT }}>Sin resultados</td></tr>
              )}
              {filtradas.map((r, i) => (
                <tr key={r.driver_id ?? i} style={{ borderBottom: "0.5px solid #f4f5f7" }}>
                  <ApTd mono>{r.driver_id}</ApTd>
                  <ApTd bold>{r.nombre || "—"}</ApTd>
                  <ApTd small>{r.course_name}</ApTd>
                  <ApTd>
                    <span style={{ background: "#fef3c7", color: "#92400e", fontSize: 10, fontWeight: 700, padding: "2px 7px", borderRadius: 4 }}>
                      {r.status === "urgent" ? "Urgente" : r.status}
                    </span>
                  </ApTd>
                  <ApTd><PadronRolBadge value={r.is_only_helper} /></ApTd>
                  <ApTd small>{r.email || <span style={{ color: PLIGHT }}>—</span>}</ApTd>
                  <ApTd mono small>{r.telefono || <span style={{ color: PLIGHT }}>—</span>}</ApTd>
                  <ApTd center>
                    {r.opera_hoy
                      ? <span style={{ background: "#d1fae5", color: "#065f46", fontSize: 10, fontWeight: 700, padding: "2px 7px", borderRadius: 4 }}>Opera</span>
                      : <span style={{ color: PLIGHT }}>—</span>}
                  </ApTd>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
      <div style={{ marginTop: 10, fontSize: 11, color: PLIGHT, fontStyle: "italic" }}>
        ℹ️ Cursos pendientes capturados desde el hub de capacitación de MELI. "Opera hoy" = aparece en el último snapshot del padrón operativo.
      </div>
    </div>
  );
}

// ── SUB-MUNDO RECHAZADOS · carga Excel -> Supabase -> vw_rechazados_actividad ─
function PadronRechazados() {
  const [rows, setRows] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [busqueda, setBusqueda] = useState("");
  const [soloActivos, setSoloActivos] = useState(false);
  const [cargando, setCargando] = useState(false);
  const [msg, setMsg] = useState(null);
  const fileRef = useRef(null);
  const PNAVY = "#1a3a6b", PMUTED = "#64748b", PLIGHT = "#94a3b8", PBORDER = "#e4e7ec";

  async function cargar() {
    setLoading(true); setError(null);
    try {
      const { data, error } = await sb.from("vw_rechazados_actividad").select("*").limit(5000);
      if (error) throw error;
      setRows(data || []);
    } catch (e) { setError(e.message || "Error"); }
    finally { setLoading(false); }
  }
  useEffect(() => { cargar(); }, []);

  // Parsea fechas tipo Excel a ISO (o null)
  function aFecha(v) {
    if (v == null || v === "") return null;
    if (v instanceof Date) return v.toISOString();
    const d = new Date(v);
    return isNaN(d.getTime()) ? null : d.toISOString();
  }

  async function onArchivo(e) {
    const file = e.target.files && e.target.files[0];
    if (!file) return;
    setCargando(true); setMsg(null); setError(null);
    try {
      // Asegurar SheetJS
      if (!window.XLSX) {
        await new Promise((res, rej) => {
          const s = document.createElement("script");
          s.src = "https://cdn.sheetjs.com/xlsx-0.20.0/package/dist/xlsx.full.min.js";
          s.onload = res; s.onerror = rej; document.head.appendChild(s);
        });
      }
      const XLSX = window.XLSX;
      const buf = await file.arrayBuffer();
      const wb = XLSX.read(buf, { type: "array", cellDates: true });
      const hoja = wb.Sheets["DATOS"] || wb.Sheets[wb.SheetNames[0]];
      const arr = XLSX.utils.sheet_to_json(hoja, { defval: null });

      // Mapeo por nombre de columna (formato estable del reporte)
      const norm = s => String(s ?? "").trim();
      const filas = arr.map(r => ({
        svc:            norm(r["SVC"]),
        nombre:         norm(r["Nombres"]),
        cargo:          norm(r["CARGO"]),
        empresa:        norm(r["EMPRESA"]),
        fecha_llegada:  aFecha(r["F. LLEGADA"]),
        enviado_meli:   aFecha(r["ENVIADO MELI"]),
        respuesta_meli: norm(r["RESPUESTA MELI"]).toUpperCase(),
        respuesta_at:   aFecha(r["H. RESPUESTA MELI"]),
        validacion_bt:  norm(r["VALIDACION BIGTICKET"]),
        rfc:            norm(r["RFC"]),
        curp:           norm(r["CURP"]).toUpperCase(),
        email:          norm(r["Email"]),
        telefono:       norm(r["Teléfono"]),
        lote:           new Date().toISOString().slice(0, 10),
      })).filter(f => f.curp || f.nombre);

      if (filas.length === 0) throw new Error("No se encontraron filas en la hoja DATOS. ¿El archivo tiene el formato esperado?");

      // REEMPLAZAR: borrar todo e insertar lo nuevo
      const { error: eDel } = await sb.from("meli_validacion_tripulaciones").delete().neq("id", -1);
      if (eDel) throw new Error("No pude limpiar la tabla: " + eDel.message);
      for (let i = 0; i < filas.length; i += 200) {
        const { error: eIns } = await sb.from("meli_validacion_tripulaciones").insert(filas.slice(i, i + 200));
        if (eIns) throw new Error("Error al insertar: " + eIns.message);
      }
      const rech = filas.filter(f => f.respuesta_meli === "RECHAZADO").length;
      setMsg(`✓ Cargadas ${filas.length} filas (${rech} rechazados). Cruzando con el padrón…`);
      await cargar();
      setMsg(`✓ Carga completa: ${filas.length} filas · ${rech} rechazados. Tabla actualizada.`);
    } catch (err) {
      setError(err.message || "Error al procesar el archivo");
    } finally {
      setCargando(false);
      if (fileRef.current) fileRef.current.value = "";
    }
  }

  const kpis = useMemo(() => ({
    total: rows.length,
    con_act: rows.filter(r => r.viajes_30d > 0).length,
    ayer: rows.filter(r => r.viajes_ayer > 0).length,
    semana: rows.filter(r => r.viajes_7d > 0).length,
  }), [rows]);

  const filtradas = useMemo(() => {
    let res = rows;
    if (soloActivos) res = res.filter(r => r.viajes_30d > 0);
    const q = busqueda.toLowerCase().trim();
    if (q) res = res.filter(r =>
      [r.curp, r.driver_id, r.nombre, r.empresa, r.sc_ultimo, r.supervisor_ultimo].some(v => String(v ?? "").toLowerCase().includes(q)));
    // orden: viajes_30d desc
    return [...res].sort((a, b) => (b.viajes_30d || 0) - (a.viajes_30d || 0));
  }, [rows, busqueda, soloActivos]);

  const exportar = () => {
    const headers = ["CURP", "ID conductor", "Nombre", "Empresa", "SC último", "Supervisor último",
      "Último viaje", "Viajes ayer", "Viajes 7d", "Viajes 15d", "Viajes 30d"];
    const filas = filtradas.map(r => [r.curp, r.driver_id ?? "", r.nombre || "", r.empresa || "",
      r.sc_ultimo || "", r.supervisor_ultimo || "", r.ultimo_viaje || "",
      r.viajes_ayer, r.viajes_7d, r.viajes_15d, r.viajes_30d]);
    padronCsv(headers, filas, "rechazados_meli");
  };

  return (
    <div style={{ padding: 20 }}>
      {/* Barra de carga */}
      <div style={{ background: "#fff", border: `1px solid ${PBORDER}`, borderRadius: 10, padding: "12px 16px", marginBottom: 14, display: "flex", alignItems: "center", gap: 12, flexWrap: "wrap" }}>
        <div style={{ flex: 1, minWidth: 220 }}>
          <div style={{ fontSize: 13, fontWeight: 700, color: PNAVY }}>Validación de tripulaciones</div>
          <div style={{ fontSize: 11, color: PMUTED }}>Cargá el Excel de validación. Reemplaza la carga anterior y vuelve a cruzar con el padrón.</div>
        </div>
        <input ref={fileRef} type="file" accept=".xlsx,.xls" onChange={onArchivo} style={{ display: "none" }} id="rech-file" />
        <button onClick={() => fileRef.current && fileRef.current.click()} disabled={cargando} style={{
          fontSize: 12, fontWeight: 700, padding: "9px 16px", borderRadius: 8, border: "none",
          background: cargando ? "#94a3b8" : "#F47B20", color: "#fff", cursor: cargando ? "default" : "pointer",
          fontFamily: "'Geist', sans-serif", display: "inline-flex", alignItems: "center", gap: 6,
        }}>
          <i className={`ti ${cargando ? "ti-loader-2" : "ti-upload"}`} style={{ fontSize: 15 }} />
          {cargando ? "Procesando…" : "Cargar Excel"}
        </button>
      </div>
      {msg && <div style={{ background: "#ecfdf5", border: "1px solid #a7f3d0", borderRadius: 8, padding: "8px 12px", fontSize: 12, color: "#065f46", marginBottom: 12 }}>{msg}</div>}
      {error && <div style={{ background: "#fef2f2", border: "1px solid #fecaca", borderRadius: 8, padding: "8px 12px", fontSize: 12, color: "#991b1b", marginBottom: 12 }}>{error}</div>}

      {/* KPIs */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 10, marginBottom: 12 }}>
        <PKpi l="Rechazados (total)" v={kpis.total} s="con CURP en el padrón" accent={PNAVY} />
        <PKpi l="Con actividad 30d" v={kpis.con_act} s="rechazados que operaron" accent="#d97706" />
        <PKpi l="⚠️ Operaron ayer" v={kpis.ayer} s="rechazados en ruta ayer" accent="#c0392b" />
        <PKpi l="Operaron 7 días" v={kpis.semana} s="actividad reciente" accent="#d97706" />
      </div>

      <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 10, flexWrap: "wrap" }}>
        <input value={busqueda} onChange={e => setBusqueda(e.target.value)} placeholder="Buscar por CURP, nombre, empresa, SC, supervisor…"
          style={{ flex: 1, minWidth: 240, maxWidth: 400, padding: "7px 10px", border: "1px solid #d0d5dd", borderRadius: 6, fontSize: 12, fontFamily: "'Geist', sans-serif" }} />
        <button onClick={() => setSoloActivos(v => !v)} style={{
          fontSize: 12, fontWeight: 700, padding: "7px 12px", borderRadius: 8, cursor: "pointer",
          border: soloActivos ? "none" : `1px solid ${PBORDER}`,
          background: soloActivos ? "#c0392b" : "#fff", color: soloActivos ? "#fff" : PMUTED,
          fontFamily: "'Geist', sans-serif",
        }}>{soloActivos ? `Solo con viajes (${kpis.con_act})` : "Solo con viajes"}</button>
        <span style={{ fontSize: 12, color: PMUTED }}>{filtradas.length} de {rows.length}</span>
        <button onClick={exportar} style={{ marginLeft: "auto", fontSize: 11, fontWeight: 600, padding: "6px 11px", borderRadius: 6, border: "none", background: PNAVY, color: "#fff", cursor: "pointer", fontFamily: "'Geist', sans-serif", display: "inline-flex", alignItems: "center", gap: 5 }}>
          <i className="ti ti-download" style={{ fontSize: 12 }} />Exportar CSV
        </button>
      </div>

      {loading ? (
        <div style={{ padding: 40, textAlign: "center", color: PMUTED, fontSize: 13 }}>Cargando…</div>
      ) : rows.length === 0 ? (
        <div style={{ background: "#fff", border: `1px dashed ${PBORDER}`, borderRadius: 10, padding: 40, textAlign: "center", color: PLIGHT, fontSize: 13 }}>
          No hay datos de validación cargados. Usá "Cargar Excel" para subir el archivo de tripulaciones.
        </div>
      ) : (
        <div style={{ background: "#fff", borderRadius: 12, border: `0.5px solid ${PBORDER}`, overflow: "hidden" }}>
          <div style={{ maxHeight: "55vh", overflow: "auto" }}>
            <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
              <thead style={{ position: "sticky", top: 0, zIndex: 1, background: "#f8fafc" }}>
                <tr>
                  <ApTh>CURP</ApTh><ApTh>ID</ApTh><ApTh>Nombre</ApTh><ApTh>Empresa</ApTh><ApTh>Rol</ApTh>
                  <ApTh>SC último</ApTh><ApTh>Supervisor último</ApTh><ApTh>Último viaje</ApTh>
                  <ApTh>Ayer</ApTh><ApTh>7d</ApTh><ApTh>15d</ApTh><ApTh>30d</ApTh>
                </tr>
              </thead>
              <tbody>
                {filtradas.length === 0 && (
                  <tr><td colSpan={12} style={{ padding: 30, textAlign: "center", color: PLIGHT }}>Sin resultados</td></tr>
                )}
                {filtradas.map((r, i) => {
                  const ayer = r.viajes_ayer > 0, sem = r.viajes_7d > 0;
                  const bg = ayer ? "#fbeceb" : sem ? "#fffbeb" : "transparent";
                  return (
                    <tr key={(r.curp || "") + (r.driver_id || i)} style={{ borderBottom: "0.5px solid #f4f5f7", background: bg }}>
                      <ApTd mono small>{r.curp}</ApTd>
                      <ApTd mono>{r.driver_id || <span style={{ color: PLIGHT }}>—</span>}</ApTd>
                      <ApTd bold>{r.nombre || "—"}</ApTd>
                      <ApTd small>{r.empresa || <span style={{ color: PLIGHT }}>—</span>}</ApTd>
                      <ApTd><PadronRolBadge value={r.is_only_helper} /></ApTd>
                      <ApTd center small>{r.sc_ultimo || <span style={{ color: PLIGHT }}>—</span>}</ApTd>
                      <ApTd small>{r.supervisor_ultimo || <span style={{ color: PLIGHT }}>—</span>}</ApTd>
                      <ApTd center small>{r.ultimo_viaje || <span style={{ color: PLIGHT }}>—</span>}</ApTd>
                      <ApTd center>{r.viajes_ayer > 0
                        ? <span style={{ color: "#c0392b", fontWeight: 800 }}>{r.viajes_ayer}</span>
                        : <span style={{ color: PLIGHT }}>0</span>}</ApTd>
                      <ApTd center>{r.viajes_7d || <span style={{ color: PLIGHT }}>0</span>}</ApTd>
                      <ApTd center>{r.viajes_15d || <span style={{ color: PLIGHT }}>0</span>}</ApTd>
                      <ApTd center bold>{r.viajes_30d || <span style={{ color: PLIGHT }}>0</span>}</ApTd>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      )}
      <div style={{ marginTop: 10, fontSize: 11, color: PLIGHT, fontStyle: "italic" }}>
        🔴 Fila roja = rechazado que operó <strong>ayer</strong> · 🟡 ámbar = operó en los últimos 7 días. El cruce es por CURP contra el padrón enriquecido; ventanas relativas a hoy.
      </div>
    </div>
  );
}

// ── SUB-MUNDO LIMPIEZA · embudo de actividad (vw_padron_embudo) + alertas ────
function PadronLimpieza() {
  const [rows, setRows] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [busqueda, setBusqueda] = useState("");
  const [filtroEsc, setFiltroEsc] = useState(null); // escalón seleccionado del embudo
  const PNAVY = "#1a3a6b", PMUTED = "#64748b", PLIGHT = "#94a3b8", PBORDER = "#e4e7ec";

  useEffect(() => {
    let alive = true;
    (async () => {
      setLoading(true); setError(null);
      try {
        const { data, error } = await sb.from("vw_padron_embudo").select("*").limit(5000);
        if (error) throw error;
        if (alive) setRows(data || []);
      } catch (e) { if (alive) setError(e.message || "Error"); }
      finally { if (alive) setLoading(false); }
    })();
    return () => { alive = false; };
  }, []);

  // Definición del embudo (orden y etiquetas)
  const ESCALONES = [
    { id: "ayer",  label: "Operó ayer/hoy",   color: "#10b981" },
    { id: "7d",    label: "Últimos 7 días",   color: "#22c55e" },
    { id: "15d",   label: "Últimos 15 días",  color: "#84cc16" },
    { id: "30d",   label: "Últimos 30 días",  color: "#eab308" },
    { id: "45d",   label: "Últimos 45 días",  color: "#f59e0b" },
    { id: "60d",   label: "Últimos 60 días",  color: "#f97316" },
    { id: "mas60", label: "Inactivo +60 días", color: "#ef4444" },
    { id: "nunca", label: "Nunca operó",      color: "#991b1b" },
  ];

  const conteos = useMemo(() => {
    const c = {};
    ESCALONES.forEach(e => c[e.id] = 0);
    rows.forEach(r => { if (c[r.escalon] != null) c[r.escalon]++; });
    return c;
  }, [rows]);

  const alertas = useMemo(() => ({
    a7:  rows.filter(r => r.alerta === "alerta_7").length,
    a15: rows.filter(r => r.alerta === "alerta_15").length,
    a30: rows.filter(r => r.alerta === "alerta_30").length,
    dep: rows.filter(r => r.alerta === "depurar").length,
  }), [rows]);

  const maxC = useMemo(() => Math.max(1, ...ESCALONES.map(e => conteos[e.id] || 0)), [conteos]);

  const filtradas = useMemo(() => {
    let res = rows;
    if (filtroEsc) res = res.filter(r => r.escalon === filtroEsc);
    const q = busqueda.toLowerCase().trim();
    if (q) res = res.filter(r => [r.driver_id, r.nombre].some(v => String(v ?? "").toLowerCase().includes(q)));
    // orden: más inactivos primero (nunca arriba, luego por días desc)
    const rank = { nunca: 999, mas60: 998 };
    return [...res].sort((a, b) => {
      const ra = rank[a.escalon] ?? (a.dias_sin_operar || 0);
      const rb = rank[b.escalon] ?? (b.dias_sin_operar || 0);
      return rb - ra;
    });
  }, [rows, busqueda, filtroEsc]);

  const escMeta = (id) => ESCALONES.find(e => e.id === id) || { label: id, color: PMUTED };

  const exportar = () => {
    const headers = ["driver_id", "Nombre", "Estado", "Escalón", "Último viaje", "Días sin operar", "Total viajes", "Alerta"];
    const filas = filtradas.map(r => [r.driver_id, r.nombre || "", r.status, escMeta(r.escalon).label,
      r.ultimo_viaje || "", r.dias_sin_operar ?? "", r.total_viajes,
      r.alerta === "depurar" ? "DEPURAR" : r.alerta === "alerta_30" ? "+30 días" :
      r.alerta === "alerta_15" ? "+15 días" : r.alerta === "alerta_7" ? "+7 días" : "OK"]);
    padronCsv(headers, filas, "padron_limpieza");
  };

  // Descarga un Excel con TODOS los conductores, una hoja por escalón + resumen
  const descargarExcelPorEscalon = async () => {
    const H = ["ID conductor", "Nombre", "Estado", "Último viaje", "Días sin operar", "Total viajes"];
    const filaDe = r => [r.driver_id, r.nombre || "(sin nombre)", r.status, r.ultimo_viaje || "—",
      r.dias_sin_operar != null ? r.dias_sin_operar : "nunca", r.total_viajes || 0];

    // Hoja resumen (embudo)
    const resumen = [["Escalón", "Conductores", "% del padrón"]];
    ESCALONES.forEach(e => {
      const n = conteos[e.id] || 0;
      resumen.push([e.label, n, (total ? Math.round(100 * n / total) : 0) + "%"]);
    });
    resumen.push(["", "", ""]);
    resumen.push(["TOTAL PADRÓN", total, "100%"]);
    resumen.push(["Candidatos a depurar (nunca + +60d)", depurar, ""]);
    resumen.push(["Activos (≤60 días)", activos, ""]);

    const hojas = [{ nombre: "Resumen embudo", datos: resumen }];

    // Una hoja por escalón (ordenado del más activo al más inactivo)
    ESCALONES.forEach(e => {
      const grupo = rows
        .filter(r => r.escalon === e.id)
        .sort((a, b) => (b.dias_sin_operar || 0) - (a.dias_sin_operar || 0));
      const datos = [H, ...grupo.map(filaDe)];
      if (grupo.length === 0) datos.push(["(sin conductores en este escalón)", "", "", "", "", ""]);
      // nombre de hoja: Excel no admite > 31 chars ni ciertos símbolos
      const nombreHoja = `${e.label} (${grupo.length})`.replace(/[\\/?*:\[\]]/g, "").slice(0, 31);
      hojas.push({ nombre: nombreHoja, datos });
    });

    await descargarExcelMultihoja(hojas, "padron_limpieza_por_escalon");
  };

  if (loading) return <div style={{ padding: 40, textAlign: "center", color: PMUTED, fontSize: 13 }}>Cargando embudo…</div>;
  if (error) return <div style={{ background: "#fef2f2", border: "1px solid #fecaca", borderRadius: 10, padding: 14, fontSize: 12, color: "#991b1b" }}>{error}</div>;

  const total = rows.length;
  const activos = (conteos.ayer || 0) + (conteos["7d"] || 0) + (conteos["15d"] || 0) + (conteos["30d"] || 0) + (conteos["45d"] || 0) + (conteos["60d"] || 0);
  const depurar = (conteos.nunca || 0) + (conteos.mas60 || 0);

  return (
    <div style={{ padding: 20 }}>
      {/* KPIs + alertas */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 10, marginBottom: 14 }}>
        <PKpi l="Padrón total" v={total} s="conductores en snapshot" accent={PNAVY} />
        <PKpi l="Activos (≤60 días)" v={activos} s="operaron en el período" accent="#10b981" />
        <PKpi l="⚠️ Candidatos a depurar" v={depurar} s="nunca operó o +60 días" accent="#ef4444" />
        <PKpi l="Alerta +30 días" v={alertas.a30} s="sin operar (revisar)" accent="#f59e0b" />
      </div>

      {/* EMBUDO */}
      <div style={{ background: "#fff", border: `1px solid ${PBORDER}`, borderRadius: 12, padding: "16px 18px", marginBottom: 14 }}>
        <div style={{ fontSize: 13, fontWeight: 700, color: PNAVY, marginBottom: 12 }}>Embudo de actividad
          <span style={{ fontWeight: 400, color: PLIGHT, fontSize: 11, marginLeft: 8 }}>· clic en un escalón para filtrar la tabla</span>
        </div>
        <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
          {ESCALONES.map(e => {
            const n = conteos[e.id] || 0;
            const pct = Math.round((n / maxC) * 100);
            const sel = filtroEsc === e.id;
            return (
              <div key={e.id} onClick={() => setFiltroEsc(sel ? null : e.id)}
                style={{ display: "flex", alignItems: "center", gap: 10, cursor: "pointer", opacity: filtroEsc && !sel ? 0.5 : 1 }}>
                <div style={{ width: 130, fontSize: 12, fontWeight: sel ? 800 : 600, color: sel ? e.color : PMUTED, textAlign: "right", flexShrink: 0 }}>{e.label}</div>
                <div style={{ flex: 1, background: "#f1f5f9", borderRadius: 6, height: 26, position: "relative", overflow: "hidden" }}>
                  <div style={{ width: `${Math.max(pct, n > 0 ? 4 : 0)}%`, height: "100%", background: e.color, borderRadius: 6, transition: "width .3s", display: "flex", alignItems: "center", justifyContent: "flex-end", paddingRight: 8 }}>
                    {pct > 12 && <span style={{ color: "#fff", fontSize: 11, fontWeight: 800 }}>{n}</span>}
                  </div>
                  {pct <= 12 && <span style={{ position: "absolute", left: `calc(${Math.max(pct,4)}% + 6px)`, top: 5, fontSize: 11, fontWeight: 800, color: e.color }}>{n}</span>}
                </div>
                <div style={{ width: 42, fontSize: 11, color: PLIGHT, textAlign: "left", flexShrink: 0 }}>{total ? Math.round(100*n/total) : 0}%</div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Banda de alertas de limpieza */}
      <div style={{ display: "flex", gap: 10, marginBottom: 12, flexWrap: "wrap" }}>
        {[
          { k: "alerta_7",  label: "+7 días sin operar",  n: alertas.a7,  c: "#eab308" },
          { k: "alerta_15", label: "+15 días sin operar", n: alertas.a15, c: "#f59e0b" },
          { k: "alerta_30", label: "+30 días sin operar", n: alertas.a30, c: "#f97316" },
          { k: "depurar",   label: "Nunca operó",         n: alertas.dep, c: "#ef4444" },
        ].map(a => (
          <div key={a.k} style={{ flex: 1, minWidth: 140, background: "#fff", border: `1px solid ${PBORDER}`, borderLeft: `4px solid ${a.c}`, borderRadius: 8, padding: "8px 12px" }}>
            <div style={{ fontSize: 20, fontWeight: 800, color: a.c }}>{a.n}</div>
            <div style={{ fontSize: 11, color: PMUTED }}>{a.label}</div>
          </div>
        ))}
      </div>

      {/* Toolbar */}
      <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 10, flexWrap: "wrap" }}>
        <input value={busqueda} onChange={e => setBusqueda(e.target.value)} placeholder="Buscar por nombre o ID…"
          style={{ flex: 1, minWidth: 220, maxWidth: 360, padding: "7px 10px", border: "1px solid #d0d5dd", borderRadius: 6, fontSize: 12, fontFamily: "'Geist', sans-serif" }} />
        {filtroEsc && (
          <button onClick={() => setFiltroEsc(null)} style={{ fontSize: 12, fontWeight: 700, padding: "7px 12px", borderRadius: 8, cursor: "pointer", border: "none", background: escMeta(filtroEsc).color, color: "#fff", fontFamily: "'Geist', sans-serif", display: "inline-flex", alignItems: "center", gap: 6 }}>
            {escMeta(filtroEsc).label} <i className="ti ti-x" style={{ fontSize: 13 }} />
          </button>
        )}
        <span style={{ fontSize: 12, color: PMUTED }}>{filtradas.length} de {total}</span>
        <button onClick={descargarExcelPorEscalon} style={{ marginLeft: "auto", fontSize: 11, fontWeight: 700, padding: "6px 12px", borderRadius: 6, border: "none", background: "#1f7a4d", color: "#fff", cursor: "pointer", fontFamily: "'Geist', sans-serif", display: "inline-flex", alignItems: "center", gap: 5 }}>
          <i className="ti ti-file-spreadsheet" style={{ fontSize: 13 }} />Excel por escalón
        </button>
        <button onClick={exportar} style={{ fontSize: 11, fontWeight: 600, padding: "6px 11px", borderRadius: 6, border: `1px solid ${PBORDER}`, background: "#fff", color: PMUTED, cursor: "pointer", fontFamily: "'Geist', sans-serif", display: "inline-flex", alignItems: "center", gap: 5 }}>
          <i className="ti ti-download" style={{ fontSize: 12 }} />CSV vista
        </button>
      </div>

      {/* Tabla */}
      <div style={{ background: "#fff", borderRadius: 12, border: `0.5px solid ${PBORDER}`, overflow: "hidden" }}>
        <div style={{ maxHeight: "50vh", overflow: "auto" }}>
          <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
            <thead style={{ position: "sticky", top: 0, zIndex: 1, background: "#f8fafc" }}>
              <tr>
                <ApTh>ID conductor</ApTh><ApTh>Nombre</ApTh><ApTh>Rol</ApTh><ApTh>Escalón</ApTh>
                <ApTh>Último viaje</ApTh><ApTh>Días sin operar</ApTh><ApTh>Total viajes</ApTh>
              </tr>
            </thead>
            <tbody>
              {filtradas.length === 0 && (
                <tr><td colSpan={7} style={{ padding: 30, textAlign: "center", color: PLIGHT }}>Sin resultados</td></tr>
              )}
              {filtradas.map((r, i) => {
                const meta = escMeta(r.escalon);
                const depurar = r.escalon === "nunca" || r.escalon === "mas60";
                return (
                  <tr key={r.driver_id ?? i} style={{ borderBottom: "0.5px solid #f4f5f7", background: depurar ? "#fef2f2" : "transparent" }}>
                    <ApTd mono>{r.driver_id}</ApTd>
                    <ApTd bold>{r.nombre || <span style={{ color: PLIGHT }}>(sin nombre)</span>}</ApTd>
                    <ApTd><PadronRolBadge value={r.is_only_helper} /></ApTd>
                    <ApTd>
                      <span style={{ background: meta.color + "22", color: meta.color, fontSize: 10, fontWeight: 700, padding: "2px 8px", borderRadius: 4 }}>{meta.label}</span>
                    </ApTd>
                    <ApTd center small>{r.ultimo_viaje || <span style={{ color: PLIGHT }}>—</span>}</ApTd>
                    <ApTd center>{r.dias_sin_operar != null
                      ? <span style={{ fontWeight: depurar ? 800 : 400, color: depurar ? "#ef4444" : "inherit" }}>{r.dias_sin_operar}</span>
                      : <span style={{ color: "#ef4444", fontWeight: 800 }}>nunca</span>}</ApTd>
                    <ApTd center>{r.total_viajes || <span style={{ color: PLIGHT }}>0</span>}</ApTd>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
      <div style={{ marginTop: 10, fontSize: 11, color: PLIGHT, fontStyle: "italic" }}>
        ℹ️ Combina histórico cargado + operación diaria. Filas en rojo = candidatos a depurar (nunca operó o +60 días sin operar). Ventanas relativas a hoy; se actualiza solo con los viajes diarios.
      </div>
    </div>
  );
}

function PadronMeliAdmin({ usuario }) {
  const [mundo, setMundo] = useState("drivers"); // drivers (principal) | vehiculos
  return (
    <div style={{ fontFamily: "'Geist', sans-serif", background: "#f0f2f5", minHeight: "60vh" }}>
      <div style={{ background: "#fff", borderBottom: "1px solid #e4e7ec", padding: "10px 24px", display: "flex", gap: 8, alignItems: "center" }}>
        <span style={{ fontSize: 11, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5, marginRight: 4 }}>Padrón MELI</span>
        {[
          { id: "drivers", label: "Conductores", icon: "ti-user" },
          { id: "vehiculos", label: "Vehículos", icon: "ti-truck" },
          { id: "cursos", label: "Cursos", icon: "ti-school" },
          { id: "rechazados", label: "Rechazados", icon: "ti-user-x" },
          { id: "limpieza", label: "Limpieza", icon: "ti-filter" },
        ].map(m => (
          <button key={m.id} onClick={() => setMundo(m.id)} style={{
            border: "none", cursor: "pointer", padding: "7px 16px", borderRadius: 8,
            fontSize: 13, fontWeight: 700, fontFamily: "'Geist', sans-serif",
            background: mundo === m.id ? "#1a3a6b" : "#eef2f7",
            color: mundo === m.id ? "#fff" : "#64748b",
            display: "inline-flex", alignItems: "center", gap: 6,
          }}>
            <i className={`ti ${m.icon}`} style={{ fontSize: 15 }} />{m.label}
          </button>
        ))}
      </div>
      {mundo === "cursos" ? <PadronCursos key="cursos" />
        : mundo === "rechazados" ? <PadronRechazados key="rechazados" />
        : mundo === "limpieza" ? <PadronLimpieza key="limpieza" />
        : <PadronMundo key={mundo} tipo={mundo} />}
    </div>
  );
}

function PadronMundo({ tipo }) {
  const cfg = PADRON_CFG[tipo];
  const [vista, setVista] = useState("data"); // data | altasbajas | repetidas | cambios
  const [fechasDisp, setFechasDisp] = useState([]);
  const [fechaSel, setFechaSel] = useState(null);       // data + repetidas
  const [fechaA, setFechaA] = useState(null);           // altas/bajas A
  const [fechaB, setFechaB] = useState(null);           // altas/bajas B
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [busqueda, setBusqueda] = useState("");

  const [dataRows, setDataRows] = useState([]);
  const [diffRows, setDiffRows] = useState([]);
  const [repRows, setRepRows] = useState([]);
  const [cambiosDia, setCambiosDia] = useState([]);   // [{fecha, altas, bajas, cambios, rows}]
  const [diaDetalle, setDiaDetalle] = useState(null); // fecha seleccionada en "cambios"

  // 1) Fechas disponibles
  useEffect(() => {
    let alive = true;
    (async () => {
      setLoading(true); setError(null);
      try {
        const { data, error } = await sb
          .from(cfg.tabla)
          .select("fecha_snapshot")
          .order("fecha_snapshot", { ascending: false })
          .limit(5000);
        if (error) throw error;
        const fechas = [...new Set((data || []).map(f => f.fecha_snapshot))];
        if (!alive) return;
        setFechasDisp(fechas);
        setFechaSel(fechas[0] || null);
        setFechaB(fechas[0] || null);
        setFechaA(fechas[1] || fechas[0] || null);
      } catch (e) {
        if (alive) { setError(e.message || "Error cargando fechas"); }
      } finally {
        if (alive) setLoading(false);
      }
    })();
    return () => { alive = false; };
  }, [tipo]);

  // 2) Data completa del snapshot seleccionado
  useEffect(() => {
    if (vista !== "data" || !fechaSel || tipo === "drivers") return;
    let alive = true;
    (async () => {
      setLoading(true); setError(null);
      try {
        const { data, error } = await sb
          .from(cfg.tabla).select(cfg.selectData)
          .eq("fecha_snapshot", fechaSel).limit(5000);
        if (error) throw error;
        if (alive) setDataRows(data || []);
      } catch (e) { if (alive) setError(e.message || "Error"); }
      finally { if (alive) setLoading(false); }
    })();
    return () => { alive = false; };
  }, [vista, fechaSel, tipo]);

  // 3) Altas / bajas / cambios entre A y B
  useEffect(() => {
    if (vista !== "altasbajas" || !fechaA || !fechaB) return;
    let alive = true;
    (async () => {
      setLoading(true); setError(null);
      try {
        const { data, error } = await sb.rpc(cfg.rpcDiff, { fecha_a: fechaA, fecha_b: fechaB });
        if (error) throw error;
        if (alive) setDiffRows(data || []);
      } catch (e) { if (alive) setError(e.message || "Error"); }
      finally { if (alive) setLoading(false); }
    })();
    return () => { alive = false; };
  }, [vista, fechaA, fechaB, tipo]);

  // 4) Placas repetidas SDD (solo vehículos)
  useEffect(() => {
    if (vista !== "repetidas" || !cfg.tieneRepetidas || !fechaSel) return;
    let alive = true;
    (async () => {
      setLoading(true); setError(null);
      try {
        const { data, error } = await sb
          .from(cfg.tabla)
          .select("vehicle_id,placa,tipo_nombre,capacidad,es_sdd")
          .eq("fecha_snapshot", fechaSel).limit(5000);
        if (error) throw error;
        const norm = p => String(p || "").replace(/^SDD-/, "");
        const baseTipo = t => String(t || "").replace(/\s*SDD$/i, "").trim();
        const grupos = {};
        (data || []).forEach(r => {
          const k = norm(r.placa);
          (grupos[k] = grupos[k] || []).push(r);
        });
        const out = Object.keys(grupos).filter(k => grupos[k].length > 1).map(k => {
          const items = grupos[k].sort((a, b) => (a.es_sdd === b.es_sdd ? 0 : a.es_sdd ? 1 : -1));
          const tiposBase = new Set(items.map(i => baseTipo(i.tipo_nombre)));
          return {
            placa_norm: k,
            variantes: items.length,
            mismo_tipo: tiposBase.size === 1,
            detalle: items.map(i => `${i.placa} = ${i.tipo_nombre}`).join("  |  "),
            items,
          };
        }).sort((a, b) => (a.mismo_tipo === b.mismo_tipo ? a.placa_norm.localeCompare(b.placa_norm) : a.mismo_tipo ? 1 : -1));
        if (alive) setRepRows(out);
      } catch (e) { if (alive) setError(e.message || "Error"); }
      finally { if (alive) setLoading(false); }
    })();
    return () => { alive = false; };
  }, [vista, fechaSel, tipo]);

  // 5) Cambios por día (últimos 30 pares consecutivos)
  useEffect(() => {
    if (vista !== "cambios" || fechasDisp.length < 2) return;
    let alive = true;
    (async () => {
      setLoading(true); setError(null); setDiaDetalle(null);
      try {
        const asc = [...fechasDisp].sort();
        const pares = [];
        for (let i = 1; i < asc.length; i++) pares.push([asc[i - 1], asc[i]]);
        const ultimos = pares.slice(-30);
        const res = await Promise.all(ultimos.map(([a, b]) =>
          sb.rpc(cfg.rpcDiff, { fecha_a: a, fecha_b: b })
            .then(r => ({ a, b, rows: r.data || [] }))
        ));
        const filas = res.map(({ a, b, rows }) => ({
          fecha: b, prev: a,
          altas: rows.filter(x => x.tipo_cambio === "alta").length,
          bajas: rows.filter(x => x.tipo_cambio === "baja").length,
          cambios: rows.filter(x => cfg.cambioTipos.includes(x.tipo_cambio)).length,
          rows,
        })).sort((x, y) => (x.fecha < y.fecha ? 1 : -1));
        if (alive) setCambiosDia(filas);
      } catch (e) { if (alive) setError(e.message || "Error"); }
      finally { if (alive) setLoading(false); }
    })();
    return () => { alive = false; };
  }, [vista, fechasDisp, tipo]);

  // ── derivados ──
  const altas = useMemo(() => diffRows.filter(r => r.tipo_cambio === "alta"), [diffRows]);
  const bajas = useMemo(() => diffRows.filter(r => r.tipo_cambio === "baja"), [diffRows]);
  const cambios = useMemo(() => diffRows.filter(r => cfg.cambioTipos.includes(r.tipo_cambio)), [diffRows, tipo]);

  const dataFiltrada = useMemo(() => {
    if (!busqueda.trim()) return dataRows;
    const q = busqueda.toLowerCase().trim();
    return dataRows.filter(r => cfg.cols.some(c => String(r[c] ?? "").toLowerCase().includes(q)));
  }, [dataRows, busqueda, tipo]);

  const PNAVY = "#1a3a6b", PMUTED = "#64748b", PLIGHT = "#94a3b8", PBORDER = "#e4e7ec", PORANGE = "#F47B20";

  const subTabs = [
    { id: "data", label: "Data completa", icon: "ti-table" },
    { id: "altasbajas", label: "Altas y bajas", icon: "ti-arrows-diff" },
    ...(cfg.tieneRepetidas ? [{ id: "repetidas", label: "Placas repetidas (SDD)", icon: "ti-copy" }] : []),
    { id: "cambios", label: "Cambios por día", icon: "ti-history" },
  ];

  const selStyle = {
    fontSize: 12, fontWeight: 600, padding: "6px 10px", borderRadius: 6,
    border: `1px solid ${PBORDER}`, background: "#fff", color: PNAVY,
    fontFamily: "'Geist', sans-serif", cursor: "pointer", outline: "none",
  };

  return (
    <div>
      {/* Sub-tabs de vista */}
      <div style={{ background: "#fff", borderBottom: `1px solid ${PBORDER}`, padding: "0 24px", display: "flex", gap: 0, flexWrap: "wrap" }}>
        {subTabs.map(t => (
          <button key={t.id} onClick={() => setVista(t.id)} style={{
            background: "transparent", border: "none", padding: "11px 16px", cursor: "pointer",
            fontSize: 12.5, fontWeight: 600, color: vista === t.id ? PNAVY : PMUTED,
            borderBottom: vista === t.id ? `2px solid ${PORANGE}` : "2px solid transparent",
            display: "inline-flex", alignItems: "center", gap: 6,
          }}>
            <i className={`ti ${t.icon}`} style={{ fontSize: 14 }} />{t.label}
          </button>
        ))}
      </div>

      {/* Toolbar de fechas según vista */}
      <div style={{ background: "#fff", borderBottom: `1px solid ${PBORDER}`, padding: "10px 24px", display: "flex", alignItems: "center", gap: 10, flexWrap: "wrap" }}>
        {(vista === "data" || vista === "repetidas") && (
          <>
            <span style={{ fontSize: 11, fontWeight: 700, color: PMUTED, textTransform: "uppercase", letterSpacing: 0.5 }}>Snapshot</span>
            <select value={fechaSel || ""} onChange={e => setFechaSel(e.target.value)} style={selStyle}>
              {fechasDisp.map(f => <option key={f} value={f}>{f}</option>)}
            </select>
          </>
        )}
        {vista === "altasbajas" && (
          <>
            <span style={{ fontSize: 11, fontWeight: 700, color: PMUTED, textTransform: "uppercase", letterSpacing: 0.5 }}>Comparar</span>
            <select value={fechaA || ""} onChange={e => setFechaA(e.target.value)} style={selStyle}>
              {fechasDisp.map(f => <option key={f} value={f}>{f}</option>)}
            </select>
            <span style={{ color: PLIGHT }}>→</span>
            <select value={fechaB || ""} onChange={e => setFechaB(e.target.value)} style={selStyle}>
              {fechasDisp.map(f => <option key={f} value={f}>{f}</option>)}
            </select>
          </>
        )}
        <div style={{ marginLeft: "auto", fontSize: 11, color: PMUTED, display: "flex", alignItems: "center", gap: 6 }}>
          <span style={{ width: 8, height: 8, borderRadius: "50%", background: "#10b981", display: "inline-block" }} />
          Última: <strong style={{ color: PNAVY }}>{fechasDisp[0] || "—"}</strong>
          <span style={{ color: PLIGHT }}>· cron 08:00 MX</span>
        </div>
      </div>

      <div style={{ padding: "16px 24px" }}>
        {error && (
          <div style={{ background: "#fef2f2", border: "1px solid #fecaca", borderRadius: 10, padding: 14, marginBottom: 12, fontSize: 12, color: "#991b1b" }}>
            {error}
          </div>
        )}
        {loading ? (
          <div style={{ padding: 40, textAlign: "center", color: PMUTED, fontSize: 13 }}>Cargando padrón de {cfg.label}…</div>
        ) : (
          <>
            {/* ── DATA COMPLETA ── */}
            {vista === "data" && (
              tipo === "drivers" ? (
                <PadronDriversData fecha={fechaSel} />
              ) : (
              <div>
                <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 10 }}>
                  <input value={busqueda} onChange={e => setBusqueda(e.target.value)} placeholder={`Buscar en ${dataRows.length} ${cfg.label}…`}
                    style={{ flex: 1, maxWidth: 360, padding: "7px 10px", border: `1px solid #d0d5dd`, borderRadius: 6, fontSize: 12, fontFamily: "'Geist', sans-serif" }} />
                  <span style={{ fontSize: 12, color: PMUTED }}>{dataFiltrada.length} de {dataRows.length}</span>
                  <button onClick={() => padronCsv(cfg.cols, dataFiltrada.map(r => cfg.cols.map(c => padronFmt(r[c]))), `padron_${tipo}`)}
                    style={{ marginLeft: "auto", fontSize: 11, fontWeight: 600, padding: "6px 11px", borderRadius: 6, border: "none", background: PNAVY, color: "#fff", cursor: "pointer", fontFamily: "'Geist', sans-serif", display: "inline-flex", alignItems: "center", gap: 5 }}>
                    <i className="ti ti-download" style={{ fontSize: 12 }} />Exportar CSV
                  </button>
                </div>
                <div style={{ background: "#fff", borderRadius: 12, border: `0.5px solid ${PBORDER}`, overflow: "hidden" }}>
                  <div style={{ maxHeight: "62vh", overflow: "auto" }}>
                    <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
                      <thead style={{ position: "sticky", top: 0, zIndex: 1, background: "#f8fafc" }}>
                        <tr>{cfg.cols.map(c => <ApTh key={c}>{c}</ApTh>)}</tr>
                      </thead>
                      <tbody>
                        {dataFiltrada.length === 0 && (
                          <tr><td colSpan={cfg.cols.length} style={{ padding: 30, textAlign: "center", color: PLIGHT }}>Sin resultados</td></tr>
                        )}
                        {dataFiltrada.map((r, i) => (
                          <tr key={i} style={{ borderBottom: "0.5px solid #f4f5f7" }}>
                            {cfg.cols.map(c => (
                              <ApTd key={c} mono={["driver_id", "vehicle_id", "carrier_id", "document_value", "placa", "tipo_id", "amount_plate"].includes(c)} small>
                                {c === "status" ? (
                                  <span style={{ background: r[c] === "active" ? "#d1fae5" : "#fef3c7", color: r[c] === "active" ? "#065f46" : "#92400e", fontSize: 10, fontWeight: 700, padding: "2px 7px", borderRadius: 4 }}>{padronFmt(r[c])}</span>
                                ) : padronFmt(r[c])}
                              </ApTd>
                            ))}
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
              </div>
              )
            )}

            {/* ── ALTAS Y BAJAS ── */}
            {vista === "altasbajas" && (
              <div>
                <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 10, marginBottom: 14 }}>
                  <PKpi l="➕ Altas" v={altas.length} s={`nuevos en ${fechaB}`} accent="#10b981" />
                  <PKpi l="➖ Bajas" v={bajas.length} s={`removidos vs ${fechaA}`} accent="#dc2626" />
                  <PKpi l="🔄 Cambios" v={cambios.length} s="status / tipo / carrier" accent={PORANGE} />
                </div>
                <PadronDiffTabla titulo="Altas" rows={altas} cols={cfg.diffCols} tipo={tipo} archivo={`altas_${tipo}`} vacio="Sin altas entre las fechas" />
                <div style={{ height: 14 }} />
                <PadronDiffTabla titulo="Bajas" rows={bajas} cols={cfg.diffCols} tipo={tipo} archivo={`bajas_${tipo}`} vacio="Sin bajas entre las fechas" />
                {cambios.length > 0 && (
                  <>
                    <div style={{ height: 14 }} />
                    <PadronDiffTabla titulo="Cambios" rows={cambios} cols={cfg.diffCols} tipo={tipo} archivo={`cambios_${tipo}`} vacio="Sin cambios" />
                  </>
                )}
              </div>
            )}

            {/* ── PLACAS REPETIDAS SDD ── */}
            {vista === "repetidas" && cfg.tieneRepetidas && (
              <div>
                <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 10, marginBottom: 14 }}>
                  <PKpi l="Placas con doble registro" v={repRows.length} s="normal + SDD el mismo día" accent={PNAVY} />
                  <PKpi l="Mismo tipo base" v={repRows.filter(r => r.mismo_tipo).length} s="solo difieren en SDD" accent="#10b981" />
                  <PKpi l="⚠️ Tipo distinto" v={repRows.filter(r => !r.mismo_tipo).length} s="normal vs SDD difieren" accent="#dc2626" />
                </div>
                <div style={{ background: "#fff", borderRadius: 12, border: `0.5px solid ${PBORDER}`, overflow: "hidden" }}>
                  <div style={{ padding: "8px 14px", borderBottom: `1px solid ${PBORDER}`, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                    <div style={{ fontSize: 11, color: PMUTED }}>{repRows.length} placas con variante normal + SDD · snapshot {fechaSel}</div>
                    <button onClick={() => padronCsv(["placa", "variantes", "mismo_tipo_base", "detalle"], repRows.map(r => [r.placa_norm, r.variantes, r.mismo_tipo ? "Sí" : "No", r.detalle]), "placas_repetidas_sdd")}
                      style={{ fontSize: 11, fontWeight: 600, padding: "5px 10px", borderRadius: 6, border: "none", background: PNAVY, color: "#fff", cursor: "pointer", fontFamily: "'Geist', sans-serif", display: "inline-flex", alignItems: "center", gap: 5 }}>
                      <i className="ti ti-download" style={{ fontSize: 12 }} />Exportar CSV
                    </button>
                  </div>
                  <div style={{ maxHeight: "58vh", overflow: "auto" }}>
                    <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
                      <thead style={{ position: "sticky", top: 0, zIndex: 1, background: "#f8fafc" }}>
                        <tr><ApTh>Placa</ApTh><ApTh>Variantes</ApTh><ApTh>Tipo base</ApTh><ApTh>Detalle (placa = tipo)</ApTh></tr>
                      </thead>
                      <tbody>
                        {repRows.length === 0 && (
                          <tr><td colSpan={4} style={{ padding: 30, textAlign: "center", color: PLIGHT }}>Sin placas repetidas en este snapshot</td></tr>
                        )}
                        {repRows.map((r, i) => (
                          <tr key={i} style={{ borderBottom: "0.5px solid #f4f5f7", background: r.mismo_tipo ? "transparent" : "#fff7ed" }}>
                            <ApTd mono bold>{r.placa_norm}</ApTd>
                            <ApTd center>{r.variantes}</ApTd>
                            <ApTd>
                              <span style={{ background: r.mismo_tipo ? "#d1fae5" : "#fee2e2", color: r.mismo_tipo ? "#065f46" : "#991b1b", fontSize: 10, fontWeight: 700, padding: "2px 7px", borderRadius: 4 }}>
                                {r.mismo_tipo ? "Mismo" : "DISTINTO"}
                              </span>
                            </ApTd>
                            <ApTd small>{r.detalle}</ApTd>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
                <div style={{ marginTop: 10, fontSize: 11, color: PLIGHT, fontStyle: "italic" }}>
                  ℹ️ Las marcadas <strong style={{ color: "#991b1b" }}>DISTINTO</strong> tienen la variante SDD con un tipo base diferente al normal (ej. Large vs Small) — conviene revisarlas en MELI.
                </div>
              </div>
            )}

            {/* ── CAMBIOS POR DÍA ── */}
            {vista === "cambios" && (
              <div>
                <div style={{ background: "#fff", borderRadius: 12, border: `0.5px solid ${PBORDER}`, overflow: "hidden", marginBottom: 14 }}>
                  <div style={{ padding: "8px 14px", borderBottom: `1px solid ${PBORDER}`, fontSize: 11, color: PMUTED }}>
                    Cambios día a día (cada fila compara contra el snapshot anterior disponible) · clic en una fila para ver el detalle
                  </div>
                  <div style={{ maxHeight: "40vh", overflow: "auto" }}>
                    <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
                      <thead style={{ position: "sticky", top: 0, zIndex: 1, background: "#f8fafc" }}>
                        <tr><ApTh>Día</ApTh><ApTh>vs</ApTh><ApTh>➕ Altas</ApTh><ApTh>➖ Bajas</ApTh><ApTh>🔄 Cambios</ApTh></tr>
                      </thead>
                      <tbody>
                        {cambiosDia.length === 0 && (
                          <tr><td colSpan={5} style={{ padding: 30, textAlign: "center", color: PLIGHT }}>Sin historial suficiente</td></tr>
                        )}
                        {cambiosDia.map((d, i) => (
                          <tr key={i} onClick={() => setDiaDetalle(diaDetalle === d.fecha ? null : d.fecha)}
                            style={{ borderBottom: "0.5px solid #f4f5f7", cursor: "pointer", background: diaDetalle === d.fecha ? "#eff6ff" : "transparent" }}>
                            <ApTd mono bold>{d.fecha}</ApTd>
                            <ApTd mono small muted>{d.prev}</ApTd>
                            <ApTd center><span style={{ color: d.altas ? "#059669" : PLIGHT, fontWeight: 700 }}>{d.altas}</span></ApTd>
                            <ApTd center><span style={{ color: d.bajas ? "#dc2626" : PLIGHT, fontWeight: 700 }}>{d.bajas}</span></ApTd>
                            <ApTd center><span style={{ color: d.cambios ? PORANGE : PLIGHT, fontWeight: 700 }}>{d.cambios}</span></ApTd>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
                {diaDetalle && (() => {
                  const d = cambiosDia.find(x => x.fecha === diaDetalle);
                  if (!d) return null;
                  const det = d.rows;
                  return (
                    <div>
                      <div style={{ fontSize: 13, fontWeight: 700, color: PNAVY, marginBottom: 8 }}>
                        Detalle {d.prev} → {d.fecha}
                      </div>
                      <PadronDiffTabla titulo="Altas" rows={det.filter(r => r.tipo_cambio === "alta")} cols={cfg.diffCols} tipo={tipo} archivo={`altas_${tipo}_${d.fecha}`} vacio="Sin altas" />
                      <div style={{ height: 12 }} />
                      <PadronDiffTabla titulo="Bajas" rows={det.filter(r => r.tipo_cambio === "baja")} cols={cfg.diffCols} tipo={tipo} archivo={`bajas_${tipo}_${d.fecha}`} vacio="Sin bajas" />
                      <div style={{ height: 12 }} />
                      <PadronDiffTabla titulo="Cambios" rows={det.filter(r => cfg.cambioTipos.includes(r.tipo_cambio))} cols={cfg.diffCols} tipo={tipo} archivo={`cambios_${tipo}_${d.fecha}`} vacio="Sin cambios" />
                    </div>
                  );
                })()}
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
}

// Tabla genérica para resultados de diff (altas / bajas / cambios)
function PadronDiffTabla({ titulo, rows, cols, tipo, archivo, vacio }) {
  const color = titulo === "Altas" ? "#10b981" : titulo === "Bajas" ? "#dc2626" : "#F47B20";
  const exportar = () => padronCsv(
    cols.map(c => c.l),
    rows.map(r => cols.map(c => r[c.k] == null ? "" : r[c.k])),
    archivo
  );
  return (
    <div style={{ background: "#fff", borderRadius: 12, border: "0.5px solid #e4e7ec", overflow: "hidden" }}>
      <div style={{ padding: "8px 14px", borderBottom: "1px solid #e4e7ec", display: "flex", justifyContent: "space-between", alignItems: "center", background: "#f8fafc" }}>
        <div style={{ fontSize: 12, fontWeight: 700, color: "#1a3a6b", display: "inline-flex", alignItems: "center", gap: 6 }}>
          <span style={{ width: 8, height: 8, borderRadius: "50%", background: color, display: "inline-block" }} />
          {titulo} <span style={{ color: "#94a3b8", fontWeight: 600 }}>({rows.length})</span>
        </div>
        {rows.length > 0 && (
          <button onClick={exportar} style={{ fontSize: 11, fontWeight: 600, padding: "5px 10px", borderRadius: 6, border: "none", background: "#1a3a6b", color: "#fff", cursor: "pointer", fontFamily: "'Geist', sans-serif", display: "inline-flex", alignItems: "center", gap: 5 }}>
            <i className="ti ti-download" style={{ fontSize: 12 }} />CSV
          </button>
        )}
      </div>
      {rows.length === 0 ? (
        <div style={{ padding: 24, textAlign: "center", color: "#94a3b8", fontSize: 12 }}>{vacio}</div>
      ) : (
        <div style={{ maxHeight: "48vh", overflow: "auto" }}>
          <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
            <thead style={{ position: "sticky", top: 0, zIndex: 1, background: "#f8fafc" }}>
              <tr>{cols.map(c => <ApTh key={c.k}>{c.l}</ApTh>)}</tr>
            </thead>
            <tbody>
              {rows.map((r, i) => (
                <tr key={i} style={{ borderBottom: "0.5px solid #f4f5f7" }}>
                  {cols.map(c => (
                    <ApTd key={c.k} mono={c.mono} bold={c.bold} small={c.small} muted={c.muted}>
                      {c.badge ? (
                        <span style={{ background: r[c.k] === "active" ? "#d1fae5" : "#fef3c7", color: r[c.k] === "active" ? "#065f46" : "#92400e", fontSize: 10, fontWeight: 700, padding: "2px 7px", borderRadius: 4 }}>{padronFmt(r[c.k])}</span>
                      ) : padronFmt(r[c.k])}
                    </ApTd>
                  ))}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

function PKpi({ l, v, s, accent }) {
  return (
    <div style={{ background: '#fff', borderRadius: 12, border: '0.5px solid #e4e7ec', padding: 14 }}>
      <div style={{ fontSize: 10.5, fontWeight: 700, color: '#64748b', textTransform: 'uppercase', letterSpacing: 0.4, marginBottom: 6 }}>{l}</div>
      <div style={{ fontSize: 22, fontWeight: 800, color: accent || '#1a1a1a', letterSpacing: -0.5, lineHeight: 1 }}>{v}</div>
      <div style={{ fontSize: 10, color: '#94a3b8', marginTop: 4 }}>{s}</div>
    </div>
  );
}

function TablaAltasBajas({ data, tipo, formatCarrier }) {
  const exportar = () => {
    const headers = ['Driver ID', 'Nombre', 'CURP', 'Status', 'Carrier'];
    const rows = data.map(d => [d.driver_id, d.nombre || '', d.document_value || '', d.status || '', formatCarrier(d.carrier_id)]);
    const csv = [headers.join(','), ...rows.map(r => r.map(v => `"${String(v || '').replace(/"/g, '""')}"`).join(','))].join('\n');
    const blob = new Blob(['\uFEFF' + csv], { type: 'text/csv;charset=utf-8;' });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `padron_${tipo}_${new Date().toISOString().split('T')[0]}.csv`;
    a.click();
  };

  if (data.length === 0) return (
    <div style={{ padding: 40, textAlign: 'center', color: '#94a3b8', fontSize: 13 }}>
      Sin {tipo === 'alta' ? 'altas' : 'bajas'} entre las fechas seleccionadas
    </div>
  );

  return (
    <>
      <div style={{ padding: '8px 14px', borderBottom: '1px solid #e4e7ec', display: 'flex', justifyContent: 'space-between', alignItems: 'center', background: '#fff' }}>
        <div style={{ fontSize: 11, color: '#64748b' }}>{data.length} {tipo === 'alta' ? 'altas' : 'bajas'}</div>
        <button onClick={exportar} style={{
          fontSize: 11, fontWeight: 600, padding: '5px 10px', borderRadius: 6,
          border: 'none', background: '#1a3a6b', color: '#fff', cursor: 'pointer',
          fontFamily: "'Geist', sans-serif", display: 'inline-flex', alignItems: 'center', gap: 5,
        }}>
          <i className="ti ti-download" style={{ fontSize: 12 }} />Exportar CSV
        </button>
      </div>
      <div style={{ maxHeight: '55vh', overflowY: 'auto' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 12 }}>
          <thead style={{ position: 'sticky', top: 0, zIndex: 1, background: '#f8fafc' }}>
            <tr>
              <ApTh>Driver ID</ApTh><ApTh>Nombre</ApTh><ApTh>CURP</ApTh>
              <ApTh>Status</ApTh><ApTh>Carrier</ApTh>
            </tr>
          </thead>
          <tbody>
            {data.map((d, i) => (
              <tr key={i} style={{ borderBottom: '0.5px solid #f4f5f7' }}>
                <ApTd mono>{d.driver_id}</ApTd>
                <ApTd bold>{d.nombre || '—'}</ApTd>
                <ApTd mono small>{d.document_value || '—'}</ApTd>
                <ApTd>
                  <span style={{
                    background: d.status === 'active' ? '#d1fae5' : '#fef3c7',
                    color: d.status === 'active' ? '#065f46' : '#92400e',
                    fontSize: 10, fontWeight: 700, padding: '2px 7px', borderRadius: 4,
                  }}>{d.status || '—'}</span>
                </ApTd>
                <ApTd mono small>{formatCarrier(d.carrier_id)}</ApTd>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </>
  );
}

function TablaCambiosCarrier({ data, formatCarrier }) {
  const exportar = () => {
    const headers = ['Driver ID', 'Nombre', 'CURP', 'Carrier anterior', 'Carrier nuevo', 'Status'];
    const rows = data.map(d => [d.driver_id, d.nombre || '', d.curp || '', formatCarrier(d.carrier_anterior), formatCarrier(d.carrier_actual), d.status]);
    const csv = [headers.join(','), ...rows.map(r => r.map(v => `"${String(v || '').replace(/"/g, '""')}"`).join(','))].join('\n');
    const blob = new Blob(['\uFEFF' + csv], { type: 'text/csv;charset=utf-8;' });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `padron_cambios_carrier_${new Date().toISOString().split('T')[0]}.csv`;
    a.click();
  };

  if (data.length === 0) return (
    <div style={{ padding: 40, textAlign: 'center', color: '#94a3b8', fontSize: 13 }}>
      Sin cambios de carrier entre las fechas seleccionadas
    </div>
  );

  return (
    <>
      <div style={{ padding: '8px 14px', borderBottom: '1px solid #e4e7ec', display: 'flex', justifyContent: 'space-between', alignItems: 'center', background: '#fff' }}>
        <div style={{ fontSize: 11, color: '#64748b' }}>{data.length} cambios de carrier</div>
        <button onClick={exportar} style={{
          fontSize: 11, fontWeight: 600, padding: '5px 10px', borderRadius: 6,
          border: 'none', background: '#1a3a6b', color: '#fff', cursor: 'pointer',
          fontFamily: "'Geist', sans-serif", display: 'inline-flex', alignItems: 'center', gap: 5,
        }}>
          <i className="ti ti-download" style={{ fontSize: 12 }} />Exportar CSV
        </button>
      </div>
      <div style={{ maxHeight: '55vh', overflowY: 'auto' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 12 }}>
          <thead style={{ position: 'sticky', top: 0, zIndex: 1, background: '#f8fafc' }}>
            <tr>
              <ApTh>Driver ID</ApTh><ApTh>Nombre</ApTh><ApTh>CURP</ApTh>
              <ApTh>Carrier anterior</ApTh><ApTh>→</ApTh><ApTh>Carrier nuevo</ApTh>
            </tr>
          </thead>
          <tbody>
            {data.map((d, i) => (
              <tr key={i} style={{ borderBottom: '0.5px solid #f4f5f7' }}>
                <ApTd mono>{d.driver_id}</ApTd>
                <ApTd bold>{d.nombre || '—'}</ApTd>
                <ApTd mono small>{d.curp || '—'}</ApTd>
                <ApTd mono small muted>{formatCarrier(d.carrier_anterior)}</ApTd>
                <ApTd center>→</ApTd>
                <ApTd mono small bold>{formatCarrier(d.carrier_actual)}</ApTd>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </>
  );
}

function ApTh({ children }) {
  return <th style={{ padding: '8px 10px', fontSize: 9, fontWeight: 700, textTransform: 'uppercase', letterSpacing: 0.5, color: '#64748b', textAlign: 'left', borderBottom: '1px solid #e4e7ec', whiteSpace: 'nowrap' }}>{children}</th>;
}

function ApTd({ children, bold, muted, mono, center, small }) {
  return <td style={{ padding: '8px 10px', fontSize: small ? 11 : 12, fontFamily: mono ? 'monospace' : "'Geist', sans-serif", color: muted ? '#64748b' : '#1a1a1a', fontWeight: bold ? 600 : 'normal', textAlign: center ? 'center' : 'left' }}>{children}</td>;
}

// ── MODAL ──────────────────────────────────────────────────────────────────
function MeliModal({ modal, onClose }) {
  const [busqueda, setBusqueda] = useState("");
  const filas = modal.filas || [];
  const columnas = modal.columnas || (filas[0] ? Object.keys(filas[0]) : []);

  const filtradas = useMemo(() => {
    let res = filas;
    if (modal.filtros) {
      Object.entries(modal.filtros).forEach(([col, valores]) => {
        if (valores && valores.length > 0) {
          res = res.filter(r => valores.includes(r[col]));
        }
      });
    }
    if (busqueda.trim()) {
      const q = busqueda.toLowerCase().trim();
      res = res.filter(row =>
        columnas.some(c => {
          const val = row[c];
          if (val == null) return false;
          return String(val).toLowerCase().includes(q);
        })
      );
    }
    return res;
  }, [busqueda, filas, columnas, modal.filtros]);

  return (
    <div onClick={onClose}
      style={{ position: "fixed", top: 0, left: 0, right: 0, bottom: 0,
        background: "rgba(15,23,42,0.55)", zIndex: 9999,
        display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
      <div onClick={e => e.stopPropagation()}
        style={{ background: "#fff", borderRadius: 12, width: "100%", maxWidth: 1200,
          maxHeight: "92vh", display: "flex", flexDirection: "column", overflow: "hidden",
          boxShadow: "0 20px 50px rgba(0,0,0,0.25)" }}>
        <div style={{ padding: "14px 20px", borderBottom: "1px solid #e4e7ec",
          display: "flex", alignItems: "center", justifyContent: "space-between", gap: 12 }}>
          <div>
            <div style={{ fontSize: 15, fontWeight: 700, color: "#1a3a6b" }}>{modal.titulo}</div>
            <div style={{ fontSize: 11, color: "#64748b", marginTop: 2 }}>
              {filtradas.length} {filtradas.length === 1 ? "registro" : "registros"}
              {(busqueda || modal.filtros) && ` (de ${filas.length} totales)`}
            </div>
          </div>
          <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
            <input type="text" placeholder="Buscar..." value={busqueda}
              onChange={e => setBusqueda(e.target.value)}
              style={{ width: 240, padding: "7px 10px", border: "1px solid #d0d5dd",
                borderRadius: 6, fontSize: 12, fontFamily: "'Geist', sans-serif" }} />
            <button onClick={() => descargarExcelMeli(filtradas, modal.nombreArchivo || "export_meli", modal.titulo.slice(0, 31))}
              className="btn-orange" style={{ padding: "7px 12px", fontSize: 12 }}>
              Descargar Excel
            </button>
            <button onClick={onClose}
              style={{ background: "transparent", border: "none", fontSize: 22, cursor: "pointer",
                color: "#64748b", padding: "0 4px", lineHeight: 1 }}>×</button>
          </div>
        </div>

        {modal.filtros_ui && (
          <div style={{ padding: "10px 20px", background: "#f8fafc", borderBottom: "1px solid #e4e7ec" }}>
            {modal.filtros_ui}
          </div>
        )}

        <div style={{ flex: 1, overflow: "auto" }}>
          <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
            <thead style={{ position: "sticky", top: 0, background: "#f8fafc", zIndex: 1 }}>
              <tr style={{ borderBottom: "2px solid #e2e8f0" }}>
                {columnas.map(c => (
                  <th key={c} style={{ textAlign: "left", padding: "8px 12px",
                    fontSize: 10, fontWeight: 700, color: "#475569",
                    textTransform: "uppercase", letterSpacing: 0.5,
                    whiteSpace: "nowrap" }}>{c}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {filtradas.length === 0 && (
                <tr><td colSpan={columnas.length} style={{ padding: 30, textAlign: "center", color: "#94a3b8" }}>
                  Sin resultados
                </td></tr>
              )}
              {filtradas.map((row, i) => (
                <tr key={i} style={{ borderBottom: "1px solid #f1f5f9" }}>
                  {columnas.map(c => (
                    <td key={c} style={{ padding: "7px 12px", color: "#1a1a1a", whiteSpace: "nowrap" }}>
                      {row[c] === null || row[c] === undefined ? "—"
                        : typeof row[c] === "boolean" ? (row[c] ? "Sí" : "No")
                        : String(row[c])}
                    </td>
                  ))}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

// ── HELPERS visuales ───────────────────────────────────────────────────────
function PoolMeliKpi({ label, value, sublabel, color = "#1a3a6b", danger = false, warn = false, onClick = null }) {
  const bg = danger ? "#fef2f2" : warn ? "#fffbeb" : "#fff";
  const border = danger ? "#fecaca" : warn ? "#fde68a" : "#e4e7ec";
  const valColor = danger ? "#991b1b" : warn ? "#92400e" : color;
  const clickable = !!onClick;
  return (
    <div onClick={onClick}
      style={{ background: bg, border: `1px solid ${border}`, borderRadius: 12, padding: 16,
        cursor: clickable ? "pointer" : "default", transition: "all 0.15s",
        ...(clickable ? { boxShadow: "0 1px 2px rgba(0,0,0,0.03)" } : {}) }}
      onMouseEnter={e => clickable && (e.currentTarget.style.boxShadow = "0 4px 12px rgba(26,58,107,0.12)")}
      onMouseLeave={e => clickable && (e.currentTarget.style.boxShadow = "0 1px 2px rgba(0,0,0,0.03)")}>
      <div style={{ fontSize: 11, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 6, fontWeight: 600,
        display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <span>{label}</span>
        {clickable && <span style={{ fontSize: 9, color: "#94a3b8" }}>VER →</span>}
      </div>
      <div style={{ fontSize: 28, fontWeight: 700, color: valColor, lineHeight: 1, marginBottom: 4 }}>{value}</div>
      {sublabel && <div style={{ fontSize: 11, color: "#94a3b8" }}>{sublabel}</div>}
    </div>
  );
}

function PerfilBadgeMX({ perfil }) {
  const styles = {
    IDEAL:         { bg: "#ecfdf5", color: "#047857", label: "IDEAL" },
    INCONSISTENTE: { bg: "#fef3c7", color: "#92400e", label: "INCONSISTENTE" },
    PROBLEMATICO:  { bg: "#fee2e2", color: "#991b1b", label: "PROBLEMÁTICO" },
    RIGUROSO:      { bg: "#dbeafe", color: "#1e40af", label: "RIGUROSO" },
    sin_datos:     { bg: "#f1f5f9", color: "#64748b", label: "S/D" },
  };
  const s = styles[perfil] || styles.sin_datos;
  return (
    <span style={{ display: "inline-block", padding: "2px 8px", borderRadius: 4, fontSize: 10, fontWeight: 700, letterSpacing: 0.5, backgroundColor: s.bg, color: s.color }}>
      {s.label}
    </span>
  );
}

function ScoreBadgeMX({ cat }) {
  const styles = {
    A: { bg: "#047857", color: "#fff" },
    B: { bg: "#0891b2", color: "#fff" },
    C: { bg: "#ca8a04", color: "#fff" },
    D: { bg: "#b91c1c", color: "#fff" },
  };
  const s = styles[cat] || styles.B;
  return (
    <span style={{ display: "inline-flex", alignItems: "center", justifyContent: "center", width: 24, height: 24, borderRadius: 4, fontSize: 12, fontWeight: 700, backgroundColor: s.bg, color: s.color }}>
      {cat}
    </span>
  );
}

// ── RESUMEN KPI · Día anterior (D-1) ────────────────────────────────────
function PoolMeliResumenKPI() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  
  // Helpers de fecha
  const restarDias = (n) => {
    const d = new Date();
    d.setDate(d.getDate() - n);
    return d;
  };
  const formatearISO = (d) => `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
  
  // ─── Selector de período ───────────────────────────────────────────────
  // modo: 'dia' (un día específico) | 'rango' (período acumulado)
  const [modo, setModo] = useState('dia');
  
  // Estado del día (default: ayer)
  const [fechaSeleccionada, setFechaSeleccionada] = useState(() => formatearISO(restarDias(1)));
  
  // Estado del rango (default: últimos 7 días)
  const [rangoSel, setRangoSel] = useState(() => ({
    desde: formatearISO(restarDias(7)),
    hasta: formatearISO(restarDias(1)),
  }));
  
  // Fechas de referencia para los botones (calculadas una vez al montar)
  const fechasReferencia = useMemo(() => ({
    d1: formatearISO(restarDias(1)),
    d7: formatearISO(restarDias(7)),
    d30: formatearISO(restarDias(30)),
  }), []);
  
  // Display formateado
  const formatearDisplay = (yyyymmdd) => {
    if (!yyyymmdd) return '';
    const [y, m, d] = yyyymmdd.split('-');
    return `${d}-${m}-${y}`;
  };
  const meses = ["Enero","Febrero","Marzo","Abril","Mayo","Junio","Julio","Agosto","Septiembre","Octubre","Noviembre","Diciembre"];
  const fechaTextoLargo = (yyyymmdd) => {
    if (!yyyymmdd) return '';
    const [y, m, d] = yyyymmdd.split('-').map(Number);
    return `${d} de ${meses[m-1]} de ${y}`;
  };
  
  // Cargar datos según modo
  useEffect(() => {
    let alive = true;
    (async () => {
      setLoading(true);
      setError(null);
      try {
        let rpc, error;
        if (modo === 'dia') {
          ({ data: rpc, error } = await sb.rpc("get_resumen_kpi_dia", { p_fecha: fechaSeleccionada }));
        } else {
          ({ data: rpc, error } = await sb.rpc("get_resumen_kpi_rango", { 
            p_fecha_desde: rangoSel.desde, 
            p_fecha_hasta: rangoSel.hasta 
          }));
        }
        if (!alive) return;
        if (error) throw error;
        setData(rpc);
      } catch (e) {
        if (alive) setError(e.message || "Error cargando datos");
      } finally {
        if (alive) setLoading(false);
      }
    })();
    return () => { alive = false; };
  }, [modo, fechaSeleccionada, rangoSel.desde, rangoSel.hasta]);

  // Modal de detalle drilldown
  const [modal, setModal] = useState(null);
  const [modalLoading, setModalLoading] = useState(false);
  
  const abrirDetalle = async (tipo, filtros = {}, titulo = "") => {
    setModalLoading(true);
    setModal({ titulo: titulo || `Cargando...`, filas: [], tipo });
    try {
      let filas, err;
      if (modo === 'dia') {
        ({ data: filas, error: err } = await sb.rpc("get_kpi_detalle", {
          p_fecha: fechaSeleccionada,
          p_tipo: tipo,
          p_filtro_sc: filtros.sc || null,
          p_filtro_fleet: filtros.fleet || null,
          p_filtro_tipo_ruta: filtros.tipo_ruta || null,
          p_filtro_caracteristica: filtros.caracteristica || null,
          p_filtro_pnr_estado: filtros.pnr_estado || null,
        }));
      } else {
        ({ data: filas, error: err } = await sb.rpc("get_kpi_detalle_rango", {
          p_fecha_desde: rangoSel.desde,
          p_fecha_hasta: rangoSel.hasta,
          p_tipo: tipo,
          p_filtro_sc: filtros.sc || null,
          p_filtro_fleet: filtros.fleet || null,
          p_filtro_tipo_ruta: filtros.tipo_ruta || null,
          p_filtro_caracteristica: filtros.caracteristica || null,
          p_filtro_pnr_estado: filtros.pnr_estado || null,
        }));
      }
      if (err) throw err;
      const arr = Array.isArray(filas) ? filas : [];
      const sufijoArchivo = modo === 'dia' ? fechaSeleccionada : `${rangoSel.desde}_a_${rangoSel.hasta}`;
      setModal({ 
        titulo: `${titulo} (${arr.length})`, 
        filas: arr, 
        tipo,
        nombreArchivo: `kpi_${tipo}_${sufijoArchivo}${filtros.sc ? '_' + filtros.sc : ''}${filtros.fleet ? '_' + filtros.fleet : ''}`
      });
    } catch (e) {
      setModal({ titulo: "Error", filas: [{ error: e.message }], tipo });
    } finally {
      setModalLoading(false);
    }
  };

  // Drilldown del Embudo de Aceptación
  const abrirDetalleEmbudo = async (status, filtros = {}, titulo = "") => {
    setModalLoading(true);
    setModal({ titulo: titulo || `Cargando...`, filas: [], tipo: 'embudo' });
    try {
      let filas, err;
      if (modo === 'dia') {
        ({ data: filas, error: err } = await sb.rpc("get_embudo_detalle_dia", {
          p_fecha: fechaSeleccionada,
          p_status: status || null,
          p_sc: filtros.sc || null,
          p_es_sdd: typeof filtros.es_sdd === 'boolean' ? filtros.es_sdd : null,
          p_tipo_flota: filtros.tipo_flota || null,
        }));
      } else {
        ({ data: filas, error: err } = await sb.rpc("get_embudo_detalle_rango", {
          p_fecha_desde: rangoSel.desde,
          p_fecha_hasta: rangoSel.hasta,
          p_status: status || null,
          p_sc: filtros.sc || null,
          p_es_sdd: typeof filtros.es_sdd === 'boolean' ? filtros.es_sdd : null,
          p_tipo_flota: filtros.tipo_flota || null,
        }));
      }
      if (err) throw err;
      const arr = Array.isArray(filas) ? filas : [];
      const sufijoArchivo = modo === 'dia' ? fechaSeleccionada : `${rangoSel.desde}_a_${rangoSel.hasta}`;
      setModal({ 
        titulo: `${titulo} (${arr.length})`, 
        filas: arr, 
        tipo: 'embudo',
        nombreArchivo: `embudo_${status || 'todos'}_${sufijoArchivo}${filtros.sc ? '_' + filtros.sc : ''}`
      });
    } catch (e) {
      setModal({ titulo: "Error", filas: [{ error: e.message }], tipo: 'embudo' });
    } finally {
      setModalLoading(false);
    }
  };

  // Helper: tooltip "i" inline
  const TooltipInfo = ({ texto }) => (
    <span 
      title={texto}
      style={{ 
        display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
        width: 14, height: 14, borderRadius: '50%', 
        background: '#cbd5e1', color: '#475569', 
        fontSize: 9, fontWeight: 700, marginLeft: 6, cursor: 'help',
        verticalAlign: 'middle'
      }}>
      i
    </span>
  );

  // Helper: top 3 SCs por métrica
  const top3SCs = (porSc, campo, orden = 'desc') => {
    if (!Array.isArray(porSc) || porSc.length === 0) return { peores: [], mejores: [] };
    const conValor = porSc.filter(s => s[campo] !== null && s[campo] !== undefined);
    const sorted = [...conValor].sort((a, b) => orden === 'desc' ? b[campo] - a[campo] : a[campo] - b[campo]);
    return {
      peores: sorted.slice(0, 3),
      mejores: sorted.slice(-3).reverse()
    };
  };
  
  
  if (loading) return <div className="pg" style={{ textAlign: "center", padding: 60, color: "#888" }}>Cargando resumen...</div>;
  if (error) return <div className="pg" style={{ padding: 40, color: "#c0392b" }}>Error: {error}</div>;
  if (!data) return <div className="pg" style={{ padding: 40, color: "#888" }}>Sin datos</div>;
  
  const cp = data.cumplimiento_promesa || {};
  const cno = data.capacidad_no_operable || { total: 0, walker: 0, crowd: 0, moto: 0, detalle: [] };
  const dtv = data.delta_tr_vs_panel || { tr_aceptadas: 0, logistic_operables: 0, delta: 0, detalle_tr_por_sc: [] };
  const rsm = data.reporte_sdd_meli || { tiene_reporte: false, totales: null, por_sc: [], no_ejecutadas_detalle: [] };
  const ccon = data.cumplimiento_contractual || { sdd_solicitadas: 0, sdd_ejecutadas: 0, sdd_no_cumplidas: 0, sdd_pct: 0, var_solicitadas: 0, var_ejecutadas: 0, var_no_cumplidas: 0, var_pct: 0, total_solicitadas: 0, total_ejecutadas: 0, total_no_cumplidas: 0, pct_total: 0, usa_reporte_oficial_sdd: false };
  const ns = data.nivel_servicio || {};
  const nv = data.nivel_visitados || {};
  const pnr = data.pnr || {};
  const ea = data.embudo_aceptacion || {};
  const eaT = ea.totales || {};
  
  const cumple = (pct, umbral) => Number(pct) >= Number(umbral);
  const colorPct = (pct, umbral) => cumple(pct, umbral) ? "#16a34a" : "#dc2626";
  const colorBg = (pct, umbral) => cumple(pct, umbral) ? "#f0fdf4" : "#fef2f2";
  
  // Texto principal del header según modo
  const tituloModo = modo === 'dia' ? 'Resumen del día' : 'Resumen del período';
  const fechaTexto = modo === 'dia' 
    ? fechaTextoLargo(fechaSeleccionada)
    : `${fechaTextoLargo(rangoSel.desde)} → ${fechaTextoLargo(rangoSel.hasta)}`;
  const fechaCorta = modo === 'dia'
    ? formatearDisplay(fechaSeleccionada)
    : `${formatearDisplay(rangoSel.desde)} → ${formatearDisplay(rangoSel.hasta)}`;
  
  // Cantidad de días del rango (cálculo simple, sin useMemo para evitar el error de hooks)
  let diasRango = 1;
  if (modo === 'rango') {
    const d1 = new Date(rangoSel.desde);
    const d2 = new Date(rangoSel.hasta);
    diasRango = Math.round((d2 - d1) / (1000 * 60 * 60 * 24)) + 1;
  }
  
  // Detectar botón activo (día)
  const botonDiaActivo = fechaSeleccionada === fechasReferencia.d1 ? 'd1'
                     : fechaSeleccionada === fechasReferencia.d7 ? 'd7'
                     : fechaSeleccionada === fechasReferencia.d30 ? 'd30'
                     : 'custom';
  
  // Detectar botón activo (rango)
  const esRango7 = rangoSel.desde === fechasReferencia.d7 && rangoSel.hasta === fechasReferencia.d1;
  const esRango30 = rangoSel.desde === fechasReferencia.d30 && rangoSel.hasta === fechasReferencia.d1;
  const botonRangoActivo = esRango7 ? '7d' : esRango30 ? '30d' : 'custom';
  
  const estiloBoton = (activo) => ({
    padding: "8px 14px",
    background: activo ? "#fff" : "transparent",
    color: activo ? "#1a3a6b" : "#fff",
    border: "1px solid rgba(255,255,255,0.3)",
    borderRadius: 6,
    fontSize: 12,
    fontWeight: 700,
    cursor: "pointer",
    fontFamily: "'Geist', sans-serif",
    transition: "all 0.15s",
  });
  
  const estiloToggle = (activo) => ({
    padding: "6px 14px",
    background: activo ? "#fff" : "rgba(255,255,255,0.1)",
    color: activo ? "#1a3a6b" : "#fff",
    border: "none",
    borderRadius: 6,
    fontSize: 12,
    fontWeight: 700,
    cursor: "pointer",
    fontFamily: "'Geist', sans-serif",
  });
  
  return (
    <div className="pg">
      {/* Header con selector de fecha */}
      <div style={{
        background: "linear-gradient(135deg, #1a3a6b 0%, #2d4f8e 100%)",
        borderRadius: 12, padding: "16px 20px", marginBottom: 20,
        color: "#fff"
      }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 12, marginBottom: 12 }}>
          <div>
            <div style={{ fontSize: 11, color: "#aac3e8", textTransform: "uppercase", letterSpacing: 0.5, fontWeight: 700 }}>
              {tituloModo}
              {modo === 'rango' && <span style={{ marginLeft: 8, opacity: 0.7 }}>· {diasRango} días</span>}
            </div>
            <div style={{ fontSize: modo === 'rango' ? 16 : 22, fontWeight: 700, marginTop: 2 }}>{fechaTexto}</div>
          </div>
          <div style={{ fontSize: 12, color: "#aac3e8" }}>
            {fechaCorta}
          </div>
        </div>
        
        {/* Toggle Día / Rango */}
        <div style={{ display: "flex", alignItems: "center", gap: 4, marginBottom: 10, background: "rgba(0,0,0,0.15)", padding: 4, borderRadius: 8, width: "fit-content" }}>
          <button onClick={() => setModo('dia')} style={estiloToggle(modo === 'dia')}>
            📅 Día exacto
          </button>
          <button onClick={() => setModo('rango')} style={estiloToggle(modo === 'rango')}>
            📊 Rango acumulado
          </button>
        </div>
        
        {/* Botones contextuales según modo */}
        {modo === 'dia' ? (
          <div style={{ display: "flex", alignItems: "center", gap: 8, flexWrap: "wrap" }}>
            <button onClick={() => setFechaSeleccionada(fechasReferencia.d1)}
                    style={estiloBoton(botonDiaActivo === 'd1')}>
              Ayer (D-1)
            </button>
            <button onClick={() => setFechaSeleccionada(fechasReferencia.d7)}
                    style={estiloBoton(botonDiaActivo === 'd7')}>
              D-7
            </button>
            <button onClick={() => setFechaSeleccionada(fechasReferencia.d30)}
                    style={estiloBoton(botonDiaActivo === 'd30')}>
              D-30
            </button>
            <div style={{ width: 1, height: 24, background: "rgba(255,255,255,0.3)", margin: "0 4px" }} />
            <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
              <span style={{ fontSize: 11, color: "#aac3e8", fontWeight: 600 }}>📅 Día específico:</span>
              <input type="date"
                     value={fechaSeleccionada}
                     max={fechasReferencia.d1}
                     onChange={(e) => e.target.value && setFechaSeleccionada(e.target.value)}
                     style={{
                       padding: "7px 10px",
                       background: botonDiaActivo === 'custom' ? "#fff" : "rgba(255,255,255,0.15)",
                       color: botonDiaActivo === 'custom' ? "#1a3a6b" : "#fff",
                       border: "1px solid rgba(255,255,255,0.3)",
                       borderRadius: 6,
                       fontSize: 12,
                       fontWeight: 600,
                       cursor: "pointer",
                       fontFamily: "'Geist', sans-serif",
                       colorScheme: botonDiaActivo === 'custom' ? "light" : "dark",
                     }} />
            </div>
          </div>
        ) : (
          <div style={{ display: "flex", alignItems: "center", gap: 8, flexWrap: "wrap" }}>
            <button onClick={() => setRangoSel({ desde: fechasReferencia.d7, hasta: fechasReferencia.d1 })}
                    style={estiloBoton(botonRangoActivo === '7d')}>
              Últimos 7 días
            </button>
            <button onClick={() => setRangoSel({ desde: fechasReferencia.d30, hasta: fechasReferencia.d1 })}
                    style={estiloBoton(botonRangoActivo === '30d')}>
              Últimos 30 días
            </button>
            <div style={{ width: 1, height: 24, background: "rgba(255,255,255,0.3)", margin: "0 4px" }} />
            <div style={{ display: "flex", alignItems: "center", gap: 6, flexWrap: "wrap" }}>
              <span style={{ fontSize: 11, color: "#aac3e8", fontWeight: 600 }}>📅 Rango personalizado:</span>
              <input type="date"
                     value={rangoSel.desde}
                     max={rangoSel.hasta}
                     onChange={(e) => e.target.value && setRangoSel(r => ({ ...r, desde: e.target.value }))}
                     style={{
                       padding: "7px 10px",
                       background: botonRangoActivo === 'custom' ? "#fff" : "rgba(255,255,255,0.15)",
                       color: botonRangoActivo === 'custom' ? "#1a3a6b" : "#fff",
                       border: "1px solid rgba(255,255,255,0.3)",
                       borderRadius: 6,
                       fontSize: 12,
                       fontWeight: 600,
                       cursor: "pointer",
                       fontFamily: "'Geist', sans-serif",
                       colorScheme: botonRangoActivo === 'custom' ? "light" : "dark",
                     }} />
              <span style={{ fontSize: 12, color: "#aac3e8" }}>→</span>
              <input type="date"
                     value={rangoSel.hasta}
                     min={rangoSel.desde}
                     max={fechasReferencia.d1}
                     onChange={(e) => e.target.value && setRangoSel(r => ({ ...r, hasta: e.target.value }))}
                     style={{
                       padding: "7px 10px",
                       background: botonRangoActivo === 'custom' ? "#fff" : "rgba(255,255,255,0.15)",
                       color: botonRangoActivo === 'custom' ? "#1a3a6b" : "#fff",
                       border: "1px solid rgba(255,255,255,0.3)",
                       borderRadius: 6,
                       fontSize: 12,
                       fontWeight: 600,
                       cursor: "pointer",
                       fontFamily: "'Geist', sans-serif",
                       colorScheme: botonRangoActivo === 'custom' ? "light" : "dark",
                     }} />
            </div>
          </div>
        )}
      </div>

      {/* BLOQUE 1: CUMPLIMIENTO DE PROMESA (Operativo + Contractual) */}
      <div style={{ background: "#fff", borderRadius: 12, padding: 20, marginBottom: 16, border: "1px solid #e4e7ec" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: 14 }}>
          <div>
            <div style={{ fontSize: 16, fontWeight: 700, color: "#1a3a6b" }}>Cumplimiento de Promesa</div>
            <div style={{ fontSize: 11, color: "#888", marginTop: 2 }}>Dos visiones complementarias del cumplimiento</div>
          </div>
        </div>

        {/* CABECERA DUAL: Operativo vs Contractual */}
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16, marginBottom: 16 }}>
          {/* OPERATIVO (Brain) */}
          <div style={{ background: "#f0fdf4", borderRadius: 10, padding: 14, border: "1px solid #bbf7d0" }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
              <div>
                <div style={{ fontSize: 11, fontWeight: 700, color: "#166534", textTransform: "uppercase", letterSpacing: 0.5 }}>Operativo (Brain)</div>
                <div style={{ fontSize: 10, color: "#166534", opacity: 0.7, marginTop: 2 }}>Lo que efectivamente operamos</div>
              </div>
              <div style={{ fontSize: 28, fontWeight: 800, color: cp.pct_cumplimiento >= 95 ? "#16a34a" : cp.pct_cumplimiento >= 85 ? "#f59e0b" : "#dc2626" }}>
                {cp.pct_cumplimiento || 0}%
              </div>
            </div>
            <div style={{ fontSize: 11, color: "#166534" }}>
              <strong>{cp.ejecutadas || 0}</strong> ejecutadas / <strong>{cp.aceptadas || 0}</strong> prometidas
            </div>
            <div style={{ fontSize: 10, color: "#166534", opacity: 0.7, marginTop: 4, fontStyle: "italic" }}>
              Fuente: Logistic Monitoring + Maestro Jornada
            </div>
          </div>

          {/* CONTRACTUAL (MELI) */}
          {ccon.total_solicitadas > 0 && (
            <div style={{ background: "#fef3c7", borderRadius: 10, padding: 14, border: "1px solid #fcd34d" }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
                <div>
                  <div style={{ fontSize: 11, fontWeight: 700, color: "#854d0e", textTransform: "uppercase", letterSpacing: 0.5 }}>Contractual (MELI)</div>
                  <div style={{ fontSize: 10, color: "#854d0e", opacity: 0.7, marginTop: 2 }}>Lo que MELI nos pidió cumplir</div>
                </div>
                <div style={{ fontSize: 28, fontWeight: 800, color: ccon.pct_total >= 95 ? "#16a34a" : ccon.pct_total >= 85 ? "#f59e0b" : "#dc2626" }}>
                  {ccon.pct_total || 0}%
                </div>
              </div>
              <div style={{ fontSize: 11, color: "#854d0e" }}>
                <strong>{ccon.total_ejecutadas || 0}</strong> ejecutadas / <strong>{ccon.total_solicitadas || 0}</strong> solicitadas
              </div>
              <div style={{ fontSize: 10, color: "#854d0e", opacity: 0.7, marginTop: 4, fontStyle: "italic" }}>
                Fuente: {ccon.usa_reporte_oficial_sdd ? "Reporte oficial MELI (SDD)" : "TR (SDD)"} + TR (Variables)
              </div>
            </div>
          )}
        </div>

        {/* Línea principal Operativo: Aceptadas / Ejecutadas / No realizadas */}
        <div style={{ fontSize: 10, color: "#666", fontWeight: 700, textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 6 }}>
          Detalle operativo
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 12, marginBottom: 14 }}>
          <div onClick={() => abrirDetalle("aceptadas", {}, "Ofertas aceptadas")}
            style={{ background: "#f0f9ff", borderRadius: 8, padding: "12px 14px", cursor: "pointer", transition: "transform 0.1s", border: "1px solid transparent" }}
            onMouseOver={e => { e.currentTarget.style.borderColor = "#1e40af"; }}
            onMouseOut={e => { e.currentTarget.style.borderColor = "transparent"; }}>
            <div style={{ fontSize: 10, color: "#1e40af", fontWeight: 700, textTransform: "uppercase", letterSpacing: 0.5, display: "flex", justifyContent: "space-between" }}>
              <span>Aceptadas</span><span style={{ fontSize: 9, opacity: 0.6 }}>VER →</span>
            </div>
            <div style={{ fontSize: 24, fontWeight: 700, color: "#1e40af", marginTop: 2 }}>{cp.aceptadas || 0}</div>
          </div>
          <div onClick={() => abrirDetalle("ejecutadas", {}, "Viajes ejecutados")}
            style={{ background: "#f0fdf4", borderRadius: 8, padding: "12px 14px", cursor: "pointer", border: "1px solid transparent" }}
            onMouseOver={e => { e.currentTarget.style.borderColor = "#166534"; }}
            onMouseOut={e => { e.currentTarget.style.borderColor = "transparent"; }}>
            <div style={{ fontSize: 10, color: "#166534", fontWeight: 700, textTransform: "uppercase", letterSpacing: 0.5, display: "flex", justifyContent: "space-between" }}>
              <span>Ejecutadas</span><span style={{ fontSize: 9, opacity: 0.6 }}>VER →</span>
            </div>
            <div style={{ fontSize: 24, fontWeight: 700, color: "#166534", marginTop: 2 }}>{cp.ejecutadas || 0}</div>
          </div>
          <div onClick={() => cp.no_realizadas > 0 && abrirDetalle("no_realizadas", {}, "Aceptadas no realizadas")}
            style={{ 
              background: cp.no_realizadas > 0 ? "#fef2f2" : "#f9fafb", 
              borderRadius: 8, padding: "12px 14px", 
              cursor: cp.no_realizadas > 0 ? "pointer" : "default",
              border: "1px solid transparent"
            }}
            onMouseOver={e => { if (cp.no_realizadas > 0) e.currentTarget.style.borderColor = "#991b1b"; }}
            onMouseOut={e => { e.currentTarget.style.borderColor = "transparent"; }}>
            <div style={{ fontSize: 10, color: cp.no_realizadas > 0 ? "#991b1b" : "#666", fontWeight: 700, textTransform: "uppercase", letterSpacing: 0.5, display: "flex", justifyContent: "space-between" }}>
              <span>No realizadas</span>
              {cp.no_realizadas > 0 && <span style={{ fontSize: 9, opacity: 0.6 }}>VER →</span>}
            </div>
            <div style={{ fontSize: 24, fontWeight: 700, color: cp.no_realizadas > 0 ? "#991b1b" : "#666", marginTop: 2 }}>{cp.no_realizadas || 0}</div>
          </div>
        </div>
        
        {/* Split SDD vs Variable - Operativo */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(2, 1fr)", gap: 12, marginBottom: 14 }}>
          <div onClick={() => abrirDetalle("ejecutadas", { fleet: "SDD" }, "Viajes ejecutados · SDD")}
            style={{ background: "#fff7ed", borderRadius: 8, padding: 14, border: "1px solid #fed7aa", cursor: "pointer" }}>
            <div style={{ fontSize: 11, color: "#9a3412", fontWeight: 700, textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 8, display: "flex", justifyContent: "space-between" }}>
              <span>SDD (Súper Dedicada)</span><span style={{ fontSize: 9, opacity: 0.6 }}>VER →</span>
            </div>
            <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13 }}>
              <div><span style={{ color: "#888" }}>Aceptadas:</span> <strong>{cp.sdd?.aceptadas || 0}</strong></div>
              <div><span style={{ color: "#888" }}>Ejecutadas:</span> <strong>{cp.sdd?.ejecutadas || 0}</strong></div>
              <div style={{ color: cp.sdd?.no_realizadas > 0 ? "#991b1b" : "#666" }}>
                <span style={{ color: "#888" }}>No realiz.:</span> <strong>{cp.sdd?.no_realizadas || 0}</strong>
              </div>
            </div>
          </div>
          <div onClick={() => abrirDetalle("ejecutadas", { fleet: "Variable" }, "Viajes ejecutados · Variable")}
            style={{ background: "#eef2ff", borderRadius: 8, padding: 14, border: "1px solid #c7d2fe", cursor: "pointer" }}>
            <div style={{ fontSize: 11, color: "#3730a3", fontWeight: 700, textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 8, display: "flex", justifyContent: "space-between" }}>
              <span>Variable (Flota libre)</span><span style={{ fontSize: 9, opacity: 0.6 }}>VER →</span>
            </div>
            <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13 }}>
              <div><span style={{ color: "#888" }}>Aceptadas:</span> <strong>{cp.variable?.aceptadas || 0}</strong></div>
              <div><span style={{ color: "#888" }}>Ejecutadas:</span> <strong>{cp.variable?.ejecutadas || 0}</strong></div>
              <div style={{ color: cp.variable?.no_realizadas > 0 ? "#991b1b" : "#666" }}>
                <span style={{ color: "#888" }}>No realiz.:</span> <strong>{cp.variable?.no_realizadas || 0}</strong>
              </div>
            </div>
          </div>
        </div>

        {/* DETALLE CONTRACTUAL: SDD vs Variable con etiquetas de fuente */}
        {ccon.total_solicitadas > 0 && (
          <>
            <div style={{ fontSize: 10, color: "#854d0e", fontWeight: 700, textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 6, marginTop: 4 }}>
              Detalle contractual MELI
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(2, 1fr)", gap: 12 }}>
              {/* SDD Contractual */}
              <div style={{ background: "#fffbeb", borderRadius: 8, padding: 14, border: "1px solid #fde68a", position: "relative" }}>
                <div style={{ position: "absolute", top: 8, right: 10, fontSize: 9, color: ccon.usa_reporte_oficial_sdd ? "#16a34a" : "#9333ea", fontWeight: 700 }}>
                  {ccon.usa_reporte_oficial_sdd ? "✅ VALIDADO" : "⚠️ FALLBACK TR"}
                </div>
                <div style={{ fontSize: 11, color: "#854d0e", fontWeight: 700, textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 6 }}>
                  SDD (Súper Dedicada)
                </div>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: 6 }}>
                  <div style={{ fontSize: 13 }}>
                    <strong>{ccon.sdd_ejecutadas || 0}</strong>
                    <span style={{ color: "#888" }}> / </span>
                    <strong>{ccon.sdd_solicitadas || 0}</strong>
                  </div>
                  <div style={{ fontSize: 18, fontWeight: 800, color: ccon.sdd_pct >= 95 ? "#16a34a" : ccon.sdd_pct >= 85 ? "#f59e0b" : "#dc2626" }}>
                    {ccon.sdd_pct || 0}%
                  </div>
                </div>
                <div style={{ fontSize: 10, color: "#854d0e" }}>
                  No cumplidas: <strong style={{ color: ccon.sdd_no_cumplidas > 0 ? "#991b1b" : "#16a34a" }}>{ccon.sdd_no_cumplidas || 0}</strong>
                </div>
                <div style={{ fontSize: 9, color: "#a16207", marginTop: 4, fontStyle: "italic" }}>
                  Fuente: {ccon.usa_reporte_oficial_sdd ? "Reporte oficial MELI" : "TR (no hay reporte hoy)"}
                </div>
              </div>

              {/* Variable Contractual */}
              <div style={{ background: "#fffbeb", borderRadius: 8, padding: 14, border: "1px solid #fde68a", position: "relative" }}>
                <div style={{ position: "absolute", top: 8, right: 10, fontSize: 9, color: "#9333ea", fontWeight: 700 }}>
                  ⚠️ EN INVESTIGACIÓN
                </div>
                <div style={{ fontSize: 11, color: "#854d0e", fontWeight: 700, textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 6 }}>
                  Variable (Flota libre)
                </div>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: 6 }}>
                  <div style={{ fontSize: 13 }}>
                    <strong>{ccon.var_ejecutadas || 0}</strong>
                    <span style={{ color: "#888" }}> / </span>
                    <strong>{ccon.var_solicitadas || 0}</strong>
                  </div>
                  <div style={{ fontSize: 18, fontWeight: 800, color: ccon.var_pct >= 95 ? "#16a34a" : ccon.var_pct >= 85 ? "#f59e0b" : "#dc2626" }}>
                    {ccon.var_pct || 0}%
                  </div>
                </div>
                <div style={{ fontSize: 10, color: "#854d0e" }}>
                  No cumplidas: <strong style={{ color: ccon.var_no_cumplidas > 0 ? "#991b1b" : "#16a34a" }}>{ccon.var_no_cumplidas || 0}</strong>
                </div>
                <div style={{ fontSize: 9, color: "#a16207", marginTop: 4, fontStyle: "italic" }}>
                  Fuente: TR (no existe reporte oficial Variables · contiene incertidumbre del delta)
                </div>
              </div>
            </div>

            {/* Caja explicativa */}
            <div style={{ marginTop: 12, padding: 10, background: "rgba(254, 243, 199, 0.5)", borderRadius: 6, fontSize: 10, color: "#92400e", lineHeight: 1.5, borderLeft: "3px solid #fcd34d" }}>
              <strong>📌 Sobre las dos visiones:</strong>
              <br />
              • <strong>Operativo</strong>: mide rutas que efectivamente operamos vs las que llegaron al panel Logistic.
              <br />
              • <strong>Contractual</strong>: mide rutas que MELI nos pidió cumplir vs las que efectivamente operamos.
              <br />
              • <strong>SDD</strong> tiene fuente oficial confiable (reporte MELI). <strong>Variables</strong> usa TR mientras se valida el delta de aceptadas vs panel.
            </div>
          </>
        )}
      </div>

      {/* BLOQUE 1.B: CAPACIDAD NO OPERABLE (Walker / Car 8h Crowd / Moto MLP) */}
      {cno.total > 0 && (
        <div style={{ 
          background: "linear-gradient(135deg, #fefce8 0%, #fef3c7 100%)", 
          borderRadius: 12, 
          padding: 16, 
          marginBottom: 16, 
          border: "1px solid #fde68a" 
        }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 12 }}>
            <div style={{ flex: 1 }}>
              <div style={{ fontSize: 14, fontWeight: 700, color: "#854d0e", display: "flex", alignItems: "center", gap: 6 }}>
                🟡 Capacidad asignada no operable
              </div>
              <div style={{ fontSize: 11, color: "#92400e", marginTop: 4, lineHeight: 1.5 }}>
                Rutas que MELI nos asignó en el panel TMS para modalidades que <strong>no operamos</strong> (Walker, Car 8h Crowd, Moto MLP).
                <br/>
                <span style={{ color: "#a16207" }}>No son leakage: aparecen una sola vez y MELI las rota a otro operador. No afectan el cumplimiento.</span>
              </div>
            </div>
            <div style={{ textAlign: "right", marginLeft: 16 }}>
              <div style={{ fontSize: 28, fontWeight: 800, color: "#854d0e", fontVariantNumeric: "tabular-nums", lineHeight: 1 }}>
                {cno.total}
              </div>
              <div style={{ fontSize: 9, color: "#a16207", textTransform: "uppercase", letterSpacing: 0.5, marginTop: 2 }}>rutas</div>
            </div>
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 8, marginTop: 8 }}>
            <div style={{ background: "#fffbeb", borderRadius: 6, padding: "8px 10px", border: "1px solid #fde68a" }}>
              <div style={{ fontSize: 10, color: "#a16207", fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.3 }}>🚗 Car 8h Crowd</div>
              <div style={{ fontSize: 18, fontWeight: 700, color: "#854d0e", fontVariantNumeric: "tabular-nums" }}>{cno.crowd || 0}</div>
            </div>
            <div style={{ background: "#fffbeb", borderRadius: 6, padding: "8px 10px", border: "1px solid #fde68a" }}>
              <div style={{ fontSize: 10, color: "#a16207", fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.3 }}>🚶 Walker</div>
              <div style={{ fontSize: 18, fontWeight: 700, color: "#854d0e", fontVariantNumeric: "tabular-nums" }}>{cno.walker || 0}</div>
            </div>
            <div style={{ background: "#fffbeb", borderRadius: 6, padding: "8px 10px", border: "1px solid #fde68a" }}>
              <div style={{ fontSize: 10, color: "#a16207", fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.3 }}>🏍️ Moto MLP</div>
              <div style={{ fontSize: 18, fontWeight: 700, color: "#854d0e", fontVariantNumeric: "tabular-nums" }}>{cno.moto || 0}</div>
            </div>
          </div>
          {Array.isArray(cno.detalle) && cno.detalle.length > 0 && (() => {
            // Detectar si los datos tienen fecha (modo rango) o no (modo día)
            const tieneFecha = cno.detalle.some(r => r.fecha);
            return (
              <details style={{ marginTop: 10 }}>
                <summary style={{ fontSize: 11, color: "#854d0e", cursor: "pointer", fontWeight: 600 }}>
                  Ver detalle por SC ({cno.detalle.length} rutas)
                </summary>
                <div style={{ marginTop: 8, maxHeight: 200, overflowY: "auto", background: "#fffbeb", border: "1px solid #fde68a", borderRadius: 6, padding: 8 }}>
                  <table style={{ width: "100%", fontSize: 11, borderCollapse: "collapse" }}>
                    <thead>
                      <tr style={{ borderBottom: "1px solid #fde68a", color: "#92400e" }}>
                        {tieneFecha && <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 700 }}>Fecha</th>}
                        <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 700 }}>SC</th>
                        <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 700 }}>ID Ruta</th>
                        <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 700 }}>Vehículo</th>
                      </tr>
                    </thead>
                    <tbody>
                      {cno.detalle.map((r, i) => (
                        <tr key={i} style={{ borderBottom: "1px dashed #fde68a" }}>
                          {tieneFecha && <td style={{ padding: "4px 8px", color: "#475569" }}>{r.fecha}</td>}
                          <td style={{ padding: "4px 8px", fontWeight: 600, color: "#0f172a" }}>{r.sc}</td>
                          <td style={{ padding: "4px 8px", color: "#475569", fontFamily: "monospace" }}>{r.id_ruta}</td>
                          <td style={{ padding: "4px 8px", color: "#475569" }}>{r.vehiculo}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </details>
            );
          })()}
        </div>
      )}

      {/* BLOQUE 1.C: DELTA TR vs PANEL OPERATIVO (a investigar) */}
      {dtv.delta > 0 && (
        <div style={{
          background: "linear-gradient(135deg, #faf5ff 0%, #f3e8ff 100%)",
          borderRadius: 12,
          padding: 16,
          marginBottom: 16,
          border: "1px solid #d8b4fe"
        }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 12 }}>
            <div style={{ flex: 1 }}>
              <div style={{ fontSize: 14, fontWeight: 700, color: "#6b21a8", display: "flex", alignItems: "center", gap: 6 }}>
                🔬 A investigar: delta de {dtv.delta} ofertas
              </div>
              <div style={{ fontSize: 11, color: "#7e22ce", marginTop: 4, lineHeight: 1.5 }}>
                Travel Requests dice <strong>{dtv.tr_aceptadas} aceptadas</strong>, panel operativo (Logistic Monitoring) dice <strong>{dtv.logistic_operables} rutas</strong>.
                <br/>
                <span style={{ color: "#9333ea" }}>
                  La diferencia es trackeable día a día. Causa por validar con MELI tras observación de patrón en ~2 semanas con captura completa.
                </span>
              </div>
            </div>
            <div style={{ textAlign: "right", marginLeft: 16 }}>
              <div style={{ fontSize: 28, fontWeight: 800, color: "#6b21a8", fontVariantNumeric: "tabular-nums", lineHeight: 1 }}>
                {dtv.delta}
              </div>
              <div style={{ fontSize: 9, color: "#9333ea", textTransform: "uppercase", letterSpacing: 0.5, marginTop: 2 }}>delta</div>
            </div>
          </div>

          <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 8, marginTop: 8 }}>
            <div style={{ background: "#faf5ff", borderRadius: 6, padding: "8px 10px", border: "1px solid #e9d5ff" }}>
              <div style={{ fontSize: 10, color: "#7e22ce", fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.3 }}>📋 TR aceptadas</div>
              <div style={{ fontSize: 18, fontWeight: 700, color: "#6b21a8", fontVariantNumeric: "tabular-nums" }}>{dtv.tr_aceptadas}</div>
            </div>
            <div style={{ background: "#faf5ff", borderRadius: 6, padding: "8px 10px", border: "1px solid #e9d5ff" }}>
              <div style={{ fontSize: 10, color: "#7e22ce", fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.3 }}>🚚 En panel</div>
              <div style={{ fontSize: 18, fontWeight: 700, color: "#6b21a8", fontVariantNumeric: "tabular-nums" }}>{dtv.logistic_operables}</div>
            </div>
            <div style={{ background: "#faf5ff", borderRadius: 6, padding: "8px 10px", border: "1px solid #e9d5ff" }}>
              <div style={{ fontSize: 10, color: "#7e22ce", fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.3 }}>🔬 Sin trazabilidad</div>
              <div style={{ fontSize: 18, fontWeight: 700, color: "#6b21a8", fontVariantNumeric: "tabular-nums" }}>{dtv.delta}</div>
            </div>
          </div>

          {Array.isArray(dtv.detalle_tr_por_sc) && dtv.detalle_tr_por_sc.length > 0 && (
            <details style={{ marginTop: 10 }}>
              <summary style={{ fontSize: 11, color: "#6b21a8", cursor: "pointer", fontWeight: 600 }}>
                Ver detalle de TR aceptadas por SC y vehículo
              </summary>
              <div style={{ marginTop: 8, maxHeight: 240, overflowY: "auto", background: "#faf5ff", border: "1px solid #e9d5ff", borderRadius: 6, padding: 8 }}>
                <table style={{ width: "100%", fontSize: 11, borderCollapse: "collapse" }}>
                  <thead>
                    <tr style={{ borderBottom: "1px solid #e9d5ff", color: "#7e22ce" }}>
                      <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 700 }}>SC</th>
                      <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 700 }}>Vehículo</th>
                      <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 700 }}>Tipo</th>
                      <th style={{ textAlign: "right", padding: "4px 8px", fontWeight: 700 }}>Aceptadas TR</th>
                    </tr>
                  </thead>
                  <tbody>
                    {dtv.detalle_tr_por_sc.map((r, i) => (
                      <tr key={i} style={{ borderBottom: "1px dashed #e9d5ff" }}>
                        <td style={{ padding: "4px 8px", fontWeight: 600, color: "#0f172a" }}>{r.sc}</td>
                        <td style={{ padding: "4px 8px", color: "#475569" }}>{r.vehicle_type}</td>
                        <td style={{ padding: "4px 8px", color: r.es_sdd ? "#9a3412" : "#3730a3", fontWeight: 600 }}>
                          {r.es_sdd ? "SDD" : "VAR"}
                        </td>
                        <td style={{ padding: "4px 8px", textAlign: "right", fontWeight: 700, color: "#0f172a", fontVariantNumeric: "tabular-nums" }}>{r.aceptadas}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </details>
          )}

          <div style={{ marginTop: 10, padding: 8, background: "rgba(255, 255, 255, 0.6)", borderRadius: 6, fontSize: 10, color: "#6b21a8", lineHeight: 1.5 }}>
            <strong>Hipótesis a validar:</strong> Ofertas marcadas como aceptadas en TR que no llegaron al panel operativo del día.
            Los dos sistemas de MELI (TR y Logistic Monitoring) están desacoplados — no comparten ID directo,
            por lo que el cruce solo es posible a nivel agregado (SC + vehículo + fecha).
          </div>
        </div>
      )}

      {/* BLOQUE 1.D: REPORTE SDD OFICIAL MELI (información complementaria) */}
      {rsm.tiene_reporte && rsm.totales && (
        <div style={{
          background: "linear-gradient(135deg, #eef2ff 0%, #e0e7ff 100%)",
          borderRadius: 12,
          padding: 16,
          marginBottom: 16,
          border: "1px solid #a5b4fc"
        }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 12 }}>
            <div style={{ flex: 1 }}>
              <div style={{ fontSize: 14, fontWeight: 700, color: "#3730a3", display: "flex", alignItems: "center", gap: 6 }}>
                📑 Reporte SDD oficial MELI
              </div>
              <div style={{ fontSize: 11, color: "#4338ca", marginTop: 4, lineHeight: 1.5 }}>
                Información complementaria descargada del panel TMS oficial de MELI.
                Solo cubre rutas SDD (Súper Dedicadas).
                <br/>
                <span style={{ color: "#6366f1" }}>
                  Esta información no modifica el cumplimiento principal del Brain.
                </span>
              </div>
            </div>
            <div style={{ textAlign: "right", marginLeft: 16 }}>
              <div style={{ 
                fontSize: 28, 
                fontWeight: 800, 
                color: rsm.totales.pct_cumplimiento >= 95 ? "#16a34a" : rsm.totales.pct_cumplimiento >= 85 ? "#f59e0b" : "#dc2626",
                fontVariantNumeric: "tabular-nums",
                lineHeight: 1
              }}>
                {rsm.totales.pct_cumplimiento}%
              </div>
              <div style={{ fontSize: 9, color: "#4338ca", textTransform: "uppercase", letterSpacing: 0.5, marginTop: 2 }}>
                cumplimiento SDD
              </div>
            </div>
          </div>

          {/* 3 sub-tarjetas: Solicitadas / Ejecutadas / No ejecutadas */}
          <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 8, marginTop: 8 }}>
            <div style={{ background: "#eef2ff", borderRadius: 6, padding: "8px 10px", border: "1px solid #c7d2fe" }}>
              <div style={{ fontSize: 10, color: "#4338ca", fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.3 }}>📋 Solicitadas</div>
              <div style={{ fontSize: 18, fontWeight: 700, color: "#3730a3", fontVariantNumeric: "tabular-nums" }}>{rsm.totales.solicitadas}</div>
            </div>
            <div style={{ background: "#eef2ff", borderRadius: 6, padding: "8px 10px", border: "1px solid #c7d2fe" }}>
              <div style={{ fontSize: 10, color: "#4338ca", fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.3 }}>✅ Ejecutadas</div>
              <div style={{ fontSize: 18, fontWeight: 700, color: "#16a34a", fontVariantNumeric: "tabular-nums" }}>{rsm.totales.ejecutadas}</div>
            </div>
            <div style={{ background: "#eef2ff", borderRadius: 6, padding: "8px 10px", border: "1px solid #c7d2fe" }}>
              <div style={{ fontSize: 10, color: "#4338ca", fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.3 }}>❌ No ejecutadas</div>
              <div style={{ fontSize: 18, fontWeight: 700, color: rsm.totales.no_ejecutadas > 0 ? "#dc2626" : "#3730a3", fontVariantNumeric: "tabular-nums" }}>{rsm.totales.no_ejecutadas}</div>
            </div>
          </div>

          {/* Detalle por SC (solo SCs con problemas) */}
          {Array.isArray(rsm.por_sc) && rsm.por_sc.filter(s => s.no_ejecutadas > 0).length > 0 && (
            <div style={{ marginTop: 10 }}>
              <div style={{ fontSize: 11, color: "#3730a3", fontWeight: 600, marginBottom: 6 }}>
                ⚠️ SCs con SDD no ejecutadas:
              </div>
              <div style={{ background: "rgba(255,255,255,0.6)", borderRadius: 6, padding: 8, border: "1px solid #c7d2fe" }}>
                <table style={{ width: "100%", fontSize: 11, borderCollapse: "collapse" }}>
                  <thead>
                    <tr style={{ borderBottom: "1px solid #c7d2fe", color: "#4338ca" }}>
                      <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 700 }}>SC</th>
                      <th style={{ textAlign: "right", padding: "4px 8px", fontWeight: 700 }}>Solicitadas</th>
                      <th style={{ textAlign: "right", padding: "4px 8px", fontWeight: 700 }}>Ejecutadas</th>
                      <th style={{ textAlign: "right", padding: "4px 8px", fontWeight: 700 }}>No ejec.</th>
                      <th style={{ textAlign: "right", padding: "4px 8px", fontWeight: 700 }}>%</th>
                    </tr>
                  </thead>
                  <tbody>
                    {rsm.por_sc.filter(s => s.no_ejecutadas > 0).map((s, i) => (
                      <tr key={i} style={{ borderBottom: "1px dashed #c7d2fe" }}>
                        <td style={{ padding: "4px 8px", fontWeight: 600, color: "#0f172a" }}>{s.sc}</td>
                        <td style={{ padding: "4px 8px", textAlign: "right", color: "#475569", fontVariantNumeric: "tabular-nums" }}>{s.solicitadas}</td>
                        <td style={{ padding: "4px 8px", textAlign: "right", color: "#16a34a", fontWeight: 600, fontVariantNumeric: "tabular-nums" }}>{s.ejecutadas}</td>
                        <td style={{ padding: "4px 8px", textAlign: "right", color: "#dc2626", fontWeight: 700, fontVariantNumeric: "tabular-nums" }}>{s.no_ejecutadas}</td>
                        <td style={{ padding: "4px 8px", textAlign: "right", fontWeight: 700, color: s.pct_cumplimiento >= 95 ? "#16a34a" : s.pct_cumplimiento >= 85 ? "#f59e0b" : "#dc2626", fontVariantNumeric: "tabular-nums" }}>{s.pct_cumplimiento}%</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {/* Detalle desplegable de las no ejecutadas */}
          {Array.isArray(rsm.no_ejecutadas_detalle) && rsm.no_ejecutadas_detalle.length > 0 && (
            <details style={{ marginTop: 10 }}>
              <summary style={{ fontSize: 11, color: "#3730a3", cursor: "pointer", fontWeight: 600 }}>
                Ver detalle de {rsm.no_ejecutadas_detalle.length} rutas SDD no ejecutadas
              </summary>
              <div style={{ marginTop: 8, maxHeight: 240, overflowY: "auto", background: "rgba(255,255,255,0.6)", border: "1px solid #c7d2fe", borderRadius: 6, padding: 8 }}>
                <table style={{ width: "100%", fontSize: 11, borderCollapse: "collapse" }}>
                  <thead>
                    <tr style={{ borderBottom: "1px solid #c7d2fe", color: "#4338ca" }}>
                      <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 700 }}>SC</th>
                      <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 700 }}>Vehículo</th>
                      <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 700 }}>ID Ruta</th>
                      <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 700 }}>Driver</th>
                      <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 700 }}>Etapa caída</th>
                    </tr>
                  </thead>
                  <tbody>
                    {rsm.no_ejecutadas_detalle.map((r, i) => (
                      <tr key={i} style={{ borderBottom: "1px dashed #c7d2fe" }}>
                        <td style={{ padding: "4px 8px", fontWeight: 600, color: "#0f172a" }}>{r.sc}</td>
                        <td style={{ padding: "4px 8px", color: "#475569", fontSize: 10 }}>{r.vehiculo}</td>
                        <td style={{ padding: "4px 8px", color: "#475569", fontFamily: "monospace", fontSize: 10 }}>
                          {r.id_ruta || <span style={{ color: "#94a3b8", fontStyle: "italic" }}>sin asignar</span>}
                        </td>
                        <td style={{ padding: "4px 8px", color: "#475569" }}>
                          {r.driver_name || <span style={{ color: "#94a3b8", fontStyle: "italic" }}>sin driver</span>}
                        </td>
                        <td style={{ padding: "4px 8px", fontWeight: 600, color: r.etapa_caida.includes("última hora") ? "#dc2626" : "#9333ea" }}>
                          {r.etapa_caida}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </details>
          )}
        </div>
      )}

      {/* BLOQUE 1.5: EMBUDO DE ACEPTACIÓN */}
      <div style={{ background: "#fff", borderRadius: 12, padding: 20, marginBottom: 16, border: "1px solid #e4e7ec" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: 14 }}>
          <div>
            <div style={{ fontSize: 16, fontWeight: 700, color: "#1a3a6b" }}>
              📊 Embudo de Aceptación
              <TooltipInfo texto="Trazabilidad del ciclo de oferta MELI: cuántas rutas nos ofreció MELI y qué pasó con cada una (aceptamos / rechazamos / MELI canceló / quedaron pending)." />
            </div>
            <div style={{ fontSize: 11, color: "#888", marginTop: 2 }}>De macro a micro: ofertas → respuestas → ranking por SC</div>
          </div>
          <div style={{ fontSize: 28, fontWeight: 800, color: (eaT.pct_aceptacion || 0) >= 90 ? "#16a34a" : (eaT.pct_aceptacion || 0) >= 75 ? "#f59e0b" : "#dc2626" }}>
            {eaT.pct_aceptacion || 0}% <span style={{ fontSize: 12, fontWeight: 600, color: "#888" }}>aceptación</span>
          </div>
        </div>
        
        {/* Línea 1: Ofrecidas (tarjeta grande) */}
        <div onClick={() => abrirDetalleEmbudo(null, {}, "Todas las ofertas MELI")}
          style={{ 
            background: "linear-gradient(135deg, #f0f9ff 0%, #e0f2fe 100%)", 
            borderRadius: 10, padding: "14px 18px", marginBottom: 14, 
            cursor: "pointer", border: "1px solid #bae6fd" 
          }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <div>
              <div style={{ fontSize: 11, color: "#0369a1", fontWeight: 700, textTransform: "uppercase", letterSpacing: 0.5 }}>
                📥 Ofrecidas
                <TooltipInfo texto="Total de ofertas de viaje que MELI puso a disposición del carrier en este período. Es el universo total del embudo." />
              </div>
              <div style={{ fontSize: 32, fontWeight: 800, color: "#0c4a6e", marginTop: 2 }}>{eaT.ofrecidas || 0}</div>
            </div>
            <div style={{ fontSize: 11, color: "#0369a1", textAlign: "right" }}>
              {(() => {
                const top = top3SCs(ea.por_sc || [], 'ofrecidas', 'desc');
                return (
                  <>
                    <div style={{ fontWeight: 700, marginBottom: 4 }}>Más activos:</div>
                    {top.peores.map(s => (
                      <div key={s.sc} style={{ fontSize: 10, color: "#0369a1" }}>
                        {s.sc}: <strong>{s.ofrecidas}</strong>
                      </div>
                    ))}
                  </>
                );
              })()}
            </div>
          </div>
        </div>
        
        {/* Línea 2: 4 tarjetas de status */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 12, marginBottom: 14 }}>
          {/* Aceptadas */}
          <div onClick={() => abrirDetalleEmbudo("accepted", {}, "Ofertas aceptadas")}
            style={{ background: "#f0fdf4", borderRadius: 8, padding: "12px 14px", cursor: "pointer", border: "1px solid transparent" }}
            onMouseOver={e => { e.currentTarget.style.borderColor = "#166534"; }}
            onMouseOut={e => { e.currentTarget.style.borderColor = "transparent"; }}>
            <div style={{ fontSize: 10, color: "#166534", fontWeight: 700, textTransform: "uppercase", letterSpacing: 0.5, display: "flex", justifyContent: "space-between" }}>
              <span>
                ✅ Aceptadas
                <TooltipInfo texto="Ofertas que aceptamos para operar. Pasan al embudo operativo (logistic + maestro)." />
              </span>
              <span style={{ fontSize: 9, opacity: 0.6 }}>VER →</span>
            </div>
            <div style={{ fontSize: 22, fontWeight: 700, color: "#166534", marginTop: 2 }}>{eaT.aceptadas || 0}</div>
            <div style={{ fontSize: 11, color: "#888" }}>{eaT.pct_aceptacion || 0}%</div>
            {(() => {
              const top = top3SCs(ea.por_sc || [], 'pct_aceptacion', 'asc');
              if (top.peores.length === 0) return null;
              return (
                <div style={{ marginTop: 8, paddingTop: 8, borderTop: "1px solid #d1fae5", fontSize: 10 }}>
                  <div style={{ color: "#991b1b", fontWeight: 600, marginBottom: 2 }}>Peores:</div>
                  {top.peores.map(s => (
                    <div key={s.sc} style={{ color: "#666", fontSize: 10 }}>
                      {s.sc}: <strong>{s.pct_aceptacion || 0}%</strong>
                    </div>
                  ))}
                </div>
              );
            })()}
          </div>
          
          {/* Rechazadas */}
          <div onClick={() => (eaT.rechazadas || 0) > 0 && abrirDetalleEmbudo("rejected", {}, "Ofertas rechazadas (rechazo propio)")}
            style={{ 
              background: (eaT.rechazadas || 0) > 0 ? "#fef2f2" : "#f9fafb", 
              borderRadius: 8, padding: "12px 14px", 
              cursor: (eaT.rechazadas || 0) > 0 ? "pointer" : "default",
              border: "1px solid transparent"
            }}
            onMouseOver={e => { if ((eaT.rechazadas || 0) > 0) e.currentTarget.style.borderColor = "#991b1b"; }}
            onMouseOut={e => { e.currentTarget.style.borderColor = "transparent"; }}>
            <div style={{ fontSize: 10, color: (eaT.rechazadas || 0) > 0 ? "#991b1b" : "#666", fontWeight: 700, textTransform: "uppercase", letterSpacing: 0.5, display: "flex", justifyContent: "space-between" }}>
              <span>
                ❌ Rechazadas
                <TooltipInfo texto="Ofertas que rechazamos antes del día de operación. Indicador de eficiencia operacional: idealmente bajo (<5%)." />
              </span>
              {(eaT.rechazadas || 0) > 0 && <span style={{ fontSize: 9, opacity: 0.6 }}>VER →</span>}
            </div>
            <div style={{ fontSize: 22, fontWeight: 700, color: (eaT.rechazadas || 0) > 0 ? "#991b1b" : "#666", marginTop: 2 }}>
              {eaT.rechazadas || 0}
            </div>
            <div style={{ fontSize: 11, color: "#888" }}>{eaT.pct_rechazo_propio || 0}%</div>
            {(() => {
              const top = top3SCs((ea.por_sc || []).filter(s => (s.rechazadas || 0) > 0), 'pct_rechazo', 'desc');
              if (top.peores.length === 0) return null;
              return (
                <div style={{ marginTop: 8, paddingTop: 8, borderTop: "1px solid #fee2e2", fontSize: 10 }}>
                  <div style={{ color: "#991b1b", fontWeight: 600, marginBottom: 2 }}>Top problemas:</div>
                  {top.peores.map(s => (
                    <div key={s.sc} style={{ color: "#666", fontSize: 10 }}>
                      {s.sc}: <strong>{s.pct_rechazo}%</strong>
                    </div>
                  ))}
                </div>
              );
            })()}
          </div>
          
          {/* Canceladas MELI */}
          <div onClick={() => (eaT.canceladas_meli || 0) > 0 && abrirDetalleEmbudo("canceled", {}, "Canceladas por MELI")}
            style={{ 
              background: (eaT.canceladas_meli || 0) > 0 ? "#fffbeb" : "#f9fafb", 
              borderRadius: 8, padding: "12px 14px", 
              cursor: (eaT.canceladas_meli || 0) > 0 ? "pointer" : "default",
              border: "1px solid transparent"
            }}
            onMouseOver={e => { if ((eaT.canceladas_meli || 0) > 0) e.currentTarget.style.borderColor = "#b45309"; }}
            onMouseOut={e => { e.currentTarget.style.borderColor = "transparent"; }}>
            <div style={{ fontSize: 10, color: (eaT.canceladas_meli || 0) > 0 ? "#b45309" : "#666", fontWeight: 700, textTransform: "uppercase", letterSpacing: 0.5, display: "flex", justifyContent: "space-between" }}>
              <span>
                🚫 Cancel. MELI
                <TooltipInfo texto="Ofertas que aceptamos pero MELI canceló después. % calculado sobre (aceptadas + canceladas). No es responsabilidad propia, pero ayuda a planificar oferta de drivers." />
              </span>
              {(eaT.canceladas_meli || 0) > 0 && <span style={{ fontSize: 9, opacity: 0.6 }}>VER →</span>}
            </div>
            <div style={{ fontSize: 22, fontWeight: 700, color: (eaT.canceladas_meli || 0) > 0 ? "#b45309" : "#666", marginTop: 2 }}>
              {eaT.canceladas_meli || 0}
            </div>
            <div style={{ fontSize: 11, color: "#888" }}>{eaT.pct_cancelacion_meli || 0}%</div>
            {(() => {
              const top = top3SCs((ea.por_sc || []).filter(s => (s.canceladas_meli || 0) > 0), 'pct_cancelacion_meli', 'desc');
              if (top.peores.length === 0) return null;
              return (
                <div style={{ marginTop: 8, paddingTop: 8, borderTop: "1px solid #fef3c7", fontSize: 10 }}>
                  <div style={{ color: "#b45309", fontWeight: 600, marginBottom: 2 }}>Top afectados:</div>
                  {top.peores.map(s => (
                    <div key={s.sc} style={{ color: "#666", fontSize: 10 }}>
                      {s.sc}: <strong>{s.pct_cancelacion_meli}%</strong>
                    </div>
                  ))}
                </div>
              );
            })()}
          </div>
          
          {/* Pending */}
          <div onClick={() => (eaT.pendientes || 0) > 0 && abrirDetalleEmbudo("pending", {}, "Ofertas pending")}
            style={{ 
              background: (eaT.pendientes || 0) > 0 ? "#f5f3ff" : "#f9fafb", 
              borderRadius: 8, padding: "12px 14px", 
              cursor: (eaT.pendientes || 0) > 0 ? "pointer" : "default",
              border: "1px solid transparent"
            }}
            onMouseOver={e => { if ((eaT.pendientes || 0) > 0) e.currentTarget.style.borderColor = "#6d28d9"; }}
            onMouseOut={e => { e.currentTarget.style.borderColor = "transparent"; }}>
            <div style={{ fontSize: 10, color: (eaT.pendientes || 0) > 0 ? "#6d28d9" : "#666", fontWeight: 700, textTransform: "uppercase", letterSpacing: 0.5, display: "flex", justifyContent: "space-between" }}>
              <span>
                ⏳ Pending
                <TooltipInfo texto="Ofertas pendientes de respuesta. Si quedan viejas (más de 1 día) son SLA crítico: MELI las rota a otro carrier y perdemos negocio." />
              </span>
              {(eaT.pendientes || 0) > 0 && <span style={{ fontSize: 9, opacity: 0.6 }}>VER →</span>}
            </div>
            <div style={{ fontSize: 22, fontWeight: 700, color: (eaT.pendientes || 0) > 0 ? "#6d28d9" : "#666", marginTop: 2 }}>
              {eaT.pendientes || 0}
            </div>
            {(() => {
              const top = top3SCs((ea.por_sc || []).filter(s => (s.pendientes || 0) > 0), 'pendientes', 'desc');
              if (top.peores.length === 0) return null;
              return (
                <div style={{ marginTop: 8, paddingTop: 8, borderTop: "1px solid #ede9fe", fontSize: 10 }}>
                  <div style={{ color: "#6d28d9", fontWeight: 600, marginBottom: 2 }}>Por SC:</div>
                  {top.peores.map(s => (
                    <div key={s.sc} style={{ color: "#666", fontSize: 10 }}>
                      {s.sc}: <strong>{s.pendientes}</strong>
                    </div>
                  ))}
                </div>
              );
            })()}
          </div>
        </div>
        
        {/* Línea 3: Split por Servicio + por Flota */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(2, 1fr)", gap: 12, marginBottom: 14 }}>
          {/* Por Servicio (SDD vs Variable) */}
          <div style={{ background: "#fff7ed", borderRadius: 8, padding: 14, border: "1px solid #fed7aa" }}>
            <div style={{ fontSize: 11, color: "#9a3412", fontWeight: 700, textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 8 }}>
              Por Servicio
              <TooltipInfo texto="SDD = Same Day Delivery (compromiso entrega rápida, alta prioridad). Variable = sin compromiso temporal." />
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
              <div onClick={() => abrirDetalleEmbudo(null, { es_sdd: true }, "Ofertas SDD")}
                style={{ cursor: "pointer", padding: 8, borderRadius: 6, background: "#fff" }}>
                <div style={{ fontSize: 10, color: "#888", marginBottom: 4 }}>SDD</div>
                <div style={{ fontSize: 13 }}>
                  <span style={{ color: "#888" }}>Ofrecidas:</span> <strong>{ea.por_servicio?.sdd?.ofrecidas || 0}</strong>
                  <br/>
                  <span style={{ color: "#888" }}>Aceptadas:</span> <strong>{ea.por_servicio?.sdd?.aceptadas || 0}</strong>
                  {(ea.por_servicio?.sdd?.rechazadas || 0) > 0 && (
                    <><br/><span style={{ color: "#991b1b" }}>Rechaz.: {ea.por_servicio.sdd.rechazadas}</span></>
                  )}
                </div>
              </div>
              <div onClick={() => abrirDetalleEmbudo(null, { es_sdd: false }, "Ofertas Variable")}
                style={{ cursor: "pointer", padding: 8, borderRadius: 6, background: "#fff" }}>
                <div style={{ fontSize: 10, color: "#888", marginBottom: 4 }}>Variable</div>
                <div style={{ fontSize: 13 }}>
                  <span style={{ color: "#888" }}>Ofrecidas:</span> <strong>{ea.por_servicio?.variable?.ofrecidas || 0}</strong>
                  <br/>
                  <span style={{ color: "#888" }}>Aceptadas:</span> <strong>{ea.por_servicio?.variable?.aceptadas || 0}</strong>
                  {(ea.por_servicio?.variable?.rechazadas || 0) > 0 && (
                    <><br/><span style={{ color: "#991b1b" }}>Rechaz.: {ea.por_servicio.variable.rechazadas}</span></>
                  )}
                </div>
              </div>
            </div>
          </div>
          
          {/* Por Flota (Fija vs Variable) */}
          <div style={{ background: "#eef2ff", borderRadius: 8, padding: 14, border: "1px solid #c7d2fe" }}>
            <div style={{ fontSize: 11, color: "#3730a3", fontWeight: 700, textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 8 }}>
              Por Flota
              <TooltipInfo texto="Fija = drivers propios contratados (más estables). Variable = drivers temporales/crowd (más cancelaciones MELI)." />
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
              <div onClick={() => abrirDetalleEmbudo(null, { tipo_flota: 'fija' }, "Ofertas · Flota Fija")}
                style={{ cursor: "pointer", padding: 8, borderRadius: 6, background: "#fff" }}>
                <div style={{ fontSize: 10, color: "#888", marginBottom: 4 }}>Fija</div>
                <div style={{ fontSize: 13 }}>
                  <span style={{ color: "#888" }}>Ofrecidas:</span> <strong>{ea.por_flota?.fija?.ofrecidas || 0}</strong>
                  <br/>
                  <span style={{ color: "#888" }}>Aceptadas:</span> <strong>{ea.por_flota?.fija?.aceptadas || 0}</strong>
                </div>
              </div>
              <div onClick={() => abrirDetalleEmbudo(null, { tipo_flota: 'variable' }, "Ofertas · Flota Variable")}
                style={{ cursor: "pointer", padding: 8, borderRadius: 6, background: "#fff" }}>
                <div style={{ fontSize: 10, color: "#888", marginBottom: 4 }}>Variable</div>
                <div style={{ fontSize: 13 }}>
                  <span style={{ color: "#888" }}>Ofrecidas:</span> <strong>{ea.por_flota?.variable?.ofrecidas || 0}</strong>
                  <br/>
                  <span style={{ color: "#888" }}>Aceptadas:</span> <strong>{ea.por_flota?.variable?.aceptadas || 0}</strong>
                  {(ea.por_flota?.variable?.canceladas || 0) > 0 && (
                    <><br/><span style={{ color: "#b45309" }}>Cancel MELI: {ea.por_flota.variable.canceladas}</span></>
                  )}
                </div>
              </div>
            </div>
          </div>
        </div>
        
        {/* Alerta crítica: Pending viejos */}
        {ea.pending_viejos?.total > 0 && (
          <div onClick={() => abrirDetalleEmbudo("pending_viejos", {}, "⚠️ Pending viejos sin responder")}
            style={{ 
              background: "#fef2f2", borderRadius: 8, padding: "12px 16px", 
              border: "2px solid #fecaca", cursor: "pointer",
              display: "flex", justifyContent: "space-between", alignItems: "center"
            }}>
            <div>
              <div style={{ fontSize: 13, fontWeight: 700, color: "#991b1b" }}>
                ⚠️ ALERTA: {ea.pending_viejos.total} pending {ea.pending_viejos.total === 1 ? 'viejo' : 'viejos'} sin responder
                <TooltipInfo texto="Ofertas que aceptamos hace varios días y siguen pending. MELI puede rotarlas a otro carrier en cualquier momento. Responder con urgencia." />
              </div>
              <div style={{ fontSize: 11, color: "#7f1d1d", marginTop: 2 }}>
                Click para ver detalle (request_id, SC, días pendiente)
              </div>
            </div>
            <div style={{ fontSize: 11, color: "#991b1b", fontWeight: 600 }}>VER →</div>
          </div>
        )}
      </div>

      {/* BLOQUE 2: NIVEL DE SERVICIO */}
      <div style={{ background: "#fff", borderRadius: 12, padding: 20, marginBottom: 16, border: "1px solid #e4e7ec" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: 14 }}>
          <div>
            <div style={{ fontSize: 16, fontWeight: 700, color: "#1a3a6b" }}>Nivel de Servicio</div>
            <div style={{ fontSize: 11, color: "#888", marginTop: 2 }}>Umbral mínimo: {ns.umbral}%</div>
          </div>
        </div>
        
        {/* NS dual: ponderado vs promedio */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(2, 1fr)", gap: 12, marginBottom: 16 }}>
          <div onClick={() => abrirDetalle("ejecutadas", {}, "Rutas ejecutadas (peor a mejor NS)")}
            style={{ 
              background: colorBg(ns.pct_ponderado, ns.umbral), 
              borderRadius: 8, padding: 16, cursor: "pointer",
              border: `2px solid ${colorPct(ns.pct_ponderado, ns.umbral)}` 
            }}>
            <div style={{ fontSize: 11, fontWeight: 700, color: "#1a3a6b", textTransform: "uppercase", letterSpacing: 0.5, display: "flex", justifyContent: "space-between" }}>
              <span>NS Ponderado (oficial MELI)</span><span style={{ fontSize: 9, opacity: 0.6 }}>VER →</span>
            </div>
            <div style={{ fontSize: 36, fontWeight: 800, color: colorPct(ns.pct_ponderado, ns.umbral), marginTop: 4 }}>
              {ns.pct_ponderado || 0}% {!cumple(ns.pct_ponderado, ns.umbral) ? "🔴" : "✅"}
            </div>
            <div style={{ fontSize: 11, color: "#666", marginTop: 4 }}>
              {Number(ns.ent_total || 0).toLocaleString()} entregados de {Number(ns.desp_total || 0).toLocaleString()} despachados
            </div>
          </div>
          <div onClick={() => abrirDetalle("ejecutadas", {}, "Rutas ejecutadas (NS por ruta)")}
            style={{ 
              background: colorBg(ns.pct_promedio, ns.umbral), 
              borderRadius: 8, padding: 16, cursor: "pointer",
              border: `2px solid ${colorPct(ns.pct_promedio, ns.umbral)}` 
            }}>
            <div style={{ fontSize: 11, fontWeight: 700, color: "#1a3a6b", textTransform: "uppercase", letterSpacing: 0.5, display: "flex", justifyContent: "space-between" }}>
              <span>NS Promedio por ruta</span><span style={{ fontSize: 9, opacity: 0.6 }}>VER →</span>
            </div>
            <div style={{ fontSize: 36, fontWeight: 800, color: colorPct(ns.pct_promedio, ns.umbral), marginTop: 4 }}>
              {ns.pct_promedio || 0}% {!cumple(ns.pct_promedio, ns.umbral) ? "🔴" : "✅"}
            </div>
            <div style={{ fontSize: 11, color: "#666", marginTop: 4 }}>
              Promedio simple del % de cada ruta
            </div>
          </div>
        </div>
        
        {/* NS por SC */}
        {(ns.por_sc || []).length > 0 && (
          <div style={{ marginBottom: 14 }}>
            <div style={{ fontSize: 12, fontWeight: 700, color: "#475569", textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 8 }}>
              Por Service Center (peor → mejor)
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(160px, 1fr))", gap: 8 }}>
              {(ns.por_sc || []).map(s => (
                <div key={s.sc} 
                  onClick={() => abrirDetalle("ejecutadas", { sc: s.sc }, `Rutas de ${s.sc}`)}
                  style={{ 
                  background: colorBg(s.ns_pct, ns.umbral), 
                  borderRadius: 6, padding: "8px 10px", cursor: "pointer",
                  border: `1px solid ${colorPct(s.ns_pct, ns.umbral)}33` 
                }}>
                  <div style={{ fontSize: 11, fontWeight: 700, color: "#1a3a6b", display: "flex", justifyContent: "space-between" }}>
                    <span>{s.sc}</span><span style={{ fontSize: 8, opacity: 0.5 }}>→</span>
                  </div>
                  <div style={{ fontSize: 18, fontWeight: 800, color: colorPct(s.ns_pct, ns.umbral) }}>
                    {s.ns_pct}%
                  </div>
                  <div style={{ fontSize: 9, color: "#888" }}>
                    {s.rutas} rutas · {Number(s.ent || 0).toLocaleString()}/{Number(s.desp || 0).toLocaleString()}
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
        
        {/* NS por tipo de ruta */}
        {(ns.por_tipo || []).length > 0 && (
          <div style={{ marginBottom: 14 }}>
            <div style={{ fontSize: 12, fontWeight: 700, color: "#475569", textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 8 }}>
              Por tipo de ruta
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(180px, 1fr))", gap: 8 }}>
              {(ns.por_tipo || []).map(t => (
                <div key={t.tipo} 
                  onClick={() => abrirDetalle("ejecutadas", { tipo_ruta: t.tipo }, `Rutas tipo ${t.tipo}`)}
                  style={{ 
                  background: colorBg(t.ns_pct, ns.umbral), 
                  borderRadius: 6, padding: "10px 12px", cursor: "pointer",
                  border: `1px solid ${colorPct(t.ns_pct, ns.umbral)}33` 
                }}>
                  <div style={{ fontSize: 12, fontWeight: 700, color: "#1a3a6b", display: "flex", justifyContent: "space-between" }}>
                    <span>{t.tipo}</span><span style={{ fontSize: 9, opacity: 0.5 }}>→</span>
                  </div>
                  <div style={{ fontSize: 20, fontWeight: 800, color: colorPct(t.ns_pct, ns.umbral) }}>
                    {t.ns_pct}%
                  </div>
                  <div style={{ fontSize: 10, color: "#888" }}>
                    {t.rutas} rutas
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
        
        {/* Características especiales (overlap permitido) */}
        {ns.caracteristicas && (
          (ns.caracteristicas.bulky?.rutas || 0) + (ns.caracteristicas.bags?.rutas || 0) + 
          (ns.caracteristicas.ambulancia?.rutas || 0) + (ns.caracteristicas.pickup_node?.rutas || 0) > 0
        ) && (
          <div>
            <div style={{ fontSize: 12, fontWeight: 700, color: "#475569", textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 8 }}>
              Características especiales (puede haber overlap)
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(160px, 1fr))", gap: 8 }}>
              {(ns.caracteristicas.bulky?.rutas || 0) > 0 && (
                <div onClick={() => abrirDetalle("ejecutadas", { caracteristica: "bulky" }, "Rutas con Bulky")}
                  style={{ background: "#fef3c7", borderRadius: 6, padding: "10px 12px", border: "1px solid #fde68a", cursor: "pointer" }}>
                  <div style={{ fontSize: 11, fontWeight: 700, color: "#92400e", textTransform: "uppercase", letterSpacing: 0.3, display: "flex", justifyContent: "space-between" }}>
                    <span>📦 Bulky</span><span style={{ fontSize: 9, opacity: 0.5 }}>→</span>
                  </div>
                  <div style={{ fontSize: 22, fontWeight: 800, color: "#92400e" }}>{ns.caracteristicas.bulky.rutas}</div>
                  <div style={{ fontSize: 11, fontWeight: 700, color: cumple(ns.caracteristicas.bulky.ns_pct, ns.umbral) ? "#16a34a" : "#dc2626", marginTop: 2 }}>
                    NS {ns.caracteristicas.bulky.ns_pct || 0}%
                  </div>
                  <div style={{ fontSize: 10, color: "#888" }}>paquetes voluminosos</div>
                </div>
              )}
              {(ns.caracteristicas.bags?.rutas || 0) > 0 && (
                <div onClick={() => abrirDetalle("ejecutadas", { caracteristica: "bags" }, "Rutas con Bags")}
                  style={{ background: "#dbeafe", borderRadius: 6, padding: "10px 12px", border: "1px solid #bfdbfe", cursor: "pointer" }}>
                  <div style={{ fontSize: 11, fontWeight: 700, color: "#1e40af", textTransform: "uppercase", letterSpacing: 0.3, display: "flex", justifyContent: "space-between" }}>
                    <span>👜 Bags</span><span style={{ fontSize: 9, opacity: 0.5 }}>→</span>
                  </div>
                  <div style={{ fontSize: 22, fontWeight: 800, color: "#1e40af" }}>{ns.caracteristicas.bags.rutas}</div>
                  <div style={{ fontSize: 11, fontWeight: 700, color: cumple(ns.caracteristicas.bags.ns_pct, ns.umbral) ? "#16a34a" : "#dc2626", marginTop: 2 }}>
                    NS {ns.caracteristicas.bags.ns_pct || 0}%
                  </div>
                  <div style={{ fontSize: 10, color: "#888" }}>envíos consolidados</div>
                </div>
              )}
              {(ns.caracteristicas.ambulancia?.rutas || 0) > 0 && (
                <div onClick={() => abrirDetalle("ejecutadas", { caracteristica: "ambulancia" }, "Rutas Ambulancia")}
                  style={{ background: "#fee2e2", borderRadius: 6, padding: "10px 12px", border: "1px solid #fecaca", cursor: "pointer" }}>
                  <div style={{ fontSize: 11, fontWeight: 700, color: "#991b1b", textTransform: "uppercase", letterSpacing: 0.3, display: "flex", justifyContent: "space-between" }}>
                    <span>🚑 Ambulancia</span><span style={{ fontSize: 9, opacity: 0.5 }}>→</span>
                  </div>
                  <div style={{ fontSize: 22, fontWeight: 800, color: "#991b1b" }}>{ns.caracteristicas.ambulancia.rutas}</div>
                  <div style={{ fontSize: 11, fontWeight: 700, color: cumple(ns.caracteristicas.ambulancia.ns_pct, ns.umbral) ? "#16a34a" : "#dc2626", marginTop: 2 }}>
                    NS {ns.caracteristicas.ambulancia.ns_pct || 0}%
                  </div>
                  <div style={{ fontSize: 10, color: "#888" }}>ruta de urgencia</div>
                </div>
              )}
              {(ns.caracteristicas.pickup_node?.rutas || 0) > 0 && (
                <div onClick={() => abrirDetalle("ejecutadas", { caracteristica: "pickup_node" }, "Rutas con Pickup Node")}
                  style={{ background: "#e0e7ff", borderRadius: 6, padding: "10px 12px", border: "1px solid #c7d2fe", cursor: "pointer" }}>
                  <div style={{ fontSize: 11, fontWeight: 700, color: "#3730a3", textTransform: "uppercase", letterSpacing: 0.3, display: "flex", justifyContent: "space-between" }}>
                    <span>📍 Pickup Node</span><span style={{ fontSize: 9, opacity: 0.5 }}>→</span>
                  </div>
                  <div style={{ fontSize: 22, fontWeight: 800, color: "#3730a3" }}>{ns.caracteristicas.pickup_node.rutas}</div>
                  <div style={{ fontSize: 11, fontWeight: 700, color: cumple(ns.caracteristicas.pickup_node.ns_pct, ns.umbral) ? "#16a34a" : "#dc2626", marginTop: 2 }}>
                    NS {ns.caracteristicas.pickup_node.ns_pct || 0}%
                  </div>
                  <div style={{ fontSize: 10, color: "#888" }}>punto de recolección</div>
                </div>
              )}
            </div>
          </div>
        )}
        
        {(ns.por_tipo || []).length === 0 && (
          <div style={{ fontSize: 11, color: "#94a3b8", fontStyle: "italic", marginTop: 8 }}>
            Tipos de ruta no disponibles (cruce con scraper de ayudantes pendiente)
          </div>
        )}
      </div>

      {/* BLOQUE 3: NIVEL DE VISITADOS */}
      <div style={{ background: "#fff", borderRadius: 12, padding: 20, marginBottom: 16, border: "1px solid #e4e7ec" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <div>
            <div style={{ fontSize: 16, fontWeight: 700, color: "#1a3a6b" }}>Nivel de Visitados</div>
            <div style={{ fontSize: 11, color: "#888", marginTop: 2 }}>Umbral mínimo: {nv.umbral}%</div>
          </div>
          <div onClick={() => (nv.no_visitados || 0) > 0 && abrirDetalle("no_visitados", {}, "Rutas con paquetes no visitados")}
            style={{ 
            background: colorBg(nv.pct_general, nv.umbral), 
            borderRadius: 8, padding: "10px 18px", 
            border: `2px solid ${colorPct(nv.pct_general, nv.umbral)}`,
            cursor: (nv.no_visitados || 0) > 0 ? "pointer" : "default"
          }}>
            <div style={{ fontSize: 32, fontWeight: 800, color: colorPct(nv.pct_general, nv.umbral) }}>
              {nv.pct_general || 0}% {!cumple(nv.pct_general, nv.umbral) ? "🔴" : "✅"}
            </div>
            <div style={{ fontSize: 11, color: "#666", textAlign: "right" }}>
              {Math.round(nv.no_visitados || 0)} no visitados de {Number(nv.desp_total || 0).toLocaleString()}
              {(nv.no_visitados || 0) > 0 && <span style={{ marginLeft: 8, opacity: 0.6 }}>VER →</span>}
            </div>
          </div>
        </div>
      </div>

      {/* BLOQUE 4: PNR */}
      <div style={{ background: "#fff", borderRadius: 12, padding: 20, border: "1px solid #e4e7ec" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: 14 }}>
          <div>
            <div style={{ fontSize: 16, fontWeight: 700, color: "#1a3a6b" }}>PNR del día anterior</div>
            <div style={{ fontSize: 11, color: "#888", marginTop: 2 }}>Casos creados el {fechaTexto}</div>
          </div>
          <div style={{ fontSize: 32, fontWeight: 800, color: "#1a3a6b" }}>
            {pnr.total || 0}
          </div>
        </div>
        
        {(pnr.por_estado || []).length === 0 ? (
          <div style={{ fontSize: 13, color: "#94a3b8", fontStyle: "italic", textAlign: "center", padding: 16 }}>
            No hay casos PNR registrados para este día
          </div>
        ) : (
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))", gap: 8 }}>
            {(pnr.por_estado || []).map(e => {
              const esCerrado = e.estado === "Anulado" || e.estado === "Enviado a facturacion";
              const bg = esCerrado ? "#f0fdf4" : "#fff7ed";
              const colorTxt = esCerrado ? "#166534" : "#9a3412";
              const colorVal = esCerrado ? "#16a34a" : "#ea580c";
              return (
                <div key={e.estado} 
                  onClick={() => abrirDetalle("pnr", { pnr_estado: e.estado }, `PNR · ${e.estado}`)}
                  style={{ background: bg, borderRadius: 8, padding: "10px 14px", border: "1px solid #e4e7ec", cursor: "pointer" }}>
                  <div style={{ fontSize: 11, fontWeight: 700, color: colorTxt, textTransform: "uppercase", letterSpacing: 0.3, display: "flex", justifyContent: "space-between" }}>
                    <span>{e.estado}</span><span style={{ fontSize: 9, opacity: 0.6 }}>VER →</span>
                  </div>
                  <div style={{ fontSize: 22, fontWeight: 800, color: colorVal, marginTop: 2 }}>
                    {e.cantidad}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
      
      {/* MODAL DE DETALLE */}
      {modal && (
        <div onClick={() => setModal(null)}
          style={{
            position: "fixed", top: 0, left: 0, right: 0, bottom: 0,
            background: "rgba(0,0,0,0.5)", zIndex: 1000,
            display: "flex", alignItems: "center", justifyContent: "center", padding: 20
          }}>
          <div onClick={(e) => e.stopPropagation()}
            style={{
              background: "#fff", borderRadius: 12, maxWidth: "95vw", maxHeight: "90vh",
              width: 1200, display: "flex", flexDirection: "column", overflow: "hidden"
            }}>
            {/* Header */}
            <div style={{
              padding: "16px 20px", borderBottom: "1px solid #e4e7ec",
              display: "flex", justifyContent: "space-between", alignItems: "center", gap: 12
            }}>
              <div style={{ fontSize: 16, fontWeight: 700, color: "#1a3a6b" }}>{modal.titulo}</div>
              <div style={{ display: "flex", gap: 8 }}>
                {modal.filas && modal.filas.length > 0 && !modal.filas[0]?.error && (
                  <button onClick={() => descargarExcelMeli(modal.filas, modal.nombreArchivo || "kpi_detalle", "Detalle")}
                    style={{
                      background: "#16a34a", color: "#fff", border: "none", borderRadius: 6,
                      padding: "8px 14px", fontSize: 12, fontWeight: 600, cursor: "pointer"
                    }}>
                    📥 Descargar Excel
                  </button>
                )}
                <button onClick={() => setModal(null)}
                  style={{
                    background: "#f1f5f9", border: "none", borderRadius: 6,
                    padding: "8px 14px", fontSize: 12, fontWeight: 600, cursor: "pointer", color: "#475569"
                  }}>
                  Cerrar
                </button>
              </div>
            </div>
            
            {/* Contenido tabla */}
            <div style={{ overflow: "auto", flex: 1, padding: 0 }}>
              {modalLoading ? (
                <div style={{ padding: 40, textAlign: "center", color: "#888" }}>Cargando...</div>
              ) : modal.filas && modal.filas.length === 0 ? (
                <div style={{ padding: 40, textAlign: "center", color: "#888" }}>
                  Sin datos para mostrar
                </div>
              ) : modal.filas && modal.filas[0]?.error ? (
                <div style={{ padding: 40, textAlign: "center", color: "#c0392b" }}>
                  Error: {modal.filas[0].error}
                </div>
              ) : (
                <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
                  <thead style={{ background: "#f8fafc", position: "sticky", top: 0, zIndex: 1 }}>
                    <tr>
                      {Object.keys(modal.filas[0] || {}).map(col => {
                        const labels = {
                          'request_id': 'Request ID',
                          'service_center': 'SC',
                          'fecha_operacion': 'Fecha Op.',
                          'vehiculo': 'Vehículo',
                          'fleet': 'Fleet',
                          'estado': 'Estado',
                          'motivo': 'Motivo',
                          'id_ruta': 'ID Ruta',
                          'driver': 'Driver',
                          'patente': 'Patente',
                          'tipo_ruta': 'Tipo Ruta',
                          'despachados': 'Despachados',
                          'entregados': 'Entregados',
                          'no_visitado': 'No Visitado',
                          'ns_ruta_pct': 'NS Ruta %',
                          'id_caso': 'ID Caso',
                          'tipo_pnr': 'Tipo PNR',
                          'fecha_caso': 'Fecha Caso',
                          'ruta': 'Ruta',
                          'conductor': 'Conductor',
                          'valor_compra': 'Valor Compra',
                          'productos': 'Productos',
                          'comentario_cierre': 'Comentario',
                        };
                        return (
                          <th key={col} style={{
                            padding: "10px 12px", textAlign: "left", fontWeight: 700,
                            color: "#475569", textTransform: "uppercase", fontSize: 10, letterSpacing: 0.5,
                            borderBottom: "2px solid #e4e7ec", whiteSpace: "nowrap"
                          }}>
                            {labels[col] || col.replace(/_/g, " ")}
                          </th>
                        );
                      })}
                    </tr>
                  </thead>
                  <tbody>
                    {modal.filas.map((fila, i) => (
                      <tr key={i} style={{ borderBottom: "1px solid #f1f5f9" }}>
                        {Object.keys(modal.filas[0] || {}).map(col => {
                          const val = fila[col];
                          const display = val === null || val === undefined ? "—" : 
                                         typeof val === "boolean" ? (val ? "Sí" : "No") :
                                         typeof val === "number" ? val.toLocaleString() : 
                                         String(val);
                          return (
                            <td key={col} style={{ 
                              padding: "8px 12px", color: "#475569", whiteSpace: "nowrap",
                              maxWidth: 300, overflow: "hidden", textOverflow: "ellipsis"
                            }}>
                              {display}
                            </td>
                          );
                        })}
                      </tr>
                    ))}
                  </tbody>
                </table>
              )}
            </div>
            
            {/* Footer */}
            <div style={{
              padding: "10px 20px", borderTop: "1px solid #e4e7ec",
              fontSize: 11, color: "#888", background: "#f8fafc"
            }}>
              {modal.filas && !modal.filas[0]?.error ? `${modal.filas.length} fila${modal.filas.length === 1 ? '' : 's'}` : ''}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
// COMPROMISO MELI — Vista de la operativa de mañana
// ═══════════════════════════════════════════════════════════════════════════
function PoolMeliCompromiso() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [refreshKey, setRefreshKey] = useState(0);
  const [excelDesde, setExcelDesde] = useState(fechaOperativaOffset(-7));
  const [excelHasta, setExcelHasta] = useState(fechaHoyOperativa());
  const [excelHistBusy, setExcelHistBusy] = useState(false);

  useEffect(() => {
    let alive = true;
    (async () => {
      setLoading(true);
      setError(null);
      try {
        const { data: result, error: err } = await sb.rpc("get_compromiso_meli_manana");
        if (!alive) return;
        if (err) throw err;
        setData(result);
      } catch (e) {
        if (alive) setError(e.message || String(e));
      } finally {
        if (alive) setLoading(false);
      }
    })();
    return () => { alive = false; };
  }, [refreshKey]);

  if (loading) {
    return <div className="pg" style={{ padding: 60, textAlign: "center", color: "#888" }}>Cargando compromiso de mañana…</div>;
  }
  if (error) {
    return <div className="pg" style={{ padding: 40, color: "#c0392b" }}>Error: {error}</div>;
  }
  if (!data) {
    return <div className="pg" style={{ padding: 40, color: "#888" }}>Sin datos</div>;
  }

  const c = data.conteos || {};
  const fechaManana = data.fecha_manana;
  const generadoEn = data.generado_en ? new Date(data.generado_en) : null;

  const ofrecidasTotal = (c.ofrecidas_sdd || 0) + (c.ofrecidas_spot || 0);
  const aceptadasTotal = (c.aceptadas_sdd || 0) + (c.aceptadas_spot || 0);
  const rechazadasTotal = (c.rechazadas_sdd || 0) + (c.rechazadas_spot || 0);
  const canceladasTotal = (c.canceladas_sdd || 0) + (c.canceladas_spot || 0);

  const calcularCump = (acept, ofrec, canc) => {
    const efectivas = ofrec - canc;
    if (efectivas <= 0) return null;
    return (acept / efectivas) * 100;
  };
  const cumpTotal = calcularCump(aceptadasTotal, ofrecidasTotal, canceladasTotal);
  const cumpSdd = calcularCump(c.aceptadas_sdd || 0, c.ofrecidas_sdd || 0, c.canceladas_sdd || 0);
  const cumpSpot = calcularCump(c.aceptadas_spot || 0, c.ofrecidas_spot || 0, c.canceladas_spot || 0);
  const efectTotal = ofrecidasTotal - canceladasTotal;
  const efectSdd = (c.ofrecidas_sdd || 0) - (c.canceladas_sdd || 0);
  const efectSpot = (c.ofrecidas_spot || 0) - (c.canceladas_spot || 0);

  const colorPct = (pct) => {
    if (pct === null) return "#94a3b8";
    if (pct >= 95) return "#047857";
    if (pct >= 85) return "#0891b2";
    if (pct >= 70) return "#ca8a04";
    return "#b91c1c";
  };

  const meses = ["enero","febrero","marzo","abril","mayo","junio","julio","agosto","septiembre","octubre","noviembre","diciembre"];
  const dias = ["domingo","lunes","martes","miércoles","jueves","viernes","sábado"];
  let fechaTexto = fechaManana;
  if (fechaManana) {
    const [y, m, d] = fechaManana.split("-").map(Number);
    const fechaObj = new Date(y, m - 1, d);
    fechaTexto = `${dias[fechaObj.getDay()]} ${d} de ${meses[m - 1]} de ${y}`;
  }

  // Export Excel de la foto de compromiso (un día: la operativa de mañana). Incluye la fecha.
  const exportarExcel = async () => {
    const fmt = (x) => (x != null ? Number(x.toFixed(1)) : "—");
    const resumenSheet = [
      ["Reporte", "Compromiso MELI · Operativa de mañana"],
      ["Fecha operativa", fechaManana || ""],
      ["Generado", generadoEn ? generadoEn.toLocaleString("es-MX") : ""],
      [""],
      ["Métrica", "SDD", "SPOT", "Total"],
      ["Ofrecidas", c.ofrecidas_sdd || 0, c.ofrecidas_spot || 0, ofrecidasTotal],
      ["Aceptadas", c.aceptadas_sdd || 0, c.aceptadas_spot || 0, aceptadasTotal],
      ["Rechazadas", c.rechazadas_sdd || 0, c.rechazadas_spot || 0, rechazadasTotal],
      ["Canceladas MELI", c.canceladas_sdd || 0, c.canceladas_spot || 0, canceladasTotal],
      ["Efectivas (ofrec − canc)", efectSdd, efectSpot, efectTotal],
      ["% Cumplimiento", fmt(cumpSdd), fmt(cumpSpot), fmt(cumpTotal)],
    ];
    const rk = (titulo, arr) => {
      const rows = [[titulo], ["SC / Facility", "Cantidad"]];
      (arr || []).forEach(x => rows.push([x.facility_id || "", Number(x.cant) || 0]));
      return rows;
    };
    const rankingSheet = [
      ...rk("SDD · Más aceptadas", data.ranking_sdd_aceptadas), [""],
      ...rk("SDD · Más rechazadas", data.ranking_sdd_rechazadas), [""],
      ...rk("SPOT · Más aceptadas", data.ranking_spot_aceptadas), [""],
      ...rk("SPOT · Más rechazadas", data.ranking_spot_rechazadas),
    ];
    await descargarExcelMultihoja(
      [{ nombre: "Compromiso", datos: resumenSheet }, { nombre: "Rankings", datos: rankingSheet }],
      `compromiso_meli_${fechaManana || "manana"}`
    );
  };

  // Export Excel por RANGO desde la tabla histórica (se llena a diario con snapshot_compromiso_meli)
  const exportarHistorico = async () => {
    if (!excelDesde || !excelHasta) { alert("Elegí el rango de fechas."); return; }
    const desde = excelDesde <= excelHasta ? excelDesde : excelHasta;
    const hasta = excelHasta >= excelDesde ? excelHasta : excelDesde;
    setExcelHistBusy(true);
    try {
      const { data: hist, error: err } = await sb
        .from("compromiso_meli_historico")
        .select("*")
        .gte("fecha_operativa", desde).lte("fecha_operativa", hasta)
        .order("fecha_operativa")
        .limit(100000);
      if (err) throw err;
      const rows = hist || [];
      if (rows.length === 0) {
        alert("No hay histórico guardado en ese rango todavía. La tabla se llena a diario con snapshot_compromiso_meli().");
        setExcelHistBusy(false);
        return;
      }
      const cumpl = (acept, ofrec, canc) => {
        const ef = (ofrec || 0) - (canc || 0);
        return ef > 0 ? Number(((acept || 0) / ef * 100).toFixed(1)) : "";
      };
      const headers = [
        "FECHA OPERATIVA",
        "OFRECIDAS SDD", "ACEPTADAS SDD", "RECHAZADAS SDD", "CANCELADAS SDD", "% CUMPL SDD",
        "OFRECIDAS SPOT", "ACEPTADAS SPOT", "RECHAZADAS SPOT", "CANCELADAS SPOT", "% CUMPL SPOT",
        "OFRECIDAS TOTAL", "ACEPTADAS TOTAL", "% CUMPL TOTAL",
        "GENERADO EN",
      ];
      const datos = rows.map(r => {
        const ofrecT = (r.ofrecidas_sdd || 0) + (r.ofrecidas_spot || 0);
        const aceptT = (r.aceptadas_sdd || 0) + (r.aceptadas_spot || 0);
        const cancT  = (r.canceladas_sdd || 0) + (r.canceladas_spot || 0);
        return [
          r.fecha_operativa,
          r.ofrecidas_sdd || 0, r.aceptadas_sdd || 0, r.rechazadas_sdd || 0, r.canceladas_sdd || 0, cumpl(r.aceptadas_sdd, r.ofrecidas_sdd, r.canceladas_sdd),
          r.ofrecidas_spot || 0, r.aceptadas_spot || 0, r.rechazadas_spot || 0, r.canceladas_spot || 0, cumpl(r.aceptadas_spot, r.ofrecidas_spot, r.canceladas_spot),
          ofrecT, aceptT, cumpl(aceptT, ofrecT, cancT),
          r.generado_en ? new Date(r.generado_en).toLocaleString("es-MX") : "",
        ];
      });
      await descargarExcelMultihoja(
        [{ nombre: "Compromiso histórico", datos: [headers, ...datos] }],
        `compromiso_meli_${desde === hasta ? desde : desde + "_a_" + hasta}`
      );
    } catch (e) {
      alert("Error al generar el histórico: " + (e.message || e));
    } finally {
      setExcelHistBusy(false);
    }
  };

  return (
    <div className="pg">
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 16 }}>
        <div>
          <div className="sec-title">Compromiso MELI</div>
          <div className="sec-sub">
            Operativa de mañana · {fechaTexto}
            {generadoEn && (
              <span style={{ color: "#94a3b8", marginLeft: 8 }}>
                · datos al {generadoEn.toLocaleString("es-MX", { hour: "2-digit", minute: "2-digit", day: "2-digit", month: "2-digit" })}
              </span>
            )}
          </div>
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: 8, flexWrap: "wrap", justifyContent: "flex-end" }}>
          <span style={{ fontSize: 10, fontWeight: 700, color: "#666", textTransform: "uppercase", letterSpacing: 0.5 }}>Excel · rango:</span>
          <input type="date" value={excelDesde} onChange={e => setExcelDesde(e.target.value)}
            style={{ padding: "5px 8px", borderRadius: 4, border: "1px solid #e4e7ec", fontSize: 12, color: "#1a1a1a" }} />
          <span style={{ fontSize: 11, color: "#888" }}>a</span>
          <input type="date" value={excelHasta} onChange={e => setExcelHasta(e.target.value)}
            style={{ padding: "5px 8px", borderRadius: 4, border: "1px solid #e4e7ec", fontSize: 12, color: "#1a1a1a" }} />
          <button onClick={exportarHistorico} disabled={excelHistBusy}
            style={{ padding: "7px 14px", borderRadius: 6, border: "1px solid #16a34a", background: excelHistBusy ? "#9ca3af" : "#16a34a", color: "#fff", fontSize: 12, fontWeight: 700, cursor: excelHistBusy ? "wait" : "pointer", display: "flex", alignItems: "center", gap: 6, fontFamily: "'Geist', sans-serif" }}
            title="Excel por rango desde la tabla histórica (se llena a diario)"
          >{excelHistBusy ? "⏳ Generando..." : "📥 Descargar Excel"}</button>
          <button
            onClick={exportarExcel}
            style={{
              padding: "8px 14px", fontSize: 12, fontWeight: 600,
              background: "#fff", color: "#1a3a6b",
              border: "1px solid #e4e7ec", borderRadius: 6,
              cursor: "pointer", fontFamily: "'Geist', sans-serif",
              display: "flex", alignItems: "center", gap: 6,
            }}
            title="Excel de la foto de mañana (un día)"
          >⬇ Mañana</button>
          <button
            onClick={() => setRefreshKey(k => k + 1)}
            style={{
              padding: "8px 14px", fontSize: 12, fontWeight: 600,
              background: "#fff", color: "#1a3a6b",
              border: "1px solid #e4e7ec", borderRadius: 6,
              cursor: "pointer", fontFamily: "'Geist', sans-serif",
              display: "flex", alignItems: "center", gap: 6,
            }}
            title="Recargar datos"
          >↻ Refrescar</button>
        </div>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 12, marginBottom: 20 }}>
        <div className="form-card" style={{
          marginBottom: 0,
          background: "linear-gradient(135deg, #1a3a6b 0%, #0f2647 100%)",
          color: "#fff", padding: 20,
        }}>
          <div style={{ fontSize: 10, fontWeight: 700, opacity: 0.8, textTransform: "uppercase", letterSpacing: 1, marginBottom: 8 }}>
            % Cumplimiento Total
          </div>
          <div style={{ fontSize: 44, fontWeight: 700, lineHeight: 1, marginBottom: 8 }}>
            {cumpTotal !== null ? `${cumpTotal.toFixed(1)}%` : "—"}
          </div>
          <div style={{ fontSize: 12, opacity: 0.9, marginBottom: 6 }}>
            {aceptadasTotal} aceptadas / {efectTotal} efectivas
          </div>
          <div style={{ fontSize: 10, opacity: 0.7, lineHeight: 1.4 }}>
            Fórmula: Aceptadas ÷ (Ofrecidas − Canceladas MELI)
          </div>
        </div>

        <div className="form-card" style={{ marginBottom: 0, padding: 20, borderTop: `4px solid ${colorPct(cumpSdd)}` }}>
          <div style={{ fontSize: 10, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: 1, marginBottom: 8 }}>
            % Cumplimiento SDD
            <span style={{ fontSize: 9, fontWeight: 600, color: "#94a3b8", marginLeft: 6, textTransform: "none", letterSpacing: 0 }}>
              · Súper Dedicadas (flota fija)
            </span>
          </div>
          <div style={{ fontSize: 44, fontWeight: 700, lineHeight: 1, marginBottom: 8, color: colorPct(cumpSdd) }}>
            {cumpSdd !== null ? `${cumpSdd.toFixed(1)}%` : "—"}
          </div>
          <div style={{ fontSize: 12, color: "#334155", marginBottom: 6 }}>
            {c.aceptadas_sdd || 0} aceptadas / {efectSdd} efectivas
          </div>
          <div style={{ fontSize: 10, color: "#94a3b8", lineHeight: 1.4 }}>
            Aceptadas ÷ (Ofrecidas − Canceladas MELI)
          </div>
        </div>

        <div className="form-card" style={{ marginBottom: 0, padding: 20, borderTop: `4px solid ${colorPct(cumpSpot)}` }}>
          <div style={{ fontSize: 10, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: 1, marginBottom: 8 }}>
            % Cumplimiento SPOT
            <span style={{ fontSize: 9, fontWeight: 600, color: "#94a3b8", marginLeft: 6, textTransform: "none", letterSpacing: 0 }}>
              · Variables (flota flexible)
            </span>
          </div>
          <div style={{ fontSize: 44, fontWeight: 700, lineHeight: 1, marginBottom: 8, color: colorPct(cumpSpot) }}>
            {cumpSpot !== null ? `${cumpSpot.toFixed(1)}%` : "—"}
          </div>
          <div style={{ fontSize: 12, color: "#334155", marginBottom: 6 }}>
            {c.aceptadas_spot || 0} aceptadas / {efectSpot} efectivas
          </div>
          <div style={{ fontSize: 10, color: "#94a3b8", lineHeight: 1.4 }}>
            Aceptadas ÷ (Ofrecidas − Canceladas MELI)
          </div>
        </div>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "repeat(5, 1fr)", gap: 12, marginBottom: 20 }}>
        <CompromisoTarjeta label="Ofrecidas" sublabel="Total por MELI" total={ofrecidasTotal} sdd={c.ofrecidas_sdd || 0} spot={c.ofrecidas_spot || 0} color="#1a3a6b" />
        <CompromisoTarjeta label="Aceptadas" sublabel="Por nosotros" total={aceptadasTotal} sdd={c.aceptadas_sdd || 0} spot={c.aceptadas_spot || 0} color="#047857" />
        <CompromisoTarjeta label="Rechazadas" sublabel="Por nosotros" total={rechazadasTotal} sdd={c.rechazadas_sdd || 0} spot={c.rechazadas_spot || 0} color="#b91c1c" />
        <CompromisoTarjeta label="Canceladas" sublabel="Por MELI" total={canceladasTotal} sdd={c.canceladas_sdd || 0} spot={c.canceladas_spot || 0} color="#92400e" />
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
        <div className="form-card" style={{ marginBottom: 0 }}>
          <div className="form-title" style={{ marginBottom: 4 }}>Ranking SDD por SC</div>
          <div style={{ fontSize: 11, color: "#64748b", marginBottom: 14 }}>Top 5 · Súper Dedicadas (compromiso obligatorio)</div>
          <RankingBloque titulo="Más aceptadas" datos={data.ranking_sdd_aceptadas || []} color="#047857" />
          <div style={{ height: 12 }} />
          <RankingBloque titulo="Más rechazadas" datos={data.ranking_sdd_rechazadas || []} color="#b91c1c" emptyMsg="Sin rechazadas SDD" />
        </div>

        <div className="form-card" style={{ marginBottom: 0 }}>
          <div className="form-title" style={{ marginBottom: 4 }}>Ranking SPOT por SC</div>
          <div style={{ fontSize: 11, color: "#64748b", marginBottom: 14 }}>Top 5 · Variables (flota flexible)</div>
          <RankingBloque titulo="Más aceptadas" datos={data.ranking_spot_aceptadas || []} color="#047857" />
          <div style={{ height: 12 }} />
          <RankingBloque titulo="Más rechazadas" datos={data.ranking_spot_rechazadas || []} color="#b91c1c" emptyMsg="Sin rechazadas SPOT" />
        </div>
      </div>
    </div>
  );
}

// ── Tarjeta de conteo por status (con desglose SDD/SPOT) ───────────────────
function CompromisoTarjeta({ label, sublabel, total, sdd, spot, color }) {
  return (
    <div className="form-card" style={{ marginBottom: 0, padding: 16, borderTop: `3px solid ${color}` }}>
      <div style={{ fontSize: 11, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5 }}>{label}</div>
      <div style={{ fontSize: 10, color: "#94a3b8", marginBottom: 8 }}>{sublabel}</div>
      <div style={{ fontSize: 36, fontWeight: 700, color, lineHeight: 1, marginBottom: 12, fontVariantNumeric: "tabular-nums" }}>{total}</div>
      <div style={{ borderTop: "1px solid #f1f5f9", paddingTop: 10 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 6 }}>
          <span style={{ fontSize: 11, fontWeight: 600, color: "#334155" }}>SDD</span>
          <span style={{ fontSize: 14, fontWeight: 700, color: "#0f172a", fontVariantNumeric: "tabular-nums" }}>{sdd}</span>
        </div>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <span style={{ fontSize: 11, fontWeight: 600, color: "#334155" }}>SPOT</span>
          <span style={{ fontSize: 14, fontWeight: 700, color: "#0f172a", fontVariantNumeric: "tabular-nums" }}>{spot}</span>
        </div>
      </div>
    </div>
  );
}

// ── Bloque de ranking (lista de SCs con barra) ─────────────────────────────
function RankingBloque({ titulo, datos, color, emptyMsg = "Sin datos" }) {
  if (!datos || datos.length === 0) {
    return (
      <div>
        <div style={{ fontSize: 11, fontWeight: 700, color, textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 8 }}>{titulo}</div>
        <div style={{ fontSize: 12, color: "#94a3b8", fontStyle: "italic", padding: "8px 0" }}>{emptyMsg}</div>
      </div>
    );
  }
  const maxCant = Math.max(...datos.map(d => Number(d.cant) || 0));
  return (
    <div>
      <div style={{ fontSize: 11, fontWeight: 700, color, textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 8 }}>{titulo}</div>
      {datos.map((d, i) => {
        const pct = maxCant > 0 ? (Number(d.cant) / maxCant) * 100 : 0;
        return (
          <div key={d.facility_id} style={{ marginBottom: 6 }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 3 }}>
              <span style={{ fontSize: 12, fontWeight: 600, color: "#0f172a" }}>
                <span style={{ color: "#cbd5e1", fontFamily: "monospace", marginRight: 6 }}>#{i + 1}</span>
                {d.facility_id}
              </span>
              <span style={{ fontSize: 13, fontWeight: 700, color, fontVariantNumeric: "tabular-nums" }}>{d.cant}</span>
            </div>
            <div style={{ height: 4, background: "#f1f5f9", borderRadius: 2, overflow: "hidden" }}>
              <div style={{ height: "100%", width: `${pct}%`, background: color, borderRadius: 2 }} />
            </div>
          </div>
        );
      })}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
// KPI DE OPERACIÓN — Comparativa NS Informe MELI vs Snapshots (día anterior)
// ═══════════════════════════════════════════════════════════════════════════
// ═══════════════════════════════════════════════════════════════════════════
// KPI DE OPERACIÓN — DASHBOARD STYLE (reemplazo completo)
// Ubicación original: líneas ~21675 a ~22206 en App.jsx
// Reemplaza la function PoolMeliKPIOperacion() entera por esta versión.
//
// FUENTES DE DATOS:
//   • get_kpi_operacion_comparativo(p_fecha)         — actual (KPIs del día)
//   • get_compromiso_meli_manana()                   — actual (Servicios ofertados)
//   • get_kpi_operacion_historico(p_desde, p_hasta)  — PENDIENTE (sparklines + deltas + rankings)
//                                                       Debe devolver un array de filas
//                                                       { fecha, ns_pond_meli, ns_pond_snap,
//                                                         ns_prom_sc_meli, ns_prom_sc_snap,
//                                                         pct_visitados, rutas, cargados,
//                                                         entregados, devueltos, ambulancias,
//                                                         no_visitados, pnr_del_dia,
//                                                         rankings: {sc, ns_pond, vs, r, carg, ent, dev, pnr, amb}[] }
//
// Si get_kpi_operacion_historico no existe aún, todo el dashboard funciona:
// los sparklines quedan vacíos y los rankings ▲/▼ usan únicamente los datos del día.
// ═══════════════════════════════════════════════════════════════════════════

function PoolMeliKPIOperacion() {
  const [data, setData] = useState(null);            // KPIs del día (comparativo)
  const [compromiso, setCompromiso] = useState(null); // Compromiso MELI (Confirmados/SDD/SPOT)
  const [historico, setHistorico] = useState([]);    // Array de filas por día (puede quedar vacío)
  const [rankingHistorico, setRankingHistorico] = useState([]); // Ranking promediado por SC del período
  const [pnrCasos, setPnrCasos] = useState([]);      // Casos PNR del período actual
  const [rutaToSc, setRutaToSc] = useState({});      // Mapeo id_ruta → service_center_id
  const [loading, setLoading] = useState(true);
  const [loadingRanking, setLoadingRanking] = useState(false);
  const [error, setError] = useState(null);
  const [refreshKey, setRefreshKey] = useState(0);
  const [periodo, setPeriodo] = useState(1); // 1, 7, 15, 22 días

  // ═══ Fecha ancla (ayer en hora MX) ═══════════════════════════════════════
  const fechaAyer = useMemo(() => {
    const ayerMX = fechaOperativaOffset(-1); // helper global ya existente
    return ayerMX;
  }, []);

  // ═══ Carga de datos ══════════════════════════════════════════════════════
  useEffect(() => {
    let alive = true;
    (async () => {
      setLoading(true);
      setError(null);
      try {
        // Calcular ventana del histórico (máx 30 días desde fechaAyer hacia atrás)
        const fechaHasta = fechaAyer;
        const desde = new Date(fechaAyer);
        desde.setDate(desde.getDate() - 29); // 30 días incluyendo fechaAyer
        const fechaDesde = desde.toISOString().slice(0, 10);

        // 1) Obtener el período PNR más reciente (formato YYYY-MM por convención del módulo PNR)
        let periodoPnrActual = null;
        try {
          const { data: periodosPnr } = await sb.from("pnr_casos")
            .select("periodo")
            .not("periodo", "is", null)
            .order("periodo", { ascending: false })
            .limit(1);
          if (periodosPnr && periodosPnr.length > 0) {
            periodoPnrActual = periodosPnr[0].periodo;
          }
        } catch { /* sin datos PNR es OK */ }

        // 2) Llamadas en paralelo
        const calls = [
          sb.rpc("get_kpi_operacion_comparativo", { p_fecha: fechaAyer }),
          sb.rpc("get_compromiso_meli_manana"),
          sb.rpc("get_kpi_operacion_historico", { p_desde: fechaDesde, p_hasta: fechaHasta }),
          // Casos PNR del período actual
          periodoPnrActual
            ? sb.from("pnr_casos").select("*").eq("periodo", periodoPnrActual).order("fecha_caso", { ascending: false })
            : Promise.resolve({ data: [], error: null }),
          // Viajes del rango histórico para mapear id_ruta → service_center_id
          sb.from("viajes")
            .select("id_ruta, service_center_id")
            .eq("pais", "MX")
            .gte("fecha_salida", fechaDesde + "T00:00:00Z")
            .lte("fecha_salida", fechaHasta + "T23:59:59Z")
            .limit(10000),
        ];
        const [rKpi, rComp, rHist, rPnr, rViajes] = await Promise.all(calls);

        if (!alive) return;
        if (rKpi.error) throw rKpi.error;
        setData(rKpi.data);
        setCompromiso(rComp.error ? null : rComp.data);
        setHistorico(rHist.error ? [] : (Array.isArray(rHist.data) ? rHist.data : []));
        setPnrCasos(rPnr.error ? [] : (rPnr.data || []));

        // Construir mapa id_ruta → service_center_id (último valor gana)
        const mapa = {};
        (rViajes.data || []).forEach(v => {
          if (v.id_ruta != null && v.service_center_id) {
            mapa[String(v.id_ruta)] = v.service_center_id;
          }
        });
        setRutaToSc(mapa);
      } catch (e) {
        if (alive) setError(e.message || String(e));
      } finally {
        if (alive) setLoading(false);
      }
    })();
    return () => { alive = false; };
  }, [refreshKey, fechaAyer]);

  // ═══ Carga del ranking promediado del período (se ejecuta al cambiar período) ═══
  useEffect(() => {
    if (periodo === 1) {
      // En D-1 usamos el ranking del día (data.ranking_sc + visitados.por_sc)
      setRankingHistorico([]);
      return;
    }
    let alive = true;
    (async () => {
      setLoadingRanking(true);
      try {
        const fechaHasta = fechaAyer;
        const desde = new Date(fechaAyer);
        desde.setDate(desde.getDate() - (periodo - 1));
        const fechaDesde = desde.toISOString().slice(0, 10);

        const { data: rData, error: rErr } = await sb.rpc(
          "get_kpi_operacion_ranking_historico",
          { p_desde: fechaDesde, p_hasta: fechaHasta }
        );
        if (!alive) return;
        if (rErr) {
          // RPC no existe aún o falló → caemos al ranking del día
          setRankingHistorico([]);
        } else {
          setRankingHistorico(Array.isArray(rData) ? rData : []);
        }
      } catch {
        if (alive) setRankingHistorico([]);
      } finally {
        if (alive) setLoadingRanking(false);
      }
    })();
    return () => { alive = false; };
  }, [periodo, fechaAyer, refreshKey]);

  // ═══ Hooks (deben ir antes de cualquier early return) ════════════════════
  // Histórico filtrado al período activo.
  // En D-1 mostramos igual los últimos 7 días en el sparkline (con dot grande en el último)
  // pero el valor grande arriba sigue siendo del día actual.
  const histPeriodo = useMemo(() => {
    if (!historico || historico.length === 0) return [];
    const ventana = periodo === 1 ? 7 : periodo;
    return historico.slice(-ventana);
  }, [historico, periodo]);

  // Período anterior (para curva punteada de comparación)
  const histPrev = useMemo(() => {
    if (!historico || historico.length === 0) return [];
    const ventana = periodo === 1 ? 7 : periodo;
    const start = Math.max(0, historico.length - ventana * 2);
    const end = historico.length - ventana;
    return historico.slice(start, end);
  }, [historico, periodo]);

  // Ranking unificado: si hay ranking histórico (período > 1), usar ese; sino, ranking del día
  const rankingsDia = useMemo(() => {
    // Si hay ranking del período seleccionado, usarlo directamente
    if (rankingHistorico && rankingHistorico.length > 0) {
      return rankingHistorico.map(r => ({
        sc: r.sc,
        ns_pond: Number(r.ns_pond) || 0,
        rutas: Math.round(Number(r.rutas) || 0),
        cargados: Number(r.cargados) || 0,
        entregados: Number(r.entregados) || 0,
        devueltos: Number(r.devueltos) || 0,
        ambulancias: Number(r.ambulancias) || 0,
        pct_visitados: r.pct_visitados != null ? Number(r.pct_visitados) : null,
        no_visitados: Number(r.no_visitados) || 0,
      }));
    }
    // Fallback: ranking del día (data.ranking_sc + visitados.por_sc)
    if (!data) return [];
    const ranking = data.ranking_sc || [];
    const visPorSc = data.visitados?.por_sc || [];
    const m = {};
    ranking.forEach(r => {
      m[r.sc] = {
        sc: r.sc,
        ns_pond: Number(r.ns_pond) || 0,
        rutas: Number(r.rutas) || 0,
        cargados: Number(r.cargados) || 0,
        entregados: Number(r.entregados) || 0,
        devueltos: Number(r.devueltos) || 0,
        ambulancias: Number(r.ambulancias) || 0,
        pct_visitados: null,
        no_visitados: 0,
      };
    });
    visPorSc.forEach(v => {
      if (!m[v.sc]) m[v.sc] = { sc: v.sc, ns_pond: 0, rutas: 0, cargados: 0, entregados: 0, devueltos: 0, ambulancias: 0 };
      m[v.sc].pct_visitados = Number(v.pct_visitados) || 0;
      m[v.sc].no_visitados = Number(v.no_visitados) || 0;
      if (!m[v.sc].cargados) m[v.sc].cargados = Number(v.cargados) || 0;
    });
    return Object.values(m);
  }, [data, rankingHistorico]);

  // ═══ Procesamiento de casos PNR ══════════════════════════════════════════
  // Clasificación de estados:
  //   ABIERTOS  = "Esperando comprobante" + "Comprobante cargado" + "Pendiente de revision" + "Sin comprobante cargado"
  //   A_COBRO   = "Con penalidad"
  //   CERRADOS  = "Anulado"
  const pnrStats = useMemo(() => {
    const ESTADOS_ABIERTOS = ["Esperando comprobante", "Comprobante cargado", "Pendiente de revision", "Sin comprobante cargado"];
    const ESTADO_COBRO = "Con penalidad";
    const ESTADO_CERRADO = "Anulado";

    const total = pnrCasos.length;
    let abiertos = 0, aCobro = 0, cerrados = 0;
    let valorAbiertos = 0, valorACobro = 0, valorTotal = 0;
    const desglose = {
      "Esperando comprobante": 0,
      "Comprobante cargado": 0,
      "Pendiente de revision": 0,
      "Sin comprobante cargado": 0,
      "Con penalidad": 0,
      "Anulado": 0,
    };

    // Casos del día (D-1)
    const casosHoy = pnrCasos.filter(c => {
      if (!c.fecha_caso) return false;
      // fecha_caso es timestamp ISO → comparar solo la parte YYYY-MM-DD
      return String(c.fecha_caso).slice(0, 10) === fechaAyer;
    });

    // Por SC (usando mapeo ruta → service_center_id)
    const porSC = {};
    pnrCasos.forEach(c => {
      const v = Number(c.valor_compra) || 0;
      valorTotal += v;
      const est = c.estado;
      if (desglose[est] !== undefined) desglose[est]++;
      if (ESTADOS_ABIERTOS.includes(est)) { abiertos++; valorAbiertos += v; }
      else if (est === ESTADO_COBRO) { aCobro++; valorACobro += v; }
      else if (est === ESTADO_CERRADO) { cerrados++; }

      // SC: buscar en el mapa por id_ruta (PNR.ruta debería matchear con viajes.id_ruta)
      const scId = rutaToSc[String(c.ruta)] || "SIN_SC";
      if (!porSC[scId]) {
        porSC[scId] = {
          sc: scId, total: 0, abiertos: 0, aCobro: 0, cerrados: 0, valor: 0, valorACobro: 0,
          esperando: 0, cargado: 0, pendiente: 0, sinComprobante: 0,
        };
      }
      porSC[scId].total++;
      porSC[scId].valor += v;
      if (est === "Esperando comprobante") porSC[scId].esperando++;
      else if (est === "Comprobante cargado") porSC[scId].cargado++;
      else if (est === "Pendiente de revision") porSC[scId].pendiente++;
      else if (est === "Sin comprobante cargado") porSC[scId].sinComprobante++;
      else if (est === ESTADO_COBRO) { porSC[scId].aCobro++; porSC[scId].valorACobro += v; }
      else if (est === ESTADO_CERRADO) porSC[scId].cerrados++;
      if (ESTADOS_ABIERTOS.includes(est)) porSC[scId].abiertos++;
    });

    // Serie histórica diaria (últimos 30 días contando casos por fecha_caso)
    const serieDiaria = {};
    pnrCasos.forEach(c => {
      if (!c.fecha_caso) return;
      const f = String(c.fecha_caso).slice(0, 10);
      serieDiaria[f] = (serieDiaria[f] || 0) + 1;
    });
    // Generar array de 30 días terminando en fechaAyer
    const sparkSerie = [];
    const base = new Date(fechaAyer + "T00:00:00");
    for (let i = 29; i >= 0; i--) {
      const d = new Date(base);
      d.setDate(d.getDate() - i);
      const key = d.toISOString().slice(0, 10);
      sparkSerie.push(serieDiaria[key] || 0);
    }

    return {
      total, abiertos, aCobro, cerrados,
      valorTotal, valorAbiertos, valorACobro,
      desglose,
      casosHoy: casosHoy.length,
      porSC: Object.values(porSC).sort((a, b) => b.total - a.total),
      sparkSerie,
    };
  }, [pnrCasos, rutaToSc, fechaAyer]);

  if (loading) {
    return <div className="pg" style={{ padding: 60, textAlign: "center", color: "#888", fontFamily: "'Geist', sans-serif" }}>Cargando KPI de operación…</div>;
  }
  if (error) {
    return <div className="pg" style={{ padding: 40, color: "#c0392b", fontFamily: "'Geist', sans-serif" }}>Error: {error}</div>;
  }
  if (!data) {
    return <div className="pg" style={{ padding: 40, color: "#888", fontFamily: "'Geist', sans-serif" }}>Sin datos</div>;
  }

  // ═══ Extracción de datos del día (RPC comparativo) ═══════════════════════
  const meli = data.meli || {};
  const meliT = meli.total || {};
  const snap = data.snap || {};
  const snapT = snap.total || {};
  const ranking = data.ranking_sc || [];
  const vis = data.visitados || {};
  const visTotal = vis.total || {};
  const visPorSc = vis.por_sc || [];
  const umbralVis = Number(vis.umbral) || 99.5;
  const generadoEn = data.generado_en ? new Date(data.generado_en) : null;

  // Foco operativo
  const porCat = data.fallidas?.por_categoria || [];
  const getCat = (k) => porCat.find(c => c.categoria_operativa === k)?.paquetes || 0;
  const devueltosTotal = getCat("DEVOLUCION");
  const ambulanciasTotal = getCat("AMBULANCIA");
  const noVisitadosTotal = getCat("NO_VISITADO");
  const pctDev = snapT.cargados > 0 ? (devueltosTotal / snapT.cargados * 100) : 0;
  const pctNoVis = snapT.cargados > 0 ? (noVisitadosTotal / snapT.cargados * 100) : 0;

  // Compromiso MELI (servicios ofertados)
  const c = compromiso?.conteos || {};
  const ofrecidasTotal = (c.ofrecidas_sdd || 0) + (c.ofrecidas_spot || 0);
  const aceptadasTotal = (c.aceptadas_sdd || 0) + (c.aceptadas_spot || 0);
  const canceladasTotal = (c.canceladas_sdd || 0) + (c.canceladas_spot || 0);
  const rechazadasTotal = (c.rechazadas_sdd || 0) + (c.rechazadas_spot || 0);
  const efectivasTotal = ofrecidasTotal - canceladasTotal;
  const calcPct = (a, ef) => ef > 0 ? (a / ef) * 100 : null;
  const pctConfirmadosTotal = calcPct(aceptadasTotal, efectivasTotal);
  const pctSDD = calcPct(c.aceptadas_sdd || 0, (c.ofrecidas_sdd || 0) - (c.canceladas_sdd || 0));
  const pctSPOT = calcPct(c.aceptadas_spot || 0, (c.ofrecidas_spot || 0) - (c.canceladas_spot || 0));

  // ═══ Fecha texto formateada ══════════════════════════════════════════════
  const meses = ["enero","febrero","marzo","abril","mayo","junio","julio","agosto","septiembre","octubre","noviembre","diciembre"];
  const dias = ["domingo","lunes","martes","miércoles","jueves","viernes","sábado"];
  let fechaTexto = data.fecha;
  if (data.fecha) {
    const [y, m, d] = data.fecha.split("-").map(Number);
    const fObj = new Date(y, m - 1, d);
    fechaTexto = `${dias[fObj.getDay()]} ${d} de ${meses[m - 1]} de ${y}`;
  }

  // ═══ Helpers de color (paleta BRAIN) ═════════════════════════════════════
  // Cumplimiento NS (meta 98.5%)
  const cumpleNS = (pct) => pct != null && Number(pct) >= 98.5;
  const cumpleVis = (pct) => pct != null && Number(pct) >= umbralVis;
  const cumpleDev = (pct) => pct != null && Number(pct) < 2;
  const cumpleNoVis = (pct) => pct != null && Number(pct) <= 0.5;

  // Badges: usa paleta de severidad del Brain (verde #16a34a / naranja #F47B20 / rojo #c0392b)
  const badge = (tipo, txt) => {
    const styles = {
      ok:   { bg: "#dcfce7", color: "#166534" },
      warn: { bg: "#fef3c7", color: "#92400e" },
      bad:  { bg: "#fee2e2", color: "#991b1b" },
    };
    const s = styles[tipo] || styles.warn;
    return (
      <span style={{
        fontSize: 9, fontWeight: 600, padding: "2px 7px", borderRadius: 4,
        textTransform: "uppercase", whiteSpace: "nowrap", letterSpacing: 0.3,
        background: s.bg, color: s.color, fontFamily: "'Geist', sans-serif",
      }}>{txt}</span>
    );
  };

  // Color de borde izquierdo según severidad (Brain colors)
  const borderColors = { bad: "#c0392b", warn: "#F47B20", ok: "#16a34a" };

  // ═══ Procesado de histórico ══════════════════════════════════════════════
  // (los useMemo de histPeriodo/histPrev/rankingsDia se calculan arriba, antes de los returns)

  // Extrae serie por campo
  const serie = (rows, campo) => rows.map(r => Number(r[campo]) || 0);

  // Delta vs período anterior
  //  • En D-1: comparar último día (ayer) vs penúltimo (anteayer)
  //  • En D-7/D-15/D-22: comparar avg del período actual vs avg del período anterior
  const computeDelta = (campo) => {
    if (periodo === 1) {
      // Necesitamos los 2 últimos puntos del histórico completo
      if (!historico || historico.length < 2) return null;
      const ult = Number(historico[historico.length - 1]?.[campo]);
      const pen = Number(historico[historico.length - 2]?.[campo]);
      if (isNaN(ult) || isNaN(pen)) return null;
      return ult - pen;
    }
    if (histPeriodo.length < 3 || histPrev.length < 3) return null;
    const avg = arr => arr.reduce((s, v) => s + v, 0) / arr.length;
    const curr = serie(histPeriodo, campo);
    const prev = serie(histPrev, campo);
    return avg(curr) - avg(prev);
  };

  const labelPeriodo = periodo === 1 ? "ayer"
                     : periodo === 7 ? "sem. anterior"
                     : periodo === 15 ? "15D anteriores"
                     : "período anterior";

  // (rankingsDia se calcula arriba como useMemo, antes de los returns)

  // top3/bot3 por métrica. lower=true → menos es mejor.
  const buildRank = (campo, fmt, lower = false) => {
    if (rankingsDia.length === 0) return { top3: "—", bot3: "—" };
    const valid = rankingsDia.filter(r => r[campo] != null);
    if (valid.length === 0) return { top3: "—", bot3: "—" };
    const sorted = [...valid].sort((a, b) => lower ? a[campo] - b[campo] : b[campo] - a[campo]);
    const top3 = sorted.slice(0, 3).map(s => `${s.sc} ${fmt(s[campo])}`).join(" · ");
    const bot3 = [...sorted].reverse().slice(0, 3).map(s => `${s.sc} ${fmt(s[campo])}`).join(" · ");
    return { top3, bot3 };
  };

  const fmtPct1 = x => `${Number(x).toFixed(1)}%`;
  const fmtPct2 = x => `${Number(x).toFixed(2)}%`;
  const fmtInt = x => `${Math.round(Number(x))}`;
  const fmtNum = x => Number(x).toLocaleString();
  const fmtZero = x => Number(x) === 0 ? "0 ✓" : `${x}`;

  // ═══ Estilos inline reutilizables (paleta Brain) ═════════════════════════
  const S = {
    NAVY: "#1a3a6b",
    ORANGE: "#F47B20",
    BG: "#f0f2f5",
    BORDER: "#e4e7ec",
    TEXT_MAIN: "#1a1a1a",
    TEXT_SEC: "#666",
    TEXT_MUTED: "#94a3b8",
    TEXT_LBL: "#64748b",
    OK: "#16a34a",
    WARN: "#F47B20",
    BAD: "#c0392b",
    INFO: "#1a3a6b",
  };

  return (
    <div style={{ fontFamily: "'Geist', sans-serif", background: S.BG, paddingBottom: 40 }}>
      {/* ═══ CONTEXT BAR ═══ */}
      <div style={{
        background: "#fff", borderBottom: `1px solid ${S.BORDER}`,
        padding: "10px 24px", display: "flex", alignItems: "center",
        justifyContent: "space-between", gap: 12, flexWrap: "wrap",
      }}>
        <div>
          <div style={{ fontSize: 14, fontWeight: 700, color: S.NAVY }}>KPI de Operación</div>
          <div style={{ fontSize: 11, color: S.TEXT_LBL, marginTop: 2 }}>
            {fechaTexto}
            {generadoEn && (
              <span style={{ color: S.TEXT_MUTED, marginLeft: 8 }}>
                · datos al {generadoEn.toLocaleString("es-MX", { hour: "2-digit", minute: "2-digit", day: "2-digit", month: "2-digit" })}
              </span>
            )}
            {historico.length === 0 && (
              <span style={{ color: S.WARN, marginLeft: 8 }}>
                · histórico no disponible (sparklines vacíos)
              </span>
            )}
          </div>
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
          <span style={{ fontSize: 10, color: S.TEXT_MUTED, fontWeight: 500, marginRight: 4 }}>Período:</span>
          {[1, 7, 15, 22].map(n => (
            <button key={n} onClick={() => setPeriodo(n)}
              style={{
                fontSize: 11, fontWeight: 600, padding: "5px 12px",
                borderRadius: 6, border: `1px solid ${periodo === n ? S.NAVY : S.BORDER}`,
                background: periodo === n ? S.NAVY : "#fff",
                color: periodo === n ? "#fff" : "#475569",
                cursor: "pointer", fontFamily: "'Geist', sans-serif",
              }}>D-{n}</button>
          ))}
          <button onClick={() => setRefreshKey(k => k + 1)}
            style={{
              marginLeft: 8, fontSize: 11, fontWeight: 600, padding: "5px 10px",
              background: "#fff", color: S.NAVY, border: `1px solid ${S.BORDER}`,
              borderRadius: 6, cursor: "pointer", fontFamily: "'Geist', sans-serif",
            }}>↻ Refrescar</button>
        </div>
      </div>

      {/* ═══ MAIN ═══ */}
      <div style={{ padding: "20px 24px", maxWidth: 1600, margin: "0 auto" }}>

        {/* ① NIVEL DE SERVICIO */}
        <GrupoTitulo icon="trend" titulo="Nivel de servicio" />
        <div style={{ display: "grid", gridTemplateColumns: "repeat(3, minmax(0, 1fr))", gap: 10, marginBottom: 28 }}>
          {/* NS Ponderado */}
          <CardNS
            S={S}
            label="NS Ponderado"
            tipo={cumpleNS(meliT.ns_ponderado) ? "ok" : "bad"}
            badgeTxt={cumpleNS(meliT.ns_ponderado) ? "Cumple" : "No cumple"}
            valorMeli={meliT.ns_ponderado}
            valorSnap={snapT.ns_ponderado}
            subtitle={`${fmtNum(meliT.entregados || 0)} / ${fmtNum(meliT.cargados || 0)}`}
            meta={98.5}
            sparkSerieMeli={serie(histPeriodo, "ns_pond_meli")}
            sparkSerieSnap={serie(histPeriodo, "ns_pond_snap")}
            sparkPrev={serie(histPrev, "ns_pond_meli")}
            sparkAllVals={serie(historico, "ns_pond_meli")}
            delta={computeDelta("ns_pond_meli")}
            deltaLabel={labelPeriodo}
            deltaUnit="pp"
            lower={false}
            ranking={buildRank("ns_pond", fmtPct1)}
            zmMin={93} zmMax={100}
          />
          {/* NS Promedio SC */}
          <CardNS
            S={S}
            label="NS Promedio SC"
            tipo={cumpleNS(meli.ns_promedio_sc) ? "ok" : "bad"}
            badgeTxt={cumpleNS(meli.ns_promedio_sc) ? "Cumple" : `${rankingsDia.filter(r => r.ns_pond > 0 && r.ns_pond < 98.5).length} SCs no cumplen`}
            valorMeli={meli.ns_promedio_sc}
            valorSnap={snap.ns_promedio_sc}
            subtitle={`avg ${snapT.rutas || 0} rutas / ${rankingsDia.length} SCs`}
            meta={98.5}
            sparkSerieMeli={serie(histPeriodo, "ns_prom_sc_meli")}
            sparkSerieSnap={serie(histPeriodo, "ns_prom_sc_snap")}
            sparkPrev={serie(histPrev, "ns_prom_sc_meli")}
            sparkAllVals={serie(historico, "ns_prom_sc_meli")}
            delta={computeDelta("ns_prom_sc_meli")}
            deltaLabel={labelPeriodo}
            deltaUnit="pp"
            lower={false}
            ranking={buildRank("ns_pond", fmtPct1)}
            zmMin={93} zmMax={100}
          />
          {/* % Visitados */}
          <CardSingle
            S={S}
            label="% Visitados"
            tipo={cumpleVis(visTotal.pct_general) ? "ok" : "bad"}
            badgeTxt={cumpleVis(visTotal.pct_general) ? "Cumple" : "No cumple"}
            valor={visTotal.pct_general}
            valorFmt={v => v != null ? `${Number(v).toFixed(2)}%` : "—"}
            subtitle={`${Number(visTotal.no_visitados || 0)} no visitado(s) · óptimo ${umbralVis}%`}
            meta={umbralVis}
            sparkSerie={serie(histPeriodo, "pct_visitados")}
            sparkPrev={serie(histPrev, "pct_visitados")}
            sparkAllVals={serie(historico, "pct_visitados")}
            delta={computeDelta("pct_visitados")}
            deltaLabel={labelPeriodo}
            deltaUnit="pp"
            lower={false}
            ranking={buildRank("pct_visitados", v => v != null ? fmtPct1(v) : "—")}
            zmMin={98} zmMax={100}
            zoom
          />
        </div>

        {/* ② VOLUMEN DEL NEGOCIO */}
        <GrupoTitulo icon="box" titulo="Volumen del negocio" />
        <div style={{ display: "grid", gridTemplateColumns: "repeat(3, minmax(0, 1fr))", gap: 10, marginBottom: 28 }}>
          <CardVolumen
            S={S}
            label="Rutas"
            valor={snapT.rutas || 0}
            subtitle={`${rankingsDia.length} SCs operando`}
            sparkSerie={serie(histPeriodo, "rutas")}
            sparkPrev={serie(histPrev, "rutas")}
            sparkAllVals={serie(historico, "rutas")}
            delta={computeDelta("rutas")}
            deltaLabel={labelPeriodo}
            deltaUnit=""
            ranking={buildRank("rutas", fmtInt)}
          />
          <CardVolumen
            S={S}
            label="Cargados"
            valor={fmtNum(snapT.cargados || 0)}
            subtitle="paquetes operados"
            sparkSerie={serie(histPeriodo, "cargados")}
            sparkPrev={serie(histPrev, "cargados")}
            sparkAllVals={serie(historico, "cargados")}
            delta={computeDelta("cargados")}
            deltaLabel={labelPeriodo}
            deltaUnit=""
            ranking={buildRank("cargados", fmtNum)}
          />
          <CardVolumen
            S={S}
            label="Entregados"
            valor={fmtNum(snapT.entregados || 0)}
            subtitle={`${(snapT.ns_ponderado || 0).toFixed(2)}% efectividad${ambulanciasTotal > 0 ? ` · incl. ${ambulanciasTotal} amb.` : ""}`}
            sparkSerie={serie(histPeriodo, "entregados")}
            sparkPrev={serie(histPrev, "entregados")}
            sparkAllVals={serie(historico, "entregados")}
            delta={computeDelta("entregados")}
            deltaLabel={labelPeriodo}
            deltaUnit=""
            ranking={buildRank("entregados", fmtNum)}
          />
        </div>

        {/* ③ FOCO OPERATIVO */}
        <GrupoTitulo icon="alert" titulo="Foco operativo" />
        <div style={{ display: "grid", gridTemplateColumns: "repeat(4, minmax(0, 1fr))", gap: 10, marginBottom: 28 }}>
          <CardFoco
            S={S}
            label="Devueltos"
            tipo={cumpleDev(pctDev) ? "ok" : "bad"}
            badgeTxt={cumpleDev(pctDev) ? "Cumple" : "No cumple"}
            valor={devueltosTotal}
            subtitle={`${pctDev.toFixed(2)}% · meta <2%`}
            sparkSerie={serie(histPeriodo, "devueltos")}
            sparkPrev={serie(histPrev, "devueltos")}
            sparkAllVals={serie(historico, "devueltos")}
            delta={computeDelta("devueltos")}
            deltaLabel={labelPeriodo}
            deltaUnit=""
            lower={true}
            ranking={buildRank("devueltos", fmtInt, true)}
          />
          <CardFoco
            S={S}
            label="PNR del día"
            tipo={pnrStats.aCobro > 0 ? "bad" : pnrStats.abiertos > 0 ? "warn" : "ok"}
            badgeTxt={
              pnrStats.aCobro > 0 ? `${pnrStats.aCobro} a cobro` :
              pnrStats.abiertos > 0 ? `${pnrStats.abiertos} abiertos` : "Sin PNR"
            }
            valor={pnrStats.casosHoy}
            subtitle={`${pnrStats.total} acumulados · $${Math.round(pnrStats.valorTotal).toLocaleString("es-MX")} en riesgo`}
            sparkSerie={pnrStats.sparkSerie.slice(-periodo)}
            sparkPrev={pnrStats.sparkSerie.slice(Math.max(0, 30 - periodo * 2), 30 - periodo)}
            sparkAllVals={pnrStats.sparkSerie}
            delta={(() => {
              const s = pnrStats.sparkSerie;
              if (s.length < periodo * 2) return null;
              const avg = a => a.reduce((x, v) => x + v, 0) / a.length;
              return avg(s.slice(-periodo)) - avg(s.slice(-periodo * 2, -periodo));
            })()}
            deltaLabel={labelPeriodo}
            deltaUnit=""
            lower={true}
            ranking={(() => {
              if (pnrStats.porSC.length === 0) return { top3: "—", bot3: "—" };
              // Filtramos SIN_SC para el ranking
              const conSC = pnrStats.porSC.filter(s => s.sc !== "SIN_SC");
              if (conSC.length === 0) return { top3: "—", bot3: "—" };
              // ▲ menos casos (mejor) · ▼ más casos (peor)
              const asc = [...conSC].sort((a, b) => a.total - b.total);
              const top3 = asc.slice(0, 3).map(s => `${s.sc} ${s.total}`).join(" · ");
              const bot3 = [...asc].reverse().slice(0, 3).map(s => `${s.sc} ${s.total}`).join(" · ");
              return { top3, bot3 };
            })()}
          />
          <CardFoco
            S={S}
            label="Ambulancias"
            tipo={ambulanciasTotal === 0 ? "ok" : "warn"}
            badgeTxt={ambulanciasTotal === 0 ? "Sin amb." : `${ambulanciasTotal} amb.`}
            valor={ambulanciasTotal}
            subtitle="Rutas con refuerzo"
            sparkSerie={serie(histPeriodo, "ambulancias")}
            sparkPrev={serie(histPrev, "ambulancias")}
            sparkAllVals={serie(historico, "ambulancias")}
            delta={computeDelta("ambulancias")}
            deltaLabel={labelPeriodo}
            deltaUnit=""
            lower={true}
            ranking={buildRank("ambulancias", x => Number(x) === 0 ? "0 ✓" : `${x}`, true)}
          />
          <CardFoco
            S={S}
            label="No visitados"
            tipo={cumpleNoVis(pctNoVis) ? "ok" : "bad"}
            badgeTxt={cumpleNoVis(pctNoVis) ? "Cumple" : "No cumple"}
            valor={`${pctNoVis.toFixed(2)}%`}
            subtitle={`${noVisitadosTotal} paquete(s) · meta ≤0.5%`}
            sparkSerie={serie(histPeriodo, "no_visitados")}
            sparkPrev={serie(histPrev, "no_visitados")}
            sparkAllVals={serie(historico, "no_visitados")}
            delta={computeDelta("no_visitados")}
            deltaLabel={labelPeriodo}
            deltaUnit=""
            lower={true}
            ranking={buildRank("no_visitados", fmtInt, true)}
          />
        </div>

        {/* ③.b DETALLE PNR — Solo si hay casos */}
        {pnrStats.total > 0 && (
          <>
            <GrupoTitulo icon="clipboard" titulo="Detalle PNR por estado y SC" />

            {/* Resumen general 4 cards */}
            <div style={{ display: "grid", gridTemplateColumns: "repeat(4, minmax(0, 1fr))", gap: 10, marginBottom: 10 }}>
              <CardWrap S={S} tipo={null}>
                <CardHeader label="Total PNR" S={S} />
                <div style={{ fontSize: 24, fontWeight: 700, color: "#111827", letterSpacing: -0.5, lineHeight: 1, marginBottom: 3 }}>
                  {pnrStats.total}
                </div>
                <div style={{ fontSize: 11, color: "#9CA3AF" }}>
                  ${Math.round(pnrStats.valorTotal).toLocaleString("es-MX")} en riesgo
                </div>
              </CardWrap>

              <CardWrap S={S} tipo="warn">
                <CardHeader label="Abiertos" tipo="warn" badgeTxt="en gestión" S={S} />
                <div style={{ fontSize: 24, fontWeight: 700, color: "#111827", letterSpacing: -0.5, lineHeight: 1, marginBottom: 3 }}>
                  {pnrStats.abiertos}
                </div>
                <div style={{ fontSize: 11, color: "#9CA3AF" }}>
                  ${Math.round(pnrStats.valorAbiertos).toLocaleString("es-MX")}
                </div>
              </CardWrap>

              <CardWrap S={S} tipo={pnrStats.aCobro > 0 ? "bad" : "ok"}>
                <CardHeader label="A cobro" tipo={pnrStats.aCobro > 0 ? "bad" : "ok"} badgeTxt={pnrStats.aCobro > 0 ? "Con penalidad" : "Sin penalidad"} S={S} />
                <div style={{ fontSize: 24, fontWeight: 700, color: pnrStats.aCobro > 0 ? "#c0392b" : "#111827", letterSpacing: -0.5, lineHeight: 1, marginBottom: 3 }}>
                  {pnrStats.aCobro}
                </div>
                <div style={{ fontSize: 11, color: "#9CA3AF" }}>
                  ${Math.round(pnrStats.valorACobro).toLocaleString("es-MX")} a pagar
                </div>
              </CardWrap>

              <CardWrap S={S} tipo="ok">
                <CardHeader label="Cerrados" tipo="ok" badgeTxt="Anulado" S={S} />
                <div style={{ fontSize: 24, fontWeight: 700, color: "#111827", letterSpacing: -0.5, lineHeight: 1, marginBottom: 3 }}>
                  {pnrStats.cerrados}
                </div>
                <div style={{ fontSize: 11, color: "#9CA3AF" }}>
                  archivados
                </div>
              </CardWrap>
            </div>

            {/* Desglose de estados (todos los 6) */}
            <div style={{ background: "#fff", border: `0.5px solid ${S.BORDER}`, borderRadius: 12, padding: 14, marginBottom: 10 }}>
              <div style={{ fontSize: 11, fontWeight: 600, color: "#6B7280", textTransform: "uppercase", letterSpacing: 0.4, marginBottom: 12 }}>
                Desglose por estado
              </div>
              <div style={{ display: "grid", gridTemplateColumns: "repeat(6, minmax(0, 1fr))", gap: 8 }}>
                {[
                  { k: "Esperando comprobante", color: "#92400e", bg: "#fef3c7" },
                  { k: "Comprobante cargado", color: "#1e40af", bg: "#dbeafe" },
                  { k: "Pendiente de revision", color: "#6b21a8", bg: "#f3e8ff" },
                  { k: "Sin comprobante cargado", color: "#c0392b", bg: "#fee2e2" },
                  { k: "Con penalidad", color: "#991b1b", bg: "#fee2e2" },
                  { k: "Anulado", color: "#475569", bg: "#f1f5f9" },
                ].map(({ k, color, bg }) => (
                  <div key={k} style={{ padding: "10px 12px", background: bg, borderRadius: 8 }}>
                    <div style={{ fontSize: 10, fontWeight: 600, color, textTransform: "uppercase", letterSpacing: 0.3, marginBottom: 4, lineHeight: 1.2, minHeight: 24 }}>
                      {k}
                    </div>
                    <div style={{ fontSize: 22, fontWeight: 700, color, lineHeight: 1 }}>
                      {pnrStats.desglose[k] || 0}
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* Tabla detallada por SC */}
            <div style={{ background: "#fff", border: `0.5px solid ${S.BORDER}`, borderRadius: 12, padding: 14, marginBottom: 28, overflow: "auto" }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: 12 }}>
                <div style={{ fontSize: 11, fontWeight: 600, color: "#6B7280", textTransform: "uppercase", letterSpacing: 0.4 }}>
                  Detalle por SC
                </div>
                <div style={{ fontSize: 10, color: "#9CA3AF" }}>
                  {pnrStats.porSC.length} SC con casos
                  {pnrStats.porSC.some(s => s.sc === "SIN_SC") && (
                    <span style={{ color: "#F47B20", marginLeft: 8 }}>
                      · {pnrStats.porSC.find(s => s.sc === "SIN_SC")?.total || 0} casos sin mapeo de ruta
                    </span>
                  )}
                </div>
              </div>
              <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12, fontFamily: "'Geist', sans-serif" }}>
                <thead>
                  <tr style={{ borderBottom: `1px solid ${S.BORDER}`, textAlign: "left" }}>
                    <th style={{ padding: "8px 10px", fontSize: 10, color: "#6B7280", textTransform: "uppercase", letterSpacing: 0.4, fontWeight: 600 }}>SC</th>
                    <th style={{ padding: "8px 10px", fontSize: 10, color: "#6B7280", textTransform: "uppercase", letterSpacing: 0.4, fontWeight: 600, textAlign: "right" }}>Total</th>
                    <th style={{ padding: "8px 10px", fontSize: 10, color: "#92400e", textTransform: "uppercase", letterSpacing: 0.4, fontWeight: 600, textAlign: "right" }}>Esperando</th>
                    <th style={{ padding: "8px 10px", fontSize: 10, color: "#1e40af", textTransform: "uppercase", letterSpacing: 0.4, fontWeight: 600, textAlign: "right" }}>Cargado</th>
                    <th style={{ padding: "8px 10px", fontSize: 10, color: "#6b21a8", textTransform: "uppercase", letterSpacing: 0.4, fontWeight: 600, textAlign: "right" }}>Pendiente</th>
                    <th style={{ padding: "8px 10px", fontSize: 10, color: "#c0392b", textTransform: "uppercase", letterSpacing: 0.4, fontWeight: 600, textAlign: "right" }}>Sin comp.</th>
                    <th style={{ padding: "8px 10px", fontSize: 10, color: "#991b1b", textTransform: "uppercase", letterSpacing: 0.4, fontWeight: 600, textAlign: "right" }}>A cobro</th>
                    <th style={{ padding: "8px 10px", fontSize: 10, color: "#475569", textTransform: "uppercase", letterSpacing: 0.4, fontWeight: 600, textAlign: "right" }}>Anulado</th>
                    <th style={{ padding: "8px 10px", fontSize: 10, color: "#6B7280", textTransform: "uppercase", letterSpacing: 0.4, fontWeight: 600, textAlign: "right" }}>$ Riesgo</th>
                  </tr>
                </thead>
                <tbody>
                  {pnrStats.porSC.map((s, i) => (
                    <tr key={s.sc} style={{ borderBottom: i === pnrStats.porSC.length - 1 ? "none" : `1px solid ${S.BORDER}` }}>
                      <td style={{ padding: "8px 10px", fontWeight: 700, color: s.sc === "SIN_SC" ? "#F47B20" : "#1a3a6b" }}>
                        {s.sc === "SIN_SC" ? "— Sin mapeo" : s.sc}
                      </td>
                      <td style={{ padding: "8px 10px", textAlign: "right", fontWeight: 700, color: "#111827", fontVariantNumeric: "tabular-nums" }}>{s.total}</td>
                      <td style={{ padding: "8px 10px", textAlign: "right", color: s.esperando > 0 ? "#92400e" : "#cbd5e1", fontVariantNumeric: "tabular-nums" }}>{s.esperando || "—"}</td>
                      <td style={{ padding: "8px 10px", textAlign: "right", color: s.cargado > 0 ? "#1e40af" : "#cbd5e1", fontVariantNumeric: "tabular-nums" }}>{s.cargado || "—"}</td>
                      <td style={{ padding: "8px 10px", textAlign: "right", color: s.pendiente > 0 ? "#6b21a8" : "#cbd5e1", fontVariantNumeric: "tabular-nums" }}>{s.pendiente || "—"}</td>
                      <td style={{ padding: "8px 10px", textAlign: "right", color: s.sinComprobante > 0 ? "#c0392b" : "#cbd5e1", fontVariantNumeric: "tabular-nums" }}>{s.sinComprobante || "—"}</td>
                      <td style={{ padding: "8px 10px", textAlign: "right", color: s.aCobro > 0 ? "#991b1b" : "#cbd5e1", fontWeight: s.aCobro > 0 ? 700 : 400, fontVariantNumeric: "tabular-nums" }}>{s.aCobro || "—"}</td>
                      <td style={{ padding: "8px 10px", textAlign: "right", color: s.cerrados > 0 ? "#475569" : "#cbd5e1", fontVariantNumeric: "tabular-nums" }}>{s.cerrados || "—"}</td>
                      <td style={{ padding: "8px 10px", textAlign: "right", color: "#1a3a6b", fontWeight: 600, fontVariantNumeric: "tabular-nums" }}>
                        ${Math.round(s.valor).toLocaleString("es-MX")}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </>
        )}

        {/* ④ SERVICIOS OFERTADOS */}
        {compromiso && (
          <>
            <GrupoTitulo icon="award" titulo="Servicios ofertados · semana en curso" />
            <div style={{ display: "grid", gridTemplateColumns: "repeat(3, minmax(0, 1fr))", gap: 10, marginBottom: 28 }}>
              <CardCompromiso
                S={S}
                label="Confirmados · Mié lock"
                tipo={pctConfirmadosTotal >= 95 ? "ok" : pctConfirmadosTotal >= 80 ? "warn" : "bad"}
                badgeTxt={pctConfirmadosTotal != null ? `${pctConfirmadosTotal.toFixed(0)}%` : "—"}
                valor={aceptadasTotal}
                subtitle={`de ${efectivasTotal} efectivos · ${ofrecidasTotal} ofertados`}
                footer={`efectivos = ofertados − canc. MELI (${canceladasTotal})`}
              />
              <CardCompromiso
                S={S}
                label="SDD · Súper dedicadas"
                tipo={pctSDD === 100 ? "ok" : pctSDD >= 95 ? "warn" : "bad"}
                badgeTxt={pctSDD != null ? `${pctSDD.toFixed(0)}%` : "—"}
                valor={`${c.aceptadas_sdd || 0}/${(c.ofrecidas_sdd || 0) - (c.canceladas_sdd || 0)}`}
                subtitle="Flota fija · deadline Mié"
                footer="Compromiso irrenunciable"
                footerIcon="lock"
              />
              <CardCompromiso
                S={S}
                label="SPOT · Variables"
                tipo={pctSPOT >= 90 ? "ok" : pctSPOT >= 70 ? "warn" : "bad"}
                badgeTxt={pctSPOT != null ? `${pctSPOT.toFixed(1)}%` : "—"}
                valor={`${c.aceptadas_spot || 0}/${(c.ofrecidas_spot || 0) - (c.canceladas_spot || 0)}`}
                subtitle={`${c.rechazadas_spot || 0} rechazados · ${c.canceladas_spot || 0} canc. MELI`}
                footer="Ver análisis de compromiso"
              />
            </div>
          </>
        )}

        <div style={{ textAlign: "center", fontSize: 10, color: S.TEXT_MUTED, padding: "12px 0 24px" }}>
          Bigticket · KPI de Operación · Pool MELI MX · {fechaTexto}
        </div>
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
// SUBCOMPONENTES
// ═══════════════════════════════════════════════════════════════════════════

function GrupoTitulo({ icon, titulo }) {
  const icons = {
    trend: <path d="M3 17 L8 12 L13 15 L18 9 L21 12 M3 3 L3 21 M3 21 L21 21" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" fill="none" stroke="#6B7280" />,
    box:   <g fill="none" stroke="#6B7280" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 3l8 4.5v9L12 21l-8-4.5v-9z"/><line x1="12" y1="12" x2="12" y2="21"/><polyline points="4 7.5 12 12 20 7.5"/></g>,
    alert: <g fill="none" stroke="#6B7280" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></g>,
    award: <g fill="none" stroke="#6B7280" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"/></g>,
    clipboard: <g fill="none" stroke="#6B7280" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M9 5H7a2 2 0 0 0-2 2v12a2 2 0 0 0 2 2h10a2 2 0 0 0 2-2V7a2 2 0 0 0-2-2h-2"/><rect x="9" y="3" width="6" height="4" rx="1"/><line x1="9" y1="12" x2="15" y2="12"/><line x1="9" y1="16" x2="13" y2="16"/></g>,
  };
  return (
    <div style={{
      display: "flex", alignItems: "center", gap: 10,
      fontSize: 14, fontWeight: 600, color: "#6B7280",
      textTransform: "uppercase", letterSpacing: 0.6, marginBottom: 12,
    }}>
      <svg width="14" height="14" viewBox="0 0 24 24">{icons[icon]}</svg>
      <span>{titulo}</span>
      <span style={{ flex: 1, height: 0.5, background: "#e4e7ec" }}></span>
    </div>
  );
}

// ─── CARD GENÉRICA (estructura visual común) ──────────────────────────────
function CardWrap({ S, tipo, children, height }) {
  const borderColors = { bad: "#c0392b", warn: "#F47B20", ok: "#16a34a" };
  const bc = tipo ? borderColors[tipo] : null;
  return (
    <div style={{
      background: "#fff",
      border: `0.5px solid ${S.BORDER}`,
      borderRadius: bc ? "0 12px 12px 0" : 12,
      borderLeft: bc ? `3px solid ${bc}` : `0.5px solid ${S.BORDER}`,
      padding: 14, display: "flex", flexDirection: "column",
      minHeight: height || "auto",
    }}>{children}</div>
  );
}

function CardHeader({ label, tipo, badgeTxt, S }) {
  const styles = {
    ok:   { bg: "#dcfce7", color: "#166534" },
    warn: { bg: "#fef3c7", color: "#92400e" },
    bad:  { bg: "#fee2e2", color: "#991b1b" },
  };
  const st = badgeTxt && tipo ? styles[tipo] : null;
  return (
    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 5 }}>
      <span style={{ fontSize: 10, fontWeight: 600, color: "#6B7280", textTransform: "uppercase", letterSpacing: 0.4 }}>
        {label}
      </span>
      {st && (
        <span style={{
          fontSize: 9, fontWeight: 600, padding: "2px 7px", borderRadius: 4,
          textTransform: "uppercase", whiteSpace: "nowrap",
          background: st.bg, color: st.color,
        }}>{badgeTxt}</span>
      )}
    </div>
  );
}

// ─── ZOOM BAR (barra de meta) ─────────────────────────────────────────────
function ZoomBar({ valor, meta, zmMin, zmMax, lower = false, S }) {
  if (valor == null || meta == null) return null;
  const v = Number(valor);
  const range = zmMax - zmMin;
  const valPct = Math.max(0, Math.min(100, ((v - zmMin) / range) * 100));
  const metaPct = Math.max(0, Math.min(100, ((meta - zmMin) / range) * 100));
  const deltaPp = v - meta;
  const cumple = lower ? v <= meta : v >= meta;
  return (
    <div style={{ marginBottom: 4 }}>
      <div style={{ position: "relative", height: 16, marginBottom: 2 }}>
        <span style={{
          position: "absolute", left: `${metaPct}%`, transform: "translateX(-50%)",
          fontSize: 9, color: "#374151", fontWeight: 600, whiteSpace: "nowrap",
          background: "#fff", padding: "0 2px", lineHeight: 1,
        }}>meta {meta}%</span>
      </div>
      <div style={{ position: "relative", height: 6, marginBottom: 4 }}>
        <div style={{ position: "absolute", inset: 0, background: "#F3F4F6", borderRadius: 3 }}></div>
        <div style={{ position: "absolute", left: 0, top: 0, height: "100%", width: `${valPct}%`, background: "#9CA3AF", borderRadius: 3 }}></div>
        <div style={{ position: "absolute", left: `${metaPct}%`, top: -5, width: 2, height: 16, background: "#111827", borderRadius: 1, zIndex: 2 }}></div>
        <div style={{
          position: "absolute", left: `${valPct}%`, top: "50%",
          width: 10, height: 10, borderRadius: "50%", background: "#374151",
          border: "2px solid #fff", transform: "translateX(-50%) translateY(-50%)",
          zIndex: 3, boxShadow: "0 0 0 1px #D1D5DB",
        }}></div>
      </div>
      <div style={{ display: "flex", justifyContent: "space-between", fontSize: 9, color: "#9CA3AF" }}>
        <span>{zmMin}%</span><span>{zmMax}%</span>
      </div>
      <div style={{ fontSize: 11, fontWeight: 500, color: "#6B7280", marginTop: 4 }}>
        {Math.abs(deltaPp).toFixed(2)} pp {cumple ? "sobre" : "para alcanzar"} la meta
      </div>
    </div>
  );
}

// ─── SPARKLINE SVG (Catmull-Rom) ──────────────────────────────────────────
function Sparkline({ vals, allVals, meta, prevVals, height = 52, color = "#9CA3AF", secondaryVals = null }) {
  // Si no hay suficientes datos, mostrar área vacía con leyenda sutil
  if (!vals || vals.length < 3) {
    return (
      <svg width="100%" height={height} viewBox={`0 0 400 ${height}`} preserveAspectRatio="none" style={{ overflow: "visible" }}>
        <text x="200" y={height / 2 + 4} textAnchor="middle" fontSize="9" fill="#cbd5e1" fontFamily="'Geist', sans-serif">
          {(vals?.length || 0) === 0 ? "sin histórico" : "datos insuficientes"}
        </text>
      </svg>
    );
  }

  const W = 400, H = height, pad = 4;
  const ref = [...(allVals && allVals.length ? allVals : vals)];
  if (meta != null) ref.push(meta);
  if (prevVals?.length) ref.push(...prevVals);
  if (secondaryVals?.length) ref.push(...secondaryVals);
  const dMin = Math.min(...ref), dMax = Math.max(...ref);
  const padY = Math.max((dMax - dMin) * 0.10, 0.15);
  const yMin = dMin - padY, yMax = dMax + padY;
  const py = v => H - pad - ((v - yMin) / (yMax - yMin)) * (H - pad * 2);

  function buildPath(data) {
    const smF = Math.min(data.length / 30, 0.5);
    const sm = data.map((v, i, a) => {
      const p = a[i - 1] ?? v, n2 = a[i + 1] ?? v;
      return v + ((p + n2) / 2 - v) * smF;
    });
    const xs = sm.map((_, i) => pad + (i / (sm.length - 1)) * (W - pad * 2));
    const ys = sm.map(v => py(v));
    const N = xs.length, t = 0.45;
    let d = `M${xs[0].toFixed(1)},${ys[0].toFixed(1)}`;
    for (let i = 0; i < N - 1; i++) {
      const x0 = xs[i > 0 ? i - 1 : 0], y0 = ys[i > 0 ? i - 1 : 0];
      const x1 = xs[i], y1 = ys[i], x2 = xs[i + 1], y2 = ys[i + 1];
      const x3 = xs[i < N - 2 ? i + 2 : N - 1], y3 = ys[i < N - 2 ? i + 2 : N - 1];
      const cp1x = x1 + (x2 - x0) * t / 3, cp1y = y1 + (y2 - y0) * t / 3;
      const cp2x = x2 - (x3 - x1) * t / 3, cp2y = y2 - (y3 - y1) * t / 3;
      d += ` C${cp1x.toFixed(1)},${cp1y.toFixed(1)} ${cp2x.toFixed(1)},${cp2y.toFixed(1)} ${x2.toFixed(1)},${y2.toFixed(1)}`;
    }
    return { d, lx: xs[N - 1].toFixed(1), ly: ys[N - 1].toFixed(1), x0: xs[0].toFixed(1) };
  }

  return (
    <svg width="100%" height={H} viewBox={`0 0 ${W} ${H}`} preserveAspectRatio="none">
      {meta != null && (
        <line x1={pad} y1={py(meta).toFixed(1)} x2={W - pad} y2={py(meta).toFixed(1)}
              stroke="#E5E7EB" strokeWidth="1" strokeDasharray="5,4" />
      )}
      {prevVals?.length >= 3 && (() => {
        const { d } = buildPath(prevVals);
        return <path d={d} fill="none" stroke="#D1D5DB" strokeWidth="1.5" strokeDasharray="4,3" strokeLinejoin="round" strokeLinecap="round" />;
      })()}
      {secondaryVals?.length >= 3 && (() => {
        const { d } = buildPath(secondaryVals);
        return <path d={d} fill="none" stroke="#1a3a6b" strokeWidth="1.3" strokeDasharray="2,3" strokeLinejoin="round" strokeLinecap="round" opacity="0.55" />;
      })()}
      {(() => {
        const { d, lx, ly, x0 } = buildPath(vals);
        return (
          <>
            <path d={`${d} L${lx},${H} L${x0},${H} Z`} fill={color} fillOpacity="0.1" />
            <path d={d} fill="none" stroke={color} strokeWidth="2" strokeLinejoin="round" strokeLinecap="round" />
            <circle cx={lx} cy={ly} r="3.5" fill="#6B7280" />
          </>
        );
      })()}
    </svg>
  );
}

// ─── DELTA TEXT ───────────────────────────────────────────────────────────
function DeltaText({ delta, lower, label, unit }) {
  if (delta == null) return <div style={{ fontSize: 11, color: "#9CA3AF", marginTop: 4, minHeight: 16 }}></div>;
  const better = lower ? delta < 0 : delta > 0;
  const worse = lower ? delta > 0 : delta < 0;
  const arrow = better ? "↑" : worse ? "↓" : "→";
  const sign = delta > 0 ? "+" : "";
  const val = `${sign}${delta.toFixed(2)}${unit ? " " + unit : ""}`;
  const color = better ? "#16a34a" : worse ? "#c0392b" : "#9CA3AF";
  return (
    <div style={{ fontSize: 11, color, marginTop: 4, minHeight: 16 }}>
      {arrow} {val} vs {label}
    </div>
  );
}

// ─── RANKING ▲▼ ───────────────────────────────────────────────────────────
function RankingBlock({ top3, bot3 }) {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 5, marginTop: "auto" }}>
      <div style={{ display: "grid", gridTemplateColumns: "14px 1fr", gap: 5, alignItems: "start" }}>
        <span style={{ color: "#16a34a", fontSize: 11, fontWeight: 600, paddingTop: 1 }}>▲</span>
        <span style={{ fontSize: 11, color: "#9CA3AF", lineHeight: 1.5 }}>{top3}</span>
      </div>
      <div style={{ display: "grid", gridTemplateColumns: "14px 1fr", gap: 5, alignItems: "start" }}>
        <span style={{ color: "#c0392b", fontSize: 11, fontWeight: 600, paddingTop: 1 }}>▼</span>
        <span style={{ fontSize: 11, color: "#9CA3AF", lineHeight: 1.5 }}>{bot3}</span>
      </div>
    </div>
  );
}

// ─── DIVISOR ──────────────────────────────────────────────────────────────
const Div = () => <div style={{ height: 0.5, background: "#F0F0F0", margin: "8px 0" }}></div>;

// ─── CARD NS (dos valores apilados: MELI + SNAPSHOTS) ─────────────────────
function CardNS({ S, label, tipo, badgeTxt, valorMeli, valorSnap, subtitle, meta,
                  sparkSerieMeli, sparkSerieSnap, sparkPrev, sparkAllVals,
                  delta, deltaLabel, deltaUnit, lower, ranking, zmMin, zmMax }) {
  const fmt = v => v != null ? `${Number(v).toFixed(2)}%` : "—";
  return (
    <CardWrap S={S} tipo={tipo}>
      <CardHeader label={label} tipo={tipo} badgeTxt={badgeTxt} S={S} />
      {/* Dos valores apilados */}
      <div style={{ marginBottom: 3 }}>
        <div style={{ display: "flex", alignItems: "baseline", gap: 6 }}>
          <span style={{ fontSize: 9, fontWeight: 700, color: "#92400e", textTransform: "uppercase", letterSpacing: 0.4 }}>📄 MELI</span>
          <span style={{ fontSize: 22, fontWeight: 700, color: "#111827", letterSpacing: -0.5, lineHeight: 1 }}>{fmt(valorMeli)}</span>
        </div>
        <div style={{ display: "flex", alignItems: "baseline", gap: 6, marginTop: 4 }}>
          <span style={{ fontSize: 9, fontWeight: 700, color: "#047857", textTransform: "uppercase", letterSpacing: 0.4 }}>📸 SNAP</span>
          <span style={{ fontSize: 16, fontWeight: 700, color: "#475569", letterSpacing: -0.3, lineHeight: 1 }}>{fmt(valorSnap)}</span>
        </div>
      </div>
      <div style={{ fontSize: 11, color: "#9CA3AF", marginBottom: 10, marginTop: 4 }}>{subtitle}</div>
      <ZoomBar valor={valorMeli} meta={meta} zmMin={zmMin} zmMax={zmMax} lower={lower} S={S} />
      <Sparkline
        vals={sparkSerieMeli}
        secondaryVals={sparkSerieSnap}
        allVals={sparkAllVals}
        meta={meta}
        prevVals={sparkPrev}
        height={72}
      />
      <DeltaText delta={delta} lower={lower} label={deltaLabel} unit={deltaUnit} />
      <Div />
      <RankingBlock {...ranking} />
    </CardWrap>
  );
}

// ─── CARD SINGLE (un solo valor + zoom bar opcional) ──────────────────────
function CardSingle({ S, label, tipo, badgeTxt, valor, valorFmt, subtitle, meta,
                      sparkSerie, sparkPrev, sparkAllVals,
                      delta, deltaLabel, deltaUnit, lower, ranking, zmMin, zmMax, zoom }) {
  return (
    <CardWrap S={S} tipo={tipo}>
      <CardHeader label={label} tipo={tipo} badgeTxt={badgeTxt} S={S} />
      <div style={{ fontSize: 24, fontWeight: 700, color: "#111827", letterSpacing: -0.5, lineHeight: 1, marginBottom: 3 }}>
        {valorFmt ? valorFmt(valor) : valor}
      </div>
      <div style={{ fontSize: 11, color: "#9CA3AF", marginBottom: 10 }}>{subtitle}</div>
      {zoom && <ZoomBar valor={valor} meta={meta} zmMin={zmMin} zmMax={zmMax} lower={lower} S={S} />}
      <Sparkline vals={sparkSerie} allVals={sparkAllVals} meta={meta} prevVals={sparkPrev} height={72} />
      <DeltaText delta={delta} lower={lower} label={deltaLabel} unit={deltaUnit} />
      <Div />
      <RankingBlock {...ranking} />
    </CardWrap>
  );
}

// ─── CARD VOLUMEN (sin borde lateral, sparkline 52px) ─────────────────────
function CardVolumen({ S, label, valor, subtitle, sparkSerie, sparkPrev, sparkAllVals,
                       delta, deltaLabel, deltaUnit, ranking }) {
  return (
    <CardWrap S={S} tipo={null}>
      <CardHeader label={label} S={S} />
      <div style={{ fontSize: 24, fontWeight: 700, color: "#111827", letterSpacing: -0.5, lineHeight: 1, marginBottom: 3 }}>{valor}</div>
      <div style={{ fontSize: 11, color: "#9CA3AF", marginBottom: 10 }}>{subtitle}</div>
      <Sparkline vals={sparkSerie} allVals={sparkAllVals} prevVals={sparkPrev} height={52} />
      <DeltaText delta={delta} lower={false} label={deltaLabel} unit={deltaUnit} />
      <Div />
      <RankingBlock {...ranking} />
    </CardWrap>
  );
}

// ─── CARD FOCO OPERATIVO (badge + sparkline lower=true) ───────────────────
function CardFoco({ S, label, tipo, badgeTxt, valor, subtitle, sparkSerie, sparkPrev, sparkAllVals,
                    delta, deltaLabel, deltaUnit, lower, ranking }) {
  return (
    <CardWrap S={S} tipo={tipo}>
      <CardHeader label={label} tipo={tipo} badgeTxt={badgeTxt} S={S} />
      <div style={{ fontSize: 24, fontWeight: 700, color: "#111827", letterSpacing: -0.5, lineHeight: 1, marginBottom: 3 }}>{valor}</div>
      <div style={{ fontSize: 11, color: "#9CA3AF", marginBottom: 10 }}>{subtitle}</div>
      <Sparkline vals={sparkSerie} allVals={sparkAllVals} prevVals={sparkPrev} height={52} />
      <DeltaText delta={delta} lower={lower} label={deltaLabel} unit={deltaUnit} />
      <Div />
      <RankingBlock {...ranking} />
    </CardWrap>
  );
}

// ─── CARD COMPROMISO (sin sparkline ni ranking, footer pequeño) ───────────
function CardCompromiso({ S, label, tipo, badgeTxt, valor, subtitle, footer, footerIcon }) {
  return (
    <CardWrap S={S} tipo={tipo}>
      <CardHeader label={label} tipo={tipo} badgeTxt={badgeTxt} S={S} />
      <div style={{ fontSize: 24, fontWeight: 700, color: "#111827", letterSpacing: -0.5, lineHeight: 1, marginBottom: 3 }}>{valor}</div>
      <div style={{ fontSize: 11, color: "#9CA3AF", marginBottom: 10 }}>{subtitle}</div>
      <Div />
      <div style={{ fontSize: 11, color: "#6B7280", display: "flex", alignItems: "center", gap: 4, marginTop: "auto" }}>
        {footerIcon === "lock" && (
          <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="#16a34a" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
            <rect x="3" y="11" width="18" height="11" rx="2"/><path d="M7 11V7a5 5 0 0 1 10 0v4"/>
          </svg>
        )}
        {footer}
      </div>
    </CardWrap>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
// DIFERENCIAS MAESTROS — Auditoría ruta por ruta MELI vs Snapshots
// ═══════════════════════════════════════════════════════════════════════════
function PoolMeliDiferenciasMaestros() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [refreshKey, setRefreshKey] = useState(0);

  // Calcular ayer en hora local
  const [fechaSel, setFechaSel] = useState(() => {
    const ahora = new Date();
    const ayer = new Date(ahora);
    ayer.setDate(ayer.getDate() - 1);
    return ayer.toISOString().slice(0, 10);
  });

  useEffect(() => {
    let alive = true;
    (async () => {
      setLoading(true);
      setError(null);
      try {
        const { data: result, error: err } = await sb.rpc("get_diferencias_maestros", { p_fecha: fechaSel });
        if (!alive) return;
        if (err) throw err;
        setData(result);
      } catch (e) {
        if (alive) setError(e.message || String(e));
      } finally {
        if (alive) setLoading(false);
      }
    })();
    return () => { alive = false; };
  }, [refreshKey, fechaSel]);

  if (loading) {
    return <div className="pg" style={{ padding: 60, textAlign: "center", color: "#888" }}>Cargando diferencias entre Maestros…</div>;
  }
  if (error) {
    return <div className="pg" style={{ padding: 40, color: "#c0392b" }}>Error: {error}</div>;
  }
  if (!data) {
    return <div className="pg" style={{ padding: 40, color: "#888" }}>Sin datos</div>;
  }

  const resumen = data.resumen || {};
  const porSc = data.por_sc || [];
  const conDif = data.con_diferencias || [];
  const soloSnap = data.solo_snapshot || [];
  const soloMeli = data.solo_meli || [];
  const generadoEn = data.generado_en ? new Date(data.generado_en) : null;

  const totalRutas = resumen.total_rutas || 0;
  const rutasMatch = resumen.rutas_match || 0;
  const rutasConDif = resumen.rutas_con_diferencias || 0;
  const rutasSoloSnap = resumen.rutas_solo_snap || 0;
  const rutasSoloMeli = resumen.rutas_solo_meli || 0;
  const pctMatch = totalRutas > 0 ? (rutasMatch / totalRutas * 100) : 0;

  // Formato fecha
  const meses = ["enero","febrero","marzo","abril","mayo","junio","julio","agosto","septiembre","octubre","noviembre","diciembre"];
  const dias = ["domingo","lunes","martes","miércoles","jueves","viernes","sábado"];
  let fechaTexto = data.fecha;
  if (data.fecha) {
    const [y, m, d] = data.fecha.split("-").map(Number);
    const fechaObj = new Date(y, m - 1, d);
    fechaTexto = `${dias[fechaObj.getDay()]} ${d} de ${meses[m - 1]} de ${y}`;
  }

  const colorPctMatch = pctMatch >= 95 ? "#047857" : pctMatch >= 85 ? "#1A3A6B" : "#b91c1c";

  return (
    <div className="pg">
      {/* Header con selector de fecha y refresh */}
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 16 }}>
        <div>
          <div className="sec-title">Diferencias Maestros</div>
          <div className="sec-sub">
            Auditoría ruta por ruta · {fechaTexto}
            {generadoEn && (
              <span style={{ color: "#94a3b8", marginLeft: 8 }}>
                · generado {generadoEn.toLocaleString("es-MX", { hour: "2-digit", minute: "2-digit", day: "2-digit", month: "2-digit" })}
              </span>
            )}
          </div>
        </div>
        <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
          <input
            type="date"
            value={fechaSel}
            onChange={(e) => setFechaSel(e.target.value)}
            style={{
              padding: "6px 10px", fontSize: 12,
              border: "1px solid #e4e7ec", borderRadius: 6,
              fontFamily: "'Geist', sans-serif", color: "#1a3a6b",
            }}
          />
          <button
            onClick={() => setRefreshKey(k => k + 1)}
            style={{
              padding: "8px 14px", fontSize: 12, fontWeight: 600,
              background: "#fff", color: "#1a3a6b",
              border: "1px solid #e4e7ec", borderRadius: 6,
              cursor: "pointer", fontFamily: "'Geist', sans-serif",
            }}
            title="Recargar datos"
          >
            ↻ Refrescar
          </button>
        </div>
      </div>

      {/* KPIs principales */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(5, 1fr)", gap: 12, marginBottom: 20 }}>
        <div className="form-card" style={{ marginBottom: 0, padding: 16, borderTop: "3px solid #1A3A6B" }}>
          <div style={{ fontSize: 10, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 4 }}>
            Total de Rutas
          </div>
          <div style={{ fontSize: 32, fontWeight: 700, color: "#1A3A6B", lineHeight: 1, marginBottom: 4 }}>
            {totalRutas}
          </div>
          <div style={{ fontSize: 10, color: "#94a3b8" }}>
            Combinadas de ambas fuentes
          </div>
        </div>
        <div className="form-card" style={{ marginBottom: 0, padding: 16, borderTop: `3px solid ${colorPctMatch}` }}>
          <div style={{ fontSize: 10, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 4 }}>
            % Match exacto
          </div>
          <div style={{ fontSize: 32, fontWeight: 700, color: colorPctMatch, lineHeight: 1, marginBottom: 4 }}>
            {pctMatch.toFixed(1)}%
          </div>
          <div style={{ fontSize: 10, color: "#94a3b8" }}>
            {rutasMatch} de {totalRutas} cuadran
          </div>
        </div>
        <div className="form-card" style={{ marginBottom: 0, padding: 16, borderTop: "3px solid #F47B20" }}>
          <div style={{ fontSize: 10, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 4 }}>
            Con diferencias
          </div>
          <div style={{ fontSize: 32, fontWeight: 700, color: "#F47B20", lineHeight: 1, marginBottom: 4 }}>
            {rutasConDif}
          </div>
          <div style={{ fontSize: 10, color: "#94a3b8" }}>
            Mismo ID, números distintos
          </div>
        </div>
        <div className="form-card" style={{ marginBottom: 0, padding: 16, borderTop: "3px solid #b91c1c" }}>
          <div style={{ fontSize: 10, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 4 }}>
            Faltantes en algún lado
          </div>
          <div style={{ fontSize: 32, fontWeight: 700, color: "#b91c1c", lineHeight: 1, marginBottom: 4 }}>
            {rutasSoloSnap + rutasSoloMeli}
          </div>
          <div style={{ fontSize: 10, color: "#94a3b8" }}>
            {rutasSoloSnap} solo Snap · {rutasSoloMeli} solo MELI
          </div>
        </div>
        <div className="form-card" style={{ marginBottom: 0, padding: 16, borderTop: `3px solid ${(resumen.rutas_no_operadas || 0) > 0 ? "#dc2626" : "#94a3b8"}` }}
          title="Rutas con vehículo cargado pero que NO salieron del SC (cierre de bodega, cancelación operativa o similar). Estos paquetes NO son fallos de entrega.">
          <div style={{ fontSize: 10, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 4 }}>
            Rutas no operadas
          </div>
          <div style={{ fontSize: 32, fontWeight: 700, color: (resumen.rutas_no_operadas || 0) > 0 ? "#dc2626" : "#94a3b8", lineHeight: 1, marginBottom: 4 }}>
            {resumen.rutas_no_operadas || 0}
          </div>
          <div style={{ fontSize: 10, color: "#94a3b8" }}>
            {(resumen.paquetes_no_operados || 0) > 0
              ? `${Number(resumen.paquetes_no_operados).toLocaleString()} paquetes no salieron`
              : "Vehículo cargado, sin salir"}
          </div>
        </div>
      </div>

      {/* Comparativa de totales (volumen agregado) */}
      <div className="form-card" style={{ marginBottom: 20 }}>
        <div className="form-title" style={{ marginBottom: 4 }}>Comparativa de volúmenes</div>
        <div style={{ fontSize: 11, color: "#64748b", marginBottom: 14 }}>Totales agregados de ambas fuentes</div>
        <div style={{ overflowX: "auto" }}>
          <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
            <thead>
              <tr style={{ borderBottom: "2px solid #e4e7ec", color: "#64748b", fontWeight: 700 }}>
                <th style={{ padding: "8px 10px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "left" }}>Métrica</th>
                <th style={{ padding: "8px 10px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "right" }}>Maestro MELI</th>
                <th style={{ padding: "8px 10px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "right" }}>Snapshots</th>
                <th style={{ padding: "8px 10px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "right" }}>Diferencia</th>
              </tr>
            </thead>
            <tbody>
              {[
                { label: "Cargados", meli: resumen.total_cargados_meli, snap: resumen.total_cargados_snap },
                { label: "Entregados", meli: resumen.total_entregados_meli, snap: resumen.total_entregados_snap },
                { label: "Devueltos", meli: resumen.total_devueltos_meli, snap: resumen.total_devueltos_snap },
              ].map((row, i) => {
                const dif = (row.snap || 0) - (row.meli || 0);
                const colorDif = dif > 0 ? "#F47B20" : dif < 0 ? "#b91c1c" : "#94a3b8";
                return (
                  <tr key={i} style={{ borderBottom: "1px solid #f1f5f9" }}>
                    <td style={{ padding: "10px", fontWeight: 600, color: "#0f172a" }}>{row.label}</td>
                    <td style={{ padding: "10px", textAlign: "right", color: "#475569", fontVariantNumeric: "tabular-nums" }}>
                      {Number(row.meli || 0).toLocaleString()}
                    </td>
                    <td style={{ padding: "10px", textAlign: "right", color: "#475569", fontVariantNumeric: "tabular-nums" }}>
                      {Number(row.snap || 0).toLocaleString()}
                    </td>
                    <td style={{ padding: "10px", textAlign: "right", color: colorDif, fontWeight: 700, fontVariantNumeric: "tabular-nums" }}>
                      {dif > 0 ? "+" : ""}{Number(dif).toLocaleString()}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {/* Resumen por SC */}
      <div className="form-card" style={{ marginBottom: 20 }}>
        <div className="form-title" style={{ marginBottom: 4 }}>Estado por SC</div>
        <div style={{ fontSize: 11, color: "#64748b", marginBottom: 14 }}>Cuántas rutas matchean, tienen diferencias o están faltantes en cada SC</div>
        <div style={{ overflowX: "auto" }}>
          <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
            <thead>
              <tr style={{ borderBottom: "2px solid #e4e7ec", color: "#64748b", fontWeight: 700 }}>
                <th style={{ padding: "8px 10px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "left" }}>SC</th>
                <th style={{ padding: "8px 10px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "center" }}>Rutas</th>
                <th style={{ padding: "8px 10px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "center" }}>Match</th>
                <th style={{ padding: "8px 10px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "center" }}>Con dif.</th>
                <th style={{ padding: "8px 10px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "center" }}>Solo Snap</th>
                <th style={{ padding: "8px 10px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "center" }}>Solo MELI</th>
                <th style={{ padding: "8px 10px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "right" }}>Σ |dif| cargados</th>
              </tr>
            </thead>
            <tbody>
              {porSc.map((sc, i) => {
                const tieneIssues = (sc.con_dif || 0) + (sc.solo_snap || 0) + (sc.solo_meli || 0) > 0;
                return (
                  <tr key={sc.sc} style={{ borderBottom: "1px solid #f1f5f9", background: i % 2 === 0 ? "#fff" : "#fafbfc" }}>
                    <td style={{ padding: "8px 10px", fontWeight: 700, color: "#0f172a" }}>{sc.sc}</td>
                    <td style={{ padding: "8px 10px", textAlign: "center", color: "#475569", fontVariantNumeric: "tabular-nums" }}>{sc.rutas}</td>
                    <td style={{ padding: "8px 10px", textAlign: "center", color: "#047857", fontWeight: 600, fontVariantNumeric: "tabular-nums" }}>{sc.match}</td>
                    <td style={{ padding: "8px 10px", textAlign: "center", color: (sc.con_dif || 0) > 0 ? "#F47B20" : "#94a3b8", fontWeight: (sc.con_dif || 0) > 0 ? 700 : 400, fontVariantNumeric: "tabular-nums" }}>
                      {sc.con_dif || 0}
                    </td>
                    <td style={{ padding: "8px 10px", textAlign: "center", color: (sc.solo_snap || 0) > 0 ? "#b91c1c" : "#94a3b8", fontWeight: (sc.solo_snap || 0) > 0 ? 700 : 400, fontVariantNumeric: "tabular-nums" }}>
                      {sc.solo_snap || 0}
                    </td>
                    <td style={{ padding: "8px 10px", textAlign: "center", color: (sc.solo_meli || 0) > 0 ? "#b91c1c" : "#94a3b8", fontWeight: (sc.solo_meli || 0) > 0 ? 700 : 400, fontVariantNumeric: "tabular-nums" }}>
                      {sc.solo_meli || 0}
                    </td>
                    <td style={{ padding: "8px 10px", textAlign: "right", color: tieneIssues ? "#F47B20" : "#94a3b8", fontWeight: tieneIssues ? 700 : 400, fontVariantNumeric: "tabular-nums" }}>
                      {sc.total_dif_cargados || 0}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {/* Rutas con diferencias en valores */}
      {conDif.length > 0 && (
        <div className="form-card" style={{ marginBottom: 20 }}>
          <div className="form-title" style={{ marginBottom: 4 }}>Rutas con diferencias en valores</div>
          <div style={{ fontSize: 11, color: "#64748b", marginBottom: 14 }}>
            Mismo ID de ruta en ambas fuentes, pero los números no coinciden. Ordenado por mayor diferencia en cargados.
          </div>
          <div style={{ overflowX: "auto" }}>
            <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 11 }}>
              <thead>
                <tr style={{ borderBottom: "2px solid #e4e7ec", color: "#64748b", fontWeight: 700 }}>
                  <th style={{ padding: "8px 6px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "left" }}>ID Ruta</th>
                  <th style={{ padding: "8px 6px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "left" }}>SC</th>
                  <th style={{ padding: "8px 6px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "left" }}>Driver</th>
                  <th style={{ padding: "8px 6px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "right" }}>Carg. MELI/Snap</th>
                  <th style={{ padding: "8px 6px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "right" }}>Δ Carg.</th>
                  <th style={{ padding: "8px 6px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "right" }}>Entr. MELI/Snap</th>
                  <th style={{ padding: "8px 6px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "right" }}>Δ Entr.</th>
                  <th style={{ padding: "8px 6px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "right" }}>Dev. MELI/Snap</th>
                  <th style={{ padding: "8px 6px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "right" }}>Δ Dev.</th>
                </tr>
              </thead>
              <tbody>
                {conDif.map((r, i) => (
                  <tr key={r.idviaje} style={{ borderBottom: "1px solid #f1f5f9", background: i % 2 === 0 ? "#fff" : "#fafbfc" }}>
                    <td style={{ padding: "8px 6px", fontFamily: "monospace", fontSize: 11, color: "#475569" }}>{r.idviaje}</td>
                    <td style={{ padding: "8px 6px", fontWeight: 700, color: "#0f172a" }}>
                      {r.sc}
                      {r.ruta_no_operada && (
                        <span title="RUTA NO OPERADA: vehículo cargado pero no salió del SC (cierre de bodega / cancelación operativa)"
                          style={{ marginLeft: 6, background: "#fef2f2", color: "#991b1b",
                            padding: "2px 6px", borderRadius: 4, fontSize: 9, fontWeight: 700,
                            border: "1px solid #fca5a5", cursor: "help",
                            display: "inline-block", whiteSpace: "nowrap" }}>
                          🚫 NO OPERADA
                        </span>
                      )}
                    </td>
                    <td style={{ padding: "8px 6px", color: "#475569" }}>{r.driver_name || "—"}</td>
                    <td style={{ padding: "8px 6px", textAlign: "right", color: "#475569", fontVariantNumeric: "tabular-nums" }}>
                      {r.cargados_meli ?? "—"} / {r.cargados_snap ?? "—"}
                    </td>
                    <td style={{ padding: "8px 6px", textAlign: "right", color: "#F47B20", fontWeight: 700, fontVariantNumeric: "tabular-nums" }}>
                      {r.dif_cargados > 0 ? "+" : ""}{r.dif_cargados}
                    </td>
                    <td style={{ padding: "8px 6px", textAlign: "right", color: "#475569", fontVariantNumeric: "tabular-nums" }}>
                      {r.entregados_meli ?? "—"} / {r.entregados_snap ?? "—"}
                    </td>
                    <td style={{ padding: "8px 6px", textAlign: "right", color: r.dif_entregados !== 0 ? "#F47B20" : "#94a3b8", fontWeight: r.dif_entregados !== 0 ? 700 : 400, fontVariantNumeric: "tabular-nums" }}>
                      {r.dif_entregados > 0 ? "+" : ""}{r.dif_entregados}
                    </td>
                    <td style={{ padding: "8px 6px", textAlign: "right", color: "#475569", fontVariantNumeric: "tabular-nums" }}>
                      {r.devueltos_meli ?? "—"} / {r.devueltos_snap ?? "—"}
                    </td>
                    <td style={{ padding: "8px 6px", textAlign: "right", color: r.dif_devueltos !== 0 ? "#F47B20" : "#94a3b8", fontWeight: r.dif_devueltos !== 0 ? 700 : 400, fontVariantNumeric: "tabular-nums" }}>
                      {r.dif_devueltos > 0 ? "+" : ""}{r.dif_devueltos}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Rutas solo en Snapshot (operaron sin estar en MELI) */}
      {soloSnap.length > 0 && (
        <div className="form-card" style={{ marginBottom: 20 }}>
          <div className="form-title" style={{ marginBottom: 4 }}>Rutas solo en Snapshot</div>
          <div style={{ fontSize: 11, color: "#64748b", marginBottom: 14 }}>
            Operaron y cerraron, pero el Maestro MELI no las reporta. Posiblemente rutas reasignadas o creadas en días anteriores.
          </div>
          <div style={{ overflowX: "auto" }}>
            <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 11 }}>
              <thead>
                <tr style={{ borderBottom: "2px solid #e4e7ec", color: "#64748b", fontWeight: 700 }}>
                  <th style={{ padding: "8px 6px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "left" }}>ID Ruta</th>
                  <th style={{ padding: "8px 6px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "left" }}>SC</th>
                  <th style={{ padding: "8px 6px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "left" }}>Driver</th>
                  <th style={{ padding: "8px 6px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "right" }}>Cargados</th>
                  <th style={{ padding: "8px 6px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "right" }}>Entregados</th>
                  <th style={{ padding: "8px 6px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "right" }}>Devueltos</th>
                  <th style={{ padding: "8px 6px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "center" }}>Status</th>
                </tr>
              </thead>
              <tbody>
                {soloSnap.map((r, i) => (
                  <tr key={r.idviaje} style={{ borderBottom: "1px solid #f1f5f9", background: i % 2 === 0 ? "#fff" : "#fafbfc" }}>
                    <td style={{ padding: "8px 6px", fontFamily: "monospace", fontSize: 11, color: "#475569" }}>{r.idviaje}</td>
                    <td style={{ padding: "8px 6px", fontWeight: 700, color: "#0f172a" }}>
                      {r.sc}
                      {r.ruta_no_operada && (
                        <span title="RUTA NO OPERADA: vehículo cargado pero no salió del SC (cierre de bodega / cancelación operativa)"
                          style={{ marginLeft: 6, background: "#fef2f2", color: "#991b1b",
                            padding: "2px 6px", borderRadius: 4, fontSize: 9, fontWeight: 700,
                            border: "1px solid #fca5a5", cursor: "help",
                            display: "inline-block", whiteSpace: "nowrap" }}>
                          🚫 NO OPERADA
                        </span>
                      )}
                    </td>
                    <td style={{ padding: "8px 6px", color: "#475569" }}>{r.driver_name || "—"}</td>
                    <td style={{ padding: "8px 6px", textAlign: "right", color: "#1A3A6B", fontWeight: 700, fontVariantNumeric: "tabular-nums" }}>{r.cargados_snap}</td>
                    <td style={{ padding: "8px 6px", textAlign: "right", color: "#475569", fontVariantNumeric: "tabular-nums" }}>{r.entregados_snap}</td>
                    <td style={{ padding: "8px 6px", textAlign: "right", color: "#475569", fontVariantNumeric: "tabular-nums" }}>{r.devueltos_snap}</td>
                    <td style={{ padding: "8px 6px", textAlign: "center", fontSize: 10, color: "#94a3b8" }}>{r.status_final || "—"}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Rutas solo en MELI (planificadas sin operar) */}
      {soloMeli.length > 0 && (
        <div className="form-card" style={{ marginBottom: 20 }}>
          <div className="form-title" style={{ marginBottom: 4 }}>Rutas solo en Maestro MELI</div>
          <div style={{ fontSize: 11, color: "#64748b", marginBottom: 14 }}>
            MELI las reporta pero los snapshots no las capturaron. Posibles rutas canceladas o que no salieron a operar.
          </div>
          <div style={{ overflowX: "auto" }}>
            <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 11 }}>
              <thead>
                <tr style={{ borderBottom: "2px solid #e4e7ec", color: "#64748b", fontWeight: 700 }}>
                  <th style={{ padding: "8px 6px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "left" }}>ID Ruta</th>
                  <th style={{ padding: "8px 6px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "left" }}>SC</th>
                  <th style={{ padding: "8px 6px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "right" }}>Cargados</th>
                  <th style={{ padding: "8px 6px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "right" }}>Entregados</th>
                  <th style={{ padding: "8px 6px", fontSize: 10, textTransform: "uppercase", letterSpacing: 0.5, textAlign: "right" }}>Devueltos</th>
                </tr>
              </thead>
              <tbody>
                {soloMeli.map((r, i) => (
                  <tr key={r.idviaje} style={{ borderBottom: "1px solid #f1f5f9", background: i % 2 === 0 ? "#fff" : "#fafbfc" }}>
                    <td style={{ padding: "8px 6px", fontFamily: "monospace", fontSize: 11, color: "#475569" }}>{r.idviaje}</td>
                    <td style={{ padding: "8px 6px", fontWeight: 700, color: "#0f172a" }}>
                      {r.sc}
                      {r.ruta_no_operada && (
                        <span title="RUTA NO OPERADA: vehículo cargado pero no salió del SC (cierre de bodega / cancelación operativa)"
                          style={{ marginLeft: 6, background: "#fef2f2", color: "#991b1b",
                            padding: "2px 6px", borderRadius: 4, fontSize: 9, fontWeight: 700,
                            border: "1px solid #fca5a5", cursor: "help",
                            display: "inline-block", whiteSpace: "nowrap" }}>
                          🚫 NO OPERADA
                        </span>
                      )}
                    </td>
                    <td style={{ padding: "8px 6px", textAlign: "right", color: "#1A3A6B", fontWeight: 700, fontVariantNumeric: "tabular-nums" }}>{r.cargados_meli}</td>
                    <td style={{ padding: "8px 6px", textAlign: "right", color: "#475569", fontVariantNumeric: "tabular-nums" }}>{r.entregados_meli}</td>
                    <td style={{ padding: "8px 6px", textAlign: "right", color: "#475569", fontVariantNumeric: "tabular-nums" }}>{r.devueltos_meli}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Nota explicativa */}
      <div style={{ fontSize: 11, color: "#64748b", padding: 12, background: "#f8fafc", borderRadius: 6, border: "1px solid #e4e7ec", marginBottom: 20 }}>
        <strong>📋 Nota:</strong> Esta pestaña audita las diferencias entre el Excel oficial de MELI (descarga del portal) y los snapshots automáticos del scraper. 
        Los Snapshots son la fuente de verdad operativa por su mayor frecuencia de captura. 
        Las diferencias detectadas se documentan aquí para identificar patrones, validar reportes y conciliar números con MELI cuando sea necesario.
        <br /><br />
        <strong>🚫 Rutas no operadas:</strong> rutas con vehículo cargado pero que nunca salieron del SC (cierre de bodega, cancelación operativa, problema mecánico, etc.). 
        MELI las reporta con todos los paquetes como "devueltos", pero NO son fallos de entrega — son paquetes que se quedaron en bodega y se reasignan al día siguiente.
        Estos paquetes NO aparecen en <code>meli_paquetes_fallidos</code> porque MELI no genera eventos individuales con substatus de fallo.
      </div>
    </div>
  );
}

// ── INVENTARIO con calendario diario ───────────────────────────────────────
function PoolMeliInventario({ drivers, vehiculos, resumen, setModal, setDetalle, mesGlobal }) {
  const [tipo, setTipo] = useState("drivers");
  const [filtroCat, setFiltroCat] = useState("activos"); // activos | durmientes | fantasmas | todos
  const [calendarios, setCalendarios] = useState({ drivers: null, vehiculos: null });
  // Mes viene del padre (mesGlobal). Usamos directamente.
  const mesSeleccionado = mesGlobal || (() => {
    const hoy = new Date();
    return { anio: hoy.getFullYear(), mes: hoy.getMonth() + 1 };
  })();
  const r = resumen || {};

  // Cargar calendarios cuando cambia el mes
  useEffect(() => {
    let alive = true;
    (async () => {
      try {
        const fechaInicio = `${mesSeleccionado.anio}-${String(mesSeleccionado.mes).padStart(2, '0')}-01`;
        const fechaFin = `${mesSeleccionado.anio}-${String(mesSeleccionado.mes).padStart(2, '0')}-${diasDelMes(mesSeleccionado.anio, mesSeleccionado.mes)}`;
        
        const [rd, rv] = await Promise.all([
          sb.from("vw_meli_calendario_drivers").select("*").gte("fecha", fechaInicio).lte("fecha", fechaFin),
          sb.from("vw_meli_calendario_vehiculos").select("*").gte("fecha", fechaInicio).lte("fecha", fechaFin),
        ]);
        if (!alive) return;
        
        // Agrupar por driver/placa
        const calDrivers = {};
        (rd.data || []).forEach(row => {
          if (!calDrivers[row.nombre]) calDrivers[row.nombre] = new Set();
          calDrivers[row.nombre].add(row.dia);
        });
        
        const calVehiculos = {};
        (rv.data || []).forEach(row => {
          if (!calVehiculos[row.placa]) calVehiculos[row.placa] = new Set();
          calVehiculos[row.placa].add(row.dia);
        });
        
        setCalendarios({ drivers: calDrivers, vehiculos: calVehiculos });
      } catch (e) {
        console.error("Error calendarios:", e);
      }
    })();
    return () => { alive = false; };
  }, [mesSeleccionado.anio, mesSeleccionado.mes]);

  // Filtrado por categoría
  const driversFiltrados = useMemo(() => {
    if (filtroCat === "todos") return drivers;
    if (filtroCat === "activos") return drivers.filter(d => d.categoria !== "durmiente" && d.categoria !== "fantasma");
    if (filtroCat === "durmientes") return drivers.filter(d => d.categoria === "durmiente");
    if (filtroCat === "fantasmas") return drivers.filter(d => d.categoria === "fantasma");
    return drivers;
  }, [drivers, filtroCat]);

  const vehiculosFiltrados = useMemo(() => {
    if (filtroCat === "todos") return vehiculos;
    if (filtroCat === "activos") return vehiculos.filter(v => v.categoria !== "durmiente" && v.categoria !== "fantasma");
    if (filtroCat === "durmientes") return vehiculos.filter(v => v.categoria === "durmiente");
    if (filtroCat === "fantasmas") return vehiculos.filter(v => v.categoria === "fantasma");
    return vehiculos;
  }, [vehiculos, filtroCat]);

  const driversActivos = drivers.filter(d => d.categoria !== "durmiente" && d.categoria !== "fantasma");
  const driversDurmientes = drivers.filter(d => d.categoria === "durmiente");
  const driversFantasma = drivers.filter(d => d.categoria === "fantasma");
  const driversEnMaster = drivers.filter(d => d.en_master);
  
  const vehiculosActivos = vehiculos.filter(v => v.categoria !== "durmiente" && v.categoria !== "fantasma");
  const vehiculosDurmientes = vehiculos.filter(v => v.categoria === "durmiente");
  const vehiculosFantasma = vehiculos.filter(v => v.categoria === "fantasma");

  const verDriversMaster = () => setModal({
    titulo: "Drivers · Master Oficial Meli",
    filas: driversEnMaster,
    nombreArchivo: "drivers_master_oficial_meli"
  });

  return (
    <div className="pg">
      {/* Selector tipo + mes */}
      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 12 }}>
        <div style={{ display: "flex", gap: 4, background: "#f1f5f9", padding: 4, borderRadius: 8 }}>
          <button onClick={() => setTipo("drivers")}
            style={{ padding: "6px 14px", fontSize: 12, fontWeight: 600, border: "none", cursor: "pointer", borderRadius: 6,
              background: tipo === "drivers" ? "#fff" : "transparent",
              color: tipo === "drivers" ? "#1a3a6b" : "#64748b",
              boxShadow: tipo === "drivers" ? "0 1px 2px rgba(0,0,0,0.05)" : "none",
              fontFamily: "'Geist', sans-serif" }}>
            Drivers ({drivers.length})
          </button>
          <button onClick={() => setTipo("vehicles")}
            style={{ padding: "6px 14px", fontSize: 12, fontWeight: 600, border: "none", cursor: "pointer", borderRadius: 6,
              background: tipo === "vehicles" ? "#fff" : "transparent",
              color: tipo === "vehicles" ? "#1a3a6b" : "#64748b",
              boxShadow: tipo === "vehicles" ? "0 1px 2px rgba(0,0,0,0.05)" : "none",
              fontFamily: "'Geist', sans-serif" }}>
            Vehículos ({vehiculos.length})
          </button>
        </div>
      </div>

      {/* KPIs */}
      {tipo === "drivers" && (
        <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 12, marginBottom: 16 }}>
          <PoolMeliKpi label="En master oficial" value={r.drivers_master ?? driversEnMaster.length} sublabel="API rostering Meli"
                       onClick={verDriversMaster} />
          <PoolMeliKpi label={`Activos en ${NOMBRES_MES[mesSeleccionado.mes - 1]}`} value={driversActivos.length} sublabel={`${Math.round(driversActivos.length / (r.drivers_master || 1) * 100)}% del master`} color="#047857"
                       onClick={() => setFiltroCat("activos")} />
          <PoolMeliKpi label="Durmientes" value={r.drivers_durmientes ?? driversDurmientes.length} sublabel="En master, no operaron"
                       onClick={() => setFiltroCat("durmientes")} />
          <PoolMeliKpi label="Fantasmas" value={r.drivers_fantasma ?? driversFantasma.length} sublabel="Operan sin estar en master" danger
                       onClick={() => setFiltroCat("fantasmas")} />
        </div>
      )}

      {tipo === "vehicles" && (
        <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 12, marginBottom: 16 }}>
          <PoolMeliKpi label="En master oficial" value={r.vehiculos_master} sublabel="API rostering Meli" />
          <PoolMeliKpi label={`Activos en ${NOMBRES_MES[mesSeleccionado.mes - 1]}`} value={vehiculosActivos.length} sublabel={`${Math.round(vehiculosActivos.length / (r.vehiculos_master || 1) * 100)}% de la flota`} color="#047857"
                       onClick={() => setFiltroCat("activos")} />
          <PoolMeliKpi label="Durmientes" value={r.vehiculos_durmientes} sublabel={`Sin uso en ${NOMBRES_MES[mesSeleccionado.mes - 1]}`}
                       onClick={() => setFiltroCat("durmientes")} />
          <PoolMeliKpi label="Fantasmas" value={r.vehiculos_fantasma} sublabel="Sin registro oficial" danger
                       onClick={() => setFiltroCat("fantasmas")} />
        </div>
      )}

      {/* Filtro de categoría */}
      <div style={{ display: "flex", gap: 6, marginBottom: 12, alignItems: "center" }}>
        <span style={{ fontSize: 10, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5, marginRight: 4 }}>Filtrar:</span>
        {[
          { id: "activos", label: "Activos", color: "#047857" },
          { id: "durmientes", label: "Durmientes", color: "#64748b" },
          { id: "fantasmas", label: "Fantasmas", color: "#b91c1c" },
          { id: "todos", label: "Todos", color: "#1a3a6b" },
        ].map(f => {
          const active = filtroCat === f.id;
          const count = tipo === "drivers"
            ? (f.id === "activos" ? driversActivos.length : f.id === "durmientes" ? driversDurmientes.length : f.id === "fantasmas" ? driversFantasma.length : drivers.length)
            : (f.id === "activos" ? vehiculosActivos.length : f.id === "durmientes" ? vehiculosDurmientes.length : f.id === "fantasmas" ? vehiculosFantasma.length : vehiculos.length);
          return (
            <button key={f.id} onClick={() => setFiltroCat(f.id)}
              style={{ padding: "5px 12px", fontSize: 11, fontWeight: 600, borderRadius: 4,
                border: active ? "none" : "1px solid #e4e7ec",
                background: active ? f.color : "#fff",
                color: active ? "#fff" : "#475569",
                cursor: "pointer", fontFamily: "'Geist', sans-serif" }}>
              {f.label}
              <span style={{ marginLeft: 6, opacity: 0.7 }}>({count})</span>
            </button>
          );
        })}
      </div>

      {/* Calendario */}
      {tipo === "drivers" && (
        <PoolMeliCalendario 
          tipo="drivers"
          registros={driversFiltrados}
          calendario={calendarios.drivers}
          mes={mesSeleccionado}
          onVerDetalle={(d) => setDetalle({ tipo: "driver", registro: d })}
        />
      )}
      {tipo === "vehicles" && (
        <PoolMeliCalendario 
          tipo="vehiculos"
          registros={vehiculosFiltrados}
          calendario={calendarios.vehiculos}
          mes={mesSeleccionado}
          onVerDetalle={(v) => setDetalle({ tipo: "vehiculo", registro: v })}
        />
      )}
    </div>
  );
}

// ── CALENDARIO de actividad por día ────────────────────────────────────────
function PoolMeliCalendario({ tipo, registros, calendario, mes, onVerDetalle }) {
  const totalDias = diasDelMes(mes.anio, mes.mes);
  const dias = Array.from({ length: totalDias }, (_, i) => i + 1);

  if (registros.length === 0) {
    return (
      <div className="form-card" style={{ textAlign: "center", padding: 30, color: "#94a3b8", fontSize: 12 }}>
        No hay registros para mostrar en esta categoría.
      </div>
    );
  }

  return (
    <div className="form-card" style={{ padding: 0, overflow: "hidden" }}>
      <div style={{ overflowX: "auto" }}>
        <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 11 }}>
          <thead>
            <tr style={{ background: "#f8fafc", borderBottom: "1px solid #e2e8f0" }}>
              <th style={{ padding: "10px 12px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5, position: "sticky", left: 0, background: "#f8fafc", zIndex: 2 }}>
                {tipo === "drivers" ? "ID Driver" : "Vehicle ID"}
              </th>
              <th style={{ padding: "10px 12px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5, position: "sticky", left: 80, background: "#f8fafc", zIndex: 2 }}>
                {tipo === "drivers" ? "Nombre" : "Placa"}
              </th>
              {dias.map(d => (
                <th key={d} style={{ padding: "6px 4px", textAlign: "center", fontSize: 9, fontWeight: 700, color: "#64748b", minWidth: 22 }}>
                  {d}
                </th>
              ))}
              <th style={{ padding: "10px 12px", textAlign: "center", fontSize: 10, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5, position: "sticky", right: 0, background: "#f8fafc", zIndex: 2 }}>
                Acción
              </th>
            </tr>
          </thead>
          <tbody>
            {registros.map((reg, i) => {
              const key = tipo === "drivers" ? reg.nombre : reg.placa;
              const idLabel = tipo === "drivers" ? reg.driver_id : reg.vehicle_id;
              const nombreLabel = tipo === "drivers" ? reg.nombre : reg.placa;
              const diasActivos = (calendario && calendario[key]) || new Set();
              const diasTrabajados = diasActivos.size || 0;
              
              return (
                <tr key={i} style={{ borderBottom: "1px solid #f1f5f9" }}>
                  <td style={{ padding: "8px 12px", fontSize: 11, color: "#0f172a", fontFamily: "monospace", position: "sticky", left: 0, background: "#fff", zIndex: 1, fontWeight: 600 }}>
                    {idLabel || "—"}
                  </td>
                  <td style={{ padding: "8px 12px", fontSize: 11, color: "#0f172a", whiteSpace: "nowrap", position: "sticky", left: 80, background: "#fff", zIndex: 1, fontWeight: 500 }}>
                    {nombreLabel}
                    <div style={{ fontSize: 9, color: "#94a3b8", marginTop: 1 }}>
                      {diasTrabajados} {diasTrabajados === 1 ? "día" : "días"} activo
                    </div>
                  </td>
                  {dias.map(d => {
                    const trabajo = diasActivos.has(d);
                    return (
                      <td key={d} style={{ padding: "4px 2px", textAlign: "center" }}>
                        <div style={{
                          width: 18, height: 18, margin: "0 auto",
                          background: trabajo ? "#10b981" : "transparent",
                          border: trabajo ? "1px solid #059669" : "1px solid #e4e7ec",
                          borderRadius: 3,
                        }} title={trabajo ? `Trabajó el ${d}` : `No trabajó el ${d}`}></div>
                      </td>
                    );
                  })}
                  <td style={{ padding: "8px 12px", textAlign: "center", position: "sticky", right: 0, background: "#fff", zIndex: 1 }}>
                    <button onClick={() => onVerDetalle(reg)}
                      style={{ padding: "4px 10px", fontSize: 10, fontWeight: 600, border: "1px solid #1a3a6b",
                        borderRadius: 4, background: "#fff", color: "#1a3a6b", cursor: "pointer",
                        fontFamily: "'Geist', sans-serif" }}>
                      Ver
                    </button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
      <div style={{ padding: "10px 16px", borderTop: "1px solid #f1f5f9", background: "#fafbfc", display: "flex", gap: 16, alignItems: "center", fontSize: 10, color: "#64748b" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
          <div style={{ width: 12, height: 12, background: "#10b981", border: "1px solid #059669", borderRadius: 2 }}></div>
          Trabajó / Usado
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
          <div style={{ width: 12, height: 12, border: "1px solid #e4e7ec", borderRadius: 2 }}></div>
          Sin actividad
        </div>
        <span style={{ marginLeft: "auto" }}>{registros.length} {tipo === "drivers" ? "drivers" : "vehículos"} mostrados</span>
      </div>
    </div>
  );
}

// ── DETALLE in-place de un Driver o Vehículo ───────────────────────────────
function PoolMeliDetalleRegistro({ tipo, registro, onVolver }) {
  const [extra, setExtra] = useState(null); // info adicional cargada (viajes, anomalías de tipo)
  const [loadingExtra, setLoadingExtra] = useState(true);

  useEffect(() => {
    let alive = true;
    (async () => {
      setLoadingExtra(true);
      try {
        if (tipo === "driver") {
          const { data } = await sb.from("meli_carrier_metricas")
            .select("fecha, service_center, placa, vehiculo, envios_despachados, envios_entregados, entrega_exitosa, dpph, orh_horas_ruta, kilometros_recorridos")
            .eq("nombre_transportista", registro.nombre)
            .order("fecha", { ascending: false })
            .limit(100);
          if (alive) setExtra({ viajes: data || [] });
        } else {
          // Vehículo: cargar viajes + chequeo de anomalía de tipo
          const [rViajes, rAnom] = await Promise.all([
            sb.from("meli_carrier_metricas")
              .select("fecha, service_center, nombre_transportista, vehiculo, envios_despachados, envios_entregados, entrega_exitosa, dpph")
              .eq("placa", registro.placa)
              .order("fecha", { ascending: false })
              .limit(100),
            sb.from("vw_meli_placas_anomalia_tipo")
              .select("*")
              .eq("placa", registro.placa)
          ]);
          if (alive) setExtra({ viajes: rViajes.data || [], anomalias: rAnom.data || [] });
        }
      } catch (e) {
        console.error("Error cargando detalle:", e);
        if (alive) setExtra({ viajes: [], anomalias: [] });
      } finally {
        if (alive) setLoadingExtra(false);
      }
    })();
    return () => { alive = false; };
  }, [tipo, registro]);

  return (
    <div style={{ padding: 0 }}>
      {/* Header */}
      <div style={{ background: "#fff", borderBottom: "1px solid #e4e7ec", padding: "12px 24px" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
          <button onClick={onVolver} className="btn-back">
            ← Volver al inventario
          </button>
        </div>
        <div style={{ marginTop: 8 }}>
          <div style={{ fontSize: 18, fontWeight: 700, color: "#1a3a6b" }}>
            {tipo === "driver" ? registro.nombre : `Placa ${registro.placa}`}
          </div>
          <div style={{ fontSize: 12, color: "#64748b", marginTop: 2 }}>
            {tipo === "driver" ? `Driver ID: ${registro.driver_id || "—"}` : `Vehicle ID: ${registro.vehicle_id || "—"} · Tipo: ${registro.tipo || "—"}`}
          </div>
        </div>
      </div>

      <div className="pg">
        {/* KPIs del registro */}
        {tipo === "driver" ? (
          <div style={{ display: "grid", gridTemplateColumns: "repeat(5, 1fr)", gap: 12, marginBottom: 16 }}>
            <PoolMeliKpi label="Categoría" value={(registro.categoria || "—").toUpperCase()} sublabel={registro.en_master ? "En master oficial" : "Sin master (FANTASMA)"} 
                         danger={registro.categoria === "fantasma"} />
            <PoolMeliKpi label="Viajes ejecutados" value={registro.viajes_total || 0} sublabel={`${registro.dias_trabajados || 0} días trabajados`} color="#047857" />
            <PoolMeliKpi label="DPPH promedio" value={registro.dpph_promedio?.toFixed?.(1) || "—"} sublabel="paquetes/hora" />
            <PoolMeliKpi label="Entrega exitosa" value={`${registro.entrega_exitosa_pct?.toFixed?.(1) || "—"}%`} sublabel={registro.entrega_exitosa_pct >= 95 ? "Excelente" : "Atención"} 
                         color={registro.entrega_exitosa_pct >= 95 ? "#047857" : "#92400e"} />
            <PoolMeliKpi label="SCs operados" value={registro.cantidad_scs || 0} sublabel={registro.scs_operados || "—"} />
          </div>
        ) : (
          <div style={{ display: "grid", gridTemplateColumns: "repeat(5, 1fr)", gap: 12, marginBottom: 16 }}>
            <PoolMeliKpi label="Categoría" value={(registro.categoria || "—").toUpperCase()} sublabel={registro.en_master ? "En master oficial" : "Sin master (FANTASMA)"} 
                         danger={registro.categoria === "fantasma"} />
            <PoolMeliKpi label="Tipo (master)" value={registro.tipo || "—"} sublabel={registro.es_sdd ? "Es SDD" : "Estándar"} />
            <PoolMeliKpi label="Capacidad" value={`${registro.capacidad || "—"} m³`} sublabel="Según master Meli" />
            <PoolMeliKpi label="Viajes" value={registro.viajes_total || 0} sublabel={`${registro.dias_usado || 0} días usado`} color="#047857" />
            <PoolMeliKpi label="Drivers distintos" value={registro.drivers_distintos || 0} sublabel={registro.drivers_distintos > 1 ? "Compartido" : "Dedicado"} />
          </div>
        )}

        {/* Anomalías de tipo (solo vehículos) */}
        {tipo === "vehiculo" && extra && extra.anomalias && extra.anomalias.length > 0 && (
          <div className="form-card" style={{ background: "#fffbeb", border: "1px solid #fde68a", marginBottom: 16 }}>
            <div className="form-title" style={{ color: "#92400e" }}>⚠ Anomalía de tipo de vehículo detectada</div>
            <div style={{ fontSize: 12, color: "#78350f", marginBottom: 12, lineHeight: 1.5 }}>
              Esta placa fue registrada con <strong>{extra.anomalias.length} tipos diferentes</strong> en distintos viajes. 
              Posibles causas: error de carga, recambio físico, o reasignación de placa.
            </div>
            <div style={{ overflowX: "auto" }}>
              <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 11 }}>
                <thead>
                  <tr style={{ borderBottom: "1px solid #fde68a" }}>
                    <th style={{ padding: "6px 10px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "#78350f", textTransform: "uppercase" }}>Tipo observado</th>
                    <th style={{ padding: "6px 10px", textAlign: "right", fontSize: 10, fontWeight: 700, color: "#78350f", textTransform: "uppercase" }}>Viajes</th>
                    <th style={{ padding: "6px 10px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "#78350f", textTransform: "uppercase" }}>Primera</th>
                    <th style={{ padding: "6px 10px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "#78350f", textTransform: "uppercase" }}>Última</th>
                    <th style={{ padding: "6px 10px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "#78350f", textTransform: "uppercase" }}>Tipo en master</th>
                    <th style={{ padding: "6px 10px", textAlign: "center", fontSize: 10, fontWeight: 700, color: "#78350f", textTransform: "uppercase" }}>Estado</th>
                  </tr>
                </thead>
                <tbody>
                  {extra.anomalias.map((a, i) => (
                    <tr key={i} style={{ borderBottom: "1px solid #fef3c7" }}>
                      <td style={{ padding: "6px 10px", fontWeight: 600 }}>{a.tipo_observado}</td>
                      <td style={{ padding: "6px 10px", textAlign: "right" }}>{a.viajes_con_este_tipo}</td>
                      <td style={{ padding: "6px 10px" }}>{a.primera_aparicion}</td>
                      <td style={{ padding: "6px 10px" }}>{a.ultima_aparicion}</td>
                      <td style={{ padding: "6px 10px" }}>{a.tipo_master || "—"}</td>
                      <td style={{ padding: "6px 10px", textAlign: "center" }}>
                        <span style={{ fontSize: 9, padding: "2px 6px", borderRadius: 3, fontWeight: 700,
                          background: a.estado_vs_master === "COINCIDE" ? "#dcfce7" : a.estado_vs_master === "PLACA_FANTASMA" ? "#fee2e2" : "#fef3c7",
                          color: a.estado_vs_master === "COINCIDE" ? "#15803d" : a.estado_vs_master === "PLACA_FANTASMA" ? "#991b1b" : "#92400e" }}>
                          {a.estado_vs_master}
                        </span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* Lista de viajes */}
        <div className="form-card" style={{ padding: 0, overflow: "hidden" }}>
          <div style={{ padding: "12px 16px", borderBottom: "1px solid #f1f5f9" }}>
            <div className="form-title" style={{ marginBottom: 4 }}>
              {tipo === "driver" ? "Historial de viajes ejecutados" : "Historial de viajes con esta placa"}
            </div>
            <div style={{ fontSize: 11, color: "#64748b" }}>
              {loadingExtra ? "Cargando..." : `${extra?.viajes?.length || 0} viajes (últimos 100)`}
            </div>
          </div>
          
          {!loadingExtra && extra && (
            <div style={{ overflowX: "auto", maxHeight: 500 }}>
              <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 11 }}>
                <thead style={{ position: "sticky", top: 0, background: "#f8fafc" }}>
                  <tr style={{ borderBottom: "1px solid #e2e8f0" }}>
                    <th style={{ padding: "8px 12px", textAlign: "left", fontSize: 9, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5 }}>Fecha</th>
                    <th style={{ padding: "8px 12px", textAlign: "left", fontSize: 9, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5 }}>SC</th>
                    {tipo === "driver" ? (
                      <th style={{ padding: "8px 12px", textAlign: "left", fontSize: 9, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5 }}>Placa</th>
                    ) : (
                      <th style={{ padding: "8px 12px", textAlign: "left", fontSize: 9, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5 }}>Driver</th>
                    )}
                    <th style={{ padding: "8px 12px", textAlign: "left", fontSize: 9, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5 }}>Vehículo</th>
                    <th style={{ padding: "8px 12px", textAlign: "right", fontSize: 9, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5 }}>Despach.</th>
                    <th style={{ padding: "8px 12px", textAlign: "right", fontSize: 9, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5 }}>Entreg.</th>
                    <th style={{ padding: "8px 12px", textAlign: "right", fontSize: 9, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5 }}>% éxito</th>
                    <th style={{ padding: "8px 12px", textAlign: "right", fontSize: 9, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5 }}>DPPH</th>
                  </tr>
                </thead>
                <tbody>
                  {(extra.viajes || []).map((v, i) => (
                    <tr key={i} style={{ borderBottom: "1px solid #f1f5f9" }}>
                      <td style={{ padding: "7px 12px", fontFamily: "monospace" }}>{v.fecha}</td>
                      <td style={{ padding: "7px 12px", fontWeight: 600 }}>{v.service_center}</td>
                      <td style={{ padding: "7px 12px", fontFamily: "monospace" }}>{tipo === "driver" ? v.placa : v.nombre_transportista}</td>
                      <td style={{ padding: "7px 12px", color: "#64748b" }}>{v.vehiculo}</td>
                      <td style={{ padding: "7px 12px", textAlign: "right", fontVariantNumeric: "tabular-nums" }}>{v.envios_despachados}</td>
                      <td style={{ padding: "7px 12px", textAlign: "right", fontVariantNumeric: "tabular-nums" }}>{v.envios_entregados}</td>
                      <td style={{ padding: "7px 12px", textAlign: "right", fontVariantNumeric: "tabular-nums", color: v.entrega_exitosa >= 95 ? "#047857" : "#92400e", fontWeight: 600 }}>{v.entrega_exitosa?.toFixed?.(1)}%</td>
                      <td style={{ padding: "7px 12px", textAlign: "right", fontVariantNumeric: "tabular-nums" }}>{v.dpph?.toFixed?.(1)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
// PESTAÑA: VENTANA DE DECISIONES
// Muestra trayectorias de estado en TR: aceptadas tarde, arrepentimientos,
// cancelaciones MELI, recuperaciones, pending rechazadas
// 3 niveles de drill-down: Tipos → SCs → Rutas individuales
// ═══════════════════════════════════════════════════════════════════════════
function PoolMeliVentanaDecisiones({ mesGlobal }) {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [modo, setModo] = useState("dia"); // "dia" o "rango"
  const [fechaDia, setFechaDia] = useState(() => {
    const d = new Date();
    d.setDate(d.getDate() - 1);
    return d.toISOString().slice(0, 10);
  });
  const [fechaDesde, setFechaDesde] = useState(() => {
    const hoy = new Date();
    const inicioMes = new Date(hoy.getFullYear(), hoy.getMonth(), 1);
    return inicioMes.toISOString().slice(0, 10);
  });
  const [fechaHasta, setFechaHasta] = useState(() => {
    const d = new Date();
    d.setDate(d.getDate() - 1);
    return d.toISOString().slice(0, 10);
  });
  
  // Drill-down state
  const [tipoExpandido, setTipoExpandido] = useState(null);
  const [scExpandido, setScExpandido] = useState(null);

  useEffect(() => {
    let cancelado = false;
    async function cargar() {
      setLoading(true);
      setError(null);
      setTipoExpandido(null);
      setScExpandido(null);
      try {
        const params = modo === "dia"
          ? { p_fecha_desde: fechaDia }
          : { p_fecha_desde: fechaDesde, p_fecha_hasta: fechaHasta };
        const { data: result, error: err } = await sb.rpc("get_ventana_decisiones", params);
        if (cancelado) return;
        if (err) throw err;
        setData(result);
      } catch (e) {
        if (!cancelado) setError(e.message || String(e));
      } finally {
        if (!cancelado) setLoading(false);
      }
    }
    cargar();
    return () => { cancelado = true; };
  }, [modo, fechaDia, fechaDesde, fechaHasta]);

  if (loading) return <div className="pg" style={{ padding: 40, color: "#888" }}>Cargando ventana de decisiones...</div>;
  if (error) return <div className="pg" style={{ padding: 40, color: "#c0392b" }}>Error: {error}</div>;
  if (!data) return <div className="pg" style={{ padding: 40, color: "#888" }}>Sin datos</div>;

  const totales = data.totales_por_tipo || {};
  const desglose = data.desglose_por_sc || {};
  const detalles = data.detalle_completo || {};
  const totalCambios = data.total_cambios || 0;

  // Definición de los 5 tipos con sus metadatos
  const tiposConfig = [
    {
      id: "aceptadas_tarde",
      label: "Aceptadas tarde",
      icon: "⏱️",
      desc: "Pending → Accepted",
      explicacion: "Ofertas que estaban en pending y terminamos aceptando, posiblemente después del ETD",
      color: "#9333ea",
      bg: "#faf5ff",
      border: "#e9d5ff"
    },
    {
      id: "arrepentimientos",
      label: "Arrepentimientos",
      icon: "↩️",
      desc: "Accepted → Rejected",
      explicacion: "Ofertas que aceptamos y luego rechazamos. Indican cambio de criterio operativo.",
      color: "#dc2626",
      bg: "#fef2f2",
      border: "#fecaca"
    },
    {
      id: "canceladas_meli",
      label: "Canceladas MELI",
      icon: "❌",
      desc: "Accepted → Canceled",
      explicacion: "Aceptamos y MELI canceló. No es responsabilidad nuestra pero impacta capacidad.",
      color: "#b45309",
      bg: "#fffbeb",
      border: "#fde68a"
    },
    {
      id: "recuperaciones",
      label: "Recuperaciones",
      icon: "♻️",
      desc: "Rejected → Accepted",
      explicacion: "Rechazamos y luego aceptamos. Probablemente tras revisión operativa.",
      color: "#16a34a",
      bg: "#f0fdf4",
      border: "#bbf7d0"
    },
    {
      id: "pending_rechazadas",
      label: "Pending rechazadas",
      icon: "⛔",
      desc: "Pending → Rejected",
      explicacion: "Ofertas que ignoramos hasta el final y terminamos rechazando.",
      color: "#64748b",
      bg: "#f1f5f9",
      border: "#cbd5e1"
    },
  ];

  const periodoTexto = data.es_rango
    ? `${data.fecha_desde} a ${data.fecha_hasta}`
    : data.fecha_desde;

  return (
    <div className="pg">
      <div className="sec-title">Ventana de Decisiones</div>
      <div className="sec-sub">
        Cambios de estado en Travel Requests · período {periodoTexto}
      </div>

      {/* Selector de modo y fechas */}
      <div style={{ display: "flex", gap: 12, alignItems: "center", marginTop: 20, marginBottom: 16, flexWrap: "wrap" }}>
        <div style={{ display: "flex", gap: 4, padding: 4, background: "#f1f5f9", borderRadius: 8 }}>
          <button onClick={() => setModo("dia")} style={{
            padding: "6px 14px", fontSize: 12, fontWeight: 600, borderRadius: 6,
            border: "none", cursor: "pointer",
            background: modo === "dia" ? "#1a3a6b" : "transparent",
            color: modo === "dia" ? "#fff" : "#475569"
          }}>Día</button>
          <button onClick={() => setModo("rango")} style={{
            padding: "6px 14px", fontSize: 12, fontWeight: 600, borderRadius: 6,
            border: "none", cursor: "pointer",
            background: modo === "rango" ? "#1a3a6b" : "transparent",
            color: modo === "rango" ? "#fff" : "#475569"
          }}>Rango</button>
        </div>
        {modo === "dia" ? (
          <input type="date" value={fechaDia} onChange={(e) => setFechaDia(e.target.value)} style={{
            padding: "6px 10px", fontSize: 13, borderRadius: 6, border: "1px solid #cbd5e1"
          }} />
        ) : (
          <>
            <input type="date" value={fechaDesde} onChange={(e) => setFechaDesde(e.target.value)} style={{
              padding: "6px 10px", fontSize: 13, borderRadius: 6, border: "1px solid #cbd5e1"
            }} />
            <span style={{ color: "#64748b" }}>→</span>
            <input type="date" value={fechaHasta} onChange={(e) => setFechaHasta(e.target.value)} style={{
              padding: "6px 10px", fontSize: 13, borderRadius: 6, border: "1px solid #cbd5e1"
            }} />
          </>
        )}
      </div>

      {/* Cabecera con total */}
      <div style={{
        background: "linear-gradient(135deg, #1a3a6b 0%, #0f1e3d 100%)",
        borderRadius: 12, padding: 20, marginBottom: 16, color: "#fff"
      }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <div>
            <div style={{ fontSize: 14, fontWeight: 700, opacity: 0.9 }}>🔄 Total de cambios detectados</div>
            <div style={{ fontSize: 11, opacity: 0.7, marginTop: 4 }}>Ofertas TR cuyo estado cambió durante el período</div>
          </div>
          <div style={{ fontSize: 48, fontWeight: 800, fontVariantNumeric: "tabular-nums" }}>
            {totalCambios}
          </div>
        </div>
      </div>

      {/* Tarjetas de tipos */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))", gap: 12, marginBottom: 16 }}>
        {tiposConfig.map(t => {
          const cantidad = totales[t.id] || 0;
          const expandida = tipoExpandido === t.id;
          return (
            <div key={t.id}
              onClick={() => {
                if (cantidad === 0) return;
                setTipoExpandido(expandida ? null : t.id);
                setScExpandido(null);
              }}
              style={{
                background: t.bg,
                borderRadius: 10,
                padding: 14,
                border: `1px solid ${expandida ? t.color : t.border}`,
                borderWidth: expandida ? 2 : 1,
                cursor: cantidad > 0 ? "pointer" : "default",
                opacity: cantidad === 0 ? 0.6 : 1,
                transition: "all 0.15s",
                position: "relative"
              }}>
              <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 4 }}>
                <span style={{ fontSize: 18 }}>{t.icon}</span>
                <span style={{ fontSize: 12, fontWeight: 700, color: t.color, textTransform: "uppercase", letterSpacing: 0.3 }}>
                  {t.label}
                </span>
              </div>
              <div style={{ fontSize: 32, fontWeight: 800, color: t.color, fontVariantNumeric: "tabular-nums", lineHeight: 1 }}>
                {cantidad}
              </div>
              <div style={{ fontSize: 10, color: t.color, opacity: 0.7, marginTop: 4 }}>
                {t.desc}
              </div>
              {cantidad > 0 && (
                <div style={{ fontSize: 9, color: t.color, opacity: 0.6, marginTop: 6, fontWeight: 600 }}>
                  {expandida ? "▲ Cerrar" : "▼ Click para ver SCs"}
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* Drill-down: SCs del tipo expandido */}
      {tipoExpandido && (() => {
        const tipo = tiposConfig.find(t => t.id === tipoExpandido);
        const scs = desglose[tipoExpandido] || [];
        const rutas = detalles[tipoExpandido] || [];
        return (
          <div style={{
            background: "#fff",
            borderRadius: 12,
            padding: 20,
            marginBottom: 16,
            border: `2px solid ${tipo.color}`
          }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 14 }}>
              <div>
                <div style={{ fontSize: 16, fontWeight: 700, color: tipo.color }}>
                  {tipo.icon} {tipo.label}
                </div>
                <div style={{ fontSize: 11, color: "#64748b", marginTop: 2 }}>
                  {tipo.explicacion}
                </div>
              </div>
              <div style={{ fontSize: 24, fontWeight: 800, color: tipo.color }}>
                {totales[tipoExpandido]}
              </div>
            </div>

            {/* Tabla de SCs */}
            <div style={{ marginBottom: 12 }}>
              <div style={{ fontSize: 11, color: "#64748b", fontWeight: 700, textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 8 }}>
                Desglose por Service Center
              </div>
              <table style={{ width: "100%", fontSize: 12, borderCollapse: "collapse" }}>
                <thead>
                  <tr style={{ borderBottom: "1px solid #e2e8f0", color: "#475569" }}>
                    <th style={{ textAlign: "left", padding: "8px 10px", fontWeight: 700 }}>SC</th>
                    <th style={{ textAlign: "right", padding: "8px 10px", fontWeight: 700 }}>Total</th>
                    <th style={{ textAlign: "right", padding: "8px 10px", fontWeight: 700 }}>SDD</th>
                    <th style={{ textAlign: "right", padding: "8px 10px", fontWeight: 700 }}>Variable</th>
                    <th style={{ textAlign: "left", padding: "8px 10px", fontWeight: 700 }}>Vehículos</th>
                    <th style={{ textAlign: "center", padding: "8px 10px", fontWeight: 700 }}>Detalle</th>
                  </tr>
                </thead>
                <tbody>
                  {scs.map((sc, i) => {
                    const expSc = scExpandido === sc.sc;
                    return (
                      <tr key={i}
                        style={{
                          borderBottom: "1px solid #f1f5f9",
                          background: expSc ? tipo.bg : (i % 2 === 0 ? "#fafbfc" : "#fff"),
                          cursor: "pointer"
                        }}
                        onClick={() => setScExpandido(expSc ? null : sc.sc)}>
                        <td style={{ padding: "8px 10px", fontWeight: 600, color: "#0f172a" }}>{sc.sc}</td>
                        <td style={{ padding: "8px 10px", textAlign: "right", fontWeight: 700, color: tipo.color, fontVariantNumeric: "tabular-nums" }}>{sc.cantidad}</td>
                        <td style={{ padding: "8px 10px", textAlign: "right", color: "#9a3412", fontVariantNumeric: "tabular-nums" }}>{sc.sdd || 0}</td>
                        <td style={{ padding: "8px 10px", textAlign: "right", color: "#3730a3", fontVariantNumeric: "tabular-nums" }}>{sc.variable || 0}</td>
                        <td style={{ padding: "8px 10px", color: "#64748b", fontSize: 11 }}>{sc.vehiculos}</td>
                        <td style={{ padding: "8px 10px", textAlign: "center", fontSize: 11, color: tipo.color, fontWeight: 600 }}>
                          {expSc ? "▲" : "▼"}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>

            {/* Drill-down nivel 3: rutas individuales del SC */}
            {scExpandido && (() => {
              const rutasSc = rutas.filter(r => r.sc === scExpandido);
              return (
                <div style={{ background: tipo.bg, borderRadius: 8, padding: 12, marginTop: 8, border: `1px solid ${tipo.border}` }}>
                  <div style={{ fontSize: 11, color: tipo.color, fontWeight: 700, textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 8 }}>
                    Rutas individuales · {scExpandido} ({rutasSc.length})
                  </div>
                  <div style={{ maxHeight: 320, overflowY: "auto" }}>
                    <table style={{ width: "100%", fontSize: 11, borderCollapse: "collapse" }}>
                      <thead style={{ position: "sticky", top: 0, background: tipo.bg, zIndex: 1 }}>
                        <tr style={{ borderBottom: `1px solid ${tipo.border}`, color: tipo.color }}>
                          {data.es_rango && <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 700 }}>Fecha op.</th>}
                          <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 700 }}>Request ID</th>
                          <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 700 }}>Travel ID</th>
                          <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 700 }}>Vehículo</th>
                          <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 700 }}>Tipo</th>
                          <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 700 }}>Trayectoria</th>
                          <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 700 }}>Último cambio</th>
                          <th style={{ textAlign: "right", padding: "4px 8px", fontWeight: 700 }}>Hs vs ETD</th>
                        </tr>
                      </thead>
                      <tbody>
                        {rutasSc.map((r, i) => (
                          <tr key={i} style={{ borderBottom: `1px dashed ${tipo.border}` }}>
                            {data.es_rango && <td style={{ padding: "4px 8px", color: "#475569" }}>{r.fecha}</td>}
                            <td style={{ padding: "4px 8px", color: "#475569", fontFamily: "monospace" }}>{r.request_id}</td>
                            <td style={{ padding: "4px 8px", color: "#475569", fontFamily: "monospace" }}>{r.travel_id || "—"}</td>
                            <td style={{ padding: "4px 8px", color: "#475569" }}>{r.vehiculo}</td>
                            <td style={{ padding: "4px 8px", fontWeight: 600, color: r.es_sdd ? "#9a3412" : "#3730a3" }}>
                              {r.es_sdd ? "SDD" : "VAR"}
                            </td>
                            <td style={{ padding: "4px 8px", fontFamily: "monospace", fontSize: 10, color: tipo.color, fontWeight: 600 }}>
                              {r.estado_inicial} → {r.estado_final}
                            </td>
                            <td style={{ padding: "4px 8px", color: "#64748b", fontSize: 10 }}>
                              {r.momento_cambio ? new Date(r.momento_cambio).toLocaleString('es-MX', {
                                day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit'
                              }) : "—"}
                            </td>
                            <td style={{ padding: "4px 8px", textAlign: "right", color: r.horas_vs_etd > 0 ? "#dc2626" : "#16a34a", fontWeight: 600, fontVariantNumeric: "tabular-nums" }}>
                              {r.horas_vs_etd != null ? `${r.horas_vs_etd > 0 ? '+' : ''}${r.horas_vs_etd}h` : "—"}
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                  <div style={{ fontSize: 10, color: tipo.color, opacity: 0.7, marginTop: 8, fontStyle: "italic" }}>
                    💡 "Hs vs ETD" en positivo: el cambio ocurrió DESPUÉS del horario de salida planeado.
                  </div>
                </div>
              );
            })()}
          </div>
        );
      })()}

      {/* Mensaje cuando no hay datos */}
      {totalCambios === 0 && (
        <div style={{
          background: "#f0fdf4",
          borderRadius: 12,
          padding: 24,
          textAlign: "center",
          border: "1px solid #bbf7d0"
        }}>
          <div style={{ fontSize: 28, marginBottom: 8 }}>✅</div>
          <div style={{ fontSize: 14, fontWeight: 700, color: "#166534" }}>Sin cambios de estado en este período</div>
          <div style={{ fontSize: 11, color: "#166534", marginTop: 4, opacity: 0.8 }}>
            Todas las ofertas TR mantuvieron su estado inicial.
          </div>
        </div>
      )}
    </div>
  );
}

// ── CICLO con embudo moderno + filtros mejorados ──────────────────────────
function PoolMeliCiclo({ scs, resumen, setModal, mesGlobal }) {
  const [perfilFiltro, setPerfilFiltro] = useState("TODOS");
  const r = resumen || {};

  // Helper de estilo para enlaces clickeables (números con underline al hover)
  const linkStyle = (color, bold = false) => ({
    background: "transparent",
    border: "none",
    color,
    cursor: "pointer",
    fontWeight: bold ? 700 : 600,
    fontSize: "inherit",
    fontVariantNumeric: "tabular-nums",
    padding: 0,
    textDecoration: "underline",
    textDecorationColor: "transparent",
    textUnderlineOffset: 3,
    transition: "text-decoration-color 0.15s",
  });

  // Split de no presentadas por fleet (SDD vs VARIABLE)
  const [splitFleet, setSplitFleet] = useState({ sdd: null, variable: null });

  // Trayectorias de Estado y Matrix Embudo↔Cumplimiento
  const [trayectorias, setTrayectorias] = useState([]);
  const [matrixData, setMatrixData] = useState([]);

  // Recargar split fleet cuando cambia el mes global
  useEffect(() => {
    if (!mesGlobal) return;
    let alive = true;
    (async () => {
      try {
        const { desde, hasta } = rangoMesGlobal(mesGlobal);
        
        const { data: fleetData, error: fleetError } = await sb.rpc("get_no_presentadas_por_fleet", {
          fecha_desde: desde,
          fecha_hasta: hasta,
        });
        if (!alive) return;
        if (fleetError) {
          console.error("Error cargando split fleet:", fleetError);
          setSplitFleet({ sdd: null, variable: null });
        } else {
          const sddRow = (fleetData || []).find(r => r.fleet_type === 'SDD');
          const varRow = (fleetData || []).find(r => r.fleet_type === 'VARIABLE');
          setSplitFleet({
            sdd: sddRow ? { 
              aceptadas: Number(sddRow.aceptadas), 
              ejecutadas: Number(sddRow.ejecutadas), 
              no_presentadas: Number(sddRow.no_presentadas) 
            } : null,
            variable: varRow ? { 
              aceptadas: Number(varRow.aceptadas), 
              ejecutadas: Number(varRow.ejecutadas), 
              no_presentadas: Number(varRow.no_presentadas) 
            } : null,
          });
        }

        // Trayectorias de estado
        const { data: trayData, error: trayError } = await sb.rpc("get_trayectorias_estado", {
          p_desde: desde,
          p_hasta: hasta,
        });
        if (!alive) return;
        if (trayError) {
          console.error("Error cargando trayectorias:", trayError);
          setTrayectorias([]);
        } else {
          setTrayectorias(trayData || []);
        }

        // Matrix Embudo ↔ Cumplimiento
        const { data: mData, error: mError } = await sb.rpc("get_matrix_embudo_cumplimiento", {
          p_desde: desde,
          p_hasta: hasta,
        });
        if (!alive) return;
        if (mError) {
          console.error("Error cargando matrix:", mError);
          setMatrixData([]);
        } else {
          setMatrixData(mData || []);
        }
      } catch (e) {
        console.error("Error cargando ciclo del mes:", e);
        if (alive) {
          setSplitFleet({ sdd: null, variable: null });
          setTrayectorias([]);
          setMatrixData([]);
        }
      }
    })();
    return () => { alive = false; };
  }, [mesGlobal?.anio, mesGlobal?.mes]);

  const filtrados = perfilFiltro === "TODOS" ? scs : scs.filter(s => s.perfil === perfilFiltro);
  const totOfr = scs.reduce((a, s) => a + (s.ofrecidas || 0), 0);
  const totAcc = scs.reduce((a, s) => a + (s.aceptadas || 0), 0);
  const totEjec = scs.reduce((a, s) => a + (s.ejecutadas || 0), 0);
  const totNoPres = scs.reduce((a, s) => a + (s.no_presentadas || 0), 0);
  const totRech = scs.reduce((a, s) => a + (s.rechazadas || 0), 0);
  const totCanc = scs.reduce((a, s) => a + (s.canceladas || 0), 0);
  const totPend = scs.reduce((a, s) => a + (s.pendientes || 0), 0);
  const conteoPorPerfil = (p) => scs.filter(s => s.perfil === p).length;
  const problematicos = scs.filter(s => s.perfil === "PROBLEMATICO");

  // Modales con datos
  const abrirRechazadas = async (filtroSC = null) => {
    const tituloSC = filtroSC ? ` · ${filtroSC}` : "";
    setModal({ titulo: `Cargando…`, filas: [], nombreArchivo: "rechazadas" });
    try {
      let q = sb.from("vw_meli_tr_rechazadas").select("*").order("fecha", { ascending: false });
      if (filtroSC) q = q.eq("service_center", filtroSC);
      const { data, error } = await q;
      if (error) throw error;
      setModal({
        titulo: `Viajes RECHAZADOS${tituloSC} (${(data || []).length})`,
        filas: data || [],
        nombreArchivo: filtroSC ? `rechazadas_${filtroSC}` : "rechazadas"
      });
    } catch (e) { setModal({ titulo: "Error", filas: [{ error: e.message }], nombreArchivo: "error" }); }
  };

  const abrirCanceladas = async (filtroSC = null) => {
    const tituloSC = filtroSC ? ` · ${filtroSC}` : "";
    setModal({ titulo: `Cargando…`, filas: [], nombreArchivo: "canceladas" });
    try {
      let q = sb.from("vw_meli_tr_canceladas").select("*").order("fecha", { ascending: false });
      if (filtroSC) q = q.eq("service_center", filtroSC);
      const { data, error } = await q;
      if (error) throw error;
      setModal({
        titulo: `Viajes CANCELADOS${tituloSC} (${(data || []).length})`,
        filas: data || [],
        nombreArchivo: filtroSC ? `canceladas_${filtroSC}` : "canceladas"
      });
    } catch (e) { setModal({ titulo: "Error", filas: [{ error: e.message }], nombreArchivo: "error" }); }
  };

  // Pendientes (último snapshot, sin respuesta del carrier)
  const abrirPendientes = async (filtroSC = null) => {
    if (!mesGlobal) return;
    const tituloSC = filtroSC ? ` · ${filtroSC}` : "";
    setModal({ titulo: `Cargando…`, filas: [], nombreArchivo: "pendientes" });
    try {
      const { desde, hasta } = rangoMesGlobal(mesGlobal);
      // Traemos los pending del último snapshot por request_id
      const { data: rawData, error } = await sb
        .from("meli_travel_requests")
        .select("request_id, facility_id, fecha, status, vehicle_type, fecha_snapshot, hora_snapshot, attributes")
        .eq("status", "pending")
        .gte("fecha", desde)
        .lte("fecha", hasta)
        .order("fecha_snapshot", { ascending: false })
        .order("hora_snapshot", { ascending: false });
      if (error) throw error;
      // Dedup por request_id (último snapshot)
      const seen = new Set();
      let dedup = (rawData || []).filter(r => {
        if (seen.has(r.request_id)) return false;
        seen.add(r.request_id);
        return true;
      });
      if (filtroSC) dedup = dedup.filter(r => r.facility_id === filtroSC);
      // Calcular días pasados desde la fecha de operación
      const hoy = new Date();
      const filas = dedup.map(r => {
        const fechaOp = new Date(r.fecha);
        const diasPasados = Math.floor((hoy - fechaOp) / (1000 * 60 * 60 * 24));
        const fleet = r.attributes && Array.isArray(r.attributes) && r.attributes.some(a => a.id === 'sdd') ? 'SDD' : 'VARIABLE';
        return {
          request_id: r.request_id,
          service_center: r.facility_id,
          fecha_operacion: r.fecha,
          dias_desde_operacion: diasPasados,
          vehicle_type: r.vehicle_type,
          fleet,
          ultimo_snapshot: `${r.fecha_snapshot} ${r.hora_snapshot || ''}`,
          critico: diasPasados > 0 ? 'SÍ' : 'NO'
        };
      });
      setModal({
        titulo: `Viajes PENDIENTES sin respuesta${tituloSC} (${filas.length})`,
        filas,
        nombreArchivo: filtroSC ? `pendientes_${filtroSC}` : "pendientes"
      });
    } catch (e) { setModal({ titulo: "Error", filas: [{ error: e.message }], nombreArchivo: "error" }); }
  };

  // No presentadas con filtros completos (SC, fecha, % min)
  const abrirNoPresentadas = async (filtroSC = null) => {
    setModal({ titulo: `Cargando…`, filas: [], nombreArchivo: "no_presentadas" });
    try {
      let q = sb.from("vw_meli_no_presentadas").select("*").order("fecha", { ascending: false });
      if (filtroSC) q = q.eq("service_center", filtroSC);
      const { data, error } = await q;
      if (error) throw error;
      const filas = data || [];
      setModal({
        titulo: filtroSC ? `Viajes NO PRESENTADOS · ${filtroSC} (${filas.length})` : `Viajes NO PRESENTADOS · todos los SCs (${filas.length})`,
        filas,
        nombreArchivo: filtroSC ? `no_presentadas_${filtroSC}` : "no_presentadas",
        // Componente con UI de filtros propios
        renderFiltrosUI: true,
      });
    } catch (e) { setModal({ titulo: "Error", filas: [{ error: e.message }], nombreArchivo: "error" }); }
  };

  const abrirEjecutadas = async (filtroSC = null) => {
    const tituloSC = filtroSC ? ` · ${filtroSC}` : "";
    setModal({ titulo: `Cargando…`, filas: [], nombreArchivo: "ejecutadas" });
    try {
      let q = sb.from("vw_meli_tr_ejecutadas_detalle").select("*").order("fecha", { ascending: false });
      if (filtroSC) q = q.eq("service_center", filtroSC);
      const { data, error } = await q;
      if (error) throw error;
      setModal({
        titulo: `Viajes EJECUTADOS${tituloSC} (${(data || []).length})`,
        filas: data || [],
        nombreArchivo: filtroSC ? `ejecutadas_${filtroSC}` : "ejecutadas"
      });
    } catch (e) { setModal({ titulo: "Error", filas: [{ error: e.message }], nombreArchivo: "error" }); }
  };

  const abrirAceptadas = async (filtroSC = null) => {
    const tituloSC = filtroSC ? ` · ${filtroSC}` : "";
    setModal({ titulo: `Cargando…`, filas: [], nombreArchivo: "aceptadas" });
    try {
      let q = sb.from("meli_travel_requests")
        .select("request_id, facility_id, fecha, destination, travel_id, vehicle_type, mel_service_description, etd, eta, status")
        .eq("status", "accepted")
        .order("fecha", { ascending: false });
      if (filtroSC) q = q.eq("facility_id", filtroSC);
      const { data, error } = await q.limit(5000);
      if (error) throw error;
      setModal({
        titulo: `Viajes ACEPTADOS${tituloSC} (${(data || []).length})`,
        filas: data || [],
        nombreArchivo: filtroSC ? `aceptadas_${filtroSC}` : "aceptadas"
      });
    } catch (e) { setModal({ titulo: "Error", filas: [{ error: e.message }], nombreArchivo: "error" }); }
  };

  const abrirOfrecidas = async (filtroSC = null) => {
    const tituloSC = filtroSC ? ` · ${filtroSC}` : "";
    setModal({ titulo: `Cargando…`, filas: [], nombreArchivo: "ofrecidas" });
    try {
      let q = sb.from("meli_travel_requests")
        .select("request_id, facility_id, fecha, destination, travel_id, vehicle_type, mel_service_description, etd, eta, status")
        .order("fecha", { ascending: false });
      if (filtroSC) q = q.eq("facility_id", filtroSC);
      const { data, error } = await q.limit(5000);
      if (error) throw error;
      setModal({
        titulo: `Viajes OFRECIDOS${tituloSC} (${(data || []).length})`,
        filas: data || [],
        nombreArchivo: filtroSC ? `ofrecidas_${filtroSC}` : "ofrecidas"
      });
    } catch (e) { setModal({ titulo: "Error", filas: [{ error: e.message }], nombreArchivo: "error" }); }
  };

  // Drilldown: Trayectoria de estado
  const abrirTrayectoria = async (trayectoria) => {
    if (!mesGlobal) return;
    setModal({ titulo: `Cargando…`, filas: [], nombreArchivo: "trayectoria" });
    try {
      const { desde, hasta } = rangoMesGlobal(mesGlobal);
      const { data, error } = await sb.rpc("get_trayectorias_detalle", {
        p_desde: desde,
        p_hasta: hasta,
        p_trayectoria: trayectoria,
      });
      if (error) throw error;
      // Mapear nombres amigables
      const filas = (data || []).map(d => ({
        "Request ID": d.request_id,
        "SC": d.facility_id,
        "Fecha Op.": d.fecha_operacion,
        "Estado Inicial": d.estado_inicial,
        "Estado Final": d.estado_final,
        "Snapshots": d.cantidad_snapshots,
        "Momento del cambio": d.momento_cambio,
        "Horas antes ETD": d.horas_antes_etd,
        "Tipo flota": d.fleet_type,
        "Servicio": d.service_description,
        "Vehículo": d.vehicle_type,
        "ETD": d.etd_date,
      }));
      setModal({
        titulo: `Trayectoria: ${trayectoria} (${filas.length})`,
        filas,
        nombreArchivo: `trayectoria_${trayectoria.replace(/\s|→/g, "_")}`,
      });
    } catch (e) {
      setModal({ titulo: "Error", filas: [{ error: e.message }], nombreArchivo: "error" });
    }
  };

  // Drilldown: Matrix (aceptadas o ejecutadas por SC+fecha)
  const abrirMatrixDetalle = async (fecha, sc, tipo) => {
    setModal({ titulo: `Cargando…`, filas: [], nombreArchivo: "matrix" });
    try {
      const { data, error } = await sb.rpc("get_matrix_detalle", {
        p_fecha: fecha,
        p_sc: sc,
        p_tipo: tipo,
      });
      if (error) throw error;
      const filas = (data || []).map(d => {
        if (tipo === "aceptadas") {
          return {
            "Request ID": d.identificador,
            "Origen": d.origen,
            "Tipo flota": d.fleet_type,
            "Servicio": d.service_description,
            "Vehículo": d.vehicle_type,
            "Estado": d.estado_o_ns,
            "ETD": d.driver_o_etd,
          };
        } else {
          return {
            "ID Ruta": d.identificador,
            "Origen": d.origen,
            "Tipo flota": d.fleet_type,
            "Servicio": d.service_description,
            "Vehículo": d.vehicle_type,
            "NS %": d.estado_o_ns,
            "Conductor": d.driver_o_etd,
            "Despachados": d.envios_despachados,
            "Entregados": d.envios_entregados,
          };
        }
      });
      const tituloTipo = tipo === "aceptadas" ? "Aceptadas (TR)" : "Ejecutadas (Maestro)";
      setModal({
        titulo: `${tituloTipo} · ${sc} · ${fecha} (${filas.length})`,
        filas,
        nombreArchivo: `matrix_${tipo}_${sc}_${fecha}`,
      });
    } catch (e) {
      setModal({ titulo: "Error", filas: [{ error: e.message }], nombreArchivo: "error" });
    }
  };

  // EMBUDO MODERNO: pirámide horizontal con conexiones
  const pctAcc = totOfr > 0 ? (totAcc / totOfr * 100) : 0;
  const pctEjec = totOfr > 0 ? (totEjec / totOfr * 100) : 0;

  return (
    <div className="pg">
      {/* Embudo moderno */}
      <div className="form-card" style={{ background: "linear-gradient(180deg, #fff 0%, #f8fafc 100%)" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 24 }}>
          <div>
            <div className="form-title" style={{ marginBottom: 4 }}>Embudo del ciclo</div>
            <div style={{ fontSize: 12, color: "#64748b" }}>
              Trayectoria: ofrecidas → aceptadas → ejecutadas
              <span style={{ marginLeft: 8, color: "#94a3b8" }}>· click en cualquier número para ver detalle</span>
            </div>
          </div>
        </div>

        {/* Pirámide moderna */}
        <div style={{ position: "relative", padding: "0 20px" }}>
          {[
            { label: "Ofrecidas por Meli", valor: totOfr, color: "#1a3a6b", colorLight: "#3b5fa3", pct: 100, onClick: () => abrirOfrecidas(), sublabel: "Total recibido" },
            { label: "Aceptadas por Bigticket", valor: totAcc, color: "#0891b2", colorLight: "#22d3ee", pct: pctAcc, onClick: () => abrirAceptadas(), sublabel: `${pctAcc.toFixed(1)}% del total` },
            { label: "Ejecutadas en operación", valor: totEjec, color: "#10b981", colorLight: "#34d399", pct: pctEjec, onClick: () => abrirEjecutadas(), sublabel: `${pctEjec.toFixed(1)}% del total · ${totAcc > 0 ? (totEjec/totAcc*100).toFixed(0) : 0}% de las aceptadas` },
          ].map((stage, i) => {
            const widthPct = stage.pct;
            const isLast = i === 2;
            return (
              <div key={stage.label}>
                <div onClick={stage.onClick}
                  style={{
                    cursor: "pointer",
                    background: `linear-gradient(135deg, ${stage.color} 0%, ${stage.colorLight} 100%)`,
                    width: `${widthPct}%`,
                    margin: "0 auto",
                    padding: "18px 24px",
                    borderRadius: 12,
                    color: "#fff",
                    boxShadow: `0 4px 12px ${stage.color}33, inset 0 1px 0 rgba(255,255,255,0.15)`,
                    display: "flex", alignItems: "center", justifyContent: "space-between",
                    transition: "transform 0.15s",
                  }}
                  onMouseEnter={e => e.currentTarget.style.transform = "scale(1.01)"}
                  onMouseLeave={e => e.currentTarget.style.transform = "scale(1)"}>
                  <div>
                    <div style={{ fontSize: 11, opacity: 0.85, textTransform: "uppercase", letterSpacing: 1, marginBottom: 4, fontWeight: 600 }}>
                      Etapa {i + 1}
                    </div>
                    <div style={{ fontSize: 14, fontWeight: 700 }}>{stage.label}</div>
                    <div style={{ fontSize: 11, opacity: 0.85, marginTop: 2 }}>{stage.sublabel}</div>
                  </div>
                  <div style={{ textAlign: "right" }}>
                    <div style={{ fontSize: 32, fontWeight: 800, lineHeight: 1, fontVariantNumeric: "tabular-nums" }}>
                      {stage.valor.toLocaleString()}
                    </div>
                    <div style={{ fontSize: 9, opacity: 0.7, textTransform: "uppercase", letterSpacing: 0.5, marginTop: 2 }}>VER DETALLE →</div>
                  </div>
                </div>
                
                {/* Conexión visual entre etapas */}
                {!isLast && (
                  <div style={{ display: "flex", justifyContent: "center", padding: "4px 0" }}>
                    <div style={{ width: 0, height: 16, borderLeft: "2px dashed #cbd5e1" }}></div>
                  </div>
                )}
              </div>
            );
          })}
        </div>

        {/* Pérdidas */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 10, marginTop: 24, paddingTop: 16, borderTop: "1px dashed #e4e7ec" }}>
          <div onClick={() => abrirRechazadas()}
            style={{ background: "linear-gradient(135deg, #fef2f2 0%, #fee2e2 100%)", borderRadius: 8, padding: 14, cursor: "pointer", border: "1px solid #fecaca" }}>
            <div style={{ fontSize: 10, fontWeight: 700, color: "#991b1b", textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 4, display: "flex", justifyContent: "space-between" }}>
              <span>Rechazadas</span><span style={{ fontSize: 9, opacity: 0.7 }}>VER →</span>
            </div>
            <div style={{ fontSize: 22, fontWeight: 700, color: "#991b1b" }}>{totRech.toLocaleString()}</div>
            <div style={{ fontSize: 10, color: "#7f1d1d", marginTop: 2 }}>{totOfr > 0 ? Math.round(totRech / totOfr * 100) : 0}% de ofrecidas</div>
          </div>
          <div onClick={() => abrirCanceladas()}
            style={{ background: "linear-gradient(135deg, #f8fafc 0%, #e2e8f0 100%)", borderRadius: 8, padding: 14, cursor: "pointer", border: "1px solid #cbd5e1" }}>
            <div style={{ fontSize: 10, fontWeight: 700, color: "#475569", textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 4, display: "flex", justifyContent: "space-between" }}>
              <span>Canceladas</span><span style={{ fontSize: 9, opacity: 0.7 }}>VER →</span>
            </div>
            <div style={{ fontSize: 22, fontWeight: 700, color: "#475569" }}>{totCanc.toLocaleString()}</div>
            <div style={{ fontSize: 10, color: "#64748b", marginTop: 2 }}>{totOfr > 0 ? Math.round(totCanc / totOfr * 100) : 0}% de ofrecidas</div>
          </div>
          <div onClick={() => abrirPendientes()}
            style={{ background: "linear-gradient(135deg, #faf5ff 0%, #f3e8ff 100%)", borderRadius: 8, padding: 14, cursor: "pointer", border: "1px solid #e9d5ff" }}>
            <div style={{ fontSize: 10, fontWeight: 700, color: "#6b21a8", textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 4, display: "flex", justifyContent: "space-between" }}>
              <span>Pendientes</span><span style={{ fontSize: 9, opacity: 0.7 }}>VER →</span>
            </div>
            <div style={{ fontSize: 22, fontWeight: 700, color: "#6b21a8" }}>{totPend.toLocaleString()}</div>
            <div style={{ fontSize: 10, color: "#7e22ce", marginTop: 2 }}>sin respuesta del carrier</div>
          </div>
          <div onClick={() => abrirNoPresentadas()}
            style={{ background: "linear-gradient(135deg, #fffbeb 0%, #fef3c7 100%)", borderRadius: 8, padding: 14, cursor: "pointer", border: "1px solid #fde68a" }}>
            <div style={{ fontSize: 10, fontWeight: 700, color: "#92400e", textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 4, display: "flex", justifyContent: "space-between" }}>
              <span>No presentadas</span><span style={{ fontSize: 9, opacity: 0.7 }}>FILTROS →</span>
            </div>
            <div style={{ fontSize: 22, fontWeight: 700, color: "#92400e" }}>{totNoPres.toLocaleString()}</div>
            <div style={{ fontSize: 10, color: "#92400e", marginTop: 2 }}>aceptadas - ejecutadas</div>
            
            {/* Split SDD vs Variable */}
            {splitFleet.sdd && splitFleet.variable && (
              <div style={{ marginTop: 12, paddingTop: 10, borderTop: "1px dashed #fde68a", display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8 }}>
                {/* SDD */}
                <div style={{ background: "rgba(255,255,255,0.6)", borderRadius: 6, padding: "8px 10px" }}>
                  <div style={{ fontSize: 9, fontWeight: 700, color: "#0f172a", textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 2 }}>
                    SDD <span style={{ color: "#94a3b8", fontWeight: 500 }}>(Súper Dedicada)</span>
                  </div>
                  <div style={{ fontSize: 18, fontWeight: 700, color: "#92400e", lineHeight: 1 }}>
                    {splitFleet.sdd.no_presentadas.toLocaleString()}
                  </div>
                  <div style={{ fontSize: 9, color: "#92400e", marginTop: 3 }}>
                    {splitFleet.sdd.aceptadas} acept · {splitFleet.sdd.ejecutadas} ejec
                  </div>
                  <div style={{ fontSize: 9, color: splitFleet.sdd.aceptadas > 0 && (splitFleet.sdd.no_presentadas / splitFleet.sdd.aceptadas) < 0.10 ? "#047857" : "#92400e", fontWeight: 600, marginTop: 1 }}>
                    {splitFleet.sdd.aceptadas > 0 ? ((splitFleet.sdd.no_presentadas / splitFleet.sdd.aceptadas) * 100).toFixed(1) : "0.0"}% no-show
                  </div>
                </div>
                {/* Variable */}
                <div style={{ background: "rgba(255,255,255,0.6)", borderRadius: 6, padding: "8px 10px" }}>
                  <div style={{ fontSize: 9, fontWeight: 700, color: "#0f172a", textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 2 }}>
                    Variable <span style={{ color: "#94a3b8", fontWeight: 500 }}>(Flota libre)</span>
                  </div>
                  <div style={{ fontSize: 18, fontWeight: 700, color: "#92400e", lineHeight: 1 }}>
                    {splitFleet.variable.no_presentadas.toLocaleString()}
                  </div>
                  <div style={{ fontSize: 9, color: "#92400e", marginTop: 3 }}>
                    {splitFleet.variable.aceptadas} acept · {splitFleet.variable.ejecutadas} ejec
                  </div>
                  <div style={{ fontSize: 9, color: splitFleet.variable.aceptadas > 0 && (splitFleet.variable.no_presentadas / splitFleet.variable.aceptadas) < 0.10 ? "#047857" : "#92400e", fontWeight: 600, marginTop: 1 }}>
                    {splitFleet.variable.aceptadas > 0 ? ((splitFleet.variable.no_presentadas / splitFleet.variable.aceptadas) * 100).toFixed(1) : "0.0"}% no-show
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Filtros perfil */}
      <div style={{ display: "flex", alignItems: "center", gap: 6, margin: "16px 0" }}>
        <span style={{ fontSize: 10, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5, marginRight: 4 }}>Filtrar:</span>
        {["TODOS", "IDEAL", "INCONSISTENTE", "PROBLEMATICO"].map(p => {
          const c = p === "TODOS" ? scs.length : conteoPorPerfil(p);
          const active = perfilFiltro === p;
          return (
            <button key={p} onClick={() => setPerfilFiltro(p)}
              style={{ padding: "5px 12px", fontSize: 11, fontWeight: 600, borderRadius: 4,
                border: active ? "none" : "1px solid #e4e7ec",
                background: active ? "#0f172a" : "#fff",
                color: active ? "#fff" : "#475569",
                cursor: "pointer", fontFamily: "'Geist', sans-serif" }}>
              {p === "TODOS" ? "Todos" : p}
              <span style={{ marginLeft: 6, opacity: 0.6 }}>({c})</span>
            </button>
          );
        })}
      </div>

      {/* Tabla por SC */}
      <div className="form-card" style={{ padding: 0, overflow: "hidden" }}>
        <div style={{ padding: "10px 16px", borderBottom: "1px solid #f1f5f9", background: "#f8fafc" }}>
          <div style={{ fontSize: 11, color: "#64748b" }}>Hacé click en cualquier número para ver el detalle de ese SC</div>
        </div>
        <div style={{ overflowX: "auto" }}>
          <table style={{ width: "100%", borderCollapse: "collapse" }}>
            <thead>
              <tr style={{ background: "#f8fafc", borderBottom: "1px solid #e2e8f0" }}>
                <th style={pm_thStyle}>SC</th>
                <th style={pm_thStyleR}>Ofrecidas</th>
                <th style={pm_thStyleR}>Aceptadas</th>
                <th style={pm_thStyleR}>Rechazadas</th>
                <th style={pm_thStyleR}>Ejecutadas</th>
                <th style={pm_thStyleR}>No present.</th>
                <th style={pm_thStyleR}>Cumpl.</th>
                <th style={{ ...pm_thStyle, textAlign: "center" }}>Perfil</th>
              </tr>
            </thead>
            <tbody>
              {filtrados.map(s => {
                const cumpl = s.aceptadas > 0 ? (s.ejecutadas / s.aceptadas * 100).toFixed(0) : 0;
                const cumplColor = cumpl >= 90 ? "#047857" : cumpl >= 70 ? "#92400e" : "#991b1b";
                const linkStyle = (color, bold = false) => ({
                  background: "transparent", border: "none", cursor: "pointer",
                  color, fontWeight: bold ? 700 : 400, padding: 0,
                  fontFamily: "inherit", fontSize: 12, fontVariantNumeric: "tabular-nums",
                  textDecoration: "underline", textDecorationColor: "transparent",
                });
                return (
                  <tr key={s.service_center} style={{ borderBottom: "1px solid #f1f5f9" }}>
                    <td style={{ ...pm_tdStyle, fontFamily: "monospace", fontWeight: 700 }}>{s.service_center}</td>
                    <td style={pm_tdStyleR}>
                      <button onClick={() => abrirOfrecidas(s.service_center)} style={linkStyle("#0f172a")}
                        onMouseEnter={e => e.currentTarget.style.textDecorationColor = "#0f172a"}
                        onMouseLeave={e => e.currentTarget.style.textDecorationColor = "transparent"}>{s.ofrecidas}</button>
                    </td>
                    <td style={pm_tdStyleR}>
                      <button onClick={() => abrirAceptadas(s.service_center)} style={linkStyle("#0891b2")}
                        onMouseEnter={e => e.currentTarget.style.textDecorationColor = "#0891b2"}
                        onMouseLeave={e => e.currentTarget.style.textDecorationColor = "transparent"}>{s.aceptadas}</button>
                    </td>
                    <td style={pm_tdStyleR}>
                      <button onClick={() => abrirRechazadas(s.service_center)} style={linkStyle(s.rechazadas > 50 ? "#991b1b" : "#64748b")}
                        onMouseEnter={e => e.currentTarget.style.textDecorationColor = s.rechazadas > 50 ? "#991b1b" : "#64748b"}
                        onMouseLeave={e => e.currentTarget.style.textDecorationColor = "transparent"}>{s.rechazadas}</button>
                    </td>
                    <td style={pm_tdStyleR}>
                      <button onClick={() => abrirEjecutadas(s.service_center)} style={linkStyle("#047857")}
                        onMouseEnter={e => e.currentTarget.style.textDecorationColor = "#047857"}
                        onMouseLeave={e => e.currentTarget.style.textDecorationColor = "transparent"}>{s.ejecutadas}</button>
                    </td>
                    <td style={pm_tdStyleR}>
                      <button onClick={() => abrirNoPresentadas(s.service_center)} style={linkStyle(s.no_presentadas > 20 ? "#991b1b" : "#92400e", true)}
                        onMouseEnter={e => e.currentTarget.style.textDecorationColor = s.no_presentadas > 20 ? "#991b1b" : "#92400e"}
                        onMouseLeave={e => e.currentTarget.style.textDecorationColor = "transparent"}>{s.no_presentadas}</button>
                    </td>
                    <td style={{ ...pm_tdStyleR, fontWeight: 700, color: cumplColor }}>{cumpl}%</td>
                    <td style={{ ...pm_tdStyle, textAlign: "center" }}><PerfilBadgeMX perfil={s.perfil} /></td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {/* Alertas */}
      {problematicos.length > 0 && (
        <div style={{ background: "#fef2f2", borderLeft: "4px solid #b91c1c", borderRadius: 8, padding: 16, marginTop: 16 }}>
          <div style={{ fontSize: 13, fontWeight: 700, color: "#0f172a", marginBottom: 8 }}>⚠ SCs críticos requieren acción inmediata</div>
          <div style={{ fontSize: 12, color: "#334155", lineHeight: 1.7 }}>
            {problematicos.map(s => {
              const cumpl = s.aceptadas > 0 ? Math.round(s.ejecutadas / s.aceptadas * 100) : 0;
              return (
                <div key={s.service_center} style={{ marginBottom: 6 }}>
                  <strong>{s.service_center}:</strong> {s.ofrecidas} ofrecidas, aceptó {s.aceptadas}, ejecutó {s.ejecutadas} ({cumpl}% cumplimiento). {s.no_presentadas} no presentadas.
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* ════════════════════════════════════════════════════════════════════ */}
      {/* BLOQUE: Trayectorias de Estado                                      */}
      {/* ════════════════════════════════════════════════════════════════════ */}
      {trayectorias.length > 0 && (() => {
        const conCambio = trayectorias.filter(t => t.tipo === "Con cambio" && Number(t.cantidad_ofertas) > 0);
        const sinCambio = trayectorias.filter(t => t.tipo === "Sin cambio");
        const totalCambios = conCambio.reduce((a, t) => a + Number(t.cantidad_ofertas), 0);
        const totalSinCambio = sinCambio.reduce((a, t) => a + Number(t.cantidad_ofertas), 0);
        const totalOfertas = totalCambios + totalSinCambio;
        const pctEstable = totalOfertas > 0 ? ((totalSinCambio / totalOfertas) * 100).toFixed(1) : "0.0";

        // Mapeo de etiquetas amigables
        const etiquetasTray = {
          "accepted → rejected": { 
            label: "Aceptada → Rechazada", 
            emoji: "🔴", 
            color: "#991b1b", 
            bg: "linear-gradient(135deg, #fef2f2 0%, #fee2e2 100%)", 
            border: "#fecaca",
            descripcion: "Echarse atrás" 
          },
          "accepted → canceled": { 
            label: "Aceptada → Cancelada", 
            emoji: "🟠", 
            color: "#9a3412", 
            bg: "linear-gradient(135deg, #fff7ed 0%, #fed7aa 100%)", 
            border: "#fdba74",
            descripcion: "MELI canceló" 
          },
          "pending → accepted": { 
            label: "Pending → Aceptada", 
            emoji: "🟢", 
            color: "#166534", 
            bg: "linear-gradient(135deg, #f0fdf4 0%, #bbf7d0 100%)", 
            border: "#86efac",
            descripcion: "Recuperación tardía" 
          },
          "pending → rejected": { 
            label: "Pending → Rechazada", 
            emoji: "🟡", 
            color: "#854d0e", 
            bg: "linear-gradient(135deg, #fefce8 0%, #fef08a 100%)", 
            border: "#fde047",
            descripcion: "Decisión consciente" 
          },
        };
        const pendingPending = sinCambio.find(t => t.trayectoria === "pending → pending");

        return (
          <div className="form-card" style={{ marginTop: 20, background: "linear-gradient(180deg, #fff 0%, #f8fafc 100%)" }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 16 }}>
              <div>
                <div className="form-title" style={{ marginBottom: 4 }}>🔄 Trayectorias de Estado</div>
                <div style={{ fontSize: 12, color: "#64748b" }}>
                  Cómo evolucionan las ofertas entre snapshots
                  <span style={{ marginLeft: 8, color: "#94a3b8" }}>· click en cualquier card para ver detalle</span>
                </div>
              </div>
              <div style={{ textAlign: "right", fontSize: 11, color: "#64748b" }}>
                <div><strong style={{ color: "#10b981" }}>{pctEstable}%</strong> estables</div>
                <div><strong style={{ color: "#dc2626" }}>{totalCambios}</strong> con cambio</div>
              </div>
            </div>

            {/* Cards de cambios */}
            {conCambio.length > 0 && (
              <div>
                <div style={{ fontSize: 11, fontWeight: 700, color: "#475569", textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 10 }}>
                  ⚠️ Atención · Cambios de estado
                </div>
                <div style={{ display: "grid", gridTemplateColumns: `repeat(${Math.min(conCambio.length, 4)}, 1fr)`, gap: 12, marginBottom: 16 }}>
                  {conCambio.map(t => {
                    const meta = etiquetasTray[t.trayectoria] || { 
                      label: t.trayectoria, emoji: "❓", color: "#475569", 
                      bg: "#f8fafc", border: "#e2e8f0", descripcion: "" 
                    };
                    return (
                      <div key={t.trayectoria}
                        onClick={() => abrirTrayectoria(t.trayectoria)}
                        style={{ 
                          background: meta.bg, 
                          borderRadius: 10, 
                          padding: 14, 
                          cursor: "pointer", 
                          border: `1px solid ${meta.border}`,
                          transition: "transform 0.15s",
                        }}
                        onMouseEnter={e => e.currentTarget.style.transform = "scale(1.02)"}
                        onMouseLeave={e => e.currentTarget.style.transform = "scale(1)"}>
                        <div style={{ fontSize: 10, fontWeight: 700, color: meta.color, textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 6, display: "flex", justifyContent: "space-between" }}>
                          <span>{meta.emoji} {meta.label}</span>
                          <span style={{ fontSize: 9, opacity: 0.7 }}>VER →</span>
                        </div>
                        <div style={{ fontSize: 26, fontWeight: 800, color: meta.color, fontVariantNumeric: "tabular-nums", lineHeight: 1 }}>
                          {Number(t.cantidad_ofertas).toLocaleString()}
                        </div>
                        <div style={{ fontSize: 11, color: meta.color, opacity: 0.85, marginTop: 4, fontStyle: "italic" }}>
                          {meta.descripcion}
                        </div>
                        <div style={{ fontSize: 10, color: "#64748b", marginTop: 6, paddingTop: 6, borderTop: `1px dashed ${meta.border}` }}>
                          {t.cantidad_scs} SC{t.cantidad_scs === 1 ? "" : "s"}: <strong>{t.scs_involucrados}</strong>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            {/* Card de oportunidades perdidas (pending → pending) */}
            {pendingPending && Number(pendingPending.cantidad_ofertas) > 0 && (
              <div
                onClick={() => abrirTrayectoria("pending → pending")}
                style={{ 
                  background: "linear-gradient(135deg, #fefce8 0%, #fef9c3 100%)", 
                  borderLeft: "4px solid #ca8a04", 
                  borderRadius: 8, 
                  padding: 14, 
                  marginBottom: 16,
                  cursor: "pointer",
                  display: "flex",
                  justifyContent: "space-between",
                  alignItems: "center",
                  transition: "transform 0.15s",
                }}
                onMouseEnter={e => e.currentTarget.style.transform = "scale(1.005)"}
                onMouseLeave={e => e.currentTarget.style.transform = "scale(1)"}>
                <div>
                  <div style={{ fontSize: 11, fontWeight: 700, color: "#854d0e", textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 4 }}>
                    🟡 Oportunidades perdidas
                  </div>
                  <div style={{ fontSize: 13, color: "#0f172a", fontWeight: 600 }}>
                    Pending sin respuesta
                  </div>
                  <div style={{ fontSize: 11, color: "#64748b", marginTop: 2 }}>
                    MELI las rota a otro carrier = negocio perdido directo · SCs: <strong>{pendingPending.scs_involucrados}</strong>
                  </div>
                </div>
                <div style={{ textAlign: "right" }}>
                  <div style={{ fontSize: 30, fontWeight: 800, color: "#854d0e", fontVariantNumeric: "tabular-nums", lineHeight: 1 }}>
                    {Number(pendingPending.cantidad_ofertas).toLocaleString()}
                  </div>
                  <div style={{ fontSize: 9, color: "#854d0e", opacity: 0.7, marginTop: 2 }}>VER DETALLE →</div>
                </div>
              </div>
            )}

            {/* Resumen de estables */}
            {sinCambio.length > 0 && (
              <div style={{ 
                background: "#f0fdf4", 
                border: "1px solid #bbf7d0", 
                borderRadius: 8, 
                padding: 12, 
                fontSize: 12, 
                color: "#166534" 
              }}>
                ✅ <strong>Comportamiento estable:</strong> {totalSinCambio.toLocaleString()} ofertas mantuvieron su estado ({pctEstable}% del total)
                <span style={{ marginLeft: 6, color: "#64748b", fontSize: 11 }}>
                  · {sinCambio.filter(t => t.trayectoria !== "pending → pending").map(t => 
                      `${t.trayectoria.split(" → ")[0]}: ${Number(t.cantidad_ofertas).toLocaleString()}`
                    ).join(" · ")}
                </span>
              </div>
            )}
          </div>
        );
      })()}

      {/* ════════════════════════════════════════════════════════════════════ */}
      {/* BLOQUE: Matrix Embudo ↔ Cumplimiento                                */}
      {/* ════════════════════════════════════════════════════════════════════ */}
      {matrixData.length > 0 && (() => {
        // Totales agregados del período
        const totAceptadas = matrixData.reduce((a, r) => a + Number(r.tr_aceptadas || 0), 0);
        const totEjecutadas = matrixData.reduce((a, r) => a + Number(r.rutas_ejecutadas || 0), 0);
        const totLeakage = matrixData.reduce((a, r) => a + Number(r.aceptadas_no_ejecutadas || 0), 0);
        const totSDDPre = matrixData.reduce((a, r) => a + Number(r.ejecutadas_sin_aceptar || 0), 0);
        const cumplGlobal = totAceptadas > 0 ? ((totAceptadas - totLeakage) / totAceptadas * 100) : 0;

        // Casos críticos: leakage > 20% y al menos 3 ofertas perdidas
        const criticos = matrixData
          .filter(r => Number(r.aceptadas_no_ejecutadas) >= 3 && Number(r.cumplimiento_pct) < 80)
          .sort((a, b) => Number(a.cumplimiento_pct) - Number(b.cumplimiento_pct))
          .slice(0, 10);

        return (
          <div className="form-card" style={{ marginTop: 20, background: "linear-gradient(180deg, #fff 0%, #f8fafc 100%)" }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 16 }}>
              <div>
                <div className="form-title" style={{ marginBottom: 4 }}>🎯 Matrix Embudo ↔ Cumplimiento</div>
                <div style={{ fontSize: 12, color: "#64748b" }}>
                  De las que aceptamos, ¿cuáles realmente se ejecutaron? Vinculación agregada por SC + fecha
                  <span style={{ marginLeft: 8, color: "#94a3b8" }}>· click en cualquier celda para ver detalle</span>
                </div>
              </div>
            </div>

            {/* Resumen de KPIs del período */}
            <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 12, marginBottom: 16 }}>
              <div style={{ background: "linear-gradient(135deg, #ecfeff 0%, #cffafe 100%)", borderRadius: 8, padding: 12, border: "1px solid #a5f3fc" }}>
                <div style={{ fontSize: 10, fontWeight: 700, color: "#155e75", textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 4 }}>Aceptadas (TR)</div>
                <div style={{ fontSize: 24, fontWeight: 800, color: "#0e7490", fontVariantNumeric: "tabular-nums", lineHeight: 1 }}>{totAceptadas.toLocaleString()}</div>
              </div>
              <div style={{ background: "linear-gradient(135deg, #f0fdf4 0%, #bbf7d0 100%)", borderRadius: 8, padding: 12, border: "1px solid #86efac" }}>
                <div style={{ fontSize: 10, fontWeight: 700, color: "#14532d", textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 4 }}>Ejecutadas (Maestro)</div>
                <div style={{ fontSize: 24, fontWeight: 800, color: "#166534", fontVariantNumeric: "tabular-nums", lineHeight: 1 }}>{totEjecutadas.toLocaleString()}</div>
              </div>
              <div style={{ background: "linear-gradient(135deg, #fef2f2 0%, #fee2e2 100%)", borderRadius: 8, padding: 12, border: "1px solid #fecaca" }}>
                <div style={{ fontSize: 10, fontWeight: 700, color: "#7f1d1d", textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 4 }}>🔴 Leakage</div>
                <div style={{ fontSize: 24, fontWeight: 800, color: "#991b1b", fontVariantNumeric: "tabular-nums", lineHeight: 1 }}>{totLeakage.toLocaleString()}</div>
                <div style={{ fontSize: 10, color: "#991b1b", opacity: 0.85, marginTop: 4 }}>aceptadas no ejecutadas</div>
              </div>
              <div style={{ background: "linear-gradient(135deg, #fefce8 0%, #fef9c3 100%)", borderRadius: 8, padding: 12, border: "1px solid #fde047" }}>
                <div style={{ fontSize: 10, fontWeight: 700, color: "#713f12", textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 4 }}>🟡 SDD pre-asignadas</div>
                <div style={{ fontSize: 24, fontWeight: 800, color: "#854d0e", fontVariantNumeric: "tabular-nums", lineHeight: 1 }}>{totSDDPre.toLocaleString()}</div>
                <div style={{ fontSize: 10, color: "#854d0e", opacity: 0.85, marginTop: 4 }}>sin pasar por TR</div>
              </div>
            </div>

            {/* Cumplimiento global */}
            <div style={{
              background: cumplGlobal >= 95 ? "#f0fdf4" : cumplGlobal >= 85 ? "#fefce8" : "#fef2f2",
              border: `1px solid ${cumplGlobal >= 95 ? "#bbf7d0" : cumplGlobal >= 85 ? "#fde047" : "#fecaca"}`,
              borderRadius: 8,
              padding: 14,
              marginBottom: 16,
              display: "flex",
              justifyContent: "space-between",
              alignItems: "center",
            }}>
              <div>
                <div style={{ fontSize: 11, fontWeight: 700, color: "#475569", textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 4 }}>
                  Cumplimiento global del período
                </div>
                <div style={{ fontSize: 12, color: "#64748b" }}>
                  De cada 100 aceptadas, {Math.round(cumplGlobal)} llegaron a operar
                </div>
              </div>
              <div style={{ 
                fontSize: 36, 
                fontWeight: 800, 
                color: cumplGlobal >= 95 ? "#166534" : cumplGlobal >= 85 ? "#854d0e" : "#991b1b",
                fontVariantNumeric: "tabular-nums", 
                lineHeight: 1 
              }}>
                {cumplGlobal.toFixed(1)}%
              </div>
            </div>

            {/* Casos críticos */}
            {criticos.length > 0 && (
              <div>
                <div style={{ fontSize: 11, fontWeight: 700, color: "#475569", textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 10 }}>
                  🚨 Top {criticos.length} casos críticos · click para ver detalle
                </div>
                <div style={{ overflowX: "auto" }}>
                  <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
                    <thead>
                      <tr style={{ background: "#f1f5f9", borderBottom: "1px solid #cbd5e1" }}>
                        <th style={{ ...pm_thStyle, textAlign: "left" }}>SC</th>
                        <th style={pm_thStyle}>Fecha</th>
                        <th style={{ ...pm_thStyle, textAlign: "right" }}>Aceptadas</th>
                        <th style={{ ...pm_thStyle, textAlign: "right" }}>Ejecutadas</th>
                        <th style={{ ...pm_thStyle, textAlign: "right" }}>No ejec.</th>
                        <th style={{ ...pm_thStyle, textAlign: "right" }}>Cumpl.%</th>
                        <th style={{ ...pm_thStyle, textAlign: "left" }}>Interpretación</th>
                      </tr>
                    </thead>
                    <tbody>
                      {criticos.map((row, idx) => {
                        const cumpl = Number(row.cumplimiento_pct);
                        const cumplColor = cumpl >= 95 ? "#166534" : cumpl >= 85 ? "#854d0e" : "#991b1b";
                        return (
                          <tr key={`${row.sc}-${row.fecha}-${idx}`} style={{ borderBottom: "1px solid #e2e8f0" }}>
                            <td style={{ ...pm_tdStyle, fontWeight: 700 }}>{row.sc}</td>
                            <td style={{ ...pm_tdStyle, textAlign: "center" }}>{row.fecha}</td>
                            <td style={pm_tdStyleR}>
                              <button onClick={() => abrirMatrixDetalle(row.fecha, row.sc, "aceptadas")}
                                style={linkStyle("#0e7490", true)}
                                onMouseEnter={e => e.currentTarget.style.textDecorationColor = "#0e7490"}
                                onMouseLeave={e => e.currentTarget.style.textDecorationColor = "transparent"}>
                                {row.tr_aceptadas}
                              </button>
                            </td>
                            <td style={pm_tdStyleR}>
                              <button onClick={() => abrirMatrixDetalle(row.fecha, row.sc, "ejecutadas")}
                                style={linkStyle("#166534", true)}
                                onMouseEnter={e => e.currentTarget.style.textDecorationColor = "#166534"}
                                onMouseLeave={e => e.currentTarget.style.textDecorationColor = "transparent"}>
                                {row.rutas_ejecutadas}
                              </button>
                            </td>
                            <td style={{ ...pm_tdStyleR, color: "#991b1b", fontWeight: 700 }}>{row.aceptadas_no_ejecutadas}</td>
                            <td style={{ ...pm_tdStyleR, fontWeight: 700, color: cumplColor }}>{cumpl.toFixed(1)}%</td>
                            <td style={{ ...pm_tdStyle, fontSize: 11, color: "#475569" }}>{row.interpretacion}</td>
                          </tr>
                        );
                      })}
                    </tbody>
                  </table>
                </div>
              </div>
            )}

            {criticos.length === 0 && (
              <div style={{ background: "#f0fdf4", border: "1px solid #bbf7d0", borderRadius: 8, padding: 14, fontSize: 12, color: "#166534", textAlign: "center" }}>
                ✅ Sin casos críticos en el período. Todas las SCs cumplieron por encima del 80% o tuvieron pocas ofertas no ejecutadas.
              </div>
            )}
          </div>
        );
      })()}

    </div>
  );
}

// ── SCORE (sin cambios) ────────────────────────────────────────────────────
function PoolMeliScore({ scores, resumen }) {
  const r = resumen || {};
  const totalEvaluados = scores.length;
  const top = scores.slice(0, 7);
  const cuentas = {
    A: r.score_a ?? scores.filter(s => s.categoria_score === "A").length,
    B: r.score_b ?? scores.filter(s => s.categoria_score === "B").length,
    C: r.score_c ?? scores.filter(s => s.categoria_score === "C").length,
    D: r.score_d ?? scores.filter(s => s.categoria_score === "D").length,
  };

  const cats = [
    { cat: "A", label: "Élite",    range: "80-100", color: "#047857", desc: "Driver A+ - alta performance" },
    { cat: "B", label: "Sólido",   range: "60-79",  color: "#0891b2", desc: "Confiable y consistente" },
    { cat: "C", label: "Promedio", range: "40-59",  color: "#ca8a04", desc: "Espacio para mejorar" },
    { cat: "D", label: "Riesgo",   range: "0-39",   color: "#b91c1c", desc: "Requiere atención" },
  ];

  const dimensiones = [
    { label: "Volumen",       pts: 30, desc: "Días trabajados",   color: "#1a3a6b" },
    { label: "Performance",   pts: 25, desc: "DPPH (paq/hora)",   color: "#0891b2" },
    { label: "Confiabilidad", pts: 20, desc: "% entrega exitosa", color: "#F47B20" },
    { label: "Compliance",    pts: 15, desc: "Master + CURP",     color: "#ca8a04" },
    { label: "Estabilidad",   pts: 10, desc: "Mismo SC",          color: "#94a3b8" },
  ];

  return (
    <div className="pg">
      <div style={{ background: "linear-gradient(135deg, #1a3a6b 0%, #0f2647 100%)", borderRadius: 12, padding: 24, color: "#fff", marginBottom: 16 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
          <div>
            <div style={{ fontSize: 10, fontWeight: 700, opacity: 0.8, textTransform: "uppercase", letterSpacing: 1.2, marginBottom: 6 }}>Innovación Brain</div>
            <div style={{ fontSize: 22, fontWeight: 700, marginBottom: 6 }}>Score de Compromiso por Driver</div>
            <div style={{ fontSize: 13, opacity: 0.9, maxWidth: 600, lineHeight: 1.5 }}>
              Calificación 0-100 que combina volumen, performance, confiabilidad, compliance y estabilidad.
            </div>
          </div>
          <div style={{ textAlign: "right" }}>
            <div style={{ fontSize: 44, fontWeight: 700, lineHeight: 1 }}>{totalEvaluados}</div>
            <div style={{ fontSize: 11, opacity: 0.8, marginTop: 4 }}>drivers evaluados</div>
          </div>
        </div>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 12, marginBottom: 16 }}>
        {cats.map(c => {
          const pct = totalEvaluados > 0 ? Math.round(cuentas[c.cat] / totalEvaluados * 100) : 0;
          return (
            <div key={c.cat} className="form-card" style={{ marginBottom: 0 }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 8 }}>
                <div style={{ fontSize: 28, fontWeight: 700, color: c.color, lineHeight: 1 }}>{c.cat}</div>
                <div style={{ fontSize: 10, fontFamily: "monospace", color: "#94a3b8" }}>{c.range} pts</div>
              </div>
              <div style={{ fontSize: 22, fontWeight: 700, color: "#0f172a", lineHeight: 1, marginBottom: 4 }}>{cuentas[c.cat]}</div>
              <div style={{ fontSize: 12, fontWeight: 600, color: "#334155", marginBottom: 2 }}>{c.label}</div>
              <div style={{ fontSize: 10, color: "#64748b", marginBottom: 10 }}>{c.desc}</div>
              <div style={{ height: 4, background: "#f1f5f9", borderRadius: 2, overflow: "hidden" }}>
                <div style={{ height: "100%", width: `${pct}%`, background: c.color }}></div>
              </div>
              <div style={{ fontSize: 10, color: "#94a3b8", marginTop: 4 }}>{pct}% del total</div>
            </div>
          );
        })}
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "2fr 1fr", gap: 12 }}>
        <div className="form-card" style={{ marginBottom: 0 }}>
          <div className="form-title" style={{ marginBottom: 4 }}>Top 7 Drivers Élite</div>
          <div style={{ fontSize: 11, color: "#64748b", marginBottom: 12 }}>Score 90+ — los pilares de la operación</div>
          {top.map((d, i) => (
            <div key={d.driver_id || d.nombre} style={{ display: "flex", alignItems: "center", gap: 12, padding: "10px 0", borderBottom: i === top.length - 1 ? "none" : "1px solid #f1f5f9" }}>
              <div style={{ fontSize: 11, color: "#cbd5e1", fontFamily: "monospace", width: 24 }}>#{i + 1}</div>
              <ScoreBadgeMX cat={d.categoria_score} />
              <div style={{ flex: 1 }}>
                <div style={{ fontSize: 13, fontWeight: 600, color: "#0f172a" }}>{d.nombre}</div>
                <div style={{ fontSize: 11, color: "#64748b", marginTop: 2 }}>
                  {d.scs_operados || "—"} · {d.dias_trabajados} días · DPPH {d.dpph_promedio?.toFixed?.(1) ?? "—"} · {d.entrega_exitosa_pct?.toFixed?.(1) ?? "—"}% entrega
                </div>
              </div>
              <div style={{ textAlign: "right" }}>
                <div style={{ fontSize: 22, fontWeight: 700, color: "#047857", lineHeight: 1 }}>{d.score_total?.toFixed?.(1) ?? "—"}</div>
                <div style={{ fontSize: 9, color: "#94a3b8", textTransform: "uppercase", letterSpacing: 0.5 }}>score</div>
              </div>
            </div>
          ))}
        </div>

        <div className="form-card" style={{ marginBottom: 0 }}>
          <div className="form-title" style={{ marginBottom: 4 }}>Composición del score</div>
          <div style={{ fontSize: 11, color: "#64748b", marginBottom: 16 }}>5 dimensiones · 100 pts total</div>
          {dimensiones.map(d => (
            <div key={d.label} style={{ marginBottom: 12 }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 4 }}>
                <span style={{ fontSize: 12, fontWeight: 600, color: "#0f172a" }}>{d.label}</span>
                <span style={{ fontSize: 13, fontWeight: 700, color: d.color }}>
                  {d.pts}<span style={{ fontSize: 10, color: "#94a3b8", marginLeft: 2 }}>pts</span>
                </span>
              </div>
              <div style={{ height: 5, background: "#f1f5f9", borderRadius: 3, overflow: "hidden", marginBottom: 4 }}>
                <div style={{ height: "100%", width: `${d.pts / 30 * 100}%`, background: d.color }}></div>
              </div>
              <div style={{ fontSize: 10, color: "#64748b" }}>{d.desc}</div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

// ── HALLAZGOS ──────────────────────────────────────────────────────────────
function PoolMeliHallazgos({ drivers, vehiculos, scs, scores, resumen, setModal, setVista, mesGlobal }) {
  const r = resumen || {};
  const driversFantasma = drivers.filter(d => d.categoria === "fantasma");
  const vehiculosFantasma = vehiculos.filter(v => v.categoria === "fantasma");
  const scsProblematicos = scs.filter(s => s.perfil === "PROBLEMATICO");
  const driversIzombi = drivers.filter(d => d.en_master && (!d.curp || d.curp === "") && (!d.viajes_total || d.viajes_total === 0));
  const driversElite = scores.filter(s => s.categoria_score === "A").slice(0, 7);
  const peorSC = [...scsProblematicos].sort((a, b) => (a.pct_cumplimiento || 0) - (b.pct_cumplimiento || 0))[0];
  const scsBajaEntrega = scs.filter(s => s.ejecutadas > 50 && s.pct_cumplimiento < 90 && s.perfil !== "PROBLEMATICO");
  const topFantasma = driversFantasma.sort((a, b) => (b.viajes_total || 0) - (a.viajes_total || 0))[0];
  const fantasmaMultiSC = driversFantasma.find(d => (d.cantidad_scs || 0) >= 2);

  // SDD no realizados por SC (se carga según el mes global)
  const [sddNoRealizados, setSddNoRealizados] = useState([]);
  // Pending viejos (sin respuesta del carrier en fechas pasadas)
  const [pendientesViejos, setPendientesViejos] = useState([]);
  useEffect(() => {
    if (!mesGlobal) return;
    let alive = true;
    (async () => {
      try {
        const { desde, hasta } = rangoMesGlobal(mesGlobal);
        const [rsdd, rpend] = await Promise.all([
          sb.rpc("get_hallazgo_sdd_no_realizados", { fecha_desde: desde, fecha_hasta: hasta }),
          sb.rpc("get_hallazgo_pendientes_viejos", { fecha_desde: desde, fecha_hasta: hasta }),
        ]);
        if (!alive) return;
        if (rsdd.error) {
          console.error("Error cargando SDD no realizados:", rsdd.error);
          setSddNoRealizados([]);
        } else {
          setSddNoRealizados(rsdd.data || []);
        }
        if (rpend.error) {
          console.error("Error cargando pendientes viejos:", rpend.error);
          setPendientesViejos([]);
        } else {
          setPendientesViejos(rpend.data || []);
        }
      } catch (e) {
        console.error("Error cargando hallazgos del mes:", e);
        if (alive) {
          setSddNoRealizados([]);
          setPendientesViejos([]);
        }
      }
    })();
    return () => { alive = false; };
  }, [mesGlobal?.anio, mesGlobal?.mes]);

  const totalSDDNoRealizadas = sddNoRealizados.reduce((a, s) => a + Number(s.sdd_no_realizadas || 0), 0);
  const peorSCsdd = sddNoRealizados[0];
  
  // Pendientes con fecha de operación pasada (críticos)
  const pendientesPasados = pendientesViejos.filter(p => Number(p.dias_pasados) > 0);
  const totalPendPasados = pendientesPasados.length;
  // Agrupar por SC para detectar concentración
  const pendPorSC = {};
  pendientesPasados.forEach(p => {
    pendPorSC[p.service_center] = (pendPorSC[p.service_center] || 0) + 1;
  });
  const peorSCpend = Object.entries(pendPorSC).sort((a, b) => b[1] - a[1])[0];

  const verSDDNoRealizados = () => setModal({
    titulo: `SDD no realizadas por SC · ${NOMBRES_MES[mesGlobal.mes - 1]} ${mesGlobal.anio}`,
    filas: sddNoRealizados,
    nombreArchivo: `sdd_no_realizados_${mesGlobal.anio}_${mesGlobal.mes}`,
  });
  
  const verPendientesViejos = () => setModal({
    titulo: `Pending sin respuesta · ${NOMBRES_MES[mesGlobal.mes - 1]} ${mesGlobal.anio}`,
    filas: pendientesViejos,
    nombreArchivo: `pendientes_${mesGlobal.anio}_${mesGlobal.mes}`,
  });

  const verSCsProblematicos = () => setModal({ titulo: `SCs Problemáticos (${scsProblematicos.length})`, filas: scsProblematicos, nombreArchivo: "scs_problematicos" });
  const verDriversFantasma = () => setModal({ titulo: `Drivers Fantasma (${driversFantasma.length})`, filas: driversFantasma, nombreArchivo: "drivers_fantasma" });
  const verVehFantasma = () => setModal({ titulo: `Vehículos Fantasma (${vehiculosFantasma.length})`, filas: vehiculosFantasma, nombreArchivo: "vehiculos_fantasma" });
  const verIzombi = () => setModal({ titulo: `IDs Zombi en Master (${driversIzombi.length})`, filas: driversIzombi, nombreArchivo: "ids_zombi" });
  const verElite = () => setModal({ titulo: `Top Drivers Élite (${driversElite.length})`, filas: driversElite, nombreArchivo: "drivers_elite" });
  const verPlanifSinMaster = async () => {
    setModal({ titulo: "Cargando…", filas: [], nombreArchivo: "planif" });
    try {
      const { data, error } = await sb.from("vw_meli_hallazgo_planif_sin_master").select("*");
      if (error) throw error;
      setModal({ titulo: `Drivers planificados sin master (${(data || []).length})`, filas: data || [], nombreArchivo: "planif_sin_master" });
    } catch (e) { setModal({ titulo: "Error", filas: [{ error: e.message }], nombreArchivo: "error" }); }
  };
  const verSMX6Diario = async () => {
    setModal({ titulo: "Cargando…", filas: [], nombreArchivo: "smx6" });
    try {
      const { data, error } = await sb.from("vw_meli_hallazgo_smx6_diario").select("*").order("fecha");
      if (error) throw error;
      setModal({ titulo: `SMX6 día por día (${(data || []).length})`, filas: data || [], nombreArchivo: "smx6_no_pres_diario" });
    } catch (e) { setModal({ titulo: "Error", filas: [{ error: e.message }], nombreArchivo: "error" }); }
  };

  const hallazgos = [];

  // ─── HALLAZGO CRÍTICO: SDD no realizadas (compromiso obligatorio con MELI) ──
  if (peorSCsdd && Number(peorSCsdd.sdd_no_realizadas) > 0) {
    hallazgos.push({
      sev: "CRITICO", categoria: "Compromiso SDD",
      titulo: `${peorSCsdd.service_center} — ${peorSCsdd.sdd_no_realizadas} viajes SDD no ejecutados`,
      desc: `La flota fija (Súper Dedicada) es un compromiso obligatorio con MELI. ` +
            `${peorSCsdd.service_center} aceptó ${peorSCsdd.sdd_aceptadas} SDD pero solo ejecutó ${peorSCsdd.sdd_ejecutadas} ` +
            `(${peorSCsdd.pct_no_presentado}% no-show, en ${peorSCsdd.dias_con_no_show} días distintos). ` +
            `Total mensual MX: ${totalSDDNoRealizadas} SDD comprometidas no realizadas.`,
      metricas: [
        { l: "SDD no realizadas", v: peorSCsdd.sdd_no_realizadas, color: "#991b1b" },
        { l: "% no-show", v: `${peorSCsdd.pct_no_presentado}%`, color: "#991b1b" },
        { l: "Días con incidencia", v: peorSCsdd.dias_con_no_show, color: "#991b1b" },
        { l: "Total MX", v: totalSDDNoRealizadas, color: "#92400e" },
      ],
      accion: { label: "Ver todos los SCs", onClick: verSDDNoRealizados },
    });
  }

  // ─── HALLAZGO CRÍTICO: Pendientes con fecha pasada (sin respuesta del carrier) ──
  if (totalPendPasados > 0) {
    const fechasMasViejas = [...pendientesPasados].sort((a, b) => Number(b.dias_pasados) - Number(a.dias_pasados));
    const masVieja = fechasMasViejas[0];
    hallazgos.push({
      sev: "CRITICO", categoria: "SLA Carrier",
      titulo: `${totalPendPasados} viajes pending sin respuesta · fecha de operación ya pasó`,
      desc: `MELI ofreció ${totalPendPasados} viajes que Bigticket NUNCA respondió (ni aceptó ni rechazó). ` +
            `Las fechas de operación ya pasaron — son ofertas perdidas y posible incumplimiento de SLA. ` +
            (peorSCpend ? `Concentración: ${peorSCpend[0]} (${peorSCpend[1]} viajes). ` : '') +
            `El más viejo es del ${masVieja.fecha_operacion} (${masVieja.dias_pasados} días sin respuesta).`,
      metricas: [
        { l: "Pending vencidos", v: totalPendPasados, color: "#991b1b" },
        { l: "SC con más casos", v: peorSCpend ? peorSCpend[0] : "—", color: "#991b1b" },
        { l: "Días más antiguo", v: masVieja.dias_pasados, color: "#991b1b" },
      ],
      accion: { label: "Ver lista completa", onClick: verPendientesViejos },
    });
  }

  if (peorSC) {
    hallazgos.push({
      sev: "CRITICO", categoria: "Operación",
      titulo: `${peorSC.service_center} — Operación crónicamente disfuncional`,
      desc: `${peorSC.aceptadas} aceptadas, solo ${peorSC.ejecutadas} ejecutadas (${peorSC.pct_cumplimiento}% cumplimiento). ${peorSC.no_presentadas} viajes comprometidos sin entregar — patrón sostenido.`,
      metricas: [
        { l: "Cumplimiento", v: `${peorSC.pct_cumplimiento}%`, color: "#991b1b" },
        { l: "No presentadas", v: peorSC.no_presentadas, color: "#991b1b" },
        { l: "Días con incidencia", v: "19", color: "#991b1b" },
      ],
      accion: { label: "Ver día por día", onClick: verSMX6Diario },
      accion2: { label: "Ir a Ciclo", onClick: () => setVista("ciclo") },
    });
  }

  const spy = scs.find(s => s.service_center === "SPY1");
  if (spy && spy.ejecutadas === 0 && spy.ofrecidas > 0) {
    hallazgos.push({
      sev: "CRITICO", categoria: "Operación",
      titulo: `SPY1 (Playa del Carmen) — 0 ejecutados, posible cierre`,
      desc: `Meli ofreció ${spy.ofrecidas} viajes a SPY1 pero no se ejecutó NINGUNO. ${spy.rechazadas} fueron rechazados directamente.`,
      metricas: [
        { l: "Ofrecidas", v: spy.ofrecidas, color: "#991b1b" },
        { l: "Ejecutadas", v: spy.ejecutadas, color: "#991b1b" },
        { l: "% Rechazo", v: `${spy.pct_rechazo}%`, color: "#991b1b" },
      ],
      accion: { label: "Ver SCs problemáticos", onClick: verSCsProblematicos },
    });
  }

  if (fantasmaMultiSC) {
    hallazgos.push({
      sev: "CRITICO", categoria: "Compliance",
      titulo: `${fantasmaMultiSC.nombre} — Driver fantasma multi-SC`,
      desc: `Operó ${fantasmaMultiSC.viajes_total} viajes en ${fantasmaMultiSC.cantidad_scs} SCs (${fantasmaMultiSC.scs_operados}) sin estar en master oficial. Riesgo legal en caso de siniestro.`,
      metricas: [
        { l: "Viajes", v: fantasmaMultiSC.viajes_total, color: "#991b1b" },
        { l: "SCs", v: fantasmaMultiSC.cantidad_scs, color: "#991b1b" },
        { l: "DPPH", v: fantasmaMultiSC.dpph_promedio?.toFixed?.(1) ?? "—", color: "#0f172a" },
      ],
      accion: { label: "Ver fantasmas", onClick: verDriversFantasma },
      accion2: { label: "Planificados sin master", onClick: verPlanifSinMaster },
    });
  }

  scsBajaEntrega.forEach(sc => {
    hallazgos.push({
      sev: "ALTO", categoria: "Performance",
      titulo: `${sc.service_center} — Problema de ejecución`,
      desc: `Acepta ${sc.aceptadas} viajes pero ejecuta ${sc.ejecutadas} (${sc.pct_cumplimiento}%). Es problema operativo de campo.`,
      metricas: [
        { l: "% Cumplimiento", v: `${sc.pct_cumplimiento}%`, color: "#92400e" },
        { l: "No presentadas", v: sc.no_presentadas, color: "#92400e" },
        { l: "Aceptadas", v: sc.aceptadas, color: "#0f172a" },
      ],
      accion: { label: "Ir a Ciclo", onClick: () => setVista("ciclo") },
    });
  });

  if (driversFantasma.length > 0) {
    hallazgos.push({
      sev: "ALTO", categoria: "Compliance",
      titulo: `${driversFantasma.length} drivers fantasma activos`,
      desc: `Personas operando viajes a nombre de Bigticket sin estar en master oficial de Meli. ${topFantasma ? `Top: ${topFantasma.nombre} (${topFantasma.viajes_total} viajes).` : ""}`,
      metricas: [
        { l: "Total fantasmas", v: driversFantasma.length, color: "#92400e" },
        { l: "Viajes acumulados", v: driversFantasma.reduce((a, d) => a + (d.viajes_total || 0), 0), color: "#92400e" },
      ],
      accion: { label: "Ver listado", onClick: verDriversFantasma },
    });
  }

  if (vehiculosFantasma.length > 0) {
    hallazgos.push({
      sev: "ALTO", categoria: "Compliance",
      titulo: `${vehiculosFantasma.length} placas fantasma operando`,
      desc: `Vehículos circulando sin estar en master oficial. Mismo riesgo legal que drivers fantasma.`,
      metricas: [
        { l: "Total placas", v: vehiculosFantasma.length, color: "#92400e" },
        { l: "Viajes", v: vehiculosFantasma.reduce((a, v) => a + (v.viajes_total || 0), 0), color: "#92400e" },
      ],
      accion: { label: "Ver listado", onClick: verVehFantasma },
    });
  }

  if (driversIzombi.length > 0) {
    hallazgos.push({
      sev: "MEDIO", categoria: "Limpieza de datos",
      titulo: `${driversIzombi.length} IDs zombi en master Meli`,
      desc: `Drivers en master con CURP vacío y 0 viajes. IDs creados pero no completados del lado de Meli.`,
      metricas: [{ l: "IDs zombi", v: driversIzombi.length, color: "#92400e" }],
      accion: { label: "Ver listado", onClick: verIzombi },
    });
  }

  const totNoPres = r.total_no_presentadas || 0;
  if (totNoPres > 0) {
    hallazgos.push({
      sev: "MEDIO", categoria: "Cumplimiento",
      titulo: `${totNoPres} viajes no presentados`,
      desc: `Bigticket aceptó pero no ejecutó. "No-show silencioso" del sistema.`,
      metricas: [
        { l: "No presentadas", v: totNoPres, color: "#92400e" },
        { l: "% del aceptado", v: `${r.total_aceptadas > 0 ? Math.round(totNoPres / r.total_aceptadas * 100) : 0}%`, color: "#92400e" },
      ],
      accion: { label: "Ver detalle", onClick: () => setVista("ciclo") },
    });
  }

  if (driversElite.length > 0) {
    const topElite = driversElite[0];
    hallazgos.push({
      sev: "INFO", categoria: "Oportunidad",
      titulo: `Top ${driversElite.length} drivers élite — modelo a replicar`,
      desc: `Drivers con score ≥90. ${topElite ? `${topElite.nombre} lidera con ${topElite.score_total} pts.` : ""}`,
      metricas: [
        { l: "Drivers élite", v: driversElite.length, color: "#047857" },
        { l: "Score top", v: topElite?.score_total ?? "—", color: "#047857" },
      ],
      accion: { label: "Ver lista", onClick: verElite },
      accion2: { label: "Ir a Score", onClick: () => setVista("score") },
    });
  }

  const conteoSev = {
    CRITICO: hallazgos.filter(h => h.sev === "CRITICO").length,
    ALTO: hallazgos.filter(h => h.sev === "ALTO").length,
    MEDIO: hallazgos.filter(h => h.sev === "MEDIO").length,
    INFO: hallazgos.filter(h => h.sev === "INFO").length,
  };

  return (
    <div className="pg">
      <div style={{ background: "linear-gradient(135deg, #1a3a6b 0%, #0f2647 100%)", borderRadius: 12, padding: 20, color: "#fff", marginBottom: 16 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <div>
            <div style={{ fontSize: 10, fontWeight: 700, opacity: 0.8, textTransform: "uppercase", letterSpacing: 1.2, marginBottom: 4 }}>Resumen ejecutivo</div>
            <div style={{ fontSize: 18, fontWeight: 700 }}>{hallazgos.length} hallazgos detectados</div>
            <div style={{ fontSize: 12, opacity: 0.85, marginTop: 4 }}>Cruce automático de las 6 fuentes operativas · ordenados por severidad</div>
          </div>
          <div style={{ display: "flex", gap: 14 }}>
            {[
              { label: "Crítico", val: conteoSev.CRITICO, bg: "#fee2e2", text: "#7f1d1d" },
              { label: "Alto", val: conteoSev.ALTO, bg: "#fef3c7", text: "#78350f" },
              { label: "Medio", val: conteoSev.MEDIO, bg: "#fef9c3", text: "#713f12" },
              { label: "Info", val: conteoSev.INFO, bg: "#dcfce7", text: "#14532d" },
            ].map(s => (
              <div key={s.label} style={{ background: s.bg, borderRadius: 8, padding: "8px 14px", textAlign: "center", minWidth: 70 }}>
                <div style={{ fontSize: 22, fontWeight: 700, color: s.text, lineHeight: 1 }}>{s.val}</div>
                <div style={{ fontSize: 10, fontWeight: 700, color: s.text, textTransform: "uppercase", letterSpacing: 0.5, marginTop: 4 }}>{s.label}</div>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
        {hallazgos.map((h, i) => <PoolMeliHallazgoCard key={i} hallazgo={h} index={i + 1} />)}
      </div>
    </div>
  );
}

function PoolMeliHallazgoCard({ hallazgo, index }) {
  const sevStyles = {
    CRITICO: { bg: "#fef2f2", border: "#fecaca", labelBg: "#b91c1c" },
    ALTO:    { bg: "#fffbeb", border: "#fde68a", labelBg: "#d97706" },
    MEDIO:   { bg: "#fefce8", border: "#fde047", labelBg: "#ca8a04" },
    INFO:    { bg: "#f0fdf4", border: "#bbf7d0", labelBg: "#15803d" },
  };
  const s = sevStyles[hallazgo.sev] || sevStyles.INFO;
  return (
    <div style={{ background: s.bg, border: `1px solid ${s.border}`, borderRadius: 10, padding: 16,
      display: "grid", gridTemplateColumns: "auto 1fr auto", gap: 16, alignItems: "start" }}>
      <div style={{ textAlign: "center", minWidth: 50 }}>
        <div style={{ fontSize: 11, color: "#94a3b8", fontFamily: "monospace", marginBottom: 4 }}>#{index}</div>
        <span style={{ display: "inline-block", padding: "3px 10px", borderRadius: 4, fontSize: 9,
          fontWeight: 800, letterSpacing: 0.8, background: s.labelBg, color: "#fff" }}>{hallazgo.sev}</span>
      </div>
      <div>
        <div style={{ fontSize: 10, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5, fontWeight: 700, marginBottom: 4 }}>{hallazgo.categoria}</div>
        <div style={{ fontSize: 14, fontWeight: 700, color: "#0f172a", marginBottom: 6 }}>{hallazgo.titulo}</div>
        <div style={{ fontSize: 12, color: "#334155", lineHeight: 1.5, marginBottom: 10 }}>{hallazgo.desc}</div>
        {hallazgo.metricas && (
          <div style={{ display: "flex", gap: 16, flexWrap: "wrap" }}>
            {hallazgo.metricas.map((m, i) => (
              <div key={i}>
                <div style={{ fontSize: 9, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5, fontWeight: 700, marginBottom: 2 }}>{m.l}</div>
                <div style={{ fontSize: 16, fontWeight: 700, color: m.color }}>{m.v}</div>
              </div>
            ))}
          </div>
        )}
      </div>
      <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
        {hallazgo.accion && (
          <button onClick={hallazgo.accion.onClick}
            style={{ padding: "6px 12px", fontSize: 11, fontWeight: 600, border: "1px solid #cbd5e1",
              borderRadius: 6, background: "#fff", color: "#1a3a6b", cursor: "pointer",
              fontFamily: "'Geist', sans-serif", whiteSpace: "nowrap" }}>{hallazgo.accion.label} →</button>
        )}
        {hallazgo.accion2 && (
          <button onClick={hallazgo.accion2.onClick}
            style={{ padding: "6px 12px", fontSize: 11, fontWeight: 500, border: "none",
              background: "transparent", color: "#64748b", cursor: "pointer",
              fontFamily: "'Geist', sans-serif", whiteSpace: "nowrap" }}>{hallazgo.accion2.label}</button>
        )}
      </div>
    </div>
  );
}

const pm_thStyle  = { textAlign: "left", fontSize: 10, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5, padding: "10px 12px" };
const pm_thStyleR = { ...pm_thStyle, textAlign: "right" };
const pm_tdStyle  = { fontSize: 12, color: "#0f172a", padding: "10px 12px" };
const pm_tdStyleR = { ...pm_tdStyle, textAlign: "right", fontVariantNumeric: "tabular-nums" };

// ═══════════════════════════════════════════════════════════════════════════════════════
// MÓDULO HELPERS · MX (Control de Ayudantes Mercado Libre)
// ───────────────────────────────────────────────────────────────────────────────────────
// Cruza el flag has_helper de logistic_ayudantes_snapshots contra quién realmente
// entregó los paquetes en meli_paquetes_entregados para detectar:
//   • CORRECTO   → helper flag activo + ambos entregaron
//   • FANTASMA   → flag activo pero solo el chofer entregó (BT paga $350 inútilmente)
//   • RARO       → flag activo pero solo el helper entregó (chofer no entregó nada)
//   • NO_MARCADO → helper trabajó sin flag (recuperable de MELI si es SC autorizado)
//
// 4 universos (U0 Resumen, U1 No autorizadas, U2 Certificación, U3 Proceso).
// Funciona con queries directas (no requiere la vista v_helpers_clasificacion_diaria).
// ═══════════════════════════════════════════════════════════════════════════════════════

const HMX_SCS_AUTORIZADOS = ["SMX1", "SMX6", "SMX7", "SMX8", "SMX9", "SMX10", "SQR1"];
const HMX_COSTO_HELPER = 350; // MXN por ruta

function hmx_clasificar({ helper_flag, pkgs_chofer, pkgs_otro }) {
  if (helper_flag && pkgs_otro > 0 && pkgs_chofer > 0) return "CORRECTO";
  if (helper_flag && pkgs_otro === 0) return "FANTASMA";
  if (helper_flag && pkgs_chofer === 0) return "RARO";
  if (!helper_flag && pkgs_otro > 0) return "NO_MARCADO";
  return "NORMAL";
}

function hmx_esAutorizado(sc) {
  return HMX_SCS_AUTORIZADOS.includes(sc);
}

function ModuloHelpersMX({ usuario }) {
  const [vista, setVista] = useState("u0");
  const [fecha, setFecha] = useState(fechaHoyOperativa());
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [rutas, setRutas] = useState([]);
  const [detalle, setDetalle] = useState(null);

  const cargarDatos = async () => {
    setLoading(true);
    setError(null);
    try {
      // 1) Flag de helper por ruta (logistic_ayudantes_snapshots)
      const { data: snaps, error: e1 } = await sb
        .from("logistic_ayudantes_snapshots")
        .select("id_ruta, has_helper, service_center_id")
        .eq("fecha", fecha);
      if (e1) throw e1;

      // Mapa id_ruta -> { helper_flag, sc }
      const flagMap = new Map();
      (snaps || []).forEach(r => {
        const prev = flagMap.get(r.id_ruta) || { helper_flag: false, sc: r.service_center_id };
        flagMap.set(r.id_ruta, {
          helper_flag: prev.helper_flag || !!r.has_helper,
          sc: r.service_center_id || prev.sc,
        });
      });

      // 2) Entregas del día (meli_paquetes_entregados)
      const { data: pkgs, error: e2 } = await sb
        .from("meli_paquetes_entregados")
        .select("id_ruta, service_center_id, driver_id, driver_name, user_id_real, user_name_real")
        .eq("fecha", fecha)
        .not("user_id_real", "is", null);
      if (e2) throw e2;

      // Agregar por ruta
      const rutaMap = new Map();
      (pkgs || []).forEach(p => {
        const id = p.id_ruta;
        let row = rutaMap.get(id);
        if (!row) {
          row = {
            id_ruta: id,
            sc: p.service_center_id,
            chofer: p.driver_name,
            chofer_id: p.driver_id,
            pkgs_chofer: 0,
            pkgs_otro: 0,
            ayudantes: new Set(),
          };
          rutaMap.set(id, row);
        }
        const mismoChofer = p.user_id_real === p.driver_id;
        if (mismoChofer) row.pkgs_chofer++;
        else {
          row.pkgs_otro++;
          if (p.user_name_real) row.ayudantes.add(p.user_name_real);
        }
      });

      // 3) Unir flag + entregas
      const todasLasRutas = new Set([...flagMap.keys(), ...rutaMap.keys()]);
      const result = [];
      todasLasRutas.forEach(id => {
        const flag = flagMap.get(id) || { helper_flag: false, sc: null };
        const entrega = rutaMap.get(id) || {
          id_ruta: id, sc: flag.sc, chofer: null, chofer_id: null,
          pkgs_chofer: 0, pkgs_otro: 0, ayudantes: new Set(),
        };
        const sc = entrega.sc || flag.sc;
        const helper_flag = flag.helper_flag;
        const pkgs_chofer = entrega.pkgs_chofer;
        const pkgs_otro = entrega.pkgs_otro;
        const clasificacion = hmx_clasificar({ helper_flag, pkgs_chofer, pkgs_otro });
        const autorizado = hmx_esAutorizado(sc);
        result.push({
          id_ruta: id,
          sc,
          autorizado,
          chofer: entrega.chofer,
          chofer_id: entrega.chofer_id,
          helper_flag,
          pkgs_chofer,
          pkgs_otro,
          pkgs_total: pkgs_chofer + pkgs_otro,
          ayudante_nombre: [...entrega.ayudantes].join(" | "),
          clasificacion,
          monto_recuperable_meli: (!helper_flag && pkgs_otro > 0 && autorizado) ? HMX_COSTO_HELPER : 0,
          costo_bt_cuestionable: (helper_flag && pkgs_otro === 0) ? HMX_COSTO_HELPER : 0,
        });
      });

      setRutas(result);
    } catch (e) {
      setError(e.message || "Error cargando datos");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { cargarDatos(); /* eslint-disable-next-line */ }, [fecha]);

  const stats = useMemo(() => {
    const conFlag = rutas.filter(r => r.helper_flag);
    const correctas = conFlag.filter(r => r.clasificacion === "CORRECTO");
    const fantasma = conFlag.filter(r => r.clasificacion === "FANTASMA");
    const raras = conFlag.filter(r => r.clasificacion === "RARO");
    const noMarcadas = rutas.filter(r => r.clasificacion === "NO_MARCADO");
    const fantasmaNoAutoriz = fantasma.filter(r => !r.autorizado);
    const fantasmaAutoriz = fantasma.filter(r => r.autorizado);
    const recuperable = rutas.reduce((s, r) => s + r.monto_recuperable_meli, 0);
    const costoCuestionable = rutas.reduce((s, r) => s + r.costo_bt_cuestionable, 0);
    return {
      total_con_flag: conFlag.length,
      correctas: correctas.length,
      fantasma: fantasma.length,
      raras: raras.length,
      no_marcadas: noMarcadas.length,
      fantasma_no_autoriz: fantasmaNoAutoriz.length,
      fantasma_autoriz: fantasmaAutoriz.length,
      recuperable_meli: recuperable,
      costo_bt_cuestionable: costoCuestionable,
      list_correctas: correctas,
      list_fantasma: fantasma,
      list_raras: raras,
      list_no_marcadas: noMarcadas,
    };
  }, [rutas]);

  const porSC = useMemo(() => {
    const map = new Map();
    rutas.filter(r => r.helper_flag).forEach(r => {
      const k = r.sc || "—";
      let row = map.get(k);
      if (!row) {
        row = { sc: k, autorizado: r.autorizado, correctas: 0, fantasma: 0, raras: 0, total: 0, costo_bt: 0 };
        map.set(k, row);
      }
      row.total++;
      if (r.clasificacion === "CORRECTO") row.correctas++;
      else if (r.clasificacion === "FANTASMA") row.fantasma++;
      else if (r.clasificacion === "RARO") row.raras++;
      row.costo_bt += r.costo_bt_cuestionable;
    });
    return [...map.values()].sort((a, b) => {
      if (a.autorizado !== b.autorizado) return a.autorizado ? 1 : -1;
      return b.total - a.total;
    });
  }, [rutas]);

  const tabs = [
    { id: "u0", label: "U0 · Resumen", desc: "Vista ejecutiva del día" },
    { id: "u1", label: "U1 · No autorizadas", desc: "Helper en SC sin tarifa MELI" },
    { id: "u2", label: "U2 · Desviaciones", desc: "Fantasmas en SC autorizados" },
    { id: "u3", label: "U3 · Detalle", desc: "Listado completo de rutas" },
  ];

  return (
    <div style={{ padding: 0 }}>
      <div style={{ background: "#fff", borderBottom: "1px solid #e4e7ec", padding: "12px 24px" }}>
        <div style={{ fontSize: 18, fontWeight: 700, color: "#1a3a6b", marginBottom: 4 }}>
          Control Helpers MX
        </div>
        <div style={{ fontSize: 12, color: "#64748b", marginBottom: 10 }}>
          Cruce de helpers declarados (logistic) vs entregadores reales (MELI) · operación Mercado Libre
        </div>
        <div style={{ display: "flex", gap: 0, borderBottom: "2px solid #e4e7ec", marginLeft: -8, flexWrap: "wrap", alignItems: "flex-end", justifyContent: "space-between" }}>
          <div style={{ display: "flex", gap: 0, flexWrap: "wrap" }}>
            {tabs.map(t => (
              <button key={t.id} onClick={() => { setVista(t.id); setDetalle(null); }}
                style={{
                  background: "transparent", border: "none", padding: "10px 16px",
                  fontSize: 13, fontWeight: 600, cursor: "pointer", color: vista === t.id ? "#1a3a6b" : "#64748b",
                  borderBottom: vista === t.id ? "2px solid #1a3a6b" : "2px solid transparent",
                  marginBottom: -2, textAlign: "left",
                }}>
                <div>{t.label}</div>
                <div style={{ fontSize: 10, color: "#94a3b8", fontWeight: 400, marginTop: 2 }}>{t.desc}</div>
              </button>
            ))}
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: 8, paddingBottom: 8 }}>
            <span style={{ fontSize: 11, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5 }}>
              Fecha:
            </span>
            <input type="date" value={fecha} onChange={e => setFecha(e.target.value)}
              style={{
                padding: "6px 10px", fontSize: 13, fontWeight: 600, borderRadius: 6,
                border: "1px solid #cbd5e1", background: "#fff", color: "#1a3a6b",
                cursor: "pointer", fontFamily: "'Geist', sans-serif", outline: "none",
                width: "auto",
              }} />
            <button onClick={cargarDatos} disabled={loading}
              style={{
                padding: "6px 12px", fontSize: 12, fontWeight: 600, borderRadius: 6,
                border: "1px solid #cbd5e1", background: "#fff", color: "#475569",
                cursor: loading ? "wait" : "pointer", fontFamily: "'Geist', sans-serif",
              }}>
              {loading ? "Cargando…" : "Refrescar"}
            </button>
          </div>
        </div>
      </div>

      <div className="pg" style={{ paddingTop: 16 }}>
        {error && (
          <div className="form-card" style={{ background: "#fef2f2", border: "1px solid #fecaca", marginBottom: 16 }}>
            <div style={{ fontSize: 13, fontWeight: 600, color: "#991b1b", marginBottom: 4 }}>
              No se pudo cargar la información
            </div>
            <div style={{ fontSize: 12, color: "#7f1d1d" }}>{error}</div>
          </div>
        )}

        {loading && (
          <div className="form-card" style={{ textAlign: "center", padding: 40, color: "#666" }}>
            Cargando datos del {fecha}…
          </div>
        )}

        {!loading && !error && rutas.length === 0 && (
          <div className="form-card" style={{ textAlign: "center", padding: 40, color: "#666" }}>
            <div style={{ fontSize: 14, fontWeight: 600, marginBottom: 6 }}>
              No hay rutas registradas para {fecha}
            </div>
            <div style={{ fontSize: 12, color: "#94a3b8" }}>
              El scraper puede no haber capturado información todavía. Probá con otra fecha o esperá al cierre del día.
            </div>
          </div>
        )}

        {!loading && !error && rutas.length > 0 && (
          <>
            {vista === "u0" && <HelpersU0 stats={stats} porSC={porSC} fecha={fecha} onIr={setVista} />}
            {vista === "u1" && <HelpersU1 porSC={porSC} stats={stats} rutas={rutas} setDetalle={setDetalle} detalle={detalle} />}
            {vista === "u2" && <HelpersU2 porSC={porSC} stats={stats} rutas={rutas} setDetalle={setDetalle} detalle={detalle} />}
            {vista === "u3" && <HelpersU3 rutas={rutas} />}
          </>
        )}
      </div>
    </div>
  );
}

// ─── U0 · Resumen ejecutivo ──────────────────────────────────────────────────
function HelpersU0({ stats, porSC, fecha, onIr }) {
  const { total_con_flag, correctas, fantasma, raras, fantasma_no_autoriz, fantasma_autoriz, recuperable_meli, costo_bt_cuestionable } = stats;

  const kpis = [
    { label: "Rutas con helper flag", valor: total_con_flag, sub: "declarados en MELI hoy", color: "#1a3a6b" },
    { label: "Correctas", valor: correctas, sub: "helper trabajó realmente", color: "#16a34a" },
    { label: "Fantasma", valor: fantasma, sub: `BT paga $${(costo_bt_cuestionable).toLocaleString("es-MX")} sin entrega`, color: "#c0392b" },
    { label: "Raras", valor: raras, sub: "solo el helper entregó", color: "#F47B20" },
  ];

  return (
    <>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))", gap: 12, marginBottom: 16 }}>
        {kpis.map((k, i) => (
          <div key={i} className="form-card" style={{ padding: 16, marginBottom: 0, borderLeft: `3px solid ${k.color}` }}>
            <div style={{ fontSize: 11, fontWeight: 700, color: "#6b7280", textTransform: "uppercase", letterSpacing: 0.4, marginBottom: 6 }}>
              {k.label}
            </div>
            <div style={{ fontSize: 26, fontWeight: 800, color: k.color, letterSpacing: -0.5, lineHeight: 1 }}>
              {k.valor}
            </div>
            <div style={{ fontSize: 11, color: "#9ca3af", marginTop: 6 }}>{k.sub}</div>
          </div>
        ))}
      </div>

      {total_con_flag > 0 && (
        <div className="form-card" style={{ marginBottom: 16 }}>
          <div className="form-title">Distribución del día · {fecha}</div>
          <div style={{ height: 32, display: "flex", borderRadius: 8, overflow: "hidden", marginBottom: 12, fontSize: 11, fontWeight: 700, color: "#fff" }}>
            {correctas > 0 && (
              <div style={{ flex: correctas, background: "#16a34a", display: "flex", alignItems: "center", justifyContent: "center" }}>
                {correctas} OK
              </div>
            )}
            {fantasma > 0 && (
              <div style={{ flex: fantasma, background: "#c0392b", display: "flex", alignItems: "center", justifyContent: "center" }}>
                {fantasma} fantasma
              </div>
            )}
            {raras > 0 && (
              <div style={{ flex: raras, background: "#F47B20", display: "flex", alignItems: "center", justifyContent: "center" }}>
                {raras} raras
              </div>
            )}
          </div>
          <div style={{ display: "flex", gap: 16, flexWrap: "wrap", fontSize: 11, color: "#6b7280" }}>
            <div style={{ display: "flex", alignItems: "center", gap: 5 }}>
              <div style={{ width: 10, height: 10, borderRadius: 2, background: "#16a34a" }}></div>
              <span><strong style={{ color: "#16a34a" }}>Correcto</strong> — helper y chofer entregaron</span>
            </div>
            <div style={{ display: "flex", alignItems: "center", gap: 5 }}>
              <div style={{ width: 10, height: 10, borderRadius: 2, background: "#c0392b" }}></div>
              <span><strong style={{ color: "#c0392b" }}>Fantasma</strong> — solo el chofer entregó · BT paga sin servicio</span>
            </div>
            <div style={{ display: "flex", alignItems: "center", gap: 5 }}>
              <div style={{ width: 10, height: 10, borderRadius: 2, background: "#F47B20" }}></div>
              <span><strong style={{ color: "#F47B20" }}>Raro</strong> — solo el helper entregó · investigar</span>
            </div>
          </div>
        </div>
      )}

      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(280px, 1fr))", gap: 12, marginBottom: 16 }}>
        <div className="form-card" style={{ padding: 16, marginBottom: 0, cursor: "pointer" }} onClick={() => onIr("u1")}>
          <div style={{ fontSize: 11, fontWeight: 700, color: "#6b7280", textTransform: "uppercase", letterSpacing: 0.4, marginBottom: 6 }}>
            U1 · No autorizadas
          </div>
          <div style={{ fontSize: 22, fontWeight: 800, color: "#c0392b", marginBottom: 4 }}>
            {porSC.filter(s => !s.autorizado).reduce((a, b) => a + b.total, 0)}
          </div>
          <div style={{ fontSize: 11, color: "#9ca3af", marginBottom: 10 }}>
            rutas con helper en SC sin tarifa MELI
          </div>
          <div style={{ fontSize: 11, fontWeight: 500, color: "#1a3a6b" }}>Ver universo →</div>
        </div>

        <div className="form-card" style={{ padding: 16, marginBottom: 0, cursor: "pointer" }} onClick={() => onIr("u2")}>
          <div style={{ fontSize: 11, fontWeight: 700, color: "#6b7280", textTransform: "uppercase", letterSpacing: 0.4, marginBottom: 6 }}>
            U2 · Desviaciones autorizados
          </div>
          <div style={{ fontSize: 22, fontWeight: 800, color: "#F47B20", marginBottom: 4 }}>
            {fantasma_autoriz}
          </div>
          <div style={{ fontSize: 11, color: "#9ca3af", marginBottom: 10 }}>
            fantasmas en SC con tarifa activa
          </div>
          <div style={{ fontSize: 11, fontWeight: 500, color: "#1a3a6b" }}>Ver universo →</div>
        </div>

        <div className="form-card" style={{ padding: 16, marginBottom: 0, cursor: "pointer" }} onClick={() => onIr("u3")}>
          <div style={{ fontSize: 11, fontWeight: 700, color: "#6b7280", textTransform: "uppercase", letterSpacing: 0.4, marginBottom: 6 }}>
            U3 · Detalle completo
          </div>
          <div style={{ fontSize: 22, fontWeight: 800, color: "#1a3a6b", marginBottom: 4 }}>
            {stats.total_con_flag}
          </div>
          <div style={{ fontSize: 11, color: "#9ca3af", marginBottom: 10 }}>
            rutas listadas con filtros
          </div>
          <div style={{ fontSize: 11, fontWeight: 500, color: "#1a3a6b" }}>Ver detalle →</div>
        </div>
      </div>

      <div className="form-card">
        <div className="form-title">Impacto financiero estimado · {fecha}</div>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(240px, 1fr))", gap: 16 }}>
          <div>
            <div style={{ fontSize: 11, color: "#6b7280", textTransform: "uppercase", fontWeight: 700, letterSpacing: 0.4, marginBottom: 4 }}>
              Costo BT cuestionable
            </div>
            <div style={{ fontSize: 20, fontWeight: 800, color: "#c0392b" }}>
              ${costo_bt_cuestionable.toLocaleString("es-MX")} MXN
            </div>
            <div style={{ fontSize: 11, color: "#9ca3af", marginTop: 4 }}>
              {fantasma} fantasmas × ${HMX_COSTO_HELPER}
            </div>
          </div>
          <div>
            <div style={{ fontSize: 11, color: "#6b7280", textTransform: "uppercase", fontWeight: 700, letterSpacing: 0.4, marginBottom: 4 }}>
              Recuperable de MELI
            </div>
            <div style={{ fontSize: 20, fontWeight: 800, color: "#16a34a" }}>
              ${recuperable_meli.toLocaleString("es-MX")} MXN
            </div>
            <div style={{ fontSize: 11, color: "#9ca3af", marginTop: 4 }}>
              {stats.no_marcadas} no marcadas en SC autorizado
            </div>
          </div>
        </div>
      </div>
    </>
  );
}

// ─── U1 · No autorizadas (PRIORIDAD) ──────────────────────────────────────────
function HelpersU1({ porSC, stats, rutas, setDetalle, detalle }) {
  const scsNoAut = porSC.filter(s => !s.autorizado);
  const totalRutas = scsNoAut.reduce((a, s) => a + s.total, 0);
  const totalFantasma = scsNoAut.reduce((a, s) => a + s.fantasma, 0);
  const totalCosto = scsNoAut.reduce((a, s) => a + s.costo_bt, 0);

  const onClickSC = (sc) => {
    const filtradas = rutas.filter(r => r.sc === sc && r.helper_flag);
    setDetalle({ tipo: "sc", filtro: sc, datos: filtradas });
  };

  return (
    <>
      <div className="form-card" style={{ background: "#fef2f2", border: "1px solid #fecaca", marginBottom: 16 }}>
        <div style={{ fontSize: 13, fontWeight: 700, color: "#991b1b", marginBottom: 4 }}>
          ⚠ Universo crítico · Acción inmediata
        </div>
        <div style={{ fontSize: 12, color: "#7f1d1d", lineHeight: 1.6 }}>
          Estas rutas tienen helper declarado en SC <strong>sin tarifa activa en MELI</strong>. BT está pagando el costo
          completo sin posibilidad de recuperarlo. La acción no es operativa: bloquear el flag en estos SC y
          negociar activación de tarifa con MELI.
        </div>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))", gap: 12, marginBottom: 16 }}>
        <div className="form-card" style={{ padding: 14, marginBottom: 0 }}>
          <div style={{ fontSize: 11, fontWeight: 700, color: "#6b7280", textTransform: "uppercase", letterSpacing: 0.4, marginBottom: 6 }}>SC no autorizados con flag</div>
          <div style={{ fontSize: 22, fontWeight: 800, color: "#c0392b" }}>{scsNoAut.length}</div>
        </div>
        <div className="form-card" style={{ padding: 14, marginBottom: 0 }}>
          <div style={{ fontSize: 11, fontWeight: 700, color: "#6b7280", textTransform: "uppercase", letterSpacing: 0.4, marginBottom: 6 }}>Rutas afectadas</div>
          <div style={{ fontSize: 22, fontWeight: 800, color: "#c0392b" }}>{totalRutas}</div>
        </div>
        <div className="form-card" style={{ padding: 14, marginBottom: 0 }}>
          <div style={{ fontSize: 11, fontWeight: 700, color: "#6b7280", textTransform: "uppercase", letterSpacing: 0.4, marginBottom: 6 }}>De las cuales fantasma</div>
          <div style={{ fontSize: 22, fontWeight: 800, color: "#c0392b" }}>{totalFantasma}</div>
        </div>
        <div className="form-card" style={{ padding: 14, marginBottom: 0 }}>
          <div style={{ fontSize: 11, fontWeight: 700, color: "#6b7280", textTransform: "uppercase", letterSpacing: 0.4, marginBottom: 6 }}>Costo BT del día</div>
          <div style={{ fontSize: 22, fontWeight: 800, color: "#c0392b" }}>${totalCosto.toLocaleString("es-MX")}</div>
        </div>
      </div>

      <div className="form-card" style={{ padding: 0, overflow: "hidden" }}>
        <div style={{ padding: "12px 16px", borderBottom: "1px solid #e4e7ec", fontSize: 13, fontWeight: 600, color: "#1a3a6b" }}>
          SCs no autorizados con helper declarado
        </div>
        {scsNoAut.length === 0 ? (
          <div style={{ padding: 24, textAlign: "center", color: "#94a3b8", fontSize: 12 }}>
            No hay SCs no autorizados con helper declarado hoy
          </div>
        ) : (
          <table style={{ width: "100%", borderCollapse: "collapse" }}>
            <thead>
              <tr>
                <th style={hmxTh}>SC</th>
                <th style={hmxThR}>Rutas con flag</th>
                <th style={hmxThR}>Correctas</th>
                <th style={hmxThR}>Fantasma</th>
                <th style={hmxThR}>Raras</th>
                <th style={hmxThR}>Costo BT</th>
                <th style={hmxThR}>Acción</th>
              </tr>
            </thead>
            <tbody>
              {scsNoAut.map(s => (
                <tr key={s.sc} style={{ borderBottom: "1px solid #f4f5f7", cursor: "pointer" }}
                  onClick={() => onClickSC(s.sc)}>
                  <td style={{ ...hmxTd, fontWeight: 700, color: "#1a3a6b" }}>{s.sc}</td>
                  <td style={hmxTdR}>{s.total}</td>
                  <td style={{ ...hmxTdR, color: s.correctas > 0 ? "#16a34a" : "#cbd5e1" }}>{s.correctas}</td>
                  <td style={{ ...hmxTdR, color: s.fantasma > 0 ? "#c0392b" : "#cbd5e1", fontWeight: s.fantasma > 0 ? 700 : 400 }}>{s.fantasma}</td>
                  <td style={{ ...hmxTdR, color: s.raras > 0 ? "#F47B20" : "#cbd5e1" }}>{s.raras}</td>
                  <td style={{ ...hmxTdR, fontWeight: 700, color: "#c0392b" }}>${s.costo_bt.toLocaleString("es-MX")}</td>
                  <td style={{ ...hmxTdR, fontSize: 11, color: "#1a3a6b", fontWeight: 600 }}>Ver detalle →</td>
                </tr>
              ))}
              <tr style={{ background: "#f9fafb", borderTop: "1px solid #e5e7eb", fontWeight: 700 }}>
                <td style={{ ...hmxTd, fontWeight: 700, color: "#1a3a6b" }}>Total</td>
                <td style={hmxTdR}>{totalRutas}</td>
                <td style={hmxTdR}>{scsNoAut.reduce((a, s) => a + s.correctas, 0)}</td>
                <td style={{ ...hmxTdR, color: "#c0392b" }}>{totalFantasma}</td>
                <td style={{ ...hmxTdR, color: "#F47B20" }}>{scsNoAut.reduce((a, s) => a + s.raras, 0)}</td>
                <td style={{ ...hmxTdR, color: "#c0392b" }}>${totalCosto.toLocaleString("es-MX")}</td>
                <td style={hmxTdR}>—</td>
              </tr>
            </tbody>
          </table>
        )}
      </div>

      {detalle && detalle.tipo === "sc" && (
        <DetalleRutasHelpers detalle={detalle} onClose={() => setDetalle(null)} />
      )}
    </>
  );
}

// ─── U2 · Desviaciones en SC autorizados ────────────────────────────────────
function HelpersU2({ porSC, stats, rutas, setDetalle, detalle }) {
  const scsAut = porSC.filter(s => s.autorizado);

  const onClickSC = (sc) => {
    const filtradas = rutas.filter(r => r.sc === sc && r.helper_flag);
    setDetalle({ tipo: "sc", filtro: sc, datos: filtradas });
  };

  return (
    <>
      <div className="form-card" style={{ background: "#fffbeb", border: "1px solid #fde68a", marginBottom: 16 }}>
        <div style={{ fontSize: 13, fontWeight: 700, color: "#92400e", marginBottom: 4 }}>
          ⚠ Desviaciones en SC autorizados
        </div>
        <div style={{ fontSize: 12, color: "#78350f", lineHeight: 1.6 }}>
          Rutas en SC con tarifa MELI activa donde el helper fue declarado pero solo el chofer entregó.
          MELI sí paga la tarifa, pero el helper podría no haber operado realmente. Validar con supervisor.
        </div>
      </div>

      <div className="form-card" style={{ padding: 0, overflow: "hidden" }}>
        <div style={{ padding: "12px 16px", borderBottom: "1px solid #e4e7ec", fontSize: 13, fontWeight: 600, color: "#1a3a6b" }}>
          SCs autorizados con helper declarado
        </div>
        {scsAut.length === 0 ? (
          <div style={{ padding: 24, textAlign: "center", color: "#94a3b8", fontSize: 12 }}>
            No hay SCs autorizados con helper declarado hoy
          </div>
        ) : (
          <table style={{ width: "100%", borderCollapse: "collapse" }}>
            <thead>
              <tr>
                <th style={hmxTh}>SC</th>
                <th style={hmxThR}>Rutas con flag</th>
                <th style={hmxThR}>Correctas</th>
                <th style={hmxThR}>Fantasma</th>
                <th style={hmxThR}>Raras</th>
                <th style={hmxThR}>% Sano</th>
                <th style={hmxThR}>Acción</th>
              </tr>
            </thead>
            <tbody>
              {scsAut.map(s => {
                const pct = s.total > 0 ? Math.round((s.correctas / s.total) * 100) : 0;
                return (
                  <tr key={s.sc} style={{ borderBottom: "1px solid #f4f5f7", cursor: "pointer" }}
                    onClick={() => onClickSC(s.sc)}>
                    <td style={{ ...hmxTd, fontWeight: 700, color: "#1a3a6b" }}>{s.sc}</td>
                    <td style={hmxTdR}>{s.total}</td>
                    <td style={{ ...hmxTdR, color: s.correctas > 0 ? "#16a34a" : "#cbd5e1" }}>{s.correctas}</td>
                    <td style={{ ...hmxTdR, color: s.fantasma > 0 ? "#c0392b" : "#cbd5e1", fontWeight: s.fantasma > 0 ? 700 : 400 }}>{s.fantasma}</td>
                    <td style={{ ...hmxTdR, color: s.raras > 0 ? "#F47B20" : "#cbd5e1" }}>{s.raras}</td>
                    <td style={{ ...hmxTdR, fontWeight: 700, color: pct >= 75 ? "#16a34a" : pct >= 50 ? "#F47B20" : "#c0392b" }}>{pct}%</td>
                    <td style={{ ...hmxTdR, fontSize: 11, color: "#1a3a6b", fontWeight: 600 }}>Ver detalle →</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        )}
      </div>

      {detalle && detalle.tipo === "sc" && (
        <DetalleRutasHelpers detalle={detalle} onClose={() => setDetalle(null)} />
      )}
    </>
  );
}

// ─── U3 · Detalle completo (tabla con filtros) ────────────────────────────
function HelpersU3({ rutas }) {
  const [filtroClas, setFiltroClas] = useState("ALL");
  const [filtroSC, setFiltroSC] = useState("ALL");
  const [busqueda, setBusqueda] = useState("");

  const scs = useMemo(() => [...new Set(rutas.map(r => r.sc).filter(Boolean))].sort(), [rutas]);

  const filtradas = useMemo(() => {
    let res = rutas.filter(r => r.helper_flag || r.clasificacion === "NO_MARCADO");
    if (filtroClas !== "ALL") res = res.filter(r => r.clasificacion === filtroClas);
    if (filtroSC !== "ALL") res = res.filter(r => r.sc === filtroSC);
    if (busqueda.trim()) {
      const q = busqueda.toLowerCase().trim();
      res = res.filter(r =>
        (r.id_ruta || "").toString().toLowerCase().includes(q) ||
        (r.chofer || "").toLowerCase().includes(q) ||
        (r.ayudante_nombre || "").toLowerCase().includes(q) ||
        (r.sc || "").toLowerCase().includes(q)
      );
    }
    return res.sort((a, b) => {
      if (a.autorizado !== b.autorizado) return a.autorizado ? 1 : -1;
      if (a.sc !== b.sc) return (a.sc || "").localeCompare(b.sc || "");
      return (a.clasificacion || "").localeCompare(b.clasificacion || "");
    });
  }, [rutas, filtroClas, filtroSC, busqueda]);

  const exportarCSV = () => {
    const header = ["SC", "Tipo SC", "ID Ruta", "Chofer", "Clasificación", "Flag", "Pkgs Chofer", "Pkgs Helper", "Helper", "Recuperable MELI", "Costo BT"];
    const rows = [header, ...filtradas.map(r => [
      r.sc, r.autorizado ? "AUTORIZADO" : "NO_AUTORIZADO", r.id_ruta, r.chofer, r.clasificacion,
      r.helper_flag ? "SI" : "NO", r.pkgs_chofer, r.pkgs_otro, r.ayudante_nombre || "",
      r.monto_recuperable_meli, r.costo_bt_cuestionable,
    ])];
    const csv = rows.map(r => r.map(v => `"${String(v ?? "").replace(/"/g, '""')}"`).join(",")).join("\n");
    const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `helpers_mx_${fechaHoyOperativa()}.csv`;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <>
      <div className="form-card" style={{ padding: 14, marginBottom: 14, display: "flex", gap: 10, flexWrap: "wrap", alignItems: "center" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
          <span style={{ fontSize: 11, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.4 }}>Clasificación:</span>
          <select value={filtroClas} onChange={e => setFiltroClas(e.target.value)}
            style={{ width: "auto", padding: "6px 10px", fontSize: 12, borderRadius: 6, border: "1px solid #cbd5e1" }}>
            <option value="ALL">Todas</option>
            <option value="CORRECTO">Correctas</option>
            <option value="FANTASMA">Fantasma</option>
            <option value="RARO">Raras</option>
            <option value="NO_MARCADO">No marcadas</option>
          </select>
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
          <span style={{ fontSize: 11, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.4 }}>SC:</span>
          <select value={filtroSC} onChange={e => setFiltroSC(e.target.value)}
            style={{ width: "auto", padding: "6px 10px", fontSize: 12, borderRadius: 6, border: "1px solid #cbd5e1" }}>
            <option value="ALL">Todos</option>
            {scs.map(s => <option key={s} value={s}>{s}</option>)}
          </select>
        </div>
        <input value={busqueda} onChange={e => setBusqueda(e.target.value)} placeholder="Buscar ruta, chofer, helper…"
          style={{ width: 240, padding: "6px 10px", fontSize: 12, borderRadius: 6, border: "1px solid #cbd5e1" }} />
        <div style={{ marginLeft: "auto", fontSize: 12, color: "#64748b" }}>
          <strong>{filtradas.length}</strong> rutas
        </div>
        <button onClick={exportarCSV} className="btn-blue" style={{ padding: "6px 14px", fontSize: 12 }}>
          Exportar CSV
        </button>
      </div>

      <div className="form-card" style={{ padding: 0, overflow: "hidden" }}>
        <div style={{ overflowX: "auto" }}>
          <table style={{ width: "100%", borderCollapse: "collapse", minWidth: 900 }}>
            <thead>
              <tr>
                <th style={hmxTh}>SC</th>
                <th style={hmxTh}>Tipo</th>
                <th style={hmxTh}>ID Ruta</th>
                <th style={hmxTh}>Chofer</th>
                <th style={hmxTh}>Helper</th>
                <th style={hmxTh}>Clasificación</th>
                <th style={hmxThR}>Pkgs ch.</th>
                <th style={hmxThR}>Pkgs h.</th>
                <th style={hmxThR}>Recup.</th>
                <th style={hmxThR}>Costo BT</th>
              </tr>
            </thead>
            <tbody>
              {filtradas.map((r, i) => (
                <tr key={r.id_ruta + "_" + i} style={{ borderBottom: "1px solid #f4f5f7" }}>
                  <td style={{ ...hmxTd, fontWeight: 700, color: "#1a3a6b" }}>{r.sc || "—"}</td>
                  <td style={hmxTd}>
                    <span style={{
                      fontSize: 10, fontWeight: 700, padding: "2px 7px", borderRadius: 4,
                      background: r.autorizado ? "#dcfce7" : "#fee2e2",
                      color: r.autorizado ? "#166534" : "#991b1b",
                    }}>
                      {r.autorizado ? "AUT" : "NO AUT"}
                    </span>
                  </td>
                  <td style={{ ...hmxTd, fontFamily: "monospace", fontSize: 11 }}>{r.id_ruta}</td>
                  <td style={{ ...hmxTd, fontSize: 11 }}>{r.chofer || "—"}</td>
                  <td style={{ ...hmxTd, fontSize: 11 }}>{r.ayudante_nombre || "—"}</td>
                  <td style={hmxTd}>
                    <HelpersBadge clasificacion={r.clasificacion} />
                  </td>
                  <td style={hmxTdR}>{r.pkgs_chofer}</td>
                  <td style={hmxTdR}>{r.pkgs_otro}</td>
                  <td style={{ ...hmxTdR, color: r.monto_recuperable_meli > 0 ? "#16a34a" : "#cbd5e1", fontWeight: r.monto_recuperable_meli > 0 ? 700 : 400 }}>
                    {r.monto_recuperable_meli > 0 ? `$${r.monto_recuperable_meli}` : "—"}
                  </td>
                  <td style={{ ...hmxTdR, color: r.costo_bt_cuestionable > 0 ? "#c0392b" : "#cbd5e1", fontWeight: r.costo_bt_cuestionable > 0 ? 700 : 400 }}>
                    {r.costo_bt_cuestionable > 0 ? `$${r.costo_bt_cuestionable}` : "—"}
                  </td>
                </tr>
              ))}
              {filtradas.length === 0 && (
                <tr>
                  <td colSpan={10} style={{ padding: 24, textAlign: "center", color: "#94a3b8", fontSize: 12 }}>
                    No hay rutas que coincidan con los filtros
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </>
  );
}

// ─── Detalle de rutas por SC (drill-down) ────────────────────────────────
function DetalleRutasHelpers({ detalle, onClose }) {
  return (
    <div className="form-card" style={{ marginTop: 14, padding: 0, overflow: "hidden" }}>
      <div style={{ padding: "12px 16px", borderBottom: "1px solid #e4e7ec", background: "#f9fafb", display: "flex", alignItems: "center", gap: 8 }}>
        <span style={{ fontSize: 13, fontWeight: 700, color: "#1a3a6b" }}>{detalle.filtro}</span>
        <span style={{ fontSize: 11, color: "#9ca3af" }}>·</span>
        <span style={{ fontSize: 12, color: "#64748b" }}>{detalle.datos.length} rutas</span>
        <button onClick={onClose} style={{ marginLeft: "auto", background: "transparent", border: "none", color: "#64748b", fontSize: 12, cursor: "pointer", fontFamily: "'Geist', sans-serif" }}>
          Cerrar ✕
        </button>
      </div>
      <div style={{ overflowX: "auto" }}>
        <table style={{ width: "100%", borderCollapse: "collapse" }}>
          <thead>
            <tr>
              <th style={hmxTh}>ID Ruta</th>
              <th style={hmxTh}>Chofer</th>
              <th style={hmxTh}>Helper detectado</th>
              <th style={hmxTh}>Clasificación</th>
              <th style={hmxThR}>Pkgs ch.</th>
              <th style={hmxThR}>Pkgs h.</th>
              <th style={hmxTh}>Acción sugerida</th>
            </tr>
          </thead>
          <tbody>
            {detalle.datos.map((r, i) => (
              <tr key={r.id_ruta + "_" + i} style={{ borderBottom: "1px solid #f4f5f7" }}>
                <td style={{ ...hmxTd, fontFamily: "monospace", fontSize: 11 }}>{r.id_ruta}</td>
                <td style={{ ...hmxTd, fontSize: 11 }}>{r.chofer || "—"}</td>
                <td style={{ ...hmxTd, fontSize: 11 }}>{r.ayudante_nombre || "—"}</td>
                <td style={hmxTd}><HelpersBadge clasificacion={r.clasificacion} /></td>
                <td style={hmxTdR}>{r.pkgs_chofer}</td>
                <td style={hmxTdR}>{r.pkgs_otro}</td>
                <td style={{ ...hmxTd, fontSize: 11, color: "#64748b" }}>
                  {r.clasificacion === "FANTASMA" && (r.autorizado ? "Validar con supervisor si el helper realmente operó" : "Bloquear flag en este SC")}
                  {r.clasificacion === "CORRECTO" && "OK · sin acción"}
                  {r.clasificacion === "RARO" && "Investigar: ¿chofer inhabilitado?"}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// ─── Badge de clasificación ─────────────────────────────────────────────
function HelpersBadge({ clasificacion }) {
  const cfg = {
    CORRECTO:   { bg: "#dcfce7", color: "#166534", label: "Correcto" },
    FANTASMA:   { bg: "#fee2e2", color: "#991b1b", label: "Fantasma" },
    RARO:       { bg: "#ffedd5", color: "#9a3412", label: "Raro" },
    NO_MARCADO: { bg: "#dbeafe", color: "#1e40af", label: "No marcado" },
    NORMAL:     { bg: "#f3f4f6", color: "#6b7280", label: "Normal" },
  }[clasificacion] || { bg: "#f3f4f6", color: "#6b7280", label: clasificacion };
  return (
    <span style={{ fontSize: 10, fontWeight: 700, padding: "3px 8px", borderRadius: 4, background: cfg.bg, color: cfg.color, whiteSpace: "nowrap" }}>
      {cfg.label}
    </span>
  );
}

// ─── Estilos de tabla compartidos del módulo helpers ───────────────────
const hmxTh  = { textAlign: "left", fontSize: 10, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5, padding: "10px 12px", borderBottom: "1px solid #e4e7ec", background: "#f9fafb" };
const hmxThR = { ...hmxTh, textAlign: "right" };
const hmxTd  = { fontSize: 12, color: "#0f172a", padding: "10px 12px" };
const hmxTdR = { ...hmxTd, textAlign: "right", fontVariantNumeric: "tabular-nums" };

// ═══════════════════════════════════════════════════════════════════════════
// MÓDULO MANTENCIONES · Cuidado de Activo
// Pestaña madre con sub-tabs. v1: Verificador de neumáticos (emula la imagen).
// ───────────────────────────────────────────────────────────────────────────
function FormRegistrarEvento({ patente, onGuardado, onCerrar, usuario }) {
  const [tipo, setTipo] = useState("reparacion");
  const [componente, setComponente] = useState("");
  const [fecha, setFecha] = useState(new Date().toISOString().slice(0,10));
  const [descripcion, setDescripcion] = useState("");
  const [item, setItem] = useState("");
  const [taller, setTaller] = useState("");
  const [odometro, setOdometro] = useState("");
  const [costo, setCosto] = useState("");
  const [archivo, setArchivo] = useState(null);
  const [guardando, setGuardando] = useState(false);
  const [err, setErr] = useState("");

  const tipos = [["reparacion","Reparación / Compra"],["mantencion","Mantención"],["siniestro","Siniestro"],["otro","Otro"]];
  const comps = [["","(ninguno)"],["neumatico","Neumáticos"],["frenos","Frenos"],["amortiguadores","Amortiguadores"],["direccion","Dirección"],["embrague","Embrague"]];

  async function guardar() {
    if (!fecha) { setErr("La fecha es obligatoria."); return; }
    if (!descripcion && !item) { setErr("Poné una descripción o ítem."); return; }
    setGuardando(true); setErr("");
    try {
      let adjunto_url = null;
      if (archivo) {
        const ext = (archivo.name.split(".").pop() || "pdf").toLowerCase();
        const path = `${patente}/${Date.now()}.${ext}`;
        const { error: upErr } = await sb.storage.from("ca-adjuntos").upload(path, archivo, { upsert: false });
        if (upErr) throw new Error("Subida PDF: " + upErr.message);
        const { data: pub } = sb.storage.from("ca-adjuntos").getPublicUrl(path);
        adjunto_url = pub?.publicUrl || null;
      }
      const { error } = await sb.from("ca_eventos").insert({
        patente, tipo, componente: componente || null, fecha_servicio: fecha,
        descripcion: descripcion || null, item: item || null, taller: taller || null,
        odometro: odometro ? Number(odometro) : null, costo: costo ? Number(costo) : null,
        adjunto_url, registrado_por: usuario?.nombre || null,
      });
      if (error) throw error;
      onGuardado && onGuardado();
    } catch (e) { setErr(e.message); }
    setGuardando(false);
  }

  return (
    <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,0.4)", display:"flex", alignItems:"center", justifyContent:"center", zIndex:1000, padding:20 }}>
      <div style={{ background:"#fff", borderRadius:14, padding:24, maxWidth:560, width:"100%", maxHeight:"90vh", overflowY:"auto" }}>
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:16 }}>
          <div style={{ fontSize:16, fontWeight:700, color:"#1a3a6b" }}>Registrar evento · {patente}</div>
          <button onClick={onCerrar} style={{ background:"none", border:"none", fontSize:20, cursor:"pointer", color:"#94a3b8" }}>×</button>
        </div>

        <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:12 }}>
          <div><Label>Tipo de evento</Label><Select value={tipo} onChange={e=>setTipo(e.target.value)}>{tipos.map(([k,v])=><option key={k} value={k}>{v}</option>)}</Select></div>
          <div><Label>Componente (resetea contador)</Label><Select value={componente} onChange={e=>setComponente(e.target.value)}>{comps.map(([k,v])=><option key={k} value={k}>{v}</option>)}</Select></div>
          <div><Label>Fecha</Label><Input type="date" value={fecha} onChange={e=>setFecha(e.target.value)} /></div>
          <div><Label>Odómetro (km)</Label><Input type="number" value={odometro} onChange={e=>setOdometro(e.target.value)} placeholder="Ej: 70010" /></div>
          <div><Label>Taller</Label><Input value={taller} onChange={e=>setTaller(e.target.value)} placeholder="Taller" /></div>
          <div><Label>Costo ($)</Label><Input type="number" value={costo} onChange={e=>setCosto(e.target.value)} placeholder="Ej: 350000" /></div>
        </div>
        <div style={{ marginTop:12 }}><Label>Ítem</Label><Input value={item} onChange={e=>setItem(e.target.value)} placeholder="Ej: Compra de neumáticos traseros" /></div>
        <div style={{ marginTop:12 }}><Label>Descripción</Label><Textarea value={descripcion} onChange={e=>setDescripcion(e.target.value)} rows={2} placeholder="Detalle del trabajo / compra" /></div>
        <div style={{ marginTop:12 }}>
          <Label>Adjunto PDF (factura/orden)</Label>
          <input type="file" accept="application/pdf,image/*" onChange={e=>setArchivo(e.target.files?.[0]||null)} style={{ fontSize:12 }} />
          {archivo && <span style={{ fontSize:11, color:"#666", marginLeft:8 }}>{archivo.name}</span>}
        </div>

        {err && <div style={{ marginTop:12, padding:"10px 14px", background:"#fee2e2", color:"#c0392b", borderRadius:8, fontSize:13 }}>{err}</div>}

        <div style={{ display:"flex", gap:10, justifyContent:"flex-end", marginTop:18 }}>
          <Btn onClick={onCerrar} color="#94a3b8" outline>Cancelar</Btn>
          <Btn onClick={guardar} color="#1a3a6b">{guardando?"Guardando…":"Guardar evento"}</Btn>
        </div>
      </div>
    </div>
  );
}

function FichaVehiculo({ usuario }) {
  const [patente, setPatente] = useState("");
  const [cargando, setCargando] = useState(false);
  const [error, setError] = useState("");
  const [data, setData] = useState(null);
  const [mostrarForm, setMostrarForm] = useState(false);

  async function buscar() {
    const p = patente.trim().toUpperCase();
    if (!p) { setError("Ingresá una patente."); return; }
    setCargando(true); setError(""); setData(null);
    try {
      const { data: veh } = await sb.from("ca_vehiculos")
        .select("patente,ceco,tipo_vehiculo,modelo,marca,anio,soap,rev_tecnica,permiso_circulacion,status,supervisor").eq("patente", p).maybeSingle();
      if (!veh) { setError(`La patente ${p} no está en la flota.`); setCargando(false); return; }

      const { data: odo } = await sb.from("ca_odometros")
        .select("odometro,fecha_lectura").eq("patente", p)
        .order("fecha_lectura", { ascending:false }).limit(1).maybeSingle();

      const [mant, rep, sin, otr, eve] = await Promise.all([
        sb.from("ca_mantenciones").select("fecha_servicio,servicio_efectuado,item,taller,odometro,costo").eq("patente", p),
        sb.from("ca_reparaciones").select("fecha_servicio,servicio_efectuado,item,taller,odometro,costo").eq("patente", p),
        sb.from("ca_siniestros").select("fecha_servicio,item,taller,odometro,costo,precio_reparacion_total").eq("patente", p),
        sb.from("ca_otros").select("fecha_servicio,servicio_efectuado,item,taller,km_al_momento,costo").eq("patente", p),
        sb.from("ca_eventos").select("fecha_servicio,tipo,componente,descripcion,item,taller,odometro,costo,adjunto_url").eq("patente", p),
      ]);

      const ev = [];
      (mant.data||[]).forEach(r => ev.push({ tipo:"Mantención", color:"#1a3a6b", bg:"#eef2ff", fecha:r.fecha_servicio, desc:r.servicio_efectuado||r.item, taller:r.taller, odometro:r.odometro, costo:Number(r.costo)||0 }));
      (rep.data||[]).forEach(r => ev.push({ tipo:"Reparación", color:"#0369a1", bg:"#e0f2fe", fecha:r.fecha_servicio, desc:r.servicio_efectuado||r.item, taller:r.taller, odometro:r.odometro, costo:Number(r.costo)||0 }));
      (sin.data||[]).forEach(r => ev.push({ tipo:"Siniestro", color:"#c0392b", bg:"#fee2e2", fecha:r.fecha_servicio, desc:r.item, taller:r.taller, odometro:r.odometro, costo:Number(r.precio_reparacion_total)||Number(r.costo)||0 }));
      (otr.data||[]).forEach(r => ev.push({ tipo:"Otro", color:"#92400e", bg:"#fef3c7", fecha:r.fecha_servicio, desc:r.servicio_efectuado||r.item, taller:r.taller, odometro:r.km_al_momento, costo:Number(r.costo)||0 }));
      (eve.data||[]).forEach(r => { const tc=({mantencion:["Mantención","#1a3a6b","#eef2ff"],reparacion:["Reparación","#0369a1","#e0f2fe"],siniestro:["Siniestro","#c0392b","#fee2e2"],otro:["Otro","#92400e","#fef3c7"]})[r.tipo]||["Evento","#475569","#f1f5f9"]; ev.push({ tipo:tc[0]+(r.componente?` · ${r.componente}`:""), color:tc[1], bg:tc[2], fecha:r.fecha_servicio, desc:r.descripcion||r.item, taller:r.taller, odometro:r.odometro, costo:Number(r.costo)||0, adjunto:r.adjunto_url }); });
      ev.sort((a,b) => new Date(b.fecha||0) - new Date(a.fecha||0));

      const tot = (arr) => arr.reduce((s,e)=>s+e.costo,0);
      const resumen = {
        total: tot(ev), n: ev.length,
        mant: tot(ev.filter(e=>e.tipo==="Mantención")),
        rep: tot(ev.filter(e=>e.tipo==="Reparación")),
        sin: tot(ev.filter(e=>e.tipo==="Siniestro")),
      };
      setData({ veh, km: odo ? Number(odo.odometro) : null, fechaOdo: odo?.fecha_lectura, ev, resumen });
    } catch (e) { setError("Error: " + e.message); }
    setCargando(false);
  }

  const clp = (n) => "$" + (Number(n)||0).toLocaleString("es-CL");
  const fch = (f) => f ? new Date(f).toLocaleDateString("es-CL") : "—";
  const venc = (f) => {
    if (!f) return { txt:"—", color:"#94a3b8" };
    const dias = Math.floor((new Date(f) - Date.now())/86400000);
    if (dias < 0) return { txt:`Vencida (${fch(f)})`, color:"#c0392b" };
    if (dias < 30) return { txt:`Vence en ${dias}d (${fch(f)})`, color:"#d97706" };
    return { txt:fch(f), color:"#166534" };
  };

  return (
    <div style={{ maxWidth:900 }}>
      <div className="form-card">
        <div style={{ display:"flex", gap:12, alignItems:"flex-end", flexWrap:"wrap" }}>
          <div style={{ flex:"1 1 220px" }}>
            <Label>Patente</Label>
            <Input value={patente} onChange={e=>setPatente(e.target.value.toUpperCase())} placeholder="Ej: SLCY14" />
          </div>
          <Btn onClick={buscar} color="#1a3a6b">{cargando ? "Buscando…" : "Buscar"}</Btn>
        </div>
        {error && <div style={{ marginTop:14, padding:"10px 14px", background:"#fee2e2", color:"#c0392b", borderRadius:8, fontSize:13 }}>{error}</div>}
      </div>

      {data && (() => {
        const soap = venc(data.veh.soap), rt = venc(data.veh.rev_tecnica);
        return (
        <>
          <div className="form-card">
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", flexWrap:"wrap", gap:10 }}>
              <div>
                <div style={{ fontSize:18, fontWeight:700, color:"#1a1a1a" }}>{data.veh.patente}</div>
                <div style={{ fontSize:13, color:"#666" }}>{data.veh.marca} {data.veh.modelo} · {data.veh.anio || "—"} · CECO: {data.veh.ceco} · Supervisor: {data.veh.supervisor||"—"}</div>
              </div>
              <div style={{ display:"flex", alignItems:"center", gap:10 }}>
                <span style={{ fontSize:11, fontWeight:700, padding:"4px 12px", borderRadius:20, background:data.veh.status==="ACTIVO"?"#dcfce7":"#f1f5f9", color:data.veh.status==="ACTIVO"?"#166534":"#64748b" }}>{data.veh.status}</span>
                <Btn onClick={()=>setMostrarForm(true)} color="#1a3a6b" small>+ Registrar evento</Btn>
              </div>
              {mostrarForm && <FormRegistrarEvento patente={data.veh.patente} usuario={usuario} onCerrar={()=>setMostrarForm(false)} onGuardado={()=>{ setMostrarForm(false); buscar(); }} />}
            </div>
            <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit,minmax(150px,1fr))", gap:12, marginTop:16 }}>
              <div><Label>KM actual</Label><div style={{ fontSize:15, fontWeight:700 }}>{data.km!=null?data.km.toLocaleString("es-CL")+" km":"—"}</div></div>
              <div><Label>SOAP</Label><div style={{ fontSize:13, fontWeight:600, color:soap.color }}>{soap.txt}</div></div>
              <div><Label>Revisión técnica</Label><div style={{ fontSize:13, fontWeight:600, color:rt.color }}>{rt.txt}</div></div>
              <div><Label>Tipo</Label><div style={{ fontSize:13, fontWeight:600 }}>{data.veh.tipo_vehiculo}</div></div>
            </div>
          </div>

          <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit,minmax(150px,1fr))", gap:12, marginBottom:16 }}>
            <KPI label="Gasto total" valor={clp(data.resumen.total)} color="#1a3a6b" />
            <KPI label="Eventos" valor={data.resumen.n} sub="en el historial" color="#0369a1" />
            <KPI label="Mantenciones" valor={clp(data.resumen.mant)} color="#1a3a6b" />
            <KPI label="Reparaciones" valor={clp(data.resumen.rep)} color="#0369a1" />
            <KPI label="Siniestros" valor={clp(data.resumen.sin)} color="#c0392b" />
          </div>

          <div className="form-card">
            <div className="form-title">Historial unificado ({data.ev.length})</div>
            {data.ev.length===0 ? (
              <div style={{ fontSize:13, color:"#94a3b8", padding:"10px 0" }}>Sin eventos registrados.</div>
            ) : (
              <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
                {data.ev.map((e,i) => (
                  <div key={i} style={{ display:"flex", gap:12, alignItems:"center", padding:"10px 12px", border:"1px solid #f1f5f9", borderRadius:8, borderLeft:`3px solid ${e.color}` }}>
                    <div style={{ minWidth:90 }}>
                      <span style={{ fontSize:10, fontWeight:700, padding:"3px 8px", borderRadius:6, background:e.bg, color:e.color }}>{e.tipo}</span>
                    </div>
                    <div style={{ minWidth:80, fontSize:12, color:"#666" }}>{fch(e.fecha)}</div>
                    <div style={{ flex:1, fontSize:13, color:"#1a1a1a" }}>
                      {e.desc || "—"}
                      <span style={{ color:"#94a3b8", fontSize:11 }}>{e.taller?` · ${e.taller}`:""}{e.odometro?` · ${Number(e.odometro).toLocaleString("es-CL")} km`:""}</span>
                    </div>
                    <div style={{ display:"flex", flexDirection:"column", alignItems:"flex-end", gap:2, whiteSpace:"nowrap" }}>
                      <span style={{ fontWeight:700, fontSize:13, color:"#1a1a1a" }}>{clp(e.costo)}</span>
                      {e.adjunto && <a href={e.adjunto} target="_blank" rel="noreferrer" style={{ fontSize:10, color:"#0369a1" }}>📎 PDF</a>}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </>
        );
      })()}
    </div>
  );
}

function TableroAlertas() {
  const [rows, setRows] = useState(null);
  const [cargando, setCargando] = useState(false);
  const [error, setError] = useState("");
  const [fComp, setFComp] = useState("todos");
  const [fEstado, setFEstado] = useState("criticos");

  async function cargar() {
    setCargando(true); setError("");
    try {
      const { data, error } = await sb.from("vw_ca_alertas").select("*");
      if (error) throw error;
      setRows(data || []);
    } catch (e) { setError("Error: " + e.message); }
    setCargando(false);
  }
  useEffect(() => { cargar(); }, []);

  const cfg = {
    supera_limite: { txt:"Supera límite", color:"#c0392b", bg:"#fee2e2", ico:"🔴", ord:0 },
    alerta:        { txt:"Alerta",        color:"#92400e", bg:"#fef3c7", ico:"🟡", ord:1 },
    ok:            { txt:"OK",            color:"#166534", bg:"#dcfce7", ico:"🟢", ord:2 },
    sin_dato:      { txt:"Sin dato",      color:"#64748b", bg:"#f1f5f9", ico:"⚪", ord:3 },
  };
  const comps = ["todos","neumatico","frenos","amortiguadores","direccion","embrague"];
  const all = rows || [];
  const resumen = {
    supera: all.filter(r=>r.estado==="supera_limite").length,
    alerta: all.filter(r=>r.estado==="alerta").length,
    ok:     all.filter(r=>r.estado==="ok").length,
    sin:    all.filter(r=>r.estado==="sin_dato").length,
  };

  let vis = all.filter(r => fComp==="todos" || r.componente===fComp);
  if (fEstado==="criticos") vis = vis.filter(r=>r.estado==="supera_limite"||r.estado==="alerta");
  else if (fEstado!=="todos") vis = vis.filter(r=>r.estado===fEstado);
  vis = [...vis].sort((a,b) => {
    const oa=cfg[a.estado]?.ord??9, ob=cfg[b.estado]?.ord??9;
    if (oa!==ob) return oa-ob;
    const da=a.dias_al_limite==null?1e9:Number(a.dias_al_limite), db=b.dias_al_limite==null?1e9:Number(b.dias_al_limite);
    return da-db;
  });

  const cl = (n)=> n==null?"—":Number(n).toLocaleString("es-CL");

  return (
    <div>
      <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit,minmax(150px,1fr))", gap:12, marginBottom:16 }}>
        <KPI label="🔴 Supera límite" valor={resumen.supera} color="#c0392b" />
        <KPI label="🟡 En alerta"     valor={resumen.alerta} color="#d97706" />
        <KPI label="🟢 En protocolo"  valor={resumen.ok} color="#166534" />
        <KPI label="⚪ Sin dato"       valor={resumen.sin} sub="sin servicio registrado" color="#64748b" />
      </div>

      <div className="form-card">
        <div style={{ display:"flex", gap:16, flexWrap:"wrap", alignItems:"flex-end", marginBottom:14 }}>
          <div style={{ minWidth:170 }}>
            <Label>Componente</Label>
            <Select value={fComp} onChange={e=>setFComp(e.target.value)}>
              {comps.map(c => <option key={c} value={c}>{c==="todos"?"Todos":c.charAt(0).toUpperCase()+c.slice(1)}</option>)}
            </Select>
          </div>
          <div style={{ minWidth:170 }}>
            <Label>Estado</Label>
            <Select value={fEstado} onChange={e=>setFEstado(e.target.value)}>
              <option value="criticos">Solo críticos (🔴+🟡)</option>
              <option value="supera_limite">🔴 Supera límite</option>
              <option value="alerta">🟡 Alerta</option>
              <option value="ok">🟢 OK</option>
              <option value="todos">Todos</option>
            </Select>
          </div>
          <Btn onClick={cargar} color="#1a3a6b" outline>{cargando?"Cargando…":"Refrescar"}</Btn>
          <div style={{ fontSize:12, color:"#94a3b8", marginLeft:"auto" }}>{vis.length} resultado(s)</div>
        </div>

        {error && <div style={{ padding:"10px 14px", background:"#fee2e2", color:"#c0392b", borderRadius:8, fontSize:13 }}>{error}</div>}

        {!error && (
          <div style={{ overflowX:"auto" }}>
            <table style={{ width:"100%", borderCollapse:"collapse", fontSize:13 }}>
              <thead>
                <tr style={{ borderBottom:"2px solid #e4e7ec", textAlign:"left", color:"#64748b", fontSize:11, textTransform:"uppercase", letterSpacing:.4 }}>
                  <th style={{ padding:"8px 6px" }}>Estado</th>
                  <th style={{ padding:"8px 6px" }}>Patente</th>
                  <th style={{ padding:"8px 6px" }}>Modelo</th>
                  <th style={{ padding:"8px 6px" }}>Componente</th>
                  <th style={{ padding:"8px 6px", textAlign:"right" }}>Recorrido / Límite</th>
                  <th style={{ padding:"8px 6px", textAlign:"right" }}>km/día (30d)</th>
                  <th style={{ padding:"8px 6px", textAlign:"right" }}>Días al límite</th>
                </tr>
              </thead>
              <tbody>
                {vis.map((r,i) => {
                  const c = cfg[r.estado] || cfg.sin_dato;
                  const dias = r.dias_al_limite;
                  const diasTxt = r.estado==="supera_limite" ? "Vencido" : dias==null ? "—" : `${cl(dias)} días`;
                  const diasColor = r.estado==="supera_limite" ? "#c0392b" : (dias!=null && Number(dias)<=30) ? "#d97706" : "#475569";
                  return (
                    <tr key={i} style={{ borderBottom:"1px solid #f1f5f9" }}>
                      <td style={{ padding:"8px 6px" }}><span style={{ fontSize:11, fontWeight:700, padding:"3px 8px", borderRadius:6, background:c.bg, color:c.color, whiteSpace:"nowrap" }}>{c.ico} {c.txt}</span></td>
                      <td style={{ padding:"8px 6px", fontWeight:700 }}>{r.patente}</td>
                      <td style={{ padding:"8px 6px", color:"#666" }}>{r.modelo}</td>
                      <td style={{ padding:"8px 6px", textTransform:"capitalize" }}>{r.componente}</td>
                      <td style={{ padding:"8px 6px", textAlign:"right" }}>{cl(r.recorrido)} / {cl(r.limite)}</td>
                      <td style={{ padding:"8px 6px", textAlign:"right", color:"#666" }}>{cl(r.km_dia_30)}</td>
                      <td style={{ padding:"8px 6px", textAlign:"right", fontWeight:700, color:diasColor }}>{diasTxt}</td>
                    </tr>
                  );
                })}
                {vis.length===0 && <tr><td colSpan={7} style={{ padding:"20px", textAlign:"center", color:"#94a3b8" }}>Sin resultados con estos filtros.</td></tr>}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

function VerificadorComponentes({ usuario }) {
  const [componente, setComponente] = useState("neumatico");
  const [patente, setPatente] = useState("");
  const [cargando, setCargando] = useState(false);
  const [error, setError] = useState("");
  const [info, setInfo] = useState(null);
  const [generando, setGenerando] = useState(false);
  const [msg, setMsg] = useState("");

  const compLabels = { neumatico:"Neumáticos", frenos:"Frenos", amortiguadores:"Amortiguadores", direccion:"Dirección", embrague:"Embrague" };

  async function verificar() {
    const p = patente.trim().toUpperCase();
    if (!p) { setError("Ingresá una patente."); return; }
    setCargando(true); setError(""); setInfo(null); setMsg("");
    try {
      const { data: veh } = await sb.from("ca_vehiculos").select("patente,ceco,tipo_vehiculo,modelo,supervisor").eq("patente", p).maybeSingle();
      if (!veh) { setError(`La patente ${p} no está en la flota.`); setCargando(false); return; }
      const { data: row } = await sb.from("vw_ca_alertas").select("*").eq("patente", p).eq("componente", componente).maybeSingle();
      if (!row) { setError(`No hay protocolo de ${compLabels[componente]} para el modelo ${veh.modelo}.`); setCargando(false); return; }
      setInfo({ veh, row });
    } catch (e) { setError("Error: " + e.message); }
    setCargando(false);
  }

  async function generarSolicitud() {
    if (!info) return;
    setGenerando(true); setMsg("");
    const { veh, row } = info;
    const num = (x) => x == null ? null : Number(x);
    const kmActual = num(row.km_actual), kmServ = num(row.km_ultimo_servicio), recorrido = num(row.recorrido);
    const alerta = num(row.alerta), limite = num(row.limite);
    const kmAlerta = kmServ!=null?kmServ+alerta:null, kmLimite = kmServ!=null?kmServ+limite:null;
    const kmRest = kmLimite!=null?kmLimite-kmActual:null;
    const cl = (n) => n==null?"—":Number(n).toLocaleString("es-CL");
    const just = `Vehículo ${veh.patente} (${veh.modelo}, ${veh.ceco}) · ${compLabels[componente]}: recorrió ${cl(recorrido)} km desde el último servicio (odómetro ${cl(kmServ)} km). Umbral de alerta: ${cl(alerta)} km; límite: ${cl(limite)} km. Km actual: ${cl(kmActual)} km. Se solicita autorización de cambio/compra.`;
    try {
      const { error } = await sb.from("ca_solicitudes").insert({
        patente:veh.patente, ceco:veh.ceco, tipo_vehiculo:veh.tipo_vehiculo, modelo:veh.modelo,
        componente, km_ultima_compra:kmServ, km_actual:kmActual, km_recorridos:recorrido,
        km_alerta:kmAlerta, km_limite:kmLimite, km_restantes:kmRest, estado_protocolo:row.estado,
        justificacion:just, solicitante: usuario?.nombre||null, status:"pendiente",
      });
      if (error) throw error;
      setMsg("✅ Solicitud generada y enviada a Finanzas.");
    } catch (e) { setMsg("❌ Error: " + e.message); }
    setGenerando(false);
  }

  const fmt = (n) => n==null?"—":Number(n).toLocaleString("es-CL")+" km";
  const estadoCfg = {
    ok:            { txt:"En protocolo",     color:"#166534", bg:"#dcfce7", ico:"✓" },
    alerta:        { txt:"En alerta",         color:"#92400e", bg:"#fef3c7", ico:"⚠" },
    supera_limite: { txt:"Supera límite",     color:"#c0392b", bg:"#fee2e2", ico:"⚠" },
    sin_dato:      { txt:"Sin servicio previo",color:"#475569", bg:"#f1f5f9", ico:"•" },
  };

  return (
    <div>
      <div style={{ maxWidth:760, marginBottom:28 }}>
        <div style={{ background:"#1a3a6b", color:"#fff", borderRadius:"14px 14px 0 0", padding:"16px 20px", display:"flex", alignItems:"center", gap:10 }}>
          <span style={{ fontSize:18 }}>🔧</span>
          <span style={{ fontSize:15, fontWeight:700 }}>Verificador de Componentes — Bigticket</span>
        </div>
        <div style={{ background:"#fff", border:"1px solid #e4e7ec", borderTop:"none", borderRadius:"0 0 14px 14px", padding:20 }}>
          <div style={{ display:"flex", gap:12, alignItems:"flex-end", flexWrap:"wrap" }}>
            <div style={{ flex:"1 1 180px" }}>
              <Label>Componente</Label>
              <Select value={componente} onChange={e=>{ setComponente(e.target.value); setInfo(null); }}>
                {Object.entries(compLabels).map(([k,v]) => <option key={k} value={k}>{v}</option>)}
              </Select>
            </div>
            <div style={{ flex:"1 1 180px" }}>
              <Label>Patente</Label>
              <Input value={patente} onChange={e=>setPatente(e.target.value.toUpperCase())} placeholder="Ej: SLCY14" />
            </div>
            <Btn onClick={verificar} color="#1a3a6b">{cargando?"Verificando…":"Verificar"}</Btn>
          </div>

          {error && <div style={{ marginTop:14, padding:"10px 14px", background:"#fee2e2", color:"#c0392b", borderRadius:8, fontSize:13 }}>{error}</div>}

          {info && (() => {
            const r = info.row;
            const recorrido = r.recorrido!=null?Number(r.recorrido):null;
            const alerta = Number(r.alerta), limite = Number(r.limite);
            const kmActual = Number(r.km_actual), kmServ = r.km_ultimo_servicio!=null?Number(r.km_ultimo_servicio):null;
            const kmAlerta = kmServ!=null?kmServ+alerta:null, kmLimite = kmServ!=null?kmServ+limite:null;
            const kmRest = kmLimite!=null?kmLimite-kmActual:null;
            const cfg = estadoCfg[r.estado] || estadoCfg.sin_dato;
            const pct = recorrido!=null?Math.min(100,Math.max(0,(recorrido/limite)*100)):0;
            const pctAl = Math.min(100,(alerta/limite)*100);
            const barColor = r.estado==="supera_limite"?"#dc2626":r.estado==="alerta"?"#d97706":"#16a34a";
            return (
            <div style={{ marginTop:18 }}>
              <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:8 }}>
                <div>
                  <div style={{ fontSize:14, fontWeight:700 }}>{compLabels[componente]} · {info.veh.modelo} {info.veh.patente}</div>
                  <div style={{ fontSize:12, color:"#666", marginTop:2 }}>CECO: {info.veh.ceco||"—"} · Supervisor: {info.veh.supervisor||"—"}</div>
                </div>
                <span style={{ fontSize:12, fontWeight:700, padding:"5px 12px", borderRadius:20, background:cfg.bg, color:cfg.color }}>{cfg.ico} {cfg.txt}</span>
              </div>
              <div style={{ fontSize:12, color:"#666", marginBottom:10 }}>Último servicio: {kmServ!=null?kmServ.toLocaleString("es-CL"):"—"} → KM actual: {kmActual.toLocaleString("es-CL")}{r.dias_al_limite!=null?` · ~${Number(r.dias_al_limite).toLocaleString("es-CL")} días al límite`:""}</div>
              <div style={{ display:"flex", justifyContent:"space-between", fontSize:11, color:"#94a3b8", marginBottom:4 }}>
                <span>0 km</span><span>Alerta: {alerta.toLocaleString("es-CL")}</span><span>Límite: {limite.toLocaleString("es-CL")}</span>
              </div>
              <div style={{ position:"relative", height:14, background:"#f1f5f9", borderRadius:8, overflow:"hidden", marginBottom:4 }}>
                <div style={{ position:"absolute", left:0, top:0, height:"100%", width:`${pct}%`, background:barColor, transition:"width .4s" }} />
                <div style={{ position:"absolute", left:`${pctAl}%`, top:0, height:"100%", width:2, background:"#64748b" }} />
              </div>
              <div style={{ display:"flex", justifyContent:"space-between", fontSize:12, marginBottom:18 }}>
                <span style={{ color:"#666" }}>Recorrido desde último servicio:</span>
                <span style={{ fontWeight:700 }}>{recorrido!=null?recorrido.toLocaleString("es-CL"):"—"} km</span>
              </div>
              <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit,minmax(150px,1fr))", gap:12, marginBottom:18 }}>
                <KPI label="KM de alerta" valor={fmt(kmAlerta)} color="#d97706" />
                <KPI label="KM límite máximo" valor={fmt(kmLimite)} color="#dc2626" />
                <KPI label="KM restantes al límite" valor={fmt(kmRest)} color={kmRest!=null&&kmRest<0?"#dc2626":"#1a3a6b"} />
              </div>
              <div style={{ borderTop:"1px solid #e4e7ec", paddingTop:16 }}>
                {(r.estado==="alerta"||r.estado==="supera_limite") ? (
                  <Btn onClick={generarSolicitud} color="#1a3a6b">{generando?"Generando…":"Generar solicitud para finanzas"}</Btn>
                ) : r.estado==="sin_dato" ? (
                  <div style={{ fontSize:13, color:"#92400e" }}>Sin servicio previo registrado de {compLabels[componente].toLowerCase()} — no se puede calcular recorrido.</div>
                ) : (
                  <div style={{ fontSize:13, color:"#166534" }}>✓ Dentro de protocolo — no corresponde cambio. Consulta registrada.</div>
                )}
                {msg && <div style={{ marginTop:12, fontSize:13, fontWeight:600 }}>{msg}</div>}
              </div>
            </div>
            );
          })()}
        </div>
      </div>

      <div style={{ fontSize:15, fontWeight:700, color:"#1a3a6b", marginBottom:4 }}>Panorama de la flota</div>
      <div style={{ fontSize:12, color:"#666", marginBottom:14 }}>Estado de todos los componentes de la flota</div>
      <TableroAlertas />
    </div>
  );
}

function FlujoCaja() {
  const [rows, setRows] = useState(null);
  const [cargando, setCargando] = useState(false);
  const [error, setError] = useState("");
  const [horizonte, setHorizonte] = useState(30);
  const [precios, setPrecios] = useState({});

  async function cargar() {
    setCargando(true); setError("");
    try {
      const { data, error } = await sb.from("vw_ca_flujo").select("*");
      if (error) throw error;
      setRows(data || []);
      const { data: pm } = await sb.from("ca_precios_mercado").select("componente,modelo,precio_clp");
      const mapa = {}; (pm||[]).forEach(p => { mapa[`${p.componente}|${p.modelo}`] = p.precio_clp!=null?Number(p.precio_clp):null; });
      setPrecios(mapa);
    } catch (e) { setError("Error: " + e.message); }
    setCargando(false);
  }
  useEffect(() => { cargar(); }, []);

  const all = rows || [];
  const compLabel = { neumatico:"Neumáticos", frenos:"Frenos", amortiguadores:"Amortiguadores", direccion:"Dirección", embrague:"Embrague" };

  // clasificar cada par vehículo-componente según el horizonte
  const items = [];
  for (const r of all) {
    const recorrido = r.recorrido!=null?Number(r.recorrido):null;
    const limite = Number(r.limite);
    const kmDia = r.km_dia_30!=null?Number(r.km_dia_30):null;
    let costo = r.costo_estimado!=null?Number(r.costo_estimado):null;
    let costoFuente = r.costo_fuente;
    if (costo==null) { const pm = precios[`${r.componente}|${r.modelo}`]; if (pm!=null) { costo = pm; costoFuente = "mercado"; } }
    if (recorrido==null) continue;
    let clase = null, diasCruce = null;
    if (r.estado==="supera_limite") { clase="inmediato"; diasCruce=0; }
    else if (kmDia && kmDia>0) {
      const proyectado = recorrido + kmDia*horizonte;
      if (proyectado >= limite) {
        clase="proyectado";
        diasCruce = Math.max(0, Math.round((limite - recorrido)/kmDia));
      }
    }
    if (clase) items.push({ ...r, costo, costo_fuente: costoFuente, clase, diasCruce });
  }
  items.sort((a,b) => (a.clase===b.clase ? (a.diasCruce-b.diasCruce) : (a.clase==="inmediato"?-1:1)));

  const sum = (arr) => arr.reduce((s,e)=>s+(e.costo||0),0);
  const inmediatos = items.filter(i=>i.clase==="inmediato");
  const proyectados = items.filter(i=>i.clase==="proyectado");
  const sinCosto = items.filter(i=>i.costo==null).length;
  const clp = (n)=> n==null?"s/d":"$"+Number(n).toLocaleString("es-CL");

  return (
    <div>
      <div className="form-card" style={{ display:"flex", gap:16, alignItems:"flex-end", flexWrap:"wrap" }}>
        <div style={{ minWidth:160 }}>
          <Label>Horizonte</Label>
          <Select value={horizonte} onChange={e=>setHorizonte(Number(e.target.value))}>
            <option value={30}>Próximos 30 días</option>
            <option value={60}>Próximos 60 días</option>
            <option value={90}>Próximos 90 días</option>
          </Select>
        </div>
        <Btn onClick={cargar} color="#1a3a6b" outline>{cargando?"Cargando…":"Refrescar"}</Btn>
        <div style={{ fontSize:11, color:"#94a3b8", marginLeft:"auto", maxWidth:280 }}>
          Costo por componente×modelo (fallback global). "s/d" = sin historial de precio.
        </div>
      </div>

      {error && <div style={{ padding:"10px 14px", background:"#fee2e2", color:"#c0392b", borderRadius:8, fontSize:13, marginBottom:16 }}>{error}</div>}

      <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit,minmax(160px,1fr))", gap:12, marginBottom:16 }}>
        <KPI label="Caja total estimada" valor={clp(sum(items))} sub={`${items.length} cambios`} color="#1a3a6b" />
        <KPI label="🔴 Gasto inmediato" valor={clp(sum(inmediatos))} sub={`${inmediatos.length} ya vencidos`} color="#c0392b" />
        <KPI label="🟡 Proyectado" valor={clp(sum(proyectados))} sub={`en ${horizonte} días`} color="#d97706" />
        {sinCosto>0 && <KPI label="Sin costo histórico" valor={sinCosto} sub="usar precio de mercado" color="#64748b" />}
      </div>

      <div className="form-card">
        <div className="form-title">Detalle de cambios — {horizonte} días</div>
        <div style={{ overflowX:"auto" }}>
          <table style={{ width:"100%", borderCollapse:"collapse", fontSize:13 }}>
            <thead>
              <tr style={{ borderBottom:"2px solid #e4e7ec", textAlign:"left", color:"#64748b", fontSize:11, textTransform:"uppercase", letterSpacing:.4 }}>
                <th style={{ padding:"8px 6px" }}>Cuándo</th>
                <th style={{ padding:"8px 6px" }}>Patente</th>
                <th style={{ padding:"8px 6px" }}>Modelo</th>
                <th style={{ padding:"8px 6px" }}>Componente</th>
                <th style={{ padding:"8px 6px", textAlign:"right" }}>Días al cruce</th>
                <th style={{ padding:"8px 6px", textAlign:"right" }}>Costo estimado</th>
                <th style={{ padding:"8px 6px" }}>Fuente</th>
              </tr>
            </thead>
            <tbody>
              {items.map((r,i) => (
                <tr key={i} style={{ borderBottom:"1px solid #f1f5f9" }}>
                  <td style={{ padding:"8px 6px" }}>
                    <span style={{ fontSize:11, fontWeight:700, padding:"3px 8px", borderRadius:6, background:r.clase==="inmediato"?"#fee2e2":"#fef3c7", color:r.clase==="inmediato"?"#c0392b":"#92400e" }}>
                      {r.clase==="inmediato"?"🔴 Ya":"🟡 Proyectado"}
                    </span>
                  </td>
                  <td style={{ padding:"8px 6px", fontWeight:700 }}>{r.patente}</td>
                  <td style={{ padding:"8px 6px", color:"#666" }}>{r.modelo}</td>
                  <td style={{ padding:"8px 6px" }}>{compLabel[r.componente]||r.componente}</td>
                  <td style={{ padding:"8px 6px", textAlign:"right" }}>{r.clase==="inmediato"?"Vencido":`${r.diasCruce} d`}</td>
                  <td style={{ padding:"8px 6px", textAlign:"right", fontWeight:700, color:r.costo==null?"#94a3b8":"#1a1a1a" }}>{clp(r.costo)}</td>
                  <td style={{ padding:"8px 6px", fontSize:11, color:"#94a3b8" }}>{r.costo_fuente||"—"}</td>
                </tr>
              ))}
              {items.length===0 && <tr><td colSpan={7} style={{ padding:"20px", textAlign:"center", color:"#94a3b8" }}>Sin cambios proyectados en este horizonte.</td></tr>}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

function Bitacora({ usuario }) {
  const [sols, setSols] = useState(null);
  const [cargando, setCargando] = useState(false);
  const [error, setError] = useState("");
  const [fEstado, setFEstado] = useState("pendiente");
  const [accion, setAccion] = useState(null);
  const [hist, setHist] = useState(null);
  const [verHist, setVerHist] = useState(false);

  async function cargar() {
    setCargando(true); setError("");
    try {
      const { data, error } = await sb.from("ca_solicitudes").select("*").order("creado_en", { ascending:false });
      if (error) throw error;
      setSols(data || []);
    } catch (e) { setError("Error: " + e.message); }
    setCargando(false);
  }
  useEffect(() => { cargar(); }, []);

  async function cambiarEstado(id, nuevo) {
    setAccion(id);
    try {
      const { error } = await sb.from("ca_solicitudes").update({ status: nuevo }).eq("id", id);
      if (error) throw error;
      await cargar();
    } catch (e) { setError("Error al actualizar: " + e.message); }
    setAccion(null);
  }

  async function toggleHist() {
    if (hist) { setVerHist(!verHist); return; }
    try {
      const { data } = await sb.from("ca_bitacora").select("*").order("fecha_solicitud", { ascending:false });
      setHist(data || []); setVerHist(true);
    } catch (e) { setError("Error histórico: " + e.message); }
  }

  const all = sols || [];
  const cfg = {
    pendiente: { txt:"Pendiente", color:"#92400e", bg:"#fef3c7" },
    aprobada:  { txt:"Aprobada",  color:"#166534", bg:"#dcfce7" },
    rechazada: { txt:"Rechazada", color:"#c0392b", bg:"#fee2e2" },
  };
  const resumen = {
    pendiente: all.filter(s=>s.status==="pendiente").length,
    aprobada:  all.filter(s=>s.status==="aprobada").length,
    rechazada: all.filter(s=>s.status==="rechazada").length,
  };
  const vis = fEstado==="todas" ? all : all.filter(s=>s.status===fEstado);
  const compLabel = { neumaticos:"Neumáticos", neumatico:"Neumáticos", frenos:"Frenos", amortiguadores:"Amortiguadores", direccion:"Dirección", embrague:"Embrague" };
  const cl = (n)=> n==null?"—":Number(n).toLocaleString("es-CL");
  const fch = (f)=> f?new Date(f).toLocaleDateString("es-CL"):"—";

  return (
    <div>
      <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit,minmax(160px,1fr))", gap:12, marginBottom:16 }}>
        <KPI label="🟡 Pendientes" valor={resumen.pendiente} color="#d97706" />
        <KPI label="🟢 Aprobadas"  valor={resumen.aprobada} color="#166534" />
        <KPI label="🔴 Rechazadas" valor={resumen.rechazada} color="#c0392b" />
      </div>

      <div className="form-card">
        <div style={{ display:"flex", gap:16, alignItems:"flex-end", marginBottom:14, flexWrap:"wrap" }}>
          <div style={{ minWidth:180 }}>
            <Label>Estado</Label>
            <Select value={fEstado} onChange={e=>setFEstado(e.target.value)}>
              <option value="pendiente">Pendientes</option>
              <option value="aprobada">Aprobadas</option>
              <option value="rechazada">Rechazadas</option>
              <option value="todas">Todas</option>
            </Select>
          </div>
          <Btn onClick={cargar} color="#1a3a6b" outline>{cargando?"Cargando…":"Refrescar"}</Btn>
          <div style={{ fontSize:12, color:"#94a3b8", marginLeft:"auto" }}>{vis.length} solicitud(es)</div>
        </div>

        {error && <div style={{ padding:"10px 14px", background:"#fee2e2", color:"#c0392b", borderRadius:8, fontSize:13, marginBottom:10 }}>{error}</div>}

        <div style={{ overflowX:"auto" }}>
          <table style={{ width:"100%", borderCollapse:"collapse", fontSize:13 }}>
            <thead>
              <tr style={{ borderBottom:"2px solid #e4e7ec", textAlign:"left", color:"#64748b", fontSize:11, textTransform:"uppercase", letterSpacing:.4 }}>
                <th style={{ padding:"8px 6px" }}>Fecha</th>
                <th style={{ padding:"8px 6px" }}>Patente</th>
                <th style={{ padding:"8px 6px" }}>Componente</th>
                <th style={{ padding:"8px 6px", textAlign:"right" }}>Recorrido / Límite</th>
                <th style={{ padding:"8px 6px" }}>Solicitante</th>
                <th style={{ padding:"8px 6px" }}>Estado</th>
                <th style={{ padding:"8px 6px" }}>Acciones</th>
              </tr>
            </thead>
            <tbody>
              {vis.map((s) => {
                const c = cfg[s.status] || cfg.pendiente;
                return (
                  <tr key={s.id} style={{ borderBottom:"1px solid #f1f5f9" }}>
                    <td style={{ padding:"8px 6px", whiteSpace:"nowrap" }}>{fch(s.creado_en)}</td>
                    <td style={{ padding:"8px 6px", fontWeight:700 }}>{s.patente} <span style={{ fontSize:11, color:"#94a3b8" }}>{s.ceco}</span></td>
                    <td style={{ padding:"8px 6px" }} title={s.justificacion||""}>{compLabel[s.componente]||s.componente} <span style={{ cursor:"help", color:"#0369a1", fontSize:11 }}>ⓘ</span></td>
                    <td style={{ padding:"8px 6px", textAlign:"right" }}>{cl(s.km_recorridos)} / {cl(s.km_limite!=null && s.km_ultima_compra!=null ? s.km_limite - s.km_ultima_compra : null)}</td>
                    <td style={{ padding:"8px 6px", color:"#666" }}>{s.solicitante||"—"}</td>
                    <td style={{ padding:"8px 6px" }}><span style={{ fontSize:11, fontWeight:700, padding:"3px 8px", borderRadius:6, background:c.bg, color:c.color }}>{c.txt}</span></td>
                    <td style={{ padding:"8px 6px" }}>
                      {s.status==="pendiente" ? (
                        <div style={{ display:"flex", gap:6 }}>
                          <button onClick={()=>cambiarEstado(s.id,"aprobada")} disabled={accion===s.id} style={{ fontSize:11, fontWeight:700, padding:"4px 10px", borderRadius:6, border:"none", background:"#166534", color:"#fff", cursor:"pointer" }}>{accion===s.id?"…":"Aprobar"}</button>
                          <button onClick={()=>cambiarEstado(s.id,"rechazada")} disabled={accion===s.id} style={{ fontSize:11, fontWeight:700, padding:"4px 10px", borderRadius:6, border:"1px solid #c0392b", background:"#fff", color:"#c0392b", cursor:"pointer" }}>Rechazar</button>
                        </div>
                      ) : (
                        <button onClick={()=>cambiarEstado(s.id,"pendiente")} style={{ fontSize:11, padding:"4px 10px", borderRadius:6, border:"1px solid #d0d5dd", background:"#fff", color:"#666", cursor:"pointer" }}>Reabrir</button>
                      )}
                    </td>
                  </tr>
                );
              })}
              {vis.length===0 && <tr><td colSpan={7} style={{ padding:"20px", textAlign:"center", color:"#94a3b8" }}>Sin solicitudes con este filtro.</td></tr>}
            </tbody>
          </table>
        </div>
      </div>

      <div style={{ marginTop:8 }}>
        <Btn onClick={toggleHist} color="#64748b" outline small>{verHist?"Ocultar":"Ver"} histórico Excel (bitácora)</Btn>
      </div>
      {verHist && hist && (
        <div className="form-card" style={{ marginTop:12 }}>
          <div className="form-title">Histórico bitácora (Excel) — {hist.length}</div>
          <div style={{ overflowX:"auto" }}>
            <table style={{ width:"100%", borderCollapse:"collapse", fontSize:12 }}>
              <thead><tr style={{ borderBottom:"2px solid #e4e7ec", textAlign:"left", color:"#64748b", fontSize:10, textTransform:"uppercase" }}>
                <th style={{ padding:"6px" }}>Patente</th><th style={{ padding:"6px" }}>Solicitud</th><th style={{ padding:"6px" }}>Necesidad</th><th style={{ padding:"6px", textAlign:"right" }}>Monto</th><th style={{ padding:"6px" }}>Status</th>
              </tr></thead>
              <tbody>
                {hist.map((h,i)=>(
                  <tr key={i} style={{ borderBottom:"1px solid #f1f5f9" }}>
                    <td style={{ padding:"6px", fontWeight:600 }}>{h.patente}</td>
                    <td style={{ padding:"6px" }}>{fch(h.fecha_solicitud)}</td>
                    <td style={{ padding:"6px", color:"#666" }}>{h.necesidad_operativa||"—"}</td>
                    <td style={{ padding:"6px", textAlign:"right" }}>{h.monto_presupuesto?("$"+cl(h.monto_presupuesto)):"—"}</td>
                    <td style={{ padding:"6px" }}>{h.status_solicitud||"—"}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
}

function MantenedorSupervisores() {
  const [veh, setVeh] = useState(null);
  const [sup, setSup] = useState(null);
  const [error, setError] = useState("");
  const [okMsg, setOkMsg] = useState("");
  const [cargando, setCargando] = useState(false);
  const [filtro, setFiltro] = useState("");
  const [vEd, setVEd] = useState({});
  const [sEd, setSEd] = useState({});
  const [guardando, setGuardando] = useState(null);
  const [nuevo, setNuevo] = useState({ nombre:"", correo:"", telefono:"", cargo:"", recibe_global:false });

  async function cargar() {
    setCargando(true); setError(""); setOkMsg("");
    try {
      const [{ data: v, error: ev }, { data: s, error: es }] = await Promise.all([
        sb.from("ca_vehiculos").select("patente,modelo,ceco,supervisor,status").order("patente"),
        sb.from("ca_supervisores").select("nombre,correo,telefono,cargo,recibe_global").order("recibe_global").order("nombre"),
      ]);
      if (ev) throw ev; if (es) throw es;
      setVeh(v||[]); setSup(s||[]);
      const ve={}; (v||[]).forEach(r=>{ ve[r.patente]={ ceco:r.ceco||"", supervisor:r.supervisor||"" }; }); setVEd(ve);
      const se={}; (s||[]).forEach(r=>{ se[r.nombre]={ correo:r.correo||"", telefono:r.telefono||"", cargo:r.cargo||"", recibe_global:!!r.recibe_global }; }); setSEd(se);
    } catch(e){ setError("Error: "+e.message); }
    setCargando(false);
  }
  useEffect(()=>{ cargar(); }, []);

  async function guardarVeh(patente) {
    setGuardando("v:"+patente); setOkMsg(""); setError("");
    try {
      const e = vEd[patente];
      const { error } = await sb.from("ca_vehiculos").update({ ceco:e.ceco||null, supervisor:e.supervisor||null }).eq("patente", patente);
      if (error) throw error;
      setOkMsg(`✅ ${patente} actualizado`);
    } catch(e){ setError("Error: "+e.message); }
    setGuardando(null);
  }
  async function guardarSup(nombre) {
    setGuardando("s:"+nombre); setOkMsg(""); setError("");
    try {
      const e = sEd[nombre];
      const { error } = await sb.from("ca_supervisores").update({ correo:e.correo||null, telefono:e.telefono||null, cargo:e.cargo||null, recibe_global:!!e.recibe_global }).eq("nombre", nombre);
      if (error) throw error;
      setOkMsg(`✅ ${nombre} actualizado`);
    } catch(e){ setError("Error: "+e.message); }
    setGuardando(null);
  }
  async function agregarSup() {
    if (!nuevo.nombre.trim()) { setError("El nombre es obligatorio."); return; }
    setGuardando("nuevo"); setOkMsg(""); setError("");
    try {
      const { error } = await sb.from("ca_supervisores").insert({ nombre:nuevo.nombre.trim().toUpperCase(), correo:nuevo.correo||null, telefono:nuevo.telefono||null, cargo:nuevo.cargo||null, recibe_global:!!nuevo.recibe_global });
      if (error) throw error;
      setNuevo({ nombre:"", correo:"", telefono:"", cargo:"", recibe_global:false });
      await cargar(); setOkMsg("✅ Supervisor agregado");
    } catch(e){ setError("Error: "+e.message); }
    setGuardando(null);
  }

  const F = (filtro||"").toUpperCase();
  const vehs = (veh||[]).filter(r => !F || r.patente.includes(F) || (r.supervisor||"").toUpperCase().includes(F) || (r.ceco||"").toUpperCase().includes(F));
  const supOptions = (sup||[]).map(s=>s.nombre);
  const th = { padding:"8px 6px", textAlign:"left", color:"#64748b", fontSize:11, textTransform:"uppercase", letterSpacing:.4 };
  const td = { padding:"6px", borderBottom:"1px solid #f1f5f9" };
  const inp = { width:"100%", padding:"5px 8px", border:"1px solid #d0d5dd", borderRadius:6, fontSize:13, boxSizing:"border-box" };

  return (
    <div>
      {error && <div style={{ padding:"10px 14px", background:"#fee2e2", color:"#c0392b", borderRadius:8, fontSize:13, marginBottom:12 }}>{error}</div>}
      {okMsg && <div style={{ padding:"10px 14px", background:"#dcfce7", color:"#166534", borderRadius:8, fontSize:13, marginBottom:12 }}>{okMsg}</div>}

      <div className="form-card">
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", flexWrap:"wrap", gap:10, marginBottom:12 }}>
          <div className="form-title" style={{ margin:0 }}>Asignación por patente — Supervisor y CECO</div>
          <Input value={filtro} onChange={e=>setFiltro(e.target.value)} placeholder="Filtrar patente / supervisor / CECO" style={{ maxWidth:280 }} />
        </div>
        <div style={{ overflowX:"auto" }}>
          <table style={{ width:"100%", borderCollapse:"collapse", fontSize:13 }}>
            <thead><tr style={{ borderBottom:"2px solid #e4e7ec" }}>
              <th style={th}>Patente</th><th style={th}>Modelo</th><th style={{...th, minWidth:150}}>CECO</th><th style={{...th, minWidth:220}}>Supervisor</th><th style={th}></th>
            </tr></thead>
            <tbody>
              {vehs.map(r => {
                const e = vEd[r.patente] || { ceco:"", supervisor:"" };
                return (
                  <tr key={r.patente}>
                    <td style={{...td, fontWeight:700}}>{r.patente}</td>
                    <td style={{...td, color:"#666"}}>{r.modelo}</td>
                    <td style={td}><input style={inp} value={e.ceco} onChange={ev=>setVEd(p=>({...p,[r.patente]:{...p[r.patente],ceco:ev.target.value}}))} /></td>
                    <td style={td}>
                      <select style={inp} value={e.supervisor} onChange={ev=>setVEd(p=>({...p,[r.patente]:{...p[r.patente],supervisor:ev.target.value}}))}>
                        <option value="">(sin asignar)</option>
                        {supOptions.map(n=><option key={n} value={n}>{n}</option>)}
                      </select>
                    </td>
                    <td style={td}><button onClick={()=>guardarVeh(r.patente)} disabled={guardando==="v:"+r.patente} style={{ fontSize:11, fontWeight:700, padding:"5px 12px", borderRadius:6, border:"none", background:"#1a3a6b", color:"#fff", cursor:"pointer" }}>{guardando==="v:"+r.patente?"…":"Guardar"}</button></td>
                  </tr>
                );
              })}
              {vehs.length===0 && <tr><td colSpan={5} style={{ padding:20, textAlign:"center", color:"#94a3b8" }}>{cargando?"Cargando…":"Sin resultados."}</td></tr>}
            </tbody>
          </table>
        </div>
        <div style={{ fontSize:12, color:"#94a3b8", marginTop:8 }}>{vehs.length} vehículo(s)</div>
      </div>

      <div className="form-card" style={{ marginTop:16 }}>
        <div className="form-title">Supervisores — correo, teléfono y rol</div>
        <div style={{ fontSize:12, color:"#666", marginBottom:10 }}>El teléfono se usa para WhatsApp. "Recibe todas" = gerencia/finanzas que recibe todas las alertas (escalamiento).</div>
        <div style={{ overflowX:"auto" }}>
          <table style={{ width:"100%", borderCollapse:"collapse", fontSize:13 }}>
            <thead><tr style={{ borderBottom:"2px solid #e4e7ec" }}>
              <th style={th}>Nombre</th><th style={th}>Cargo</th><th style={th}>Correo</th><th style={th}>Teléfono</th><th style={{...th, textAlign:"center"}}>Recibe todas</th><th style={th}></th>
            </tr></thead>
            <tbody>
              {(sup||[]).map(r => {
                const e = sEd[r.nombre] || { correo:"", telefono:"", cargo:"", recibe_global:false };
                return (
                  <tr key={r.nombre} style={{ background: e.recibe_global ? "#f0f9ff" : "transparent" }}>
                    <td style={{...td, fontWeight:600}}>{r.nombre}</td>
                    <td style={td}><input style={inp} value={e.cargo} onChange={ev=>setSEd(p=>({...p,[r.nombre]:{...p[r.nombre],cargo:ev.target.value}}))} /></td>
                    <td style={td}><input style={inp} value={e.correo} onChange={ev=>setSEd(p=>({...p,[r.nombre]:{...p[r.nombre],correo:ev.target.value}}))} /></td>
                    <td style={td}><input style={inp} value={e.telefono} onChange={ev=>setSEd(p=>({...p,[r.nombre]:{...p[r.nombre],telefono:ev.target.value}}))} placeholder="+569..." /></td>
                    <td style={{...td, textAlign:"center"}}><input type="checkbox" checked={!!e.recibe_global} onChange={ev=>setSEd(p=>({...p,[r.nombre]:{...p[r.nombre],recibe_global:ev.target.checked}}))} /></td>
                    <td style={td}><button onClick={()=>guardarSup(r.nombre)} disabled={guardando==="s:"+r.nombre} style={{ fontSize:11, fontWeight:700, padding:"5px 12px", borderRadius:6, border:"none", background:"#1a3a6b", color:"#fff", cursor:"pointer" }}>{guardando==="s:"+r.nombre?"…":"Guardar"}</button></td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>

        <div style={{ borderTop:"1px solid #e4e7ec", marginTop:14, paddingTop:14 }}>
          <div style={{ fontSize:13, fontWeight:700, marginBottom:8 }}>Agregar supervisor</div>
          <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit,minmax(150px,1fr))", gap:8, alignItems:"end" }}>
            <div><Label>Nombre</Label><Input value={nuevo.nombre} onChange={e=>setNuevo({...nuevo,nombre:e.target.value})} /></div>
            <div><Label>Cargo</Label><Input value={nuevo.cargo} onChange={e=>setNuevo({...nuevo,cargo:e.target.value})} /></div>
            <div><Label>Correo</Label><Input value={nuevo.correo} onChange={e=>setNuevo({...nuevo,correo:e.target.value})} /></div>
            <div><Label>Teléfono</Label><Input value={nuevo.telefono} onChange={e=>setNuevo({...nuevo,telefono:e.target.value})} placeholder="+569..." /></div>
            <label style={{ fontSize:12, display:"flex", alignItems:"center", gap:6 }}><input type="checkbox" checked={nuevo.recibe_global} onChange={e=>setNuevo({...nuevo,recibe_global:e.target.checked})} /> Recibe todas</label>
            <Btn onClick={agregarSup} color="#166534">{guardando==="nuevo"?"…":"Agregar"}</Btn>
          </div>
        </div>
      </div>
    </div>
  );
}

function ModuloMantencionesMadre({ usuario }) {
  const [sub, setSub] = useState("verificador");
  const tabs = [
    { id: "verificador", label: "Verificador de Componentes" },
    { id: "ficha",       label: "Ficha Vehículo" },
    { id: "costos",      label: "Flujo de Caja" },
    { id: "bitacora",    label: "Bitácora" },
    { id: "supervisores", label: "Supervisores" },
  ];
  return (
    <div className="pg">
      <div className="sec-title">Mantenciones · Cuidado de Activo</div>
      <div className="sec-sub">Control de protocolo de flota — Bigticket</div>
      <div style={{ display:"flex", gap:4, borderBottom:"1px solid #e4e7ec", marginBottom:20, overflowX:"auto" }}>
        {tabs.map(t => (
          <button key={t.id} onClick={()=>setSub(t.id)} style={{
            padding:"10px 16px", background:"none", border:"none",
            borderBottom: sub===t.id ? "2px solid #1a3a6b" : "2px solid transparent",
            color: sub===t.id ? "#1a3a6b" : "#64748b", fontSize:13, fontWeight:700,
            cursor:"pointer", whiteSpace:"nowrap", marginBottom:-1, fontFamily:"'Geist',sans-serif"
          }}>{t.label}</button>
        ))}
      </div>
      {sub === "verificador" && <VerificadorComponentes usuario={usuario} />}
      {sub === "ficha"       && <FichaVehiculo usuario={usuario} />}
      {sub === "costos"      && <FlujoCaja />}
      {sub === "bitacora"    && <Bitacora usuario={usuario} />}
      {sub === "supervisores" && <MantenedorSupervisores />}
    </div>
  );
}

function MantPlaceholder({ titulo }) {
  return (
    <div className="form-card" style={{ textAlign:"center", padding:40, color:"#94a3b8" }}>
      <div style={{ fontSize:15, fontWeight:700, color:"#475569", marginBottom:6 }}>{titulo}</div>
      <div style={{ fontSize:13 }}>En construcción — próxima iteración.</div>
    </div>
  );
}

function VerificadorNeumaticos({ usuario }) {
  const [patente, setPatente] = useState("");
  const [cargando, setCargando] = useState(false);
  const [error, setError] = useState("");
  const [info, setInfo] = useState(null);
  const [generando, setGenerando] = useState(false);
  const [msg, setMsg] = useState("");

  async function verificar() {
    const p = patente.trim().toUpperCase();
    if (!p) { setError("Ingresá una patente."); return; }
    setCargando(true); setError(""); setInfo(null); setMsg("");
    try {
      const { data: veh } = await sb.from("ca_vehiculos")
        .select("patente,ceco,tipo_vehiculo,modelo").eq("patente", p).maybeSingle();
      if (!veh) { setError(`La patente ${p} no está en la flota.`); setCargando(false); return; }

      const { data: prot } = await sb.from("ca_protocolo_vida_util")
        .select("neumatico,neumatico_alerta").eq("modelo", veh.modelo).maybeSingle();
      if (!prot || !prot.neumatico) { setError(`No hay protocolo de neumáticos para el modelo ${veh.modelo}.`); setCargando(false); return; }

      const { data: odo } = await sb.from("ca_odometros")
        .select("odometro,fecha_lectura").eq("patente", p)
        .order("fecha_lectura", { ascending:false }).limit(1).maybeSingle();
      const kmActual = odo ? Number(odo.odometro) : null;
      if (kmActual == null) { setError(`No hay lectura de odómetro para ${p}.`); setCargando(false); return; }

      const { data: reps } = await sb.from("ca_reparaciones")
        .select("odometro,fecha_servicio").eq("patente", p)
        .ilike("servicio_efectuado", "%neumat%")
        .order("odometro", { ascending:false }).limit(1);
      const ultima = reps && reps.length ? reps[0] : null;
      const kmUltima = ultima ? Number(ultima.odometro) : null;

      const limiteOffset = Number(prot.neumatico);
      const alertaOffset = prot.neumatico_alerta != null ? Number(prot.neumatico_alerta) : Math.round(limiteOffset * 0.8);

      const recorrido = kmUltima != null ? kmActual - kmUltima : null;
      const kmAlerta  = kmUltima != null ? kmUltima + alertaOffset : null;
      const kmLimite  = kmUltima != null ? kmUltima + limiteOffset : null;
      const kmRestantes = kmLimite != null ? kmLimite - kmActual : null;
      let estado = "sin_compra";
      if (recorrido != null) {
        estado = recorrido >= limiteOffset ? "supera_limite" : recorrido >= alertaOffset ? "alerta" : "ok";
      }

      setInfo({ veh, kmActual, kmUltima, limiteOffset, alertaOffset, recorrido, kmAlerta, kmLimite, kmRestantes, estado });
    } catch (e) {
      setError("Error consultando: " + e.message);
    }
    setCargando(false);
  }

  async function generarSolicitud() {
    if (!info) return;
    setGenerando(true); setMsg("");
    const { veh, kmActual, kmUltima, limiteOffset, alertaOffset, recorrido, kmAlerta, kmLimite, kmRestantes, estado } = info;
    const cl = (n) => n == null ? "—" : Number(n).toLocaleString("es-CL");
    const just = `Vehículo ${veh.patente} (${veh.modelo}, ${veh.ceco}): recorrió ${cl(recorrido)} km desde la última compra de neumáticos (odómetro ${cl(kmUltima)} km). Umbral de alerta del protocolo: ${cl(alertaOffset)} km; límite máximo: ${cl(limiteOffset)} km. Km actual: ${cl(kmActual)} km. Se solicita autorización de compra de neumáticos.`;
    try {
      const { error } = await sb.from("ca_solicitudes").insert({
        patente: veh.patente, ceco: veh.ceco, tipo_vehiculo: veh.tipo_vehiculo, modelo: veh.modelo,
        componente: "neumaticos", km_ultima_compra: kmUltima, km_actual: kmActual, km_recorridos: recorrido,
        km_alerta: kmAlerta, km_limite: kmLimite, km_restantes: kmRestantes, estado_protocolo: estado,
        justificacion: just, solicitante: usuario?.nombre || null, status: "pendiente",
      });
      if (error) throw error;
      setMsg("✅ Solicitud generada y enviada a Finanzas.");
    } catch (e) {
      setMsg("❌ Error al generar: " + e.message);
    }
    setGenerando(false);
  }

  const fmt = (n) => n == null ? "—" : Number(n).toLocaleString("es-CL") + " km";
  const estadoCfg = {
    ok:            { txt:"En protocolo",      color:"#166534", bg:"#dcfce7", ico:"✓" },
    alerta:        { txt:"En alerta",          color:"#92400e", bg:"#fef3c7", ico:"⚠" },
    supera_limite: { txt:"Supera límite",      color:"#c0392b", bg:"#fee2e2", ico:"⚠" },
    sin_compra:    { txt:"Sin compra previa",  color:"#475569", bg:"#f1f5f9", ico:"•" },
  };
  const tipos = ["AUTO","CAMIONETA","CAMION"];

  return (
    <div style={{ maxWidth:760 }}>
      <div style={{ background:"#1a3a6b", color:"#fff", borderRadius:"14px 14px 0 0", padding:"16px 20px", display:"flex", alignItems:"center", gap:10 }}>
        <span style={{ fontSize:18 }}>🚚</span>
        <span style={{ fontSize:15, fontWeight:700 }}>Verificador de estado de neumáticos — Bigticket</span>
      </div>
      <div style={{ background:"#fff", border:"1px solid #e4e7ec", borderTop:"none", borderRadius:"0 0 14px 14px", padding:20, marginBottom:16 }}>
        <div style={{ display:"flex", gap:12, alignItems:"flex-end", flexWrap:"wrap" }}>
          <div style={{ flex:"1 1 220px" }}>
            <Label>Patente</Label>
            <Input value={patente} onChange={e=>setPatente(e.target.value.toUpperCase())} placeholder="Ej: SLCY14" />
          </div>
          <Btn onClick={verificar} color="#1a3a6b">{cargando ? "Verificando…" : "Verificar"}</Btn>
        </div>

        {error && <div style={{ marginTop:14, padding:"10px 14px", background:"#fee2e2", color:"#c0392b", borderRadius:8, fontSize:13 }}>{error}</div>}

        {info && (() => {
          const cfg = estadoCfg[info.estado];
          const pct = info.recorrido != null ? Math.min(100, Math.max(0, (info.recorrido / info.limiteOffset) * 100)) : 0;
          const pctAlerta = Math.min(100, (info.alertaOffset / info.limiteOffset) * 100);
          const barColor = info.estado==="supera_limite" ? "#dc2626" : info.estado==="alerta" ? "#d97706" : "#16a34a";
          return (
          <div style={{ marginTop:18 }}>
            <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit,minmax(140px,1fr))", gap:12, marginBottom:18 }}>
              <div><Label>Centro de costo</Label><div style={{ fontSize:14, fontWeight:600 }}>{info.veh.ceco || "—"}</div></div>
              <div><Label>Modelo</Label><div style={{ fontSize:14, fontWeight:600 }}>{info.veh.modelo}</div></div>
              <div>
                <Label>Tipo de vehículo</Label>
                <div style={{ display:"flex", gap:4 }}>
                  {tipos.map(t => {
                    const on = (info.veh.tipo_vehiculo||"").toUpperCase() === t;
                    return <span key={t} style={{ fontSize:11, fontWeight:700, padding:"4px 8px", borderRadius:6, background:on?"#1a3a6b":"#f1f5f9", color:on?"#fff":"#94a3b8" }}>{t}</span>;
                  })}
                </div>
              </div>
            </div>

            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:8 }}>
              <div style={{ fontSize:14, fontWeight:700, color:"#1a1a1a" }}>{info.veh.modelo} {info.veh.patente} — {info.veh.ceco}</div>
              <span style={{ fontSize:12, fontWeight:700, padding:"5px 12px", borderRadius:20, background:cfg.bg, color:cfg.color }}>{cfg.ico} {cfg.txt}</span>
            </div>
            <div style={{ fontSize:12, color:"#666", marginBottom:10 }}>
              KM última compra: {info.kmUltima!=null?info.kmUltima.toLocaleString("es-CL"):"—"} → KM actual: {info.kmActual.toLocaleString("es-CL")}
            </div>

            <div style={{ display:"flex", justifyContent:"space-between", fontSize:11, color:"#94a3b8", marginBottom:4 }}>
              <span>0 km</span><span>Alerta: {info.alertaOffset.toLocaleString("es-CL")}</span><span>Límite: {info.limiteOffset.toLocaleString("es-CL")}</span>
            </div>
            <div style={{ position:"relative", height:14, background:"#f1f5f9", borderRadius:8, overflow:"hidden", marginBottom:4 }}>
              <div style={{ position:"absolute", left:0, top:0, height:"100%", width:`${pct}%`, background:barColor, transition:"width .4s" }} />
              <div style={{ position:"absolute", left:`${pctAlerta}%`, top:0, height:"100%", width:2, background:"#64748b" }} />
            </div>
            <div style={{ display:"flex", justifyContent:"space-between", fontSize:12, marginBottom:18 }}>
              <span style={{ color:"#666" }}>Recorrido desde última compra:</span>
              <span style={{ fontWeight:700, color:"#1a1a1a" }}>{info.recorrido!=null?info.recorrido.toLocaleString("es-CL"):"—"} km recorridos</span>
            </div>

            <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit,minmax(150px,1fr))", gap:12, marginBottom:18 }}>
              <KPI label="KM de alerta" valor={fmt(info.kmAlerta)} color="#d97706" />
              <KPI label="KM límite máximo" valor={fmt(info.kmLimite)} color="#dc2626" />
              <KPI label="KM restantes al límite" valor={fmt(info.kmRestantes)} color={info.kmRestantes!=null && info.kmRestantes<0 ? "#dc2626" : "#1a3a6b"} />
            </div>

            <div style={{ borderTop:"1px solid #e4e7ec", paddingTop:16 }}>
              {(info.estado==="alerta" || info.estado==="supera_limite") ? (
                <Btn onClick={generarSolicitud} color="#1a3a6b">{generando ? "Generando…" : "Generar solicitud para finanzas"}</Btn>
              ) : info.estado==="sin_compra" ? (
                <div style={{ fontSize:13, color:"#92400e" }}>Sin compra de neumáticos registrada — no se puede calcular recorrido. Cargá la última compra en reparaciones.</div>
              ) : (
                <div style={{ fontSize:13, color:"#166534" }}>✓ Dentro de protocolo — no corresponde compra. Consulta registrada.</div>
              )}
              {msg && <div style={{ marginTop:12, fontSize:13, fontWeight:600 }}>{msg}</div>}
            </div>
          </div>
          );
        })()}
      </div>
    </div>
  );
}

export default function App() {
  const [usuario, setUsuario] = useState(() => {
    try {
      const guardado = localStorage.getItem("bt_usuario");
      return guardado ? JSON.parse(guardado) : null;
    } catch { return null; }
  });
  const [tab, setTabState] = useState(() => {
    try { return localStorage.getItem("bt_nav_tab") || "brain"; } catch { return "brain"; }
  });
  const setTab = (t) => { try { localStorage.setItem("bt_nav_tab", t); } catch {} setTabState(t); };

  const handleLogin = (u) => {
    localStorage.setItem("bt_usuario", JSON.stringify(u));
    setUsuario(u);
  };
  const handleLogout = () => {
    localStorage.removeItem("bt_usuario");
    try { localStorage.removeItem("bt_nav_tab"); localStorage.removeItem("bt_nav_subtab_pagos"); } catch {}
    setUsuario(null);
  };

  if (!usuario) return <><style>{css}</style><Login onLogin={handleLogin} /></>;
  if (tab === "brain") return <><style>{css}</style><BrainCentral setTab={setTab} usuario={usuario} /></>; 
  return (
    <>
      <style>{css}</style>
      <div>
        <div className="topbar">
          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
            <img src={BIGGY_IMG} alt="Biggy" style={{ width: 30, height: 30, borderRadius: "50%", objectFit: "cover", border: "1.5px solid #F47B20" }} />
            <span style={{ fontSize: 16, fontWeight: 700 }}>
              <span style={{ color: "#F47B20" }}>Big</span><span style={{ color: "#fff" }}>ticket</span>
            </span>
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
            <span style={{ fontSize: 12, color: "#aac3e8" }}>👤 {usuario.nombre}</span>
            <button className="btn-gw" onClick={handleLogout}>Salir</button>
          </div>
        </div>
        <div className="admin-nav">
          {MODULOS[usuario.rol]?.map(k => (
            <button key={k} className={`nav-btn ${tab === k ? "active" : ""}`} onClick={() => setTab(k)}>
              {MODULOS_LABELS[k]}
            </button>
          ))}
        </div>
        {tab === "brain" && <BrainCentral setTab={setTab} usuario={usuario} />}
        {tab === "pool_meli_mx" && <IndicadoresOperacionalesMX usuario={usuario} />}
        {tab === "certificaciones" && <ModuloCertificacionesMadre />}
        {tab === "configuracion" && (
          <div className="pg" style={{ maxWidth: 700 }}>
            <div className="sec-title">Configuración</div>
            <div className="sec-sub">Sistema Integrado Bigticket</div>
            <div className="form-card">
              <div className="form-title">Conexiones activas</div>
              <div style={{ fontSize: 13, color: "#555", lineHeight: 2.2 }}>
                <div>✅ Supabase — tabla certificaciones_mx</div>
                <div>✅ Pipefy — Pipe {PIPE_ID} · Fase: Validación MELI</div>
                <div>✅ Google Forms — Validación Drivers MLM</div>
                <div>✅ Gmail — certificacionbigticketmx@gmail.com</div>
                <div>✅ Biggy (Claude Vision) — Análisis automático de documentos</div>
              </div>
            </div>
            <div className="form-card">
              <div className="form-title">Usuarios</div>
              {Object.entries(USUARIOS).map(([email, u]) => (
                <div key={email} style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "8px 0", borderBottom: "1px solid #f4f5f7" }}>
                  <div>
                    <div style={{ fontSize: 13, fontWeight: 600 }}>{u.nombre}</div>
                    <div style={{ fontSize: 12, color: "#888" }}>{email}</div>
                  </div>
                  <span style={{ fontSize: 11, padding: "2px 10px", borderRadius: 20, background: u.rol === "superadmin" ? "#eef2ff" : "#f0fdf4", color: u.rol === "superadmin" ? "#1a3a6b" : "#166534", fontWeight: 600 }}>
                    {u.rol}
                  </span>
                </div>
              ))}
            </div>
          </div>
        )}
        {tab === "maestro" && <ModuloMaestro usuario={usuario} />}
        {tab === "mantenciones" && <ModuloMantencionesMadre usuario={usuario} />}
        {tab === "pnr" && <ModuloPNR />}
        {tab === "pagos" && <ModuloPagosMadre usuario={usuario} />}
      </div>
    </>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════════════
// MÓDULO PREFACTURAS · MX (v3 · lectura directa del PDF, sin planilla intermedia)
// ───────────────────────────────────────────────────────────────────────────────────────
// 4 sub-tabs:
//   • Envío masivo (default): drag-and-drop de PDFs · el Brain extrae datos del PDF
//     (EMPRESA TRANSPORTE, OPERACIÓN→CECO, PERIODO PREFACTURADO) y los cruza con
//     Supabase (transportistas + parámetros por CECO) para armar cada correo.
//   • Transportistas: CRUD de transportistas (nombre, RFC, correos TO/CC/BCC).
//   • Parámetros: CRUD de CECOs (supervisor, asunto, cuerpo plantilla, cuenta envío).
//   • Historial: log de envíos pasados (Supabase).
//
// Webhook n8n: https://bigticket2026.app.n8n.cloud/webhook/prefacturas-enviar-mx
//
// Variables en plantillas: {TRANSPORTISTA} {CECO} {PERIODO} {RFC} {OPERACION} {SUPERVISOR}
// ═══════════════════════════════════════════════════════════════════════════════════════

const PREFACTURAS_WEBHOOK = "https://bigticket2026.app.n8n.cloud/webhook/prefacturas-enviar-mx";
const PAUSA_ENTRE_ENVIOS_MS = 1500;
const VARIABLES_PLANTILLA = [
  "TRANSPORTISTA", "CECO", "PERIODO", "RFC", "OPERACION", "SUPERVISOR",
];
// Regex de CECO: S + 1-3 letras + 1-2 dígitos. Sin \b para que detecte SMX7 dentro de ML_MXSMX7
// Ejemplos válidos: SMX7, SMX10, SCY1, SHP1, SPY1, SQR1, STL1, STX1, SVH1
const REGEX_CECO = /S[A-Z]{1,3}\d{1,2}/g;
// PDF.js desde CDN
const PDFJS_CDN = "https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.min.js";
const PDFJS_WORKER = "https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js";
// localStorage keys (se persiste el último asunto/cuerpo entre sesiones)
const LS_KEY_ASUNTO = "pref_mx_ultimo_asunto";
const LS_KEY_CUERPO = "pref_mx_ultimo_cuerpo";
// Defaults iniciales (se usan solo si nunca se editó el cuerpo)
const ASUNTO_DEFAULT = "Prefactura {CECO} — período {PERIODO} — {OPERACION}";
const CUERPO_DEFAULT = `Estimado(a) {TRANSPORTISTA},

Adjunto encontrará su prefactura correspondiente al período {PERIODO}, operación {CECO}.

Favor emitir su factura como máximo el día jueves XX/XX a las 12:00 Hrs para que esta pueda ser procesada y pagada el mismo XX-XX. En caso contrario, su pago será reagendado para el día lunes XX-XX.

En caso de presentar diferencias, favor notificar vía mail a su supervisor directo para que estas puedan ser validadas e informadas a nuestra área para reliquidación.

Quedamos a sus órdenes ante cualquier consulta.

Saludos cordiales,
Equipo BigTicket MX`;

// ─── HELPERS ─────────────────────────────────────────────────────────────────────────
function pf_correoValido(c) {
  if (!c) return false;
  return /^[^\s@;,]+@[^\s@;,]+\.[^\s@;,]+$/.test(String(c).trim());
}
function pf_limpiarLista(s) {
  if (s == null) return { limpia: "", valida: true };
  const partes = String(s).split(/[;,]/).map(x => x.trim()).filter(Boolean);
  if (partes.length === 0) return { limpia: "", valida: true };
  return { limpia: partes.join("; "), valida: partes.every(pf_correoValido) };
}
function pf_fileToBase64(file) {
  return new Promise((resolve, reject) => {
    const r = new FileReader();
    r.onload = () => {
      const result = r.result;
      const idx = result.indexOf(",");
      resolve(idx >= 0 ? result.slice(idx + 1) : result);
    };
    r.onerror = reject;
    r.readAsDataURL(file);
  });
}
function pf_aplicarPlantilla(template, vars) {
  if (!template) return "";
  let out = template;
  Object.entries(vars).forEach(([k, v]) => {
    const val = (v == null) ? "" : String(v);
    out = out.replace(new RegExp("\\{" + k + "\\}", "g"), val);
  });
  return out;
}

// ─── CARGA DINÁMICA DE PDF.JS ───────────────────────────────────────────────────────
async function pf_cargarPDFJS() {
  if (window.pdfjsLib) return window.pdfjsLib;
  await new Promise((resolve, reject) => {
    const s = document.createElement("script");
    s.src = PDFJS_CDN;
    s.onload = resolve; s.onerror = reject;
    document.head.appendChild(s);
  });
  if (window.pdfjsLib) {
    window.pdfjsLib.GlobalWorkerOptions.workerSrc = PDFJS_WORKER;
  }
  return window.pdfjsLib;
}

// ─── EXTRACCIÓN DE TEXTO DE UN PDF ──────────────────────────────────────────────────
async function pf_extraerTextoPDF(file) {
  const pdfjs = await pf_cargarPDFJS();
  if (!pdfjs) throw new Error("No se pudo cargar PDF.js");
  const buf = await file.arrayBuffer();
  const pdf = await pdfjs.getDocument({ data: buf }).promise;
  let textoCompleto = "";
  for (let i = 1; i <= pdf.numPages; i++) {
    const page = await pdf.getPage(i);
    const content = await page.getTextContent();
    // Reconstruir el texto preservando orden vertical y agregando espacios
    const items = content.items.map(it => ({
      str: it.str,
      x: it.transform[4],
      y: it.transform[5],
    }));
    // Ordenar por Y descendente (arriba primero) y X ascendente
    items.sort((a, b) => (b.y - a.y) || (a.x - b.x));
    // Agrupar items por línea (mismo Y aproximado)
    const lineas = [];
    let lineaActual = [];
    let yPrev = null;
    const TOL = 3;
    for (const it of items) {
      if (yPrev === null || Math.abs(it.y - yPrev) <= TOL) {
        lineaActual.push(it);
      } else {
        if (lineaActual.length) lineas.push(lineaActual);
        lineaActual = [it];
      }
      yPrev = it.y;
    }
    if (lineaActual.length) lineas.push(lineaActual);
    const textoPag = lineas.map(l => l.map(x => x.str).join(" ")).join("\n");
    textoCompleto += textoPag + "\n";
  }
  return textoCompleto;
}

// ─── PARSING DE LOS CAMPOS DEL PDF ──────────────────────────────────────────────────
// Los regex están diseñados para tolerar que el PDF tenga "ruido" de la columna de la
// derecha (RESUMEN POR PATENTE) que PDF.js suele mezclar con la columna principal.
function pf_parsearPDF(texto) {
  const t = texto.replace(/\u00A0/g, " ").replace(/[ \t]+/g, " ");

  // EMPRESA TRANSPORTE: nombre en mayúsculas, corta al encontrar RFC/RESUMEN/PATENTE/$/etc
  const reTransp = /EMPRESA\s+TRANSPORTE\s*:?\s*([A-ZÁÉÍÓÚÑ][A-ZÁÉÍÓÚÑa-záéíóúñ\s\.]+?)(?=\s*(?:RFC\b|RESUMEN\b|OPERACI[ÓO]N\b|SUPERVISOR\b|PERIODO\b|MES\s+FACTURA\b|VALOR\s+UF\b|PATENTE\b|\$|\n|$))/i;
  const mTransp = t.match(reTransp);
  const transportista = mTransp ? mTransp[1].trim().replace(/\s+/g, " ") : "";

  // RFC EMPRESA TRANSPORTE
  const reRfc = /RFC\s+EMPRESA\s+TRANSPORTE\s*:?\s*([A-Z0-9]{10,15})/i;
  const mRfc = t.match(reRfc);
  const rfc = mRfc ? mRfc[1].trim().toUpperCase() : "";

  // OPERACIÓN: solo el token tipo ML_MXSMX7 (letras/dígitos/_), sin texto extra a la derecha
  const reOp = /OPERACI[ÓO]N\s*:?\s*([A-Z][A-Z0-9_]+)/i;
  const mOp = t.match(reOp);
  const operacion = mOp ? mOp[1].trim() : "";

  // SUPERVISOR: nombre en mayúsculas, corta al encontrar patrón de patente o label
  const reSup = /SUPERVISOR\s*:?\s*([A-ZÁÉÍÓÚÑ][A-ZÁÉÍÓÚÑa-záéíóúñ\s\.]+?)(?=\s*(?:[A-Z]{3,}\d|PERIODO|MES|VALOR|\$|\n|$))/i;
  const mSup = t.match(reSup);
  const supervisorPDF = mSup ? mSup[1].trim().replace(/\s+/g, " ") : "";

  // PERIODO PREFACTURADO: formato "XX DE MES AL XX DE MES"
  const rePer = /PERIODO\s+PREFACTURADO\s*:?\s*(\d{1,2}\s+DE\s+[A-ZÁÉÍÓÚ]+\s+AL\s+\d{1,2}\s+DE\s+[A-ZÁÉÍÓÚ]+)/i;
  const mPer = t.match(rePer);
  const periodo = mPer ? mPer[1].trim().toUpperCase() : "";

  // CECO: dentro de OPERACIÓN primero (debe coincidir con SMX7 dentro de ML_MXSMX7),
  // luego en todo el texto como fallback
  let ceco = "";
  if (operacion) {
    const m = operacion.match(REGEX_CECO);
    if (m && m.length > 0) ceco = m[m.length - 1]; // el último match en la operación
  }
  if (!ceco) {
    const m = t.match(REGEX_CECO);
    if (m && m.length > 0) ceco = m[0];
  }

  return { transportista, rfc, operacion, supervisorPDF, periodo, ceco };
}

// ═══════════════════════════════════════════════════════════════════════════════════════
// COMPONENTE ROOT: Modulo Prefacturas (4 sub-tabs)
// ═══════════════════════════════════════════════════════════════════════════════════════
function ModuloPrefacturasMX({ usuario }) {
  const [subtab, setSubtab] = useState("envio");
  const [transportistas, setTransportistas] = useState([]);
  const [parametros, setParametros] = useState([]);
  const [cargando, setCargando] = useState(true);

  const cargarDatos = async () => {
    setCargando(true);
    try {
      const [{ data: t }, { data: p }] = await Promise.all([
        sb.from("prefacturas_transportistas_mx").select("*").order("nombre"),
        sb.from("prefacturas_parametros_mx").select("*").order("ceco"),
      ]);
      setTransportistas(t || []);
      setParametros(p || []);
    } catch (e) {
      console.error("Error cargando datos prefacturas:", e);
    }
    setCargando(false);
  };

  useEffect(() => { cargarDatos(); }, []);

  const subtabs = [
    { id: "envio",          label: "Envío masivo",       icon: "📨" },
    { id: "transportistas", label: "Transportistas",     icon: "🚚" },
    { id: "parametros",     label: "Parámetros / CECOs", icon: "⚙️" },
    { id: "historial",      label: "Historial",          icon: "📋" },
  ];

  return (
    <div style={{ padding: 0 }}>
      <div style={{ background: "#fff", borderBottom: "1px solid #e4e7ec", padding: "12px 24px" }}>
        <div style={{ display: "flex", gap: 6, flexWrap: "wrap" }}>
          {subtabs.map(t => (
            <button key={t.id} onClick={() => setSubtab(t.id)}
              style={{
                padding: "8px 16px", borderRadius: 8,
                border: `1px solid ${subtab === t.id ? "#1a3a6b" : "#e4e7ec"}`,
                background: subtab === t.id ? "#1a3a6b" : "#fff",
                color: subtab === t.id ? "#fff" : "#475569",
                fontSize: 12, fontWeight: 600, cursor: "pointer",
                fontFamily: "Geist, sans-serif",
              }}>
              {t.icon} {t.label}
            </button>
          ))}
        </div>
      </div>

      {cargando ? (
        <div className="loading">Cargando configuración de prefacturas...</div>
      ) : (
        <>
          {subtab === "envio"          && <PrefEnvioMasivo transportistas={transportistas} parametros={parametros} usuario={usuario} onActualizarMaestros={cargarDatos} />}
          {subtab === "transportistas" && <PrefTransportistas data={transportistas} onChange={cargarDatos} />}
          {subtab === "parametros"     && <PrefParametros data={parametros} onChange={cargarDatos} />}
          {subtab === "historial"      && <PrefHistorial pais="MX" />}
        </>
      )}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════════════
// SUB-TAB 1: ENVÍO MASIVO — solo PDFs, lectura directa
// ═══════════════════════════════════════════════════════════════════════════════════════
function PrefEnvioMasivo({ transportistas, parametros, usuario, onActualizarMaestros }) {
  const [pdfsEnProceso, setPdfsEnProceso] = useState(0);
  const [filas, setFilas] = useState([]);          // [{ idx, file, parsed, ... }]
  const [error, setError] = useState("");
  const [enviando, setEnviando] = useState(false);
  const [progreso, setProgreso] = useState({ actual: 0, total: 0 });
  const [editFila, setEditFila] = useState(null);
  const [logFinal, setLogFinal] = useState(null);
  const [arrastrando, setArrastrando] = useState(false);
  const [modalAgregar, setModalAgregar] = useState(null);
  const pdfInputRef = useRef(null);

  // ★ Editor de asunto/cuerpo del lote (se aplica a TODOS los envíos)
  // Persiste en localStorage para que Esteban no tenga que reescribir cada vez
  const [asuntoLote, setAsuntoLote] = useState(() => {
    try { return localStorage.getItem(LS_KEY_ASUNTO) || ASUNTO_DEFAULT; }
    catch { return ASUNTO_DEFAULT; }
  });
  const [cuerpoLote, setCuerpoLote] = useState(() => {
    try { return localStorage.getItem(LS_KEY_CUERPO) || CUERPO_DEFAULT; }
    catch { return CUERPO_DEFAULT; }
  });

  // Guardar en localStorage cuando cambian
  useEffect(() => {
    try { localStorage.setItem(LS_KEY_ASUNTO, asuntoLote); } catch {}
  }, [asuntoLote]);
  useEffect(() => {
    try { localStorage.setItem(LS_KEY_CUERPO, cuerpoLote); } catch {}
  }, [cuerpoLote]);

  // Lookups
  const transByNombre = useMemo(() => {
    const m = new Map();
    transportistas.forEach(t => m.set(String(t.nombre).toUpperCase().trim(), t));
    return m;
  }, [transportistas]);
  const paramsByCeco = useMemo(() => {
    const m = new Map();
    parametros.forEach(p => m.set(String(p.ceco).toUpperCase().trim(), p));
    return m;
  }, [parametros]);

  // Procesar un PDF: extraer texto + parsear + cruzar con Supabase
  // El asunto/cuerpo NO se aplican acá, se aplican al momento de enviar (con el editor del lote)
  const procesarPDF = async (file, idx) => {
    try {
      const texto = await pf_extraerTextoPDF(file);
      const parsed = pf_parsearPDF(texto);
      const trans = parsed.transportista
        ? transByNombre.get(parsed.transportista.toUpperCase().trim())
        : null;
      const param = parsed.ceco
        ? paramsByCeco.get(parsed.ceco.toUpperCase().trim())
        : null;

      // CC: combinar el CC del transportista (si tiene) + el correo del supervisor del CECO (si tiene)
      // Si ambos coinciden, no duplicar
      const ccs = [];
      if (trans?.correo_cc) ccs.push(trans.correo_cc.trim());
      if (param?.correo_supervisor) {
        const sup = param.correo_supervisor.trim();
        // Evitar duplicados (case-insensitive)
        const yaEsta = ccs.some(c => c.toLowerCase() === sup.toLowerCase());
        if (!yaEsta) ccs.push(sup);
      }
      const ccCombinado = ccs.join("; ");

      return {
        idx,
        file,
        nombre: file.name,
        size: file.size,
        parsed,
        trans,
        param,
        editTo: trans?.correo_to || "",
        editCc: ccCombinado,
        editBcc: trans?.correo_bcc || "",
        // editAsunto/editCuerpo NO se guardan aquí — se generan dinámicamente desde el editor del lote
        // Solo se llenan si el usuario edita manualmente esta fila puntual (override por fila)
        overrideAsunto: null,
        overrideCuerpo: null,
        estadoEnvio: null,
        motivoEnvio: "",
        tsEnvio: null,
        errorParseo: "",
      };
    } catch (e) {
      return {
        idx,
        file,
        nombre: file.name,
        size: file.size,
        parsed: { transportista: "", rfc: "", operacion: "", supervisorPDF: "", periodo: "", ceco: "" },
        trans: null,
        param: null,
        editTo: "", editCc: "", editBcc: "",
        overrideAsunto: null, overrideCuerpo: null,
        estadoEnvio: null, motivoEnvio: "", tsEnvio: null,
        errorParseo: e.message || String(e),
      };
    }
  };

  // Drop / selección de PDFs
  const onPdfsDrop = async (fileList) => {
    setError("");
    const archivos = Array.from(fileList || []).filter(f => /\.pdf$/i.test(f.name) && f.size > 0);
    if (archivos.length === 0) {
      setError("No se detectaron archivos PDF válidos.");
      return;
    }
    setPdfsEnProceso(archivos.length);
    const idxInicio = filas.length;
    const nuevos = [];
    for (let i = 0; i < archivos.length; i++) {
      const fila = await procesarPDF(archivos[i], idxInicio + i);
      nuevos.push(fila);
      setPdfsEnProceso(archivos.length - i - 1);
    }
    setPdfsEnProceso(0);
    setFilas(prev => {
      const map = new Map();
      [...prev, ...nuevos].forEach(f => map.set(f.nombre, f));
      return Array.from(map.values()).map((f, i) => ({ ...f, idx: i }));
    });
    setLogFinal(null);
  };

  // Función para armar las variables y aplicar plantillas de UNA fila
  const armarVariables = (f) => ({
    TRANSPORTISTA: f.parsed.transportista,
    CECO: f.parsed.ceco,
    PERIODO: f.parsed.periodo,
    RFC: f.parsed.rfc,
    OPERACION: f.parsed.operacion,
    SUPERVISOR: f.param?.supervisor || f.parsed.supervisorPDF || "",
  });

  // Validación y estado de cada fila (incluye reemplazo de variables en preview)
  const filasConEstado = useMemo(() => {
    return filas.map(f => {
      const valTo = pf_limpiarLista(f.editTo);
      const valCc = pf_limpiarLista(f.editCc);
      const valBcc = pf_limpiarLista(f.editBcc);
      const errores = [];
      if (f.errorParseo) errores.push("Error de parseo: " + f.errorParseo);
      if (!f.parsed.transportista) errores.push("PDF sin EMPRESA TRANSPORTE");
      if (!f.parsed.ceco) errores.push("PDF sin CECO detectable");
      if (f.parsed.transportista && !f.trans) errores.push("Transportista no registrado");
      if (f.parsed.ceco && !f.param) errores.push("CECO no registrado");
      if (!valTo.limpia) errores.push("Sin correo TO");
      else if (!valTo.valida) errores.push("TO inválido");
      if (f.editCc && !valCc.valida) errores.push("CC inválido");
      if (f.editBcc && !valBcc.valida) errores.push("BCC inválido");

      // Preview del asunto/cuerpo aplicando variables
      const vars = armarVariables(f);
      const asuntoFinal = pf_aplicarPlantilla(f.overrideAsunto !== null ? f.overrideAsunto : asuntoLote, vars);
      const cuerpoFinal = pf_aplicarPlantilla(f.overrideCuerpo !== null ? f.overrideCuerpo : cuerpoLote, vars);

      return { ...f, errores, listo: errores.length === 0, asuntoFinal, cuerpoFinal };
    });
  }, [filas, asuntoLote, cuerpoLote]);

  const totalListos = filasConEstado.filter(f => f.listo).length;
  const totalConErrores = filasConEstado.length - totalListos;

  // Edición inline (override de fila puntual)
  const guardarEdicion = (idx, campos) => {
    setFilas(prev => prev.map(f => f.idx === idx ? { ...f, ...campos } : f));
    setEditFila(null);
  };
  const eliminarFila = (idx) => {
    setFilas(prev => prev.filter(f => f.idx !== idx).map((f, i) => ({ ...f, idx: i })));
  };
  const limpiarTodo = () => {
    if (!confirm("¿Limpiar todos los PDFs y resultados?\n\n(El asunto y cuerpo se mantienen)")) return;
    setFilas([]); setError(""); setLogFinal(null); setProgreso({ actual: 0, total: 0 });
  };
  const restaurarPlantillaDefault = () => {
    if (!confirm("¿Restaurar el asunto y cuerpo al valor por defecto?\n\nVas a perder cualquier cambio que hayas hecho.")) return;
    setAsuntoLote(ASUNTO_DEFAULT);
    setCuerpoLote(CUERPO_DEFAULT);
  };

  const onAgregarYRefrescar = async () => {
    setModalAgregar(null);
    await onActualizarMaestros();
    if (filas.length > 0) {
      const reprocesadas = [];
      for (const f of filas) {
        const nueva = await procesarPDF(f.file, f.idx);
        reprocesadas.push({
          ...nueva,
          editTo: f.editTo && f.editTo !== "" ? f.editTo : nueva.editTo,
          editCc: f.editCc && f.editCc !== "" ? f.editCc : nueva.editCc,
          editBcc: f.editBcc && f.editBcc !== "" ? f.editBcc : nueva.editBcc,
          overrideAsunto: f.overrideAsunto,
          overrideCuerpo: f.overrideCuerpo,
          estadoEnvio: f.estadoEnvio,
          motivoEnvio: f.motivoEnvio,
          tsEnvio: f.tsEnvio,
        });
      }
      setFilas(reprocesadas);
    }
  };

  // ─── Envío masivo ────────────────────────────────────────────────────────────
  const enviarMasivo = async () => {
    const enviables = filasConEstado.filter(f => f.listo);
    if (enviables.length === 0) {
      alert("No hay filas listas para enviar. Revisá los errores en la tabla.");
      return;
    }
    if (!asuntoLote.trim()) {
      alert("El asunto del correo está vacío. Escribí un asunto antes de enviar.");
      return;
    }
    if (!cuerpoLote.trim()) {
      alert("El cuerpo del correo está vacío. Escribí un cuerpo antes de enviar.");
      return;
    }
    if (!confirm(
      `Se enviarán ${enviables.length} correo(s) desde la cuenta configurada en n8n.\n\n` +
      `${totalConErrores > 0 ? `Hay ${totalConErrores} fila(s) con errores que NO se enviarán.\n\n` : ""}` +
      `¿Confirmás el envío?`
    )) return;

    setEnviando(true);
    setLogFinal(null);
    setProgreso({ actual: 0, total: enviables.length });

    let okCount = 0, errCount = 0;
    const inicio = Date.now();
    const logsParaSupabase = [];

    for (let i = 0; i < enviables.length; i++) {
      const f = enviables[i];
      setProgreso({ actual: i + 1, total: enviables.length });
      setFilas(prev => prev.map(x => x.idx === f.idx
        ? { ...x, estadoEnvio: "enviando", motivoEnvio: "", tsEnvio: null }
        : x));

      let resultado = { ok: false, motivo: "", messageId: "" };
      try {
        const pdfBase64 = await pf_fileToBase64(f.file);
        const payload = {
          idEnvio: `${Date.now()}-${f.idx}`,
          transportista: f.parsed.transportista,
          ceco: f.parsed.ceco,
          rfc: f.parsed.rfc,
          operacion: f.parsed.operacion,
          periodo: f.parsed.periodo,
          correoTo: pf_limpiarLista(f.editTo).limpia,
          cc: pf_limpiarLista(f.editCc).limpia,
          bcc: pf_limpiarLista(f.editBcc).limpia,
          asunto: f.asuntoFinal || `Prefactura ${f.parsed.ceco} — ${f.parsed.periodo}`,
          cuerpo: f.cuerpoFinal || "",
          nombrePdf: f.nombre,
          pdfBase64,
        };
        const resp = await fetch(PREFACTURAS_WEBHOOK, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(payload),
        });
        let data = {};
        try { data = await resp.json(); } catch { /* no-json */ }
        if (resp.ok && data.ok !== false) {
          resultado = { ok: true, motivo: data.messageId || "Enviado", messageId: data.messageId || "" };
          okCount++;
        } else {
          resultado = { ok: false, motivo: data.error || `HTTP ${resp.status}`, messageId: "" };
          errCount++;
        }
      } catch (e) {
        resultado = { ok: false, motivo: "Error red: " + e.message, messageId: "" };
        errCount++;
      }

      const tsAhora = new Date().toISOString();
      setFilas(prev => prev.map(x => x.idx === f.idx
        ? { ...x, estadoEnvio: resultado.ok ? "ok" : "fallido", motivoEnvio: resultado.motivo, tsEnvio: tsAhora }
        : x));

      logsParaSupabase.push({
        fecha_envio: tsAhora,
        transportista: f.parsed.transportista,
        ceco: f.parsed.ceco,
        periodo: f.parsed.periodo,
        correo_to: pf_limpiarLista(f.editTo).limpia,
        nombre_pdf: f.nombre,
        estado: resultado.ok ? "enviado" : "fallido",
        motivo: resultado.motivo,
        message_id: resultado.messageId,
        usuario: usuario?.email || "—",
        pais: "MX",
      });

      if (i < enviables.length - 1) {
        await new Promise(r => setTimeout(r, PAUSA_ENTRE_ENVIOS_MS));
      }
    }

    try {
      if (logsParaSupabase.length > 0) {
        await sb.from("prefacturas_envios_log").insert(logsParaSupabase);
      }
    } catch (e) {
      console.error("Error guardando log:", e);
    }

    const segs = Math.round((Date.now() - inicio) / 1000);
    setLogFinal({ ok: okCount, err: errCount, omitidos: totalConErrores, segs, fecha: new Date() });
    setEnviando(false);
    setProgreso({ actual: 0, total: 0 });
  };

  const descargarLog = async () => {
    const detalle = [
      ["#", "Archivo PDF", "Transportista", "RFC", "CECO", "Operación", "Período",
       "Correo TO", "CC", "BCC", "Asunto",
       "Estado envío", "Motivo / MessageID", "Timestamp"],
      ...filasConEstado.map((f, i) => [
        i + 1, f.nombre,
        f.parsed.transportista, f.parsed.rfc, f.parsed.ceco, f.parsed.operacion, f.parsed.periodo,
        f.editTo, f.editCc, f.editBcc, f.asuntoFinal,
        f.estadoEnvio === "ok" ? "ENVIADO" :
          f.estadoEnvio === "fallido" ? "FALLIDO" :
          f.errores.length > 0 ? "OMITIDO: " + f.errores.join(", ") : "PENDIENTE",
        f.motivoEnvio || "",
        f.tsEnvio ? new Date(f.tsEnvio).toLocaleString("es-MX") : "",
      ]),
    ];
    const resumen = [
      ["Reporte de envío de prefacturas MX"],
      ["Fecha", new Date().toLocaleString("es-MX")],
      ["Usuario", usuario?.nombre || usuario?.email || "—"],
      ["PDFs cargados", filas.length],
      ["Enviados OK", filasConEstado.filter(f => f.estadoEnvio === "ok").length],
      ["Fallidos", filasConEstado.filter(f => f.estadoEnvio === "fallido").length],
      ["Pendientes/Omitidos", filasConEstado.filter(f => !f.estadoEnvio).length],
      [""],
      ["Asunto utilizado"],
      [asuntoLote],
      [""],
      ["Cuerpo utilizado"],
      [cuerpoLote],
    ];
    await descargarExcelMultihoja(
      [{ nombre: "Resumen", datos: resumen }, { nombre: "Detalle", datos: detalle }],
      "log_prefacturas_envio_mx"
    );
  };

  return (
    <div className="pg" style={{ maxWidth: 1400 }}>
      <div style={{ marginBottom: 16 }}>
        <div className="sec-title">Prefacturas · Envío Masivo</div>
        <div className="sec-sub">
          Arrastrá los PDFs generados por la macro. Ajustá el asunto y cuerpo del lote.
          El Brain lee cada PDF, cruza con la base de datos, y envía masivamente.
        </div>
      </div>

      {error && (
        <div style={{
          background: "#fee2e2", border: "1px solid #fca5a5", color: "#991b1b",
          padding: "10px 14px", borderRadius: 8, marginBottom: 14, fontSize: 13,
        }}>⚠ {error}</div>
      )}

      {/* ═══ ZONA PRINCIPAL: DRAG-AND-DROP DE PDFs ═══════════════════════════ */}
      <div
        onDragOver={e => { e.preventDefault(); e.stopPropagation(); setArrastrando(true); }}
        onDragLeave={e => { e.preventDefault(); e.stopPropagation(); setArrastrando(false); }}
        onDrop={e => {
          e.preventDefault(); e.stopPropagation();
          setArrastrando(false);
          onPdfsDrop(e.dataTransfer.files);
        }}
        onClick={() => pdfInputRef.current?.click()}
        style={{
          border: `3px dashed ${arrastrando ? "#F47B20" : "#1a3a6b"}`,
          borderRadius: 16,
          padding: "40px 24px",
          textAlign: "center",
          cursor: "pointer",
          background: arrastrando ? "#fff7ed" : "#f8fafc",
          transition: "all 0.2s",
          marginBottom: 16,
        }}
      >
        <div style={{ fontSize: 48, marginBottom: 10 }}>📄</div>
        <div style={{ fontSize: 17, color: "#1a3a6b", fontWeight: 700, marginBottom: 6 }}>
          {pdfsEnProceso > 0
            ? `Procesando PDFs... (${pdfsEnProceso} pendientes)`
            : arrastrando
              ? "Soltá los PDFs aquí"
              : "Arrastrá los PDFs de prefacturas"}
        </div>
        <div style={{ fontSize: 13, color: "#64748b" }}>
          {pdfsEnProceso > 0
            ? "El Brain está leyendo cada PDF para extraer los datos."
            : "o hacé clic para seleccionarlos · sin límite de cantidad"}
        </div>
        {filas.length > 0 && pdfsEnProceso === 0 && (
          <div style={{
            marginTop: 16, padding: "8px 14px", background: "#fff",
            border: "1px solid #1a3a6b", borderRadius: 10,
            display: "inline-flex", alignItems: "center", gap: 12,
          }}>
            <span style={{ fontSize: 13, color: "#1a3a6b", fontWeight: 700 }}>
              ✓ {filas.length} PDF{filas.length === 1 ? "" : "s"} cargado{filas.length === 1 ? "" : "s"}
            </span>
            <button onClick={e => { e.stopPropagation(); limpiarTodo(); }}
              style={{
                background: "#fee2e2", border: "none", borderRadius: 6,
                padding: "4px 10px", fontSize: 11, color: "#991b1b",
                cursor: "pointer", fontWeight: 600, fontFamily: "Geist, sans-serif",
              }}>Quitar todos</button>
          </div>
        )}
        <input
          ref={pdfInputRef} type="file" accept=".pdf" multiple
          style={{ display: "none" }}
          onChange={e => { onPdfsDrop(e.target.files); e.target.value = ""; }}
        />
      </div>

      {/* ═══ ★ NUEVO: EDITOR DE ASUNTO Y CUERPO DEL LOTE ═════════════════════ */}
      <div className="form-card">
        <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 12, flexWrap: "wrap" }}>
          <div className="form-title" style={{ margin: 0 }}>
            ✉️ Asunto y cuerpo del correo
          </div>
          <span style={{ fontSize: 11, color: "#94a3b8", marginLeft: "auto" }}>
            Se aplica a TODOS los envíos del lote
          </span>
          <button onClick={restaurarPlantillaDefault}
            style={{
              background: "transparent", border: "1px solid #e4e7ec", borderRadius: 6,
              padding: "4px 10px", fontSize: 11, color: "#64748b", cursor: "pointer",
              fontWeight: 600, fontFamily: "Geist, sans-serif",
            }}>↺ Restaurar default</button>
        </div>

        {/* Asunto */}
        <div className="field-row">
          <div className="field-label">Asunto</div>
          <input
            value={asuntoLote}
            onChange={e => setAsuntoLote(e.target.value)}
            placeholder="Prefactura {CECO} — período {PERIODO}"
            style={{ fontSize: 13 }}
          />
        </div>

        {/* Cuerpo */}
        <div className="field-row">
          <div className="field-label">Cuerpo del correo</div>
          <textarea
            value={cuerpoLote}
            onChange={e => setCuerpoLote(e.target.value)}
            placeholder="Estimado(a) {TRANSPORTISTA}, ..."
            style={{ height: 220, fontSize: 12, fontFamily: "monospace", lineHeight: 1.6, resize: "vertical" }}
          />
        </div>

        {/* Variables disponibles */}
        <div style={{ display: "flex", flexWrap: "wrap", gap: 6, alignItems: "center", marginTop: 8 }}>
          <span style={{ fontSize: 11, color: "#64748b", fontWeight: 600 }}>Variables disponibles:</span>
          {VARIABLES_PLANTILLA.map(v => (
            <code key={v} style={{
              background: "#eef2ff", color: "#1a3a6b", padding: "2px 8px",
              borderRadius: 4, fontSize: 11, fontFamily: "monospace",
            }}>{"{" + v + "}"}</code>
          ))}
        </div>

        <div style={{
          marginTop: 12, padding: "10px 12px", background: "#eef2ff", borderRadius: 8,
          fontSize: 11, color: "#1a3a6b",
        }}>
          💡 Las variables se reemplazan automáticamente con los datos extraídos de cada PDF.
          Tus cambios se guardan automáticamente en este navegador para la próxima vez.
        </div>
      </div>

      {/* ═══ INDICADORES ════════════════════════════════════════════════════ */}
      {filas.length > 0 && (
        <div style={{
          display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(180px, 1fr))",
          gap: 10, marginBottom: 14,
        }}>
          <IndicadorPF label="PDFs procesados" valor={filas.length} color="#1a3a6b" />
          <IndicadorPF label="Listas para enviar" valor={totalListos} color="#16a34a" />
          <IndicadorPF label="Con errores" valor={totalConErrores} color="#dc2626" />
        </div>
      )}

      {/* ═══ TABLA ═════════════════════════════════════════════════════════ */}
      {filas.length > 0 && (
        <div className="form-card" style={{ padding: 0, overflow: "hidden" }}>
          <div style={{
            padding: "12px 16px", borderBottom: "1px solid #e4e7ec",
            display: "flex", justifyContent: "space-between", alignItems: "center",
            flexWrap: "wrap", gap: 8,
          }}>
            <div className="form-title" style={{ margin: 0 }}>Revisión y envío</div>
            <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
              {(logFinal || filasConEstado.some(f => f.estadoEnvio)) && (
                <BotonDescargarExcel onClick={descargarLog} label="Descargar log Excel" />
              )}
              <button
                onClick={enviarMasivo}
                disabled={enviando || totalListos === 0}
                className="btn-orange"
                style={{ padding: "9px 18px", fontSize: 13 }}>
                {enviando
                  ? `Enviando ${progreso.actual}/${progreso.total}...`
                  : `📨 Enviar ${totalListos} correo${totalListos === 1 ? "" : "s"}`
                }
              </button>
            </div>
          </div>

          {enviando && (
            <div style={{ padding: "10px 16px", borderBottom: "1px solid #e4e7ec", background: "#fffbeb" }}>
              <div style={{ fontSize: 12, color: "#92400e", marginBottom: 6, fontWeight: 600 }}>
                Enviando {progreso.actual} de {progreso.total}...
              </div>
              <div style={{ height: 8, background: "#fef3c7", borderRadius: 4, overflow: "hidden" }}>
                <div style={{
                  width: `${(progreso.actual / progreso.total) * 100}%`,
                  height: "100%", background: "#F47B20", transition: "width 0.3s",
                }} />
              </div>
            </div>
          )}

          {logFinal && !enviando && (
            <div style={{
              padding: "10px 16px", borderBottom: "1px solid #e4e7ec",
              background: logFinal.err === 0 ? "#f0fdf4" : "#fffbeb",
            }}>
              <div style={{
                fontSize: 13, fontWeight: 600,
                color: logFinal.err === 0 ? "#166534" : "#92400e",
              }}>
                {logFinal.err === 0 ? "✓" : "⚠"} Envío finalizado en {logFinal.segs}s ·{" "}
                {logFinal.ok} enviado{logFinal.ok === 1 ? "" : "s"} ·{" "}
                {logFinal.err} fallido{logFinal.err === 1 ? "" : "s"}
                {logFinal.omitidos > 0 && ` · ${logFinal.omitidos} omitido${logFinal.omitidos === 1 ? "" : "s"}`}
              </div>
            </div>
          )}

          <div style={{ overflowX: "auto" }}>
            <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
              <thead>
                <tr style={{ background: "#f8fafc", borderBottom: "1px solid #e4e7ec" }}>
                  <th style={pf_th()}>Estado</th>
                  <th style={pf_th()}>Transportista (PDF)</th>
                  <th style={pf_th()}>CECO</th>
                  <th style={pf_th()}>Período</th>
                  <th style={pf_th()}>Correo TO</th>
                  <th style={pf_th()}>CC</th>
                  <th style={pf_th()}>Acción</th>
                </tr>
              </thead>
              <tbody>
                {filasConEstado.map((f) => (
                  <FilaPrefactura
                    key={f.idx}
                    fila={f}
                    enEdicion={editFila === f.idx}
                    onEdit={() => setEditFila(f.idx)}
                    onGuardar={(campos) => guardarEdicion(f.idx, campos)}
                    onCancelar={() => setEditFila(null)}
                    onEliminar={() => eliminarFila(f.idx)}
                    onAgregarTransportista={() => setModalAgregar({
                      tipo: "trans",
                      prefill: { nombre: f.parsed.transportista, rfc: f.parsed.rfc },
                    })}
                    onAgregarCECO={() => setModalAgregar({
                      tipo: "ceco",
                      prefill: { ceco: f.parsed.ceco, supervisor: f.parsed.supervisorPDF },
                    })}
                    enviando={enviando}
                  />
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Modal embebido para agregar transportista o CECO desde el envío */}
      {modalAgregar?.tipo === "trans" && (
        <ModalEdicionTransportista
          inicial={{
            nombre: modalAgregar.prefill.nombre || "",
            rfc: modalAgregar.prefill.rfc || "",
            estado: "Activo",
            correo_to: "", correo_cc: "", correo_bcc: "", notas: "",
          }}
          esNuevo={true}
          onCancelar={() => setModalAgregar(null)}
          onGuardarOK={onAgregarYRefrescar}
        />
      )}
      {modalAgregar?.tipo === "ceco" && (
        <ModalEdicionParametro
          inicial={{
            ceco: modalAgregar.prefill.ceco || "",
            supervisor: modalAgregar.prefill.supervisor || "",
            correo_supervisor: "",
            cuenta_envio: "prefacturas@bigticket.cl",
          }}
          esNuevo={true}
          onCancelar={() => setModalAgregar(null)}
          onGuardarOK={onAgregarYRefrescar}
        />
      )}
    </div>
  );
}

// ─── Helpers de estilo de tabla ─────────────────────────────────────────────────
function pf_th(align = "left") {
  return {
    padding: "8px 10px", textAlign: align, fontSize: 10,
    color: "#64748b", fontWeight: 600, textTransform: "uppercase",
    letterSpacing: 0.3, whiteSpace: "nowrap",
  };
}
function pf_td(align = "left") {
  return {
    padding: "8px 10px", textAlign: align, fontSize: 12,
    color: "#1f2937", borderBottom: "1px solid #f1f5f9", verticalAlign: "top",
  };
}

function IndicadorPF({ label, valor, color }) {
  return (
    <div style={{
      background: "#fff", border: "0.5px solid #e4e7ec", borderRadius: 10,
      padding: "12px 14px",
    }}>
      <div style={{
        fontSize: 10, color: "#94a3b8", textTransform: "uppercase",
        letterSpacing: 0.5, marginBottom: 4, fontWeight: 600,
      }}>{label}</div>
      <div style={{ fontSize: 22, fontWeight: 700, color }}>{valor}</div>
    </div>
  );
}

// ─── Fila individual ────────────────────────────────────────────────────────────
function FilaPrefactura({ fila, enEdicion, onEdit, onGuardar, onCancelar, onEliminar,
                         onAgregarTransportista, onAgregarCECO, enviando }) {
  const [to, setTo] = useState(fila.editTo);
  const [cc, setCc] = useState(fila.editCc);
  const [bcc, setBcc] = useState(fila.editBcc);
  // El asunto/cuerpo del lote ya están aplicados en fila.asuntoFinal/fila.cuerpoFinal
  // Si la fila tiene override (porque el usuario ya editó manualmente), respetamos eso
  const [asunto, setAsunto] = useState(fila.asuntoFinal);
  const [cuerpo, setCuerpo] = useState(fila.cuerpoFinal);

  useEffect(() => {
    if (enEdicion) {
      setTo(fila.editTo); setCc(fila.editCc); setBcc(fila.editBcc);
      setAsunto(fila.asuntoFinal); setCuerpo(fila.cuerpoFinal);
    }
  }, [enEdicion, fila.editTo, fila.editCc, fila.editBcc, fila.asuntoFinal, fila.cuerpoFinal]);

  let bgFila = "transparent";
  if (fila.estadoEnvio === "ok") bgFila = "#f0fdf4";
  else if (fila.estadoEnvio === "fallido") bgFila = "#fef2f2";
  else if (fila.estadoEnvio === "enviando") bgFila = "#fffbeb";
  else if (!fila.listo) bgFila = "#fef2f2";

  if (enEdicion) {
    return (
      <tr style={{ background: "#eff6ff" }}>
        <td colSpan={7} style={{ padding: 14, borderBottom: "2px solid #1a3a6b" }}>
          <div style={{ fontSize: 12, fontWeight: 700, color: "#1a3a6b", marginBottom: 10 }}>
            ✏️ Editando: {fila.parsed.transportista || fila.nombre} · {fila.parsed.ceco || "—"} · {fila.parsed.periodo || "—"}
          </div>
          <div className="two-col" style={{ marginBottom: 10 }}>
            <div>
              <div className="field-label">Correo TO *</div>
              <input value={to} onChange={e => setTo(e.target.value)}
                placeholder="correo@dominio.com (separá varios con ;)" />
            </div>
            <div>
              <div className="field-label">CC</div>
              <input value={cc} onChange={e => setCc(e.target.value)} placeholder="opcional" />
            </div>
          </div>
          <div className="field-row">
            <div className="field-label">BCC</div>
            <input value={bcc} onChange={e => setBcc(e.target.value)} placeholder="opcional" />
          </div>
          <div className="field-row">
            <div className="field-label">Asunto (override solo para esta fila)</div>
            <input value={asunto} onChange={e => setAsunto(e.target.value)} />
          </div>
          <div className="field-row">
            <div className="field-label">Cuerpo (override solo para esta fila · variables ya reemplazadas)</div>
            <textarea value={cuerpo} onChange={e => setCuerpo(e.target.value)} style={{ height: 140 }} />
          </div>
          <div style={{ fontSize: 11, color: "#64748b", marginBottom: 10 }}>
            💡 Estos cambios solo aplican a este envío puntual. Para cambiar el asunto/cuerpo
            de todo el lote, editalo arriba en "Asunto y cuerpo del correo".
          </div>
          <div style={{ display: "flex", gap: 8, justifyContent: "flex-end" }}>
            <button onClick={onCancelar}
              style={{
                background: "#fff", border: "1px solid #e4e7ec", borderRadius: 8,
                padding: "7px 14px", fontSize: 12, color: "#475569", cursor: "pointer",
                fontFamily: "Geist, sans-serif", fontWeight: 600,
              }}>Cancelar</button>
            <button onClick={() => onGuardar({
              editTo: to, editCc: cc, editBcc: bcc,
              overrideAsunto: asunto, overrideCuerpo: cuerpo,
            })} className="btn-blue" style={{ padding: "7px 14px", fontSize: 12 }}>
              Guardar cambios
            </button>
          </div>
        </td>
      </tr>
    );
  }

  const tieneTransNoRegistrado = fila.parsed.transportista && !fila.trans;
  const tieneCECONoRegistrado = fila.parsed.ceco && !fila.param;

  return (
    <tr style={{ background: bgFila }}>
      <td style={pf_td()}><EstadoBadge fila={fila} /></td>
      <td style={pf_td()}>
        <div style={{ fontWeight: 600 }}>
          {fila.parsed.transportista || <em style={{ color: "#dc2626" }}>(no detectado)</em>}
        </div>
        <div style={{ fontSize: 10, color: "#94a3b8" }}>{fila.parsed.rfc || "sin RFC"}</div>
        <div style={{ fontSize: 9, color: "#94a3b8", marginTop: 2 }}>📄 {fila.nombre.length > 35 ? fila.nombre.slice(0, 32) + "..." : fila.nombre}</div>
        {tieneTransNoRegistrado && (
          <button onClick={onAgregarTransportista}
            style={{
              marginTop: 4, background: "#fef2f2", border: "1px solid #fca5a5",
              borderRadius: 6, padding: "2px 8px", fontSize: 10, color: "#991b1b",
              cursor: "pointer", fontWeight: 600, fontFamily: "Geist, sans-serif",
            }}>+ Agregar a Supabase</button>
        )}
      </td>
      <td style={pf_td()}>
        {fila.parsed.ceco ? (
          <>
            <span style={{
              background: fila.param ? "#eef2ff" : "#fef2f2",
              color: fila.param ? "#1a3a6b" : "#991b1b",
              padding: "2px 8px", borderRadius: 4, fontSize: 11, fontWeight: 600,
            }}>{fila.parsed.ceco}</span>
            {tieneCECONoRegistrado && (
              <button onClick={onAgregarCECO}
                style={{
                  display: "block", marginTop: 4,
                  background: "#fef2f2", border: "1px solid #fca5a5",
                  borderRadius: 6, padding: "2px 8px", fontSize: 10, color: "#991b1b",
                  cursor: "pointer", fontWeight: 600, fontFamily: "Geist, sans-serif",
                }}>+ Agregar CECO</button>
            )}
          </>
        ) : <em style={{ color: "#dc2626", fontSize: 11 }}>(no detectado)</em>}
      </td>
      <td style={pf_td()}>
        <span style={{ fontSize: 11, color: "#475569" }}>{fila.parsed.periodo || "—"}</span>
      </td>
      <td style={pf_td()}>
        <div style={{ wordBreak: "break-all", maxWidth: 240 }}>
          {fila.editTo || <em style={{ color: "#dc2626" }}>vacío</em>}
        </div>
        {fila.trans && (
          <div style={{ fontSize: 9, color: "#16a34a", marginTop: 2 }}>✓ desde Supabase</div>
        )}
      </td>
      <td style={pf_td()}>
        <div style={{ wordBreak: "break-all", maxWidth: 200, fontSize: 11, color: "#64748b" }}>
          {fila.editCc || "—"}
        </div>
      </td>
      <td style={pf_td()}>
        <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
          <button onClick={onEdit}
            disabled={enviando || fila.estadoEnvio === "ok"}
            style={{
              background: "transparent", border: "1px solid #e4e7ec", borderRadius: 6,
              padding: "3px 8px", fontSize: 11, color: "#1a3a6b", cursor: "pointer",
              fontFamily: "Geist, sans-serif", fontWeight: 600,
              opacity: (enviando || fila.estadoEnvio === "ok") ? 0.4 : 1,
            }}>Editar</button>
          <button onClick={onEliminar} disabled={enviando}
            style={{
              background: "transparent", border: "1px solid #fca5a5", borderRadius: 6,
              padding: "3px 8px", fontSize: 11, color: "#991b1b", cursor: "pointer",
              fontFamily: "Geist, sans-serif", fontWeight: 600,
              opacity: enviando ? 0.4 : 1,
            }}>Quitar</button>
        </div>
      </td>
    </tr>
  );
}

function EstadoBadge({ fila }) {
  if (fila.estadoEnvio === "ok") {
    return (
      <div title={fila.motivoEnvio + (fila.tsEnvio ? " · " + new Date(fila.tsEnvio).toLocaleTimeString("es-MX") : "")}>
        <span style={{
          background: "#dcfce7", color: "#166534", padding: "3px 8px",
          borderRadius: 20, fontSize: 10, fontWeight: 700,
        }}>✓ ENVIADO</span>
      </div>
    );
  }
  if (fila.estadoEnvio === "fallido") {
    return (
      <div title={fila.motivoEnvio}>
        <span style={{
          background: "#fee2e2", color: "#991b1b", padding: "3px 8px",
          borderRadius: 20, fontSize: 10, fontWeight: 700,
        }}>✗ FALLIDO</span>
        <div style={{ fontSize: 9, color: "#991b1b", marginTop: 2, maxWidth: 160 }}>
          {fila.motivoEnvio?.slice(0, 60)}{fila.motivoEnvio?.length > 60 ? "..." : ""}
        </div>
      </div>
    );
  }
  if (fila.estadoEnvio === "enviando") {
    return (
      <span style={{
        background: "#fef3c7", color: "#92400e", padding: "3px 8px",
        borderRadius: 20, fontSize: 10, fontWeight: 700,
      }}>⏳ ENVIANDO</span>
    );
  }
  if (!fila.listo) {
    return (
      <div title={fila.errores.join(" · ")}>
        <span style={{
          background: "#fee2e2", color: "#991b1b", padding: "3px 8px",
          borderRadius: 20, fontSize: 10, fontWeight: 700,
        }}>⚠ {fila.errores[0]}</span>
        {fila.errores.length > 1 && (
          <div style={{ fontSize: 9, color: "#991b1b", marginTop: 2 }}>
            +{fila.errores.length - 1} error{fila.errores.length === 2 ? "" : "es"} más
          </div>
        )}
      </div>
    );
  }
  return (
    <span style={{
      background: "#dbeafe", color: "#1e40af", padding: "3px 8px",
      borderRadius: 20, fontSize: 10, fontWeight: 700,
    }}>LISTO</span>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════════════
// SUB-TAB 2: TRANSPORTISTAS (CRUD)
// ═══════════════════════════════════════════════════════════════════════════════════════
function PrefTransportistas({ data, onChange }) {
  const [busqueda, setBusqueda] = useState("");
  const [filtroEstado, setFiltroEstado] = useState("todos");
  const [editando, setEditando] = useState(null);
  const [mostrarImportador, setMostrarImportador] = useState(false);

  const filtrados = useMemo(() => {
    let r = [...data];
    if (filtroEstado !== "todos") r = r.filter(t => (t.estado || "").toLowerCase() === filtroEstado);
    if (busqueda.trim()) {
      const q = busqueda.toLowerCase();
      r = r.filter(t =>
        (t.nombre || "").toLowerCase().includes(q) ||
        (t.rfc || "").toLowerCase().includes(q) ||
        (t.correo_to || "").toLowerCase().includes(q)
      );
    }
    return r;
  }, [data, busqueda, filtroEstado]);

  const handleEliminar = async (id, nombre) => {
    if (!confirm(`¿Eliminar al transportista "${nombre}"?\n\nEsta acción no se puede deshacer.`)) return;
    try {
      const { error } = await sb.from("prefacturas_transportistas_mx").delete().eq("id", id);
      if (error) throw error;
      await onChange();
    } catch (e) {
      alert("Error eliminando: " + e.message);
    }
  };

  const filaEdicion = editando === "nuevo"
    ? { nombre: "", rfc: "", estado: "Activo", correo_to: "", correo_cc: "", correo_bcc: "", notas: "" }
    : (editando ? data.find(t => t.id === editando) : null);

  return (
    <div className="pg" style={{ maxWidth: 1300 }}>
      <div style={{ marginBottom: 16, display: "flex", justifyContent: "space-between", alignItems: "flex-end", flexWrap: "wrap", gap: 10 }}>
        <div>
          <div className="sec-title">Transportistas MX</div>
          <div className="sec-sub">Editá nombres, RFC y correos. Esta es la fuente de verdad para el envío.</div>
        </div>
        <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
          <BotonDescargarExcel
            onClick={async () => {
              const cabeceras = ["Nombre", "RFC", "Estado", "Correo TO", "CC", "BCC", "Contacto"];
              const filas = filtrados.map(t => [
                t.nombre || "",
                t.rfc || "",
                t.estado || "",
                t.correo_to || "",
                t.correo_cc || "",
                t.correo_bcc || "",
                t.notas || "",
              ]);
              await descargarExcelMultihoja(
                [{ nombre: "Transportistas MX", datos: [cabeceras, ...filas] }],
                "transportistas_mx"
              );
            }}
            label="Descargar Excel"
          />
          <button onClick={() => setMostrarImportador(true)}
            style={{
              background: "#fff", border: "1px solid #1a3a6b", borderRadius: 8,
              padding: "9px 16px", fontSize: 13, color: "#1a3a6b", cursor: "pointer",
              fontFamily: "Geist, sans-serif", fontWeight: 600,
            }}>
            📤 Importar Excel
          </button>
          <button className="btn-orange" onClick={() => setEditando("nuevo")} style={{ padding: "9px 16px", fontSize: 13 }}>
            + Nuevo transportista
          </button>
        </div>
      </div>

      <div className="form-card" style={{ padding: "12px 16px" }}>
        <div style={{ display: "flex", gap: 10, alignItems: "center", flexWrap: "wrap" }}>
          <input
            placeholder="Buscar por nombre, RFC o correo..."
            value={busqueda} onChange={e => setBusqueda(e.target.value)}
            style={{ flex: "1 1 280px", maxWidth: 400 }}
          />
          <select value={filtroEstado} onChange={e => setFiltroEstado(e.target.value)} style={{ width: 160 }}>
            <option value="todos">Todos los estados</option>
            <option value="activo">Activo</option>
            <option value="inactivo">Inactivo</option>
          </select>
          <div style={{ fontSize: 12, color: "#64748b", marginLeft: "auto" }}>
            {filtrados.length} de {data.length} transportistas
          </div>
        </div>
      </div>

      <div className="form-card" style={{ padding: 0, overflow: "hidden" }}>
        <div style={{ overflowX: "auto" }}>
          <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
            <thead>
              <tr style={{ background: "#f8fafc", borderBottom: "1px solid #e4e7ec" }}>
                <th style={pf_th()}>Nombre</th>
                <th style={pf_th()}>RFC</th>
                <th style={pf_th()}>Estado</th>
                <th style={pf_th()}>Correo TO</th>
                <th style={pf_th()}>CC</th>
                <th style={pf_th()}>BCC</th>
                <th style={pf_th()}>Acciones</th>
              </tr>
            </thead>
            <tbody>
              {filtrados.length === 0 ? (
                <tr><td colSpan={7} style={{ padding: 30, textAlign: "center", color: "#94a3b8" }}>
                  Sin resultados. Probá quitar filtros o agregar un nuevo transportista.
                </td></tr>
              ) : filtrados.map(t => (
                <tr key={t.id}>
                  <td style={pf_td()}>
                    <div style={{ fontWeight: 600 }}>{t.nombre}</div>
                    {t.notas && <div style={{ fontSize: 10, color: "#94a3b8" }}>{t.notas}</div>}
                  </td>
                  <td style={pf_td()}>
                    <code style={{ fontSize: 11, color: "#64748b" }}>{t.rfc || "—"}</code>
                  </td>
                  <td style={pf_td()}>
                    <span style={{
                      background: (t.estado || "").toLowerCase() === "activo" ? "#dcfce7" : "#fee2e2",
                      color: (t.estado || "").toLowerCase() === "activo" ? "#166534" : "#991b1b",
                      padding: "2px 8px", borderRadius: 20, fontSize: 10, fontWeight: 700,
                    }}>{t.estado || "—"}</span>
                  </td>
                  <td style={pf_td()}>
                    <div style={{ wordBreak: "break-all", maxWidth: 220, fontSize: 11 }}>
                      {t.correo_to || <em style={{ color: "#dc2626" }}>vacío</em>}
                    </div>
                  </td>
                  <td style={pf_td()}>
                    <div style={{ wordBreak: "break-all", maxWidth: 200, fontSize: 11, color: "#64748b" }}>
                      {t.correo_cc || "—"}
                    </div>
                  </td>
                  <td style={pf_td()}>
                    <div style={{ wordBreak: "break-all", maxWidth: 200, fontSize: 11, color: "#64748b" }}>
                      {t.correo_bcc || "—"}
                    </div>
                  </td>
                  <td style={pf_td()}>
                    <div style={{ display: "flex", gap: 6 }}>
                      <button onClick={() => setEditando(t.id)}
                        style={{
                          background: "transparent", border: "1px solid #e4e7ec", borderRadius: 6,
                          padding: "3px 8px", fontSize: 11, color: "#1a3a6b", cursor: "pointer",
                          fontWeight: 600, fontFamily: "Geist, sans-serif",
                        }}>Editar</button>
                      <button onClick={() => handleEliminar(t.id, t.nombre)}
                        style={{
                          background: "transparent", border: "1px solid #fca5a5", borderRadius: 6,
                          padding: "3px 8px", fontSize: 11, color: "#991b1b", cursor: "pointer",
                          fontWeight: 600, fontFamily: "Geist, sans-serif",
                        }}>Eliminar</button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {filaEdicion && (
        <ModalEdicionTransportista
          inicial={filaEdicion}
          esNuevo={editando === "nuevo"}
          editandoId={editando !== "nuevo" ? editando : null}
          onCancelar={() => setEditando(null)}
          onGuardarOK={async () => { setEditando(null); await onChange(); }}
        />
      )}

      {mostrarImportador && (
        <ModalImportadorTransportistas
          config={CONFIG_IMPORTADOR_MX}
          dataExistente={data}
          onCancelar={() => setMostrarImportador(false)}
          onImportadoOK={async () => { await onChange(); }}
        />
      )}
    </div>
  );
}

function ModalEdicionTransportista({ inicial, esNuevo, editandoId, onCancelar, onGuardarOK }) {
  const [form, setForm] = useState(inicial);
  const [guardando, setGuardando] = useState(false);

  const handleGuardar = async () => {
    if (!form.nombre.trim()) { alert("El nombre es obligatorio."); return; }
    setGuardando(true);
    try {
      const payload = {
        nombre: form.nombre.trim(),
        rfc: (form.rfc || "").trim() || null,
        estado: form.estado || "Activo",
        correo_to: (form.correo_to || "").trim() || null,
        correo_cc: (form.correo_cc || "").trim() || null,
        correo_bcc: (form.correo_bcc || "").trim() || null,
        notas: (form.notas || "").trim() || null,
        updated_at: new Date().toISOString(),
      };
      if (esNuevo) {
        const { error } = await sb.from("prefacturas_transportistas_mx").insert(payload);
        if (error) throw error;
      } else {
        const { error } = await sb.from("prefacturas_transportistas_mx").update(payload).eq("id", editandoId);
        if (error) throw error;
      }
      await onGuardarOK();
    } catch (e) {
      alert("Error guardando: " + e.message);
    }
    setGuardando(false);
  };

  return (
    <div style={{
      position: "fixed", inset: 0, background: "rgba(0,0,0,0.5)",
      display: "flex", alignItems: "center", justifyContent: "center", zIndex: 1000, padding: 20,
    }} onClick={onCancelar}>
      <div onClick={e => e.stopPropagation()} style={{
        background: "#fff", borderRadius: 14, padding: 24, maxWidth: 600, width: "100%",
        maxHeight: "90vh", overflowY: "auto",
      }}>
        <div style={{ fontSize: 16, fontWeight: 700, color: "#1a3a6b", marginBottom: 16 }}>
          {esNuevo ? "Nuevo transportista" : "Editar transportista"}
        </div>
        <div className="field-row">
          <div className="field-label">Nombre *</div>
          <input value={form.nombre} onChange={e => setForm({ ...form, nombre: e.target.value })}
            placeholder="Ej: LUIS FELIPE HIDALGO SANTIAGO" />
        </div>
        <div className="two-col">
          <div className="field-row">
            <div className="field-label">RFC</div>
            <input value={form.rfc || ""} onChange={e => setForm({ ...form, rfc: e.target.value })}
              placeholder="HISL871105C2A" />
          </div>
          <div className="field-row">
            <div className="field-label">Estado</div>
            <select value={form.estado || "Activo"} onChange={e => setForm({ ...form, estado: e.target.value })}>
              <option value="Activo">Activo</option>
              <option value="Inactivo">Inactivo</option>
            </select>
          </div>
        </div>
        <div className="field-row">
          <div className="field-label">Correo TO *</div>
          <input value={form.correo_to || ""} onChange={e => setForm({ ...form, correo_to: e.target.value })}
            placeholder="correo@dominio.com" />
        </div>
        <div className="field-row">
          <div className="field-label">Correo CC</div>
          <input value={form.correo_cc || ""} onChange={e => setForm({ ...form, correo_cc: e.target.value })}
            placeholder="opcional · separá varios con ;" />
        </div>
        <div className="field-row">
          <div className="field-label">Correo BCC</div>
          <input value={form.correo_bcc || ""} onChange={e => setForm({ ...form, correo_bcc: e.target.value })}
            placeholder="opcional" />
        </div>
        <div className="field-row">
          <div className="field-label">Notas internas</div>
          <textarea value={form.notas || ""} onChange={e => setForm({ ...form, notas: e.target.value })}
            placeholder="(opcional)" style={{ height: 60 }} />
        </div>
        <div style={{ display: "flex", gap: 8, justifyContent: "flex-end", marginTop: 14 }}>
          <button onClick={onCancelar} disabled={guardando}
            style={{
              background: "#fff", border: "1px solid #e4e7ec", borderRadius: 8,
              padding: "8px 14px", fontSize: 12, color: "#475569", cursor: "pointer",
              fontFamily: "Geist, sans-serif", fontWeight: 600,
            }}>Cancelar</button>
          <button onClick={handleGuardar} disabled={guardando} className="btn-blue"
            style={{ padding: "8px 14px", fontSize: 12 }}>
            {guardando ? "Guardando..." : "Guardar"}
          </button>
        </div>
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════════════
// SUB-TAB 3: PARÁMETROS / CECOs (simplificado: sin plantillas, esas viven en el envío)
// ═══════════════════════════════════════════════════════════════════════════════════════
function PrefParametros({ data, onChange }) {
  const [editando, setEditando] = useState(null);

  const handleEliminar = async (id, ceco) => {
    if (!confirm(`¿Eliminar el CECO "${ceco}"?`)) return;
    try {
      const { error } = await sb.from("prefacturas_parametros_mx").delete().eq("id", id);
      if (error) throw error;
      await onChange();
    } catch (e) {
      alert("Error eliminando: " + e.message);
    }
  };

  const filaEdicion = editando === "nuevo"
    ? { ceco: "", supervisor: "", correo_supervisor: "", cuenta_envio: "prefacturas@bigticket.cl" }
    : (editando ? data.find(p => p.id === editando) : null);

  return (
    <div className="pg" style={{ maxWidth: 1300 }}>
      <div style={{ marginBottom: 16, display: "flex", justifyContent: "space-between", alignItems: "flex-end", flexWrap: "wrap", gap: 10 }}>
        <div>
          <div className="sec-title">Parámetros por CECO</div>
          <div className="sec-sub">
            Datos por centro de operación. El supervisor y su correo se usan automáticamente
            en cada envío del CECO correspondiente.
          </div>
        </div>
        <button className="btn-orange" onClick={() => setEditando("nuevo")} style={{ padding: "9px 16px", fontSize: 13 }}>
          + Nuevo CECO
        </button>
      </div>

      <div className="form-card" style={{ background: "#eff6ff", borderColor: "#bfdbfe" }}>
        <div style={{ fontSize: 13, fontWeight: 700, color: "#1a3a6b", marginBottom: 6 }}>
          💡 Sobre el asunto y cuerpo del correo
        </div>
        <div style={{ fontSize: 12, color: "#1e40af" }}>
          El asunto y cuerpo del correo NO se configuran aquí. Se editan directamente en la
          sub-tab <strong>"Envío masivo"</strong> arriba de la tabla de envío, así podés ajustar
          las fechas y detalles de cada lote sin tener que modificar la configuración permanente.
        </div>
      </div>

      <div className="form-card" style={{ padding: 0, overflow: "hidden" }}>
        <div style={{ overflowX: "auto" }}>
          <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
            <thead>
              <tr style={{ background: "#f8fafc", borderBottom: "1px solid #e4e7ec" }}>
                <th style={pf_th()}>CECO</th>
                <th style={pf_th()}>Supervisor</th>
                <th style={pf_th()}>Correo supervisor (CC automático)</th>
                <th style={pf_th()}>Cuenta envío</th>
                <th style={pf_th()}>Acciones</th>
              </tr>
            </thead>
            <tbody>
              {data.length === 0 ? (
                <tr><td colSpan={5} style={{ padding: 30, textAlign: "center", color: "#94a3b8" }}>
                  No hay CECOs configurados. Agregá uno con el botón de arriba.
                </td></tr>
              ) : data.map(p => (
                <tr key={p.id}>
                  <td style={pf_td()}>
                    <span style={{
                      background: "#eef2ff", color: "#1a3a6b", padding: "3px 10px",
                      borderRadius: 4, fontSize: 12, fontWeight: 700,
                    }}>{p.ceco}</span>
                  </td>
                  <td style={pf_td()}>{p.supervisor || <em style={{ color: "#94a3b8" }}>—</em>}</td>
                  <td style={pf_td()}>
                    <span style={{ fontSize: 11, color: "#64748b", wordBreak: "break-all" }}>
                      {p.correo_supervisor || "—"}
                    </span>
                  </td>
                  <td style={pf_td()}>
                    <span style={{ fontSize: 11, color: "#64748b" }}>{p.cuenta_envio}</span>
                  </td>
                  <td style={pf_td()}>
                    <div style={{ display: "flex", gap: 6 }}>
                      <button onClick={() => setEditando(p.id)}
                        style={{
                          background: "transparent", border: "1px solid #e4e7ec", borderRadius: 6,
                          padding: "3px 8px", fontSize: 11, color: "#1a3a6b", cursor: "pointer",
                          fontWeight: 600, fontFamily: "Geist, sans-serif",
                        }}>Editar</button>
                      <button onClick={() => handleEliminar(p.id, p.ceco)}
                        style={{
                          background: "transparent", border: "1px solid #fca5a5", borderRadius: 6,
                          padding: "3px 8px", fontSize: 11, color: "#991b1b", cursor: "pointer",
                          fontWeight: 600, fontFamily: "Geist, sans-serif",
                        }}>Eliminar</button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {filaEdicion && (
        <ModalEdicionParametro
          inicial={filaEdicion}
          esNuevo={editando === "nuevo"}
          editandoId={editando !== "nuevo" ? editando : null}
          onCancelar={() => setEditando(null)}
          onGuardarOK={async () => { setEditando(null); await onChange(); }}
        />
      )}
    </div>
  );
}

function ModalEdicionParametro({ inicial, esNuevo, editandoId, onCancelar, onGuardarOK }) {
  const [form, setForm] = useState(inicial);
  const [guardando, setGuardando] = useState(false);

  const handleGuardar = async () => {
    if (!form.ceco.trim()) { alert("El CECO es obligatorio."); return; }
    setGuardando(true);
    try {
      const payload = {
        ceco: form.ceco.trim().toUpperCase(),
        supervisor: (form.supervisor || "").trim() || null,
        correo_supervisor: (form.correo_supervisor || "").trim() || null,
        cuenta_envio: (form.cuenta_envio || "").trim() || "prefacturas@bigticket.cl",
        updated_at: new Date().toISOString(),
      };
      if (esNuevo) {
        const { error } = await sb.from("prefacturas_parametros_mx").insert(payload);
        if (error) throw error;
      } else {
        const { error } = await sb.from("prefacturas_parametros_mx").update(payload).eq("id", editandoId);
        if (error) throw error;
      }
      await onGuardarOK();
    } catch (e) {
      alert("Error guardando: " + e.message);
    }
    setGuardando(false);
  };

  return (
    <div style={{
      position: "fixed", inset: 0, background: "rgba(0,0,0,0.5)",
      display: "flex", alignItems: "center", justifyContent: "center", zIndex: 1000, padding: 20,
    }} onClick={onCancelar}>
      <div onClick={e => e.stopPropagation()} style={{
        background: "#fff", borderRadius: 14, padding: 24, maxWidth: 600, width: "100%",
        maxHeight: "90vh", overflowY: "auto",
      }}>
        <div style={{ fontSize: 16, fontWeight: 700, color: "#1a3a6b", marginBottom: 16 }}>
          {esNuevo ? "Nuevo CECO" : "Editar parámetros del CECO"}
        </div>
        <div className="two-col">
          <div className="field-row">
            <div className="field-label">CECO *</div>
            <input value={form.ceco} onChange={e => setForm({ ...form, ceco: e.target.value.toUpperCase() })}
              placeholder="SMX7" disabled={!esNuevo} />
            {!esNuevo && <div style={{ fontSize: 10, color: "#94a3b8", marginTop: 2 }}>El CECO no se puede modificar después de creado.</div>}
          </div>
          <div className="field-row">
            <div className="field-label">Cuenta envío</div>
            <input value={form.cuenta_envio || ""} onChange={e => setForm({ ...form, cuenta_envio: e.target.value })}
              placeholder="prefacturas@bigticket.cl" />
          </div>
        </div>
        <div className="field-row">
          <div className="field-label">Supervisor</div>
          <input value={form.supervisor || ""} onChange={e => setForm({ ...form, supervisor: e.target.value })}
            placeholder="ROBERTO LOPEZ" />
        </div>
        <div className="field-row">
          <div className="field-label">Correo supervisor (irá en CC del envío)</div>
          <input value={form.correo_supervisor || ""} onChange={e => setForm({ ...form, correo_supervisor: e.target.value })}
            placeholder="supervisor@bigticket.mx" />
        </div>
        <div style={{
          marginTop: 8, padding: "10px 12px", background: "#eff6ff", borderRadius: 8,
          fontSize: 11, color: "#1a3a6b",
        }}>
          💡 El asunto y cuerpo del correo se editan en la sub-tab "Envío masivo" antes de cada lote.
        </div>
        <div style={{ display: "flex", gap: 8, justifyContent: "flex-end", marginTop: 14 }}>
          <button onClick={onCancelar} disabled={guardando}
            style={{
              background: "#fff", border: "1px solid #e4e7ec", borderRadius: 8,
              padding: "8px 14px", fontSize: 12, color: "#475569", cursor: "pointer",
              fontFamily: "Geist, sans-serif", fontWeight: 600,
            }}>Cancelar</button>
          <button onClick={handleGuardar} disabled={guardando} className="btn-blue"
            style={{ padding: "8px 14px", fontSize: 12 }}>
            {guardando ? "Guardando..." : "Guardar"}
          </button>
        </div>
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════════════
// SUB-TAB 4: HISTORIAL DE ENVÍOS
// ═══════════════════════════════════════════════════════════════════════════════════════
function PrefHistorial({ pais = "MX" }) {
  const [logs, setLogs] = useState([]);
  const [cargando, setCargando] = useState(true);
  const [filtroEstado, setFiltroEstado] = useState("todos");
  const [busqueda, setBusqueda] = useState("");
  const [limite, setLimite] = useState(100);

  const cargar = async () => {
    setCargando(true);
    try {
      const { data } = await sb.from("prefacturas_envios_log")
        .select("*")
        .eq("pais", pais)
        .order("fecha_envio", { ascending: false }).limit(limite);
      setLogs(data || []);
    } catch (e) { console.error(e); }
    setCargando(false);
  };

  useEffect(() => { cargar(); }, [limite, pais]);

  const filtrados = useMemo(() => {
    let r = [...logs];
    if (filtroEstado !== "todos") r = r.filter(l => (l.estado || "") === filtroEstado);
    if (busqueda.trim()) {
      const q = busqueda.toLowerCase();
      r = r.filter(l =>
        (l.transportista || "").toLowerCase().includes(q) ||
        (l.ceco || "").toLowerCase().includes(q) ||
        (l.correo_to || "").toLowerCase().includes(q)
      );
    }
    return r;
  }, [logs, filtroEstado, busqueda]);

  const stats = useMemo(() => ({
    total: logs.length,
    ok: logs.filter(l => l.estado === "enviado").length,
    err: logs.filter(l => l.estado === "fallido").length,
  }), [logs]);

  return (
    <div className="pg" style={{ maxWidth: 1300 }}>
      <div style={{ marginBottom: 16 }}>
        <div className="sec-title">Historial de envíos</div>
        <div className="sec-sub">Registro de todos los correos enviados desde el Brain.</div>
      </div>

      <div style={{
        display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(160px, 1fr))",
        gap: 10, marginBottom: 14,
      }}>
        <IndicadorPF label="Total registros" valor={stats.total} color="#1a3a6b" />
        <IndicadorPF label="Enviados OK" valor={stats.ok} color="#16a34a" />
        <IndicadorPF label="Fallidos" valor={stats.err} color="#dc2626" />
      </div>

      <div className="form-card" style={{ padding: "12px 16px" }}>
        <div style={{ display: "flex", gap: 10, alignItems: "center", flexWrap: "wrap" }}>
          <input
            placeholder="Buscar transportista, CECO o correo..."
            value={busqueda} onChange={e => setBusqueda(e.target.value)}
            style={{ flex: "1 1 280px", maxWidth: 400 }}
          />
          <select value={filtroEstado} onChange={e => setFiltroEstado(e.target.value)} style={{ width: 160 }}>
            <option value="todos">Todos los estados</option>
            <option value="enviado">Solo enviados</option>
            <option value="fallido">Solo fallidos</option>
          </select>
          <select value={limite} onChange={e => setLimite(Number(e.target.value))} style={{ width: 130 }}>
            <option value={100}>Últimos 100</option>
            <option value={500}>Últimos 500</option>
            <option value={2000}>Últimos 2000</option>
          </select>
          <button onClick={cargar} style={{
            background: "#fff", border: "1px solid #e4e7ec", borderRadius: 8,
            padding: "8px 14px", fontSize: 12, color: "#475569", cursor: "pointer",
            fontFamily: "Geist, sans-serif", fontWeight: 600,
          }}>🔄 Refrescar</button>
        </div>
      </div>

      <div className="form-card" style={{ padding: 0, overflow: "hidden" }}>
        {cargando ? (
          <div className="loading">Cargando historial...</div>
        ) : filtrados.length === 0 ? (
          <div className="empty">Sin envíos registrados.</div>
        ) : (
          <div style={{ overflowX: "auto" }}>
            <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
              <thead>
                <tr style={{ background: "#f8fafc", borderBottom: "1px solid #e4e7ec" }}>
                  <th style={pf_th()}>Fecha</th>
                  <th style={pf_th()}>Estado</th>
                  <th style={pf_th()}>Transportista</th>
                  <th style={pf_th()}>CECO</th>
                  <th style={pf_th()}>Período</th>
                  <th style={pf_th()}>Correo</th>
                  <th style={pf_th()}>Motivo / MessageID</th>
                  <th style={pf_th()}>Usuario</th>
                </tr>
              </thead>
              <tbody>
                {filtrados.map(l => (
                  <tr key={l.id}>
                    <td style={pf_td()}>
                      <span style={{ fontSize: 11, color: "#475569" }}>
                        {new Date(l.fecha_envio).toLocaleString("es-MX")}
                      </span>
                    </td>
                    <td style={pf_td()}>
                      <span style={{
                        background: l.estado === "enviado" ? "#dcfce7" : "#fee2e2",
                        color: l.estado === "enviado" ? "#166534" : "#991b1b",
                        padding: "3px 8px", borderRadius: 20, fontSize: 10, fontWeight: 700,
                      }}>
                        {l.estado === "enviado" ? "✓ ENVIADO" : "✗ FALLIDO"}
                      </span>
                    </td>
                    <td style={pf_td()}>{l.transportista || "—"}</td>
                    <td style={pf_td()}>
                      <span style={{
                        background: "#eef2ff", color: "#1a3a6b", padding: "2px 8px",
                        borderRadius: 4, fontSize: 11, fontWeight: 600,
                      }}>{l.ceco || "—"}</span>
                    </td>
                    <td style={pf_td()}><span style={{ fontSize: 11 }}>{l.periodo || "—"}</span></td>
                    <td style={pf_td()}>
                      <div style={{ wordBreak: "break-all", maxWidth: 200, fontSize: 11 }}>
                        {l.correo_to || "—"}
                      </div>
                    </td>
                    <td style={pf_td()}>
                      <div style={{ wordBreak: "break-all", maxWidth: 260, fontSize: 10, color: "#64748b" }}>
                        {l.motivo || l.message_id || "—"}
                      </div>
                    </td>
                    <td style={pf_td()}>
                      <span style={{ fontSize: 10, color: "#94a3b8" }}>{l.usuario || "—"}</span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════════════
// WRAPPER: ModuloPrefacturasEnvio — Selector de país (MX / CL)
// Renderiza ModuloPrefacturasMX o ModuloPrefacturasCL según selección
// ═══════════════════════════════════════════════════════════════════════════════════════
function ModuloPrefacturasEnvio({ usuario }) {
  const [pais, setPais] = useState(() => {
    try { return localStorage.getItem("pref_pais_seleccionado") || "MX"; }
    catch { return "MX"; }
  });

  useEffect(() => {
    try { localStorage.setItem("pref_pais_seleccionado", pais); } catch {}
  }, [pais]);

  return (
    <div style={{ padding: 0 }}>
      {/* Selector de país */}
      <div style={{
        background: "#fff", borderBottom: "1px solid #e4e7ec", padding: "12px 24px",
        display: "flex", alignItems: "center", gap: 16, flexWrap: "wrap",
      }}>
        <span style={{ fontSize: 12, fontWeight: 600, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5 }}>
          País:
        </span>
        <div style={{ display: "flex", gap: 6 }}>
          <button onClick={() => setPais("MX")}
            style={{
              padding: "8px 18px", borderRadius: 8,
              border: `1px solid ${pais === "MX" ? "#1a3a6b" : "#e4e7ec"}`,
              background: pais === "MX" ? "#1a3a6b" : "#fff",
              color: pais === "MX" ? "#fff" : "#475569",
              fontSize: 13, fontWeight: 600, cursor: "pointer",
              fontFamily: "Geist, sans-serif",
            }}>
            🇲🇽 México
          </button>
          <button onClick={() => setPais("CL")}
            style={{
              padding: "8px 18px", borderRadius: 8,
              border: `1px solid ${pais === "CL" ? "#1a3a6b" : "#e4e7ec"}`,
              background: pais === "CL" ? "#1a3a6b" : "#fff",
              color: pais === "CL" ? "#fff" : "#475569",
              fontSize: 13, fontWeight: 600, cursor: "pointer",
              fontFamily: "Geist, sans-serif",
            }}>
            🇨🇱 Chile
          </button>
        </div>
      </div>

      {pais === "MX" && <ModuloPrefacturasMX usuario={usuario} />}
      {pais === "CL" && <ModuloPrefacturasCL usuario={usuario} />}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════════════
// MÓDULO PREFACTURAS · CL
// ═══════════════════════════════════════════════════════════════════════════════════════
// Webhook n8n: https://bigticket2026.app.n8n.cloud/webhook/prefacturas-enviar-cl
//
// Diferencias clave vs MX:
//   • Tablas: prefacturas_transportistas_cl, prefacturas_parametros_cl
//   • Identificador del PDF: nombre transportista (ej "ISISLINE_SPA.pdf")
//   • Solo 1 correo TO por transportista (no hay CC/BCC separados en nómina)
//   • CC del envío = correo_supervisor + lideres de la operación del CECO
//   • OPERACIÓN tiene formato "CLIENTE - CENTRO_COSTO" (ej "MERCADO LIBRE - RM")
//   • Estado "Bloqueado" → no se permite envío (NO ENVIAR)
// ═══════════════════════════════════════════════════════════════════════════════════════

const PREFACTURAS_CL_WEBHOOK = "https://bigticket2026.app.n8n.cloud/webhook/prefacturas-enviar-cl";
const VARIABLES_PLANTILLA_CL = [
  "TRANSPORTISTA", "RUT", "OPERACION", "CLIENTE", "CENTRO_COSTO",
  "PERIODO", "MES_FACTURA", "SUPERVISOR", "VALOR_UF", "REGION",
];
const LS_KEY_ASUNTO_CL = "pref_cl_ultimo_asunto";
const LS_KEY_CUERPO_CL = "pref_cl_ultimo_cuerpo";
const ASUNTO_DEFAULT_CL = "PREFACTURA {OPERACION}//{MES_FACTURA}//{TRANSPORTISTA}";
const CUERPO_DEFAULT_CL = `Estimado/a,

Junto con saludar y esperando se encuentre bien, adjunto prefactura detallada en asunto correspondiente al período de {MES_FACTURA}.

SE SOLICITA UTILIZAR COMO GLOSA: "PRODUCCION {MES_FACTURA}"; en caso de no referirse la glosa citada, la factura será rechazada.

Favor adjuntar pdf de factura y copiar a prefacturas@bigticket.cl

Sí por algún motivo hay alguna diferencia; favor hacérnosla saber completando el siguiente formulario https://app.pipefy.com/public/form/Yp603otD detallando los viajes u observaciones presentadas en el documento adjunto para que estas puedan ser validadas por su supervisor y reliquidadas en siguiente facturación.

Si sus diferencias no son reportadas en el formulario mencionado anteriormente; estas no serán procesadas. Respecto al envío de facturas, esta debe ser por el mismo canal de siempre.
Emitir Factura y envío con fecha máximo: XX-XX-2026 a las 12:00 Hrs.
Fecha Pago: XX-XX-2026

De no recibir su factura en el plazo estipulado, el pago se reprogramará con fecha XX de XXXXX 2026 o hasta el viernes más próximo posterior a la recepción de su factura y documentos de certificación pendientes [si es que aplica].

RECORDAR: Para evitar retenciones y postergaciones de pago, favor tener presente que la fecha CORTE DE RECEPCION DE DOCUMENTOS DE CERTIFICACION ES EL DIA XX-XX-2026; Debe contar con toda la certificación mensual enviada EN FORMATO PDF y validada en plataforma certronic. Recuerde que una vez cargada la documentación, el equipo de certronic cuenta con 48 horas para su validación por lo que se sugiere no esperar hasta la fecha limite para evitar retenciones innecesarias.

Agradeciendo desde ya su comprensión y colaboración,
Saludos.
Departamento Pago Transportes.
Alonso de Córdova No. 5870, Oficina 724, Las Condes.`;

// Regex para detectar OPERACIÓN en formato "CLIENTE - CECO" en el PDF Chile
// Por ejemplo: "MERCADO LIBRE - RM", "SODIMAC - SERENA", "ROSEN - VIÑA"
const REGEX_OPERACION_CL = /([A-ZÁÉÍÓÚÑ][A-ZÁÉÍÓÚÑ\s]+?)\s*-\s*([A-ZÁÉÍÓÚÑ][A-ZÁÉÍÓÚÑ\s]+)/;

// ─── PARSING DE LOS CAMPOS DEL PDF CHILE ────────────────────────────────────────────
// El PDF Chile tiene la misma estructura que MX pero con campos extras (VALOR UF, MES FACTURA)
// y OPERACIÓN con formato "CLIENTE - CECO" en vez de "ML_MXSMX7"
function pf_parsearPDF_CL(texto) {
  const t = texto.replace(/\u00A0/g, " ").replace(/[ \t]+/g, " ");

  // EMPRESA TRANSPORTE
  const reTransp = /EMPRESA\s+TRANSPORTE\s*:?\s*([A-ZÁÉÍÓÚÑ0-9][A-ZÁÉÍÓÚÑa-z0-9áéíóúñ\s\.\&\-]+?)(?=\s*(?:RUT\b|RESUMEN\b|OPERACI[ÓO]N\b|SUPERVISOR\b|PERIODO\b|MES\s+FACTURA\b|VALOR\s+UF\b|PATENTE\b|CORREO\b|\$|\n|$))/i;
  const mTransp = t.match(reTransp);
  const transportista = mTransp ? mTransp[1].trim().replace(/\s+/g, " ") : "";

  // RUT EMPRESA TRANSPORTE
  const reRut = /RUT\s+EMPRESA\s+TRANSPORTE\s*:?\s*([0-9]{1,10}-[0-9Kk])/i;
  const mRut = t.match(reRut);
  const rut = mRut ? mRut[1].trim().toUpperCase() : "";

  // OPERACIÓN: capturar el primer match con formato "CLIENTE - CECO"
  // Buscamos después del label "OPERACIÓN:" para evitar falsos positivos
  let operacion = "";
  let cliente = "";
  let centroCosto = "";
  const reOpLabel = /OPERACI[ÓO]N\s*:?\s*([^\n]+?)(?=\s*(?:SUPERVISOR\b|PERIODO\b|MES\s+FACTURA\b|VALOR\s+UF\b|RESUMEN\b|CORREO\b|\$|\n|$))/i;
  const mOpLabel = t.match(reOpLabel);
  if (mOpLabel) {
    const linea = mOpLabel[1].trim();
    const mOp = linea.match(REGEX_OPERACION_CL);
    if (mOp) {
      cliente = mOp[1].trim().replace(/\s+/g, " ");
      centroCosto = mOp[2].trim().replace(/\s+/g, " ");
      operacion = `${cliente} - ${centroCosto}`;
    } else {
      // Si no matchea el patrón "CLIENTE - CECO", usar la línea completa
      operacion = linea.replace(/\s+/g, " ");
    }
  }

  // SUPERVISOR (del PDF, solo informativo — el real lo tomamos de Supabase)
  const reSup = /SUPERVISOR\s*:?\s*([^\n]+?)(?=\s*(?:CORREO\b|PERIODO\b|MES\s+FACTURA\b|VALOR\s+UF\b|RESUMEN\b|\$|\n|$))/i;
  const mSup = t.match(reSup);
  const supervisorPDF = mSup ? mSup[1].trim().replace(/\s+/g, " ") : "";

  // PERIODO PREFACTURADO
  const rePer = /PERIODO\s+PREFACTURADO\s*:?\s*([^\n]+?)(?=\s*(?:MES\s+FACTURA\b|VALOR\s+UF\b|RESUMEN\b|TOTAL\b|\$|\n|$))/i;
  const mPer = t.match(rePer);
  const periodo = mPer ? mPer[1].trim().replace(/\s+/g, " ").toUpperCase() : "";

  // MES FACTURA
  const reMes = /MES\s+FACTURA\s*:?\s*([A-ZÁÉÍÓÚ]+(?:\s+\d{4})?)/i;
  const mMes = t.match(reMes);
  const mesFactura = mMes ? mMes[1].trim().toUpperCase() : "";

  // VALOR UF
  const reUf = /VALOR\s+UF\s*:?\s*\$?\s*([0-9\.\,]+)/i;
  const mUf = t.match(reUf);
  const valorUf = mUf ? mUf[1].trim() : "";

  return {
    transportista, rut, operacion, cliente, centroCosto,
    supervisorPDF, periodo, mesFactura, valorUf,
  };
}

// ═══════════════════════════════════════════════════════════════════════════════════════
// COMPONENTE ROOT CHILE: ModuloPrefacturasCL (4 sub-tabs)
// ═══════════════════════════════════════════════════════════════════════════════════════
function ModuloPrefacturasCL({ usuario }) {
  const [subtab, setSubtab] = useState("envio");
  const [transportistas, setTransportistas] = useState([]);
  const [parametros, setParametros] = useState([]);
  const [cargando, setCargando] = useState(true);

  const cargarDatos = async () => {
    setCargando(true);
    try {
      const [{ data: t }, { data: p }] = await Promise.all([
        sb.from("prefacturas_transportistas_cl").select("*").order("nombre"),
        sb.from("prefacturas_parametros_cl").select("*").order("operacion"),
      ]);
      setTransportistas(t || []);
      setParametros(p || []);
    } catch (e) {
      console.error("Error cargando datos prefacturas CL:", e);
    }
    setCargando(false);
  };

  useEffect(() => { cargarDatos(); }, []);

  const subtabs = [
    { id: "envio",          label: "Envío masivo",        icon: "📨" },
    { id: "transportistas", label: "Transportistas",      icon: "🚚" },
    { id: "parametros",     label: "Operaciones / CECOs", icon: "⚙️" },
    { id: "historial",      label: "Historial",           icon: "📋" },
  ];

  return (
    <div style={{ padding: 0 }}>
      <div style={{ background: "#fff", borderBottom: "1px solid #e4e7ec", padding: "12px 24px" }}>
        <div style={{ display: "flex", gap: 6, flexWrap: "wrap" }}>
          {subtabs.map(t => (
            <button key={t.id} onClick={() => setSubtab(t.id)}
              style={{
                padding: "8px 16px", borderRadius: 8,
                border: `1px solid ${subtab === t.id ? "#1a3a6b" : "#e4e7ec"}`,
                background: subtab === t.id ? "#1a3a6b" : "#fff",
                color: subtab === t.id ? "#fff" : "#475569",
                fontSize: 12, fontWeight: 600, cursor: "pointer",
                fontFamily: "Geist, sans-serif",
              }}>
              {t.icon} {t.label}
            </button>
          ))}
        </div>
      </div>

      {cargando ? (
        <div className="loading">Cargando configuración de prefacturas Chile...</div>
      ) : (
        <>
          {subtab === "envio"          && <PrefCLEnvioMasivo transportistas={transportistas} parametros={parametros} usuario={usuario} onActualizarMaestros={cargarDatos} />}
          {subtab === "transportistas" && <PrefCLTransportistas data={transportistas} onChange={cargarDatos} />}
          {subtab === "parametros"     && <PrefCLParametros data={parametros} onChange={cargarDatos} />}
          {subtab === "historial"      && <PrefHistorial pais="CL" />}
        </>
      )}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════════════
// SUB-TAB 1 CHILE: ENVÍO MASIVO
// ═══════════════════════════════════════════════════════════════════════════════════════
function PrefCLEnvioMasivo({ transportistas, parametros, usuario, onActualizarMaestros }) {
  const [pdfsEnProceso, setPdfsEnProceso] = useState(0);
  const [filas, setFilas] = useState([]);
  const [error, setError] = useState("");
  const [enviando, setEnviando] = useState(false);
  const [progreso, setProgreso] = useState({ actual: 0, total: 0 });
  const [editFila, setEditFila] = useState(null);
  const [logFinal, setLogFinal] = useState(null);
  const [arrastrando, setArrastrando] = useState(false);
  const [modalAgregar, setModalAgregar] = useState(null);
  const pdfInputRef = useRef(null);

  const [asuntoLote, setAsuntoLote] = useState(() => {
    try { return localStorage.getItem(LS_KEY_ASUNTO_CL) || ASUNTO_DEFAULT_CL; }
    catch { return ASUNTO_DEFAULT_CL; }
  });
  const [cuerpoLote, setCuerpoLote] = useState(() => {
    try { return localStorage.getItem(LS_KEY_CUERPO_CL) || CUERPO_DEFAULT_CL; }
    catch { return CUERPO_DEFAULT_CL; }
  });

  useEffect(() => {
    try { localStorage.setItem(LS_KEY_ASUNTO_CL, asuntoLote); } catch {}
  }, [asuntoLote]);
  useEffect(() => {
    try { localStorage.setItem(LS_KEY_CUERPO_CL, cuerpoLote); } catch {}
  }, [cuerpoLote]);

  // Lookups
  const transByNombre = useMemo(() => {
    const m = new Map();
    transportistas.forEach(t => m.set(String(t.nombre).toUpperCase().trim(), t));
    return m;
  }, [transportistas]);
  const paramsByOp = useMemo(() => {
    const m = new Map();
    parametros.forEach(p => m.set(String(p.operacion).toUpperCase().trim(), p));
    return m;
  }, [parametros]);

  const procesarPDF = async (file, idx) => {
    try {
      const texto = await pf_extraerTextoPDF(file);
      const parsed = pf_parsearPDF_CL(texto);
      const trans = parsed.transportista
        ? transByNombre.get(parsed.transportista.toUpperCase().trim())
        : null;
      const param = parsed.operacion
        ? paramsByOp.get(parsed.operacion.toUpperCase().trim())
        : null;

      // CC Chile: correo del supervisor + líderes de la operación (concatenados)
      const ccs = [];
      if (param?.correo_supervisor) ccs.push(param.correo_supervisor.trim());
      if (param?.lideres) ccs.push(param.lideres.trim());
      const ccCombinado = ccs.join("; ");

      return {
        idx,
        file,
        nombre: file.name,
        size: file.size,
        parsed,
        trans,
        param,
        editTo: trans?.correo || "",
        editCc: ccCombinado,
        editBcc: "",
        overrideAsunto: null,
        overrideCuerpo: null,
        estadoEnvio: null,
        motivoEnvio: "",
        tsEnvio: null,
        errorParseo: "",
      };
    } catch (e) {
      return {
        idx,
        file,
        nombre: file.name,
        size: file.size,
        parsed: { transportista: "", rut: "", operacion: "", cliente: "", centroCosto: "",
                  supervisorPDF: "", periodo: "", mesFactura: "", valorUf: "" },
        trans: null,
        param: null,
        editTo: "", editCc: "", editBcc: "",
        overrideAsunto: null, overrideCuerpo: null,
        estadoEnvio: null, motivoEnvio: "", tsEnvio: null,
        errorParseo: e.message || String(e),
      };
    }
  };

  const onPdfsDrop = async (fileList) => {
    setError("");
    const archivos = Array.from(fileList || []).filter(f => /\.pdf$/i.test(f.name) && f.size > 0);
    if (archivos.length === 0) {
      setError("No se detectaron archivos PDF válidos.");
      return;
    }
    setPdfsEnProceso(archivos.length);
    const idxInicio = filas.length;
    const nuevos = [];
    for (let i = 0; i < archivos.length; i++) {
      const fila = await procesarPDF(archivos[i], idxInicio + i);
      nuevos.push(fila);
      setPdfsEnProceso(archivos.length - i - 1);
    }
    setPdfsEnProceso(0);
    setFilas(prev => {
      const map = new Map();
      [...prev, ...nuevos].forEach(f => map.set(f.nombre, f));
      return Array.from(map.values()).map((f, i) => ({ ...f, idx: i }));
    });
    setLogFinal(null);
  };

  const armarVariables = (f) => ({
    TRANSPORTISTA: f.parsed.transportista,
    RUT: f.parsed.rut,
    OPERACION: f.parsed.operacion,
    CLIENTE: f.param?.cliente || f.parsed.cliente,
    CENTRO_COSTO: f.param?.centro_costo || f.parsed.centroCosto,
    PERIODO: f.parsed.periodo,
    MES_FACTURA: f.parsed.mesFactura,
    SUPERVISOR: f.param?.supervisor || f.parsed.supervisorPDF || "",
    VALOR_UF: f.parsed.valorUf,
    REGION: f.param?.region || "",
  });

  const filasConEstado = useMemo(() => {
    return filas.map(f => {
      const valTo = pf_limpiarLista(f.editTo);
      const valCc = pf_limpiarLista(f.editCc);
      const valBcc = pf_limpiarLista(f.editBcc);
      const errores = [];
      if (f.errorParseo) errores.push("Error de parseo: " + f.errorParseo);
      if (!f.parsed.transportista) errores.push("PDF sin EMPRESA TRANSPORTE");
      if (!f.parsed.operacion) errores.push("PDF sin OPERACIÓN detectable");
      if (f.parsed.transportista && !f.trans) errores.push("Transportista no registrado");
      if (f.parsed.operacion && !f.param) errores.push("Operación no registrada");
      if (f.trans && String(f.trans.estado || "").toLowerCase() === "bloqueado") errores.push("Transportista BLOQUEADO (NO ENVIAR)");
      if (!valTo.limpia) errores.push("Sin correo TO");
      else if (!valTo.valida) errores.push("TO inválido");
      if (f.editCc && !valCc.valida) errores.push("CC inválido");
      if (f.editBcc && !valBcc.valida) errores.push("BCC inválido");

      const vars = armarVariables(f);
      const asuntoFinal = pf_aplicarPlantilla(f.overrideAsunto !== null ? f.overrideAsunto : asuntoLote, vars);
      const cuerpoFinal = pf_aplicarPlantilla(f.overrideCuerpo !== null ? f.overrideCuerpo : cuerpoLote, vars);

      return { ...f, errores, listo: errores.length === 0, asuntoFinal, cuerpoFinal };
    });
  }, [filas, asuntoLote, cuerpoLote]);

  const totalListos = filasConEstado.filter(f => f.listo).length;
  const totalConErrores = filasConEstado.length - totalListos;

  const guardarEdicion = (idx, campos) => {
    setFilas(prev => prev.map(f => f.idx === idx ? { ...f, ...campos } : f));
    setEditFila(null);
  };
  const eliminarFila = (idx) => {
    setFilas(prev => prev.filter(f => f.idx !== idx).map((f, i) => ({ ...f, idx: i })));
  };
  const limpiarTodo = () => {
    if (!confirm("¿Limpiar todos los PDFs y resultados?\n\n(El asunto y cuerpo se mantienen)")) return;
    setFilas([]); setError(""); setLogFinal(null); setProgreso({ actual: 0, total: 0 });
  };
  const restaurarPlantillaDefault = () => {
    if (!confirm("¿Restaurar el asunto y cuerpo al valor por defecto?\n\nVas a perder cualquier cambio que hayas hecho.")) return;
    setAsuntoLote(ASUNTO_DEFAULT_CL);
    setCuerpoLote(CUERPO_DEFAULT_CL);
  };

  const onAgregarYRefrescar = async () => {
    setModalAgregar(null);
    await onActualizarMaestros();
    if (filas.length > 0) {
      const reprocesadas = [];
      for (const f of filas) {
        const nueva = await procesarPDF(f.file, f.idx);
        reprocesadas.push({
          ...nueva,
          editTo: f.editTo && f.editTo !== "" ? f.editTo : nueva.editTo,
          editCc: f.editCc && f.editCc !== "" ? f.editCc : nueva.editCc,
          editBcc: f.editBcc && f.editBcc !== "" ? f.editBcc : nueva.editBcc,
          overrideAsunto: f.overrideAsunto,
          overrideCuerpo: f.overrideCuerpo,
          estadoEnvio: f.estadoEnvio,
          motivoEnvio: f.motivoEnvio,
          tsEnvio: f.tsEnvio,
        });
      }
      setFilas(reprocesadas);
    }
  };

  const enviarMasivo = async () => {
    const enviables = filasConEstado.filter(f => f.listo);
    if (enviables.length === 0) {
      alert("No hay filas listas para enviar. Revisá los errores en la tabla.");
      return;
    }
    if (!asuntoLote.trim()) { alert("El asunto está vacío."); return; }
    if (!cuerpoLote.trim()) { alert("El cuerpo está vacío."); return; }
    if (!confirm(
      `Se enviarán ${enviables.length} correo(s) Chile desde la cuenta configurada en n8n.\n\n` +
      `${totalConErrores > 0 ? `Hay ${totalConErrores} fila(s) con errores que NO se enviarán.\n\n` : ""}` +
      `¿Confirmás el envío?`
    )) return;

    setEnviando(true);
    setLogFinal(null);
    setProgreso({ actual: 0, total: enviables.length });

    let okCount = 0, errCount = 0;
    const inicio = Date.now();
    const logsParaSupabase = [];

    for (let i = 0; i < enviables.length; i++) {
      const f = enviables[i];
      setProgreso({ actual: i + 1, total: enviables.length });
      setFilas(prev => prev.map(x => x.idx === f.idx
        ? { ...x, estadoEnvio: "enviando", motivoEnvio: "", tsEnvio: null }
        : x));

      let resultado = { ok: false, motivo: "", messageId: "" };
      try {
        const pdfBase64 = await pf_fileToBase64(f.file);
        const payload = {
          idEnvio: `${Date.now()}-${f.idx}`,
          transportista: f.parsed.transportista,
          rut: f.parsed.rut,
          operacion: f.parsed.operacion,
          cliente: f.parsed.cliente,
          centroCosto: f.parsed.centroCosto,
          periodo: f.parsed.periodo,
          mesFactura: f.parsed.mesFactura,
          valorUf: f.parsed.valorUf,
          correoTo: pf_limpiarLista(f.editTo).limpia,
          cc: pf_limpiarLista(f.editCc).limpia,
          bcc: pf_limpiarLista(f.editBcc).limpia,
          asunto: f.asuntoFinal || `PREFACTURA ${f.parsed.operacion} — ${f.parsed.mesFactura}`,
          cuerpo: f.cuerpoFinal || "",
          nombrePdf: f.nombre,
          pdfBase64,
        };
        const resp = await fetch(PREFACTURAS_CL_WEBHOOK, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(payload),
        });
        let data = {};
        try { data = await resp.json(); } catch { /* no-json */ }
        if (resp.ok && data.ok !== false) {
          resultado = { ok: true, motivo: data.messageId || "Enviado", messageId: data.messageId || "" };
          okCount++;
        } else {
          resultado = { ok: false, motivo: data.error || `HTTP ${resp.status}`, messageId: "" };
          errCount++;
        }
      } catch (e) {
        resultado = { ok: false, motivo: "Error red: " + e.message, messageId: "" };
        errCount++;
      }

      const tsAhora = new Date().toISOString();
      setFilas(prev => prev.map(x => x.idx === f.idx
        ? { ...x, estadoEnvio: resultado.ok ? "ok" : "fallido", motivoEnvio: resultado.motivo, tsEnvio: tsAhora }
        : x));

      logsParaSupabase.push({
        fecha_envio: tsAhora,
        transportista: f.parsed.transportista,
        ceco: f.parsed.operacion,  // En Chile, "operacion" es el equivalente al CECO
        periodo: f.parsed.periodo,
        correo_to: pf_limpiarLista(f.editTo).limpia,
        nombre_pdf: f.nombre,
        estado: resultado.ok ? "enviado" : "fallido",
        motivo: resultado.motivo,
        message_id: resultado.messageId,
        usuario: usuario?.email || "—",
        pais: "CL",
      });

      if (i < enviables.length - 1) {
        await new Promise(r => setTimeout(r, PAUSA_ENTRE_ENVIOS_MS));
      }
    }

    try {
      if (logsParaSupabase.length > 0) {
        await sb.from("prefacturas_envios_log").insert(logsParaSupabase);
      }
    } catch (e) {
      console.error("Error guardando log:", e);
    }

    const segs = Math.round((Date.now() - inicio) / 1000);
    setLogFinal({ ok: okCount, err: errCount, omitidos: totalConErrores, segs, fecha: new Date() });
    setEnviando(false);
    setProgreso({ actual: 0, total: 0 });
  };

  const descargarLog = async () => {
    const detalle = [
      ["#", "Archivo PDF", "Transportista", "RUT", "Operación", "Período", "Mes Factura",
       "Correo TO", "CC", "BCC", "Asunto",
       "Estado envío", "Motivo / MessageID", "Timestamp"],
      ...filasConEstado.map((f, i) => [
        i + 1, f.nombre,
        f.parsed.transportista, f.parsed.rut, f.parsed.operacion, f.parsed.periodo, f.parsed.mesFactura,
        f.editTo, f.editCc, f.editBcc, f.asuntoFinal,
        f.estadoEnvio === "ok" ? "ENVIADO" :
          f.estadoEnvio === "fallido" ? "FALLIDO" :
          f.errores.length > 0 ? "OMITIDO: " + f.errores.join(", ") : "PENDIENTE",
        f.motivoEnvio || "",
        f.tsEnvio ? new Date(f.tsEnvio).toLocaleString("es-CL") : "",
      ]),
    ];
    const resumen = [
      ["Reporte de envío de prefacturas Chile"],
      ["Fecha", new Date().toLocaleString("es-CL")],
      ["Usuario", usuario?.nombre || usuario?.email || "—"],
      ["PDFs cargados", filas.length],
      ["Enviados OK", filasConEstado.filter(f => f.estadoEnvio === "ok").length],
      ["Fallidos", filasConEstado.filter(f => f.estadoEnvio === "fallido").length],
      ["Pendientes/Omitidos", filasConEstado.filter(f => !f.estadoEnvio).length],
      [""],
      ["Asunto utilizado"],
      [asuntoLote],
      [""],
      ["Cuerpo utilizado"],
      [cuerpoLote],
    ];
    await descargarExcelMultihoja(
      [{ nombre: "Resumen", datos: resumen }, { nombre: "Detalle", datos: detalle }],
      "log_prefacturas_envio_cl"
    );
  };

  return (
    <div className="pg" style={{ maxWidth: 1400 }}>
      <div style={{ marginBottom: 16 }}>
        <div className="sec-title">Prefacturas Chile · Envío Masivo</div>
        <div className="sec-sub">
          Arrastrá los PDFs generados por la macro Chile. Ajustá el asunto y cuerpo del lote.
          El Brain lee cada PDF, cruza con la base Chile, y envía masivamente.
        </div>
      </div>

      {error && (
        <div style={{
          background: "#fee2e2", border: "1px solid #fca5a5", color: "#991b1b",
          padding: "10px 14px", borderRadius: 8, marginBottom: 14, fontSize: 13,
        }}>⚠ {error}</div>
      )}

      {/* Drag-and-drop */}
      <div
        onDragOver={e => { e.preventDefault(); e.stopPropagation(); setArrastrando(true); }}
        onDragLeave={e => { e.preventDefault(); e.stopPropagation(); setArrastrando(false); }}
        onDrop={e => {
          e.preventDefault(); e.stopPropagation();
          setArrastrando(false);
          onPdfsDrop(e.dataTransfer.files);
        }}
        onClick={() => pdfInputRef.current?.click()}
        style={{
          border: `3px dashed ${arrastrando ? "#F47B20" : "#1a3a6b"}`,
          borderRadius: 16,
          padding: "40px 24px",
          textAlign: "center",
          cursor: "pointer",
          background: arrastrando ? "#fff7ed" : "#f8fafc",
          transition: "all 0.2s",
          marginBottom: 16,
        }}
      >
        <div style={{ fontSize: 48, marginBottom: 10 }}>📄</div>
        <div style={{ fontSize: 17, color: "#1a3a6b", fontWeight: 700, marginBottom: 6 }}>
          {pdfsEnProceso > 0
            ? `Procesando PDFs... (${pdfsEnProceso} pendientes)`
            : arrastrando
              ? "Soltá los PDFs aquí"
              : "Arrastrá los PDFs de prefacturas Chile"}
        </div>
        <div style={{ fontSize: 13, color: "#64748b" }}>
          {pdfsEnProceso > 0
            ? "El Brain está leyendo cada PDF para extraer los datos."
            : "o hacé clic para seleccionarlos · sin límite de cantidad"}
        </div>
        {filas.length > 0 && pdfsEnProceso === 0 && (
          <div style={{
            marginTop: 16, padding: "8px 14px", background: "#fff",
            border: "1px solid #1a3a6b", borderRadius: 10,
            display: "inline-flex", alignItems: "center", gap: 12,
          }}>
            <span style={{ fontSize: 13, color: "#1a3a6b", fontWeight: 700 }}>
              ✓ {filas.length} PDF{filas.length === 1 ? "" : "s"} cargado{filas.length === 1 ? "" : "s"}
            </span>
            <button onClick={e => { e.stopPropagation(); limpiarTodo(); }}
              style={{
                background: "#fee2e2", border: "none", borderRadius: 6,
                padding: "4px 10px", fontSize: 11, color: "#991b1b",
                cursor: "pointer", fontWeight: 600, fontFamily: "Geist, sans-serif",
              }}>Quitar todos</button>
          </div>
        )}
        <input
          ref={pdfInputRef} type="file" accept=".pdf" multiple
          style={{ display: "none" }}
          onChange={e => { onPdfsDrop(e.target.files); e.target.value = ""; }}
        />
      </div>

      {/* Editor de asunto y cuerpo del lote */}
      <div className="form-card">
        <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 12, flexWrap: "wrap" }}>
          <div className="form-title" style={{ margin: 0 }}>
            ✉️ Asunto y cuerpo del correo
          </div>
          <span style={{ fontSize: 11, color: "#94a3b8", marginLeft: "auto" }}>
            Se aplica a TODOS los envíos del lote
          </span>
          <button onClick={restaurarPlantillaDefault}
            style={{
              background: "transparent", border: "1px solid #e4e7ec", borderRadius: 6,
              padding: "4px 10px", fontSize: 11, color: "#64748b", cursor: "pointer",
              fontWeight: 600, fontFamily: "Geist, sans-serif",
            }}>↺ Restaurar default</button>
        </div>

        <div className="field-row">
          <div className="field-label">Asunto</div>
          <input
            value={asuntoLote}
            onChange={e => setAsuntoLote(e.target.value)}
            placeholder="PREFACTURA {OPERACION}//{MES_FACTURA}//{TRANSPORTISTA}"
            style={{ fontSize: 13 }}
          />
        </div>

        <div className="field-row">
          <div className="field-label">Cuerpo del correo</div>
          <textarea
            value={cuerpoLote}
            onChange={e => setCuerpoLote(e.target.value)}
            placeholder="Estimado/a, ..."
            style={{ height: 320, fontSize: 12, fontFamily: "monospace", lineHeight: 1.6, resize: "vertical" }}
          />
        </div>

        <div style={{ display: "flex", flexWrap: "wrap", gap: 6, alignItems: "center", marginTop: 8 }}>
          <span style={{ fontSize: 11, color: "#64748b", fontWeight: 600 }}>Variables disponibles:</span>
          {VARIABLES_PLANTILLA_CL.map(v => (
            <code key={v} style={{
              background: "#eef2ff", color: "#1a3a6b", padding: "2px 8px",
              borderRadius: 4, fontSize: 11, fontFamily: "monospace",
            }}>{"{" + v + "}"}</code>
          ))}
        </div>

        <div style={{
          marginTop: 12, padding: "10px 12px", background: "#eef2ff", borderRadius: 8,
          fontSize: 11, color: "#1a3a6b",
        }}>
          💡 Las variables se reemplazan automáticamente con los datos extraídos de cada PDF.
          Tus cambios se guardan automáticamente en este navegador para la próxima vez.
        </div>
      </div>

      {filas.length > 0 && (
        <div style={{
          display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(180px, 1fr))",
          gap: 10, marginBottom: 14,
        }}>
          <IndicadorPF label="PDFs procesados" valor={filas.length} color="#1a3a6b" />
          <IndicadorPF label="Listas para enviar" valor={totalListos} color="#16a34a" />
          <IndicadorPF label="Con errores" valor={totalConErrores} color="#dc2626" />
        </div>
      )}

      {filas.length > 0 && (
        <div className="form-card" style={{ padding: 0, overflow: "hidden" }}>
          <div style={{
            padding: "12px 16px", borderBottom: "1px solid #e4e7ec",
            display: "flex", justifyContent: "space-between", alignItems: "center",
            flexWrap: "wrap", gap: 8,
          }}>
            <div className="form-title" style={{ margin: 0 }}>Revisión y envío</div>
            <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
              {(logFinal || filasConEstado.some(f => f.estadoEnvio)) && (
                <BotonDescargarExcel onClick={descargarLog} label="Descargar log Excel" />
              )}
              <button
                onClick={enviarMasivo}
                disabled={enviando || totalListos === 0}
                className="btn-orange"
                style={{ padding: "9px 18px", fontSize: 13 }}>
                {enviando
                  ? `Enviando ${progreso.actual}/${progreso.total}...`
                  : `📨 Enviar ${totalListos} correo${totalListos === 1 ? "" : "s"}`
                }
              </button>
            </div>
          </div>

          {enviando && (
            <div style={{ padding: "10px 16px", borderBottom: "1px solid #e4e7ec", background: "#fffbeb" }}>
              <div style={{ fontSize: 12, color: "#92400e", marginBottom: 6, fontWeight: 600 }}>
                Enviando {progreso.actual} de {progreso.total}...
              </div>
              <div style={{ height: 8, background: "#fef3c7", borderRadius: 4, overflow: "hidden" }}>
                <div style={{
                  width: `${(progreso.actual / progreso.total) * 100}%`,
                  height: "100%", background: "#F47B20", transition: "width 0.3s",
                }} />
              </div>
            </div>
          )}

          {logFinal && !enviando && (
            <div style={{
              padding: "10px 16px", borderBottom: "1px solid #e4e7ec",
              background: logFinal.err === 0 ? "#f0fdf4" : "#fffbeb",
            }}>
              <div style={{
                fontSize: 13, fontWeight: 600,
                color: logFinal.err === 0 ? "#166534" : "#92400e",
              }}>
                {logFinal.err === 0 ? "✓" : "⚠"} Envío finalizado en {logFinal.segs}s ·{" "}
                {logFinal.ok} enviado{logFinal.ok === 1 ? "" : "s"} ·{" "}
                {logFinal.err} fallido{logFinal.err === 1 ? "" : "s"}
                {logFinal.omitidos > 0 && ` · ${logFinal.omitidos} omitido${logFinal.omitidos === 1 ? "" : "s"}`}
              </div>
            </div>
          )}

          <div style={{ overflowX: "auto" }}>
            <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
              <thead>
                <tr style={{ background: "#f8fafc", borderBottom: "1px solid #e4e7ec" }}>
                  <th style={pf_th()}>Estado</th>
                  <th style={pf_th()}>Transportista</th>
                  <th style={pf_th()}>Operación</th>
                  <th style={pf_th()}>Período / Mes</th>
                  <th style={pf_th()}>Correo TO</th>
                  <th style={pf_th()}>CC</th>
                  <th style={pf_th()}>Acción</th>
                </tr>
              </thead>
              <tbody>
                {filasConEstado.map((f) => (
                  <FilaPrefacturaCL
                    key={f.idx}
                    fila={f}
                    enEdicion={editFila === f.idx}
                    onEdit={() => setEditFila(f.idx)}
                    onGuardar={(campos) => guardarEdicion(f.idx, campos)}
                    onCancelar={() => setEditFila(null)}
                    onEliminar={() => eliminarFila(f.idx)}
                    onAgregarTransportista={() => setModalAgregar({
                      tipo: "trans",
                      prefill: { nombre: f.parsed.transportista, rut: f.parsed.rut },
                    })}
                    onAgregarOperacion={() => setModalAgregar({
                      tipo: "op",
                      prefill: { operacion: f.parsed.operacion, cliente: f.parsed.cliente,
                                 centro_costo: f.parsed.centroCosto, supervisor: f.parsed.supervisorPDF },
                    })}
                    enviando={enviando}
                  />
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {modalAgregar?.tipo === "trans" && (
        <ModalEdicionTransportistaCL
          inicial={{
            nombre: modalAgregar.prefill.nombre || "",
            rut: modalAgregar.prefill.rut || "",
            estado: "Activo",
            correo: "", contacto: "", telefono: "", notas: "",
          }}
          esNuevo={true}
          onCancelar={() => setModalAgregar(null)}
          onGuardarOK={onAgregarYRefrescar}
        />
      )}
      {modalAgregar?.tipo === "op" && (
        <ModalEdicionParametroCL
          inicial={{
            operacion: modalAgregar.prefill.operacion || "",
            cliente: modalAgregar.prefill.cliente || "",
            centro_costo: modalAgregar.prefill.centro_costo || "",
            supervisor: modalAgregar.prefill.supervisor || "",
            correo_supervisor: "",
            lideres: "",
            region: "",
            cuenta_envio: "prefacturas@bigticket.cl",
          }}
          esNuevo={true}
          onCancelar={() => setModalAgregar(null)}
          onGuardarOK={onAgregarYRefrescar}
        />
      )}
    </div>
  );
}

// ─── Fila individual Chile ──────────────────────────────────────────────────────
function FilaPrefacturaCL({ fila, enEdicion, onEdit, onGuardar, onCancelar, onEliminar,
                            onAgregarTransportista, onAgregarOperacion, enviando }) {
  const [to, setTo] = useState(fila.editTo);
  const [cc, setCc] = useState(fila.editCc);
  const [bcc, setBcc] = useState(fila.editBcc);
  const [asunto, setAsunto] = useState(fila.asuntoFinal);
  const [cuerpo, setCuerpo] = useState(fila.cuerpoFinal);

  useEffect(() => {
    if (enEdicion) {
      setTo(fila.editTo); setCc(fila.editCc); setBcc(fila.editBcc);
      setAsunto(fila.asuntoFinal); setCuerpo(fila.cuerpoFinal);
    }
  }, [enEdicion, fila.editTo, fila.editCc, fila.editBcc, fila.asuntoFinal, fila.cuerpoFinal]);

  let bgFila = "transparent";
  if (fila.estadoEnvio === "ok") bgFila = "#f0fdf4";
  else if (fila.estadoEnvio === "fallido") bgFila = "#fef2f2";
  else if (fila.estadoEnvio === "enviando") bgFila = "#fffbeb";
  else if (!fila.listo) bgFila = "#fef2f2";

  if (enEdicion) {
    return (
      <tr style={{ background: "#eff6ff" }}>
        <td colSpan={7} style={{ padding: 14, borderBottom: "2px solid #1a3a6b" }}>
          <div style={{ fontSize: 12, fontWeight: 700, color: "#1a3a6b", marginBottom: 10 }}>
            ✏️ Editando: {fila.parsed.transportista || fila.nombre} · {fila.parsed.operacion || "—"} · {fila.parsed.mesFactura || "—"}
          </div>
          <div className="two-col" style={{ marginBottom: 10 }}>
            <div>
              <div className="field-label">Correo TO *</div>
              <input value={to} onChange={e => setTo(e.target.value)}
                placeholder="correo@dominio.com (separá varios con ;)" />
            </div>
            <div>
              <div className="field-label">CC (supervisor + líderes)</div>
              <input value={cc} onChange={e => setCc(e.target.value)} placeholder="opcional" />
            </div>
          </div>
          <div className="field-row">
            <div className="field-label">BCC</div>
            <input value={bcc} onChange={e => setBcc(e.target.value)} placeholder="opcional" />
          </div>
          <div className="field-row">
            <div className="field-label">Asunto (override solo para esta fila)</div>
            <input value={asunto} onChange={e => setAsunto(e.target.value)} />
          </div>
          <div className="field-row">
            <div className="field-label">Cuerpo (override solo para esta fila · variables ya reemplazadas)</div>
            <textarea value={cuerpo} onChange={e => setCuerpo(e.target.value)} style={{ height: 200 }} />
          </div>
          <div style={{ fontSize: 11, color: "#64748b", marginBottom: 10 }}>
            💡 Estos cambios solo aplican a este envío puntual.
          </div>
          <div style={{ display: "flex", gap: 8, justifyContent: "flex-end" }}>
            <button onClick={onCancelar}
              style={{
                background: "#fff", border: "1px solid #e4e7ec", borderRadius: 8,
                padding: "7px 14px", fontSize: 12, color: "#475569", cursor: "pointer",
                fontFamily: "Geist, sans-serif", fontWeight: 600,
              }}>Cancelar</button>
            <button onClick={() => onGuardar({
              editTo: to, editCc: cc, editBcc: bcc,
              overrideAsunto: asunto, overrideCuerpo: cuerpo,
            })} className="btn-blue" style={{ padding: "7px 14px", fontSize: 12 }}>
              Guardar cambios
            </button>
          </div>
        </td>
      </tr>
    );
  }

  const transNoReg = fila.parsed.transportista && !fila.trans;
  const opNoReg = fila.parsed.operacion && !fila.param;
  const transBloqueado = fila.trans && String(fila.trans.estado || "").toLowerCase() === "bloqueado";

  return (
    <tr style={{ background: bgFila }}>
      <td style={pf_td()}><EstadoBadgeCL fila={fila} /></td>
      <td style={pf_td()}>
        <div style={{ fontWeight: 600 }}>
          {fila.parsed.transportista || <em style={{ color: "#dc2626" }}>(no detectado)</em>}
        </div>
        <div style={{ fontSize: 10, color: "#94a3b8" }}>{fila.parsed.rut || "sin RUT"}</div>
        <div style={{ fontSize: 9, color: "#94a3b8", marginTop: 2 }}>📄 {fila.nombre.length > 35 ? fila.nombre.slice(0, 32) + "..." : fila.nombre}</div>
        {transNoReg && (
          <button onClick={onAgregarTransportista}
            style={{
              marginTop: 4, background: "#fef2f2", border: "1px solid #fca5a5",
              borderRadius: 6, padding: "2px 8px", fontSize: 10, color: "#991b1b",
              cursor: "pointer", fontWeight: 600, fontFamily: "Geist, sans-serif",
            }}>+ Agregar a Supabase</button>
        )}
        {transBloqueado && (
          <div style={{ marginTop: 4, fontSize: 10, color: "#991b1b", fontWeight: 700 }}>
            ⛔ BLOQUEADO en Supabase
          </div>
        )}
      </td>
      <td style={pf_td()}>
        {fila.parsed.operacion ? (
          <>
            <span style={{
              background: fila.param ? "#eef2ff" : "#fef2f2",
              color: fila.param ? "#1a3a6b" : "#991b1b",
              padding: "2px 8px", borderRadius: 4, fontSize: 11, fontWeight: 600,
            }}>{fila.parsed.operacion}</span>
            {opNoReg && (
              <button onClick={onAgregarOperacion}
                style={{
                  display: "block", marginTop: 4,
                  background: "#fef2f2", border: "1px solid #fca5a5",
                  borderRadius: 6, padding: "2px 8px", fontSize: 10, color: "#991b1b",
                  cursor: "pointer", fontWeight: 600, fontFamily: "Geist, sans-serif",
                }}>+ Agregar Operación</button>
            )}
          </>
        ) : <em style={{ color: "#dc2626", fontSize: 11 }}>(no detectado)</em>}
      </td>
      <td style={pf_td()}>
        <span style={{ fontSize: 11, color: "#475569" }}>{fila.parsed.periodo || "—"}</span>
        <div style={{ fontSize: 10, color: "#94a3b8" }}>{fila.parsed.mesFactura || ""}</div>
      </td>
      <td style={pf_td()}>
        <div style={{ wordBreak: "break-all", maxWidth: 220 }}>
          {fila.editTo || <em style={{ color: "#dc2626" }}>vacío</em>}
        </div>
        {fila.trans && (
          <div style={{ fontSize: 9, color: "#16a34a", marginTop: 2 }}>✓ desde Supabase</div>
        )}
      </td>
      <td style={pf_td()}>
        <div style={{ wordBreak: "break-all", maxWidth: 200, fontSize: 11, color: "#64748b" }}>
          {fila.editCc || "—"}
        </div>
      </td>
      <td style={pf_td()}>
        <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
          <button onClick={onEdit}
            disabled={enviando || fila.estadoEnvio === "ok"}
            style={{
              background: "transparent", border: "1px solid #e4e7ec", borderRadius: 6,
              padding: "3px 8px", fontSize: 11, color: "#1a3a6b", cursor: "pointer",
              fontFamily: "Geist, sans-serif", fontWeight: 600,
              opacity: (enviando || fila.estadoEnvio === "ok") ? 0.4 : 1,
            }}>Editar</button>
          <button onClick={onEliminar} disabled={enviando}
            style={{
              background: "transparent", border: "1px solid #fca5a5", borderRadius: 6,
              padding: "3px 8px", fontSize: 11, color: "#991b1b", cursor: "pointer",
              fontFamily: "Geist, sans-serif", fontWeight: 600,
              opacity: enviando ? 0.4 : 1,
            }}>Quitar</button>
        </div>
      </td>
    </tr>
  );
}

function EstadoBadgeCL({ fila }) {
  if (fila.estadoEnvio === "ok") {
    return (
      <span style={{
        background: "#dcfce7", color: "#166534", padding: "3px 8px",
        borderRadius: 20, fontSize: 10, fontWeight: 700,
      }}>✓ ENVIADO</span>
    );
  }
  if (fila.estadoEnvio === "fallido") {
    return (
      <div title={fila.motivoEnvio}>
        <span style={{
          background: "#fee2e2", color: "#991b1b", padding: "3px 8px",
          borderRadius: 20, fontSize: 10, fontWeight: 700,
        }}>✗ FALLIDO</span>
        <div style={{ fontSize: 9, color: "#991b1b", marginTop: 2, maxWidth: 160 }}>
          {fila.motivoEnvio?.slice(0, 60)}{fila.motivoEnvio?.length > 60 ? "..." : ""}
        </div>
      </div>
    );
  }
  if (fila.estadoEnvio === "enviando") {
    return (
      <span style={{
        background: "#fef3c7", color: "#92400e", padding: "3px 8px",
        borderRadius: 20, fontSize: 10, fontWeight: 700,
      }}>⏳ ENVIANDO</span>
    );
  }
  if (!fila.listo) {
    return (
      <div title={fila.errores.join(" · ")}>
        <span style={{
          background: "#fee2e2", color: "#991b1b", padding: "3px 8px",
          borderRadius: 20, fontSize: 10, fontWeight: 700,
        }}>⚠ {fila.errores[0]}</span>
        {fila.errores.length > 1 && (
          <div style={{ fontSize: 9, color: "#991b1b", marginTop: 2 }}>
            +{fila.errores.length - 1} error{fila.errores.length === 2 ? "" : "es"} más
          </div>
        )}
      </div>
    );
  }
  return (
    <span style={{
      background: "#dbeafe", color: "#1e40af", padding: "3px 8px",
      borderRadius: 20, fontSize: 10, fontWeight: 700,
    }}>LISTO</span>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════════════
// SUB-TAB 2 CHILE: TRANSPORTISTAS (CRUD)
// ═══════════════════════════════════════════════════════════════════════════════════════
function PrefCLTransportistas({ data, onChange }) {
  const [busqueda, setBusqueda] = useState("");
  const [filtroEstado, setFiltroEstado] = useState("todos");
  const [editando, setEditando] = useState(null);
  const [mostrarImportador, setMostrarImportador] = useState(false);

  const filtrados = useMemo(() => {
    let r = [...data];
    if (filtroEstado !== "todos") r = r.filter(t => (t.estado || "").toLowerCase() === filtroEstado);
    if (busqueda.trim()) {
      const q = busqueda.toLowerCase();
      r = r.filter(t =>
        (t.nombre || "").toLowerCase().includes(q) ||
        (t.rut || "").toLowerCase().includes(q) ||
        (t.correo || "").toLowerCase().includes(q) ||
        (t.contacto || "").toLowerCase().includes(q)
      );
    }
    return r;
  }, [data, busqueda, filtroEstado]);

  const handleEliminar = async (id, nombre) => {
    if (!confirm(`¿Eliminar al transportista "${nombre}"?\n\nEsta acción no se puede deshacer.`)) return;
    try {
      const { error } = await sb.from("prefacturas_transportistas_cl").delete().eq("id", id);
      if (error) throw error;
      await onChange();
    } catch (e) {
      alert("Error eliminando: " + e.message);
    }
  };

  const filaEdicion = editando === "nuevo"
    ? { nombre: "", rut: "", estado: "Activo", correo: "", contacto: "", telefono: "", notas: "" }
    : (editando ? data.find(t => t.id === editando) : null);

  return (
    <div className="pg" style={{ maxWidth: 1300 }}>
      <div style={{ marginBottom: 16, display: "flex", justifyContent: "space-between", alignItems: "flex-end", flexWrap: "wrap", gap: 10 }}>
        <div>
          <div className="sec-title">Transportistas Chile</div>
          <div className="sec-sub">Nombre, RUT, correo, contacto, teléfono y estado. Estado "Bloqueado" impide envío.</div>
        </div>
        <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
          <BotonDescargarExcel
            onClick={async () => {
              const cabeceras = ["Nombre", "RUT", "Estado", "Correo", "Contacto", "Teléfono", "Notas"];
              const filas = filtrados.map(t => [
                t.nombre || "",
                t.rut || "",
                t.estado || "",
                t.correo || "",
                t.contacto || "",
                t.telefono || "",
                t.notas || "",
              ]);
              await descargarExcelMultihoja(
                [{ nombre: "Transportistas CL", datos: [cabeceras, ...filas] }],
                "transportistas_cl"
              );
            }}
            label="Descargar Excel"
          />
          <button onClick={() => setMostrarImportador(true)}
            style={{
              background: "#fff", border: "1px solid #1a3a6b", borderRadius: 8,
              padding: "9px 16px", fontSize: 13, color: "#1a3a6b", cursor: "pointer",
              fontFamily: "Geist, sans-serif", fontWeight: 600,
            }}>
            📤 Importar Excel
          </button>
          <button className="btn-orange" onClick={() => setEditando("nuevo")} style={{ padding: "9px 16px", fontSize: 13 }}>
            + Nuevo transportista
          </button>
        </div>
      </div>

      <div className="form-card" style={{ padding: "12px 16px" }}>
        <div style={{ display: "flex", gap: 10, alignItems: "center", flexWrap: "wrap" }}>
          <input
            placeholder="Buscar por nombre, RUT, correo o contacto..."
            value={busqueda} onChange={e => setBusqueda(e.target.value)}
            style={{ flex: "1 1 280px", maxWidth: 400 }}
          />
          <select value={filtroEstado} onChange={e => setFiltroEstado(e.target.value)} style={{ width: 160 }}>
            <option value="todos">Todos los estados</option>
            <option value="activo">Activo</option>
            <option value="bloqueado">Bloqueado</option>
          </select>
          <div style={{ fontSize: 12, color: "#64748b", marginLeft: "auto" }}>
            {filtrados.length} de {data.length} transportistas
          </div>
        </div>
      </div>

      <div className="form-card" style={{ padding: 0, overflow: "hidden" }}>
        <div style={{ overflowX: "auto" }}>
          <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
            <thead>
              <tr style={{ background: "#f8fafc", borderBottom: "1px solid #e4e7ec" }}>
                <th style={pf_th()}>Nombre</th>
                <th style={pf_th()}>RUT</th>
                <th style={pf_th()}>Estado</th>
                <th style={pf_th()}>Correo</th>
                <th style={pf_th()}>Contacto</th>
                <th style={pf_th()}>Teléfono</th>
                <th style={pf_th()}>Acciones</th>
              </tr>
            </thead>
            <tbody>
              {filtrados.length === 0 ? (
                <tr><td colSpan={7} style={{ padding: 30, textAlign: "center", color: "#94a3b8" }}>
                  Sin resultados.
                </td></tr>
              ) : filtrados.map(t => (
                <tr key={t.id}>
                  <td style={pf_td()}>
                    <div style={{ fontWeight: 600 }}>{t.nombre}</div>
                    {t.notas && <div style={{ fontSize: 10, color: "#94a3b8" }}>{t.notas}</div>}
                  </td>
                  <td style={pf_td()}>
                    <code style={{ fontSize: 11, color: "#64748b" }}>{t.rut || "—"}</code>
                  </td>
                  <td style={pf_td()}>
                    <span style={{
                      background: (t.estado || "").toLowerCase() === "activo" ? "#dcfce7" : "#fee2e2",
                      color: (t.estado || "").toLowerCase() === "activo" ? "#166534" : "#991b1b",
                      padding: "2px 8px", borderRadius: 20, fontSize: 10, fontWeight: 700,
                    }}>{t.estado || "—"}</span>
                  </td>
                  <td style={pf_td()}>
                    <div style={{ wordBreak: "break-all", maxWidth: 220, fontSize: 11 }}>
                      {t.correo || <em style={{ color: "#dc2626" }}>vacío</em>}
                    </div>
                  </td>
                  <td style={pf_td()}>
                    <span style={{ fontSize: 11, color: "#64748b" }}>{t.contacto || "—"}</span>
                  </td>
                  <td style={pf_td()}>
                    <span style={{ fontSize: 11, color: "#64748b" }}>{t.telefono || "—"}</span>
                  </td>
                  <td style={pf_td()}>
                    <div style={{ display: "flex", gap: 6 }}>
                      <button onClick={() => setEditando(t.id)}
                        style={{
                          background: "transparent", border: "1px solid #e4e7ec", borderRadius: 6,
                          padding: "3px 8px", fontSize: 11, color: "#1a3a6b", cursor: "pointer",
                          fontWeight: 600, fontFamily: "Geist, sans-serif",
                        }}>Editar</button>
                      <button onClick={() => handleEliminar(t.id, t.nombre)}
                        style={{
                          background: "transparent", border: "1px solid #fca5a5", borderRadius: 6,
                          padding: "3px 8px", fontSize: 11, color: "#991b1b", cursor: "pointer",
                          fontWeight: 600, fontFamily: "Geist, sans-serif",
                        }}>Eliminar</button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {filaEdicion && (
        <ModalEdicionTransportistaCL
          inicial={filaEdicion}
          esNuevo={editando === "nuevo"}
          editandoId={editando !== "nuevo" ? editando : null}
          onCancelar={() => setEditando(null)}
          onGuardarOK={async () => { setEditando(null); await onChange(); }}
        />
      )}

      {mostrarImportador && (
        <ModalImportadorTransportistas
          config={CONFIG_IMPORTADOR_CL}
          dataExistente={data}
          onCancelar={() => setMostrarImportador(false)}
          onImportadoOK={async () => { await onChange(); }}
        />
      )}
    </div>
  );
}

function ModalEdicionTransportistaCL({ inicial, esNuevo, editandoId, onCancelar, onGuardarOK }) {
  const [form, setForm] = useState(inicial);
  const [guardando, setGuardando] = useState(false);

  const handleGuardar = async () => {
    if (!form.nombre.trim()) { alert("El nombre es obligatorio."); return; }
    setGuardando(true);
    try {
      const payload = {
        nombre: form.nombre.trim(),
        rut: (form.rut || "").trim() || null,
        estado: form.estado || "Activo",
        correo: (form.correo || "").trim() || null,
        contacto: (form.contacto || "").trim() || null,
        telefono: (form.telefono || "").trim() || null,
        notas: (form.notas || "").trim() || null,
        updated_at: new Date().toISOString(),
      };
      if (esNuevo) {
        const { error } = await sb.from("prefacturas_transportistas_cl").insert(payload);
        if (error) throw error;
      } else {
        const { error } = await sb.from("prefacturas_transportistas_cl").update(payload).eq("id", editandoId);
        if (error) throw error;
      }
      await onGuardarOK();
    } catch (e) {
      alert("Error guardando: " + e.message);
    }
    setGuardando(false);
  };

  return (
    <div style={{
      position: "fixed", inset: 0, background: "rgba(0,0,0,0.5)",
      display: "flex", alignItems: "center", justifyContent: "center", zIndex: 1000, padding: 20,
    }} onClick={onCancelar}>
      <div onClick={e => e.stopPropagation()} style={{
        background: "#fff", borderRadius: 14, padding: 24, maxWidth: 600, width: "100%",
        maxHeight: "90vh", overflowY: "auto",
      }}>
        <div style={{ fontSize: 16, fontWeight: 700, color: "#1a3a6b", marginBottom: 16 }}>
          {esNuevo ? "Nuevo transportista Chile" : "Editar transportista"}
        </div>
        <div className="field-row">
          <div className="field-label">Nombre *</div>
          <input value={form.nombre} onChange={e => setForm({ ...form, nombre: e.target.value })}
            placeholder="Ej: ISISLINE SPA" />
        </div>
        <div className="two-col">
          <div className="field-row">
            <div className="field-label">RUT</div>
            <input value={form.rut || ""} onChange={e => setForm({ ...form, rut: e.target.value })}
              placeholder="77395507-7" />
          </div>
          <div className="field-row">
            <div className="field-label">Estado</div>
            <select value={form.estado || "Activo"} onChange={e => setForm({ ...form, estado: e.target.value })}>
              <option value="Activo">Activo</option>
              <option value="Bloqueado">Bloqueado (NO ENVIAR)</option>
            </select>
          </div>
        </div>
        <div className="field-row">
          <div className="field-label">Correo *</div>
          <input value={form.correo || ""} onChange={e => setForm({ ...form, correo: e.target.value })}
            placeholder="correo@dominio.com" />
        </div>
        <div className="two-col">
          <div className="field-row">
            <div className="field-label">Contacto</div>
            <input value={form.contacto || ""} onChange={e => setForm({ ...form, contacto: e.target.value })}
              placeholder="Nombre persona contacto" />
          </div>
          <div className="field-row">
            <div className="field-label">Teléfono</div>
            <input value={form.telefono || ""} onChange={e => setForm({ ...form, telefono: e.target.value })}
              placeholder="940383148" />
          </div>
        </div>
        <div className="field-row">
          <div className="field-label">Notas internas</div>
          <textarea value={form.notas || ""} onChange={e => setForm({ ...form, notas: e.target.value })}
            placeholder="(opcional)" style={{ height: 60 }} />
        </div>
        <div style={{ display: "flex", gap: 8, justifyContent: "flex-end", marginTop: 14 }}>
          <button onClick={onCancelar} disabled={guardando}
            style={{
              background: "#fff", border: "1px solid #e4e7ec", borderRadius: 8,
              padding: "8px 14px", fontSize: 12, color: "#475569", cursor: "pointer",
              fontFamily: "Geist, sans-serif", fontWeight: 600,
            }}>Cancelar</button>
          <button onClick={handleGuardar} disabled={guardando} className="btn-blue"
            style={{ padding: "8px 14px", fontSize: 12 }}>
            {guardando ? "Guardando..." : "Guardar"}
          </button>
        </div>
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════════════
// SUB-TAB 3 CHILE: OPERACIONES / CECOs
// ═══════════════════════════════════════════════════════════════════════════════════════
function PrefCLParametros({ data, onChange }) {
  const [editando, setEditando] = useState(null);
  const [busqueda, setBusqueda] = useState("");

  const filtrados = useMemo(() => {
    if (!busqueda.trim()) return data;
    const q = busqueda.toLowerCase();
    return data.filter(p =>
      (p.operacion || "").toLowerCase().includes(q) ||
      (p.cliente || "").toLowerCase().includes(q) ||
      (p.centro_costo || "").toLowerCase().includes(q) ||
      (p.supervisor || "").toLowerCase().includes(q)
    );
  }, [data, busqueda]);

  const handleEliminar = async (id, op) => {
    if (!confirm(`¿Eliminar la operación "${op}"?`)) return;
    try {
      const { error } = await sb.from("prefacturas_parametros_cl").delete().eq("id", id);
      if (error) throw error;
      await onChange();
    } catch (e) {
      alert("Error eliminando: " + e.message);
    }
  };

  const filaEdicion = editando === "nuevo"
    ? { operacion: "", cliente: "", centro_costo: "", supervisor: "", correo_supervisor: "", lideres: "", region: "", cuenta_envio: "prefacturas@bigticket.cl" }
    : (editando ? data.find(p => p.id === editando) : null);

  return (
    <div className="pg" style={{ maxWidth: 1300 }}>
      <div style={{ marginBottom: 16, display: "flex", justifyContent: "space-between", alignItems: "flex-end", flexWrap: "wrap", gap: 10 }}>
        <div>
          <div className="sec-title">Operaciones / CECOs Chile</div>
          <div className="sec-sub">Cliente + Centro de Costo, supervisor, líderes y región. Supervisor y líderes van todos en CC.</div>
        </div>
        <button className="btn-orange" onClick={() => setEditando("nuevo")} style={{ padding: "9px 16px", fontSize: 13 }}>
          + Nueva operación
        </button>
      </div>

      <div className="form-card" style={{ padding: "12px 16px" }}>
        <input placeholder="Buscar por operación, cliente, CECO o supervisor..."
          value={busqueda} onChange={e => setBusqueda(e.target.value)}
          style={{ width: "100%", maxWidth: 500 }} />
      </div>

      <div className="form-card" style={{ background: "#eff6ff", borderColor: "#bfdbfe" }}>
        <div style={{ fontSize: 12, color: "#1e40af" }}>
          💡 El asunto y cuerpo del correo se editan en la sub-tab <strong>"Envío masivo"</strong> antes de cada lote.
          Aquí solo se guarda la info estática por operación.
        </div>
      </div>

      <div className="form-card" style={{ padding: 0, overflow: "hidden" }}>
        <div style={{ overflowX: "auto" }}>
          <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
            <thead>
              <tr style={{ background: "#f8fafc", borderBottom: "1px solid #e4e7ec" }}>
                <th style={pf_th()}>Operación</th>
                <th style={pf_th()}>Cliente</th>
                <th style={pf_th()}>CECO</th>
                <th style={pf_th()}>Supervisor</th>
                <th style={pf_th()}>Correo supervisor</th>
                <th style={pf_th()}>Líderes</th>
                <th style={pf_th()}>Región</th>
                <th style={pf_th()}>Acciones</th>
              </tr>
            </thead>
            <tbody>
              {filtrados.length === 0 ? (
                <tr><td colSpan={8} style={{ padding: 30, textAlign: "center", color: "#94a3b8" }}>
                  Sin resultados.
                </td></tr>
              ) : filtrados.map(p => (
                <tr key={p.id}>
                  <td style={pf_td()}>
                    <span style={{
                      background: "#eef2ff", color: "#1a3a6b", padding: "3px 10px",
                      borderRadius: 4, fontSize: 11, fontWeight: 700,
                    }}>{p.operacion}</span>
                  </td>
                  <td style={pf_td()}><span style={{ fontSize: 11 }}>{p.cliente || "—"}</span></td>
                  <td style={pf_td()}><span style={{ fontSize: 11 }}>{p.centro_costo || "—"}</span></td>
                  <td style={pf_td()}>{p.supervisor || <em style={{ color: "#94a3b8" }}>—</em>}</td>
                  <td style={pf_td()}>
                    <span style={{ fontSize: 11, color: "#64748b", wordBreak: "break-all" }}>
                      {p.correo_supervisor || "—"}
                    </span>
                  </td>
                  <td style={pf_td()}>
                    <span style={{ fontSize: 10, color: "#64748b", wordBreak: "break-all", maxWidth: 220, display: "block" }}>
                      {p.lideres || "—"}
                    </span>
                  </td>
                  <td style={pf_td()}>
                    <span style={{ fontSize: 11, color: "#64748b" }}>{p.region || "—"}</span>
                  </td>
                  <td style={pf_td()}>
                    <div style={{ display: "flex", gap: 6 }}>
                      <button onClick={() => setEditando(p.id)}
                        style={{
                          background: "transparent", border: "1px solid #e4e7ec", borderRadius: 6,
                          padding: "3px 8px", fontSize: 11, color: "#1a3a6b", cursor: "pointer",
                          fontWeight: 600, fontFamily: "Geist, sans-serif",
                        }}>Editar</button>
                      <button onClick={() => handleEliminar(p.id, p.operacion)}
                        style={{
                          background: "transparent", border: "1px solid #fca5a5", borderRadius: 6,
                          padding: "3px 8px", fontSize: 11, color: "#991b1b", cursor: "pointer",
                          fontWeight: 600, fontFamily: "Geist, sans-serif",
                        }}>Eliminar</button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {filaEdicion && (
        <ModalEdicionParametroCL
          inicial={filaEdicion}
          esNuevo={editando === "nuevo"}
          editandoId={editando !== "nuevo" ? editando : null}
          onCancelar={() => setEditando(null)}
          onGuardarOK={async () => { setEditando(null); await onChange(); }}
        />
      )}
    </div>
  );
}

function ModalEdicionParametroCL({ inicial, esNuevo, editandoId, onCancelar, onGuardarOK }) {
  const [form, setForm] = useState(inicial);
  const [guardando, setGuardando] = useState(false);

  const handleGuardar = async () => {
    if (!form.operacion.trim()) { alert("La operación es obligatoria."); return; }
    setGuardando(true);
    try {
      const payload = {
        operacion: form.operacion.trim().toUpperCase(),
        cliente: (form.cliente || "").trim() || null,
        centro_costo: (form.centro_costo || "").trim() || null,
        supervisor: (form.supervisor || "").trim() || null,
        correo_supervisor: (form.correo_supervisor || "").trim() || null,
        lideres: (form.lideres || "").trim() || null,
        region: (form.region || "").trim() || null,
        cuenta_envio: (form.cuenta_envio || "").trim() || "prefacturas@bigticket.cl",
        updated_at: new Date().toISOString(),
      };
      if (esNuevo) {
        const { error } = await sb.from("prefacturas_parametros_cl").insert(payload);
        if (error) throw error;
      } else {
        const { error } = await sb.from("prefacturas_parametros_cl").update(payload).eq("id", editandoId);
        if (error) throw error;
      }
      await onGuardarOK();
    } catch (e) {
      alert("Error guardando: " + e.message);
    }
    setGuardando(false);
  };

  return (
    <div style={{
      position: "fixed", inset: 0, background: "rgba(0,0,0,0.5)",
      display: "flex", alignItems: "center", justifyContent: "center", zIndex: 1000, padding: 20,
    }} onClick={onCancelar}>
      <div onClick={e => e.stopPropagation()} style={{
        background: "#fff", borderRadius: 14, padding: 24, maxWidth: 700, width: "100%",
        maxHeight: "90vh", overflowY: "auto",
      }}>
        <div style={{ fontSize: 16, fontWeight: 700, color: "#1a3a6b", marginBottom: 16 }}>
          {esNuevo ? "Nueva operación Chile" : "Editar operación"}
        </div>
        <div className="field-row">
          <div className="field-label">Operación *  <span style={{ color: "#94a3b8", fontWeight: 400 }}>(formato: CLIENTE - CECO)</span></div>
          <input value={form.operacion} onChange={e => setForm({ ...form, operacion: e.target.value.toUpperCase() })}
            placeholder="MERCADO LIBRE - RM" disabled={!esNuevo} />
        </div>
        <div className="two-col">
          <div className="field-row">
            <div className="field-label">Cliente</div>
            <input value={form.cliente || ""} onChange={e => setForm({ ...form, cliente: e.target.value })}
              placeholder="MERCADO LIBRE" />
          </div>
          <div className="field-row">
            <div className="field-label">Centro de Costo</div>
            <input value={form.centro_costo || ""} onChange={e => setForm({ ...form, centro_costo: e.target.value })}
              placeholder="RM" />
          </div>
        </div>
        <div className="two-col">
          <div className="field-row">
            <div className="field-label">Supervisor</div>
            <input value={form.supervisor || ""} onChange={e => setForm({ ...form, supervisor: e.target.value })}
              placeholder="MANUEL NEIRA | CONSTANZA SOTO" />
          </div>
          <div className="field-row">
            <div className="field-label">Región</div>
            <input value={form.region || ""} onChange={e => setForm({ ...form, region: e.target.value })}
              placeholder="RM, V, VI, VIII, IV, XV..." />
          </div>
        </div>
        <div className="field-row">
          <div className="field-label">Correo supervisor (irá en CC)</div>
          <input value={form.correo_supervisor || ""} onChange={e => setForm({ ...form, correo_supervisor: e.target.value })}
            placeholder="manuel.neira@bigticket.cl; constanza.soto@bigticket.cl" />
        </div>
        <div className="field-row">
          <div className="field-label">Líderes (también irán en CC · separá con ;)</div>
          <textarea value={form.lideres || ""} onChange={e => setForm({ ...form, lideres: e.target.value })}
            placeholder="randy.becerra@bigticket.cl; leonardo.castro@bigticket.cl"
            style={{ height: 60 }} />
        </div>
        <div className="field-row">
          <div className="field-label">Cuenta envío</div>
          <input value={form.cuenta_envio || ""} onChange={e => setForm({ ...form, cuenta_envio: e.target.value })}
            placeholder="prefacturas@bigticket.cl" />
        </div>
        <div style={{ display: "flex", gap: 8, justifyContent: "flex-end", marginTop: 14 }}>
          <button onClick={onCancelar} disabled={guardando}
            style={{
              background: "#fff", border: "1px solid #e4e7ec", borderRadius: 8,
              padding: "8px 14px", fontSize: 12, color: "#475569", cursor: "pointer",
              fontFamily: "Geist, sans-serif", fontWeight: 600,
            }}>Cancelar</button>
          <button onClick={handleGuardar} disabled={guardando} className="btn-blue"
            style={{ padding: "8px 14px", fontSize: 12 }}>
            {guardando ? "Guardando..." : "Guardar"}
          </button>
        </div>
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════════════
// IMPORTADOR MASIVO DE TRANSPORTISTAS — Modal genérico para MX y CL
// ───────────────────────────────────────────────────────────────────────────────────────
// Recibe configuración del esquema (columnas, tabla, lookup de duplicados) y maneja:
//   1. Descarga de plantilla Excel vacía con encabezados correctos
//   2. Drag-and-drop de Excel con datos
//   3. Preview con 3 estados: nuevos (insertar) / duplicados (saltar) / con errores
//   4. Inserción masiva en Supabase
// ═══════════════════════════════════════════════════════════════════════════════════════

async function pf_cargarXLSX_imp() {
  if (window.XLSX) return window.XLSX;
  await new Promise((res, rej) => {
    const s = document.createElement("script");
    s.src = "https://cdn.sheetjs.com/xlsx-0.20.0/package/dist/xlsx.full.min.js";
    s.onload = res; s.onerror = rej;
    document.head.appendChild(s);
  });
  return window.XLSX;
}

function ModalImportadorTransportistas({ config, dataExistente, onCancelar, onImportadoOK }) {
  // config: {
  //   pais: "MX" | "CL",
  //   tabla: "prefacturas_transportistas_mx" | "prefacturas_transportistas_cl",
  //   columnas: [{key, label, oblig, validador?}],
  //   identificadorUnico: "rfc" | "rut",   // campo que define duplicado (además del nombre)
  //   ejemploFila: { nombre: "...", rfc: "...", ... }
  // }
  const [arrastrando, setArrastrando] = useState(false);
  const [analizando, setAnalizando] = useState(false);
  const [filas, setFilas] = useState([]);  // [{ data, estado: "nuevo"|"duplicado"|"error", errores: [], duplicadoConId? }]
  const [importando, setImportando] = useState(false);
  const [resultado, setResultado] = useState(null);
  const [errorGeneral, setErrorGeneral] = useState("");
  const fileInputRef = useRef(null);

  // ─── Descargar plantilla vacía ─────────────────────────────────────────────
  const descargarPlantilla = async () => {
    try {
      const XLSX = await pf_cargarXLSX_imp();
      const cabeceras = config.columnas.map(c => c.label);
      const ejemplo = config.columnas.map(c => config.ejemploFila[c.key] || "");
      const datos = [cabeceras, ejemplo];

      const ws = XLSX.utils.aoa_to_sheet(datos);
      // Anchos sugeridos
      ws["!cols"] = config.columnas.map(c => ({ wch: Math.max(c.label.length + 4, 18) }));
      const wb = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(wb, ws, "Transportistas");
      XLSX.writeFile(wb, `plantilla_transportistas_${config.pais.toLowerCase()}.xlsx`);
    } catch (e) {
      alert("Error generando plantilla: " + e.message);
    }
  };

  // ─── Procesar Excel cargado ────────────────────────────────────────────────
  const procesarExcel = async (file) => {
    setErrorGeneral("");
    setResultado(null);
    setAnalizando(true);
    try {
      const XLSX = await pf_cargarXLSX_imp();
      const buf = await file.arrayBuffer();
      const wb = XLSX.read(buf, { type: "array" });
      const wsName = wb.SheetNames[0];
      const ws = wb.Sheets[wsName];
      const filas2D = XLSX.utils.sheet_to_json(ws, { header: 1, defval: null });

      if (filas2D.length < 2) {
        setErrorGeneral("El Excel está vacío o solo tiene la cabecera.");
        setFilas([]);
        setAnalizando(false);
        return;
      }

      // Primera fila = headers
      const headers = filas2D[0].map(h => String(h || "").trim().toLowerCase());

      // Mapear cada columna del Excel a una key del esquema
      // Acepta tanto el label como la key como nombre de columna
      const headerToKey = {};
      config.columnas.forEach(c => {
        const labelLower = c.label.toLowerCase();
        const keyLower = c.key.toLowerCase();
        const idx = headers.findIndex(h => h === labelLower || h === keyLower);
        if (idx >= 0) headerToKey[idx] = c.key;
      });

      // Verificar que al menos los campos obligatorios estén presentes
      const obligs = config.columnas.filter(c => c.oblig);
      const obligsFaltantes = obligs.filter(c => !Object.values(headerToKey).includes(c.key));
      if (obligsFaltantes.length > 0) {
        setErrorGeneral(`Faltan columnas obligatorias: ${obligsFaltantes.map(c => c.label).join(", ")}`);
        setFilas([]);
        setAnalizando(false);
        return;
      }

      // Lookup para detectar duplicados (case-insensitive)
      const lookupNombre = new Map();
      const lookupId = new Map();
      dataExistente.forEach(t => {
        if (t.nombre) lookupNombre.set(String(t.nombre).toUpperCase().trim(), t);
        const idVal = t[config.identificadorUnico];
        if (idVal) lookupId.set(String(idVal).toUpperCase().trim(), t);
      });

      // Para detectar duplicados dentro del mismo Excel
      const yaVistosNombre = new Set();
      const yaVistosId = new Set();

      const filasProcesadas = [];
      for (let i = 1; i < filas2D.length; i++) {
        const raw = filas2D[i];
        // Saltar filas totalmente vacías
        if (!raw || raw.every(c => c == null || String(c).trim() === "")) continue;

        // Armar el objeto data según el esquema
        const data = {};
        Object.entries(headerToKey).forEach(([excelIdx, key]) => {
          const val = raw[Number(excelIdx)];
          data[key] = val == null ? "" : String(val).trim();
        });

        // Validar obligatorios
        const errores = [];
        obligs.forEach(c => {
          if (!data[c.key] || data[c.key].trim() === "") {
            errores.push(`Falta ${c.label}`);
          }
        });

        // Validadores custom por columna
        config.columnas.forEach(c => {
          if (c.validador && data[c.key]) {
            const err = c.validador(data[c.key]);
            if (err) errores.push(err);
          }
        });

        // Detectar duplicado: por nombre o por identificador único (RFC/RUT)
        let estado = "nuevo";
        let duplicadoConId = null;
        let motivoDup = "";
        const nombreUp = (data.nombre || "").toUpperCase().trim();
        const idUp = (data[config.identificadorUnico] || "").toUpperCase().trim();

        if (yaVistosNombre.has(nombreUp)) {
          errores.push("Duplicado dentro del Excel (mismo nombre)");
        }
        if (idUp && yaVistosId.has(idUp)) {
          errores.push(`Duplicado dentro del Excel (mismo ${config.identificadorUnico.toUpperCase()})`);
        }

        if (errores.length === 0) {
          if (nombreUp && lookupNombre.has(nombreUp)) {
            estado = "duplicado";
            duplicadoConId = lookupNombre.get(nombreUp).id;
            motivoDup = "Mismo nombre ya existe en Supabase";
          } else if (idUp && lookupId.has(idUp)) {
            estado = "duplicado";
            duplicadoConId = lookupId.get(idUp).id;
            motivoDup = `Mismo ${config.identificadorUnico.toUpperCase()} ya existe en Supabase`;
          }
        } else {
          estado = "error";
        }

        if (nombreUp) yaVistosNombre.add(nombreUp);
        if (idUp) yaVistosId.add(idUp);

        filasProcesadas.push({
          filaExcel: i + 1,
          data,
          estado,
          errores,
          motivoDup,
          duplicadoConId,
        });
      }

      setFilas(filasProcesadas);
    } catch (e) {
      setErrorGeneral("Error procesando Excel: " + e.message);
      setFilas([]);
    }
    setAnalizando(false);
  };

  const onFileDrop = (fileList) => {
    const archivos = Array.from(fileList || []).filter(f => /\.(xlsx|xls)$/i.test(f.name) && f.size > 0);
    if (archivos.length === 0) {
      setErrorGeneral("Subí un archivo Excel (.xlsx).");
      return;
    }
    procesarExcel(archivos[0]);
  };

  // ─── Importar (insertar las filas "nuevas" en Supabase) ────────────────────
  const importar = async () => {
    const aInsertar = filas.filter(f => f.estado === "nuevo");
    if (aInsertar.length === 0) {
      alert("No hay registros nuevos para importar.");
      return;
    }
    const omitidos = filas.length - aInsertar.length;
    if (!confirm(
      `Se insertarán ${aInsertar.length} transportista(s) nuevos.\n` +
      `${omitidos > 0 ? `(Se omiten ${omitidos} duplicados/errores)\n` : ""}\n` +
      `¿Confirmás la importación?`
    )) return;

    setImportando(true);
    let okCount = 0, errCount = 0;
    const erroresDetallados = [];
    const BATCH_SIZE = 50;  // Supabase rate limit

    for (let i = 0; i < aInsertar.length; i += BATCH_SIZE) {
      const lote = aInsertar.slice(i, i + BATCH_SIZE);
      const payloads = lote.map(f => {
        const p = { ...f.data };
        // Limpiar strings vacíos a null para columnas opcionales
        config.columnas.forEach(c => {
          if (!c.oblig && p[c.key] === "") p[c.key] = null;
        });
        // Estado default
        if (!p.estado) p.estado = "Activo";
        p.updated_at = new Date().toISOString();
        return p;
      });
      try {
        const { error } = await sb.from(config.tabla).insert(payloads);
        if (error) {
          errCount += lote.length;
          erroresDetallados.push(`Lote ${Math.floor(i / BATCH_SIZE) + 1}: ${error.message}`);
        } else {
          okCount += lote.length;
        }
      } catch (e) {
        errCount += lote.length;
        erroresDetallados.push(`Lote ${Math.floor(i / BATCH_SIZE) + 1}: ${e.message}`);
      }
    }

    setResultado({ ok: okCount, err: errCount, omitidos, erroresDetallados });
    setImportando(false);

    if (okCount > 0) {
      // Refrescar la lista de transportistas en el padre
      await onImportadoOK();
    }
  };

  // ─── Contadores y stats ────────────────────────────────────────────────────
  const stats = useMemo(() => ({
    total: filas.length,
    nuevos: filas.filter(f => f.estado === "nuevo").length,
    duplicados: filas.filter(f => f.estado === "duplicado").length,
    conError: filas.filter(f => f.estado === "error").length,
  }), [filas]);

  return (
    <div style={{
      position: "fixed", inset: 0, background: "rgba(0,0,0,0.5)",
      display: "flex", alignItems: "center", justifyContent: "center", zIndex: 1000, padding: 20,
    }} onClick={!importando ? onCancelar : undefined}>
      <div onClick={e => e.stopPropagation()} style={{
        background: "#fff", borderRadius: 14, padding: 24, maxWidth: 1100, width: "100%",
        maxHeight: "92vh", overflowY: "auto",
      }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16, flexWrap: "wrap", gap: 8 }}>
          <div>
            <div style={{ fontSize: 16, fontWeight: 700, color: "#1a3a6b" }}>
              Importador masivo · Transportistas {config.pais}
            </div>
            <div style={{ fontSize: 12, color: "#64748b", marginTop: 4 }}>
              Subí un Excel con la nómina de transportistas. Validamos antes de insertar.
            </div>
          </div>
          <button onClick={descargarPlantilla}
            style={{
              background: "#fff", border: "1px solid #1a3a6b", borderRadius: 8,
              padding: "8px 14px", fontSize: 12, color: "#1a3a6b", cursor: "pointer",
              fontFamily: "Geist, sans-serif", fontWeight: 600,
            }}>
            📋 Descargar plantilla
          </button>
        </div>

        {errorGeneral && (
          <div style={{
            background: "#fee2e2", border: "1px solid #fca5a5", color: "#991b1b",
            padding: "10px 14px", borderRadius: 8, marginBottom: 14, fontSize: 13,
          }}>⚠ {errorGeneral}</div>
        )}

        {filas.length === 0 && !resultado && (
          <>
            {/* Drag-and-drop */}
            <div
              onDragOver={e => { e.preventDefault(); e.stopPropagation(); setArrastrando(true); }}
              onDragLeave={e => { e.preventDefault(); e.stopPropagation(); setArrastrando(false); }}
              onDrop={e => {
                e.preventDefault(); e.stopPropagation();
                setArrastrando(false);
                onFileDrop(e.dataTransfer.files);
              }}
              onClick={() => fileInputRef.current?.click()}
              style={{
                border: `3px dashed ${arrastrando ? "#F47B20" : "#1a3a6b"}`,
                borderRadius: 12, padding: "40px 24px", textAlign: "center",
                cursor: "pointer", background: arrastrando ? "#fff7ed" : "#f8fafc",
                marginBottom: 16, transition: "all 0.2s",
              }}
            >
              <div style={{ fontSize: 40, marginBottom: 10 }}>📤</div>
              <div style={{ fontSize: 15, color: "#1a3a6b", fontWeight: 700, marginBottom: 4 }}>
                {analizando
                  ? "Analizando Excel..."
                  : arrastrando
                    ? "Soltá el Excel aquí"
                    : "Arrastrá el Excel de transportistas"}
              </div>
              <div style={{ fontSize: 12, color: "#64748b" }}>
                o hacé clic para seleccionar · solo .xlsx
              </div>
              <input
                ref={fileInputRef} type="file" accept=".xlsx,.xls"
                style={{ display: "none" }}
                onChange={e => { onFileDrop(e.target.files); e.target.value = ""; }}
              />
            </div>

            {/* Instrucciones */}
            <div style={{
              background: "#eff6ff", border: "1px solid #bfdbfe", borderRadius: 8,
              padding: 14, fontSize: 12, color: "#1a3a6b", lineHeight: 1.6,
            }}>
              <div style={{ fontWeight: 700, marginBottom: 6 }}>💡 Formato esperado del Excel:</div>
              <div>El archivo debe tener una hoja con las siguientes columnas (en la primera fila):</div>
              <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginTop: 8 }}>
                {config.columnas.map(c => (
                  <code key={c.key} style={{
                    background: "#fff", border: "1px solid #bfdbfe", borderRadius: 4,
                    padding: "2px 8px", fontSize: 11, fontFamily: "monospace",
                  }}>
                    {c.label}{c.oblig ? " *" : ""}
                  </code>
                ))}
              </div>
              <div style={{ marginTop: 8, fontSize: 11 }}>
                * = obligatorio · Descargá la plantilla arriba para tener el formato exacto.
              </div>
            </div>
          </>
        )}

        {filas.length > 0 && !resultado && (
          <>
            {/* Indicadores */}
            <div style={{
              display: "grid", gridTemplateColumns: "repeat(4, 1fr)",
              gap: 10, marginBottom: 16,
            }}>
              <IndicadorImp label="Total" valor={stats.total} color="#1a3a6b" />
              <IndicadorImp label="Nuevos" valor={stats.nuevos} color="#16a34a" />
              <IndicadorImp label="Duplicados" valor={stats.duplicados} color="#f59e0b" />
              <IndicadorImp label="Con errores" valor={stats.conError} color="#dc2626" />
            </div>

            {/* Tabla preview */}
            <div style={{
              border: "1px solid #e4e7ec", borderRadius: 8, overflow: "hidden",
              maxHeight: "45vh", overflowY: "auto", marginBottom: 16,
            }}>
              <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 11 }}>
                <thead style={{ position: "sticky", top: 0, background: "#f8fafc", zIndex: 1 }}>
                  <tr>
                    <th style={pf_th()}>Fila</th>
                    <th style={pf_th()}>Estado</th>
                    {config.columnas.map(c => (
                      <th key={c.key} style={pf_th()}>{c.label}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {filas.map(f => {
                    let bg = "transparent";
                    if (f.estado === "nuevo")      bg = "#f0fdf4";
                    if (f.estado === "duplicado")  bg = "#fffbeb";
                    if (f.estado === "error")      bg = "#fef2f2";
                    return (
                      <tr key={f.filaExcel} style={{ background: bg, borderTop: "1px solid #f1f5f9" }}>
                        <td style={pf_td()}><span style={{ fontSize: 10, color: "#94a3b8" }}>#{f.filaExcel}</span></td>
                        <td style={pf_td()}>
                          {f.estado === "nuevo" && (
                            <span style={{ background: "#dcfce7", color: "#166534", padding: "2px 8px", borderRadius: 20, fontSize: 10, fontWeight: 700 }}>
                              ✓ NUEVO
                            </span>
                          )}
                          {f.estado === "duplicado" && (
                            <div title={f.motivoDup}>
                              <span style={{ background: "#fef3c7", color: "#92400e", padding: "2px 8px", borderRadius: 20, fontSize: 10, fontWeight: 700 }}>
                                ⊘ DUPLICADO
                              </span>
                              <div style={{ fontSize: 9, color: "#92400e", marginTop: 2 }}>{f.motivoDup}</div>
                            </div>
                          )}
                          {f.estado === "error" && (
                            <div title={f.errores.join(" · ")}>
                              <span style={{ background: "#fee2e2", color: "#991b1b", padding: "2px 8px", borderRadius: 20, fontSize: 10, fontWeight: 700 }}>
                                ✗ ERROR
                              </span>
                              <div style={{ fontSize: 9, color: "#991b1b", marginTop: 2, maxWidth: 200 }}>
                                {f.errores[0]}
                                {f.errores.length > 1 && ` (+${f.errores.length - 1})`}
                              </div>
                            </div>
                          )}
                        </td>
                        {config.columnas.map(c => (
                          <td key={c.key} style={{ ...pf_td(), maxWidth: 180, wordBreak: "break-all", fontSize: 11 }}>
                            {f.data[c.key] || <em style={{ color: "#cbd5e1" }}>—</em>}
                          </td>
                        ))}
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>

            <div style={{
              fontSize: 11, color: "#64748b", marginBottom: 14, padding: "10px 12px",
              background: "#f8fafc", borderRadius: 8,
            }}>
              💡 Al confirmar se insertan solo los registros marcados como <strong style={{ color: "#16a34a" }}>NUEVO</strong>.
              Los <strong style={{ color: "#f59e0b" }}>DUPLICADOS</strong> se saltan (no se modifica nada existente).
              Los <strong style={{ color: "#dc2626" }}>ERRORES</strong> se omiten — corregilos en el Excel y volvé a importar.
            </div>
          </>
        )}

        {resultado && (
          <div style={{
            background: resultado.err === 0 ? "#f0fdf4" : "#fffbeb",
            border: `1px solid ${resultado.err === 0 ? "#86efac" : "#fde68a"}`,
            borderRadius: 10, padding: 16, marginBottom: 14,
          }}>
            <div style={{ fontSize: 15, fontWeight: 700, color: resultado.err === 0 ? "#166534" : "#92400e", marginBottom: 8 }}>
              {resultado.err === 0 ? "✓ Importación completada" : "⚠ Importación con errores"}
            </div>
            <div style={{ fontSize: 13, color: "#475569", lineHeight: 1.8 }}>
              <div><strong style={{ color: "#16a34a" }}>{resultado.ok}</strong> registro(s) insertados correctamente</div>
              {resultado.err > 0 && (
                <div><strong style={{ color: "#dc2626" }}>{resultado.err}</strong> registro(s) fallaron al insertar</div>
              )}
              {resultado.omitidos > 0 && (
                <div><strong style={{ color: "#f59e0b" }}>{resultado.omitidos}</strong> registro(s) omitidos (duplicados o con errores)</div>
              )}
            </div>
            {resultado.erroresDetallados.length > 0 && (
              <details style={{ marginTop: 10 }}>
                <summary style={{ fontSize: 12, cursor: "pointer", color: "#991b1b", fontWeight: 600 }}>
                  Ver errores detallados ({resultado.erroresDetallados.length})
                </summary>
                <div style={{ fontSize: 11, color: "#991b1b", marginTop: 8, lineHeight: 1.6 }}>
                  {resultado.erroresDetallados.map((e, i) => <div key={i}>• {e}</div>)}
                </div>
              </details>
            )}
          </div>
        )}

        {/* Botones */}
        <div style={{ display: "flex", gap: 8, justifyContent: "flex-end", flexWrap: "wrap" }}>
          {resultado ? (
            <button onClick={onCancelar} className="btn-blue"
              style={{ padding: "9px 18px", fontSize: 13 }}>
              Cerrar
            </button>
          ) : filas.length === 0 ? (
            <button onClick={onCancelar}
              style={{
                background: "#fff", border: "1px solid #e4e7ec", borderRadius: 8,
                padding: "9px 14px", fontSize: 12, color: "#475569", cursor: "pointer",
                fontFamily: "Geist, sans-serif", fontWeight: 600,
              }}>Cancelar</button>
          ) : (
            <>
              <button onClick={() => { setFilas([]); setErrorGeneral(""); setResultado(null); }}
                disabled={importando}
                style={{
                  background: "#fff", border: "1px solid #e4e7ec", borderRadius: 8,
                  padding: "9px 14px", fontSize: 12, color: "#475569", cursor: "pointer",
                  fontFamily: "Geist, sans-serif", fontWeight: 600,
                  opacity: importando ? 0.4 : 1,
                }}>← Subir otro Excel</button>
              <button onClick={onCancelar} disabled={importando}
                style={{
                  background: "#fff", border: "1px solid #e4e7ec", borderRadius: 8,
                  padding: "9px 14px", fontSize: 12, color: "#475569", cursor: "pointer",
                  fontFamily: "Geist, sans-serif", fontWeight: 600,
                  opacity: importando ? 0.4 : 1,
                }}>Cancelar</button>
              <button onClick={importar}
                disabled={importando || stats.nuevos === 0}
                className="btn-orange"
                style={{ padding: "9px 18px", fontSize: 13 }}>
                {importando
                  ? "Importando..."
                  : `📥 Confirmar e importar ${stats.nuevos} nuevo${stats.nuevos === 1 ? "" : "s"}`
                }
              </button>
            </>
          )}
        </div>
      </div>
    </div>
  );
}

function IndicadorImp({ label, valor, color }) {
  return (
    <div style={{
      background: "#fff", border: "0.5px solid #e4e7ec", borderRadius: 8,
      padding: "10px 12px",
    }}>
      <div style={{
        fontSize: 10, color: "#94a3b8", textTransform: "uppercase",
        letterSpacing: 0.5, marginBottom: 4, fontWeight: 600,
      }}>{label}</div>
      <div style={{ fontSize: 20, fontWeight: 700, color }}>{valor}</div>
    </div>
  );
}

